window.BANNANJE_VERSE_MEANINGS_HI =
{
  "1.3": "पश्य एतम् पाण्डुपुत्रानाम् आचार्य महातिम् चामूम्।\nव्यूधं द्रुपदपुत्रेण तव शिष्येन धीमता -- आचार्य, पांडु पुत्रों की इस विशाल सेना को देखो। आपके विद्वान शिष्य द्रुपा के पुत्र द्वारा सुसज्जित।",
  "1.4": "अत्र शूरः मह इषु असः भीमार्जुन समः युधि |\nयुधानाः विराटः च द्रुपदः च महारथः - यहाँ सभी महारथी वीर हैं। युद्ध में भीमार्जुन के समान — सात्यकि, विराट और द्रुपद भी महारथी हैं।\n\nदुर्योधन, जो पांडव सेना को देखकर मानसिक रूप से हिल गया था, द्रोणाचार्य के पास जाता है और पांडव सेना और वहां के नायकों के बारे में बात करता है। अक्सर ऐसा लगता है कि जिस व्यक्ति से हम डरते हैं वह हर जगह मौजूद है। जैसे कृष्ण ने कंस को दर्शन दिये। यह मनोविज्ञान है. इधर दुर्योधन भीमार्जुन से डरता है।",
  "1.7": "अस्माकं तु विशिष्टः ये तं निबोध द्विजोत्तम |\n\nनायकः मम धिम्यस्य संजना अर्थं तं ब्रविमि ते -- हे द्विजोत्तमा, हमारा पक्ष।\nमेरी सेना के नेता, नेता कौन हैं? उनके बारे में पूछें. आपके इशारे पर उन्हें\nनामकरण\n\nयुद्ध के समय नायक की शक्ति कम होने पर भी वह कुशलता से कार्य करता है\nप्रबंधन एक नेता अपने सैनिकों, अपने अनुयायियों की जय-जयकार करता है।\nवह अपनी सेना में यह विश्वास जगाता है कि वह शत्रु सेना से अधिक शक्तिशाली है। लेकिन यहाँ\nदुर्योधन ने अपने सेनापति भीष्म को परामर्श के लिए और आचार्य द्रोण को छोड़ दिया\nशत्रु सेना के नायकों के बारे में विशेष रूप से बोलें, 'हमारी सेना का अग्ररक्षक आपकी आज्ञा और आह्वान पर है\nमैं आपको इसके बारे में बताऊंगा!",
  "1.9": "अन्ये च बहवः शूराः मत अर्थे त्यक्त जीवितः।\nनाना वर्ण प्रहरणः सर्वे युद्ध विषाहर्दः - 'अभी भी कई वीर हैं। मेरे लिए जियो\nजो लोग भुगतान करने आए थे। विभिन्न हथियारों से लड़ने में सक्षम. सभी युद्ध के आदी हैं।\n\nप्रथमदृष्टया, यदि हम इस श्लोक को देखें, तो दुर्योधन अपने नायकों के बारे में बात कर रहा है\nभले ही ऐसा लगता है कि वह कह रहे हैं, लेकिन यहां वह जो कह रहे हैं वह अलग है। उन्होंने ये बात कही\nद्रोण बोल रहे हैं, और वह अपना भाषण \"पांडवों के आचार्य\" से शुरू करते हैं।\nयहाँ वह है - हमारे पक्ष में कई बहादुर लोग हैं, 'वे सभी अपनी जान देने आए हैं'\nवह पाखंड से कह रहा है. दुर्योधन कहता है कि वे सभी अलग-अलग हथियारों का उपयोग कर सकते हैं।\nवह इस भावना को व्यक्त करता है कि उसके लिए कोई नहीं है।\n\nअपर्यप्तं तदस्माकं बलं भीष्मभिरक्षितम् |\nपर्यपतं त्विदमेतेषां बलं भीमाभिरक्षम्।",
  "1.5": "धृष्टकेतुः चेकितानः काशीराजः च वीर्यवान् |\nपुरुजित कुन्तिभोजः च शैब्यः च नरपुंगवः -- धृष्टकेतु, चेकितान, काशीराज को भी जलने दो। पुरुजिता, कुन्तिभोज, शैब्य भी पुरुष हों।\n\nजाहिर तौर पर इस श्लोक में हमें छह नायकों के नाम मिलते हैं। लेकिन यहां हमें सिर्फ इन छह लोगों को ही नहीं देखना है. दुर्योधन की मनःस्थिति, उसका दर्द इन लोगों के नाम बता रहे हैं। शिशुपाल का पुत्र धृष्टकेतु - शिशुपाल कृष्ण द्वारा मारा गया था; अब वह शत्रु पुत्र पांडवों के पक्ष में है! चेकितान यादव\nवीरा - बलराम की अनुपस्थिति में पांडव शिविर में शामिल हो गया। काशीराज भीमसेन के ससुर थे। पुरुजीत और कुंतिभोज कुंतीदेवी के दत्तक रिश्तेदार हैं - जो पांडव समर्थक भी हैं। शैब्या - भीमसेन द्वारा मारा गया जब उसने अपने बेटे जयद्रथ की मदद की; वह शैब्या भी पांडवों के पक्ष में है।",
  "1.10": "अपर्यप्तं तत् अस त्रम् बलं भीष्म अभिरिक्तम्।\nपर्याप्तम् तु इदम् एतेषाम् बलम् भीम अभिरिक्षतम -- वह भीष्माचार्य की दृष्टि का।\nहमारी सेना अच्छी तरह सुसज्जित नहीं है. भीम की निगरानी में उनकी सेना अच्छी तरह से तैयार है।\n\nयहाँ दुर्योधन के भाषण का निष्कर्ष है (1€986€105100)। वह कहता है: “वह हमारा है\nकोई सेना नहीं है, यह पांडव पक्षपाती भीष्माचार्य के नेतृत्व में हमारी सेना है\nभीम की इस सेना के सामने तैयार रहना ही काफी नहीं है. यहाँ एक नज़दीकी नज़र है\nभीष्मचार्य कौरव सेनापति थे। लेकिन भीम पांडव सरदार नहीं हैं. दुर्योधन को\nभीम से घृणा और भय किया जाता है। इस कारण वह भीम की निगरानी में पांडव सेना है\nवह उसे संबोधित करता है। अधिक ध्यान से देखें तो- दुर्योधन का अपनी भूमि पर युद्ध\nवह सेना में सबसे आगे खड़े हैं. पांडव सेना उससे बहुत दूर है। लेकिन बोलते समय\nवह \"यह पांडव सेना\" और \"हमारी वह सेना\" को संबोधित करते हैं। पांडव सेना\nउनका कहना है कि वे पहले ही उनके करीब आ चुके हैं और उनकी सेना उनसे काफी दूर है\nबात कर रहा है\n\nअयनेषु च सर्वेषु यथाभागमवस्थितः |\nभीष्ममेवभिरक्षन्थु भवन्तः सर्व एव हि",
  "1.16": "अनंतविजयं राजा कुंथिपुत्रः युधिष्ठिरः |\nनकुलः सहदेवः च सुघोषा मणिपुष्पकौ - कुंती के पुत्र राजा युधिष्ठिर अनंतविजय,\nनकुल सहदेव ने सुघोष और मणिपुष्ट को एक शंख भी दिया\n\nभीम के बाद कुंती के सबसे बड़े पुत्र, राजा युधिष्ठिर आए - जो धर्म और विजय का प्रतीक थे।\nउन्होंने 'अनंतविजय' नामक शंख बजाया। नकुल और सहदेव सुघोष और\nमणिपुष्टि नियमित रूप से बजती थी।\n\nमहाभारत में कहीं भी किसी अन्य राजा के शंख नाम का उल्लेख नहीं है। पांडवों में से पांच\nशंख का नाम केवल भगवत गीता में ही मिलता है। शायद यह हमारे लिए नियमित है\nयादगार होना चाहिए. गीत में इन पाँचों नामों का विशेष उल्लेख इसी उद्देश्य से किया गया है\nउल्लेख किया जा सकता है.\n\nकस्यश्च परमेश्वरसः शिखंडी च महारथः |\n\nधृष्ट द्युम्नो विराताश्च सत्यनिष्ठ पराजितः",
  "1.13": "ततः शंखः च भेर्यः च पणव अनाका गोमुखः |\nसहसा एव अभ्यहन्यन्त सः शब्दः तुमुलः अभवत् -- उसके बाद शंख, नागरी, तमते --\nडोलू-गोमुख (तुरही) तुरंत बजाए गए। आवाज बहरा कर देने वाली थी.\n\nभीष्माचार्य के बाद कौरव सेना की ओर से प्रधान सेनापति शंखण बने\nशंख, नागरी-नगाड़े-गोमुख-एक ही बार बजाए जाते हैं।  वह आवाज बहरा कर देने वाली है\nहंगामा मच गया. यहां न तो दुर्योधन ने शंख बजाया और न ही उसके रिश्तेदारों ने. इसके बजाय\nसरदार ने शंख बजाया। इसके पीछे सेना के नेता और सैनिक थे\nशंख बन गया. इस तरह यह एक अव्यवस्थित शोर जैसा महसूस हुआ. यहाँ\nयह स्पष्ट है कि दुर्योधन ने अपनी शक्तियों का व्यवस्थित विकास नहीं किया।\nहमारे बीच। कोई भी उपकरण कितना भी उपयोगी (5650-60) क्यों न हो, जब तक वह उपकरण हमारे पास नहीं है\nयदि आपको इसका नियमित उपयोग नहीं आता है, तब तक यह उपकरण बेकार है।\nहाथ में उपकरण के साथ. सत्ता की चाहत वाली मन की स्थिति. हारना\nमांडलू (1.68668) को कभी सफलता नहीं मिलेगी।\n\nततः श्वेतैरहयैरयुक्ते महति सयन्दने स्थितौ |\nमाधवः पाण्डपश्चेव दिव्याउ शंखौ प्रद्धमतुः",
  "1.11": "अयनेषु च सर्वेषु यथा भागं अवस्थितः |\nभीष्मम एव अभिरक्षंतु भवनतः सर्वे एव हि - रणनीतिक रूप से हर जगह वितरित,\nसावधान रहो- तुम सबको भीष्म की प्रतीक्षा करनी चाहिए।\n\n\"आप सभी भीष्म हैं, रणनीति के सभी क्षेत्रों में साझा करें और पहरा दें\nदुर्योधन द्रोण से बोलता है। यहाँ हममें से थोड़ा सा है\nउन्होंने कहा, \"बूढ़े जनरल भीष्मचार्य का ख्याल रखें।\" उसका उससे\nसरदार पर विश्वास मत करो!\n\nयह सुनकर भीष्माचार्य को कितना दुःख हुआ होगा। अपने विवेक के विरुद्ध, स्वयं\nवह अपनी अंतरतम इच्छा के विरुद्ध, उस परिवार के शाही आदेश से बंधे हुए प्यार करता था जिसमें वह पैदा हुआ था\nजब वह अपने चचेरे भाइयों के खिलाफ लड़ने के लिए ईमानदारी से खड़ा हुआ, आशा है। खो गया\nदुर्योधन के व्यंग्यपूर्ण भाषण से उसे कितना कष्ट हुआ होगा।\nइसकी कल्पना करना हमारे लिए कठिन है. यह सुनकर भीष्मचार्य ने क्या किया?\nआइए इसे अगले श्लोक में देखें।\n\nतस्य संजानयन हर्षं कुरुवृद्ध पितामहः |\n\nसिंहनादं विन्द्योच्च शंखं दध्मौ प्रतापवान्",
  "1.1": "धृतराष्ट्रः उवाच- धृतराष्ट्र ने पूछा:\n\nधर्मक्षेत्रे कुरूक्षेत्रे समावेतः युयुत्सवः |\n\nमामकः पांडवः च एव किम् अकुर्वत संजय - धर्म की भूमि, कुरूक्षेत्र में युद्ध\nसंजय, मैंने और पाण्डवों ने इच्छा से क्या एकत्र किया?\n\nजैसा कि पहले बताया गया है कि अंधे धृतराष्ट्र का प्रश्न भी 'जीव' का अंधा प्रश्न है। हम कितना\nहमें यह भी पता नहीं कि अंधे लोग कुछ नहीं जानते! इसलिए गीत\nइसकी शुरुआत धृतराष्ट्र के सवाल से होती है.\n\nसंजय में अंधे धृतराष्ट्र को टेलीविजन और दूर से सुनने की शक्ति व्यास से मिली थी\nजो प्रश्न पूछा गया है वह गीत का पहला छंद है। परशुराम से समन्तपंचक (लगभग पाँच)\nसरोवर) का निर्माण हुआ और इसे धर्मक्षेत्र कहा गया, यह युद्ध भूमि तब 'कुरु' नामक राजा की थी।\nउस समय कुरूक्षेत्र सर्वोच्च धार्मिक स्थल बन गया। यहीं है \"धर्मक्षेत्र कुरूक्षेत्र\"\nउसे संबोधित किया. हमारा ह्रदय स्थल. धर्म क्या है और अधर्म क्या है\nनिर्णय लेने वाला मन (!176)-कुरुक्षेत्र (कर्मक्षेत्र)। महाभारत मन का संघर्ष है\nइधर अंधे धृतराष्ट्र ने संजय से पूछा, 'मेरी प्रजा जो युद्ध की इच्छा से आगे आई थी।'\nऔर 'पांडवों' ने क्या किया?'' यहां 'मेरे और. पांडवों की\nधृतराष्ट्र जो शासक राजा थे, उन्होंने अपनी कमजोरी को संबोधित किया\nजो व्यक्त किया जा रहा है वह इस श्लोक में स्पष्ट रूप से उजागर हुआ है।",
  "1.12": "तस्य संजानयन हर्षं कुरुवृद्ध पितामहः |\nसिंहादम् विन्द्य उच्चेः शंखं दध्मौ प्रतापवान् - कौरवों का उसे प्रसन्न करने के लिए।\nउस वक्षधारी भीष्म, हृष्ट-पुष्ट सिंह ने शंख बजाया।\n\nयुद्ध से पहले आशा खो चुका दुर्योधन खेदपूर्वक बोलता है\nउनकी आशाओं को जगाने के लिए, उनमें आत्मविश्वास भरने के लिए, कुरुवंश की सबसे वरिष्ठ प्रतापशाली\nवृद्ध भीष्मचार्य अपने कर्तव्य के अनुसार सिंह बन गये और शंख अर्पित किया।\n\nशंख महापापनाशक है। पहले के समय में सुबह-शाम घर का कोना-कोना-\nवह शंख ध्वनि इसलिए करते थे ताकि वह कोने से लेकर सभी दिशाओं में सुनाई दे। इसका कारण शंख है\nनाडा में दुष्टात्मा की छाती तोड़ने वाली क्षमता। जब तक शंख की ध्वनि सुनाई देती है।\nतब तक कोई भी बुरी शक्तियां भटक नहीं सकती। मृत्यु के रणक्षेत्र में आसुरी\nताकि सत्ता से प्रभावित न हों, खुद को युद्ध के लिए तैयार करें वगैरह-वगैरह\n\nशत्रु स्वयं. पहले शंख का उपयोग तत्परता का संकेत देने के लिए किया जाता था। यहाँ\nभीष्मचार्य ने कौरव सेना और पांडवों को शंख बजाकर अपनी तत्परता का संकेत दिया\nसेना में भी भेजा गया.\n\nततः संखश्च भेर्यश्च पणवनकागोमुखः |\nसहसैवभ्यहन्यन्त स सभस्तुमुलो*भवत्",
  "1.14": "ततः श्वेतैः ह्यकैः युक्ते महति सयन्दने स्थितौ |\nमाधवः पाण्डवः च एव दिव्यु शंखौ प्रद्धमतुः - फिर सफेद घोड़ों पर आरूढ़\nबड़े रथ पर बैठे भगवान कृष्ण और अर्जुन ने शंख बजाया।\n\nशंखनगरी में कौरव सेना के उत्पात के बाद वे चार सफेद घोड़ों पर सवार होकर वहां पहुंचे\nभगवान कृष्ण और अर्जुन अपने दिव्य शंखों के साथ सभी रथों में से सबसे बड़े पर बैठे हैं\n(पहले भगवान कृष्ण फिर अर्जुन)।\n\nइस श्लोक में माधव और पांडव दो विशेषणों का प्रयोग किया गया है। यहाँ भगवान है\nमाधवः कहकर सम्बोधित किया जाता है। 'माँ' का अर्थ है माँ लक्ष्मी। तो माधव का अर्थ है लक्ष्मीपति\nभगवान-श्री मन्ना रायण. हाँ, 'माँ' का अर्थ है ज्ञान। भगवान ज्ञान के स्वामी हैं.\nतो वह माधव है. उन्हें माधव कहा जाता था क्योंकि उनका जन्म मधुवंश में श्रीकृष्ण-अवतार में हुआ था\nवेद में मातृ शब्द का अर्थ वाक् या वाज्मय है\nखुग्वेद, यजुर्वेद, सामवेद, अथर्ववेद नामक सात महान ग्रंथों का उपयोग किया गया।\nरामायण, महाभारत और पुराणों को मातृ कहा जाता है। अतः सब कुछ वैदिक है\nभगवान माधव जो वाज्मय के वकील हैं।\n\nयहां अर्जुन को 'पांडव' कहकर संबोधित किया गया है। अर्जुन कुंती की तीन संतानों में से एक\nआखिरी वाला आमतौर पर आखिरी बेटे को हमेशा अधिक प्यार किया जाता है। उसके लिए वह\nउन्हें पार्थ, कौन्तेय, पांडव कहा जाता था। अर्जुन के पास भगवान की विशेष उपस्थिति थी।\nवह नारायण के साथी 'नर' का भी रूप हैं।\n\nहमारा शरीर भी एक रथ है। ऐसे रथ में जीवन का नेतृत्व करने वाले भगवान की उपस्थिति होती है। चार\nघोड़े चार वेद हैं। सफेद रंग सत्त्वगुण का प्रतीक है\n\nपाञ्चजन्यं हृषीकेशो देवदत्तं धनञ्जयः ॥\nपौण्ड्रं दध्मौ महाशंखं भीमकर्म वृकोदरः",
  "1.17": "कश्यः च परम इषु असः शिखंडी च महारथः |\nधृष्टद्युम्नः विराटः च सत्यकिः च अपराजितः -- वृद्ध बिल्दोजा काशीराज, वृद्ध थेरलु\n\nजिसमें शिखंडी, धृष्टद्युम्न और विराट, शंखना के साथ सोलारिया के सात्यकि भी शामिल हैं।\nकिया\n\nफिर ज्येष्ठ बिल्लोजा काशीराज, ज्येष्ठ तेरलु शिखंडी, धृष्टद्युम्न और विराट,\nसात्यकि थकते नहीं थे, इस प्रकार उन्होंने एक-एक करके शंख ध्वनि की।\n\nहमें यहां ध्यान देना चाहिए कि शिखंडी को महारथ कहकर संबोधित किया जाता है। बहुत सारे लोग\nशिखंडी को किन्नर कहा जाता है। लेकिन शिखंडी का मतलब किन्नर नहीं है. शिखंडी का अर्थ है\nमूलतः वह जिसके पास शिखंड है। यहां शिखा का मतलब सिर के बाल से है। सिर के बाल\nशिखंडी वे हैं जो इसे अच्छी तरह से कंघी करते हैं और इसे अंडे की तरह वापस बांधते हैं। जब हुआ था महाभारत के इस शिखंडी का जन्म\nवह एक महिला बन गया » और फिर मराठा एक पुरुष बन गया। भीष्माचार्य उनके ख़िलाफ़ हैं क्योंकि वह 'स्त्रीवत' हैं\nतीर का परीक्षण नहीं किया गया था.",
  "1.28": "अर्जुन उवाच —\nदृष्ट्वेमं स्वजनं कृष्ण युयुत्सुं समुपस्थितम् ।\nसीदन्ति मम गात्राणि मुखं च परिशुष्यति ॥\n\nअर्जुन ने युयुत्सु (युद्ध के लिए तैयार) अपने स्वजनों को देखकर कहा — मेरे अंग शिथिल पड़ रहे हैं और मुख सूख रहा है।\n\nयह अर्जुन के विषाद का शारीरिक प्रकटीकरण — मन का संकट शरीर में उतरता है। 'स्वजनम्' — अपने ही जनों को। युद्धभूमि में खड़े कृष्ण-अर्जुन के बीच यह संवाद गीता की भूमिका है।",
  "1.8": "भवन भीष्मः च कर्णः च कृपाः च समितंजय |\nअश्वत्थामा विकर्णः च सौमदतिः तथा एव च ​​-- आदरणीय, भीष्म और कर्ण, कृपा भी।\nविजेता अश्वत्थामा और विकर्ण; सोमदत्त का पुत्र भूरिश्रवा भी ऐसा ही था।\n\nपांडव सेना में - सेनापति, ग्यारह महान वीर और छह पांडव\nबालकों की वीरता का वर्णन करने वाले दुर्योधन को अपने पक्ष में कोई वीर नजर नहीं आता! यहाँ\nउन्होंने व्यंग्य करते हुए अपने पक्ष के सात नायकों के नाम का जिक्र किया है. 'भवन' यानी\nस्वयं (पांडव 1 के आचार्य के रूप में); युद्ध से पहले धर्मराय विजयी हो\nधन्य भीष्मचार्य! ; \"भीष्म जब तक युद्ध के मैदान में रहेंगे तब तक लड़ते रहेंगे\nकर्ण कसम खा कर बैठ गया कि मैं ऐसा नहीं करूंगा; वैदिक विशेषज्ञ आचार्य कृपा; पागल दिमाग\nअश्वत्थामा; विकर्ण जिसने द्रौपदी के अपमान की निंदा की और उससे लाभ उठाने की कोशिश की;\nदक्षिण की ओर आये भीष्माचार्य के पिता - शान्तनु के भाई के पुत्र - सोमदत्त के पुत्र भूरिश्रवा!\nइस प्रकार दुर्योधन ने अपने सात वीरों के नाम भीष्मचार्य रख दिये\nवह द्रोणाचार्य में कहता है सुनो।\n\nयहां हम विस्तार से देखते हैं कि ग्यारह अक्षौहिणी कौरव पक्ष की सेना का नेतृत्व कर सकती थीं\nवीर थे. उसके निन्यानवे लोग उसके साथ थे। शल्य भगदत्त जैसे वीर\nदुर्योधन के पक्ष में था. परंतु पांडव सेना के भय से वह यह सब भूल गया\nदुर्योधन केवल अपने पक्ष के वीरों की बात करता है! यहाँ\nहमें यह स्पष्ट है कि दुर्योधन मानसिक रूप से कितना परेशान था।\nयुद्ध के परिणाम के बारे में सोचकर वह अपना कर्तव्य भूल गया था!\n\nअन्ये च बहवः शूरा मदार्थे त्यक्तजीवतः |\n\nविभिन्न हथियारों के साथ युद्ध का सर्वेक्षण करें",
  "1.6": "युधामन्युः च विक्रांत उत्तमौजः च वीर्यवान् |\nसौभद्रः द्रौपदेयः च सर्वे एव महारथः - युधामन्यु वीर है। उत्तमौजा\nअँधेरा भी होने दो. सुभद्रे के पुत्र, द्रौपदी के पुत्र सभी निश्चित रूप से वरिष्ठ थेरल थे।\n\nदुर्योधन, जो पांडव सेना को देखकर अंदर से भयभीत हो गया था, उसी घर का रहने वाला था\nयहां हर व्यक्ति का जिक्र है. युधामन्यु और उत्तमौजा द्रुपद हैं\nदो अन्य बच्चे. दुर्योधन उन्हें वीर विक्रांत कहकर संबोधित करता है।\nइतना ही नहीं, वह सुभद्रा का पुत्र अभिमन्यु है, और अभी तक प्रयप्रभुद नहीं है\nद्रौपदी के पाँचों पुत्र, जिनकी आयु तेरह से अठारह वर्ष के बीच थी, महारथी थे। वह है\nपते!\n\nस्पष्ट रूप से, हमें यहां जो खोजने की आवश्यकता है वह यह है कि एक बार जब हम डर जाते हैं, तो हमारे पास एक रस्सी होती है\nयह सांप की तरह दिखने लगता है. ऐसी स्थितियों में हमारी असली ताकत भी यही है।'\nबर्बाद. हालाँकि युद्ध से पहले उनकी सेना ग्यारह अक्षोहिणी सेना थी\nजय-जयकार करने के अलावा दुर्योधन पांडव सेना के वीरों के बारे में भी बात कर रहा है\nयह उनकी मनःस्थिति को स्पष्ट रूप से दर्शाता है। उन्होंने यहां ग्यारह नायकों के नाम बताए\nहमें ध्यान देना चाहिए कि क्या कहा गया है (सात्यकि, विराट, द्रुपद, धृष्टकेतु, चेकितान, काशीराज,\nपुरुजित, कुन्तिभोज, शैभ्य, युधामन्यु और उत्तमौजा)। वह ग्यारह अक्षोहिणी हैं\nभले ही सेना का प्रतिनिधित्व करने वाले नायक हैं, वह सात अक्षौहिणी सेना के साथ एक पांडव हैं\nसेना में ग्यारह नायक उभरने लगे! भगवान से दूर रहे\nप्रत्येक अधर्मी व्यक्ति का यही भाग्य है। वे सदैव आंतरिक भय में रहते हैं\nऔर उस डर को छिपाने के लिए वे 'नहीं' कहते हैं। दुष्ट मनुष्य आदरहीन होता है\nबात करने का मतलब है कि वह अंदर से बहुत डरा हुआ है. उनमें से\nकोई भी शक्ति उन्हें बचा नहीं सकती। उनके प्रति उनकी शक्ति के कारण\nके बारे में आश्वस्त नहीं हूँ.  यही वह मनोविज्ञान है जिसे हमें यहां खोजना है।\n\nअस्माकंथु विष्ठा ये तं निबोध द्विजोत्तम |\n\nनायक मम धमियस्य संज्नार्थं तं ब्रविमि ते",
  "1.15": "पाञ्चजन्यं हृषीकेश देवदत्तं धनंजयः |\nपौण्ड्रं दध्मौ महासंखं भीमकर्म वृकोदरः - भगवान कृष्ण ने पांचजन्य दिया,\nअर्जुन ने देवदत्त और भीम ने पौंड्र नामक महान शंख बजाया।\n\nपांडव पक्ष की ओर से सबसे पहले भगवान श्रीकृष्ण अपना शंख बजाते हैं। भगवान कृष्ण का शंख\nनाम है पाञ्चजन्य. इस 'पाञ्चजन्य' शंख के पीछे एक कहानी है। भगवान कृष्ण अपनी पढ़ाई में\nयह सांदीपनि मुनि के आश्रम में किया गया था। पढ़ाई पूरी कर लौटते समय विद्यार्थी\nगुरुदक्षिणा देना आम बात है. यहां कृष्ण द्वारा अपने गुरु को दी गई गुरुदक्षिणा बहुत अनोखी है।\n'पंचजन' नामक असुर ने सांदीपनि मुनि के पुत्र को मार डाला था। अपनी शिक्षा पूरी की\nवापस जाते समय, कृष्ण ने गुरु दम्पति को गुरुदक्षिणा के रूप में उनका पुत्र लौटा दिया। वह\nपांचजन्य राक्षस पंचजना वाला शंख है। पाञ्चजन्य-असुर संहारक तथा\nआत्मज्ञान का संकेत.\n\nकृष्ण के शंख के पीछे अर्जुन ने अपना 'देवदत्त' नामक शंख दिया। स्वर्गीय काल के दौरान\nइंद्र ने असुरों के खिलाफ लड़ने के लिए देवलोक में अर्जुन को एक अनोखा मुकुट पहनाया\nयह शंख उपहार स्वरूप दिया गया था। यह शंख दुष्ट दमन का भी प्रतीक है।\n\nअर्जुन के शंख के बाद वृकोदर भीम ने पौंड्र नामक महान शंख बजाया।\nयहां भीम को वृकोदर नाम से संबोधित किया गया है। वृकोदर का अर्थ है जो संपूर्ण ब्रह्मांड को जला सकता है\nइसका अर्थ है जो अपने पेट में अग्नि धारण करता है। यहाँ बताया गया है कि भीम कितने शक्तिशाली हैं\nजैसे व्यक्त किया गया.\n\nइस श्लोक में भगवान कृष्ण को हृषिकेश कहकर संबोधित किया गया है। हृषिकेश का अर्थ हृषियों के लिए है\nईशा. यहाँ। हृषिक का अर्थ है इन्द्रियाँ। वह इन्द्रियों का स्वामी है। हम में से प्रत्येक\nवह जो इंद्रियों को प्रदान करता है और उनमें निवास करता है, वह हृषिकों का स्वामी हृषीकेश है। बाल\nइस शब्द का अर्थ है सूर्य की किरण. सूर्य की किरणों में सात रंग होते हैं। इसमें सात वर्ण हैं\nभगवान हृषिकेश जो पूर्ण जीवन को आनंद प्रदान करते हैं",
  "1.23": "योत्स्यमानं अवेकशे अहम् ये एते अत्र समागतः |\n\nधार्तराष्ट्रस्य दुर्बुद्धे युद्धे प्रिय चिकिर्सवः - यहाँ एकत्र हुए हैं: जो लोग लड़ने के लिए निकले हैं,\nजो लोग उन्मत्त दुर्योधन का कल्याण चाहते थे और उसे युद्ध में कंधा देना चाहते थे,\nअर्जुन कहते हैं मैं देखूंगा।\n\n“हमें परेशान करने के लिए, मूर्ख दुर्योधन के लिए विजय चाहने के लिए मेरे विरुद्ध\nअर्जुन भगवान श्रीकृष्ण से आदेशात्मक स्वर में कहते हैं, जो लोग खड़े हैं, मुझे उन्हें अवश्य देखना चाहिए।\nयहां भगवान कृष्ण में अर्जुन कह रहे हैं, \"मुझे उन लोगों को देखना है जो मेरे खिलाफ खड़े हैं।\"\nअहंकार का गुलाम होना हमें स्पष्ट दिखाई देता है। इस अहंकार में अर्जुन स्वयं भगवान हैं\nभूल कर बात करना.",
  "1.21": "अर्जुनः उवाच- अर्जुन बोलेः\n\nसेनायोः उभयोः मधे रथम् स्थापय मेई अच्युता - 'हे कृष्ण, लुप्त हो जाओ' मेरे रथ को दोनों सेनाओं के बीच रोक दो।\n\nइस श्लोक में हमें अर्जुन के अहंकार के स्वर को ध्यान से देखना चाहिए। 'मे' का अर्थ है \"मेरा\"। यद्यपि भगवान कृष्ण स्वयं अर्जुन का रथ चला रहे थे, यहाँ अहंकार में वे एक सामान्य सारथी के रूप में कृष्ण से बात करते हैं और आदेशात्मक स्वर में कहते हैं, ``दोनों सेनाओं के बीच मेरे रथ को रोको।''\n\nयहां अर्जुन भगवान कृष्ण को अच्युत कहकर संबोधित करते हैं। अच्युत का अर्थ है भगवान जिनमें कोई आत्म-अनुशासन नहीं है, जो भक्तों की अवज्ञा को दूर कर देते हैं। अहंकार के बाहरी दिखावे के बावजूद, केवल अर्जुन की आंतरिक आत्मा सतर्क थी, और वह आंतरिक आत्मा इस नाम को अपने मुँह में खेलती थी। अहंकार ने किसी महात्मा को नहीं छोड़ा. एक बार सत्ता हमारे हाथ में आ जाए\nजब हमें यह पता चल जाता है तो हम सब कुछ भूल जाते हैं और अहंकार के गुलाम बन जाते हैं। यह अहंकार हमें पतन की ओर ले जाता है। अर्जुन एक ऋषि और भगवान कृष्ण के भक्त हैं। आइए निम्नलिखित श्लोकों में देखें कि जब भगवान कृष्ण अपने भक्त के अहंकारी हो जाते हैं तो उनकी क्या प्रतिक्रिया होती है।",
  "1.19": "स घोषः धार्तराष्ट्र नाम हृदयानि व्यादरायत् |\nनभः च पृथ्वीवेम् च एव तुमुलः व्यानुनादयन -- वह ध्वनि फर्श से टकराकर बोली।\nचिल्लाओ, धर्तराष्ट्र कहलाने वाले तुम्हारे पुत्रों की छाती फूल गई।\n\nयहां संजय धृतराष्ट्र के पुत्रों को 'धर्तराष्ट्रम्' कहकर संबोधित करते हैं। क्योंकि\nये उनका उपनाम (50978830) है. पहले \"मेरे पुत्र और पांडव\" कहकर संबोधित किया जाता था।\nयह संजयन कुहाका का धृतराष्ट्र को उत्तर है।\n\nसंजय कहते हैं: “पांडवों द्वारा विधिवत बजाया गया शंख भूमि का द्वार है\nभर-भर कर, जय-जयकार करते हुए, धर्तराष्ट्र कहलाने वाले अपने पुत्रों की छाती फाड़ डाली।” यह\nजैसा कि पहले उल्लेख किया गया है, पांडवों की अनुशासित चाल कौरवों में पहले ही घुस चुकी थी। युद्ध\nपांडवों ने शुरुआत से पहले ही कौरवों को मानसिक रूप से हरा दिया था।\n\nअथ संस्थं दृष्ट्वा धर्तराष्ट्र न कपिद्वजः |\nप्रवृत्तिते वर्णसंपथे धनुरुद्यम्य पाण्डवः",
  "1.33": "येषां अरथे कांक्षितं नः राज्यं भोगः सुखनि च।\nते इमे अवस्थितः युद्ध प्राणान त्यक्त्वा धनानि च - राज्य किसके लिए है? वह सुख और भोग के लिए धन और वस्त्र को छोड़कर युद्ध के मैदान में खड़ा है।\n\nयदि यह राजसी सुख आवश्यक है तो किसके लिए है? हमें अपने सभी बड़ों के बीच खुश रहना चाहिए। हम उन सभी को मारकर खुश क्यों हैं?",
  "1.22": "यावत् एतान् निरीक्षे अहं योधुकामन् अवस्थितन् |\nकै: मया सह योद्धव्यं अस्मिन राणा समुद्यमे - मैं उन लोगों की ओर मुड़ा जो प्रतीक्षा करने के लिए एकत्र हुए थे।\n\nनज़र डालना। इस लड़ाई में कौन मेरे साथ है और मैं किसके साथ हूं\nइसके लिए इंतजार करना चाहिए?\n\nमहाभारत युद्ध इतिहास में दर्ज पहला वैश्विक युद्ध था। ऐसा युद्ध\nअर्जुन सोफे पर खड़े होकर अहंकार से बात कर रहे हैं. वह यहां श्रीकृष्ण में एकत्रित हुए\nमुझे उस पर एक नजर डालनी है. जो मेरे और मेरे विरुद्ध युद्ध करने आये थे\nउन्होंने कहा, ''मुझे देखना है कि मेरी तरफ से कौन मुझसे लड़ने आया है.''\nयहाँ वह यह कहते हुए अहंकारी है, \"मुझे उन लोगों को अवश्य देखना चाहिए जो मुझसे लड़ने आए हैं।\"\nविडम्बना है. यह एक अहंकारपूर्ण कथन है कि वह एक महान नायक है और उसके सामने एकत्र हुई यह सेना मेरे लिए कुछ भी नहीं है।\n\nयोत्समाननववेक्शे5हं य एत*त्र समागतः |\nधार्तराष्ट्र सय दुर्बुद्धेरूधे प्रियचिकिर्षवः",
  "1.24": "संजय उवाच- संजय ने कहा:\n\nएवम् उक्तः हृषीकेश गुडाकेशेन भारत |\n\nसेनायोः उभयोः मधे स्थापयित्व रथ उत्तमम् --। हे भरतवंश के राजा,\nगुडाकेश की बात सुनकर हृषिकेश ने बड़े टेरा को दोनों सेनाओं के बीच रोक दिया।\n\nइंद्रियों के स्वामी भगवान कृष्ण ने बिना कुछ बोले दोनों सेनाओं के बीच रथ रोक दिया।\nयहां से आगे. हम सभी भगवान कृष्ण के हैं। मनोचिकित्सा प्रगति पर है\nकस्टम(?9)€0116880)) पाया जा सकता है। अहंकार एक मानसिक अवस्था है. हम हैं\nऐसी स्थिति से बाहर निकलने के लिए हमें मनोवैज्ञानिक उपचार की आवश्यकता होती है। कृष्ण यहाँ यही करते हैं\nदिखाया है ऐसे भगवान कृष्ण को हम मनोविज्ञान का जनक कहते हैं (53(॥6॥08 76168101081)।\nकॉल करना गलत नहीं है. गीता के प्रथम अध्याय में मनोविज्ञान के कई विषय छुपे हुए हैं।\n\nइस श्लोक में कृष्ण को हृषिकेश और अर्जुन को गुडाकेश कहकर संबोधित किया गया है।\nगुडाकेश का अर्थ है वह नायक जिसने नींद पर विजय प्राप्त कर ली।",
  "1.37": "तस्मात् अर्ह वयं हंतुम् धार्तराष्ट्रं स्व बंधवान्।\nस्व जन्म हि कथं हत्वा सुखिनः सम माधव - इसलिए हमें अपने आश्रितों धर्तराष्ट्र को नहीं मारना चाहिए। हम अपनों को मारकर कैसे खुश रह सकते हैं, माधा?",
  "1.25": "भीष्मः द्रोण प्रग्मतः सर्वेषाम् च महीकेसेतम |\n\nउवाच पार्थ पश्य एतं समावेतां कुरुण इति - भीष्म, द्रोण और अन्य राजा\nकृष्ण प्रत्यक्ष दर्शन में रथ रोककर कहते हैं, हे पार्थ, इस भीड़ को देखो\n\"कुरु\"।\n\nभगवान श्रीकृष्ण भीष्म-द्रोण अर्जुन के रथ के समान रथ को दोनों सेनाओं के बीच ले आये\nऔर सभी राजा स्पष्ट दृष्टि से भांडव्य की प्रशंसा करते हुए खड़े हो गए\nवह कहते हैं: \"हे पार्थ, यहाँ इकट्ठे हुए अपने 'कुरुओं' को देखो।\"\n\nयह श्रीकृष्ण की अद्भुत मनोचिकित्सा है(6):€10 (1€/80)). यहाँ अर्जुन की मानसिक स्थिति की परीक्षा है\nजा रहा हूँ अर्जुन एक राजा है. उनका मूल कर्तव्य धर्म के लिए लड़ना है और\nशासन करना. इस प्रकार वह अपना कर्तव्य निभाते हुए धर्म के विरुद्ध खड़ा हो जाता है\nचाहे कोई भी हो, उन्हें दंड देना उसका कर्तव्य है। वह एक जज की तरह हैं. यहाँ मेरा है\nपरिवार के सदस्यों, मेरे रिश्तेदारों, मेरे दोस्तों के साथ भेदभाव नहीं किया जाना चाहिए। ऐसे जिम्मेदार\nकाम में लगे अर्जुन को जब अपने सगे संबंधियों और गुरु के दर्शन हुए तो कैसा लगा\nआइए अगले श्लोक में देखें कि वे क्या कहते हैं।",
  "1.30": "गाण्डीवं श्रमसते हस्तत् त्वक् च एव परिदह्यते |\nनच शक्नोमि अवस्थतुं भ्रमति इव च मेइ मनः -- गांडीव हाथ से फिसल रहा है, चमड़ा।\nआग लगी है स्थिर नहीं रह सकता. मेरा दिमाग चकरा रहा है.\n\nजब कोई व्यक्ति अपना आत्मविश्वास खो देता है, तो उसका आंतरिक आत्म शारीरिक रूप से कैसा महसूस करता है?\nजो उभर कर सामने आता है उसे यहां देखा जा सकता है. अविश्वासी व्यक्ति ने अपनी मुट्ठी भींच ली\nपकड़ नहीं सकते अर्जुन की हालत यहां भी वैसी ही है. वह कहता है: “गांडीव मेरे हाथ में है\n“फिसलते-फिसलते मेरा पूरा शरीर ऐसे तड़प रहा है मानो आग लग गई हो।”\nअभिव्यंजक। एक बार मन स्थिर नहीं हुआ तो शरीर भी स्थिर नहीं रह सकता। इसी प्रकार यदि शरीर स्थिर नहीं है\nमन को स्थिर नहीं किया जा सकता. \"इस रथ में नहीं बैठ सकते. मन\nभ्रमित,'' अर्जुन ने कृष्ण से विलाप किया।",
  "1.18": "जी\n\nद्रुपदः द्रौपदेयः च सर्वः पृथिवीपते |\nसौभद्रः च महाबाहुः शंखं दध्मुः पृथक पृथक -- ​​हे पृथ्वी धारण करने वाले; द्रुपद, द्रौपदी के\nबच्चों सहित महापराक्रमी अभिमन्यु। और इसलिए हर कोई, एक-एक करके\n\nउन्होंने एक शंख भी दिया.\n\nयदि आप यहां ध्यान से देखें, तो पांडवों का अनुशासन (11€1011%6) स्पष्ट दिखता है। कौरवों का\nशिविर से शंख की ध्वनि के उत्तर में पांडवों ने अनुशासनपूर्वक कहा।\nशंख का निर्माण नियमित रूप से किया जाता है। मनोवैज्ञानिक रूप से कहें तो, एक अनुशासित छोटी सेना\nयहां हम देखते हैं कि एक अनुशासनहीन सेना की छाती कैसे कांप सकती है\nभगवान के प्रति बिना किसी अहंकार के, भगवान के प्रति पूर्ण समर्पण पाया जा सकता है\nरथों पर सवार होकर, पांडव सेना धर्मयुद्ध के लिए मानसिक रूप से पूरी तरह तैयार थी।\nअहंकार का नशा, सत्ता की लालसा, मानसिक स्थिरता खोना, भगवान के विरुद्ध।\nदुर्योधन के नेतृत्व में कौरव सेना पहले ही आत्मविश्वास खो चुकी थी।\nयहाँ एक और विचित्रता देखने को मिलती है कि पाण्डवों की संख्या क्रम से अठारह है\nशंख बनाया. अंकज्योतिष पर नजर डालें तो वर्णमाला पद्धति में अट्ठारह का मतलब अठारह होता है\n\nके\nविजय जे8 यासा। वर्णमाला में पहला अंक एकल अंक है, दूसरा दशमलव अंक है। तो जे-\n\nया का मतलब इक्यासी नहीं-अट्ठारह है। पांडवों के पास विजय का प्रतीक 'अठारह शंख' हैं\nभगवत गीता का अठारहवाँ श्लोक शिविर में बजते ही समाप्त हो गया!\n\nसघोषपशो धर्तराष्ट्र नाम हृदयानि व्यादरायत् |\nनभश्च पृथिवीं चैव तुमुलो व्यानुनादयन",
  "1.29": "अर्जुनः उवाचा--अर्जुन ने कहाः\n\nदृष्टा इमाम स्वजनं कृष्ण युयुत्सुम समुपथिथम ॥\n\nसिद्दन्ति मम पगराणि मुखं च परिशुष्यति |\n\nवेपथुः च शरीर में रोमा हर्षः च जयते -- कृष्ण, हम जो यहां युद्ध की भावना से एकत्र हुए हैं\nजब मैं लोगों को देखता हूं तो मेरे अंग कांपने लगते हैं। मुँह भी सूख जाता है. मेरा सारा शरीर\nयह कोमल और कांपने वाला है.\n\nअर्जुन कहते हैं: “अपने बड़े भाइयों को यहाँ देखकर मेरे अंग एकत्रित हो गए\nछेड़खानी हमें आज इस युद्ध के मैदान में एक दूसरे के साथ दोस्ती करके रहना है\nजब मैं उन्हें आमने सामने खड़े होकर लड़ने लगता हूँ तो मेरा चेहरा शर्म से लाल हो जाता है।\n\nहम बुद्धिमान लोग ऐसे घिनौने काम में लग गये हैं। यह निर्णय हम स्वयं करें\nहम इसके प्रति प्रतिबद्ध होकर युद्ध के मैदान में नहीं खड़े हैं। मेरा दिल हमें देखकर मुस्कुरा रहा है. चेहरा\nरूखी-सूखी बात नहीं कर सकते. हम कितने नीचे गिर गये हैं. मैं इसके बारे में सोचकर कांप उठता हूं।”\nवह कहता है। यहाँ अर्जुन के शब्दों में पहले दया, फिर लज्जा, फिर भय, फिर\nहम विस्मय को व्यक्त होते देखते हैं।\n\nगाण्डीवं श्रमसते हस्तत् त्वक् चैव परिदह्यते |\nनच शक्नोम्यवस्थतुं भ्रामक च मे मनः",
  "1.34": "आचार्यः पितरः पुत्रः तथा एव च ​​पितामहः |\nमातुलः श्वासुराः पुत्रः सलाह संबिः तथा - गुरु, पिता और माता की तरह,\nबच्चे. इसी तरह, दादा-दादी, सास-ससुर, साले-बहनोई, पोते-पोतियाँ, सास-ससुर\n\nऔर नेंटेरिश्तस।\n\nअर्जुन ने कृष्ण से पहले अपने रिश्तेदारों, परिवार के सदस्यों की सूची का दावा किया।\nगुरु, पैतृक रिश्तेदार, बच्चे, दादा, ससुर, बहुएँ, पोते-पोतियाँ,\nपत्नी के भाई-बहन और रिश्तेदार। इस प्रकार केवल उनके रिश्तेदारों की सूची दी जा रही है\nयहां यह स्पष्ट है कि अर्जुन अपने सामाजिक कर्तव्य को भूलकर व्यक्तिगत बात कर रहे हैं।\n\nएथनं हन्थुमिच्छामि फ्लैटोएप मधुसूदन |\nअपि त्रैलोक्यराज्यस्य हितो किं नु महजिता",
  "1.26": "स्वशुरन् सुहृदश्चेव सेनायोरुभयोरावपि।\n\nतत्र अपश्यात् स्थितं पार्थः पित्य-न या पितामहं |\n\nआचार्य मातुलं भ्रातृहं पुत्रं पौत्रं सखीन तथा ॥\n\nश्वशुरन् सुहृदः च एव सेनायोः उभयोः अपि - वहाँ दोनों ओर की सेनाएँ हैं।\nअर्जुन ने भीड़ देखी.    पिता, दादा, शिक्षक,\nभाई-बहन, भाई-बहन, बच्चे, पोते-पोतियाँ, जीवनसाथी\nससुराल वाले और दोस्त.\n\nजैसे ही कृष्ण ने अर्जुन के प्रिय रिश्तेदारों के सामने रथ रोका, अर्जुन ने उपस्थित सभी लोगों का अभिवादन किया।\nदेखता है कि उसके पिता, जो अब उसके सामने खड़े हैं, वह उसके बराबर है जिसने इतने लंबे समय तक गर्व से बात की है।\nदादा-दादी, शिक्षक, बहनोई, चचेरे भाई-बहन, बच्चे, पोते-पोतियाँ,\nमिलनसार जीवनसाथी, ससुराल वाले, शुभचिंतक, सभी दोनों तरफ दिखाई देते हैं।\n\nयदि हम इस श्लोक को ध्यान से देखें तो अर्जुन के पास युद्ध के मैदान में कई महत्वपूर्ण लोग हैं\nयह भी देखा गया कि वहाँ केवल गुरु वरिष्ठजन, रिश्तेदार और प्रियजन ही थे। यहां उनका एक रिश्तेदार है\nप्रेम जागृति स्पष्ट है। कर्तव्यपरायण लोकसेवी राजा के प्रति भाईचारे का प्रेम |\nऐसा नहीं। जो प्रजापालक है उसके लिए प्रजापालन ही मूल धर्म है। उसे इससे कभी छुटकारा न मिले\nप्रबंधित किया जाना चाहिए. \"मेरे रिश्तेदार, मेरा परिवार\" इस ​​तरह काम करते हुए।\nकोई भेदभाव नहीं हो सकता.\n\nतं समेक्ष्य सकौन्तेयः सर्वान् बन्धुनावस्थितं",
  "1.35": "एतां हन्तुम इच्छामि घ्नतः अपि मधुसूदन |\nअपि त्रैलोक्य राज्यस्य हितो किम् नु महीगतते - हे मधुसूदन, भले ही तुम मुझे मार डालो\nमैं उन्हें मारना चाहता हूं. तीनों लोकों पर कब्ज़ा करने के लिए भी. पृथ्वी के बारे में क्या?\n\nमैं उसे मारना नहीं चाहता. यदि वे मुझे मारने भी आएं, तो भी मैं वह हूं\nमैं मार नहीं सकता भले ही मैं संपूर्ण ब्रह्मांड पर कब्ज़ा कर लूं, फिर भी मैं लड़ नहीं सकता।\nतो ज़मीन के इस टुकड़े के लिए क्यों लड़ें?\n\nयहां अर्जुन भगवान कृष्ण को 'मधुसूदन' कहकर संबोधित करते हैं। मधु का अर्थ है आनंद।\nमधुसूदन का अर्थ है. सुख का नाश करने वाला... धर्म का मार्ग छोड़कर अधर्मी बन जाना,\nवह अभिमान से चलने वालों के सुखों को नष्ट कर देता है, और सज्जनों का उद्धार करता है\nआनंदरूपी भगवान मधुसूदन। \"सात्विकों को सुख देना और तामसी लोगों के सुख को नष्ट करना\nआप क्या करने आये थे?\" इस सम्बोधन में है। यहाँ \"युद्ध\" है\nमैं असमंजस में हूं कि ऐसा करूं या नहीं,'' अर्जुन ने कहा\nकृष्ण में प्रकट होता है.\n\nनिहत्या धर्तराष्ट्र नन्ह का प्रीतिः स्वज्वनार्दन |\n\nपापमेव8श्रयेदस्मान् हत्वैतनतथैणः।",
  "1.39": "कथं न ग्नेयं आसा 6बिह पापत् अस्मात् निवर्तितुम् |\nकुलक्षय कृतं दोषं प्रापश्यधि जनार्दन- हे जनार्दन, कुल के लुप्त होने से होने वाली हानि।\nहम यह पूर्वानुमान कैसे नहीं लगा सकते कि हमें ऐसी गलती से बचना चाहिए?\n\nयदि हम नहीं जानते कि दुर्योधन और हम इतना बड़ा पाप न करें\nक्या अंतर है? जन्म और मृत्यु के बंधन से बचाने वाले, हे जनार्दन!\nमैं उस त्रुटि को स्पष्ट रूप से देख सकता हूँ जो कुल को नष्ट कर देगी। युद्धोत्तर भारत की एक तस्वीर\nमेरी आंख पकड़ रहा है. युद्ध से होने वाले नुकसान को जानते हुए भी युद्ध में कूद पड़ने की बुद्धिमत्ता\nदिखा देंगे तो क्या हम दुर्योधन की तरह अपमानित नहीं हो जायेंगे? ये अर्जुन है\n\nवा\nप्रश्न",
  "1.38": "यदि अपि एते न पश्यन्ति लोभा उपहता चेतसः।\nकुलक्षय कृतं दोषं मित्रद्रोहे च पाठकम् - ये सभी हृदय लालच की चपेट में हैं।\nवह कबीले के विलुप्त होने और सहयोगियों के विश्वासघात से होने वाले नुकसान को नहीं देखता है।\n\nपैसे की चाहत और लालच में अंधे होकर उनके दिमाग ने सोचने की शक्ति खो दी है।\nइससे नरसंहार होगा. सम्पूर्ण भरतवंश नष्ट हो जायेगा। हम भाई हैं\nउन्हें एक-दूसरे के साथ दोस्त की तरह रहना था। लेकिन हम एक दूसरे से नफरत करते हैं.\nयह विश्वासघात है.\n\nयहाँ 'मित्र' शब्द का प्रयोग हुआ है। सच्चा मित्र कौन है? हम कब खतरे में होंगे?\nयह मान लें कि हमारे सामने, बिना किसी पुरस्कार की पूर्व इच्छा के, जीवन है\nजीवनदाता 'मित्र' है।\n\nकथं च ज्ञेयमास्कमविः पापदस्मान्निवर्तितुम् |\nकुलक्ष्यकृतं दोषं प्रापश्यद्धि राजनार्दन",
  "1.45": "अहो बात महत् पापं कर्तुम् व्यवसितः वयम्।\nयत् राज्यसुखलोभेण हन्तुम स्वजनं उद्यतः -- अफसोस! हमने कितनी बड़ी गलती की है! वह स्वामित्व के सुख के लालच में हमारे लोगों को मारने नहीं जा रहा है!\n\nइधर अर्जुन रुंधे स्वर में कहता है - \"हाय.. हमारे सामने कितनी बड़ी त्रासदी हो रही थी, कितना बड़ा पाप हो रहा था? यह कैसी गलती होने वाली थी? हम बहुत बड़ी गलती कर रहे थे। हम राज्य के सुख के लालच में अपने ही लोगों को मार डालते और पूरी जाति को बर्बाद कर देते।\"\nवह है।",
  "1.32": "न कांक्षे विजयं कृष्ण न च राज्यं सुखनि च |\n\nकिं न राज्येण गोविंदा किं भोग्यैः जीवितेन वा -। कृष्णा, मैं जीत गया\nनहीं चाहता; कोई राजकुमारी नहीं; ख़ुशी भी. गोविंदा, हमारे पास क्या है?\nविलासिता के बारे में क्या? यदि आप जीवित रहे तो क्या होगा?\n\nअर्जुन ने धर्मरायण की ओर से युद्ध किया। न तो शत्रुता का अंत और न ही कोई समाधान\nयदि लिया भी जाए तो यह अंततः धर्म राय के विवेक पर निर्भर होना चाहिए। यहाँ\nअर्जुन ऐसे बोलता है मानो वह निर्णायक हो। \"किसे चाहिए इस जीत की कृष्णा,\nवह कहते हैं, \"मैं जीत नहीं चाहता, मैं गुरुहिरी को मारना चाहता हूं, मैं जीत नहीं चाहता।\"\nश्लोक में वह फिर से खुद को \"कृष्ण\" कहकर संबोधित करते हैं। यहां \"कृष्ण\" का अर्थ खींचने वाला है। उसका\nइसका मतलब है जो सुंदरता से आकर्षित और उत्साहित करता है। \"तुम दुनिया का आकर्षण हो\nआप हमें, इस अठारह अक्षौहिणी सेना को युद्धभूमि में क्यों खींच ले आये?\nअर्जुन भावार्थ में बोलते हैं।\n\nअर्जुन आगे कहता है: \"हमें इस राज्य को पाने के लिए क्या चाहिए? यह राज्य\nभोग प्राप्त करने और उसका आनंद लेने से क्या फायदा?'' यहां भगवान अर्जुन हैं\nसंबोधन \"गोविंदा\"। गोविंदा का अर्थ है वेदों का, वेदों का पाठ करने वाला\nजो पूर्ण अर्थ जानता है, जो पृथ्वी पर आता है, जो गायों आदि की देखभाल करता है। कृष्ण के लिए इतना ही\nदुष्ट राक्षसों और राजाओं का वध करने वाला। लेकिन सिंहासन तक कहीं नहीं\nउसने गायों को ग्वालों के साथ मिलाकर रखा था। यहां अर्जुन कहते हैं, ''मैं आपके जैसा हूं\nवह इस अर्थ में बोल रहे हैं कि उन्हें राजगद्दी बनने की कोई चाहत नहीं है\nआप मुझसे युद्ध के लिए क्यों आग्रह कर रहे हैं? इसी अर्थ में उन्होंने भगवान को 'गोविंदा' कहा।\nसंबोधित किया।\n\nयेषामार्थे कांक्षितामनो राज्यं भोगः सुखनि च।\n\nता इमेयवस्थिता युद्धे प्राणांस्क्यक्त्वा धनानि च",
  "1.43": "दोषके एतैह कुलघ्नानं वर्णसंकर कारकेः |\nउत्सा दयन्ते जातिधर्मः कुलधर्मः च शवस्तः-जिससे समाज का विघटन होता है।\nआदिवासियों की ऐसी ही गलतियों के कारण सहज धर्म और अमर आदिवासी धर्म की स्थापना हुई।\n\nसमाज पर युद्ध का सीधा प्रभाव नेतृत्वहीन, युवाहीन समाज पर पड़ता है।\nपुरुष-महिला अनुपात में अंतर. इसे ठीक करने में कितने साल लगेंगे? हम हैं\nयदि आप महाभारत युद्ध को देखें तो वहां कम से कम पचास लाख लोग मारे गये थे। जैसे कि\n\nअर्जुन कहते हैं कि हम महायुद्ध द्वारा सम्पूर्ण समाज का नाश करने वाले कुलकान्तकार बनेंगे\nचिंता “जब समाज की व्यवस्था नष्ट हो जाती है, तो प्रकृति नष्ट हो जाती है, और व्यक्तिगत जीवन भी नष्ट हो जाता है\nचरित्र विकास के बिना व्यक्तित्व विकास नष्ट हो जाता है। शाश्वत मूल्य का सामाजिक धर्म\nनष्ट हो जायेंगे. समाज द्वारा अनादिकाल से स्वीकृत निश्चित धर्म नष्ट हो जायेगा।\nअर्जुन कृष्ण के समक्ष अपना तर्क प्रस्तुत करते हैं।",
  "1.46": "यदि मम अप्रतिकारं अनारं अर्पणयः |\nधर्तराष्ट्र ह्राणे हनुः तत् मेइ क्षेम तरं भवेत् - जो एक बार भी खड़ा होकर युद्ध नहीं करता,\nयदि धर्तराष्ट्र मुझे निहत्था मार डालेगा तो यह मेरा भाग्य होगा।\n\nमेरा कोई बदला नहीं है. अगर वे मुझे मारने आएंगे तो मैं मारूंगा\nकोई पलटवार नहीं. मुझे लगता है कि मुझे तलवार से मार डालना ही मेरी नियति है\nमर जायेंगे ऐसी त्रासदी के साथ क्यों जियें? कुछ तो सही है, मैं युद्ध नहीं चाहता. वह है\nअर्जुन अपना हाथ ऊपर उठाता है।\n\nयुद्ध की शुरुआत में उन्होंने दारपा से कहा,\nअर्जुन- एक क्षण में विलीन हो गये। ये बात उसके अवचेतन मन में छुपी होती है\nबैठने का एहसास. कृष्ण ने अपने मनोवैज्ञानिक उपचार से इसे पूरी तरह हटा दिया (?9)6€8086180))।\nगिरा दिया. मानसिक रूप से परेशान व्यक्ति के लिए यह पहला इलाज है। आदमी का\nवह दुनिया को यह दिखाने वाले पहले महान मनोवैज्ञानिक थे कि मनोविकृति को कैसे ठीक किया जा सकता है\nकृष्ण. यदि कृष्ण ने अर्जुन के प्रियजनों के सामने रथ न रोका होता तो यह सब होता\nविचार. यह बात उसके दिमाग से निकल ही नहीं रही थी. भगवान कृष्ण यह मनोचिकित्सा,\nमनोविज्ञान को हम तभी समझते हैं जब हम उसे दर्शनशास्त्र के साथ समझते हैं और उसका विश्लेषण करते हैं।",
  "2.1": "संजय उवाच —\nतमेव कृपया आविष्टं अश्रुपूर्णाकुलेक्षणम् ।\nविषीदन्तं इदं वाक्यं उवाच मधुसूदनः ॥\n\nकरुणा से आविष्ट, अश्रुपूर्ण-आकुल नेत्र, विषादग्रस्त उस अर्जुन को देखकर मधुसूदन ने यह वाक्य कहा।\n\nसंजय वर्णन करता है — कृष्ण ने अर्जुन को देखा, करुणा में डूबे, आँसू से आँखें भरी और मन उदास। उस हालत में मधुसूदन ने उपदेश का आरम्भ किया। 'मधुसूदन' — मधु-दैत्य का नाश करने वाले — अज्ञान के मधुर भ्रम का भी नाश करने वाले।",
  "1.20": "हृषीकेशं तदा वाक्यमिदमह महीपते।\n\nअथ सिस्तामथन दृष्ट्वा धार्तराष्ट्रं कपिद्वजः |\n\nप्रवृत्तिते वर्णसंपथे धनुः उजाग्य पाण्डवः ॥\n\nहृषीकेशं तदा वयकं इदं अहा महीपते - हे राजन, हनुमान के द्वार अर्जुन।\nधृतराष्ट्र को व्यूहबद्ध देखकर कृष्ण ने युद्ध करने के लिए अपना धनुष खींच लिया\nइस बारे में उन्होंने ये बात कही\n\nयुद्ध तब शुरू होता है जब दोनों पक्ष सहमत हो जाते हैं। इस मामले में, अपने रथ में\nअर्जुन, जिसके पास अंजनेय, इंद्रियों के स्वामी, भगवान कृष्ण (हृषिकेश) की विशेष उपस्थिति है।\nबारे में बात करना\n\nइधर अर्जुन के रथ में प्राणदेव की विशेष उपस्थिति थी। हमारे शरीर नामक रथ में भी\nजीवन हमेशा 'ईश्वर की उपस्थिति में' प्राण द्वारा संरक्षित होता है। जहाँ जीवन है, वहाँ ईश्वर है\n\nनिकटता पौराणिक रूप से, अर्जुन के रथ में अंजनेय का सन्नी धन होने का कारण पवन देवता थे।\nदूसरा रूप है भीमसेन. जब भीमसेन सौगंधिका फूल लाने गया तो हनुमान ने उसका पीछा किया\nपूँछ से रुक गया. इस अवसर पर हुए कार्यक्रम में विशेष रूप से आंजनेय स्वयं अर्जुन थे\nवह भीमसेन से वादा करता है कि वह रथ में मौजूद रहेगा। इधर भीमसेन और\nअंजनेय प्राणदेव का दोहरा रूप हैं (राम और परशुराम की तरह)।\n\nअपने ध्वज में अंजनेय के सन्निधान, हाथ में गांडीव, सारथी कृष्ण, महा के साथ\nपराक्रमी भीमसेना. अर्जुन, जो इस प्रकार युद्ध के लिए तैयार है, घमंड से ग्रस्त है (5_0)। यह\nवे अहंकारपूर्वक कृष्ण के बारे में कहते हैं:\n\nअर्जुन उवाचा टी\n\nसेनायोरुभयोर्मध्ये रथं स्थापय मये*च्युत | 21\n\nअर्जुनः उवाच- अर्जुन बोला\nसेनायोः उभयोः मधे रथम् स्थापय मेई अच्युत - दो सेनाओं के 'अविनाशी कृष्ण'।\nमेरे रथ को बीच में ही रोक दो।\n\nइस श्लोक में हमें अर्जुन के अहंकार के स्वर को ध्यान से देखना चाहिए। 'मई' यानी\n\"मेरा'। यद्यपि भगवान कृष्ण ने स्वयं अर्जुन के रथ की कमान संभाली थी, फिर भी वे यहाँ अहंकार में हैं\nएक सामान्य सारथी के रूप में कृष्ण को संबोधित करते हुए, “दोनों सेनाओं के बीच में मेरे रथ को रोको\nवह आदेशात्मक स्वर में कहता है।\n\nयहां अर्जुन भगवान कृष्ण को अच्युत कहकर संबोधित करते हैं। अच्युत का अर्थ है स्वयं को हटाए बिना,\nभगवान जो भक्तों के पापों का नाश करते हैं। यद्यपि बाह्य रूप से अभिमानी, अर्जुन\nकेवल अंतरात्मा ही सचेत थी, उस अंतरात्मा ने यह नाम अपने मुख में बजाया। अहंकार\nकोई महात्मा पीछे नहीं छूटा. एक बार जब हम जान जाते हैं कि हमारे हाथ में शक्ति है तो हम सब कुछ करते हैं\nहम भूल जाते हैं और अहंकार के गुलाम बन जाते हैं। यह अहंकार हमें पतन की ओर ले जाता है। अर्जुन\nमहाजनी और भगवान कृष्ण के भक्त। जब भगवान कृष्ण का भक्त अहंकारी हो गया तो उनकी क्या प्रतिक्रिया थी?\nआइए निम्नलिखित श्लोकों में देखें कि वह क्या दर्शाता है।\n\nयावदेथान निरीक्षेहहं योधुकामनावस्थितन् |\nकैरमया भी योद्धव्यमस्मिन रणसमुद्यमे",
  "1.27": "कृपया मुझे क्षमा करें *यह बहुत बुरा डम्ब्रावीथ है।\n\nतं समेक्ष्य सः कौन्तेयः सर्वान् बन्धुं अवस्थितं |\nकृपाय पराया अविष्ट ह विषदं इदं अब्रवीथ - कि वे सभी रिश्तेदार एक साथ आ जाएं।\nयह देखकर अर्जुन करुणा से भर गया और हर्षित हो गया - ऐसा कहा\n\nउन सभी भाइयों को एकजुट देखकर अर्जुन करुणा से द्रवित हो उठे।\nदुःख के कारण, वह कृष्ण पर अपना प्रभाव डालता है।\n\nयहीं से अर्जुन अनेक प्रकार से भगवान श्रीकृष्ण को पुकारेंगे\nहम देखेंगे. आइए अगले छंदों को देखने से पहले यहां थोड़ा विश्लेषण करें।\nकुछ लोग गीता पढ़ते समय भगवान कृष्ण की गति को समझ नहीं पाते हैं। “अरे-कैसे मेरे रिश्तेदार\nयदि अर्जुन पूछता है, \"लड़ो,\" तो कृष्ण कहते हैं, \"लड़ो।\" यह\nन्याय का प्रश्न अधिकांश लोगों को परेशान करता है। यहां हमें यह ध्यान देने की आवश्यकता है कि अर्जुन\n\nअगर ये बात एक आम इंसान के तौर पर कही जाए तो यकीनन हमें सहमत होना चाहिए. लेकिन\nयहां वह राजा हैं जो भरतखंड के रक्षक के रूप में धर्म के लिए लड़ने के लिए धर्म राय के साथ खड़े थे।\nवे सहमत होते अगर उन्होंने कहा होता, \"भारत खंड के लोगों को हमारे लिए नहीं मरना चाहिए\"।\nलेकिन उन्होंने ऐसा नहीं कहा. वहां उसे केवल रिश्तेदार ही दिखे। राजा के लिये धर्म का पक्ष |\nएकमात्र व्यक्ति जो खड़ा है वह एक रिश्तेदार है। जो भी धर्म के विरुद्ध खड़ा होता है वह अपराधी ही होता है। उन्हें\nदण्ड देना राजा का परम धर्म है। न्याय के पद पर खड़ा एक न्यायाधीश, उसने अन्याय किया है\nजैसे किसी रिश्तेदार को 'मेरा पक्ष' होने के लिए माफ नहीं किया जा सकता, वैसे ही यहां राजा को भी माफ नहीं किया जा सकता\nजो देखना चाहिए वह धर्म है, रिश्तेदारी नहीं।\n\nअगला। अर्जुन (4/8013015) भगवान श्रीकृष्ण अनेक प्रकार से\n(8051411360) व्यवस्थित होता दिख रहा है। लेकिन श्रीकृष्ण हर जगह इस प्रश्न का सीधा उत्तर हैं\nनहीं देता क्योंकि यदि उसने ऐसा किया होता तो वह अवांछित विवाद का दोषी होता\nयह डालने जैसा था. अर्जुन, जो मानसिक भ्रम की स्थिति में है, उसके द्वारा कहे गए प्रत्येक शब्द को सुनता है\nएक अच्छे श्रोता की तरह पूछें, फिर कृष्ण के साथ एक मानसिक रोगी की तरह व्यवहार करें\nहम देखते हैं क्या हुआ.\n\nआइए इन बातों को ध्यान में रखते हुए अगले श्लोक पर एक नज़र डालें।",
  "2.3": "क्लैब्यं मा स्म गमः पार्थ नैतत्त्वय्युपपद्यते ।\nक्षुद्रं हृदयदौर्बल्यं त्यक्त्वोत्तिष्ठ परन्तप ॥\n\n'हे पार्थ, नपुंसकता को मत प्राप्त हो — यह तुझमें नहीं शोभता। हे शत्रुतापन, क्षुद्र हृदय-दुर्बलता छोड़कर उठो।'\n\nकृष्ण का पहला आदेश — उठो। क्लैब्यम् — नपुंसकता, कायरता। परन्तप — शत्रुओं को तापित करने वाला। कृष्ण अर्जुन की वास्तविक प्रकृति याद दिलाते हैं — 'यह तुझे शोभा नहीं देता।' मन की दुर्बलता ही संकट का कारण है — उसे तज दो।",
  "1.41": "अधर्म अभिभावत् कृष्ण प्रदुष्यन्ति कुलस्त्रियः\nस्त्रीषु दिष्टसु वर्षेय जयते वर्णसंकरः - हे वर्षेय, अधर्म के आक्रमण से।\n\nलड़कियाँ समाज में भटक जाती हैं। उसके कारण समाज में विभ्रम उत्पन्न होता है।\n\nयदि युद्ध हुआ तो उसमें सभी युवा मर जायेंगे। अराजकता समाज पर आक्रमण करती है।\nयुवा विहीन समाज का निर्माण होगा। सामाजिक रूप से महिलाएँ असुरक्षित हो जाती हैं। इसका\nइसका परिणाम उसकी मासूमियत का दुरुपयोग है। इससे समाज में भ्रम की स्थिति पैदा होगी\nअर्जुन कहते हैं.\n\nयहां वर्णसंकर का अर्थ जीवन के रंग या स्वभाव का बिगड़ना है। एक महिला उसके साथ जबरदस्ती की जाती है\nशास्त्रों में उल्लेख है कि उच्च शिक्षा मन के विरुद्ध नहीं दी जानी चाहिए। उसके कारण\nउसके गर्भाशय पर असर पड़ता है. इसका असर गर्भ में पल रहे बच्चे पर पड़ता है।\nजब एक महिला अपनी इच्छा के विरुद्ध खुद को व्यस्त रखती है; बहुत से आदमियों की संगति करके; अगला\nसंतान पर भयंकर प्रभाव पड़ता है। वह किसी की नहीं सुनता, वह किसी के नियमों के आगे नहीं झुकता\nसंतान विक्षिप्त होने की संभावना है। यह वर्णसंकर है जिसके बारे में अर्जुन यहां बात कर रहे हैं।\n\nयहां अर्जुन कृष्ण को 'वार्षजेय' कहकर संबोधित करते हैं। वृष्टि, यादव वंश के सबसे बड़े राजा थे।\nउसी वंश में कृष्ण वर्षेय अवतरित हुए। वेदों में इस नाम का उल्लेख मिलता है। चाहता था\nभगवान वार्थोया देवताओं के स्वामी हैं जो अभिषा देने वाली वरिष्ठ शक्तियाँ हैं। “हर किसी का पसंदीदा\nआप जो धर्म को पूरा करने, स्थापित करने के लिए आये हैं, आप इस युद्ध को क्यों नहीं रोक रहे हैं” आवाज ने कहा।\nअर्जुन इसी पते पर हैं.",
  "1.73": "येषां अरथे कांक्षितं नः राज्यं भोगः सुखनि च।\nते. इमे अवस्थितः युद्ध प्राणान त्यक्त्वा धनानि च - सिंहासन किसके लिए है? ख़ुशी-\n\nसुख के लिए उसने धन-दौलत का मोह त्याग दिया है और युद्ध के मैदान में खड़ा हो गया है।\n\nयदि यह राजसी सुख आवश्यक है तो किसके लिए है? हम सब बुजुर्गों के बीच में हैं\nहमें खुश रहना चाहिए. हम उन सभी को मारकर खुश क्यों हैं? किसके लिए\n\nजो लोग इस जीवन का, राज्य का सुख चाहते हैं, उन सभी ने जीवन की इच्छा छोड़ दी है,\nवे हमारे सामने सब कुछ खोने को तैयार खड़े हैं।\n\nआचार्य पितरः पुत्रस्तथैव च पितामहः।\n\nमातुलः स्वशुरः पौत्रः सलाह संबिनिस्टथा",
  "1.31": "निमित्तनि च पश्यामि दुःखनि केशव |\nन च श्रेयः अनुपश्यामि हत्वा स्वजनम् अहावे -- केशव, मैं 6 अपशकुन देख रहा हूं।\nयुद्ध में हमारे आदमियों को मारना यह नहीं जानता कि क्या अच्छा है।\n\n'कारण'. मतलब शकुन. यहां अर्जुन के अतीत में घटित कुछ अपशकुन दिए गए हैं\nयाद है कि युद्ध भूमि पर आने से पहले उन्होंने इन संकेतों पर ध्यान दिया था। लेकिन उसके लिए\nयह अब दिमाग में आ रहा है.\n\nप्राचीन लोग शगुन को बहुत महत्व देते थे। इस संसार में सब कुछ एक है\nविलीन हो गया। एक परमाणु से ब्रह्माण्ड तक एक दूसरे के साथ सामंजस्य में\n\nसब कुछ गणितीय है. इसकी वजह से कोई भी चीज़ गणितीय तरीके से पाई जा सकती है. यही तो है\nज्योतिष, शकुन, पंचाग आदि यहां कुछ भी आकस्मिक नहीं है। ऐसा तभी होता है जब हम नहीं जानते\nहमारे लिए आकस्मिक.\n\nयहां महाभारत के दौरान देखे गए कुछ शगुन हैं: हाथी, युद्ध के लिए घोड़े\nपहले आंसू थे. सेना के चारों ओर गीदड़ फिरते थे। जानवरों को खून बहाना\nऔर मृत्यु की भविष्यवाणी होती है. आगे क्या हो रहा है इसका सटीक अंदाज़ा उन्हें लग जाता है. यह है\nमहाभारत युद्ध से पहले देखा गया एक शकुन. ब्रह्मांड में तेरह दिन और\nमहाभारत युद्ध के दौरान बीच में दो ग्रहण पड़े। युद्ध शुरू होने के पाँचवें दिन\nएक ग्रहण, फिर तेरह दिन के अंतराल पर, एक और ग्रहण। यह मृत्यु का शगुन है\nयह बात व्यास ने पहले ही धृतराष्ट्र को बता दी थी। 'आपके पुत्र से जो विश्व-विजेता है-\nदुनिया नष्ट हो जाएगी'.\n\nअर्जुन, पिछले संकेतों की याद दिलाते हुए, कृष्ण को 'केशव' कहकर संबोधित करते हैं।\nहमने प्रारंभ में उन्हें 'कृष्ण' कहकर संबोधित होते देखा है। कृष्ण का अर्थ है कृषक -\nइसका मतलब है जो धरती को खुशी और ताकत देने आया था। केशव का अर्थ है का-एशा*व।\nयहाँ 'का' का अर्थ है चतुर्मुखी ब्रह्मा जो सृष्टि का कारण है; 'एशा' का अर्थ है मारना\nशंकर कारण हैं; केशव का अर्थ है सृजन और विनाश के लिए जिम्मेदार पराशक्ति।\n\nयहां अर्जुन द्वारा कृष्ण को 'केशव' कहकर संबोधित करने का एक विशेष कारण है। \"पृथ्वी को\nआप, निर्माता जो आनंद और सहनशक्ति देने के लिए नीचे आए, हत्यारे के रूप में, यह\nयुगान्ता महान युद्ध का मास्टरमाइंड क्यों है? ''आपका उद्देश्य क्या है?''\nविशेषण के पीछे की ध्वनि. महाभारत युद्ध के अठारहवें दिन द्वापर युग का अंत हुआ\nयहां हम याद कर सकते हैं कि कलियुग का आरंभ हुआ था।\n\nयहां से अर्जुन कुछ कारण बताते हैं कि उन्हें युद्ध क्यों नहीं करना चाहिए\nवह देना शुरू कर देता है. \"नच श्रेयः अनुपश्यामि हत्वा स्वजनम अहावे\" - 'हमारे भाई\nहत्या करके युगों-युगों तक हमारा नाम इतिहास में प्रशंसनीय रहेगा\nअर्जुन कहते हैं कि मुझे ऐसा बिल्कुल भी महसूस नहीं होता.",
  "1.44": "उत्सन्न कुलधर्माणां मन्शीनां जनार्दन |\nनरके नियतम् वासः भवति इति अनुशुश्रुमा - हे जनार्दन, कुल धर्म से बहिष्कृत लोगों के लिए।\nमैंने सुना है कि नरक एक अंतहीन निवास स्थान है।\n\nइसमें नरक, पारा में नरक, और इस प्रकार सभी जन्म नरक में हैं। हमेशा के लिए नरक में सड़ो\nमैंने उन लोगों से सुना है जो जानते हैं कि स्थिति आएगी। इस प्रकार यह नरक और परा है\nहम नरक का कारण हैं।\n\nअहो बात महत् पापं कर्तुम् व्यवसिता वयम्।\nयद् राज्यसुखलोभेन हन्तुं स्वजनमुद्यतः 1॥45॥\n\nअहो बात महत् पापं कर्तुम् व्यवसितः वयम् |\n\nयत् राज्यसुखलोभेन हन्तुम स्वजनं उद्यतः - अफसोस! कितनी बड़ी गलती है\nहमने यह करना शुरू कर दिया! कब्जे के सुख के लालच में अपने ही लोगों को मार डालो\nनहीं जा रहा!\n\nइधर अर्जुन रुंधे स्वर में कहता है- “अफसोस...कितनी बड़ी त्रासदी, कितनी महान\nक्या पाप का कार्य हमारे सामने हो रहा था? यह कितनी बड़ी गलती होने वाली थी. हमने बहुत बड़ी गलती की\nहम काम में हाथ डालते थे.  हमने राज्य-सुख के लालच में अपनी प्रजा को मार डाला है\nहमने देश को पतन की ओर धकेलने का काम किया होगा।”\n\nयदि ममाप्रतिकारमवर्णं अर्पणयः |\nधार्तराष्ट्र राणे हनुष्ठान्मे क्षेमतरं भवेत्",
  "2.8": "न हि प्रपश्यामि ममापनुद्याद्यच्छोकमुच्छोषणमिन्द्रियाणाम् ।\nअवाप्य भूमावसपत्नमृद्धं राज्यं सुराणामपि चाधिपत्यम् ॥\n\n'जो मेरी इन्द्रियों को सुखाने वाला यह शोक है — उसे दूर करे ऐसा कोई साधन नहीं दीखता — चाहे पृथ्वी पर निष्कण्टक समृद्ध राज्य मिले, चाहे देवों का आधिपत्य भी मिले।'\n\nअर्जुन का संकट गहरा है — बाह्य सफलता से शोक नहीं जाएगा। 'उच्छोषणम्' — सुखाने वाला — शोक इन्द्रियों की शक्ति छीन लेता है। यह जिज्ञासा उत्पन्न करता है — फिर किससे शोक जाएगा? उत्तर अगले अध्यायों में।",
  "1.42": "संकरः नरकाय एव कुलघ्ननं कुलस्य च |\nपतन्ति पितरः हि एषाम् लुप्त पिण्ड उदक क्रियाः - कुलों और कुलों का रंग।\nनर्क में धकेल देता है. ऐसे लोगों के पूर्वज बिना पिंड-तर्पण के कष्ट भोगते हैं।\n\nविक्षिप्त बच्चों के जन्म से पूरे समाज को नरक में जाना पड़ता है। और उस तक\nहम जो जिम्मेदार हैं उन्हें भी नर्क में जाना पड़ेगा।' जब समाज इस तरह जटिल हो, तो सभी\nअर्जुन कहते हैं कि श्रद्धा नष्ट हो जाने पर पितर पिंड रहित नरक में गिरते हैं\nयुद्धोपरांत की भयावहता की संकल्पना।\nयहाँ पिंडा का क्या मतलब है? इसका महत्व क्या है? यह किसके पास जाता है और कैसे पहुंचता है\nआइये समझते हैं. सीधे हमारे द्वारा रखे गए स्थूल भ्रूण के मृत जीवन पर जाएँ\nनहीं है. मृत्यु के बाद सूक्ष्म जीवन में जीव को स्थूल शरीर की आवश्यकता नहीं होती। जीवन उसका है\nकर्म वहीं जाता है जहां उसे जाना चाहिए। पितृ देवताओं को ही हम पिंड लगाते हैं।\nयह एक मंदिर है. इसमें कुल एक सौ देवता हैं। इनमें तीन मुख्य ``पिता'' हैं।\nमृत्यु के बाद, जैसे भक्त जीवन भर देवताओं की पूजा करते थे, यह\nस्थूल शरीर से निकलकर देवतागण-पितृगण जो प्राणों की रक्षा करते हैं। ये पिता\nशासक वसु-रुद्र-आदित्य हैं। इन पितृ देवताओं का हमारे पूर्वजों द्वारा निधन हो गया था\nवार्षिक दिवस पर पूजा करने की परंपरा है। ऐसा इसलिए क्योंकि पितरों को पिंड प्रधान बनाया जाता है\nअर्थात्, यदि कारण विशेष रूप से हमारे बुजुर्गों को उनके मार्ग में बाधा डालता है,\nइसके समाधान की प्रार्थना ही पिंड प्रधान है। \"उन्हें बुरे कर्मों से बचाओ\"\nपितर-देवताओं की पूजा. अब कौए को छूने का मतलब है कि परमपिता परमेश्वर हमारी पूजा कर रहे हैं\nएक शकुन का संकेत प्राप्त हुआ.\n\nमित्रेतैः कुलघ्नानं वर्णसंकरकारकेः।\n\nउत्सा दयन्ते जातिधर्मः कुलधर्मश्च शवस्ताः",
  "2.5": "गुरूनहत्वा हि महानुभावान् श्रेयो भोक्तुं भैक्ष्यमपीह लोके ।\nहत्वार्थकामांस्तु गुरूनिहैव भुञ्जीय भोगान् रुधिरप्रदिग्धान् ॥\n\n'इन महानुभावों को मारे बिना इस लोक में भिक्षा माँगकर खाना भी श्रेयस्कर है। धन-कामना से गुरुजनों को मारकर जो भोग मिलेंगे — वे रुधिर से सने होंगे।'\n\nअर्जुन का नैतिक द्वन्द्व — गुरुओं को मारकर मिली सम्पदा भोगने से भिक्षावृत्ति बेहतर। 'रुधिरप्रदिग्धान्' — खून से लथपथ भोग — शक्तिशाली काव्यबिम्ब। यह प्रश्न केवल अर्जुन का नहीं — हर उस व्यक्ति का है जो कर्तव्य और स्नेह के बीच फँसा हो।",
  "2.9": "संजय उवाच —\nएवमुक्त्वा हृषीकेशं गुडाकेशः परन्तपः ।\nन योत्स्य इति गोविन्दमुक्त्वा तूष्णीं बभूव ह ॥\n\nसंजय उवाच — अरि-तापक गुडाकेश ने हृषीकेश से इस प्रकार कहकर, 'मैं नहीं लड़ूँगा' — गोविन्द से यह कहकर चुप हो गया।\n\nगुडाकेश — निद्रा-विजयी, सदैव जागृत। गोविन्द — गायों का रक्षक, वेदों का ज्ञाता। संजय जानता है — ब्रह्माण्ड में ऐसा कोई नहीं जो अर्जुन को युद्ध से रोक सके। फिर भी आज अर्जुन चुप है।",
  "2.10": "तमुवाच हृषीकेशः प्रहसन्निव भारत ।\nसेनयोरुभयोर्मध्ये विषीदन्तमिदं वचः ॥\n\nहे भारत, दोनों सेनाओं के बीच में विषादग्रस्त उसे हृषीकेश ने मुस्कुराते हुए यह वचन कहा।\n\n'प्रहसन्निव' — मुस्कुराते हुए। कृष्ण का मुस्कुराना — क्यों? क्योंकि जो अर्जुन सोचता है वह दुखद है — पर उसका मोह एक क्षणिक अज्ञान है। कृष्ण जानते हैं कि ज्ञान का प्रकाश अभी आएगा। दो सेनाओं के बीच — दो विपरीत दृष्टियों के बीच — भगवान् का उपदेश।",
  "2.6": "न चैतद्विद्मः कतरन्नो गरीयो यद्वा जयेम यदि वा नो जयेयुः ।\nयानेव हत्वा न जिजीविषामस्तेऽवस्थिताः प्रमुखे धार्तराष्ट्राः ॥\n\n'यह भी नहीं जानते कि हमारे लिए क्या श्रेयस्कर है — हम जीतें या वे जीतें। जिन्हें मारकर हम जीना नहीं चाहते, वे ही धार्तराष्ट्र हमारे सामने खड़े हैं।'\n\nयहाँ तक अर्जुन अपना पक्ष रखता है। अब वह कृष्ण की ओर मुड़ता है — 'मुझे मार्ग दिखाओ।' यह शरणागति का संक्रमण-क्षण है।",
  "2.7": "कार्पण्यदोषोपहतस्वभावः पृच्छामि त्वां धर्मसंमूढचेताः ।\nयच्छ्रेयः स्यान्निश्चितं ब्रूहि तन्मे शिष्यस्तेऽहं शाधि मां त्वां प्रपन्नम् ॥\n\n'दौर्बल्यदोष से मेरा स्वभाव आहत है; धर्म के बारे में मन मूढ़ है। जो निश्चित श्रेयस्कर हो वह बताइए — मैं आपका शिष्य हूँ, आपकी शरण आए इस मुझे शिक्षित कीजिए।'\n\nयह गीता का केन्द्रीय मोड़ — अर्जुन की शरणागति। 'कार्पण्यदोष' — दौर्बल्य का दोष। 'धर्मसंमूढचेताः' — किस धर्म का पालन करूँ — यह संशय। 'शिष्यस्तेऽहम्' — पहली बार स्वीकार करता है कि मैं शिष्य हूँ, गुरु मुझे बताओ। यह समर्पण ही उपदेश का द्वार है।",
  "2.4": "अर्जुन उवाच —\nकथं भीष्ममहं संख्ये द्रोणं च मधुसूदन ।\nइषुभिः प्रतियोत्स्यामि पूजार्हावरिसूदन ॥\n\n'हे मधुसूदन, रण में भीष्म और द्रोण को — पूजनीय जनों को — मैं कैसे बाणों से मारकर लड़ूँ?'\n\nकृष्ण के तीखे उत्तर और उनके मुस्कुराते चेहरे को देखकर अर्जुन का स्वर बदल जाता है — भावावेश छोड़कर भावुकता से। 'अरिसूदन' — शत्रुओं का नाश करने वाले — कृष्ण के लिए। प्रश्न सम्मान का है — गुरु-बड़ों पर बाण कैसे चलाएँ?",
  "2.12": "न त्वेवाहं जातु नासं न त्वं नेमे जनाधिपाः ।\nन चैव न भविष्यामः सर्वे वयमतः परम् ॥\n\n'ऐसा कभी नहीं था कि मैं था नहीं — या तू था नहीं — या ये राजा नहीं थे। और आगे भी ऐसा नहीं होगा कि हम सब नहीं रहेंगे।'\n\nयह श्लोक अद्वैत-मत का खण्डन करता है। तीन अलग सत्ताएँ — मैं (भगवान्), तू (जीव), और ये (जीव-समूह) — तीनों थे, हैं, और रहेंगे। भगवान् और जीव की पृथकता नित्य है — मोक्ष में भी भेद नष्ट नहीं होता। यह मध्वाचार्य के द्वैत सिद्धान्त का मूलाधार।",
  "2.13": "देहे रहने वाले जीव को इस देह में ही बाल्य, यौवन, वृद्धावस्था होती है — वैसे ही देहान्तर की प्राप्ति होती है। इसमें धीर व्यक्ति मोहित नहीं होता।\n\nदेहनाश स्वरूपनाश नहीं। जीव प्रतिक्षण देहपरिवर्तन अनुभव करता है — बाल्यदेह से युवादेह, युवादेह से वृद्धदेह। मृत्यु भी ऐसा ही एक परिवर्तन है। धीरः — जो इसे जानता है — मोहित नहीं होता।",
  "1.36": "निहत्या धर्तराष्ट्र नन्ह का प्रीतिः सत् जनार्दन |\nपापं एव आश्रयेत् अस्मान् हत्वा एतं अताटैना;ः -- धर्तराष्ट्र को मारो\nहम लोगों के लिए इसमें कौन सी ख़ुशी है? यदि हम इन हरामियों को मार डालें तो यह हमारे लिए पाप होगा।\n\nयदि धृतराष्ट्र मारा जाये तो हमें क्या खुशी? इससे मृत्यु तक लगातार जारी है\nअपराधबोध हमें परेशान कर सकता है। आपको उन्हें मारना होगा और अपराधबोध के साथ जीना होगा\nकोई लाभ नहीं-यह अर्जुन का तर्क है।\n\nइस श्लोक में अर्जुन \"आताताई\" शब्द का प्रयोग करते हैं। पिता यानी कोई और\nएक घर में आगजनी करने वाला; जो दूसरे के भोजन में विष मिलाता है; दूसरे की संपत्ति\nटालमटोल करने वाला; वह जो स्त्री-समर्थक आदि पर हाथ रखता है, जहाँ शास्त्र 'माता-पिता' को देखता है\nइसमें कहा गया है कि मारो और मार डालो. यहां दुर्योधन ने उनके साथ तमाम बुरे काम किए। भीम को\nउसने उसे जहर दे दिया था, द्रौपदी को निर्वस्त्र कर दिया था और अरागा के उस घर में आग लगा दी थी जहाँ पांडव थे। लेकिन\nइधर अर्जुन को अपने भाई का प्यार सता रहा है। इसका मतलब है कि वह \"वे सभी\" हैं\nक्या वे पिता होते हुए भी मेरे परदादा के पुत्र नहीं हैं? कृष्ण पूछते हैं.\n\nइस श्लोक में अर्जुन भगवान कृष्ण को 'जनार्दन' कहकर संबोधित करते हैं। जनार्दन का अर्थ है\nवह दुष्टों का वध करने वाला और सज्जनों को अजन्मा मोक्षदायक मृत्यु देने वाला है।\n\"आप जो उद्धारकर्ता हैं, हम इस जन्म और मृत्यु के चक्र में बार-बार आने वाले युद्ध में क्यों हैं?\"\nसंलग्न? युद्ध कभी भी मुक्तिदायक नहीं होता, वह प्रतिशोध और घृणा से भरा होता है। जब ऐसा है\nयह युद्ध क्यों?” इस संबोधन के पीछे की आवाज है.\n\nतस्मान्नरह वयं हन्तुं धार्तराष्ट्रं स्वबन्धवान् |।\n\nस्वजनं हि कथं हत्वा सुखिनः सम माधव 137।\n\nतस्मात् अर्ह व्यं हंतुं धार्तराष्ट्र स्व बंधवान् |\nस्व जन्म हि कथम् हत्वा सुखिनः सम माधव - इसलिए हमारे उपांग\n\nहम धर्तराष्ट्र हैं. मारना ऐसा नहीं है. हम अपने लोगों को कैसे मार सकते हैं?\nसुख क्या हैं माधा?\n\nधर्तराष्ट्र हमारे भाई हैं. उन्हें मारना अच्छा नहीं है. हम अपने लोग हैं\nहम हत्या करके कैसे खुश रह सकते हैं? यह अर्जुन का प्रश्न है जब अर्जुन को करीब से देखा जाता है\nवह यह बात बिल्कुल भूल गया कि वह एक लोक सेवक है और धर्म की रक्षा करना मेरा कर्तव्य है\nयह स्पष्ट है कि क्या कहा जा रहा है।\n\nयहां अर्जुन कृष्ण को 'माधव' कहकर संबोधित करते हैं। 'माँ' का अर्थ है माँ लक्ष्मी। इसलिए\nमाधव का अर्थ है भगवान लक्ष्मीपति। हाँ, 'माँ' का अर्थ है ज्ञान। भगवान जानता है\nभगवान, इसलिए वह माधव हैं. चूँकि भगवान कृष्ण का जन्म मधुवंश में हुआ था, इसलिए उन्हें माधव के नाम से भी जाना जाता है\nवेद में मातृ शब्द का अर्थ वाणी या वाज्मय है\nप्रयुक्त भगवान माधव समस्त वैदिक वाज्मय के प्रतिपादक हैं। अर्जुन\nभगवान श्रीकृष्ण को इस प्रकार संबोधित करने का एक कारण भी है। कृष्णा बारी के साले का बेटा नहीं है।\nउसे डर था कि कुछ और अलौकिक था। इस वजह से वह एक तरफ हैं\nकिसी तरह उसे ईश्वर की उस अलौकिक शक्ति का स्मरण हो आया। \"आप इस दुनिया के हैं\nमैं इसे आद्यशक्ति के रूप में जानता हूं। फिर भी इस अनुबंध में मूकदर्शक क्यों बने रहें\nआप बैठे हैं''- उनके संबोधन का यही मतलब है.\n\nयह कितना अजीब है. एक महान ऋषि जो भगवान के साथ हैं और कृष्ण को अलौकिक शक्ति के रूप में जानते हैं\nअर्जुन हर क्षण भ्रमित रहता है। तो हम आपके साथ क्या करें? यह अजीब है\nमिट्टी खाने के बाद जादुई यशोदा ने भगवान कृष्ण के मुख में भगवान के विश्व रूप को देखा,\nवह कृष्ण को दंडित करने की पेशकश करती है। यह 'मेरे बच्चे' के भ्रम में है. यहाँ\nअर्जुन की स्थिति भी ऐसी ही है.\n\nयद्यपेथे न पश्यन्ति लोभोपहतचेतसः |\nकुलक्ष्यकृतं दोषं मित्रद्रोहे च पाठकम्।",
  "2.18": "नित्य, अनाशी, अप्रमेय शरीरी के ये शरीर अन्तवान् कहे गए हैं। इसलिए हे भारत, युद्ध करो।\n\nनाशी देह — नित्य जीव की नाता। देह तीन प्रकार — स्थूल, सूक्ष्म, कारण — इनमें से केवल स्थूल दिखता है। जीव भगवान् का प्रतिबिम्ब — इसीलिए अनाशी। 'भारत' — भरतवंशोचित वीरता याद दिलाते हैं कृष्ण।",
  "2.19": "जो इसे मारने वाला जानता है और जो इसे मरा समझता है — वे दोनों नहीं जानते। यह न मारता है न मरता है।\n\nजीव न मार सकता है न मर सकता है। मारने की क्रिया का कर्ता परमात्मा है — जीव निमित्त है। यह श्लोक केवल जीव के बारे में नहीं — 'एनम्' = भगवान्। भगवान् अजेय, अमर — उन्हें कोई मार नहीं सकता।",
  "2.17": "जो इस सबको व्याप्त करता है — उसे अविनाशी जानो। अव्यय के विनाश को कोई नहीं कर सकता।\n\nजो सर्वत्र व्याप्त है उसका नाश नहीं। नाम-रूपात्मक जगत् की तरह नामात्मक जगत् भी है — वह नित्य है। 'एन' शब्द — यहाँ भगवान् का वाचक। भगवान् सर्वव्यापी — जिस पर आयुध का वार नहीं।",
  "2.20": "यह न कभी जन्म लेता है, न मरता है — न था और फिर नहीं होगा। यह अज, नित्य, शाश्वत, पुराण है — शरीर के मारे जाने पर भी मरता नहीं।\n\n'न जायते म्रियते वा कदाचित्' — जीव त्रिकाल में अमर। 'अज' — जन्मरहित। 'नित्य' — सदा विद्यमान। 'शाश्वत' — कभी न बदलने वाला। 'पुराण' — सनातन, कभी नया नहीं होता।\n\nभगवान् के पाँच गुण यहाँ — जन्मरहितता, नित्यता, शाश्वतता, पुराणत्व, अमरता — जीव में भी ये अंशतः हैं।",
  "2.11": "भगवान् उवाच —\nअशोच्यानन्वशोचस्त्वं प्रज्ञावादांश्च भाषसे ।\nगतासूनगतासूंश्च नानुशोचन्ति पण्डिताः ॥\n\n'जो शोक के योग्य नहीं उनके लिए तू शोक कर रहा है, और ज्ञानवान् की-सी बातें कह रहा है। पण्डित लोग न मरे हुओं के लिए शोक करते हैं, न जीवितों के लिए।'\n\nयह गीता का प्रथम वचन। इसमें समग्र गीता का सार है — (१) मृत के लिए शोक क्यों नहीं — जीव अमर है; (२) जीवित के लिए शोक क्यों नहीं — भगवान् नियन्ता हैं। 'अशोच्यान्' — शोक के अयोग्य। पाँच लोगों के विषय में — भगवान्, लक्ष्मी, नित्यमुक्त, मुमुक्षु, भक्त — ये शोकयोग्य नहीं।",
  "2.2": "भगवान् उवाच —\nकुतस्त्वा कश्मलमिदं विषमे समुपस्थितम् ।\nअनार्यजुष्टमस्वर्ग्यमकीर्तिकरमर्जुन ॥\n\n'हे अर्जुन, इस संकट के समय में यह मलिनता कहाँ से आ गई — जो श्रेष्ठजनों को अनुचित, स्वर्ग के लिए अयोग्य, और यहाँ अपकीर्तिकर है?'\n\nकश्मल — आत्मा की मलिनता, भौतिक आवरण। कृष्ण तीखे शब्दों से शुरू करते हैं — 'यह कहाँ से आया?' — क्योंकि अर्जुन का पराक्रम जग-प्रसिद्ध है। अनार्यजुष्टम् — जो आर्यजन नहीं करते। अस्वर्ग्यम् — जो परलोक में फल न देगा। अकीर्तिकरम् — यहाँ भी अपमान।",
  "2.21": "हे पार्थ, जो इसे अविनाशी, नित्य, अज, अव्यय जानता है — वह पुरुष कैसे किसे मारता है या मरवाता है?\n\nजो अनाशी, नित्य, जन्मरहित, बदलाव-रहित जीव को जानता है — वह किसे और कैसे मारे? मारना-मरना केवल देह का है — जीव का नहीं। यही ज्ञान अर्जुन को चाहिए।",
  "1.40": "कुलक्षये प्रणस्यन्ति कुल धर्मः सनातनः |\nधर्मे नते कुलं कृत्स म अधर्मः अभिभवति उता - कुल धर्म जो कुल के पतन पर नष्ट नहीं होते।\nगायब। यदि धर्म लुप्त हो गया, तो इद्या के कुल पर अधर्म का आक्रमण हो जाएगा।\n\nयुद्ध से उत्पन्न सबसे बड़ी समस्या \"कुलधर्म\" का विनाश है। इस श्लोक में अर्जुन का धर्म |\nजाति धर्म, कुलधर्म, सनातनधर्म आदि शब्दों के बारे में कुछ शब्दों का प्रयोग करता है\nसमझने के लिए सबसे पहले हमें यह समझना होगा कि धर्म का मतलब क्या है? यह कितने प्रकार का होता है? वह\nजानने की जरूरत है.\n\nआमतौर पर जब हम जाति धर्म के बारे में सोचते हैं तो हमें ब्राह्मण-क्षत्रिय-वैश्य-शूद्र जाति नजर आती है।\nकुलधर्म ही परिवार का मूल कार्य है। बढ़ई, लोहार, मोची आदि लेकिन\nयह वह नहीं है जो यहां कहा जा रहा है। कुलधर्म का अर्थ है समाजधर्म (5m11€101 08 50010); जाति धर्म\n\nइसका अर्थ है मनुष्य का जन्म से ही स्वाभाविक व्यक्तिगत धर्म। इन दोनों धर्मों से परे\nसनातनधर्म अर्थात शाश्वत धर्म है। हर समय, हर देश में, सनातनधर्म नहीं बदलता।\nव्यक्तित्व व्यक्तियों के बीच भिन्न-भिन्न होता है। कालानुसार, देशानुसार समाज धर्म\nबदलता रहता है.\n\nजातिवाद का अर्थ है हमारी प्राकृतिक उत्पत्ति (स्वभाव)। प्रत्येक जीवन का अपना होता है\nप्रकृति वहाँ है, लेकिन उसका पता लगाना कठिन है। इसके ऊपर दो कोष्ठकों के कारण। एक\nवंशानुगत और अन्य पर्यावरणीय प्रभाव। मनुष्य पर्यावरण का शिशु है\nवह वंशानुगत गुणों एवं वातावरण के प्रभाव में रहता है। ये असली हैं\nवे प्रकृति को कवर करते हैं.\n\nसमाजधर्म: हम दूसरों की सहायता के बिना अकेले नहीं रहते। तो संगठन को\nएक अलग धर्म. सामाजिक धर्म के लिए व्यक्तिगत धर्म (व्यक्तिगत रुचि)।\n(उदाहरण: ऊंची आवाज में बात करना मेरा निजी धर्म है। लेकिन\nअस्पताल में चुप रहना समाजधर्म है)। सामाजिक धर्म जैसे-जैसे समाज बदलता है,\nसमाज के अनुसार बदलता रहता है. उदाहरण के लिए विवाह. इतनी उम्र में\nसमय के साथ शादी करने की ज़रूरत बदलती रहती है। वैदिक काल में कन्याओं की संख्या\nबाल विवाह का प्रचलन था। कारण यह था कि वहाँ गुरुकुल व्यवस्था थी और पुत्र उन्हीं के होते थे\nआठ साल की उम्र से लेकर बीस साल की उम्र तक गुरुकुल और फिर घर में पढ़ाई\nवह वापस आ जाता था (इसे समावर्तन कहते हैं)। ऐसा सीखने वाला लड़का आठ साल का था\nवे स्त्रियों से विवाह करते थे। वयस्क होने के बाद वह विद्याभास को उनकी शिष्या के रूप में सीखती है\nवह सोच रही थी. ताकि वह अपने पति को, अपने पति के घर के माहौल को जान सके\nअनुकूलता आ रही थी. धीरे-धीरे जब गुरुकुल व्यवस्था समाप्त हो गई तो यह बाल विवाह भी समाप्त हो गया\nख़त्म हुआ बाल विवाह रामायण महाभारत काल में नहीं था। फिर हाल ही में\nलगभग एक हजार साल पहले विदेशी आक्रमण के दौरान लड़कियों को स्कूल नहीं भेजा जाता था\nवे जल्द ही शादी करने लगे। यह सामाजिक दबाव के कारण हुआ बदलाव है. इस प्रकार\nसामाजिक धर्म समय और समाज के साथ बदलता रहता है।\n\nसनातनधर्म: यह एक ऐसा धर्म है जो हर समय और हर परिस्थिति में कभी नहीं बदलता। वेद कहते हैं\nसनातन धर्म. उदाहरण के लिए: ईमानदारी से जीना, दूसरे की संपत्ति\nचोरी मत करो, सत्य बोलो, भगवान पर भरोसा रखो आदि यही सनातन धर्म है।\nएक ऐसा धर्म जो हर युग में नहीं बदलता।\n\nसामाजिक धर्म को सनातन धर्म के अनुरूप समायोजित किया जाना चाहिए। जातिवाद\nइसे सामाजिक धर्म के अनुसार समायोजित किया जाना चाहिए। किसी वस्तु का असाधारण गुण (03॥1)।\n\nइसका धर्म. उदाहरणार्थ: देखना आँखों का धर्म है, सुनना कानों का धर्म है। लेकिन कौन सा\nधर्म अधार्मिक हो सकता है. जो नहीं देखना चाहिए उसे देखना अधर्म है! देखने लायक एक\nएक क्षेत्र है. इसके पार हो जाने पर धर्म ही अधर्म बन जाता है।\n\nयहाँ अर्जुन कहते हैं: “न्याय व्यवस्था तब संचालित होनी चाहिए जब समाज कुलक्षय हो जाए\nइसके नष्ट होने से सामाजिक धर्म नष्ट हो जायेगा। सामाजिक व्यवस्था ध्वस्त हो जाती है। पूरा समाज\nअधर्म में डूब जाता है. यह वह उपहार है जो हम संघर्ष करके समाज को देते हैं।\n\nअधर्माभिभावत् कृष्ण प्रदुष्यन्ति कुलस्त्रियः |\n\nस्त्रीषु सुखतासु वर्षेय जयते वर्णसंकरः",
  "2.27": "जन्मे हुए की मृत्यु निश्चित है और मरे हुए का जन्म निश्चित है। इसलिए अपरिहार्य विषय में तुम्हें शोक करना उचित नहीं।\n\nमृत्यु और जन्म — दोनों अवश्यम्भावी। जो अवश्यम्भावी है उसके लिए शोक क्यों? यह सनातन नियम है — शरीर का जन्म-मरण अटल। इस नियम को स्वीकारना ज्ञान है।",
  "2.23": "इस जीव को शस्त्र नहीं काट सकते, अग्नि नहीं जला सकती, जल नहीं भिगो सकता, वायु नहीं सुखा सकती।\n\nकिसी भी वस्तु को नष्ट करने के चार प्रधान साधन — मृत्तिका (घन शस्त्र), जल, अग्नि, वायु। जीव सबसे सूक्ष्म — इन चारों का उस पर प्रभाव नहीं। चारों महाभूत जीव को नहीं छू सकते — तो कोई शत्रु कैसे?",
  "2.15": "हे पुरुषर्षभ, जिस पुरुष को ये सुख-दुःख विचलित नहीं करते — सुख-दुःख में सम, धीर — वह अमृतत्व के योग्य बनता है।\n\nद्वन्द्वों से ऊपर उठना सम्भव है — यह एक मानसिक अवस्था है। जो सुख में हर्षित न हो, दुःख में खिन्न न हो — वह 'धीर' है। 'अमृतत्वाय कल्पते' — मोक्ष का अधिकारी बनता है।",
  "2.25": "यह अव्यक्त, अचिन्त्य, अविकार्य कहा जाता है। इसलिए इसे इस प्रकार जानकर शोक करना उचित नहीं।\n\nभगवान् अव्यक्त — इन्द्रियों से अदृश्य। जीव भी अव्यक्त — स्थूल से सूक्ष्मतर। अचिन्त्य — सामान्य तर्कबुद्धि से ग्रहण नहीं। अविकार्य — किसी भी प्रकार के विकार से रहित। 'इसे जानकर' — इस ज्ञान के बाद शोक का कोई आधार नहीं।",
  "1.47": "संजय उवाच - संजय ने कहा:\n\nएवम् उक्त्वा अर्जुनः शंखे रथ उपस्थे उपविशत् |\n\nविसृज्य सशरं चापं शोक समविग्न मनसः - युद्ध के मैदान में अर्जुन का धनुष और बाण।\nबिसुतु आंसुओं से लथपथ होकर टेरा की गोद में बैठ गया।\n\nरथ में खड़े हैं. इतना कहकर अर्जुन गिर पड़े और रथ के बीच में बैठ गये। सब अपने आप से\nउसने हथियार नीचे छोड़ दिये और हाथ पर हाथ धरे बैठ गया।\n\nइस अध्याय में अर्जुन ने अपनी सारी भावनाएँ कृष्ण के सामने प्रकट कर दी हैं। अर्जुन बोला\nप्रत्येक चीज़ कुछ न कुछ है जिसे हम जानते हैं। लेकिन हम नहीं जानते कि कृष्णा आगे क्या कहेंगे.\nनिम्नलिखित अध्यायों में प्रभु का उत्तर जो अंधकार से प्रकाश की ओर ले जाता है\nचलो देखते हैं.\n\nअगले अध्याय पर जाने से पहले थोड़ा विश्लेषण। हममें से अधिकांश के लिए एक\nसंदेह. युद्ध भूमि में भगवान श्रीकृष्ण और अर्जुन किस प्रकार संवाद करते हैं, यह इन सात सौ श्लोकों का संवाद है\nक्या उनके पास इतना समय था? वह है। सबसे पहले इस प्रश्न का उत्तर दिया जाना चाहिए\nहमें महाभारत काल की युद्ध प्रणाली को अवश्य जानना चाहिए। उस समय के मार्शल लॉ के अनुसार\nयुद्ध में, यदि प्रतिद्वंद्वी तैयार नहीं था, तो उस पर हमला नहीं किया जा सकता था। बिना तैयार खड़े\nयुद्ध शुरू नहीं होता. सवाल यह है कि उनकी बातचीत कितनी देर तक चली. अर्जुन\nउस समय की महान प्रतिभाओं में से एक. यहां बातचीत दो प्रतिभाओं के बीच है।\nआज ज्ञान के उस स्तर की कल्पना करना कठिन है। उनकी पूरी बातचीत आज हुई\nइस सात सौ श्लोक रूप में नहीं. हमारे लिए वेदव्यास का संवाद समझना\nयही सब कुछ उन्होंने सात सौ श्लोकों के रूप में हमारे सामने प्रस्तुत किया है। ये श्लोक आज भी हमारे लिए है\nसमझ में नहीं आता उसके लिए हमें हजारों पन्नों में गीता भाष्य मिलता है। लेकिन\nमहान प्रतिभावान लोग किसी बात को बहुत ही कम समय में बहुत ही संक्षेप में कह सकते हैं और उसका अर्थ भी निकाल सकते हैं\nकृष्ण और अर्जुन के बीच की बातचीत भी बहुत दिलचस्प है\nएक संक्षिप्त बातचीत.\n\nदूसरी महत्वपूर्ण बात यह है कि कृष्ण ने अर्जुन को यह गीत क्यों सुनाया? अपने बड़े भाई भीम को\nया दूसरों को क्यों नहीं बताते? सवाल यह है कि इस सवाल का जवाब बहुत आसान है. रोगग्रस्त के लिए\nदूसरों के लिए नहीं बल्कि नशे के लिए. वहाँ अर्जुन ही एकमात्र ऐसा व्यक्ति था जो मानसिक रूप से आंतरिक अशांति में था।\nउसके लिए, भगवान कृष्ण ने अर्जुन को उपदेश दिया (उनके माध्यम से हमें)।\n\nइति प्रथमो*ध्यायः\nपहला अध्याय ख़त्म हो चुका है.\n\nचिंता मत करो\n\nअध्याय दो\n\nरथ में गिरे हुए अर्जुन को भगवान कृष्ण की दूसरी चेतावनी यह है कि वह युद्ध नहीं करेगा\nचैप से शुरू. यह अध्याय संपूर्ण भगवद गीता का पंचांग है और व्यापक है\nव्यास ने यहां संदेश के सार को पकड़ लिया है। यहां उपदेश का व्यापक रूप अलग है\nसोलह अध्याय.\nसंजय उवाचा.\nतम् तथा कृपाय$5 व्यापकश्रुपूर्णकुलेक्षणम् |\nविषिदन्तमिदं वकामुवाच मधुसूदनः ॥1॥\n\nसंजय उवाचा-संजय ने कहा:\n\nतम तथा कृपाय अविष्टम असरु पूर्ण अकुला ईशानम् |\n\nविषिदन्तं इदं वयकं उवाच मधुसूदनः - करुणा से भरी आँखों की तरह।\nउसे हल्की-हल्की लार टपकाता देखकर कृष्ण ने यह बात कही।\n\nअर्जुन के मन में संपूर्ण समाज और जाति के प्रति दया भाव है। युद्ध करने से लेकर नरसंहार तक\nउसके दिमाग में यह भरा हुआ है कि हम कारण बनेंगे। अनुग्रह से भरी आँखों में\nबारिश हो रही है. अज्ञानता के कोहरे ने मन को भ्रमित कर दिया है। तर्क के माध्यम से स्वयं\nऔचित्य तलाश रहे हैं. यह कोई प्राकृतिक प्रवृत्ति नहीं है, यह एक जुनून है। इस पर कृष्ण\nसख्ती से जवाब देता है.\nभगवान का वचन\nकुतस्त्व कशमलमिदं विषमे समुपथिथम।\nअनार्यजुष्टमस्वर्ग्यमाकीर्तिकारामर्जुन ॥2॥\n\nभगवान उवाच- भगवान ने कहा:\n\nकुतः त्वा कशमलं इदं विषमे समुपस्थितम् |\n\nअनार्य जुष्पं असवर्ग्यं अकीर्ति करम अर्जुन - अर्जुन, जो ऐसे संकट में जानता है।\nयह गँवार, वहाँ का अप्राप्य, स्वर्ग के अयोग्य, यहाँ का प्रसिद्ध, तुम्हारे लिए कवि क्यों बन गया?\n\n\"तुम्हें यह बुद्धि कहाँ से मिली? यह भौतिक गंदगी तुम्हारे साथ कैसे चिपक गई? ऐसी आपात स्थिति में,\nतत्काल कार्रवाई के इस क्षण में—यह गंदा विचार क्या है? कोई भी आर्य नहीं है\nऐसा कभी मत सोचो. ऐसी विचारधारा से- पारा और यहां स्वर्ग नहीं है\n\nकोई महिमा नहीं. जो जानते हैं, बुद्धिमान हैं, बुजुर्ग हैं वे कभी ऐसा नहीं सोचते",
  "2.32": "हे पार्थ, ऐसा युद्ध बिना यत्न के मिला — खुला स्वर्ग का द्वार — ऐसे युद्ध को भाग्यशाली क्षत्रिय ही पाते हैं।\n\nबन्नञ्जे की विस्तृत व्याख्या यहाँ पुस्तक पृष्ठ पर जारी — मुख्य अर्थ: धर्मयुद्ध अपने-आप में स्वर्गप्राप्ति का साधन है। सभी शास्त्रों के अनुसार युद्ध में मरने से सद्गति मिलती है।",
  "2.16": "असत् का अस्तित्व नहीं, सत् का अभाव नहीं — दोनों का अन्त तत्त्वदर्शियों को दृष्ट है।\n\nप्रकृति भी अविनाशी है — भगवान् भी अविनाशी। बुराई से भलाई नहीं होती, भलाई से बुराई नहीं। सत् — जो है — नाशरहित। असत् — जो नहीं — उत्पत्तिरहित। मध्वाचार्य के मत में 'सत्' = भगवान् और प्रकृति दोनों; 'असत्' = जो वास्तव में नहीं।",
  "2.14": "हे कौन्तेय, इन्द्रियों के विषय-सम्पर्क ही शीत-उष्ण, सुख-दुःख देते हैं। ये आने-जाने वाले, अनित्य हैं — हे भारत, इन्हें सहो।\n\nबचपन का शरीर खोकर युवावस्था का शरीर पाते हैं, युवा का खोकर वृद्धावस्था का। उसी प्रकार वृद्धशरीर खोकर नया शरीर पाते हैं — इसमें शोक नहीं। सुख-दुःख भी आने-जाने वाले हैं — सहन करो।",
  "2.35": "जो महारथी तुम्हें पहले बड़े सम्मान से जानते थे — वे तुम्हें तुच्छ समझेंगे।\n\n'महारथाः' — वे जो तुम्हें पहले सम्मान से जानते थे। लघुता — छोटाई, तुच्छता। वीर का सम्मान उसके कर्म से — कर्म से पीठ दिखाने पर सम्मान जाता है। यह सामाजिक सत्य भी अर्जुन को युद्ध करने को कहता है।",
  "2.24": "यह काटा नहीं जा सकता, जलाया नहीं, भिगोया नहीं, सुखाया नहीं। यह नित्य, सर्वगत, स्थाणु, अचल, सनातन है।\n\nपिछले श्लोक में चार नाश-साधन बताए — यहाँ उन सबका खण्डन। जीव स्थाणु — एक ही स्थान में, कोई परिवर्तन नहीं। अचल — कोई बाहरी शक्ति हिला नहीं सकती। सर्वगत — भगवान् के साथ सब स्थानों में। सनातन — कभी नया नहीं, कभी पुराना नहीं।",
  "2.26": "अथ चैनं नित्यजातं नित्यं वा मन्यसे मृतम् ।\nतथापि त्वं महाबाहो नैनं शोचितुमर्हसि ॥\n\nयदि इस जीव को तू नित्यजन्मशील और नित्यमरणशील भी मानता हो — तो भी, हे महाबाहो, इस पर शोक करना उचित नहीं।\n\nकृष्ण यहाँ द्विपक्षीय तर्क देते हैं — यदि जीव अमर है तो शोक व्यर्थ; यदि नश्वर भी माना जाए तो भी — जन्म-मरण स्वाभाविक है, शोक नहीं। दोनों ही पक्षों में युद्ध करना कर्तव्य।",
  "1.2": "संजय उवाच- संजय कहते हैं:\n\nदृष्ट्वा तु पांडव अनिकं व्यूधं दुर्योधन तदा।\n\nआचार्यं उपसंगम्य राजा वचनं अब्रवीथ - दुर्योधन द्वारा सुसज्जित, जिसने उस समय शासन किया था।\nवह पांडव सेना को देखकर आचार्य की ओर चला और बोला।\n\nइस श्लोक का विश्लेषण करने से पहले यहां 'अनेका' शब्द के अर्थ के बारे में थोड़ा जान लेते हैं\nआइए जानें. जैसा कि आप जानते हैं, महाभारत युद्ध में अठारह अक्षोहिणियों ने भाग लिया था\nसात अक्षौहिणी सेना पांडवों की ओर से लड़ी थी जबकि शेष सेना कौरवों की थी।\nयहाँ की अंतिम अक्षोहिणी सेना की सबसे बड़ी डिवीज़न है। अतीत में सेना\nइसे नौ खंडों में विभाजित किया गया था। वे हैं:\n\n(1) पट्टी: एक हाथी; एक रथ; तीन घोड़ों और पाँच पैदल सैनिकों की एक टुकड़ी।\n\n(2) सेनामुख: तीन पत्ती\n\n(3) गुलका: तीन सैन्य चेहरे\n\n(4) गण : तीन तिल्ली\n\n(5) वाहिनी : तीन गण\n\n(6) पृथना: तीन नाड़ियाँ\n\n(7) चामू: तीन प्रीताना\n\n(एल) अनिकिनी: तीन चामू\n\n(9) अक्षोहिणी: दस अनेकिनी- अर्थात 21870 हाथी, 21870 रथ, 65610 घोड़े, 1,09,350\nपैदल सैनिक (संख्या युक्ति यहां नोट करें: 2*13583730518; 635365130518;\n1409-3550518).\n\nउपरोक्त गणना के अनुसार एक अनिकिनी अक्षोहिणी का दसवां भाग होती है। यानी 2187\nहाथी, 2187 रथ, 6561 घोड़े, 1,09,35 पैदल सेना। यह पांडव सेना का सत्तरवाँ भाग है\nएक भाग युद्ध करते समय सभी अठारह अक्षौहिणियाँ एक साथ नहीं लड़तीं।\nएक समय में एक इकाई एक विशिष्ट संरचना बनाती है और लड़ती है।\n\nपांडव सेना की एक 'अनिका', एक अद्वितीय संरचना (व्यूधम) में अनुशासित खड़ी है।\nदुर्योधन का क्रोध तब बढ़ जाता है जब वह देखता है कि मानसिक रूप से उसके लिए यह पहली घटना है\nसदमा इसी मनःस्थिति में वह आचार्य के पास जाता है। यहां आचार्य का तात्पर्य गुरुओं में से है\nज्येष्ठ द्रोणाचार्य. उनके पास जाकर दण्डवत् करो; शिष्य की तरह व्यवहार मत करो, वह एक राजा है\nवह इस तरह से बात करते हैं जिसे गर्व के साथ नहीं खेला जाना चाहिए।'\n\nइस श्लोक में मनोविज्ञान के विषय पर ध्यान दीजिये। युद्ध की भूमि के लिए “तन\nदुर्योधन जो आया था, उसने कहा, \"मैं जीतूंगा तो जीतूंगा।\" जैसे ही उसने एक पांडव को देखा तो वह मानसिक रूप से परेशान हो गया\nअसंतुलित हो जाता है. इस श्लोक में बताया गया है कि वह उससे किस प्रकार परेशान थे\n'दृष्टवथु (मेलान्टू)' में जोर दिया गया है। हालाँकि उनके पास ग्यारह अक्षोहिणियों की सेना थी,\nआचार्य दुर्योधन ने जब पांडवों की छोटी अनिका को देखा तो वह मानसिक रूप से विक्षिप्त हो गया\nद्रोण में. अगले श्लोक में बताया गया है कि वह कैसे गया और अहंकार से बोला\nचलो देखते हैं.\n\nपश्यैतं पाण्डुपुत्रनामाचार्य महतिं चमुम्।\nव्यूधं द्रुपदपुत्रेण तव शिष्येन धीमता 1 3।\n\nपश्य एतम् पाण्डुपुत्रानाम् आचार्य महातिम् चामूम्\nव्यूधं द्रुपदपुत्रेण तव शिष्येन धी-माता - देखो, आचार्य, पांडु के इन महान पुत्रों को।\nआपके विद्वान शिष्य द्रुपा के पुत्र द्वारा सुसज्जित गिरोह।\n\nदुर्योधन का सेनापति भीष्म के पास नहीं, बल्कि द्रोणाचार्य के पास, भीष्माचार्य के पास गया।\nसुनते समय, आचार्य द्रोण से नानजिन के बारे में बात करते हैं। यहां दुर्योधन द्वारा द्रोण का वध कर दिया जाता है\nचूची उन्हें \"पांडवों के आचार्य\" कहकर संबोधित करते हैं। “अपने प्रिय शिष्यों के समान उदार\nमत दिखाओ'' उनके शब्दों का अर्थ है.\n\nद्रुप के पुत्र दृष्टद्युम्न पांडवों की सेना के प्रभारी थे। द्रुपद और द्रोण\nबचपन के मित्र लेकिन कुछ समय बाद द्रुपा राजगद्दी पर बैठे। उस समय गरीब\nब्राह्मण द्रोण ने द्रुपद से अपने पुत्र को दूध पिलाने के लिए एक गाय देने को कहा।\nवह अपने बचपन के दिनों में इसकी मांग करता है। लेकिन द्रुपद कहते हैं, \"आप मुझे मित्र कहते हैं\nकोई योग्यता नहीं, मैं राजा हूं, लेकिन तुम एक गरीब ब्राह्मण हो। आपकी और मेरी कैसी दोस्ती है।”\nवह मेरा अपमान करता है. इसी द्वेष के कारण द्रोणाचार्य कौरव-पांडवों के गुरु बन गये\nसाथ में, द्रुपद को उनके आधे, अनुष्ठान को पूरा करने के बाद पांडवों ने पकड़ लिया था\nउसने राज्य छीनते हुए कहा, \"अब मैं तुम्हारे बराबर हो गया हूं। फिर भी मुझे मित्र कहो।\"\nसहमत हूँ।\" इस प्रतिशोध के साथ, द्रुपा एक महान बलिदान करने और द्रोण को मारने में सक्षम हुए\nवरदान के रूप में एक पुत्र प्राप्त करने और उसे द्रोणाचार्य के अधीन शिक्षित करने के बाद, उसने अपना बदला लिया।\nछुड़ाए जाने की प्रतीक्षा में. वह दृष्टा ध्युम्न हैं - पांडव सेनापति।\n\nदुर्योधन ने द्रोण को \"आपका शिष्य-द्रुपा का पुत्र, बहुत करीबी, अनुशासित\" बताया है\nसेना (चामू) की जो व्यूह रचना की गई है, उसे देखो,'' वह उपहास के साथ कहते हैं। यहाँ\nअंदर से डरा हुआ दुर्योधन जो क्षणिक गलती कर रहा है, उस पर ध्यान दीजिए।\nराजा बनने की इच्छा, घृणा, ईर्ष्या, मानसिक मंदता\nटालना, इस प्रकार वह करना जो नहीं करना चाहिए। यही हम अपने दैनिक जीवन में देखते हैं\nबहुत सामान्य विचार. ऐसे विभिन्न चरण होते हैं जिनमें मनुष्य भटक जाता है।\n\nअत्र शूरा महेश्वसा भिमार्जुनसामा युधि |\nयुधानो विराटश्च द्रुपदश्च महारथः |4|\n\nअत्र शूरः मह इषु असः भीमार्जुन समः युधि |\nयुधानाः विराटः च द्रुपदः च महारथः - यहाँ सभी महारथी वीर हैं। युद्ध में भीमार्जुन के समान — सात्यकि, विराट और द्रुपद भी महारथी हैं।\n\nपांडव सेना को देखकर मानसिक रूप से विचलित दुर्योधन द्रोणाचार्य के पास जाता है\nवह जाकर पांडव सेना और वहां के वीरों के बारे में बात करता है। सामान्य तौर पर हम किसके हैं\n\nयदि आप उनसे डरते हैं, तो आपको ऐसा लगेगा जैसे आप उन्हें हर जगह देखते हैं। जैसे कृष्ण ने कंस को दर्शन दिये। ये है\nमनोविज्ञान यहां दुर्योधन भीमार्जुन से डरता है। वह उस डर से कहता है, \"वहां\nभीमार्जुन के समान सभी वीर हैं। वह असाधारण धनुष से लड़ सकता है और जीत सकता है\n\"महावीरा\"। दरअसल उस समय के महाबिल्लु का मतलब गंधीव होता था। गांधीवा\nअर्जुन-भीम और भगवान कृष्ण ही हैं जो पकड़ कर लड़ सकते हैं। इस मामले में दुर्योधन को\nपांडव सेना के सभी महान वीर भीमर्जुन के समान बिलारस के रूप में देखे जाते हैं। ये है\nदुर्योधन की मनःस्थिति को बताना |\n\nइसके बाद दुर्योधन एक-एक करके पांडवों के वीरों के नाम बताना शुरू करता है।\nवह कहते हैं, ''पांडव सेना में सात्यकि, विराट, द्रुपद जैसे महारथी हैं.'' यहाँ ये तीन हैं\nनाम आने की एक खास वजह है. इन तीनों को भी कौरवों की ओर आना पड़ा।\nद्रुपद, जो जरासंध के साथ थे, को पहले पांडवों ने गिरफ्तार कर लिया था, जिन्होंने कृष्ण और उनके खिलाफ लड़ाई लड़ी थी\nहमने पहले देखा है कि अर्धराज्य छीनकर द्रोण को दे दिया गया था। लेकिन पांडवों के लिए\nउन्होंने द्रुपद और पांडवों का पक्ष लिया, जिन्होंने द्रौपदी को त्याग दिया और रिश्ता स्थापित किया। कीचक से पहले विराट\nवह भय के कारण देश पर शासन कर रहा था। विराट एक पांडव हैं क्योंकि कीचक को भीम ने मारा था\nशिविर में शामिल हुए. अब सात्यकि नहीं रहे जो बलराम के प्रेम को पार न कर सके। यहाँ बलराम हैं\nसात्यकि यह कह कर तीर्थयात्रा पर निकल गयी है कि वह युद्ध में अपना सिर नहीं लगाएगी\nवह भी पांडवों के साथ खड़े थे। इस प्रकार दुर्योधन को जो इनमें से प्रत्येक नाम को बाहर निकाल रहा है\nअंदर से वह कहता है, \"ओह, ये महारथी जो मेरे पक्ष में होने वाले हैं, वे पांडवों के पक्ष में नहीं हैं।\"\nपीड़ा है यही दुर्योधन का खेद है! वह अपनी रणनीति बनाने के लिए निकले, यहां हैं\nवह इस बात पर पछताते रहे कि जिन्हें उनके पास आना चाहिए था वे पांडवों में शामिल हो गए\nकर रहा है दुर्योधन कई और वीरों के नाम गिनाता है.",
  "2.29": "कोई इसे आश्चर्यवत् देखता है, कोई आश्चर्यवत् कहता है, कोई आश्चर्यवत् सुनता है — और सुनकर भी कोई नहीं जानता।\n\nजीव का स्वरूप अत्यन्त रहस्यमय। देखना, कहना, सुनना — तीनों प्रकार से इस आश्चर्य को अनुभव किया जाता है। पर 'सुनकर भी नहीं जानता' — जब तक भगवद्कृपा न हो, तत्त्वज्ञान नहीं। गीता का पूरा उपदेश इसीलिए — सुनने के बाद जानने तक पहुँचाने के लिए।",
  "2.37": "मरे तो स्वर्ग पाओगे, जीते तो पृथ्वी का राज्य भोगोगे। इसलिए हे कौन्तेय, युद्ध का निश्चय करके उठो।\n\nयह श्लोक ज्ञान-खण्ड का अन्तिम तर्क है। दोनों विकल्प अच्छे — मृत्यु में स्वर्ग, जय में राज्य। 'कृत-निश्चय' — दृढ़ निश्चय के साथ। 'उत्तिष्ठ' — उठो। यहाँ से कर्मयोग का उपदेश आरम्भ होगा।",
  "2.30": "हे भारत, सभी के देह में रहने वाला यह जीव नित्य अवध्य है। इसलिए सभी भूतों के लिए शोक करना उचित नहीं।\n\nजीव प्रत्येक शरीर में — और वह नित्य अवध्य। 'सर्वाणि भूतानि' — सभी प्राणियों में, सभी देवों में। सबका जीव अमर — इसलिए किसी की भी मृत्यु पर शोक निरर्थक। यह ज्ञान प्रत्येक के लिए उपयोगी है।",
  "2.22": "जैसे मनुष्य पुराने वस्त्र उतारकर दूसरे नए वस्त्र पहनता है — वैसे ही जीव पुराने शरीर छोड़कर दूसरे नए शरीर ग्रहण करता है।\n\nयह गीता का सबसे प्रसिद्ध दृष्टान्त। पुनर्जन्म का सरल, स्पष्ट चित्र। पुराने शरीर से नए शरीर में जाना उतना ही स्वाभाविक जितना पुराने वस्त्र बदलना। मृत्यु का भय अज्ञान से — ज्ञान से यह स्वाभाविक परिवर्तन मात्र।",
  "2.42": "हे पार्थ, अज्ञानी कहते हैं — वेद में इससे अधिक कुछ नहीं — ऐसे वेदवादरत लोग।\n\n'वेदवादरताः' — वेद के केवल कर्मकाण्ड भाग से संतुष्ट। 'नान्यदस्ति' — इससे अधिक कुछ नहीं — ऐसा मानने वाले। ये आधे-अधूरे ज्ञान से वेद पढ़ते हैं। कृष्ण यहाँ वेद-विरोधी नहीं — वे वेद के सम्पूर्ण अर्थ की ओर संकेत करते हैं।",
  "2.28": "भरतवंशज, सभी भूतों का आरम्भ अव्यक्त, मध्य व्यक्त, और अन्त फिर अव्यक्त — तो फिर शोक किस बात का?\n\nजीवों की जीवन-यात्रा — जन्म से पहले अव्यक्त, मृत्यु के बाद अव्यक्त, बीच में दृश्य। यह एक चक्र है — आरम्भ में भी अदृश्य, अन्त में भी अदृश्य। दृश्य-काल ही वास्तव में हमारा जानने का क्षेत्र — उसमें करने योग्य करें।",
  "2.43": "कामनाओं की पूर्ति और ऐश्वर्य की प्राप्ति के लिए अनेक क्रिया-विशेषों का वर्णन करने वाले।\n\n'क्रियाविशेषबहुलाम्' — अनेक विशेष क्रियाओं का वर्णन। भोग-ऐश्वर्य की ओर ले जाने वाले कर्म। ये लोग वेद को केवल ऐहिक-पारलौकिक फलों के लिए पढ़ते हैं — भगवद्ज्ञान के लिए नहीं।",
  "2.34": "लोग तुम्हारी स्थायी अपकीर्ति की कथा कहते रहेंगे — और सम्मानित के लिए अपकीर्ति मृत्यु से भी बढ़कर है।\n\n'संभावितस्य' — सम्मानित व्यक्ति के लिए। अपकीर्ति — मृत्यु से भी भारी। क्षत्रिय का सम्मान उसकी कीर्ति में है — वह खो जाए तो जीवन व्यर्थ। यही अर्जुन को स्पष्टतः याद दिलाते हैं।",
  "2.33": "यदि तुम इस धर्मयुद्ध को नहीं करते तो स्वधर्म और कीर्ति खोकर पाप पाओगे।\n\nयुद्ध न करने के परिणाम — (१) स्वधर्म का त्याग; (२) कीर्ति का नाश; (३) पाप की प्राप्ति। धर्मत्याग, अपकीर्ति, पाप — तीनों एकसाथ। इसकी तुलना में युद्ध करना अनेकों गुना बेहतर।",
  "2.41": "हे कुरुनन्दन, व्यवसायात्मिका बुद्धि एक ही — अव्यवसायियों की बुद्धियाँ अनन्तशाखी हैं।\n\n'व्यवसायात्मिका बुद्धि' — एकनिष्ठ, दृढ़ संकल्पयुक्त बुद्धि — एक ही होती है। 'अव्यवसायिनाम्' — जो दृढ़ संकल्प नहीं रखते उनकी बुद्धि अनेक दिशाओं में बिखरती है। कर्मयोग में एकाग्रता आवश्यक — इसीलिए 'व्यवसायात्मिका'।",
  "2.52": "जब तुम्हारी बुद्धि मोहरूपी दलदल को पार कर लेगी — तब जो सुना है और सुनने योग्य है उससे वैराग्य होगा।\n\n'मोहकलिलम्' — मोह का दलदल। जब बुद्धि इस दलदल को पार करे — तो वेद-सुने सब फलों से वैराग्य होता है। 'श्रोतव्यस्य च' — जो और सुनने योग्य था उससे भी। ज्ञान होते ही वेदिय फलकामनाएँ स्वतः छूटती हैं।",
  "2.48": "हे धनञ्जय, योग में स्थित होकर — सफलता-असफलता को समान मानकर — कर्म करो। समत्व को ही योग कहते हैं।\n\n'समत्वं योग उच्यते' — योग की सरलतम परिभाषा। समत्व — सफलता और असफलता दोनों में समभाव। यह समत्व ही वास्तविक योग है। 'योगस्थः' — योग में स्थित होकर।",
  "2.31": "अपने धर्म को देखकर भी तुम्हें विचलित नहीं होना चाहिए — क्षत्रिय के लिए धर्मयुद्ध से बढ़कर कोई श्रेय नहीं।\n\nजीवतत्त्व का प्रतिपादन पूरा हुआ। अब कर्तव्य का प्रश्न — क्षत्रिय का धर्म क्या? युद्ध। 'स्वधर्मम् अपि अवेक्ष्य' — अपना धर्म देखकर भी। 'न विकम्पितुम् अर्हसि' — डगमगाना उचित नहीं।",
  "2.38": "सुख-दुःख, लाभ-हानि, जय-पराजय को समान करके युद्ध करो — इस प्रकार पाप नहीं लगेगा।\n\nयहाँ से कर्मयोग का आरम्भ। 'समे कृत्वा' — समान दृष्टि से। सुख-दुःख, लाभ-हानि, जय-पराजय — तीनों द्वन्द्व। इन सबमें समभाव से कार्य करना — 'नैव्यं पापमवाप्स्यसि' — पाप नहीं लगेगा। यह कर्मयोग का प्रथम सूत्र।",
  "2.36": "तुम्हारे विरोधी तुम्हारी सामर्थ्य की अनुचित निन्दा करेंगे — इससे बढ़कर दुःखदायी और क्या होगा?\n\n'अवाच्यवादान्' — जो कहने योग्य न हों ऐसे वचन। शत्रु तुम्हारी शक्ति का उपहास करेंगे — यही सबसे बड़ा दुःख। वीर के लिए अपनी शक्ति की निन्दा सुनना असहनीय।",
  "2.58": "जब यह सब ओर से इन्द्रियों को विषयों से उसी प्रकार समेट लेता है जैसे कछुआ अपने अंगों को समेट लेता है — उसकी प्रज्ञा स्थित होती है।\n\nगीता का प्रसिद्ध कछुआ-दृष्टान्त। कछुआ खतरे में अपने सभी अंग भीतर समेट लेता है। स्थितप्रज्ञ भी — जब आवश्यक हो — इन्द्रियों को विषयों से भीतर खींच लेता है। यह दमन नहीं — नियन्त्रण है।",
  "2.56": "दुःख में जिसका मन उद्विग्न नहीं, सुख में जो स्पृहारहित है, राग-भय-क्रोध से रहित — वह स्थितधी मुनि कहलाता है।\n\n'दुःखेषु अनुद्विग्नमनाः' — दुःख में मन अशान्त नहीं। 'सुखेषु विगतस्पृहः' — सुख में लालसा नहीं। 'वीतरागभयक्रोधः' — राग, भय, क्रोध — तीनों से रहित। ये तीनों एक-दूसरे से जुड़े — राग से भय, भय से क्रोध।",
  "2.55": "भगवान् उवाच — हे पार्थ, जब मन में स्थित सभी कामनाओं को त्याग देता है, और आत्मा में ही आत्मा से सन्तुष्ट रहता है — तब स्थितप्रज्ञ कहलाता है।\n\nस्थितप्रज्ञ का प्रथम लक्षण — कामनाशून्यता। 'प्रजहाति यदा कामान्' — त्याग करता है — यह क्रमशः होता है। 'आत्मन्येवात्मना तुष्टः' — आत्मा में आत्मा से सन्तुष्ट — भगवान् में स्थित आत्मा।",
  "2.50": "बुद्धियुक्त इस लोक में ही सुकृत-दुष्कृत दोनों को त्याग देता है। इसलिए योग के लिए तत्पर हो — योग ही कर्म में कौशल है।\n\n'बुद्धियुक्तः' — बुद्धियोगयुक्त। 'जहाति उभे सुकृतदुष्कृते' — अच्छे-बुरे दोनों कर्मों का फल छूटता है। 'योगः कर्मसु कौशलम्' — योग कर्म में कुशलता है — यह गीता का एक और महत्त्वपूर्ण सूत्र।",
  "2.60": "हे कुन्तीपुत्र, प्रयत्नशील विद्वान् का भी मन इन्द्रियाँ बलपूर्वक हर लेती हैं।\n\nसाधक काफी जानता है, काफी प्रयास करता है — फिर भी इन्द्रियाँ बलपूर्वक खींच लेती हैं। 'प्रमाथीनि' — मथने वाली, उखाड़ फेंकने वाली। 'बलवद्' — बलपूर्वक। इन्द्रियों की शक्ति अद्भुत — इसलिए भगवान् की सहायता आवश्यक।",
  "2.57": "जो सर्वत्र स्नेहरहित है — इस या उस शुभ-अशुभ को पाकर न हर्षित होता है न द्वेष करता है — उसकी प्रज्ञा स्थित है।\n\n'सर्वत्र स्नेहरहित' — किसी वस्तु से आसक्ति नहीं। 'शुभम् प्राप्य' — शुभ पाकर हर्षित नहीं। 'अशुभम् प्राप्य' — अशुभ पाकर द्वेष नहीं। राग और द्वेष — दोनों से मुक्त — यही स्थितप्रज्ञ।",
  "2.61": "उन सबको वश में करके, मुझे परतत्त्व मानकर एकाग्र योग में बैठे — जिसकी इन्द्रियाँ वश में हैं उसकी प्रज्ञा स्थित है।\n\n'तानि सर्वाणि संयम्य' — उन सबको (इन्द्रियों को) नियन्त्रित करके। 'मत्परः' — मुझे परतत्त्व मानकर। 'युक्त आसीत' — एकाग्र योग में बैठे। उपाय स्पष्ट — भगवान् को परतत्त्व मानना और उनमें चित्त लगाना।",
  "2.62": "विषयों के बारे में सोचते रहने से उन पर आसक्ति होती है, आसक्ति से काम उत्पन्न होता है, काम से क्रोध उत्पन्न होता है।\n\nपतन की क्रमिक सीढ़ी — ध्यान → संग → काम → क्रोध → सम्मोह → स्मृतिभ्रंश → बुद्धिनाश → सर्वनाश। यह अत्यन्त महत्त्वपूर्ण कार्य-कारण-श्रृंखला है जिसे अगले श्लोक में पूरा किया जाएगा।",
  "2.53": "जब श्रुतिविचलित बुद्धि समाधि में अचल स्थिर हो जाएगी — तब योग की प्राप्ति होगी।\n\n'श्रुतिविप्रतिपन्ना' — जो श्रुतियों के भिन्न-भिन्न वचनों से विचलित होती थी। 'समाधावचला' — समाधि में अचल। यह अवस्था ही योग है — जहाँ बुद्धि किसी भी बाहरी प्रभाव से न डोले।",
  "2.39": "हे पार्थ, सांख्य में यह बुद्धि तुम्हें बताई — अब योग में सुनो। इस बुद्धि से युक्त होकर तुम कर्मबन्धन को तोड़ दोगे।\n\n'एषा ते अभिहिता सांख्ये' — जीवतत्त्व का ज्ञान (श्लोक 11-37) सांख्य। 'योगे त्विमां श्रृणु' — अब कर्मयोग सुनो। बुद्धियोग — व्यवसायात्मिका बुद्धि — से जुड़कर कर्मबन्धन तोड़ा जा सकता है।",
  "2.49": "हे धनञ्जय, बुद्धियोग से कर्म दूर (हीन) है। बुद्धि में शरण लो। फल के लिए कर्म करने वाले कृपण हैं।\n\n'दूरेण हि अवरं कर्म बुद्धियोगात्' — बुद्धियोग की तुलना में साधारण कर्म निम्न। 'बुद्धौ शरणम् अन्विच्छ' — बुद्धियोग की शरण लो। 'कृपणाः फलहेतवः' — जो फल के लिए कर्म करते हैं वे 'कृपण' हैं — दीन, संकुचित।",
  "2.40": "इस मार्ग में न आरम्भ का नाश है, न विपरीत फल की बाधा। इस धर्म का थोड़ा-सा भी महाभय से रक्षा करता है।\n\n'नेहाभिक्रमनाशोऽस्ति' — एक बार भी भगवान् की ओर लिया गया कदम कभी व्यर्थ नहीं। 'प्रत्यवायः' — विपरीत फल — इस मार्ग में नहीं। 'महतो भयात्' — संसारचक्र के महाभय से — थोड़ा-सा अभ्यास भी रक्षा करता है।",
  "2.51": "बुद्धियुक्त ज्ञान से जन्मबन्धन से मुक्त, निर्दोष पद को जाते हैं।\n\nज्ञानपूर्वक नैष्कर्म्यकर्म — जन्म-जन्म के बन्धन से मुक्त करता है। 'अनामयम् पदम्' — दोषरहित, विकाररहित पद = मोक्ष। भगवद्ज्ञानपूर्वक कर्म — मोक्षदायक।",
  "2.68": "इसलिए हे महाबाहो, जिसकी इन्द्रियाँ सब ओर से विषयों से संयमित हैं — उसकी प्रज्ञा स्थित होती है।\n\n'तस्माद्' — इन सभी कारणों से। 'महाबाहो' — महावीर अर्जुन को — इन्द्रियसंयम का कर्तव्य याद दिलाते हैं। 'सर्वशः' — सब ओर से। यह स्थितप्रज्ञ के लक्षण-खण्ड का उपसंहार।",
  "2.47": "तेरा अधिकार केवल कर्म में है, फलों में कभी नहीं। तू कर्म के फल का कारण भी मत बन, और अकर्म में भी आसक्त मत हो।\n\nयह गीता का सर्वाधिक प्रसिद्ध श्लोक। 'कर्मण्येवाधिकारस्ते' — अधिकार केवल कर्म में। 'मा फलेषु कदाचन' — फल में अधिकार नहीं। 'मा कर्मफलहेतुर्भूः' — फल के लिए कर्म मत करो। 'मा ते सङ्गोऽस्त्वकर्मणि' — अकर्म में भी आसक्ति नहीं।\n\nफल भगवान् के हाथ में — मनुष्य का काम केवल करना है।",
  "2.64": "किन्तु जो अपने वश में आत्मा को लाकर — राग-द्वेष से रहित होकर — स्वतः नियन्त्रित इन्द्रियों से विषयों में विचरता है — वह प्रसाद प्राप्त करता है।\n\n'आत्मवश्यैः' — जो अपने अधीन हैं। 'विधेयात्मा' — आज्ञाकारी आत्मा। 'प्रसाद' — चित्त का प्रसन्न स्थिर भाव। राग-द्वेष छोड़कर विषयों में जाना — पाप नहीं; राग-द्वेषपूर्वक जाना — पाप।",
  "2.45": "वेद त्रिगुणविषयक हैं — हे अर्जुन, तुम निर्द्वन्द्व, नित्यसत्त्व, निर्योगक्षेम, आत्मवान् बनो।\n\n'त्रैगुण्यविषया वेदाः' — वेद दिखने में त्रिगुणों से जुड़े। किन्तु उनका गहरा अर्थ भगवद्ज्ञान है। 'निर्द्वन्द्व' — द्वन्द्वरहित। 'नित्यसत्त्व' — सदा सत्त्वगुण में स्थित। 'निर्योगक्षेम' — नए की प्राप्ति और पुराने की रक्षा की चिन्ता से रहित। 'आत्मवान्' — आत्मज्ञानी।",
  "2.70": "जिस प्रकार सभी जल नदियाँ आकर समुद्र में मिलती हैं — समुद्र अचल रहता है — वैसे ही जिसमें सभी कामनाएँ आकर मिल जाती हैं वह शान्ति पाता है — कामी नहीं।\n\nसमुद्र-दृष्टान्त। समुद्र अचल — नदियाँ आती हैं — समुद्र भरा नहीं। वैसे स्थितप्रज्ञ — विषय आते हैं — वह प्रभावित नहीं। 'कामकामी' — जो काम चाहता है — शान्ति नहीं पाता।",
  "2.71": "जो पुरुष सभी कामनाओं को त्यागकर, ममता-अहंकाररहित होकर विचरता है — वह शान्ति पाता है।\n\n'सर्वान् कामान्' — सभी। 'निर्ममः' — मेरा-पन से रहित। 'निरहंकारः' — अहंकाररहित। 'शान्तिम् अधिगच्छति' — शान्ति प्राप्त करता है। ये तीनों लक्षण मिलकर पूर्ण स्थितप्रज्ञ का चित्र बनाते हैं।",
  "2.66": "अयुक्त की बुद्धि नहीं, अयुक्त की भावना नहीं — भावनाहीन को शान्ति नहीं, अशान्त को सुख नहीं।\n\n'अयुक्तस्य' — जो योग में नहीं। चारों निषेध — बुद्धिः नास्ति, भावना नास्ति, शान्तिः नास्ति, सुखम् नास्ति। यह एक उद्धरण-श्रृंखला है — विपरीत क्रम में। पहले शान्ति, तब भावना, तब बुद्धि।",
  "2.46": "सब ओर से परिपूर्ण जलाशय होने पर जितना उपयोग छोटे जलाशय से — उतना ही उपयोग ब्राह्मण के लिए सब वेदों में।\n\nजल का दृष्टान्त। छोटे कुएँ का उपयोग तब है जब बड़ा जलाशय न हो। जब सब ओर से जल भरा हो तो कुएँ की आवश्यकता नहीं। ज्ञानी ब्राह्मण को — जिसे भगवद्ज्ञान है — वेदों का उपयोग उतना ही जितना आवश्यक। वेद साधन हैं — भगवान् साध्य।",
  "2.65": "प्रसाद में सभी दुःखों का नाश होता है। प्रसन्नचित्त की बुद्धि शीघ्र स्थिर हो जाती है।\n\n'प्रसादे सर्वदुःखानां हानिः' — चित्तप्रसाद से दुःखों का अभाव। 'बुद्धि परियवतिष्ठते' — बुद्धि स्थिर हो जाती है। यह क्रम — इन्द्रियनियन्त्रण → प्रसाद → दुःखनाश → बुद्धिस्थैर्य — स्थितप्रज्ञ बनने का मार्ग।",
  "3.2": "व्यामिश्रेण इव वाक्येन बुद्धिम् मोहयसि इव मे |\n\nतत्... एकं वद सेख्य येन श्रेयः अहम् अप्लुयम् - दोनों के शब्दों से।\nनिर्णय लेने में भ्रमित करता है। तो, एक निर्णय करें और कहें: किससे\nमुझे क्या अच्छा मिला?\n\nयहां 'व्यामिश्रेण' का अर्थ विरोधाभास (00788610070/00115170) है। “यह इस तरह है\nक्या सही है और क्या गलत इसका निष्कर्ष मुझे शब्दों से नहीं मिलता, और वो\nमुझमें जानने की शक्ति नहीं है. मुझे आपकी बात समझ नहीं आयी. मैं जिस भी राह पर चलूं\nश्रेय किसको मिलता है? कृष्ण मुझे मेरे जीवन को सार्थक बनाने का निश्चित उपाय बताएं\nअर्जुन पूछता है.",
  "3.5": "न हि कश्चित् क्षणं अपि जातु तिष्ठति अकर्म कृत।\nकार्यते हि अवसः कर्म सर्वः प्रकृतिजयः गुणायः -- कोई एक क्षण भी निष्क्रिय नहीं रह सकता। प्रत्येक व्यक्ति प्रकृति के गुणों से अवगत हुए बिना कर्म (ईश्वर के अधीन) करता है।\n\nकर्मत्याग से सिद्धि नहीं मिलती। इतना ही नहीं, कर्मत्याग संभव नहीं है। हमारा अन्नमय और प्राणमयकोश निरंतर कार्य कर रहा है। जीवित रहते हुए निष्क्रिय रहना असंभव है।",
  "2.63": "क्रोध से सम्मोह होता है, सम्मोह से स्मृतिभ्रंश, स्मृतिभ्रंश से बुद्धिनाश — और बुद्धिनाश से विनाश।\n\nपिछले श्लोक की श्रृंखला पूरी। 'सम्मोह' — विवेक का नाश। 'स्मृतिभ्रंश' — अच्छे-बुरे की याद चली जाती है। 'बुद्धिनाश' — विवेकबुद्धि नष्ट। 'प्रणश्यति' — मनुष्य का पतन। केवल क्रोध से — अन्ततः सर्वनाश।",
  "2.69": "जो सब भूतों के लिए रात्रि है — उसमें संयमी मुनि जागृत है। जिसमें भूत जागते हैं — वह ज्ञानी मुनि के लिए रात्रि है।\n\nअत्यन्त गूढ़ श्लोक। दो 'रात्रि-दिन' — (१) विषयजगत् जो लोगों के लिए दिन है, वह ज्ञानी के लिए रात्रि; (२) आत्मज्ञान जो ज्ञानी का दिन है, वह लोगों के लिए रात्रि। दोनों की दृष्टि विपरीत।",
  "3.6": "कर्मेन्द्रियाणि संयम यः अस्ते मनसा चरण |\nइन्द्रिया अर्थं विमूधा आत्मा मिथ्या आचार: सः उच्यते- कर्मेन्द्रियों का अदुमित्तु स;\nजो मूर्ख अपने मन से कामुक वस्तुओं का स्वप्न देखता है, वह पाखंडी है।\n\nइस श्लोक में कृष्ण ने एक महत्वपूर्ण बात कही है. आम तौर पर आज की दुनिया में\nहम बाहरी आवरण को अधिक महत्व देते हुए देखते हैं। मन में सारी इच्छा\nफिर भी ऐसे लोग हैं जो किसी चीज़ के डर से बाहरी तौर पर धार्मिकता से जीते हैं। कृष्ण\nइसे पाखंडी धर्म कहा जाता है. हमें सबसे पहले अपने विवेक को धोखा देना होगा\nजीना चाहिए. बाहरी अनुष्ठान से पहले आंतरिक अनुष्ठान की पवित्रता महत्वपूर्ण है। यदि नहीं तो कभी नहीं\nकोई मुक्ति नहीं है. कर्मेन्द्रियों में लिप्त होना, मन से ही कामुक चीजों के सपने देखना\n\nकृष्णा का कहना है कि थुलिगेडी एक पाखंडी है।\n\nयस्तिन्द्रियाणि मनसा निम्यारभतेर्जुन |\nकर्मेन्द्रियैः कर्मयोगमसक्तः स विशिष्यते",
  "3.7": "यः तु इन्द्रियाणि मनसा निम्या अर्भते अर्जुन |\n\nकर्म इन्द्रियः कर्मयोगं असक्तः सः विशिष्यते - हे अर्जुन, इन्द्रियाँ\nजो मानसिक बल से विजय प्राप्त करता है, वह फल की आसक्ति को त्यागकर इंद्रियों के माध्यम से सिद्धि में लग जाता है\nबाकी\n\nजब मन शुद्ध हो और इन्द्रियों पर मानसिक लगाम मजबूत हो - कर्मेन्द्रिय द्वारा\nकरने की सिद्धि कर्मयोग बन जाती है। यह शुद्ध आध्यात्मिक उपलब्धि है. इस अवस्था में इन्द्रियाँ\nभटको मत. अपने जीवन स्वरूप की प्रकृति के अनुसार मन की पवित्रता से किया गया कर्म\nसच्ची आध्यात्मिक उपलब्धि. जो व्यक्ति इस प्रकार की उपलब्धि में संलग्न होता है उसे बहुत अच्छा महसूस होता है। वे ऐसे ही हैं\nअंदर या बाहर हुए बिना, मानसिक शक्ति से इंद्रियों पर विजय प्राप्त करें और फल प्राप्त करें\nत्याग दिया और चढ़ गया.\n\nनियतं कुरु कर्म त्वं कर्म ज्यौ ह्यकर्मणः |\nफिजियोलॉजिस्ट चा ते प्रसिद्ध कर्मणाः",
  "3.12": "इष्टं भोगं हि वः देवः दास्यन्ते यज्ञ भवितः |\nतैः दत्तं अप्रदया एभ्यः यः भुंक्ते स्तेनः एव सः - ऐसे बलिदान से देवता मजबूत होते हैं।\nआपकी मनोकामना पूरी करता है. जो कोई उन्हें उनका दिया हुआ भोजन दिए बिना खाता है, वह चोर है\n\nठीक है\n\nयह प्रकृति हमें वह देती है जिसकी हमें आवश्यकता होती है। तो हमारे लिए जो इसका उपयोग करते हैं\nआभार चाहिए. इसके अलावा यदि सत्ता अहंकार दिखाए और कहे कि 'यह मेरा कर्तव्य है' तो कोई मुक्ति नहीं है। प्रकृति\nजो कोई दिया हुआ धन बिना धन्यवाद किए ले लेता है और कहता है, 'यह मेरा धन है' वह चोर है!\n\nयज्ञसिष्टशिनः सन्तो मुच्यन्ते सर्वकिलबिषाः।\n\nभुंजते ते त्वघं पापा ये पचन्त्यात्मकारणात्",
  "3.14": "अन्नत् भवन्ति भूतानि पर्जन्यात् अन्न संभवः।\n\nयज्ञात भवति पर्जन्यः यज्ञः कर्म समुद्भवः - भोजन से प्राणियों की उत्पत्ति; खाद्य फसल\nसूरज से[बादल से]। सौर ऊर्जा की वृद्धि (मेघ का जन्म)-यज्ञ से; यज्ञ का पालन-\nकर्म से.\n\nकर्म ब्रह्मोद्भवम् विधि ब्रह्माक्षरसमुद्धवम् |\nतस्मात् सर्वगतं ब्रह्म नित्यं यज्ञे प्रतिष्ठितम्...",
  "3.10": "सह यज्ञः प्रजाः सृष्ट्वा पुरा उवाच प्रजापतिः |\n\nअनेना प्रसाविष्यध्वं एषा वः अस्तु इष्ट काम धुक - पूर्व में भगवान प्रजापति का एक पूजनीय रूप।\nउन्होंने कर्म सहित मनुष्य की रचना की और कहा: इससे बढ़ो, यह तुम्हारा है\nमनोकामना पूर्ण हो.\n\nअतीत में चतुर्भुज विचारशील मानवों का निर्माण हुआ, जिनके लिए उनका उत्सव मनाया जाना चाहिए\nसृष्टि ने यज्ञ किया। और कहा, \"इस पूजा से जो चाहो पा लो। यही तुम हो।\"\nवह कौन सी वासना है जो अभीष्ट अभिशाप देती है।” जैसा कि पहले बताया गया है, 'यज्ञ' का अर्थ है 'ईश्वर'\nपूजा का तरीका; 'दान' और 'संगतिकरण' भी यज्ञ हैं। दान विशेष है\nअर्थ है. अपने पास पर्याप्त होना और जो चीज़ किसी को नहीं चाहिए उसे दूसरे को दे देना दान नहीं है। अपने आप में\nजब दो वक्त का खाना हो और दूसरे के पास एक वक्त का खाना भी न हो तो उसका अपना होता है\nभोजन देना और बाँटना ही वास्तविक दान है। दूसरे के दुःख में पिघलना ही सच्चा दान है।\nअब संगतीकरण का अर्थ है एक ओर ज्ञान के लिये कला। प्रवचन एक संश्लेषण है.",
  "3.15": "कर्म ब्रह्मौद्भवम् विद्धि ब्रह्म अक्षर समुद्धवम् |\nतस्मात् सर्व गतं ब्रह्म नित्यं यज्ञे प्रतिष्ठितम् - कर्म निष्ठा भगवान की ओर से है;\nईश्वर की अभिव्यक्ति- वेदों से। इसलिए सर्वव्यापी भगवान सदैव यज्ञ में उपस्थित रहते हैं।",
  "3.13": "यज्ञ शीर्ष अशिन्ह संतः मुच्यन्ते सर्व किल्बिषाः |\n\nभुंजते ते तू अघम पापः ये पचन्ति आत्मा वर्णत- शेष को देवताओं को समर्पित कर दो।\nउलान के सजहा सभी पापों से मुक्त हो जाते हैं। जो लोग अपने लिये चावल पकाते हैं, यह उनका ही पाप है\nवे खाते हैं.\n\nजो कोई जो कुछ प्राप्त किया है उसे अर्पित करता है और उसे प्रभु का प्रसाद समझकर स्वीकार करता है\nवे जीवन की सभी अशुद्धियों से मुक्त हो जाते हैं और स्वच्छ जीवन जीते हैं। किसके घर में\nयदि वह अपने लिए चावल खाता है, तो वह चावल नहीं पाप खाता है। ये खाना हमारे लिए\nईश्वर दाता है. उनके प्रति हमें सबसे पहले कृतज्ञता प्रकट करनी चाहिए। इसके अलावा, यह मेरा है\nसंपादित करें, यदि हमारे अंदर यह भावना विकसित हो जाए कि मैं इसे किसी और के साथ क्यों साझा करूं?\nहम अपने पाप की गांठ विकसित कर लेते हैं। यदि सृष्टि के उद्देश्य के रूप में स्थापित नहीं किया गया है (08:176 ॥/॥)।\nहम जो कमाते हैं वह भी हमारे लिए पर्याप्त नहीं है।\n\nअन्नद भवन्ति भूतानि पर्जन्यदन्नसम्भवः |\nयज्ञाद् भवति पर्जन्यो यज्ञः कर्मसमुद्ध वः",
  "3.1": "अर्जुनः उवाच- अर्जुन ने कहाः\n\nजायसी चेत कर्मणः ते माता बुद्धिः जनार्दन |\n\nतत् किं कर्माणि घोरे मम नियोजयसी केशव - हे जनार्दन, कायका से भी बेहतर जानो।\nयदि तुम्हारी यही इच्छा है, तो तुम मुझे इस हत्याकाण्ड में क्यों डाल रहे हो?\n\nबाल?\n\nकृष्ण द्वारा ज्ञान और कर्म की व्याख्या अर्जुन को भ्रमित करती है। क्या है?\nरास्ता मुफ़्त है या नहीं, यह सवाल उसे परेशान करता है। कृष्ण एक बार ज्ञान के मार्ग पर चले - यह महान है\nवह कहता है; इनो ममे लड़ाई का आह्वान करता है! किसी को महान ज्ञान के पथ पर क्यों नहीं आगे बढ़ना चाहिए,\nअर्जुन असमंजस में है कि युद्ध क्यों किया जाये। इसी असमंजस में अर्जुन कृष्ण\nपूछता है: “हे जनार्दन, यदि आपकी इच्छा है कि ज्ञान का मार्ग कर्म से श्रेष्ठ है, तो मेरा\nआप निकट कर्म करने को क्यों कह रहे हैं? युद्ध भयंकर राग-द्वेषों से परिपूर्ण है\nतमसाकार्य। वह कर्म है जो आध्यात्मिक उपलब्धि के बिल्कुल विपरीत है। तो मैं ही क्यों?\nक्या तुम कार्रवाई में संलग्न हो, केशव?” वह है।\n\nइस श्लोक में अर्जुन भगवान कृष्ण को दो विशेष नामों 'जनार्दन' और 'केशव' से संबोधित करते हैं।\nहम इसे संबोधित पाते हैं। यहां अर्जुन के प्रश्न पूछने का भाव निहित है। जन-अर्दाना\nअर्थात प्रजा का नाश करने वाला! यहां लोगों का मतलब बुरे लोगों से है. जनार्दन का अर्थ है बुराई का नाश करने वाला।\n\"आप जो दुष्टों का दमन करने के लिये अवतरित हुए हैं, मेरे द्वारा यह कार्य करा रहे हैं। परन्तु यहाँ।\"\nजो भी लोग हैं वे बुरे लोग नहीं हैं। तो उन्हें मारने वाला कर्म श्रेष्ठ कैसे है? जन्म\n\nआप मोक्ष के प्रति दयालु हैं, मुझे गुरु बड़ों की हत्या के इस भयानक कर्म से मुक्त करें\nआप ऐसा क्यों कर रहे हैं?” अर्जुन का प्रश्न है\nयह विशेषण अर्जुन के समर्पण को दर्शाता है। का*ईश*व-केशव; यहां 'का' का मतलब है\nचतुर्मुखी ब्रह्मा जो सृष्टि का कारण हैं; ईशा का अर्थ है शंकर जो हत्या के लिए जिम्मेदार है। केशव\nइसका मतलब है पराशक्ति जिसमें ब्रह्म शक्ति और शिव शक्ति शामिल है जो सृजन और विनाश के लिए जिम्मेदार है। “सृजन-अवस्था-\nहे अर्जुन, जो विनाश और मोक्ष का कारण है, मुझे इस भ्रम से बचाओ\nभगवान कृष्ण के प्रति समर्पण करें.\n\nव्यामिश्रेण्येव वाक्येन बुद्धिम् मोहयशिव मई |\nतदेकं वद सेक्षयाय येन श्रेयोहामाप्नयम्",
  "2.67": "इन्द्रियों में विचरते हुए मन को जो इन्द्रिय उसे खींच लेती है — वह उसकी बुद्धि को वैसे ही हर लेती है जैसे जल में वायु नाव को।\n\nअत्यन्त सटीक दृष्टान्त। नाव जल में तैरती है — अचानक आया तूफान उसे दिशाहीन कर देता है। वैसे ही मन — एक भी इन्द्रिय खींची तो बुद्धि चली जाती है। 'तत् अस्य हरति प्रज्ञाम्' — वह (वह इन्द्रिय) उसकी प्रज्ञा हर लेती है।",
  "3.3": "भगवानुवाचा- भगवान बोले:\n\nलोके अस्मिन दवि विधा निष्ठा पुरा प्रोक्ता माया अनघा |\n\nज्ञानयोगेन सांख्यानं कर्मयोगेन योगिनम् - हे अनघ, इस संसार में दो हैं\nमैंने पहले कहा है कि इरा (मुक्ति) का प्रकार है: ज्ञान ज्ञान के मार्गों का प्रमुख है\nउपलब्धि से; कर्म उपलब्धि से कर्म पथ तक।\n\nइससे पहले कृष्ण ने ज्ञानमार्ग और कर्ममार्ग के बारे में बताया था कि यह किस आधार पर और किस स्तर पर है\nयहां वह बताते हैं कि क्या महत्वपूर्ण है. यहां कर्म योग के बारे में विशेष व्याख्या दी गई है\nशुरू होता है.\n\nइस श्लोक में 'निष्ठा' शब्द का प्रयोग हुआ है। यहां 'निष्ठा' का अर्थ जीवन की दिशा या अंत है\nस्थिति-'मोक्ष' के समान। कृष्ण कहते हैं: \"साधक दो प्रकार के होते हैं - सांख्य और योगी\"।\nयहां सांख्य का अर्थ ज्ञान के मार्ग में उपलब्धि हासिल करने वालों से है। योगी कर्मसाधना हैं\nजो हासिल करते हैं\n\nइस श्लोक पर एक सरसरी नज़र डालने पर यह कहा जाता है: “ज्ञान के साधक को ज्ञान के मार्ग पर चलना चाहिए, कर्म के मार्ग पर नहीं।\nयह देखा जाएगा कि जो इससे प्राप्त करते हैं उन्हें कर्म के मार्ग पर जाना चाहिए। यहाँ\nअर्जुन को कर्म के माध्यम से हासिल करना है, इसलिए कृष्ण उसे लड़ने के लिए कहते हैं\nऐसा लगता है कि कहा गया है. लेकिन वह वास्तविक अर्थ नहीं है. जैसा कि आप जानते हैं अर्जुन उस समय के थे\nमहान ऋषियों में से एक। तो, हम उपरोक्त अर्थ को इस श्लोक पर लागू कर सकते हैं\nव्याख्या नहीं की जानी चाहिए. यहां गहन चिंतन आवश्यक है.\n\nशास्त्रों के अनुसार ज्ञान से ही मोक्ष संभव है। मोक्ष का कोई दूसरा रास्ता नहीं है.\nफिर मोक्ष की प्राप्ति के लिए ज्ञान की आवश्यकता होती है। ज्ञान के लिए कर्म अस्तित्व में है। ज्ञान का पूरक नहीं\nकर्म कर्म नहीं है. यदि आप सुबह से लेकर शाम तक जप माला को पकड़कर बैठे रहते हैं\nहमें ऊपर नहीं ले जा सकते. यह जानते हुए भी कि जो भी कर्म होता है मृत्यु उसे ही करती है\nकर्म करना चाहिए कर्म करना ज्ञान का पूरक होना चाहिए। तो सिर्फ ज्ञान योग नहीं,\nकोई मात्र कर्म योग नहीं है. कर्म के बिना ज्ञान नहीं, ज्ञान के बिना कर्म नहीं। चंडोज्ञ\nउपनिषदों में. जैसा कि कहा गया है: \"यदेव विद्याय करोति श्रद्धा, तदेव का उपनिषद है\nवीर्यवत्तारं भवति, विज्ञानं यज्ञं तनुते।'' इसका मतलब है \"आप जो भी करते हैं उसे जानें\nज्ञान से किया गया कर्म सफल होता है। अन्यथा यह बर्बादी है”। कर्म करना है\nहमें पता होना चाहिए कि हम यह क्यों कर रहे हैं, इसे करने का परिणाम क्या है, इसे कैसे करना है।\nअज्ञानता में किया गया कर्म व्यर्थ जाता है। यहां कृष्ण ने जो कहा है वह कर्मवाच्य है\nएक मार्ग (जनकादि की भाँति) और दूसरा बुद्धिमान पथ (सनकादि की भाँति)।",
  "2.72": "हे पार्थ, यह ब्राह्मी-स्थिति है। इसे प्राप्त करके मोहित नहीं होता। इसमें अन्त-काल में भी स्थित होकर ब्रह्मनिर्वाण प्राप्त करता है।\n\n'ब्राह्मी स्थिति' — ब्रह्मभूत अवस्था, भगवत्-समीपवास। 'एनां प्राप्य न विमुह्यति' — इसे पाकर मोह नहीं। 'अन्तकाले' — मृत्युकाल में भी। 'ब्रह्मनिर्वाण' — भगवत्-मोक्ष। यह गीता के द्वितीय अध्याय का उपसंहार।\n\nइति द्वितीयोऽध्यायः — सांख्ययोगः।",
  "2.59": "विषयरहित देहधारी के लिए विषय दूर हो जाते हैं — पर रस (आसक्ति) बना रहता है। परमतत्त्व देखकर रस भी निवृत्त होता है।\n\nअहार-त्याग से विषय दूर होते हैं पर आसक्ति बनी रहती है — यह अधूरा उपाय। 'परम् दृष्ट्वा' — परमतत्त्व भगवान् का दर्शन होने पर — रस भी स्वतः छूटता है। भगवत्साक्षात्कार ही पूर्ण उपाय।",
  "3.8": "नियतं कुरु कर्म त्वम् कर्म ज्यः हि अकर्मणः |\nशरीरा यत्र अपि च ते न प्रध्यादेथ अकर्मणः - आप अपने हिस्से का कर्म करें।\nक्या कर्म तटस्थता से बेहतर नहीं है? अगर आप खाली हैं तो आपके बच्चे का सफर नहीं चलेगा.\n\nकृष्ण कहते हैं: 'तू अपने जीवन-स्वभाव के अनुरूप नियमित क्रिया है, ज्ञान का पूरक है\nकरो'. यहां अर्जुन को देखा जाए तो उसका जीवन स्वभाव अन्याय के खिलाफ लड़ना है\nदेश के नागरिकों की रक्षा करने वाले क्षत्रिय का स्वभाव | इसके अलावा देश में अन्याय भी है\nयदि कोई बिना ज्ञान के तांडव करते हुए तपस्या करता है तो वह वास्तविक योग नहीं लगता।\nकृष्ण कहते हैं, “कभी निष्क्रिय मत बनो, तुम अपना कर्म करो, तो क्या हुआ\nजब तुम्हें यह मिल जाए तो इसे महसूस करो। लेकिन करने के कर्म को ज्ञान का पूरक बनने दें। प्रभु का जागरण\nऐसा हमेशा हो।” “भगवान यह कर्म मेरे हाथों से कर रहे हैं, यह\nजब हम 'उसकी रचना' की भावना से कर्म करते हैं तो कोई भी कर्म हमें नहीं बांधता।\n\nअपनी भूमिका निभाएं, आना न भूलें और प्रवाह के प्रति जागरूक रहें।\nहरि ही ईश्वर हैं, हरि ही गुरु आधार हैं, हरि ही जगत के माता-पिता हैं।\n\nजब तक हम एक शरीर में हैं कर्म अपरिहार्य है। परोक्ष ज्ञान आने पर भी कर्म\nनिरंतर. इस प्रकार कृष्ण ने इस श्लोक के माध्यम से कर्म के सिद्धांत को हमारे सामने उजागर किया है।\n\nएक चीज़ है जिसे हमें यहीं प्राप्त करने की आवश्यकता है। शास्त्रों के अनुसार कर्म\nकर्म को दोहराने से हम कर्म के चक्र में फंस जाते हैं। लेकिन यहां कृष्ण कहते हैं-\nकर्म अपरिहार्य है. तो मुक्ति का मार्ग क्या है? हमारे इस सवाल के आगे\nश्लोक में इसका स्पष्ट उत्तर है।\n\nयज्ञार्थत् कर्मोन्योत्र लोकोयं कर्मबन्धनः |\n\nतदर्थं कर्म कौन्तेय मुक्तसंगः समाचार",
  "3.4": "न कर्मणां अनारंभात नैष्कर्म्यं पुरुषः अश्नु ते।\nनच संन्यासनात् एव सिद्धिं समाधिगच्छति - कर्मों में संलग्न न होने से संतुष्ट।\n\nकर्म से मुक्ति नहीं है. सिर्फ कर्म के फल को छोड़ने के लिए\n\nसिद्धि नहीं मिलती.\nजैसा कि शास्त्र कहते हैं, 'कर्म बंधन का मार्ग है और ज्ञान मुक्ति का मार्ग है।' लेकिन कृष्ण ने कहा -\nकि मोक्ष के दो मार्ग हैं, ज्ञान और कर्म। यहाँ इसकी व्याख्या है\nकृष्ण देते हैं. मोक्ष अकर्म से प्राप्त होता है; यदि कर्म-बंधक का संबंध है, तो एक\nशरीर में जीवन के लिए कोई कर्म न करना संभव नहीं है। शरीर आने पर कर्म क्रिया हुई\nहोता है. कर्म करने के तुरंत बाद मोक्ष नहीं मिलता। मूलतः कर्म\nछोड़ना भी संभव नहीं है. एक यांत्रिक कर्म बंधन जो ज्ञान का पूरक नहीं है। ज्ञान का पूरक\nकर्म कभी बंधनकारी नहीं होता. कर्म के फल की इच्छा किये बिना कोई भी सिद्धि प्राप्त नहीं की जा सकती। बस\nकर्मत्याग से कभी भी सिद्धि नहीं मिल सकती।\n\nनहि कश्चित् क्षणमपि जतु तिष्ठ्यकर्मकृत् |\nकार्यते ह्यवषा कर्म सर्वः प्रकृतिजैर्गुणैः 851\n\nन हि कश्चित् क्षणं अपि जातु तिष्ठति अकर्म कृत |\n\nकार्यते हि अवसः कर्म सर्वः प्रकृतिजैः गुणाः - एक क्षण के लिए भी कुछ नहीं करना।\nबेड़ा पर नहीं हो सकता. प्रकृति (ईश्वर के) गुणों से सभी अनभिज्ञ हैं।\nअधीनस्थ) कर्म करता है।\n\nकर्मत्याग से सिद्धि नहीं मिलती। इतना ही नहीं, कर्मत्याग संभव नहीं है। हमारा अन्नमय\nऔर प्राणमयकोश निरंतर कार्य कर रहे हैं। जीवित रहते हुए निष्क्रिय रहना\nअसंभव कोई भी व्यक्ति किसी भी समय एक क्षण के लिए भी निष्क्रिय नहीं हो सकता।\n\"कार्यते हि अवसः\" - शरीर के भीतर जीवन में उसके शरीर के माध्यम से, उसके मन के माध्यम से,\nवर्ड-ऑफ-वर्क हो गया है. इसमें जीवन नहीं है. यह भगवान का है.\nसम्पूर्ण ब्रह्माण्ड प्रकृति द्वारा निर्मित है। इसका मूल द्रव्य सत्त्व-रजसु-तमस्सु है। जिंदगी अपनी है\nइसका अपना स्वभाव है. तदनुसार प्रकृति के इन त्रिगुणों का प्रभाव हम पर पड़ता है।\nअतः निष्क यता निरर्थक है। हमें खुद को जीवन में शामिल करना होगा।\nकर्तव्यपरायण होना चाहिए. इसके साथ ही हम मानसिक रूप से सांसारिक दुनिया से परे सत्य के पक्ष में हैं\nमन सतर्क रहना चाहिए. सभी कर्तव्यपरायण कार्य इसी जागरूकता के साथ किये जाने चाहिए। निष्क्रियता\nवेदांत नहीं-कर्तव्याच्युति रहस्यवाद नहीं है। प्रभु चेतना के साथ आप अपने हिस्से के कर्म हैं\nजब ऐसा किया जाता है, तो कर्म और ज्ञान के मार्ग एक दूसरे के पूरक हो जाते हैं।\n\nकर्मेन्द्रियाणि संयम य अस्ते मनसा चरण |\nइन्द्रियार्थं विमूढ़ात्मा मिथ्याचारः स उच्यते",
  "3.17": "यः तु आत्मा रतिः एव सत् आत्मा त्रिप्पः च मानवः |\n\nआत्मानि एव च सन्तुष्टः तस्य कार्यं न विद्यते-परमात्मा को पाना\nवह जो दया से धन्य है, जो भगवान के उपहार (दया से) द्वारा बनाया गया है,\nएक समाधिमग्न (जो संतुष्ट है) जो सर्वोच्च सत्ता में आनंदित है, और कुछ नहीं चाहता।\nलेकिन करने को कुछ नहीं है.\n\nअपने भीतर भगवान को पाने का आनंद 'आत्मरति' है.. यह समाधि अवस्था है\nपहुंच सकते हैं सच्ची समाधि अवस्था में हमारी इंद्रियां और मन काम नहीं करते।\n'समस्थिति' भगवान को ज्ञान के रूप में प्रत्यक्ष रूप से देखने की अवस्था है। हालत में\nईश्वर से सीधा संपर्क संभव है। ऐसी अवस्था में व्यक्ति पर कोई कर्म संबंधी कलंक नहीं होता।\nईश्वर के दर्शन के बाद वह इस सांसारिक संसार से ही संतुष्ट हो जाता है और उसे नहीं चाहता। बस\nवह ईश्वर-प्राप्ति के आनंदमय सागर में डूबा हुआ है। ऐसे में उसके पास नहीं है\nकोई कर्तव्य कर्म नहीं है, वह अनुष्ठान निषेधों से मुक्त है।\n\nनैव तस्य कृतेनार्थो नाकृतेनेह कश्चन |\nनचस्य सर्वभूतेषु कश्चिदार्थव्यापाश्रयः",
  "3.22": "न मय प्रार्थना अस्ति दैव्यं त्रिषु लोकेषु किंचन |\n\nन अनवप्तरं अवप्तव्यं वर्तते एव च ​​कर्माणि -- पार्थ, मैं तीनों लोकों में हूं।\nकरने को कुछ नहीं है. बिना पाए कुछ भी पाना नहीं है. फिर भी मैं कर्म में हूँ\nलगे हुए हैं\n\nयदि ह्यहम् वर्तेयं जातु कर्मण्यतन्द्रितः |\nमम वर्त्मनुववरन्ते मनुष्यः पार्थ सर्वषा",
  "3.23": "यदि हि अहम् न वर्तेयं जतु कर्माणि अतन्द्रितः\n\nमम वर्तमान अनुवर्तन्ते मनुष्यः पार्थ सर्वसह -। हे पार्थ, मैं कभी भी\nयदि मैं सावधानी से कर्म नहीं करूंगा तो लोग हर प्रकार से मेरे ही मार्ग का अनुसरण करेंगे\nचला जाऊंगा\n\nउत्सि येदेयुरिमे लोका के कूर्यं कर्म चेदाहम्।\n\nसंकरस्य च कर्ता समुपहन्यमहि प्रजाः",
  "3.20": "कर्मणा एवहि संसिद्धिम स्थितः जनक अदायः |\nलोकसंग्रहं एव अपि संपश्यं कर्तुम् अर्हसि - जनक की तरह कर्म से ही प्राप्त होता है।\nलक्ष्य पूरा हो गया. भले ही आप लोगों को सुधारने के लिए जिम्मेदार हों, आपको कर्म तो करना ही होगा।\n\nअतीत के कई राजा इस मार्ग पर चले और मोक्ष प्राप्त किया। वे सब अपना सब कुछ त्याग देते हैं\nजंगल में नहीं गये. इसका एक अच्छा उदाहरण जनक महाराज हैं। वह समस्त राज्य सुखों के साथ है\nएक आदमी जिसने शासन किया. लेकिन उन दिनों उनके जैसा महान कोई नहीं था। बहुत बढ़िया\nवह राजा है. शुकाचार्य वैराग्य को ठीक से समझने के लिए जनक के पास आये थे!\nयही एक सच्चे अभ्यासी का जीवन है। जनक सत्ता के सभी सुखों के बीच थे और उदासीनता का जीवन जी रहे थे।\nइसलिए कृष्ण यहां जनक के नाम का उल्लेख करते हैं। कृष्ण कहते हैं: “जनक की तरह\nजब तक राजाओं ने कर्म योग के माध्यम से ज्ञान प्राप्त नहीं किया और कर्म, कर्म करके ऊंचाइयों पर नहीं पहुंचे\nबलिदान से नहीं।” इस प्रकार आप जो समाज के मार्गदर्शक हैं, समाज के लिये लड़ें\nकृष्ण कह रहे हैं.\n\nकृष्ण ने अब जब समाज का नेता गलत रास्ते पर चलता है तो कर्तव्य कर्म के बारे में विस्तार से बताया\nनिम्नलिखित छंदों में वह स्वयं को उपरोक्त प्रभाव के उदाहरण के रूप में लेते हैं\nसमझाता है.\n\nयदाचरति श्रेष्ठसत्तदेवेतरो जनः |\nस यत् प्रमाणं कुरुते लोकस्तदनुवर्ते",
  "3.11": "देवं भावयता अनेना ते देवः भवन्तु वः |\nएक वर्ष से अधिक समय तक ऋण प्राप्त करना उत्तर திதத்குத்தியாத்து-by इससे देवताओं को मदद मिलती है. वो देवदूत\nमुझे आपकी मदद करने दीजिये. एक-दूसरे की मदद करें और वरिष्ठों का कल्याण करें।\n\nजैसा कि यज्ञ की रचना करने वाले चतुर्मुख ने कहा: “यज्ञों के माध्यम से आप देवताओं के पास हैं\nउनकी मदद करें और उन्हें आपकी इच्छाएं पूरी करने दें।\" \"इस प्रकार एक दूसरे की मदद करना\nवरिष्ठता प्राप्त करें” हमेशा की तरह। हम अपने लिए वही बनाते हैं जो हम चाहते हैं\n\nवह हमारा भ्रम है. हमें जो बोना और उगाना है वह प्रकृति की एक विसंगति है\nनहीं होना चाहिए. अन्यथा हम कुछ भी नहीं उगा सकते। हर कार्य के पीछे कई लोग होते हैं\nदेवता काम पर हैं. हमारे प्रत्येक अंग में एक पंखा होता है\nएक देवदूत है. यदि वह शक्ति काम नहीं कर रही है तो हम कुछ नहीं कर सकते। तो हमारे लिए\nजीवन दो, देखने के लिए आँखें दो, सुनने के लिए कान दो, देखने के लिए अच्छा, सुनने के लिए अच्छा\nबुद्धि देना यह सब कार्य देवताओं के समूह द्वारा निरंतर किया जाता है\nएक व्यवस्था है. ऐसे में हमें ऐसी दैवीय शक्तियों का आभारी होना चाहिए। इस प्रकार\nजब हम एक-दूसरे की मदद करते हैं तो हमें खुशी मिल सकती है।\n\nयज्ञ अग्नि के समक्ष पूजा करने की प्रथा है। भगवान की पूजा में अग्नि\nसबसे महत्वपूर्ण प्रतीक. क्योंकि अग्नि अत्यंत शुद्ध है. अग्नि में जो भी डाला जाता है वह पवित्र हो जाता है।\nअग्नि भगवान का प्रतीक है। प्रभु निराकार है, वह प्रकाशमान और पवित्र है। वही गुणवत्ता\nहम आग में देख सकते हैं. अब हमें कुछ खाना है और भगवान को अर्पित करना है, वह है अग्नि\nकेवल चेहरे से. यज्ञ में हम अग्नि की नहीं अग्नि मुखेण की पूजा करते हैं\nअग्निनारायण की पूजा-यज्ञ. इस ज्ञान के बिना यदि तुम यज्ञ करोगे तो धुआं खाकर मर जाओगे!\nहमारी पूजा अग्नि नारायण से वापस नरनारायण में सूर्यनारायण से जुड़ें\nइसके लिए भगवान के लिए किया जाने वाला यज्ञ सदैव दिन के उजाले में ही किया जाता है।\nयज्ञ शक्ति, वातावरण, जो अग्नि के सात रंगों के माध्यम से सूर्य के सात रंगों में विलीन हो जाती है\nये मिलकर विश्व को मंगलमय बनाते हैं। इसे यहाँ देने और लेने की क्रिया कहा जाता है।",
  "3.18": "न एव तस्य कृतेन अर्थः न अकृतेन एह कश्चन |\n\nन च अस्य सर्वभूतेषु कश्चित् अर्थ व्यपश्रयः - क्योंकि वह कुछ और भी करता है\nइसे न करने का कोई फ़ायदा या नुक़सान नहीं है। सभी प्राणियों के बीच उसे\nकोई फल का स्वाद नहीं.\n\nसमाधि की अवस्था में उसे न तो भूख होती है और न ही प्यास। उसे बाहरी दुनिया की जानकारी नहीं है.\nऐसी अवस्था में कुछ और करना मोक्ष नहीं, कर्तव्य है\nचूक का कोई दोष नहीं है. उन्हें पंचभूतों और पंचकोशों का भी समर्थन प्राप्त है\nजरूरत नहीं। इस अवस्था में सम्पूर्ण जाति और परिवार नाम की कोई चीज़ नहीं है। उसे\nबाहरी दुनिया में कोई दिलचस्पी नहीं. इस प्रकार जो व्यक्ति समाधि की स्थिति से भगवान को देखता है, वह कर्तव्य के कारण है\nवह परे है.\n\nतस्मादसक्तः सदाचं कार्यं कर्म समाचर |\n\nअसक्तो हचरण कर्म परमाप्नोति पुरुषः",
  "3.32": "सदृशं चेष्टते स्वस्यः प्रकृतिः ज्ञानवान् अपि।\nप्रकृतिं यान्ति भूतानि निग्रहः किं करिष्यति - जो इतना जानता है वह अपने संस्कार (स्वभाव) के अनुसार कार्य करता है। सभी प्राणी संस्कार (प्रकृति) की कठपुतलियाँ हैं। आगे क्या हुआ?",
  "3.19": "तस्मात् असक्तः सातकं कार्यं कर्म समाचरः।\n\nअसक्तः हि आचरण कर्म परम आप्नोति पुरुषः - इसलिए फल की आसक्ति छोड़कर सदैव कर्तव्य परायण रहो।\nकर्म करो. आसक्ति को त्याग कर कर्तव्य में लग जाने से मनुष्य भगवान को प्राप्त कर लेता है\nजुड़ना संभव है.\n\nइन सबके कारण हमें अपना कर्तव्य कर्म करना होगा। “सब कुछ करो, लेकिन\nकिसी भी बात पर अड़े मत रहो. जो कुछ भी करना है परिणाम के बारे में सोचे बिना (अधिकार)\nबिना हासिल किये) करना। इस प्रकार कर्म करना तुम्हें भगवान तक ले जाएगा। बस इतना ही\nतुम्हें फिर कभी कर्म बंधन में नहीं धकेला जाएगा। ऐसा करने से प्रभु!\nजुड़ना केवल कर्म त्याग के माध्यम से ही संभव है,\" कृष्ण कहते हैं।\n\nयहाँ \"पुरुष\" शब्द का प्रयोग हुआ है। पुरुष जो पूर्ण शरीर में है)।\nसाधक-पुरुष जो पुर का पूर्ण उपयोग करता है। साधना शरीर में है\nजीव पुरुष सिद्धि में लगा हुआ है।\n\nकर्म के सिद्धांत को इस प्रकार समझाकर कृष्ण अगले श्लोक में एक पूरक उदाहरण देते हैं\nदेता है",
  "3.9": "यज्ञ का अर्थ है कर्मणः अन्यत्र लोकः अयं कर्म बंधनः |\nतत् अर्थं कर्म कौन्तेय मुक्तसंगः समाचर-- भगवान की पूजा का यही स्वरूप है।\n\nकर्म से भिन्न कार्य करने से ही साधक कर्म के जाल में फंसता है। हे कौन्तेय, फलदायी!\nआसक्ति को त्यागें और भगवान की पूजा के रूप में कर्म करें।\n\nयह संसार कर्म से बंधा हुआ है। लेकिन सभी कर्म बंधनकारी नहीं होते. जानने के लिए कर्म\nकभी बाध्य नहीं. हम जो कर्म करते हैं वह प्रभु चेतना के साथ किया जाना चाहिए। हम हैं\nफार्मूला गुड़िया की तरह. भगवान सूत्रधार. जब हम इस जागरूकता के साथ अपना कर्म करते हैं\nप्रत्येक कर्म भी यज्ञ बन जाता है। उदाहरण के लिए हम सांस लेते हैं। बाहर से\nहम ऑक्सीजन लेते हैं और कार्बन डाइऑक्साइड छोड़ते हैं। हमारे भीतर वह विशेष मशीन\nहमें कोई अंदाज़ा नहीं है. यह प्रक्रिया हमारी जागरूकता के बिना होती है। हमने छोड़ दिया\nपौधे हवा का उपभोग करते हैं और हमें आवश्यक ऑक्सीजन देते हैं। यह सब उस प्रभु का है\nव्यवस्था. इसी कारण भारतीय अश्वत्थ वृक्ष को सबसे अधिक ऑक्सीजन देने वाला मानते हैं\nउस वृक्ष में भगवान की विशेष विभूति छुपी हुई है। हममें से प्रत्येक ऐसे ही हैं\nजब हम कर्म में भी भगवान की महानता को जान लेते हैं, तो हम जो कर्म करते हैं वह कर्मयोग बन जाता है।\nऔर यह कभी भी बाध्यकारी नहीं है.\n\nयहां प्रयुक्त 'यज्ञ' शब्द का अर्थ है 'यज-देव-पूजा' अर्थात ईश्वर की पूजा। भगवान\nइसे यज्ञ भी कहा जाता है। अतः केवल अग्नि के समक्ष पूजा करना ही यज्ञ नहीं है।\nहमारा प्रत्येक कार्य यज्ञ बन जाता है जब हम उसे ईश्वर के प्रति समर्पण भाव से करते हैं। यहाँ हम हैं\nयह वह कर्म नहीं है जिसे जाने दिया जाना चाहिए, बल्कि यह है कि हम कर्म के बारे में कैसा महसूस करते हैं, उसमें बदलाव की जरूरत है\nआपको बस इतना ही खरीदना है। कर्म का अर्थ है 'कर*मा' जिसका अर्थ है कि हम, भगवान के राज्य के नागरिक, उसके हैं\nकर्म वह 'कर' या राजस्व है जिसका भुगतान किया जाता है। दहेज की कमाई भगवान को कभी नहीं मिलती।\nहमें स्वयं को सामाजिक कार्यों में शामिल करके उनका बकाया चुकाना होगा। यह\nजब भावना आती है तो वह कर्म से बंधे बिना मोक्ष का मार्ग बन जाता है।\n\nयहां कृष्ण अर्जुन को 'कौन्तेय' कहकर संबोधित करते हैं। यहां संबोधित करने के लिए विशेष\nएक कारण है. भले ही कुंती का जन्म और पालन-पोषण इतने बड़े परिवार में हुआ, लेकिन उन्होंने कभी भी अपनी इच्छा पूरी नहीं की\nवह पीड़िता नहीं है. अपनी युवावस्था जंगल में बिताने के बाद, जब उनके बच्चों ने साहस दिखाया तो उनका साहस बढ़ गया\nएक बहादुर महिला. उसकी पीड़ा उतनी नहीं है. लेकिन उसने कृष्ण से कहा, “मुझे कष्ट दो, क्योंकि\nतब हम हमेशा आपके साथ रहने के लिए भाग्यशाली रहेंगे! एक बहादुर आदमी जिसने दुनिया को अपना कर्तव्य दिखाया\nवह एक महिला है. ऐसी महान महिला के पुत्र होने के नाते, आप कर्म योग के बारे में जानते हैं। बुलाया\nस्वर में कृष्ण अर्जुन को 'कौन्तेय' कहकर संबोधित करते हैं।\n\nइस प्रकार ज्ञान और कर्म में सामंजस्य बिठाकर कैसे जियें\nकृष्ण ने इसे एक कहानी के रूप में आगे समझाते हुए कहा, ताकि इसे स्पष्ट रूप से समझा जा सके\nआइए उस व्याख्या को निम्नलिखित श्लोकों में देखें।",
  "3.33": "इन्द्रियस्य इन्द्रियस्य अर्थे राग वेतौ सिस्तेमौ।\nतयो न वशं आगच्छेत् तौ हि अस्य परिपंथिनौ - हर भाव में और उसकी सामग्री में राग-द्वेष निवास करते हैं। उनके शिकार मत बनो; वे साधक के मार्ग के शत्रु हैं।",
  "3.25": "सकतः कर्माणि अविद्वंसः यथा कुर्वन्ति भारत |\n\nकुर्यात् विद्वान् तथा असक्तः चिकिरशुः लोक संकरम् -- हे भारत, अज्ञानी का फल।\nनन्ति के लिए कर्म किसी तरह किए जाते हैं, जो यह जानता है उसे कर्म-फलदा नन्ति भी करना चाहिए\nसमाज छोड़ने और सुधारने के लिए.\n\nबिना समझे लोग इच्छा से कर्म करते हैं। परन्तु जाननेवाला, बुद्धिमान मनुष्य, कोई फल नहीं देता\nबिना शक्ति प्राप्त किये उसे निष्काम कर्म करना चाहिए। \"मैं अपनी आंखों के सामने बड़ा हो रहा हूं\nराष्ट्र के मार्गदर्शक के रूप में प्रभु की सेवा करते हुए, प्रभु मेरे साथ क्या कर रहे हैं?\nकर्म ``खुशी देने'' के इरादे से किया जाना चाहिए। यही सच्चा कर्मयोग है।",
  "3.26": "न बुद्धि भेदं जनयेत् अज्ञातं कर्म संगीनम् |\n\nजोशयेत् सर्व कर्माणि विद्वान् युक्तः समाचरन्--बिना समझे फल की लज्जा है।\nकर्ता का विश्वास नहीं डिगना चाहिए. वह सर्वज्ञ है\nउन्हें कर्म करके प्रसन्न करना चाहिए।\n\nसमाज में बहुत से अभागे लोग हैं। हर कोई नहीं समझता. वे उस पर विश्वास करते हैं\nवे उसी हिसाब से खड़े हैं. किसी जानकार को यह अंधविश्वास लग सकता है। लेकिन कभी नहीं\nमत जाओ और ऐसे लोगों का मजाक मत उड़ाओ। हर पत्थर का एक नाम है\nइसे भगवान के रूप में पूजा जा सकता है। समर्पण में उसका महान विश्वास उसकी रक्षा करता है।\nइस पर उपहास करना मूर्खता है. वह विश्वास की ऐसी बुनियाद पर जीता है\nवे आशा में जीते हैं. उनमें शाश्वतता का बोध है. सार्वभौमिक, सर्वज्ञ\nऔर क्या सर्वशक्तिमान ईश्वर के लिए पत्थर के चेहरे से उसकी रक्षा करना संभव नहीं है? इसलिए\nऐसे लोगों पर कभी मत हंसो. उसे छोड़कर धीरे-धीरे उसे ज्ञान के क्षितिज पर लाना\nप्रयास तो करना ही होगा. सब कुछ सामाजिक सरोकार से करना चाहिए, लेकिन सब वैराग्य से\nकर्म करके अज्ञानी को ज्ञान देना चाहिए।",
  "3.21": "यत् यत् अचरति श्रेष्ठः तत् तत् एव उतरः जनः |\n\nसः यत् प्रणाम कुरुते लोकः तत् अनुवर्तते--नेता क्या करता है।\nबाकी लोग भी उसी राह पर चलते हैं. लोग वही हैं जिन्हें वह आधार के रूप में उपयोग करता है\nउसी से पीठ चढ़ती है.\n\nजो समाज में वरिष्ठ माना जाता है (उम्र में, व्यवहार में, ज्ञान में श्रेष्ठ) वह समाज का मार्गदर्शक होता है\nजो आदमी यह कर सकता है, जो शीर्ष पर है, वह वैसे ही चलता है, बाकी लोग भी वैसा ही करते हैं\nआगे बढ़ेंगे यहां अर्जुन समाज के नेता हैं। समाज वही है जो वह करता है\nअनुसरण करता है। क्योंकि साधारण मनुष्य शास्त्र आदि नहीं जानते, वे तो आदर्श मात्र हैं\nवे उन लोगों का अनुसरण करते हैं जिन्हें वे व्यक्तिगत मानते हैं। एक नेता की शपथ क्या होती है?\nवह जो करते हैं आम लोग उसका अनुसरण करते हैं।'\n\nइस श्लोक में कृष्ण द्वारा दिया गया संदेश हमें अपने दैनिक जीवन में मिलता है। एक\nयदि संस्था के मुखिया का आचरण एवं आचरण सही दिशा में नहीं है तो संस्था\nगिरावट नजर आ रही है. बुरी शक्तियां उत्पन्न होंगी. क्योंकि नेता क्या है\nउसके अधीन लोग उसी शपथ का पालन करते हैं जैसे कि उनके पास यह थी ही नहीं\nअनुसरण करना शुरू कर देता है. इस कारण कोई भी नेता कितना भी सावधान क्यों न हो, वह पर्याप्त नहीं है। एक\nयदि देश का मुखिया ही भ्रष्ट हो तो पूरा देश भ्रष्टाचार के रास्ते पर चल पड़ेगा\nसम्भावना है. मनुष्य आम तौर पर अच्छाई के बजाय अच्छाई का अनुसरण करता है\nतेजी से बुराई आने की संभावना अधिक होती है। उदाहरण के लिए एक अच्छा शिक्षक धूम्रपान करता है\nयदि वह शौक़ीन है, तो उसके छात्र उसके ज्ञान से कहीं अधिक उसके होते हैं\nआदत को शपथ मानकर बुरा रास्ता अपनाने की संभावना अधिक होती है। ये है\nबुजुर्गों के गलत रास्ते पर चलने से समाज पर बुरा प्रभाव पड़ता है। यह बहुत ज्यादा है\nखतरनाक-हमें इसके प्रति सचेत रहना चाहिए।",
  "3.36": "अर्जुन उवाच-अर्जुन ने पूछा\nअथ केन प्रयुक्तः अयं पापं चरति पुरुषः |\nअनिच्चन अपि वारशेय बलात इव नियोजितः-हे वारशेय, मनुष्य पाप करता है। खुद को\nमानो किसी ने न चाहते हुए भी उसे ऐसा करने के लिए मजबूर किया हो! यह किसकी प्रेरणा है?\n\nकृष्ण के उपदेश को सुनने के बाद अर्जुन नम्मा। एक बहुत ही महत्वपूर्ण बात जो आप सभी के लिए आती है\nवह सवाल पूछता है. \"यह जानते हुए कि पाप पुण्य है और यह जानते हुए कि यह कुछ ऐसा है जिसे नहीं किया जाना चाहिए, हे मनुष्य\nकभी-कभी वह गलतियाँ करता है—ऐसा क्यों है? जब हम सही और गलत जानते हैं तो हम गलत क्यों करते हैं?",
  "2.44": "जिनकी बुद्धि भोग-ऐश्वर्य में खिंची है — उनकी व्यवसायात्मिका बुद्धि समाधि में नहीं बनती।\n\nवेद पढ़कर भी, जो केवल फलकामना से पढ़ते हैं — उनकी बुद्धि एकाग्र नहीं होती। 'समाधौ' — स्थिर एकाग्र चित्त में। भोग-ऐश्वर्य की ओर लगी बुद्धि — निश्चयात्मिका नहीं बनती।",
  "3.24": "उत्सीदेयः इमे लोकः न कुर्यं कर्म चेत अहम् |\n\nसंकरस्य च कर्ता सम उपहन्यं इमः प्रजाः - यदि मैं यह कर्म नहीं करता हूँ\nसभी लोग भटक जाते हैं और नष्ट हो जाते हैं। इन सब मनुष्यों में धर्म की मिलावट का कारण मैं ही हूँ\nयह ऐसा है मानो इसे हाथ से ध्वस्त किया गया हो।\n\nउपरोक्त तीन श्लोकों में कृष्ण ने स्वयं को एक उदाहरण के रूप में प्रयोग किया है\nविषय को समझाता है. अर्जुन के सारथी बनकर खड़े कृष्ण कहते हैं- ''मेरे लिए कुछ\nऐसा कुछ भी नहीं है जिसे किया जाना चाहिए या नहीं किया जाना चाहिए जिससे परेशानी हो, लेकिन मैं कर्तव्य से बंधा हूं\nकर्म में खड़ा हूँ।” तीनों लोकों में सृष्टि-स्थिति-संहार उसका शाश्वत कर्म है।\nभगवान जो कर रहे हैं, वह सब कुछ अपने प्रिय भक्तों के लिए, प्राणियों के लिए कर रहे हैं\nलेकिन लाभ के लिए नहीं.\n\nयदि कृष्ण स्वयं को दैनिक कर्म में शामिल नहीं करते, तो बाकी सभी लोग ऐसा करते\nउसने अपनी शपथ पूरी की और अपना रास्ता अपनाया। इसी कारण भगवान अवतरित हुए हैं\nएक साधारण मनुष्य के रूप में प्रकट होकर, अपने दैनिक कर्म, कर्तव्यपरायण कर्म करते हुए\nप्रबंधन यदि आप कृष्ण अवतार को देखें, तो कृष्ण संध्यावंदने जैसे बुनियादी कर्म को न चूकें\nयह उसके लिए नहीं, बल्कि उसका अनुसरण करने वाले लोगों के मार्गदर्शन के लिए कर रहा था।\n\nकृष्ण कहते हैं, \"यदि मैं कर्म न करूँ तो सारा संसार कर्म का भाव खो देगा।\"\nवह भटक जाता है, स्वच्छंदता आ जाती है और निश्चित व्यवस्था चली जाती है।'' किसके लिए क्या?\nधर्म तो करना ही पड़ेगा. यह एक सिस्टम है. अन्यथा हर कोई वैसा ही है जैसा वह उचित समझता है\nवे ऐसा करना शुरू कर देते हैं. \"इससे अराजकता और जिम्मेदारी पैदा होती है\nहम होंगे, ”कृष्ण कहते हैं।",
  "3.29": "(नागा0\n\nप्रकृतिः गुण सम्मूधाः सज्जन्ते गुणकर्मसु |\n\nतं अकृतस्नाविदः मंडं कृतस्नावित् न। विचालयेत - प्रकृति के अंग\nजो लोग इंद्रियों में लीन हैं वे इंद्रियों की गतिविधियों से चिपके रहते हैं। भर में\nजो लोग सत्य को नहीं जानते उन्हें उन लोगों से भ्रमित नहीं होना चाहिए जो पूर्ण रूप से जानते हैं।\n\nजो लोग प्रकृति की विशेषता वाले कामुक सुखों में डूबे हुए हैं; मूल प्रकृति के त्रिगुण का\nमुग्ध, सत्य न जानने वाला, मुग्ध; वह कहता है कि वह ईश्वर के गुणों के अधीन है\nजो जागे हुए नहीं हैं-उन्हें कृष्ण ने 'प्रकृतेर्गुण सम्मूदः' कहा है। ऐसे लोग\nभगवान के गुणों और कार्यों को अपना मानकर वे कहते हैं, 'मैं ही सब कुछ हूं, सब मुझसे हैं।'\nऐसे लोगों में सत्य या पूर्ण जानने की क्षमता नहीं होती।\nउन्हें 'पूर्ण जानने वालों' से भ्रमित नहीं होना चाहिए। जानिए उनमें क्या सच्चाई है\nयदि योग्यता होगी तो वे उस स्थिति से बाहर आ जायेंगे। उनमें से किसी में भी योग्यता नहीं है\nभरा नहीं जा सकता; जो पुण्य था उसे कोई छीन नहीं सकता. सच कौन जानता है\nआप चाहें तो उनके साथ जुड़ सकते हैं और उनसे या उनके लिए सीख सकते हैं\nसमझा सकते हैं.\n\nमय सर्वाणि कर्माणि संन्यस्का\n\nयद्यात्मचेतासा |\n\nनिराशिरनिर्ममो भूत्वा युध्यस्व विगतज्वरः",
  "3.43": "[बन्नञ्जे गोविन्दाचार्य के भाष्य में अध्याय 3 में 42 श्लोक हैं — यह 3.43 (यदि है) उनके मूल पाठ में समाहित है। अध्याय 3 का निष्कर्ष — एवं बुद्धेः परं बुद्ध्वा संस्तभ्यात्मानमात्मना, जहि शत्रुं महाबाहो कामरूपं दुरासदम् — इस अद्भुत ज्ञानयोग उपदेश के साथ पूर्ण हुआ।]",
  "3.35": "श्रेयन् स्व धर्मः विगुणः परधर्मात् सु अनुष्ठितत् |\n\nस्वधर्म निधनं श्रेय: परधर्मः भय अवहा - एक ऐसा धर्म जो किसी के स्वभाव से अलग है।\nसहज धर्म का अच्छे से अभ्यास करने की अपेक्षा आधे-अधूरे मन से अभ्यास करना बेहतर है।\nधर्म में मृत्यु से प्रकृति श्रेष्ठ है। विदेशी धर्म तो उससे भी अधिक भयानक है।\n\nजैसा कि पहले उल्लेख किया गया है, प्रत्येक जीवन की अपनी प्रकृति होती है और उसे बदलने की आवश्यकता होती है\nजीवन के स्वभाव के अनुसार नहीं आता, हमारा धर्म स्वधर्म है। यह एक प्राकृतिक प्रक्रिया है. हमारा स्वभाव\nयदि प्रकृति कुछ है तो हमें इसे अन्य चीजों के बिना ही करना चाहिए। इस कारण माता-पिता उनके हैं\nबच्चों पर स्वाद थोपने की बजाय बच्चों के असली स्वभाव को पहचानें और उनके अनुरूप व्यवहार करें\nभविष्य को आकार देना होगा. अन्यथा उनका भविष्य बर्बाद हो जायेगा. बच्चों की प्रतिभा\nयह उनके स्वाभाविक स्वभाव में है. प्रत्येक व्यक्ति अपने जीवन स्वभाव के अनुसार कार्य करता है\nकायम रहना चाहिए और किसी अन्य धर्म का पालन नहीं करना चाहिए। यहाँ कृष्ण कहते हैं “तुम्हारा\nयद्यपि स्वधर्म के आचरण में दोष है, तथापि यह विदेशी धर्म के आचरण से बेहतर है।\nइससे कोई फर्क नहीं पड़ता कि कोई व्यक्ति परधर्म का कितनी अच्छी तरह से पालन करता है, इसमें कोई अच्छाई नहीं है, यह घृणित है या\nभयानक.\n\nअर्जुन का स्वभाव यहाँ युद्ध करना है। वह इसे छोड़कर तपस्या करने वन में चले गये\nजाना उसके अपने धर्म के विरुद्ध है। इसलिए स्वधर्म का पालन करो, राग द्वेष छोड़ो\nकृष्ण कह रहे हैं लड़ो.",
  "3.16": "एवं प्रवर्तितं चक्रं न अनुवर्तयति इह यः |\n\nअघा अयः इन्द्रिय हमामः मोघं पार्थ सः जीवति - इस प्रकार संसार का जूआ\nजो व्यक्ति निरंतरता नहीं रखता वह पाप का जीवन जीता है और कामुक सुखों में डूबा रहता है। हे पार्थ,\nउसका जीवन बर्बाद हो गया.\n\nअन्न से ही जीव का जन्म होता है। भोजन के बिना कोई जीवन नहीं है. यह भोजन फसलों से प्राप्त होता है। फसल करना\nबुनियादी सौर ऊर्जा और वर्षा. वर्षा आती है बलिदानों से, ईमानदारी से जीने से आती है,\nभगवदर्पण बुद्धि द्वारा। यज्ञ का सम्पादन कर्म से होता है, हमारी गतिविधि से होता है। कर्म का अर्थ है\nकर्तव्यपरायण कार्रवाई, ईमानदार कार्रवाई. ऐसा कर्म भगवान द्वारा किया जाता है। यह भगवान (ब्रह्मा)\nवेदों (अक्षरों) में स्थित है। वेद जीव (मनुष्य) में हैं। तो यह बात है\nपहिया मानव भोजन वर्षा यज्ञ भगवान वैदिक पुरुष। यहां वेद का अर्थ वेद है\nकोई मंत्र नहीं पढ़ना. वैदिक वाज्मय की जागृत चेतना। इस चक्र में हम अपने हैं\nकर्म को छोड़ा नहीं जा सकता. कर्म सदैव यज्ञ, भगवदर्पण के समान ही करना चाहिए।\nयदि ईश्वर की जागरूकता, वैदिक वाज्मय चेतना सभी समान हैं, तो वर्षा, वर्षा से वर्षा, फसल से फसल\nजीवन जो भी इस चक्र को जारी नहीं रखता वह संसार चक्र की गति है\nजो टूट गया है, जो समाज की स्वाभाविक धारा को तोड़ चुका है। ऐसा शुद्ध कामुक आनंद है\nवह भोग-विलास में खोकर अपना जीवन बर्बाद कर देता है।\n\nयदि हमें यहां बताए गए इस सृष्टि चक्र का ज्ञान अपने दैनिक कार्यों में हो तो हमारा जीवन सार्थक होगा।\nयदि हम सदैव उस सार्वभौमिक शक्ति के चरणों का पालन करें तो हमारा उद्धार निश्चित है। जो भी हो\nहमें डरने की जरूरत नहीं है. हमारे दैनिक जीवन को यज्ञमय बनायें\nहमें ईश्वरीय चेतना में रहने की आदत बनानी चाहिए। यह वास्तविक है\nकर्म योग. यही मोक्ष का मार्ग है. यह प्रभु तक पहुंचने का मार्ग है।\n\nइस ब्रह्मांड में सब कुछ एक दूसरे से जुड़ा हुआ है (॥15: 6606766900.\nमदद के साथ खड़ा है. कोई भी स्वतंत्र नहीं है (11117866 10! 17690676600)। हर छोटा बच्चा\nक्रिया में समस्त विश्व की शक्तियाँ भी परोक्ष रूप से भाग लेती हैं। हम जो खाना खाते हैं उसके पीछे कई लोग हैं\nनिशान हैं. यदि आप इसे याद नहीं रखते हैं, तो यह विश्व शक्ति के प्रति कृतघ्न होने जैसा है।\n\nसंसार का \"कर्मचक्र\"; इसमें हमारा \"कर्तव्यकर्म\"; हमारे \"यज्ञ यागादि\" - इसके बारे में\nकृष्ण ने विस्तार से कहा. लेकिन यहां हमारा एक सवाल हो सकता है. वह है: अतीत में कृष्ण\n\nउन्होंने कहा कि ज्ञान महान है, लेकिन उन्होंने यह भी कहा कि कर्म छूटता नहीं है. लेकिन शास्त्र में\nउन्होंने कहा कि ज्ञानी कर्म नहीं चाहते। इसका क्या मतलब है? हमारा ये सवाल खुद कृष्णा ने उठाया\nइसका उत्तर वह अगले श्लोक में देते हैं। क्या उस व्यक्ति के लिए कोई कर्म है जिसे अपने हृदय में यज्ञ करना है?\nयदि वह कर्म नहीं करता तो क्या कोई चूक है? वह कौन सी अवस्था है जिसमें मनुष्य कर्म से मुक्त हो जाता है?\nक्या मोक्ष से पहले संसार अवस्था में कर्म न करना संभव है? कर्म रहित पूर्ण\nक्या आंतरिक अवस्था में रहना संभव है? आदि प्रश्नों का कृष्ण ने स्पष्टीकरण दिया है।\n\nयस्त्वत्मरतिरेव सदात्मातृप्तश्च मानवः।\n\nआत्मन्येव च सन्तुष्टस्तस्य कार्यं न विद्यते",
  "3.30": "मै सर्वाणि कर्माणि संन्यासस्य अध्यात्म चेतसा।\nनिरासिः निर्ममः भूत्वा युध्यस्व विगत तवरः - सभी कर्म मुझे अर्पित कर दो, मुझे समर्पित कर दो\nयाचना करो, लालसा छोड़ो, कड़वाहट छोड़ो, ठंड छोड़ो और लड़ो।\n\nकृष्ण कहते हैं, \"तुम जो भी करो, मेरे लिए करो।\" यहाँ 'संन्यास'\nशब्द का प्रयोग किया जाता है. मैंने जो कुछ भी किया वह मेरा अपना नहीं था। मेरे द्वारा क्या कार्यवाही की गयी\nभगवान ने इसे मेरे हाथों से बनाया है. मेरे द्वारा जो कुछ हुआ वह ईश्वर की पूजा है\nभक्ति भावना तप. \"नहं कर्ता हरि कर्ता; हरि कर्ता ही केवलम्\"\" ; \"माय\nआपके मुख से जो भी निकले, वह आपकी प्रशंसा हो। मेरे मन में जो कुछ भी चलता है वह सब तुम्हारा है\nएक स्मृति बनो. यह विचार विकसित करें कि हर चीज़ आपकी पूजा होनी चाहिए - युद्ध में भी।\n\nकृष्ण कहते हैं.\n\nयहाँ युद्ध समूह का निष्कर्ष है। धर्मराय लगभग तेरह वर्ष पहले\nजब वहां राजसूय यज्ञ किया गया तो शिशुपाल का सिर नीचे झुक गया। तब व्यास धर्मराय के पास आये\n\"यह लगभग तेरह साल बाद होने वाले महान युद्ध का पूर्वाभास है।\"\nकहते हैं इसका मतलब है कि यह युद्ध नियति है। यहाँ अर्जुन मात्र एक उपकरण है (!1513670)।\nइसलिए, \"अपना मन भगवान पर लगाओ, लालसा छोड़ो और मन की शांति के साथ लड़ो।\"\nकृष्ण अर्जुन से कहते हैं.\n\nहमारा जीवन एक संघर्ष है. इस संघर्ष में हम वही हैं जो हम करते हैं\nईमानदार रहें. जो होगा सो होगा. इसे रोकना हम पर निर्भर है\nजो काम प्रभु ने मुझे दिया है, वह उसने मेरे ही हाथों से किया है\nउसकी पूजा की जाए. जो भी फल आता है वह प्रभु का प्रसाद है। यह\nजब कार्य दृढ़ संकल्प के साथ किया जाता है, तो चाहे कुछ भी हो, ईश्वर इसकी जिम्मेदारी वहन करेगा।\nइससे बड़ी कोई इबादत नहीं है. यही जीवन संदेश कृष्ण ने गीता के माध्यम से हमें दिया है। इस का\nफलश्रुति के रूप में अगले दो श्लोक हैं।",
  "3.39": "अवृतं ज्ञानं एतेन ज्ञानिनः नित्यवैरिण |\n\nकाम रूपेण कौन्तेय दुष्बुरेण अनलेना च - हे कौन्तेय, आग की तरह भस्म करने वाले\nयह अतृप्त, अंतहीन वासना अभ्यासी की शाश्वत शत्रु है। यह कविता उन लोगों के लिए है जो जानते हैं\nफीका पड़ जाता है.\n\nइस रजोगुण का पर्दा यह है कि जिसके पास ज्ञान है उसके लिए ज्ञान बेकार है, जिसके पास ज्ञान नहीं है उसके लिए ज्ञान बेकार है\nअवरोध बनकर खड़ा है. राग-द्वेष हमारा सबसे बड़ा शत्रु है। यह कितना भयानक है\nइसे 'इच्छा की अग्नि' कहा जा सकता है। इसे कितना भी परोसा जाए, काफी है। लंगड़े की तरह\nमहान माता के पुत्र, तुम इस वासना के शत्रु हो, O6301120100।\nकृष्ण कहते हैं जानो.\n\nयहां हमें पता चलता है कि हमारा असली दुश्मन हमारी वासना या इच्छा या राग-द्वेष है।\nतो इस शत्रु का आधार क्या है? इसे कृष्ण ने अगले श्लोक में समझाया है।\n\nइन्द्रियाणि मनो बुद्धिरस्याधिष्ठानमुच्यते |\nएतैरविमोहयत्येसा ज्ञानमवृत्य देहिनम्",
  "3.41": "तस्मात् त्वं इन्द्रियाणि अदौ निम्या भारत ख़ुशभा |\n\nपाप्मनं प्रजाहि हि एनं ज्ञान विज्ञान नाशनम - इसलिए, हे भरतवंश के नायक, पहले\nआप इंद्रियों को नियंत्रण में रखते हैं और गहन विचार के ज्ञान और शक्ति को नष्ट कर देते हैं\nइस पापी को झाड़ दो।\n\nहमें प्रथम चरण में ही इतने बड़े शत्रु को वश में करना होगा। इस दुश्मन की पहली एंट्री\nइसे उस अर्थ में नियंत्रित किया जाना चाहिए जो द्वार है। हमारा ज्ञान (श्रवण), विज्ञान मन-\n\nनिधिध्यासन) यह महापापी है जो हमारी सोचने की शक्ति को नष्ट कर सकता है\nकृष्ण कहते हैं इसे धक्का दो। आख़िर कैसे? इसमें कौन मदद करेगा? आगे पूछो!\n\nइन्द्रियाणि परण्यहुरिन्द्रियेभ्यः परं मनः।\n\nमनसस्तु परा बुद्धिर्यो बुद्धेः परतस्तु सः",
  "4.1": "भगवान उवाच- भगवान ने कहा:\n\nइमाम विवस्वथे योगम् प्रोक्तवान् अहं अव्यम् |\n\nविवस्वान् मनवे प्राहा मनुः इक्ष्वाकवे अब्रवीथ - मैं साधना के इस अविनाशी मार्ग का अनुसरण करता हूं।\nमैंने सूर्या से कहा. सूर्य ने मनु को बताया था. मनु ने इक्षाकु से कहा था.\n\nएवं परम्पराप्रप्रमिमान राजर्षयोविदुः |\nसकलेनेहा महता योगो हानि ह परंतप",
  "3.38": "धूमेण अव्रियते वह्नि ह यथा आदर्शः मलेण च |\n\nयथा उल्देन अवृतः गर्भः तथा तेन इदम् अवृतम् - धुएं से निकलने वाली अग्नि के समान\n(भगवान), गंदगी (मन) से दर्पण की तरह, गर्भ कोशिका (जीवन) से भ्रूण की तरह,\nवासना ने यह सब खा लिया है। [वासना सज्जनों को वैसे ही भस्म कर देती है जैसे धुआँ अग्नि को भस्म कर देता है।\nउदारवादी दर्पण को धूमिल करने वाली गंदगी के समान हैं। जैसे ही गर्भ भ्रूण को बंद कर देता है]\n\nयहां कृष्ण इस बात की सुंदर व्याख्या कर रहे हैं कि कैसे राग-द्वेष हमारी आंखों को अंधा कर देते हैं\nउसने वह अग्नि दी है जो सब कुछ जला देती है, वह खुद भी जल जाती है और सब कुछ जला देती है।\nजब यह अग्नि धुएं से भर जाती है तो इसे देखा या जलाया नहीं जा सकता। भगवान अग्नि के समान हैं. हमारा\nरजो गुण धुएँ के समान है। हमारे और भगवान के बीच. रजोगुण के परदे ने अग्नि को घेर लिया\nधुएं की तरह यह कृष्ण द्वारा एक सात्विक व्यक्ति को दिया गया एक उदाहरण है। अब कृष्ण राजाओं को देंगे\nइसका एक उदाहरण रंगीन कांच का दर्पण है। उनका कहना है कि मन का दर्पण रजोगुण नामक मैल से सना हुआ है\n\nकृष्ण. तमसारि के लिए कृष्ण का रूपक गर्भ में पल रहा भ्रूण है। सब कुछ अंधकारमय है. खुली आँखों से नहीं देख सकते\nजैसे जीवजटा नामक चूजे को रजोगुण नामक अंडे में रखा जाता है।\n\nइस प्रकार धुएँ से आग की तरह - भगवान का आवरण यह रजो गुण है; दर्पण पर कालिख की तरह-\nआंतरिक कारण के लिए कोष्ठक यह रजोगुण है। जब आंतरिक कार्यप्रणाली काम नहीं कर रही होती है, तो भगवान दिखाई नहीं देते हैं\nफिर- 'भ्रूण की तरह' जीवन के लिए सब कुछ अंधकारमय है। बिना उपयोग के सब कुछ बर्बाद हो जाता है।\n\nअवृतं ज्ञानमेतेन ज्ञानिनो नित्यवैरिण |\nकामरूपेना काउंटी दुस्बू रेनानलेना च",
  "4.3": "सः एव अयं मया ते आद्या योगः प्रोक्तः पुरातनः |\nभक्तः असि मेई सखा च इति घस्याम हि एतत् उत्तमम् -- वही प्राचीन योग मैंने आज तुम्हें बताया है। क्योंकि तुम मेरे भक्त और मित्र हो. यह सबसे बड़ा रहस्य है.\n\n[बीजी 4.3 मार्कर अध्याय-उद्घाटन पृष्ठ के नीचे दिखाई देता है; पूर्ण टिप्पणी पुस्तक अध्याय 4 के अगले पृष्ठों पर जारी है।]",
  "3.34": "इन्द्रियस्य इन्द्रियस्यार्थे राग वैतौ व्यवस्थित |\nतयो न वशं आगच्छेत् तौ हि अस्य परिपंथिनौ - एक कामुक मामले में भी भोग -\nशत्रुता प्रचुर है. उनके शिकार मत बनो. वे साधक के शत्रु हैं।\n\nदो चीजें हमारी इंद्रियों में दुश्मन की तरह काम करती हैं। अर्थात्\nराग (पसंद, &॥301/73€10; और वर्दु एन्नु वा बयाकेकामा, 806516)। जैसे-\nउससे राग, वासना।  नापसंद - इससे घृणा, क्रोध। एक चीज़ चाहिए थी, वो\nजब मुझे वह नहीं मिला तो मैं क्रोधित हो गया। दूसरे को मिल गया फिर नफरत, मिल गया लेकिन जैसा हमने सोचा था वैसा ही हुआ\nनहीं तो गुस्सा. मूलतः इच्छा ही सबसे बड़ा दोष है। जो अधिक है\nयदि हम चाहें तो इससे हम और भी अधिक दुःखी होते जायेंगे। इच्छा को सीमित किए बिना\nहमारे हर भाव में राग-द्वेष नहीं आ सकता; काम और क्रोध से भरा हुआ. लेकिन\nहमें कभी भी इन चाहतों और आवश्यकताओं, क्रोध और घृणा के आगे नहीं झुकना चाहिए। मैं तुमसे बहुत प्यार करता हूँ\n(1055561/97255) हमें पतन की ओर ले जाता है। मुझे यह चाहिए, यह किसी और के लिए है\nन पाया जाना हर अर्थ में भरा हुआ है। यह हमारी प्रवृत्ति के पीछे है\nअहमकारा (₹8090)। कृष्ण कहते हैं: \"कभी भी इन इच्छाओं के गुलाम मत बनो, ये आपकी उपलब्धि हैं\nरास्ते में रुकावट. वे आपके असली दुश्मन हैं।\"\n\nहमें इन शत्रुओं के सामने झुके बिना अपनी इंद्रियों का विश्लेषण करना चाहिए। मेरी इंद्रियाँ\nक्या चाह रहा है, क्यों चाह रहा है, इसके पीछे क्या स्वार्थ है, ये मैं हूं\nभटकाने की इच्छा या ऊपर उठाने की इच्छा? इसके बारे में कुछ इस तरह सोचें\nइच्छाओं को शुद्ध करना चाहिए. जैसा कि वेदों में कहा गया है 'आटा छान लिया जाता है\nअलग करना. हम अपने मन के सार से अपनी इच्छाओं की शुद्धि कर रहे हैं\nकरना चाहिए तब दोस्ती का बंधन होता है। वहां लक्ष्मी सदैव निवास करती हैं।”\n\nयहाँ जब कृष्ण अर्जुन से युद्ध कर रहे हों तब भी राग-द्वेष मन में मत रखना,\nवे कह रहे हैं कि वैराग्य से लड़ो यानी न्याय की लड़ाई ही तो है! वह है\nदुर्योधन के मरने पर कोई खुशी नहीं; जब उनके अपने पुत्र अभिमन्यु की मृत्यु हो जाती है तो वे कहते हैं कि उन्हें दुःखी नहीं होना चाहिए\nयुद्ध-पूर्व अफवाह!\n\nश्रेयन् स्वधर्मो विगुणः परधर्मात् स्वनुष्ठितत् |\nस्वधर्मे निधनं श्रेयः परधर्मो भयवाहः",
  "3.28": "तत्त्ववित् तु महाबाहो गुण कर्म विद्यायोः |\n\nगुणः गुणेषु वर्तमान्ते इति मत्वा न सज्जते- हे महावीर, इंद्रियों के (जीवित प्रकृति के)\n(गुणों के) और कर्मों के प्रकार के सच्चे ज्ञाता, इंद्रियों के विषयों में लगे हुए हैं\nइसका मतलब है कि वे चिपकते नहीं हैं.\n\nएक दार्शनिक जो तत्त्व को जानता है या सत्य का एहसास करता है - गुणकर्म, इंद्रिय और उसमें\nक्रियाभेद को जानना चाहिए। मूलतः इन्द्रियाँ सात्विक, राजस और तमस होती हैं\nकर्म त्रिगुणों द्वारा संचालित होते हैं। यह हम पीछे अटक गए हैं\nप्रभाव पड़ सकता है. इसके फलस्वरूप मिलने वाले कर्म के प्रति हमें तटस्थ रहना चाहिए। ये बात\nमनोविज्ञान से संबंधित. अपने कार्यों का तटस्थ भाव से विश्लेषण करना!\nत्रिमूर्ति का कौन सा गुण मुझ पर प्रभाव डाल रहा है इसका आत्मविश्लेषण करें (Self Analysis)\nकरो, जब आप कर्म विभाजन के सिद्धांत को समझ जायेंगे तो आपको त्रिदेव के प्रभाव का एहसास हो जायेगा। फिर\nहम सच्चाई जानते हैं कि इस पर हमारा कोई स्वामित्व नहीं है।'\nउसके ऊपर जीवन की प्रकृति है - उसके ऊपर भगवान का ज्ञानानंद - जो सभी कर्म की दृष्टि से अर्थहीन हैं\nजड़ता में नंगे काम (एस0॥00), इच्छा और जीवन में काम (11160079) के माध्यम से व्यक्त किया गया\n30401) और ईश्वर में स्वतंत्र इच्छा (Independent Intentional Action)—यह कर्मभेद है।\nइस प्रकार जो गुणभेद और कर्मभेद को जानता है वह 'तत्त्वित' है। इस सिद्धांत का अर्थ है \"मैंने किया\"।\nहम अहंकार से कभी परेशान नहीं होंगे।\n\nआइए उपरोक्त विषय को एक उदाहरण के साथ देखें - दिलचस्प ढंग से, सहजता से\nउस वक्ता को देखो जो बोलता है: काश उसके पास बोलने के लिए मुँह होता\nबस इतना ही नहीं, मुंह में आवाज़ आनी चाहिए. केवल शब्द नहीं - जो बोला जाता है वह उचित है\nआवाज़ आनी चाहिए. उस ध्वनि को पाने के लिए शब्दों को एक एहसास की आवश्यकता होती है। भावना मन में है\nचमकना चाहिए. भावना के अनुरूप ही ध्वनि आनी चाहिए। मुख से यही शब्द निकला\nघर[ की जरूरत है. यदि ध्वनि को अनुभूति से जन्म लेना है तो आकाश और वायु को माध्यम के रूप में आवश्यक है। ये सब\nवह तभी अच्छा बोल सकता है जब कार्य सुचारू हो। मन में भाव और शब्द\nकौन चमकता है? यदि जो कहना है उसके अनुरूप शब्द प्रकट न हो\nअगर वहाँ है? यदि उस समय हमारे मस्तिष्क का कोई बटन काम नहीं कर रहा हो तो क्या होगा? यहाँ हमारा है\nक्या हाल है? जब तुम यह जानते हो तो अहंकारी मत बनो। जब आप यह जानते हैं, तो आप हर किसी की तरह हैं\nचिपकना संभव नहीं है.\n\nइन्द्रियों में सत्त्व-रजो-तमो गुण जीवन की प्रकृति के अनुसार कार्य करते हैं।\nभगवान का ज्ञानानंद स्वरूप- जीवन इंद्रियों के गुणों को नियंत्रित करता है। यह जानकर\n\nमैं-मेरा चला जाता है. मैं ब्रह्मांड नामक इस विशाल महासागर में रेत का एक टुकड़ा हूं\nकण की सच्चाई पता है. \"मैंने किया\" को दुनिया के सबसे महानगरीय अस्तित्व द्वारा मान्यता प्राप्त है।\nकभी भी कुछ न कहें और न ही चिपकाएँ (4॥80113600)।\n\nइस श्लोक में कृष्ण अर्जुन को 'महाबाहो' कहकर संबोधित करते हैं।  ऊपर\nमहाबाहु का अर्थ है नायक, योद्धा। हे बाहुबलियों, कायर बन कर युद्ध मत करो\nयहीं भावना है. लेकिन इसके अलावा भी कई मायने हैं. “महत वहतिति\nमहाबाहु'. इसका मतलब है जो कुछ बड़ा लेकर चलता है। हृदय से संसार का मूलभूत सत्य\nइसका मतलब होता है धारण करने वाला. “ज्ञान की उस महान भुजा से जो दुनिया की महानता को समझ सकती है\nसत्य (भगवान) को क्षितिज से परे पकड़ो” इस संबोधन के पीछे एक और बात है\n\nअनुभूति",
  "4.9": "जन्म कर्म च मे दिव्यं एवं यः वेत्ति तत्वतः |\nत्यक्त्वा देहं पुनर्जन्म न एति माम एति सः अर्जुन-इस प्रकार मेरा अलौकिक जन्म, काज्वा।\nएक वास्तविक व्यक्ति शरीर छोड़कर दोबारा जन्म नहीं लेता है। अर्जुन—वह मेरे साथ है।\n\nइस प्रकार। भगवान के ज्ञानानंदमय, दिव्य (1179), लीलामय अवतार के बारे में जागरूकता\nअगर ठीक से समझा जाए तो यह हमें मोक्ष का मार्ग दिखा सकता है। इसका पुनर्जन्म नहीं होता\nमोक्ष प्राप्ति हेतु एक बहुमूल्य ज्ञान। जिन्होंने इस प्रकार अधिष्ठान द्वारा सिद्धि प्राप्त की है\nकृष्णा आगे बताते हैं.\n\nवीतराग्भयक्रोध मन्मया ममपाश्रितः |\nबहो ज्ञानतपसा पूत मदभा वामगतः",
  "3.37": "भगवानुच- भगवान ने कहा:\n\nकामः एष क्रोधः एष रजः गुण समुद्धवः |\n\nमहा आसनः महापश्म विद्धि अनाम एह वैरिणम् - पाप को चलाने वाली शक्ति वासना है।\n(कालनेमि, काम प्रेमी) इसका एक प्रकार क्रोध है। इसकी उत्पत्ति रजोगुण से होती है।\nयह एक अतृप्त पेटू है. महाकाव्यों का घर. यह इस साधना पथ में है\nउस नफरत को जानो.\n\nहर चीज़ का कारण हमारे भीतर की इच्छा है। कुछ हमें कुछ चाहने पर मजबूर करता है\nयह प्रेरणा सताती है कि गलत काम करके भी वह इच्छा पूरी की जा सकती है\n(1917018100) हमारे पास है। ऐसा करने वाला 'कालनेमि' अर्थात् काम-प्रिय दुष्टात्मा है;\nअगर हमारे अंदर कोई विपत्ति है, तो हम गलतियाँ करेंगे जैसे कि हमारे पास वह थी ही नहीं। मूलतः\nइंसानों से गलतियाँ होने के दो कारण हैं। कोई चाहता है और कामना करता है\nपूर्ति न होने पर क्रोध आना। गुस्से के सूखे में इंसान कितनी गलतियां कर बैठता है, यह कहना मुश्किल है।\n\nहम गलतियाँ करते हैं और अंततः पछताते हैं। इस क्रोध की जड़ काम है। बिना वासना के\nकोई गुस्सा नहीं. सभी क्रोध के पीछे संवेदनहीन वासना है।\n\nमनुष्य में रजोगुण राग-द्वेष को जन्म देता है। पेट में चाहे कितना भी खाना डाल लो\nभरा नहीं! इसका अच्छा उदाहरण है: कोई काम के लिए भटकता है, फिर उसके लिए\nएक राय है कि पेट के लिए नौकरी मिल जाना ही काफी है. एक बार जब आपको नौकरी मिल जाए,\nउसकी चाहत अधिक वेतन पाने की ओर बहती है। अधिक से अधिक, इत्यादि\nबड़ा होता है. संतुष्टि कभी नहीं होती.\n\nइस प्रकार यदि हम गलत करने के आदी हो जाएं तो वह 'महाशासन' बन जाता है। उसके लिए क्या दावत है\nअगर डाल भी दो तो दोबारा चाहिए. जब तक इसका मतलब कुछ ऐसा है जो हमें नहीं करना चाहिए\nऐसा कहा जाता है कि जो व्यक्ति अपनी इच्छा पूरी करने के चक्कर में पड़ जाता है उसे ब्रह्मचर्य से परहेज नहीं है\nशास्त्र! तो हमारा पहला शत्रु है राग-द्वेष। इसके प्रति सावधान रहें. यह आपके भीतर है\nइसे आप पर हावी न होने दें. कुरान में यही कहा गया है \"0148 17607 06! 170/3 1818 )/0 308 0001\n61967 04. राग द्वेष हमारे व्यक्तित्व को गढ़ते हैं और उन पर शासन करते हैं\nबाहर निकलो, जैसे हो वैसे जियो।",
  "4.5": "भगवान उवाच- भगवान ने कहा।\n\nबहुनि मय व्यतितानि जन्मनि तव च अर्जुन |\n\nतानि अहम वेद सर्वाणि न त्वं वेत्थ परंतप - हे अर्जुन, मुझे कई जन्म दो।\nतुम भी गए. हे ज्ञान लानेवाले, मैं उन सब को जानता हूँ - परन्तु तुम नहीं जानते।\n\nजन्म का अर्थ है जन्म या जन्म। जो अस्तित्व में नहीं है उसका जन्म नहीं हो सकता। जड़ पैदा होना\nहम कॉल नहीं करते. सूक्ष्म शरीर से स्थूल शरीर में आना ही जन्म है। मरना\nइसका अर्थ है सूक्ष्म शरीर की स्थूल शरीर की सफाई। यहाँ कृष्ण कहते हैं: \"मुझे और तुम्हें\nअनेक जन्म हुए। मैं यह जानता हूं लेकिन आपके परांठेपना के साथ भी यह समस्या है\nपता नहीं\"।",
  "4.4": "अर्जुन उवाच-अर्जुन ने पूछा:\n\nअपरं भवतः जन्म परम जन्म विवस्वतः |\n\nकथं एतत् विजनीयं त्वं अदौ प्रोक्तवन् इति-आपका जन्म हाल ही में हुआ है। सूरज\nपहला जन्म. यदि आप ही वह व्यक्ति हैं जिसने इसे सबसे पहले कहा था तो आप इसकी व्याख्या कैसे करेंगे?\n\nज्ञान की विरासत का वर्णन करते हुए, कृष्ण कहते हैं, \"मैंने सबसे पहले सूर्य को (देवताओं को) बताया।\"\nउसने कहा। यहां अर्जुन कृष्ण से इस बारे में सवाल करते हैं। कृष्ण अर्जुन से बड़े हैं\nकरीब छह महीने का. ऐसा मैंने लाखों वर्ष पहले सूर्य को बताया था\nअर्जुन का प्रश्न है कि इसकी व्याख्या कैसे की जाए।\n\nयहाँ अर्जुन स्वयं भगवान से इस प्रश्न का उत्तर प्राप्त करना चाहता है। इसीलिए ये सवाल\nइष्ट ने कहा है ''इसके अलावा, अर्जुन, महान ऋषि जो सभी तंत्रिकाओं के प्रतिनिधि के रूप में खड़े हैं, हमारे और आप सभी के लिए हैं\nवह यह प्रश्न पूछता है. इसका उल्लेख प्रारम्भ में ही किया जा चुका है। कृष्ण ने कहा: \"हम सभी\nहम अतीत में थे, हम अब भी हैं और हम भविष्य में भी रहेंगे'' (ए-2, श्लो-12...)\nपूर्ण विवरण यहाँ आता है. भगवान जो किसी भी कर्म से बंधे नहीं हैं, सर्वशक्तिमान हैं\nकृष्ण ने इस प्रश्न का उत्तर निम्नलिखित श्लोकों में दिया है कि वे पृथ्वी पर क्यों आते हैं।",
  "3.40": "इन्द्रियाणि मनः बुद्धिः अस्य अधिष्ठानं उच्यते |\nएतयः विमोहयति एष ज्ञानं आवर्त्य देहिनम् - इस वासना की इन्द्रियाँ, मन, बुद्धि।\nआधार. इनके माध्यम से यह ज्ञान को कमजोर करके अभ्यासकर्ता को भ्रमित करता है।\n\nहमारी इच्छाओं की शृंखला सबसे पहले हमारी इंद्रियों में आकर बैठती है। आंख को, कान को\nसुनना, सूंघना, छूना, हर इच्छा अलग-अलग रूप में\nएक भाव में आकर बैठ जाता है. अगर हम इसे वहीं नहीं दबाएंगे. यह हमारा है\n\nदिमाग पर कब्जा कर लेता है. . यदि हम वहां विश्राम करेंगे तो इससे हमारी बुद्धि का विकास होगा\nकब्ज़ा. इस प्रकार अंगल (इंद्रिय) के इस शत्रु को मोगासले (मन) को बुलाओ, फिर\nऐसा लगता है जैसे हमें घर (बुद्धि) में बंद कर दिया गया है। एक बार यह शत्रु हमारी बुद्धि पर आक्रमण कर देता है, आगे\nइससे छुटकारा पाना बहुत मुश्किल है. इस अवस्था में इच्छा सैद्धांतिक रूप से हमारे भीतर है\nखुद पर शासन करने लगते हैं. इस प्रकार इच्छा हमारे जीवन का धर्म बन जाती है।\nजैसे एक बात हमारे कान पर पड़ती है. हमें उस मामले से क्या लेना-देना?\nमुझे नहीं लगता कि उपयोगिता पर ध्यान क्यों दिया जाए। इसे विषय पर छोड़ दें\nदेखने के लिए उत्सुक हूं. देखने के बाद छूने (खाने, सूंघने आदि) की इच्छा!\nइस प्रकार हम अपनी हर दृष्टि से वासना के इस शत्रु को प्रोत्साहित करते हैं। तब यह था\nधीरे-धीरे हमारे दिमाग पर कब्जा कर लेता है। मन निरंतर उस विषय पर रहता है\nसोचने लगता है. मन कहता है 'यह मेरा हो जाए, यह मेरा हो जाए (10556551/67655)'\nसोचने का अर्थ है कि इस शत्रु ने मन पर आक्रमण कर दिया है। अब से बुद्धि; 'इसे छोड़ो\nमैं इसे प्राप्त नहीं कर सकता, मुझे इसे प्राप्त करना ही होगा, चाहे कुछ भी हो' आदि, यही हमारी इच्छा है।\nबुद्धि को धारण करने का निर्देश | यह विनाश का पूर्वाभास है. इस प्रकार यह ज्ञान का भ्रम है\nहमारा यह शत्रु तीन स्थानों पर बैठकर ज्ञान का पर्दा बनकर खड़ा है।\n\nयहाँ 'देहिनम्' शब्द का प्रयोग हुआ है। ज्ञान से ही हमारा शरीर है\nएक उठाने वाला उपकरण. लेकिन जब हम कामने नामक शत्रु से मिलते हैं, तो वह हम ही होते हैं\nयह पतन का साधन बन जाता है। इस शब्द के पीछे यही अर्थ है.\n\nतो हमारा दुश्मन कौन है, उसकी स्थिति क्या है और वह हम पर कैसे हमला करता है\nस्पष्टीकरण देने के बाद, कृष्ण आगे उस देवी का वर्णन करते हैं जो इस शत्रु को मारती है।\n\nतस्मात् त्वमिन्द्रियन्यदौ निम्या भरतर्षभा।\n\nपोपमानं प्रजाहि ह्येनं ज्ञानविज्ञाननाशनम्",
  "3.27": "प्रकृतिः क्रियमाणानि गुणैः कर्माणि सर्वषा |\n\nअहम्कारविमूढ़ा आत्मा कर्ता अहम् इति मन्यते - प्रकृति के अंग\nसभी प्रकार की इंद्रियाँ (ईश्वर के अधीन, जीवन के प्राकृतिक गुण)।\nकर्म भी हो रहे हैं. जो हमसे मंत्रमुग्ध हो जाता है वह जानता है कि 'मैंने यह किया है।'\n\nयह श्लोक कई प्रकार से प्रकट होता है। यहाँ कृष्ण मुख्य रूप से अहंकार है कि 'मैंने यह किया'\nउन्होंने बताया कि यह कितना बुरा है और क्यों। कृष्ण कहते हैं “जो कोई भी\nयदि वह जानता है कि मैंने कुछ किया है, तो यह उसकी अज्ञानता है।\" सृजन में\nएक अजीब बात यह है कि कोई कुछ नहीं करता-लेकिन सब कुछ सबके हाथों से होता है! यह\nशरीर (पिंडंद) प्रकृति का निर्माण है। स्वभावतः यह तत्ववाद का समर्थक है\nइंद्रियाँ हैं. प्रकृति यह शरीर है, इसके गुण इन्द्रियाँ हैं। ध्वनि-स्पर्श-रस-रूप-\nचंदन कान-त्वचा-जीभ-आंख-नाक;    तदनुसार, आकाश (ध्वनि), वायु (स्पर्श),\nजल (रस), अग्नि (रूप), और मिट्टी (गंध) प्रकृति के गुण हैं। इस मामले में हम\nयह कहना कि मैंने स्वयं कुछ किया, का अर्थ शून्य है। उदाहरण के लिए\n'आँख से देखा हुआ; हमें यह आंख किसने दी? ताकि आप जन्म से अंधों को आंखें दे सकें\nक्या यह संभव है इसका मतलब है कि आंख प्रकृति का एक उपहार है। भगवान ने हमें देखने के लिए आँखें दी हैं\nवस्तु रखी, देखने को कहा - हमने देखा! अगर हमारा सुर अच्छा है\nहमें इस पर गर्व है. लेकिन हमें यह स्वर किसने दिया? हम इस बारे में कभी नहीं हैं\nयह मत सोचो कि यदि कोई कार्य करना है तो पूरे विश्व की कई इकाइयों को एक साथ मिलकर काम करना होगा\nप्रबंधित किया जाना चाहिए. प्रकृति जड़ है और इसकी कोई इच्छा नहीं है। 'हम करते हैं' का अर्थ है स्वेच्छा से। हम लोगो को\nएक इच्छा है; प्रत्येक जीवन का अपना जीवन स्वभाव होता है। हम जो कुछ भी करते हैं\nकर्म हमारे जीवन स्वभाव से मेल खाता है। यह एक स्वैच्छिक कार्रवाई है. हमारी एक इच्छा है\nलेकिन कोई स्वतंत्र इच्छा नहीं है.\n\nस्वतंत्र इच्छा केवल ईश्वर में मौजूद है। उसी के अनुरूप सारा कार्य किया जाएगा।\nतो जो हमारी प्रकृति को नियंत्रित करता है वह संपूर्ण ब्रह्मांड का मूल रचयिता भगवान है। उसका\nसंसार का व्यापार इच्छानुसार होता है। यही संसार की व्यवस्था है. पूरे विश्व के कर्म चक्र में\nहम एक इकाई हैं तो 'मैंने यह किया' पर गर्व करने का क्या मतलब है?\nनहीं, असली लेखक भगवान हैं। जीवन में एक लेखकत्व है और निर्जीव में एक लेखकत्व है। इस का\nहमें अंतर जानना चाहिए. मिट्टी निष्क्रिय है और उसे पसंद नहीं है. एक बीज आत्मा, वह एक वृक्ष बन जाती है\nप्रकृति तो है लेकिन आज़ादी नहीं. वह प्रभु माली है जो बीज बोता है। प्रभु का\nसंसार में इच्छा के अनुसार, जीव में प्रकृति के अनुसार कार्य होता है।\nकार्रवाई के पीछे पूरी दुनिया की साझेदारी है।\n\nसिद्धांत था महाबाहो गुणकर्मविभागयोः।\n\nगुण गुणेषु वर्तन इति मत्वा न सजजते",
  "4.8": "परित्राणाय साधुनां विनाशाय च दुष्कृतम् |\nधर्म संस्थापन अर्थाय संभवामि युगयुगे - सज्जनों, दुष्टों को बचाने के लिए\nमैं युग-युग में धर्म को मिटाने और स्थापित करने के लिए उत्पन्न होता हूं।\n\nजो लोग समाज का बुरा करते हैं और उससे लाभ उठाते हैं ऐसे लोग होते हैं\nसंपूर्ण विनाश के लिए, सज्जनों और संसार की व्यापक रक्षा के लिए, भगवान धर्म का बीज बोएं\nभूलोक में अवतार लेते हैं। यहाँ युग-युग का अर्थ है \"एक युग से दूसरे युग तक\"। यानी\nइसका मतलब यह नहीं कि भगवान हर युग में अवतार लेते हैं। जैसा कि ऊपर बताया गया है, वह अवतरित हुए हैं\nअवसर आने पर ही. एक युग में अनेक अवतार हो सकते हैं; किसी और युग में\nहो सकता है कि कोई अवतार ही न हो. लेकिन भगवान की उत्पत्ति के कई महान व्यक्ति युग-युग के थे-\nवे युगों-युगों में भी आते-जाते रहते हैं। उनके द्वारा युगों-युगों तक भगवान के धर्म की रक्षा होती रहती है\nनिरंतर।\n\nजन्म कर्म च मय दिव्यमेवं यो वेत्ति तत्वतः |\n\nत्यक्त्वा देहं पुनर्जन्म नैति मामेति सोर्जुन",
  "4.16": "किं कर्म किं अकर्म इति कवयः अपि अत्र मोहितः\n\nतत् ते कर्म प्रवक्ष्यामि यत् ज्ञात्वा मोक्षसे अशुभत्-कर्म क्या है, अकर्म क्या है\nजो जानते हैं वे भ्रमित हो जायेंगे। मैं आपको ऐसे कर्मों के बारे में बताऊंगा। आप यह जानते हैं\nहानि से बचें.",
  "4.10": "वीत राग भय क्रोधः मत माया मम उपाश्रितः |\n\nबहवः ज्ञान तपसा पूतः मत भावम् अगातः - जो राग-भय-क्रोध का त्याग करता है,\nऐसे बहुत से लोग हैं जो मुझे हर जगह देखते हैं (मेरी महानता का एहसास करते हैं), मेरे प्रति समर्पण करते हैं-\nज्ञान की तपस्या से वह मुझसे जुड़ गया है।\n\nतीसरे अध्याय (श्लोक-39) के अंत में कृष्ण कहते हैं कि राग-द्वेषादि हमारे सर्वोच्च हैं\nशत्रु. हम अपने जीवन में सभी समस्याओं का कारण बनते हैं (इच्छा, राग, 35301/7011,\nशर्म (भय) और क्रोध (क्रोध) को छोड़ो और जो है उसमें आनन्द मनाओ\nऔर जो कुछ भी आता है उसे स्वीकार करने का एक हर्षित दृष्टिकोण विकसित करके,\nखुश होना चाहिए. 'मनमय' का अर्थ है जीवन के सभी क्षेत्रों में भगवान को समाहित करना\nऔर सांसारिक चेतना को कम करना। एक बार हम ईश्वर के चिंतन में लग जाएं\nये राग-द्वेष तुच्छ लगने लगते हैं। इस सत्य को जानना कि ईश्वर सर्वोच्च है,\nयह जानकर कि वह सदैव हमारी सुरक्षा के लिए मौजूद है, हम उस प्रभु पर गर्व से छुटकारा पा लेते हैं\nजो समर्पण करते हैं उन्हें मोक्ष का मार्ग मिल जाता है। हमारे जीवन का प्रत्येक कर्म ऐसा ही होता है\nभावना को विकसित करना एक तपस्या है। इससे हमारा जीवन पवित्र हो जाता है। इस प्रकार राग-\nकृष्ण कहते हैं कि जो लोग नफरत की गंदगी से मुक्त हो जाएंगे वे मुझसे जुड़ जाएंगे। हमें अपने राग से नफरत है-\nक्रोध में भी प्रभु का ध्यान रखना चाहिए! . हमारी इच्छा भगवान के दर्शन की है\nवांछित होना; भय- 'यदि मैं गलती करुँगा तो ईश्वर मुझे क्षमा नहीं करेगा' भय होना चाहिए;\nहमारा क्रोध हमारी अयोग्य वासनाओं पर होना चाहिए। इस प्रकार ये तीन शत्रु हैं\nजब हम प्रभु की कृपा करते हैं, तो हम प्रभु को देख सकते हैं।\n\nयेयथामं प्रपद्यन्ते तमस्तथैव भजाम्यहम् |\nमम वर्त्मनुवर्तने मनुष्यः पार्थ सर्वषा",
  "4.6": "अजः अपि सुं अव्यय आत्मा भूतानं ईश्वरः अपि सुं |\n\nप्रकृतिं स्वं अधिष्ठाय संभवामि आत्ममयया - मेरा जन्म नहीं हुआ है। मेरा शरीर भी\nकोई मृत्यु नहीं मैं सभी जीवित प्राणियों का स्वामी हूं। हालाँकि, प्रकृति मुझमें है\nनाभि ज्ञान के स्वभाव से (अपनी इच्छा से)\nचलो.\n\nभगवान, जो सभी जीवित प्राणियों के स्वामी हैं, कई बार पृथ्वी पर अवतरित होते हैं। उससे पैदा हुआ\nमुझे ऐसा नहीं लगता. हालाँकि, वह पैदा हुआ है। वह अवाया है; उनका जन्म नश्वर शरीर के साथ नहीं हुआ था।\nइसलिए भगवान के लिए शरीर के माध्यम से कोई जन्म और मृत्यु नहीं है। यहाँ आती है 'आत्म माया'\nइस शब्द के कई अर्थ हैं. आत्म माया प्रेम का पर्दा है जो जीवन पर लिखा है; ईश्वर की महिमा आत्मा है\nजादू ईश्वर की अपनी इच्छा और ज्ञान आत्म-भ्रम है। प्रभु धरती पर आ रहे हैं\nकिसी भ्रम के अधीन होकर नहीं, बल्कि अपने ज्ञान की महिमा से। भगवान उनके भक्त हैं\nप्रकृति ने अपनी इच्छाओं की पूर्ति के लिए स्वयं को स्वेच्छा से बनाया है\nवह इसे माध्यम बनाकर नीचे उतरता है। यह उनकी महिमा है. हमारे लिए जो प्यार की स्क्रीन पर रहते हैं\nयह एक सामान्य जन्म प्रतीत होता है. क्योंकि हमारे पास उसका ज्ञान है\nशरीर को देखा नहीं जा सकता. हमें अपने स्वयं के जीवन स्वरूप का भी पता नहीं चलता - जबकि वह ऐसा है\nक्या ईश्वर को जानना संभव है? इसी कारण भगवान हमारे लिये पंचभौतिक हैं\nवह एक शरीर की तरह दिखता है. जैसा कि हम जानते हैं कि कुछ जानवर रंग नहीं देख सकते। उनकी आँखों के लिए\nकोई शक्ति नहीं. तो सब कुछ काला और सफेद है. लेकिन असल में दुनिया में रंग हैं, उन जानवरों के लिए\nरंग पहचानने की क्षमता नहीं होती. इसी तरह, भगवान हमारे लिए हैं जो प्रेम की स्क्रीन में रहते हैं\nज्ञानानंद स्वरूप शरीर प्रकट नहीं होता, बल्कि पंचभौतिक शरीर का जन्म और विनाश होता है\nऐसा प्रतीत होता है परंतु मूलतः भगवान न तो जन्मते हैं और न ही नष्ट होते हैं। वह अपने स्वभाव से है\nमूडी अपनी मर्जी से आता है।\n\nप्रभु किस कारण से पृथ्वी पर आते हैं? इसके पीछे दैवीय मंशा क्या है? यह\nप्रश्न का उत्तर अगले दो श्लोकों में पाया जा सकता है।",
  "4.15": "एवं ज्ञात्वा कृतं कर्म पूर्वैः अपि मुमुक्षुभिः\n\nकुरु कर्म एव तस्मात् त्वम् पूर्वैः पूर्व तरम् कृतम् - वह पूर्व जो मुक्ति चाहता था\nउन्होंने भी \"जानबूझकर\" कर्म किया, इसलिए बड़े-बुजुर्ग पहले से ही कर्म करते आ रहे हैं\nकर्म तो आप ही करते हैं.\n\nकुछ लोग सोच सकते हैं कि \"निष्क्रियता\" कर्म बंधन से बाहर निकलने का एक आसान तरीका है।\nकृष्ण निष्क्रियता का घोर विरोध करते हैं। 'सौ वर्ष जियो लेकिन एक कर्तव्यपरायण व्यक्ति बनो\nइसे बनाओ और जियो. निष्क बनकर मत जियो. यह कृष्ण का सिद्धांत है. कर्म का अर्थ है करना\nकुछ नहीं कर रहा. कर्म हमारे जीवन स्वभाव (वर्ण) के अनुसार करना चाहिए। कर रहा हूँ\nकर्म को सोच-समझकर और महत्वाकांक्षा, अभिमान और फल की इच्छा के बिना किया जाना चाहिए। “तुम्हारा\nपहले के राजा और ऋषि-मुनि यही करते थे। कर्म योग और ज्ञान योग\nकृष्ण कहते हैं कि उभय योग के बिना भगवान से कोई संबंध नहीं है।",
  "4.14": "न माम् कर्माणि लिम्पन्ति नाम कर्मफले स्क्रिहा\nइति माम् यः अभिजानाति कर्मभिः न सः बध्यते-कर्म मुझसे चिपकते नहीं। मेरे लिए\nकर्म की कोई इच्छा नहीं. जो मुझे इस प्रकार जानता है, वह कर्म के बंधन में फंस जाता है।\n\nभगवान अपने स्वभाव के अनुसार, अपने कर्म के अनुसार\nविश्व नामक एक उद्यान का निर्माण करें, यह पृथ्वी चार वर्णों के उद्धारकर्ताओं की रचना है\nऊपर बनाया गया. कृष्ण कहते हैं, ''इससे ​​मुझे कोई कर्म नहीं मिलेगा.'' कर्म चिपचिपा है\n'यह मेरा है', 'मैंने किया है' तभी प्रशंसा होती है। ईश्वर के लिए कर्म ही गोंद है\n\nया कोई कनेक्शन नहीं. कर्म की कोई प्रशंसा नहीं है. वह कोई मेहनती, थकाऊ लेखक नहीं हैं\nफल की कोई इच्छा नहीं. जो इस सत्य को जान लेता है, अनुभव कर लेता है और अपने जीवन में अपना लेता है, वही कर्म है\nहिरासत में लिया गया.\n\nएवं ज्ञात्वा कृतं कर्म पूर्वैरपि मुमुक्षुभिः |\nकुरु कर्मैव तस्मात् त्वं पूर्वैः पूर्वतरं कृतम्",
  "4.11": "ये यथा मम प्रपद्यन्ते तं तथा एव भजामि अहम्।\n\nमम वर्त्मा अनुवर्तन्ते मनुष्यः पार्थ सर्वशहा - कौन मेरी कैसे सेवा करेगा?\nमैं उन्हें भी आशीर्वाद देता हूं. हे पार्थ, मनुष्य जो भी मार्ग अपनायें\nअंततः वे मेरे पास आये।\n\nभगवान की पूजा करने का सही तरीका क्या है? हर कोई अलग-अलग तरीके से पूजा करता है।\nइससे भ्रम और उत्तेजना. जो किसी भी तरह से पूजा करता है वह भगवान के समान है\nवह आशीर्वाद देता है. हम जिस भी रूप में पूजा करें वह सर्वव्यापी हो जाता है\nप्रभु से जुड़ जाता है. इसीलिए हम भगवान की विशेष विभूति के साथ अपनी पूजा करते हैं\nहम इसकी पूजा तुलसी, अश्वत्थवृक्ष, गाय आदि के रूप में करते हैं, लेकिन यहां एक चेतावनी जरूरी है। तुलसी\nपौधे को ही भगवान मानकर उसकी पूजा न करें, बल्कि तुलसी में भगवान की विशेष विभूति छुपी हुई है।\n\nपूजा-पाठ जरूरी है. इस प्रकार हमें अपने प्रत्येक कार्य में ईश्वर के प्रति जागरूकता और ज्ञान रहता है\nआवश्यक भगवान को जिस भी नाम से पुकारा जाए, वह भगवान का ही नाम है\nसावधानी जरूरी है. व्यक्ति जहां भी बैठकर पूरी श्रद्धा से भगवान को याद करता है, वह सर्वव्यापी है\nविश्वंभरा से जुड़ता है. वह सदैव हमारी रक्षा करता है।\n\nकंकशान्तः कर्मणां सिद्धिं यजन्त इह देवताः\nक्षिप्रं हि मानुषे लोके सिद्धिर्भवति कर्मजा",
  "3.31": "ये मेई मतं इदं नित्यं अनुतिष्ठन्ति मानवः।\nश्रद्धावन्तः अनुसूयन्तः मुच्यन्ते ते अपि कर्मभिः - कौन मनुष्य मुझे नहीं पुकारते।\nजो लोग सिद्धांत में विश्वास करते हैं वे कर्मों से बच जायेंगे।\n\n\"प्रभु मेरे हाथों से सब कुछ करता है, मैं जो कुछ भी करता हूं वह मेरे लिए उसकी पूजा है\nईश्वर मुझसे बेहतर जानता है कि कौन सा फल अच्छा है। तो वास्तव में\nईश्वर से उपहार के रूप में शक्ति की मांग किए बिना जो मिलता है उसे स्वीकार करके जीना। ये हमारा है\nजीवन की दिनचर्या का हिस्सा बनें. यह दृष्टिकोण जीवन के प्रत्येक क्षण में विद्यमान है\nमनुष्य (गतगा 381. 06176, बुद्धिमान, मानवीय) अश्रद्धा (रजस) और\nजब ईर्ष्या (तमस) को त्याग दिया जाता है और निष्कामकर्म किया जाता है, तो उनका ज्ञान बढ़ता है। उससे\nवे कर्म बंधन से मुक्त हो जाते हैं और मोक्ष जाने के पात्र बन जाते हैं। यह दैनिक व्यवहार में है\nजब अनुसन्धान होता है, तो हमारा कर्म ही हमें कर्म बंधन से मुक्त करने के लिए आगे बढ़ता है\nऔर कर्म बंधन से छूट जाता है।\n\nये थ्वेतद्भ्यसुयन्तो नानीतिष्टन्ति मेइ मतम्।\n302\n\nये तु एतत् अभ्याससुयन्तः न अनुतिष्ठन्ति मे मातम् |\n\nसर्व ज्ञान विमूधन तन विद्धि नतन अचेतसः - जिसने मेरे सिद्धांत को मात दे दी\nयदि वे इसे व्यवहार में नहीं लाते हैं, तो वे सभी उधार का ज्ञान हैं। विनाश-\nयह जानिए.\n\nउपरोक्त कार्यान्वयन से अनभिज्ञ, ईर्ष्या और अधीरता से, 'मैं अपने काम में अकेला हूं\nजिम्मेदार, मैं जो करता हूं अपने हित में करता हूं, मुझे उसका फल मिलता है, मेरा\n'मेरा वजूद मेरे हाथ में है, इसके लिए कोई भगवान जिम्मेदार नहीं है।'\nअहंकार में जीने वालों के लिए ज्ञान का द्वार कभी नहीं खुलता। वह संसार में है\nउसे विमूढ़ (महामूर्ख) कहा जाता है। उसे यह भी नहीं पता कि वह कुछ नहीं जानता!\nऐसे लोग सत्य के बारे में सोचने के योग्य नहीं हैं। वे विनाश की ओर चलते हैं\nमैकरॉन वह अंधकार से अंधकार की ओर चला गया और अपने अस्तित्व के विनाश तक पहुंच गया\nहार जायेंगे\n\nजब हम कृष्ण का उपरोक्त सन्देश सुनते हैं तो हमारे सामने एक प्रश्न आता है। यही संसार का सार है\nहर कोई सत्य का पालन क्यों नहीं करता? वह है। इस पर कृष्णा ने बेहद दिलचस्प जवाब दिया\nवह अगले दो श्लोकों में देते हैं।\n\nसदृशं चेष्टते स्वस्यः प्रकृतर्जनावनपि।\nप्रकृतिं यान्ति भूतानि निग्रहः किम् करिष्यति 331\n\nसदृशं चेष्टते स्वस्यः प्रकृतिः ज्ञानवान् अपि |\n\nप्रकृतिं यान्ति भूतानि निग्रहः किं करिष्यति -- चाहे वह कितना भी जानता हो, उसके संस्कार\nवह (प्रकृति) के अनुसार आचरण करता है। सभी प्राणी संस्कार (प्रकृति) की कठपुतलियाँ हैं।\nआगे क्या हुआ?\n\nकोई कितना भी उपदेश दे, पूरी दुनिया में सभी एक ही राह पर चलते हैं\nइसका कारण हमारा व्यवहार, हमारी संस्कृति और हमारे जीवन का स्वभाव है। हम अपने हैं\nयदि हम पिछले संस्कारों को देखें तो सात्विक, राजस, तमस के अनेक अनुभव जन्म लेते हैं-\nवे जन्म से ही अवचेतन होते हैं। अनेक जन्मों से प्रवाहित इस जीवन को अनेक\nजन्म-जन्मान्तर के अनुभव का संस्कार है। भले ही आपने केवल एक ही जन्म देखा हो, आप बड़े हो गए हैं\nवातावरण की छाप, यह प्रभाव, हम पर सदैव पड़ता है। और प्रत्येक का अपना\nवहाँ जीवन है. वह सदैव उसी के अनुरूप आचरण करता है। काली मिर्च का पौधा कितना मीठा होता है\nयदि कोई व्यक्ति फल नहीं दे सकता तो उसके जीवन स्वभाव को बदलना असंभव है। प्रकृति और\nयह जीवन प्रभावों का समुच्चय है।\n\nउपरोक्त विश्लेषण को देखते हुए स्वाभाविक रूप से हमारे सामने एक प्रश्न उठता है। “जीवन\nप्रकृति के रूप में जीवन का क्रम; स्वभाव के रूप में क्रिया; सब कुछ प्रकृति के अनुसार होता है. तो फिर\nप्रयास क्यों करें?” वह है। क्योंकि हमेशा प्रयास करते रहने से, संस्कार से या\nप्रभाव पर काबू पाना संभव है. प्रभाव से लगातार बचता रहता है जब तक कि यह प्रकृति में रुक न जाए\nप्रयास आवश्यक है. निरंतर आध्यात्मिक अभ्यास हमें अपने प्राकृतिक स्वभाव को व्यक्त करने में मदद करता है\nकरूँगा",
  "4.7": "यदायदाहि धर्मस्य ग्लानिः भवति भारत |\nअभ्युत्थानं अधर्मस्य तदा आत्मानं सृजामि अहम्..हे भारत, जब धर्म लुप्त हो जाता है,\nजब-जब अधर्म सामने आता है, तब-तब मैं जन्म लेता हूं।\n\nईडी की दुनिया में, जब धर्म अशुद्ध हो जाता है और अधर्म की भेंट चढ़ जाता है, तो सिर\nकृष्ण कहते हैं कि अगर नीचे खड़े होने का मौका मिले तो मैं नीचे आ जाऊंगा. यहाँ धर्म\nहारने का मतलब यह है कि यह एक घर-एक देश की बात नहीं है। पूरी दुनिया में\n\nजब ऐसी स्थिति आती है कि धर्म को कोई स्थान नहीं मिलता तो वह ईश्वर का अवतार बन जाता है। बुरी शक्तियां धरती पर हैं\nजब सत्त्वगुण का सिर नियंत्रित हो जाता है और सिर नहीं उठाया जाता है, तो भगवान स्वयं पृथ्वी पर होते हैं\nवह बनाता है. \"तदा55त्मानं सृजाम्यहम्\" में 'मैं अपने प्रियजन हूं\nदो स्वर हैं: 'मैं भेजूंगा' और 'मैं अवतार लूंगा'। धर्म के लिए\nजब प्रांत में विफलता के लक्षण मिलते हैं, तो भगवान उसके साथ होते हैं\nवह प्रियजनों (देवताओं) को पृथ्वी पर भेजता है। वे आचार्यपुरुष बनकर आये\nसमाज को बदलो. जब ऐसी व्यवस्था भी ध्वस्त हो जाती है और तमस शक्तियाँ पनपने लगती हैं।\nअंततः भगवान स्वयं अवतरित होते हैं। कृष्ण का अवतार समय की अवस्था है\nअवलोकन करने पर यह स्पष्ट हो जाता है कि उस समय का धर्म पडेनु था। जरासंध दुनिया का एक कोना है\nउसने लगभग 22,800 राजकुमारों को अपनी कैद में रखा। कामसन अपनी बेटी को\nउसे छोड़ दिया और शूरसेन को कैद करने की साजिश रची\nजरासंध सफल हुआ. और उसके सहयोगी नरकासुर की लगभग 16,100 राजकुमारियाँ थीं\nउन्हें जेल में रखा गया. भीष्मचार्य ने संपूर्ण विश्व में शांति संधि की\nउसने अपना एकाधिकार स्थापित करने और लोगों से जबरन वसूली करने की योजना तैयार की थी\nजरासंध तब का भारत आज के भारत जैसा नहीं था। यह ज़मीन का सबसे बड़ा टुकड़ा था। यदि ऐसा है\nयदि कृष्ण अवतार न होता तो सारी पृथ्वी इन पापियों के हाथ में होती। ऐसे मामले में\nकृष्ण अवतरित हुए. कृष्ण, जिन्होंने कंस का वध किया और शूरसेन को राजा के रूप में बहाल किया,\nनरकासुर का वध किया और उसके अधीन राजकुमारियों को मुक्त कराया। इस प्रकार\nजब मुक्त हुई राजकुमारियाँ संदिग्ध समाज से डरती हैं तो शीला उन्हें आश्रय देती है\nउसने स्वयं उनसे विवाह किया और उनका सम्मान बचाया। कृष्ण पर जरासंध\nलगभग 23 अक्षोहिनी सैनिकों के साथ हमला होने पर भागने का नाटक करें\nभीमर्जुन के साथ जरासंधन का मुकाबला- मल्ल युद्ध में भीम द्वारा जरासंधन का मुकाबला\nजितने राजकुमारों को मार डाला गया और वे उसकी कैद में थे, वे सब अपने-अपने राज्य में चले गए\nभेजा गया\n\nइस प्रकार सारी पृथ्वी तभी प्रभु की है जब स्थिति अधर्म की दासता में आ जाती है\nभूलोक में अवतार होता है।\n\nपरित्राणाय साधुनां विनाशाय च दुष्कृतम् |\nधर्मसंस्थापनानर्तया संभवामि युगेयुगे",
  "4.25": "दैवं एव अपरे यज्ञं योगिनः पर्युपासते |\nब्रह्मा अग्नौ अपरे यज्ञं यज्ञेन एव उपजुह्वति - कुछ साधक भगवदुपासना नामक मानस यज्ञ करते हैं। भगवान स्वयं यज्ञ रूप में पूजे जाते हैं। कुछ लोग अग्नि के रूप में भगवान की पूजा करके बाह्य यज्ञ द्वारा यज्ञ नमक भगवान की पूजा करते हैं।\n\nकुछ योगी (साधक) जो भगवान की आराधना के मार्ग पर चलते हैं, भगवान की पूजा यज्ञ के रूप में करते हैं। अर्थात उनका यज्ञ भगवान की निरंतर पूजा है। इसके लिए किसी बाहरी सहायक उपकरण की आवश्यकता नहीं है। यह यज्ञ का एक ध्यानात्मक रूप है। बाह्य उपकरणों के बिना किया गया यज्ञ सबसे बड़ा यज्ञ है।",
  "4.12": "कनकशांतः कर्मणां सिद्धिं यजन्ते इह देवताः |\nक्षिप्रं हि मानुषे लोकाय सिद्धिः भवति कर्मजा - जो कर्मों के माध्यम से फल चाहता है वह यहीं है\nदेवताओं की पूजा की जाती है। इस देश में कर्म का फल सिद्धि के समान नहीं है?\n\nहममें से कुछ। देवता स्वयं भगवान और देवों के बीच अंतर नहीं जानते\nवे भगवान के रूप में पूजा करते हैं. स्वर्गदूतों के बारे में हमारी यह ग़लतफ़हमी है। ईश्वर अनेक हैं\nनहीं, वह अकेला है; लेकिन ऐसे कई देवता हैं जो भगवान के अधीन हैं। हमें तुरंत परिणाम मिलते हैं\nइच्छावश भगवान को भूल जाना। अनेक देवताओं की पूजा करने की परंपरा\nहम बड़े हो गए हैं.  ऐसा करने से परिणाम तो मिल सकते हैं - लेकिन केवल थोड़े समय के लिए।  सांसारिक\nसुख की तलाश करना और अलग-अलग परिणामों के लिए अलग-अलग देवताओं की पूजा करना ही हमारा शाश्वत मोक्ष है\nरास्ते पर नहीं ले जाया जा सकता. इन्द्रिय सुख के लिए की गई पूजा को पूजा नहीं कहा जा सकता।\nमोक्ष की राह में देवदूत हमारी मदद कर सकते हैं, लेकिन सर्वशक्तिमान भगवान सावधान रहें\nबहुत महत्वपूर्ण.\n\nभगवान की जिस भी रूप में पूजा की जाती है, वह सांसारिक सुखों के लिए नहीं, बल्कि सर्वव्यापी है\nभगवान से जुड़ने के इरादे से पूजा करना आध्यात्मिक प्राप्ति में सबसे महत्वपूर्ण बात है।\nयह उचित है कि आप अपने भगवान को कृष्ण या अल्लाह कहें। लेकिन हम सबको बचा लो\nसत्य को जानो कि पोषण करने की शक्ति एक ही है। भगवान की पूजा विभिन्न रूपों में की जा सकती है। लेकिन\nअलग-अलग सुखों के लिए अलग-अलग देवी-देवताओं की पूजा करना आध्यात्मिक उपलब्धि नहीं हो सकती।\nभगवान को देवी-देवताओं की शक्ल में या देवी-देवताओं में देखना गलत नहीं है। क्योंकि प्रभु\nसर्वव्यापी, उसके बिना कोई जगह नहीं है. इसके अलावा यदि देवताओं की पूजा भगवान के रूप में की जाती है\nयहाँ तक कि देवता भी इसकी सराहना नहीं कर सकते।\n\nकृष्ण ने अपने अवतार के उद्देश्य और रहस्य को जानकर ऐसे ज्ञान से सिद्धि प्राप्त की\nउदाहरण दिया गया. बहुदेववाद से छुटकारा पाओ, ईश्वर एक है, देवता अनेक हैं\nउन्होंने इसे स्पष्ट कर दिया और यह भी स्पष्ट रूप से बताया कि पूजा कैसी होनी चाहिए. यह\nहमारे लिए एक सवाल उठ सकता है. मानव जाति का निर्माण इसी धरती पर हुआ है\nयह ईश्वर की ओर से हुआ. लेकिन एक इंसान दूसरे इंसान जैसा नहीं होता. प्रकृति विविधता का मूल क्या है?\nभगवान ने प्रत्येक को अलग-अलग क्यों बनाया? कृष्ण इस प्रश्न का उत्तर अगले श्लोक में देते हैं\n\nवह जवाब देता है.",
  "4.23": "गता संगस्य मुक्तस्य ज्ञान अवस्थिता चेतसः |\nयज्ञाय अचरतः कर्म घमन्न प्रविलीयते - फल के प्रति आसक्ति का त्याग, शरीर के प्रति आसक्ति का त्याग,\nउपासक के सभी कर्म भगवान की जागरूकता में स्थिर होते हैं।\n\nइस श्लोक में उपसंहार के रूप में ऊपर बताई गई सभी चीजें हमारे भगवान हैं\nआगे रखो\n\nफल की अधिक इच्छा न करो; बहुत ज्यादा उम्मीद मत करो; कर्तव्यनिष्ठ बनो;\nदेह प्रेम, पारिवारिक प्रेम त्यागकर अनासक्त होकर जीना सीखा; मन\nभगवान (चेतासु) में स्थित हो जाओ जो ज्ञान का रूप है। जब हम इस तरह रहते हैं तो हम यही करते हैं\nसभी कर्म यज्ञ के रूप में यज्ञ नमक भगवान में शामिल हो जाते हैं और कर्म ज्ञान की अग्नि में जल जाते हैं।\nगंदगी जल जाती है.\n\nब्रह्मर्पणं ब्रह्म हविर्ब्रह्मग्न ब्राह्मण हुतम् |\nब्रह्मैव तेन गन्तव्यं ब्रह्मकर्मसमाधिना",
  "4.17": "कर्मणः हि अपि बोद्धव्यं बोधव्यं च विकर्मणः।\n\nअकर्मणः च बोद्धव्यं गहन कर्मणः गतिः -- कर्म के बारे में भी जानना चाहिए। कर्म के विपरीत\nहमें रास्ता भी जानना चाहिए, हमें कर्म यज्ञ के बारे में भी जानना चाहिए।\nविकर्म हमें जानना चाहिए; अकर्म भी हमसे जानना चाहिए।] कर्म का क्रम\nरहस्यमय.\n\nकर्म क्या है और अकर्म क्या है यह ज्ञानियों के लिए भी भ्रम का विषय है। हम हैं\nआपको जानना होगा कि क्या करना है. हमारा कर्म प्रबुद्ध होना चाहिए। तो कर्म का मतलब है\nपहले मैं आपको बता दूं क्या. उनका कहना है कि इससे आप नुकसान से बच जायेंगे.\nकृष्ण.\n\nकर्म के बारे में जानना इतना आसान नहीं है। लेकिन ये तो पता होना चाहिए. कर्म का फल ही सबसे बड़ा है\nएक रहस्य. कर्म क्या है और अकर्म क्या है यह जानना बहुत कठिन है। बहुत बड़ा\nयह तो बुद्धिमान भी नहीं जानते। इतिहास में कुछ देख रहे हैं... हम\nयह भ्रमित करने वाला हो जाता है। उदाहरण के लिए वेदव्यास। वह एक अविवाहित बड़ी उम्र की लड़की से है\nकुंवारी (पुरुष) पैदा हुआ; वेदव्यास के पुत्र पांडु और धृतराष्ट्र की विधवाओं से पैदा हुए थे\nबच्चे; पति होते हुए भी कुलीनों के यहां जन्मे पांडव! धर्म क्या है? पांडव\nऔचित्य कितना सही है? क्या वेदव्यास को महाजनी ब्राह्मण स्वीकार करना संभव है? यह\nधर्म क्या है, अधर्म क्या है, क्या सही है, क्या गलत है, इसका उदाहरण देखिये\nहम भ्रमित हो जाते हैं.\n\nहमारे अनंत कर्म, अकर्म, विकर्म के पीछे अनंत भगवद् शक्ति काम कर रही है।\nहमें इसके प्रति सचेत रहना चाहिए. इस ज्ञान के बिना कर्म के सार को महसूस नहीं किया जा सकता है। एक\nशरीर में भगवान अनेक रूपों में (विकर्मणः) रहते हैं और कर्म करते हैं। कर्म तो बहुत है\nएक पेचीदा बात. इसे हमें ईश्वर से जानना होगा। निम्नलिखित श्लोक में कृष्ण कर्म\nरहस्य बताते हैं.",
  "2.54": "अर्जुन उवाच — हे केशव, स्थितप्रज्ञ का क्या लक्षण है? स्थितधी कैसे बोलता है, कैसे बैठता है, कैसे चलता है?\n\nयहाँ से गीता के सबसे प्रसिद्ध खण्ड का आरम्भ — स्थितप्रज्ञ का वर्णन (2.55–72)। अर्जुन का प्रश्न तीन स्तरों पर — (१) लक्षण; (२) वाणी; (३) आचरण। 'स्थितप्रज्ञ' — जिसकी प्रज्ञा स्थिर है।",
  "4.19": "यस्य सर्वे सीरमणः काम संकल्पवर्जितः\nज्ञान अग्नि दग्धा कर्मणां तम औह पंडितं बुधः - करने की इच्छा, पाने की\nवह जो इच्छाओं को त्याग देता है और जागरूकता की अग्नि के साथ सभी कर्मों में संलग्न होता है\nजला हुआ जो जानते हैं, ऐसे व्यक्ति को पंडित कहते हैं।\n\nहमारे जीवन की व्यस्तता के पीछे एक इच्छा है, एक संकल्प है। मुझे खुश होना चाहिए, मेरे\nपरिवार को खुश रखना चाहिए. वासना इसके लिए कोई अन्य विधि\n\nहम अनुसरण करेंगे. यही वह समस्या है जो मनुष्य को हर कार्य के पीछे परेशान करती है। उसकी चाहत का\nहम स्वयं को पूर्णता के लिए प्रतिबद्ध करते हैं। जिसके शामिल होने में चाहतों का स्पर्श\nअन्यथा वह तो विद्वान है। एक विद्वान की विद्वता उसके शब्दों में नहीं बल्कि उसके कार्यों में दिखनी चाहिए।\nयह आपके जीवन में ऐसा ही होना चाहिए, आपको इसे कैसे करना चाहिए, आप इससे क्या प्राप्त करना चाहते हैं,\nइच्छाओं को त्याग दो और सहजता से कर्तव्य करो। भगवान जो कुछ भी प्रसाद के रूप में देते हैं\nस्वीकार करें जो कुछ भी आपके सामने आए उसमें संतुष्ट रहना सीखें। अगर ऐसा नहीं है तो चिंता न करें. यह है\n'वासना से दूर रहो. [कुछ नहीं चाहिए, लेकिन ऐसा कुछ नहीं चाहिए\nवासना से परहेज]। जो भी आए, तुम खूब कोशिश करो. जो आया उससे खुश\nऐसी जागरूकता से किया गया सजीव कर्म शुद्ध होता है। यह कर्म गंदगी जागरूकता की अग्नि से है\nसफाई। ऐसी चाल रखने वाले को विद्वान माना जाता है। इन्हें बुद्धिमान लोग ``बुद्धिमान'' के रूप में जानते हैं।\nपहचानें यह वह नहीं है जो एक आदमी कहता है, यह वह है जो वह अभ्यास करता है\nमहत्वपूर्ण: मन को ढेर सारी इच्छाओं से भर देना और किसी चीज़ की इच्छा के पीछे होने का दिखावा करना\nजो पहन कर जीता है वह कभी ऊंचा नहीं उठ पाता।\n\nत्यक्त्वा कर्मफलसंगम नित्यथ्रिप्तो[5]निराश्रयः |\nकर्मण्यभिप्रवर्तोपि नैव किंचित् करोति सः",
  "4.2": "एवं परम्परा प्राप्तं इमं राजा खुशायः विदुः |\n\nसः कालेना एह महता योगः नित्तः परंतप-इस प्रकार यह एक से दूसरे में प्रवाहित हुआ है।\nबुद्धिमान राजा जानते थे. हे ज्ञान लाने वाले, यह बहुत समय के बाद उस ज्ञान का मार्ग है\nजमीन में गायब हो गया.\n\nसवेयं मया तेन्द्य योगः प्रोक्तः पुरातनः।\nभक्तोसि मे सखा चेति घस्याम ह्येतदुत्तमम् ॥3॥\n\nसः एव अयं मया ते आद्या योगः प्रोक्तः पुरातनः |\n\nभक्तः असि मेई सखा च इति घस्याम हि एतत् उत्तमम्-। जानने का वही पुराना तरीका\nमैंने अभी तुमसे कहा- क्योंकि तुम मेरे भक्त और मित्र हो। यह बहुत ही गोपनीय है\nबुजुर्ग तथ्य.\n\nउपरोक्त तीन श्लोकों में यह बताया गया है कि सृष्टि के आरंभ से लेकर अब तक ज्ञान की यह विरासत किस प्रकार विकसित हुई है\nछवि कृष्ण द्वारा दी गई है. वेद वस्तुतः ज्ञान का स्रोत हैं। वेदों का सार संग्रह करें\nइस प्रकार सम्पूर्ण वेदार्थ संग्रह के समान एक ग्रन्थ की रचना हो गयी। इसे पंचरात्र के नाम से जाना जाता है\nजिसे पंचरात्र कहा जाता है वह वैदिक वाह्मय और कर्म योग का ज्ञानयोग है\nएक विस्तृत पुस्तक. भगवत गीता उस पंचरात्र का संग्रह है। सृष्टि के आरंभ में,\nस्वायम्भुव मन्वंतर में भगवान पंचरात्र को चतुर्मुख को उपदेश दिया गया था। इस प्रकार संसार\nसृष्टि के निर्माण से पहले ही पंचरात्र का ज्ञान चतुर्मुख और देवताओं को हो गया था। सूरज\nवैवस्वत मन्वंतर में यह बात मनु से और मनु ने इक्षकु से कही है। यहीं कृष्ण हैं\nवे अर्जुन को समझा रहे हैं.\n\nदेवताओं को सबसे पहले यह ज्ञान भगवान से प्राप्त हुआ। इन्हीं देवताओं में से एक हैं सूर्य\nएक सूर्य वह देवता है जो पृथ्वी और देवताओं को जोड़ता है। उनसे वैवस्वत मन्वन्तर\nयह ज्ञान मनु को हुआ तो वह प्रशंसक बन गये। मनु ने यह बात अपने पुत्र इक्षकु को बताई।\nवह एक महान राजा थे जो पृथ्वी पर एक सम्राट के रूप में रहते थे। इस प्रकार यह ज्ञान देवताओं का है\nधरती में प्रवाहित हो गये.\n\nज्ञान शाश्वत है.. अमर विज्ञान है. यह विज्ञान प्रत्येक सृष्टि के आरंभ में है\nऐसा भगवान ने कहा है. फिर देवता, देवताओं से राजर्षि, फिर खुशियाँ\nइस प्रकार ज्ञान की विरासत बढ़ती है। आज वह ज्ञान लुप्त हो रहा है जो इस प्रकार प्रवाहित होता था; लोग\nयहाँ तक कि महर्षि अर्जुन भी इस ज्ञान को भूल गये हैं। जैसा कि पहले बताया गया है\nअर्जुन उस समय के एक महान ऋषि थे। हालाँकि, उसे यह याद नहीं है। यहाँ कृष्ण अर्जुन हैं\n\"परंतपा\" कहकर संबोधित किया जाता है। परंतप का अर्थ है सदैव भगवान को जानना\nदृश्यमान \"आप एक बुद्धिमान व्यक्ति हैं; आपके पास ज्ञान की विरासत है; फिर भी आपने संदेह किया;\nज्ञान की यह शाश्वत विरासत आपके अंदर लुप्त होती जा रही है। तो फिर बाकी का क्या?\nध्वनि इस परंतप के सम्बोधन में है।\n\nज्ञान नष्ट नहीं होता, मोह का पर्दा उसे रोकता है। तो अब मेरे पास आपके लिए वह ज्ञान है\nकृष्ण कहते हैं मैं फिर से कह रहा हूं। अर्जुन का कृष्ण के प्रति अपार सम्मान और भक्ति\nअंतरंगता को पहचानते हुए, अर्जुन को शाश्वत, अद्वितीय कृष्ण का यह ज्ञान\n\nअर्जुन की भक्ति को याद दिला रहा है कि भक्ति के नए रूपों में से एक है (श्रवण, कीर्तन, स्मरण, पादसेवन, अर्चना,\nवन्दना, दस सख्य और आत्मनिवेदन) एक सख्य हैं। उसने प्रभु को अपना मित्र बना लिया\nइसी कारण से कृष्ण यहाँ कहते हैं: \"तुम मेरे भक्त और मित्र हो। इसी कारण से यह।\"\nमैं तुम्हें बहुमूल्य ज्ञान बता रहा हूं.\n\n'यहाँ मैं तुम्हें गुप्त ज्ञान बता रहा हूँ' कृष्ण ने कहा। ज्ञान को गुप्त रखना\nदो कारण हैं. एक है इसका दुरुपयोग और दूसरा है इसका दुरूपयोग. कौन\nजो लोग ज्ञान प्राप्त नहीं कर सकते उन्हें ज्ञान देना और अपनी पीढ़ी को ज्ञान देना\nबर्बाद इस प्रकार, ज्ञान की विरासत को खोया नहीं जा सकता। अब कोई दुर्व्यवहार नहीं. ज्ञान हमारा है\nआत्मा की मुक्ति के लिए और दूसरों की मुक्ति का रास्ता दिखाने के लिए\nट्रेडिंग के लिए नहीं. ज्ञान से समाज को धोखा दिया जा सकता है। समझ\nवह उन लोगों को बरगला सकता है और धोखा दे सकता है जो उसके ज्ञान से रहित हैं। यह सब ज्ञान गुप्त होने के कारण ही गुप्त है\nविषय अतीत में, ऋषियों को योग सिद्धि से लुप्त होने का विज्ञान पता था। इतना बहुमूल्य ज्ञान\nदुरुपयोग बहुत आसान है. इसी वजह से इसे गुप्त रखा गया था. जानवरों की भाषा भी समझें\nहमारे पास इसे करने की शिक्षा थी। इसे भी गुप्त रखा गया. इस प्रकार ज्ञान से\nदुरुपयोग की संभावना होने पर इसे गुप्त रखना चाहिए। कितनी गुप्त बात है\n\nकृष्ण ने कहा मैं तुम्हें चुन रहा हूं।",
  "4.27": "सर्वाणि इन्द्रिय कर्माणि प्राणकर्माणि च अपारे |\nआत्म संयम योग अग्न जुह्वति ज्ञानदीपिते - कुछ लोग सभी कामुक क्रियाओं को कहते हैं,\nअग्नि में प्राण वायु की क्रियाओं को जानकर आत्मसंयम की प्राप्ति होती है\nपसंद है\n\nहमारे शरीर में संज्ञानात्मक एवं कर्मेन्द्रिय की सतत् प्रक्रिया चलती रहती है। इसके अलावा\nऐसे कई कार्य हैं जो प्राण शक्ति से उत्पन्न होते हैं (जैसे: सांस, शक्ति, प्रजनन क्षमता, खुशी या आदि)।\nदुःख होने पर आँसू आदि)। मनोनिग्रह नामक अग्नि में यह ज्ञानेन्द्रिय, कर्मेन्द्रिय है\nऔर प्राण-शक्ति की क्रिया को होम करना (धारण करना) ही यज्ञ है। ये जिद के लिए है\nनहीं, यज्ञ के रूप में भगवान की पूजा के रूप में। यह ईश्वर की चेतना से प्रकाशित आत्मा है\nभगवान के लिए संयमित आत्म-संयम; ईश्वर प्राप्ति की ओर\nसचेतन संयम जो वहन करता है, उतावलापन नहीं।\n\nयज्ञों की विविधता को गिनाते हुए, कृष्ण हमें यज्ञों की एक सूची देते हैं:",
  "4.32": "एवम बहुविध यज्ञः वितः ब्राह्मणः मुखे |\nकर्मज़ान विधि तं सर्वं एवं ज्ञात्वा विमोक्ष्यसे - इस प्रकार भगवान के मुख में अनेक प्रकार के यज्ञ फैले हुए हैं। जान लें कि ये सब कर्म के कारण हैं। यदि तुम यह जान लोगे तो तुम मुक्त हो जाओगे।\n\nयज्ञ के अनेक पहलू हैं। जब जीवन का कोई भी कार्य ईश्वर की चेतना के साथ किया जाता है, जब जीवन का कार्य ईश्वर के प्रति एक कार्य होता है, तो वह यज्ञ बन जाता है।",
  "3.42": "इन्द्रियाणि पराणि अहुः इन्द्रियेभ्यः परम मनः।\n\nमनसाः तु परा बुद्धिः यः बुद्धेः परतः तु सः-इन्द्रियॉं [शरीर से] बड़े स्थल हैं।\n[इंद्रियाँ जो इंद्रियों की प्रेमी हैं वे वरिष्ठ देवता हैं]। मन इन्द्रियों से श्रेष्ठ है\nधत्.[इंद्रिय-प्रेमी देवताओं से भी मन-प्रेमी रुद्र ज्येष्ठ देवता हैं]. दिमाग की बजाय बुद्धि\nहिरिया भट्ट [सरस्वती मनोभिमानी की तुलना में बुद्धिमानिनी की बड़ी देवता हैं]... बुद्धि से भी अधिक\nजो परे है वह वह परतत्त्व है [भगवान जो बुद्धि से श्रेष्ठ नहीं है]।\n\nजैसे बुरी आत्माएं होती हैं, वैसे ही दिव्य आत्माएं भी होती हैं जो हमारा भला चाहती हैं और हमारी रक्षा करती हैं\nहर भाव के लिए एक देवता प्रशंसक खड़े हैं। हमारी इंद्रियों का\nइन्द्र पंखा देवता हैं। शिव-पार्वती मन के प्रशंसक हैं, सरस्वती बुद्धि की प्रशंसक हैं।\nजो बुद्धि से परे है वह आत्मा है - वही उस भगवान का स्थान है।\n\nहमें उस दिव्य शक्ति के प्रति समर्पण करना होगा जो हमारे कामुक मन और बुद्धि को नियंत्रित करती है। फिर वो\nदेव शक्तियों की सहायता से हम ज्ञान प्राप्त कर सकते हैं और ईश्वर को पा सकते हैं। हमारा\nप्रत्येक इंद्रिय का एक संरक्षक देवता होता है। आँखों के लिए सूर्य, कानों के लिए चंद्रमा, मुँह के लिए\nअग्नि, जीभ के लिए -वरुण, नाक के लिए -अश्वेदेवता, हाथों के लिए -इंद्र (वह इंद्रियों का स्वामी भी है)।\nहाँ), पैर के लिए-इंद्र के पुत्र उपेन्द्र, यम-उत्सर्जन और कुशल संतान के लिए।\nसंबंधित अंग का देवता। इस प्रकार प्रत्येक देवता हमें हमारे शत्रु से बचा सकते हैं\nमदद करेंगे. इस प्रकार देवताओं से प्रार्थना करें और उनकी सहायता प्राप्त करें और बुरी शक्ति से दूर रहें\nआगे बढ़ें और उस दूसरेपन से जुड़ें जो पीछे छूट गया है।\n\nके\nजहि शत्रुं महाबाहो कामरूपं दुरसादम्\n\nएवं बुद्धे परमं बुद्ध्वा संसक्तभका त्मानमात्मना।\n\nएवं बुद्धे परमं बुद्ध्वा समस्तभ्य आत्मानं आत्माना |\nजहि शत्रुं मह बहो कामरूपं दुरसादम्-हे महावीर, आप जो इतने मूर्ख हैं।\n\nअनित्यता को जानकर, बुद्धि से मार्ग को पकड़कर, सामान्य लोगों की अदम्य वासना से घृणा करो।\nहिलाना\n\nइस प्रकार मन के चंचल घोड़े इन्द्रिय-मन-बुद्धि की अनित्यता को जानना\nबुद्धि की लगाम बांधो, उस लगाम को भगवान और सभी देवताओं के हाथों में सौंप दो\nमदद से, वह कदम दर कदम राक्षस कालनेमि को हराता है और भगवान से जुड़ जाता है\nकृष्ण. जब हमें कोई बुरी इच्छा होती है तो यदि हम यहां दी गई व्याख्या को याद रखें तो इसे कालनेमि कहा जाता है\nहम राक्षस को अपने अंदर प्रवेश करने से रोक सकते हैं। क्योंकि सभी इच्छाएं बुरी नहीं होतीं. प्रभु\nजुड़ने की चाहत जरूरी है. तो हे दुष्टों, हमारी बुद्धि प्रभु के हाथों में सौंप दो\nकोई भी व्यक्ति देवताओं की सहायता से इच्छाओं से लड़ सकता है और मोक्ष प्राप्त कर सकता है। यहाँ एक है\nसावधान रहना जरूरी है, इस बुरी ताकत से एक बार में जीत पाना नामुमकिन है।\nइसे चरण दर चरण अर्जित किया जाना चाहिए। उपलब्धि के विभिन्न स्तरों पर विभिन्न देवता हमारे लिए हैं\nमदद करेंगे.\n\nइति तृतीयोध्याय\nतीसरा अध्याय ख़त्म हो गया\n\nचिंता मत करो\n\nचौथा अध्याय\n\nइससे पहले कृष्ण ने उसके बाद दूसरे अध्याय में ज्ञानमार्ग और कर्ममार्ग का उल्लेख किया था\nतीसरे अध्याय में कर्म योग की सीमा बताई गई है। चौथे अध्याय में भगवान\nकृष्ण ज्ञान के संज्ञानात्मक पहलू और कर्म की किस्मों का वर्णन करते हैं। ज्ञान योग का उल्लेख पहले किया जा चुका है\nऔर कर्मयोग को ही ज्ञान के महत्व और कर्म के प्रकार, इन दोनों तक विस्तारित कर रहे हैं\nइस अध्याय में भगवान की उस महिमा का वर्णन किया गया है जो हमें मार्ग से प्राप्त हो सकती है। यह\nअध्याय की शुरुआत कृष्ण के शब्दों से होती है।\n\nभगवान का वचन\nइमान विवस्वथे योगं प्रोक्तवनहामव्यम् |\nविवस्वान् मनवे प्राहा मनुरिक्षा कवे$ब्रवीथ.. ॥1॥\n\nभगवान उवाच- भगवान ने कहा:\n\nइमाम विवस्वथे योगम् प्रोक्तवान् अहं अव्यम् |\n\nविवस्वान् मनवे प्राहा मनुः इक्ष्वाकवे अब्रवीथ - मैं साधना के इस अविनाशी मार्ग का अनुसरण करता हूं।\nमैंने सूर्या से कहा. सूर्य ने मनु को बताया था. मनु ने इक्षाकु से कहा था.\n\nएवं परम्पराप्रप्रमिमान राजर्षयोविदुः |\nसकलेनेहा महता योगो हानि हा परंतप ॥2॥\n\nएवं परम्परा प्राप्तं इमं राजा खुशायः विदुः |\n\nसः कालेना एह महता योगः नित्तः परंतप-इस प्रकार यह एक से दूसरे में प्रवाहित हुआ है।\nबुद्धिमान राजा जानते थे. हे ज्ञान लाने वाले, यह बहुत समय के बाद उस ज्ञान का मार्ग है\nजमीन में गायब हो गया.\n\nसवेयं मया तेन्द्य योगः प्रोक्तः पुरातनः।\nभक्तोसि मे सखा चेति घस्याम ह्येतदुत्तमम् ॥3॥\n\nसः एव अयम म",
  "4.26": "श्रोत्र आदिनि इन्द्रियाणि अन्ये संयम अग्निषु जुह्वति |\nशब्द अदीन विषयं अन्य इंद्रिय अग्निषु जुह्वति-कुछ लोग इंद्रियों का उपयोग कानों की तरह करते हैं।\nआग में जलता है. ध्वनि जैसी कुछ चीजें इंद्रियों की अग्नि में हैं\nपसंद है\n\nयज्ञ भी एक विशिष्ट उपलब्धि है जो साधक के पास होनी चाहिए। कामुक इच्छा का 'दमन'\nअग्नि में जलना एक यज्ञ है। बुरा मत सुनो, बुरा मत खेलो,\nबुरा न देखने के दृढ़ निश्चय के साथ, इंद्रियों पर संयम के साथ\nहोमिनी यह इंद्रियों पर विजय पाने की प्रक्रिया है। अग्नि में इन्द्रिय को संयम कहा जाता है\nचपला के विचार से प्रभु की आराधना करें। भगवान इससे प्रसन्न हों\nयह एक यज्ञ है जो मुझे सिद्धि के मार्ग पर ले जाने के लिए कहने के सन्दर्भ में किया जाता है।\nऔर अच्छी बातों को इंद्रियों में धारण करना भी एक यज्ञ है। अग्नि कुण्ड में जिसे किवि कहा जाता है\nईश्वर की स्तुति की आशा रखकर अग्नि पात्र में ईश्वर का प्रतीक जिसे नेत्र कहा जाता है।\nमूगू नामक अग्नि पात्र में मनोकामना रखकर भगवान को तुलसी, चंदन अर्पित किया जाता है।\nफॉर्म की वसीयत लगाना. इस प्रकार इंद्रिय विषयों की स्वीकृति भी एक यज्ञ बन जाती है।\nइन्द्रियों के दमन की भाँति इन्द्रियों का ग्रहण करना भी एक यज्ञ है। ईश्वर के विचार का पूरक\nजो है उसे अपनाओ और जो नहीं है उसका त्याग करो- यही प्राप्ति का मार्ग है\nएक महत्वपूर्ण कदम.",
  "4.21": "निरसिह यश चित्त आत्मा त्यक्त सर्व परिग्रह |\n\nशारीरम् केवलं कर्म कुर्वन के अप्नोथी किल्बिषम -- जब मन और भावनाओं को नियंत्रण में रखा जाता है।\nलालसा दूर हो जाती है. मैं-मेरा का भाव लुप्त हो जाता है। कर्म केवल शरीर के पोषण के लिए है\nयदि ऐसा होता भी है तो भी यह असफल नहीं होगा।\n\nसदैव संतुष्ट रहने की इच्छा लेकिन इसे आदत कैसे बनाएं? इस प्रश्न के लिए यहाँ कृष्ण हैं\nवह जवाब देता है. सांसारिक इच्छा होने पर असंतोष गलत नहीं है। जो आपके पास नहीं है उसे चाहने से आपको कभी खुशी नहीं मिलेगी। संतुष्ट\nयदि ऐसा होना है, तो सबसे पहले चाहतों और आवश्यकताओं की सूची को संकुचित किया जाना चाहिए। सबसे पहले 'सकारात्मक रहें'\n'निराश हो जाओ' (18 00101! 5/10 51378405 )/012%) कृष्ण कहते हैं। पहले हम\nहमें अपने मूड और दिमाग पर नियंत्रण रखना होगा. यहाँ चित्त का अर्थ है हमारा अतीत\nयादें(116130//)। मन अतीत की इच्छाओं की स्मृति है। मन में इच्छाएँ और निराशाएँ\nपूर्ण है पहले यह देख लें कि पिछली इच्छाएँ दोबारा न उभरें। अतीत को फिर से जियो\nखोदो मत. इसे पूरी तरह से जाने दें और मन को वर्तमान काल की इच्छाओं और जरूरतों की ओर जाने दें\nप्रवाह को नियंत्रित करें. अगर हम ऐसी आदत बना लें तो हम उससे संतुष्ट रह सकते हैं।\nइस प्रकार संतुष्टि प्राप्त करने के साथ-साथ 'आत्म्यक्त सर्व परिग्रह' भी। यहाँ परिग्रह का अर्थ है\nघर-परिवार, सब कुछ छोड़ कर जंगल में चले जाओ. उसके ऊपर, सब कुछ के बावजूद\n\nग्रेट स्किपिंग मोहा (040 88800/790)। अभिमान त्याग (18130180)\n8030173910 करना है। यह सब कुछ हो लेकिन इसमें फंस मत जाओ।\nइसके साथ जियो - लेकिन इससे चिपके मत रहो। कमल का पत्ता जल और जल में कैसे रहता है?\nजैसे चिपकता ही नहीं. जब ऐसा होता है तो हम सब कुछ करते हैं लेकिन कुछ नहीं करते। क्योंकि\nजब होशपूर्वक किया जाता है तो कोई कर्म नहीं होता। यदि हम आसक्ति के बिना जीना सीख जाते हैं, तो कर्म भी वैसा ही हो जाता है\nहमें परवाह नहीं है. शरीर निर्वाह के लिए आवश्यक कर्म पर मानसिक रूप से टिके बिना डींगें हांकना\nइसके बिना कर्म करो. कृष्ण कहते हैं कि तब कर्म का मैल तुम्हें छू नहीं पाएगा।\n\nयदृच्छलाभसंतुष्टु  द्वन्द्वतितो विमत्सा रः।\n\nसमः सिदवासीदौ च कृत *पिनानिबद्धदा ते",
  "4.20": "त्यक्त्वा कर्म फल असंगम नित्य त्रिप्पाः [ए] निराश्रयः\n\nकर्माणि अभिप्रवृत्तः अपि न एव किंचित् करोति सः - नेहा को कर्मफल में छोड़कर, वह\nप्रभु के आदर्श के रूप में जिसने कभी कोई अन्य इच्छा नहीं की और किसी के सामने सिर नहीं झुकाया\nजो जानता है [वह जो हमेशा भगवान के साथ शांति में रहता है] भले ही वह कर्म में संलग्न हो\nवास्तव में कुछ नहीं करता.\n\nकुछ लोग ऐसा नहीं चाहते, ये चाहते हैं. लेकिन जब यह आता है तो मजा आता है। कर्म\nफलों में अत्यधिक मित्रता अच्छी नहीं होती। भगवान ने प्रेरित किया. इसे बुद्धिमानी से प्रयोग करें\nसोचो यह कैसे करना है; फूलो मत. इसके आने की आशा मत करो, इसकी आशा मत करो\nजब आप पहुंचें तो उड़ें नहीं। फल के प्रति अत्यधिक लगाव अच्छा नहीं है। यही एकमात्र मनुष्य है जो आरामदायक है\nआराम से जीने का एक तरीका. यदि ऐसा नहीं है (11580001786 कटिट्टा बुट्टी!\n\nआदमी सपने बुनता रहता है कि मैं ऐसा हो जाऊं।\nजो कुछ चाहा जाता है वह सब हासिल नहीं होता। फिर हताशा, उदासी, तनाव (7685101)। यह मानसिक है\n\nव्याकुलता (181955100)। जब धन असमय आता है, तो पलायन - जीवन को नष्ट कर देता है! यह\n\nयदि यह किसी कारण से आया, यदि नहीं आया, या यदि इसे आना चाहिए, तो चिंता मत करो।\nसाफ मन से कर्तव्य में लग जाओ. किसी भी स्थिति में शांत रहें. इस तरह\nकृष्ण ने कहा कि अपने मन को प्रशिक्षित करो। यही कृष्ण का मनोविज्ञान है.\n\nजीवन ईश्वर का प्रतिबिम्ब है। इसकी कोई स्वतंत्रता नहीं है. दर्पण जैसा दर्पण। भगवान शाश्वत हैं\nसंतुष्ट, वह असंतुष्ट नहीं है. उसी प्रकार हमें भी असंतोष के बिना जीना सीखना चाहिए।\nकिसी इच्छा की पूर्ति के लिए इतने सारे लोगों के पीछे घूमना\nस्वार्थी होकर जीना जीवन नहीं है. प्रभु जिसका कोई आश्रय नहीं\nप्रतिबिम्ब, आपको दुखी जीवन क्यों जीना चाहिए? भगवान की तरह बेघर हो जाओ. भगवान आपका सदैव कल्याण करें\nइस सत्य को जानकर जियो कि शरण है। यद्यपि ऐसा जीवन जीने वाला मनुष्य कर्म में लगा रहता है\nकुछ नहीं करता. क्योंकि वह जानता है कि ईश्वर सबसे ऊपर है\nज्ञात हो इसकी अधिक व्याख्या निम्नलिखित श्लोकों में पाई जा सकती है।\n\nनिराशिर्यात्चित्त (त्यक्तसर्वपरिग्रह |\nशरीरं केवलं कर्म कुर्वन नाथपनो त्रि किल्बी शम्",
  "4.22": "जो स्वतः प्राप्त वस्तु में सन्तुष्ट है, जीवन के द्वन्द्वों से परे है, ईर्ष्यारहित है, सफलता और असफलता में समान भाव रखता है — वह कर्म करके भी नहीं बँधता।\n\nज्ञानयोगी के चार लक्षण — (१) यदृच्छालाभसन्तुष्ट: जो मिल जाए उसमें सन्तोष; (२) द्वन्द्वातीत: सुख-दुःख, मान-अपमान से परे; (३) विमत्सर: दूसरों की उन्नति में ईर्ष्या नहीं; (४) सिद्धि-असिद्धि में सम: कर्म के परिणाम से अप्रभावित। ये चार मिलकर सच्चे कर्मयोगी का चित्र बनाते हैं।",
  "4.34": "तत् विद्धि प्रणिपथेन परिप्रश्नेन सेवया |\nउपदेक्ष्यन्ति ते ज्ञानं ज्ञानिनः तत्त्वदर्शिनः - ज्ञान प्राप्त करने के लिए, कृष्ण कहते हैं, \"आपको बुद्धिमानों का अनुसरण करना चाहिए; उन ऋषियों से ज्ञान प्राप्त करें जिन्होंने सत्य का एहसास किया है।\" सिर्फ किताब पढ़ने से ज्ञान नहीं मिलता. यही हमारा एहसास होना चाहिए. \"सत्य एक अंतर्ज्ञान है\nफ़्लैश, यह बौद्धिक नहीं है\"। सत्य हमारे सामने स्पष्ट होना चाहिए।\n\nसामान्य तौर पर, सत्य का एहसास कर चुके बुद्धिमान लोग कभी भी उन लोगों को ज्ञान नहीं सिखाते जो योग्य नहीं हैं। इसीलिए कृष्ण कहते हैं: \"जब आप दार्शनिकों को देखें तो उन्हें जाने न दें, उनकी पीठ पर चढ़ें, उन्हें चाटें, उनके सामने खुद को योग्य साबित करें। उन्हें अपनी अनूठी इच्छा के बारे में बताएं।\nसमर्पण।\"",
  "4.36": "अपि चेत असि पापेभ्यः सर्वेभ्यः पापा कृत तमः\nसर्वं ज्ञान प्लवेण एव वृजिनं संतरिस्यसि - आप सभी पापियों में सबसे महान हैं।\nएक पापी व्यक्ति भी ज्ञान की नाव से सभी संकटों को पार कर सकता है।\n\n\"यद्यपि आप अपने समय के सबसे बड़े पापी हैं, एक बार जब आप प्रभु के प्रति जागरूक हो जाते हैं\nयदि आप उठते हैं, तो आप जीतते हैं,\" कृष्ण कहते हैं। क्योंकि ज्ञान के मार्ग पर समझ के बाद आ गया है\nयदि यह चलता रहा तो पिछला कोई भी पाप नहीं रुकेगा। ज्ञान पाप के सागर में नाव के समान है। इतना ही\nहमें किनारे कर सकते हैं. ज्ञान ही पाप सागर से पार होने का एकमात्र साधन है। जैसे कि\n\nकृष्ण ने बहुत बड़ा वचन दिया है. तो हम सभी आज इसी क्षण से ज्ञान के पथ पर हैं\nआइए आगे बढ़ने के संकल्प के साथ आगे बढ़ें - क्योंकि कल का मतलब है कि कल हमारे पास नहीं आएगा\nशायद!  एस/ए5॥शश0762)/ 5/25 1151001/, 1017309704/ 15 ए 07)/5101/, ₹083)/ 15 0005 010, (205 5/1)/ 8\n\n€3 1! 8 85011.\n\nअगले श्लोक में बताया गया है कि ज्ञान का मार्ग अपनाने वाले पापी का क्या होता है\nकृष्ण ने स्पष्टीकरण दिया है.",
  "4.38": "नहि ज्ञानेन सदृशं पवित्रं एह विद्यते\nतत् स्वयं योग संसिद्ध कालेना आत्मानि विंदति- यहां ज्ञान के समकक्ष पवित्र वस्तु है।\nकोई दूसरा नहीं है. जो व्यक्ति उपलब्धि से वश में हो जाता है वह नियत समय में उसे अपने अंदर प्राप्त कर लेता है।\n\nज्ञान पवित्र है. इस संसार में इसकी तुलना करने वाली कोई अन्य वस्तु नहीं है। क्योंकि\nज्ञान ही ईश्वर है. इसलिए \"ज्ञान का मार्ग पकड़ो, उचित समय पर तुम्हें सिद्धि प्राप्त होगी।\"\nयदि आप इसे प्राप्त करते हैं, तो आप इसे प्राप्त करेंगे\" कृष्ण का वादा है। कभी-कभी सिद्धि के पथ पर सिद्धि प्राप्त करने के लिए\nइसमें कुछ जन्म लग सकते हैं. लेकिन विश्वास के साथ परमेश्वर के वादे पर भरोसा रखना\nजो आगे रहता है उसे सिद्धि मिलती है।\n\nश्रद्धावान लबते ज्ञानं तत्परः संयतेन्द्रियः।\n\nज्ञानं लब्ध्वा परमं शांतिमाचिरेनाधिगच्छति",
  "4.41": "योग संन्यस्थ कर्मणां ज्ञान समुच्चिन्न संशयम्\nआत्मवंतमं कर्माणि निबद्धन्ति धनंजय - धनंजय, सिद्धि से कर्म फल।\nभगवद्भ कथन को कर्म नहीं बांधते, जिसने त्याग दिया है, जिसने जागरूकता के कारण अपना संदेह खो दिया है।\n\nकृष्ण कहते हैं जीवन में कर्म करो, कर्म करो और कर्म संन्यास करो। यहाँ कर्म\nसंन्यास कर्म त्याग नहीं है. 'यह कर्म भगवान का है, कर्म भगवान में है\n'अर्पण'- कर्मसंन्यास (इसकी अधिक व्याख्या अगले अध्याय में मिलेगी)।\nकर्म के फल की इच्छा का त्याग करना, निष्पक्ष होकर सब कुछ समभाव से देखना।\nनिरंतर कर्म करना ही कर्मसंन्यास है। ज्ञान के साथ कर्म को प्रभु में अर्पित करें\nशंका समाधान करो, बुद्धिमान बनो, मन जगाओ, आत्मवान बनो\nजब हम जीना सीख जाते हैं तो कोई भी कर्म हमें बांध नहीं सकता। \"युद्ध में शत्रु\n\nकृष्ण कहते हैं, \"तुम जिसने धन जीत लिया है, धनंजय जिसने ज्ञान जीत लिया है, तुम कर्म से बंधे नहीं हो।\"",
  "4.37": "यथा एधनसि समिधा अग्निः भस्म सत् कुरुते अर्जुन |\nज्ञानाग्नि ह सर्व कर्माणि भस्म सत् कुरुते तथा- अर्जन, जलती हुई अग्नि\nजागरूकता की आग लकड़ी की तरह सभी कर्मों को जला देती है।\n\nज्ञान सदैव जलती रहने वाली अग्नि है। उससे अधिक शक्तिशाली कोई अग्नि नहीं है। कैसे\nजैसे जलती हुई अग्नि लकड़ी को जला देती है, वैसे ही ज्ञान की अग्नि सभी पाप कर्मों को जला देती है\nजैसा कि भागवत में कहा गया है, आध्यात्मिक रूप से अग्नि सत्व गुण का प्रतीक है। इसलिए यह है\nएक ऐसी शक्ति जो प्रकाश देती है और सदैव सकारात्मक रहती है। इसी प्रकार लकड़ी को सदैव नीचे खींचा जाता है\nतमोगुण का प्रतीक...जैसे आग लकड़ी को जलाती है, ज्ञान तमस्ना अभ्यासी में\nजलेगा यहां कृष्ण 'अर्जुन' को संबोधित करते हैं। अर्जुन का अर्थ है 'प्रयास करने वाला',\nज्ञान नामक अग्नि है। इस संबोधन से कृष्ण अर्जुन के ज्ञान पर मोहित हो गये\nस्क्रीन को हिला रहा है.\n\nनहि ज्ञानेन सदृशं पवित्रमिहा विद्यते |\nतत् स्वयं योगसमसिद्ध कालेना*त्मणि विंदति।",
  "4.40": "अज्ञः च अश्रद्धानः च संशय आत्मा विन्यशति\nन अयं लोकः अस्ति, न परः न सुखं संशय आत्मानः - अज्ञानी, अविश्वासी\nदो विनाश की ओर जाते हैं। दो के लिए नहीं; कोई बात नहीं; कोई शांति नहीं है.\n\nज्ञान और परिश्रम के बिना अज्ञानी लोग निरंतर संदेह में रहते हैं। बिना ज्ञान और परिश्रम के\nयहीं से संदेह बढ़ने लगता है. वह संदेह मन पर आक्रमण करता है और फिर इच्छा तक पहुँच जाता है।\nमन में आये संदेह का कोई समाधान नहीं है. यह हमें विनाश की ओर ले जाता है। इस से\nऐसी कोई बात नहीं, कोई बात नहीं, कोई शांति नहीं.\n\nयोगसंन्यस्थकर्मणं ज्ञानसमचिन्नासंशयम् |\nआत्मवन्तं कर्माणि निबधाना ति धनंजय",
  "4.28": "द्रव्य यज्ञ तपः यज्ञ योग यज्ञ तथा अपरे |\n\nस्वाध्याय ज्ञान यज्ञः च यतयः संसीता व्रतः - कुछ लोग संपत्ति के स्वामी होते हैं।\nकुछ लोग तपस को भगवान मानते हैं। कर्म सिद्धि कुछ लोगों का बलिदान है। तीव्र निष्ठा\nकुछ इच्छुक लोगों के लिए, वेदाध्ययन भगवान को जानने के लिए यज्ञ है।\n\nद्रव्यज्ञ: कुछ लोग द्रव्य के माध्यम से भगवान की पूजा करते हैं। यह आग है\nयह दान, दान, अन्न दान, कन्यादान आदि के रूप में हो सकता है।\nजो योग्य है, उसे सही समय पर, जो योग्य है, उनके भीतर का प्रभु प्रेम करे\nवह देना भौतिक त्याग है।\n\nतपोयज्जा: इसके दो पहलू हैं। एक बाहरी और दूसरा आंतरिक. उसके लिए निरंतर ध्यान\nईश्वर के विचार के लिए किसी बाहरी...उपकरण...दूसरे...की आवश्यकता नहीं है। आवश्यकता है\n\nआत्मसंयम (6150179)-इसे तप कहते हैं... जैसे ब्रह्मचर्य,\nवृतानुष्ठान, आदि।\n\nयोगयज्ञ: इसका अर्थ है भगवान के प्रेम में विभिन्न कर्म योग करना।\nयह बाहरी कर्मों के माध्यम से भगवान की पूजा है। उदाहरण के लिए: भगवान को 108 प्रदक्षिणा, अर्चना,\nआदि। इसके अलावा योग शास्त्र में बताए अनुसार यमान्यम का पालन करना चाहिए।\n\nस्वाध्याय ज्ञानयज्ञ: यह भगवान का सबसे प्रिय यज्ञ है। यहीं स्वाध्याय है\nइसके कई अर्थ हैं. वह पढ़ना जो उसके लिए प्रासंगिक है, उसे क्या पढ़ने की ज़रूरत है। उसकी शाखा का\nवेदाध्ययन; उस परमेश्वर के गुण का अध्ययन करो जो सर्वत्र स्वतंत्र है\nस्वाध्याय सभी शास्त्रों में पाया जाता है। जो इस युग में विज्ञान के रहस्य को जानते हैं\nमिलना बहुत दुर्लभ है. भगवान कितने बुद्धिमान हैं कि ऐसे मामले में समय बर्बाद न करें\nजो दिया गया है उसका उपयोग करके जितना हो सके अध्ययन करना भी स्वाभाविक है। यह\nसमस्त स्वाध्याय हमारे ज्ञान की वृद्धि में सहायक है। हम वही जानते हैं जो हम जानते हैं\nदूसरों के साथ साझा करना ईश्वर को सबसे प्रिय है। दूसरों के साथ बांटने से बढ़ता है\nधन का एक स्रोत ज्ञान है। यदि हमें ज्ञानयज्ञ करना है तो हमें यति बनना होगा। यहाँ\nयति कोई साधु नहीं है. यति का अर्थ है निरंतर प्रयास करना। सिद्धि भी और तीव्र अभ्यास भी\nजरूरी भी है. इसका अर्थ है स्वच्छ एवं ईमानदार जीवन। इसके बिना कोई भी कर्म किया जाता है\nयह कोई बलिदान नहीं होगा. अध्यात्म की राह पर आगे बढ़ने के लिए चलना जरूरी है।\n\nअपाने जुह्वति प्राणं प्रणम्पनं तथा$परे।\n\nप्राणापानगति रूध्वा प्रहयामापरायणः",
  "4.18": "कर्माणि अकर्म यः पश्येत् अकर्मणि च कर्म यः |\nसः बुद्धिमान मन्शिनेषु सः युक्तः कृत्स्नकर्म कृत -- जब संसार की क्रिया चल रही हो तब भी।\nजो यह जानता है कि उससे कुछ नहीं हुआ, उसके कुछ न करने पर भी संसार की क्रिया चल रही है\n\nजो यह जानता है, [जो जानता है कि कर्म से बंधे व्यक्ति के जीवन में कोई कर्म नहीं है, वह अकर्मक हो जाता है\nवह जो भगवान में सभी कर्मों को देखता है] वास्तव में मनुष्यों में ज्ञाता है। वह उपलब्धि हासिल करने वाला है\nवह जो रास्ता जानता है; जिसे सभी कर्मों का फल मिलता है।\n\nयहाँ कृष्ण कर्म क्या है इसके बारे में एक बहुत ही रोचक विचार बताते हैं। अतीत में\nजैसा कि उल्लेख किया गया है, संस्कृत गुप्त अर्थ वाली भाषा है (135॥ळ 18760899)। उसके लिए भगवत गीता\nपढ़ने के बाद बिना आध्यात्मिक अनुभव के कुछ भी पता नहीं चलता। हम आध्यात्मिक अनुभव के स्थान पर कितने हैं\nआप जितना गहराई में जाएंगे, गीत उतना ही गहरा होता जाएगा। यह श्लोक इसका उदाहरण है.\nयह कविता एक पागल बयान की तरह है जो एक पहेली की तरह खुद का खंडन करती है! यह यहाँ है\nकहा जाता है: \"जहाँ कर्म है, वहाँ कर्म नहीं है। जहाँ कर्म नहीं है, वहाँ कर्म है। यह कौन जानता है?\"\nवह बुद्धिमान है” या “जो कर्म है वह कर्म नहीं है, जो कर्म नहीं है वह कर्म है;\nजो यह जानता है वह बुद्धिमान है” यदि आप अध्ययन के साथ-साथ यहां इसका अर्थ भी जानना चाहते हैं\nआध्यात्मिकता की भावना की आवश्यकता है।\n\n'जहाँ कर्म है वहाँ कर्म नहीं है।' हमें एहसास होता है कि हमारे पास कर्म हैं। 'मुझमें\nहमारी भावना है कि कर्म की मुक्ति है - मुझे किसी से कोई लगाव नहीं है। लेकिन हमारे पास जो कर्म है\nप्रभु के अधीन. सृष्टि के इस चक्र में जब हम कुछ नहीं करते तब भी क्रिया निरंतर बनी रहती है\nयदि आप कुछ कर रहे हैं तो यह कार्य आपके कारण नहीं हुआ है। मेरे पास कार्रवाई है\nभ्रम छोड़ो. प्रकृति निरंतर अपना कर्तव्य निभा रही है। विश्व कार्रवाई\nऐसा तब भी होता है जब हम निष्क्रिय होते हैं। हम कुछ भी करें, कुछ नहीं होता। यह चक्र\nनिरंतर.\n\nआइए इसे समझने के लिए एक सांसारिक उदाहरण देखें। एक स्व (यह संसार चक्र)\nइसके सिर पर एक छोटी सी चींटी (सामान्य मनुष्य) है। हाथी पूर्व से पश्चिम की ओर बढ़ रहा है।\nचींटी लगातार सिर से पूंछ तक यानी पश्चिम से पूर्व की ओर घूम रही है। लेकिन हाथी पर\nयह चींटी जिस भी दिशा में चलती है, हाथी जहां जुड़ जाता है, वहीं जुड़ जाती है। यहाँ\nचींटी की गति व्यर्थ है—उसका कोई उपयोग नहीं है। अगर यह चींटी मेरा हाथी है\nयह जानते हुए भी कि यह वहां से यहां तक पहुंच गया? कितना अजीब है ना? खैर, हमारा आंदोलन\nइसके पीछे एक महान प्रेरक शक्ति है। संपूर्ण ब्रह्माण्ड (002/7309) को लेते हुए, इस पृथ्वी को\nअन्य ग्रहों के बीच एक छोटा सा बिंदु. उस समय हमारा देश अभी भी छोटा था\nवह बिंदु जिसमें 'मैं' अकल्पनीय बिन्दुओगा/ 01) 316 175107110800) है।\nलेकिन हम यही सोचते हैं कि यह ब्रह्माण्ड हमारी वजह से बन रहा है। संपूर्ण\nहम विश्व की गति के साथ हैं। एक इकाई होने के अतिरिक्त हमारा अपना कुछ भी नहीं\n\nनहीं हो रहा है. तो कृष्ण कहते हैं, 'कर्म में अकर्म देखो।' इस प्रकार उसका कर्म\nएक बुद्धिमान व्यक्ति जो जानता है कि ईश्वर सार्वभौमिक शक्ति को नियंत्रित करने वाली शक्ति है।'\n'युक्तः' का अर्थ है जो अपने मन को सत्य की ओर मोड़ता है और सत्य को जानने के लिए ध्यान करता है\nइसका मतलब है कि इस प्रकार जो सही और गलत को जानता है उसे सभी कर्मों का पूरा फल मिलता है। इस व्यक्ति के लिए लेखकत्व\nयद्यपि इसकी प्रशंसा नहीं की जाती; मैंने जो किया है उस पर मुझे गर्व नहीं है; मैं स्वतंत्र हूं\nकोई भ्रम नहीं है. इसलिए वह जो भी कर्म करता है वह फलदायी होता है। प्रभु की सर्वोच्चता\nउनका जीवन जागरूकता से आकार लेता है। ऐसा व्यक्ति छोटा सा भी कार्य करे तो भी उसे बड़ा फल मिलता है\nअहंकार से छुटकारा पाना अध्यात्म में सबसे महत्वपूर्ण बात है। कृष्ण\nये बात वो गाने में बार-बार कहते हैं. अहंकार इतना खतरनाक है कि\nगीता पढ़ने के बाद 'मैंने गीता पढ़ी है' का अहंकार आ जाता है! इसलिए ज्ञान\nसंपादन के साथ-साथ एक सावधानी भी सदैव बरतनी चाहिए। कभी अहंकार मत करो.\nअहंकार अध्यात्म का मार्ग नहीं है।\nयदि भगवान कर्म भी करते हैं, तो भी वे कर्म से कलंकित नहीं होते। भगवान में बिना किसी कर्म के\nसारे कर्म वहीं हैं. यदि कर्म है तो कर्म नहीं है। पूर्ण वही है जो कर्मों से मुक्त है\nउसे फल मिलता है. कर्म के वशीभूत व्यक्ति सोचता है कि 'मैंने यह किया, यह मेरे कारण हुआ।'\nकैद में फंसकर वह संघर्ष करता है। यह कृष्ण के कर्म का वर्णन है (66181108)। भगवान में कर्म\nकोई लेप नहीं है, लेकिन सर्वशक्तिमानता है। हमने जितना कर्म संचित किया है\nकर्म का फल हमें मिलता है। जो यह जानता है वह बुद्धिमान है। वह... कर्म का सच्चा है\nअनुसन्धान से उसका पूरा फल मिलता है। इसे अगले श्लोक में और स्पष्ट करें\nकृष्ण बताते हैं.\n\nयस्य सर्वे सारेमनः कामसंकल्पवर्जितः |\nज्ञानाग्निदगकर्मणं तमहुः पण्डितं बुधः",
  "4.30": "अपरे नियत आहारः प्राणान प्राणेषु जुह्वति |\n\nसर्वेक्षण एपीआई. एते यज्ञविदः यज्ञक्षपिता कल्माशः -कुछ लोग अपने भोजन को संयमित करते हैं\nइन्द्रियवृत्ति की तुलना इंद्रियों से की जाती है\nवे स्वयं को इंद्रिय-देवताओं के अधीन मानते हैं] ये सभी बलिदान का तरीका जानते हैं;\nजिन्होंने यज्ञ से मैल धोया।\n\nकुछ लोग भोजन पर नियंत्रण रखकर और कामुक सुखों को कम करके हासिल करते हैं।\nआहार नियंत्रण का अर्थ है बहुत अधिक भोजन न करना, कम नमकीन-खट्टा-स्वादयुक्त भोजन करना\nआदि। इससे तनाव की भावना कम हो जाती है। इसका असर सीधा दिमाग पर पड़ता है.\nइस प्रकार आहार-नियंत्रण से सिद्धि यज्ञ है। इसी कारण हमारे यहाँ अनेक त्यौहार हैं\nहरिदान के दिनों में, एकादशिन्दु-उपवास सामाजिक रूप से स्थापित हो गया। इससे कम से कम वह\nइसका मतलब यह है कि एक दिन के लिए भी मन को साफ करके भगवान की भक्ति में लगाना चाहिए\nपिछला इरादा.\n\nयज्ञ का दूसरा प्रकार है \"प्राणं प्राणेषु जुह्वति\" अर्थात प्राणों में प्राण\nइन्द्रियों में भाव का होम करना या होम करना। यहाँ तात्पर्य इन्द्रियों से है\nकामुक देवता. हमारी प्रत्येक इंद्रिय का एक प्रशंसक देवदूत है। यह\nदेवता एक स्तर (1901000) में काम करते हैं। प्रत्येक देवता\nवे सीढ़ियों पर खड़े होकर काम करते हैं और वे हमारे लिए प्रभु से जुड़ते हैं\nमदद करेंगे. इन देवताओं के साथ विभिन्न स्तरों पर भेदभाव करने के बारे में सोचना, यह है\nभगवान मुखेन का चिंतन एक बलिदान है। परमेश्वर प्रथम हैं। सब कुछ उसका है\nउनके बाद माता प्रकृति लक्ष्मी, फिर ब्रह्मा-वायु, सरस्वती-भारती, गरुड़-शेष-रुद्र,\nसुपर्णी-वरुणि-पार्वती, इंद्र-कमरा, दक्षादि, सूर्य-चंद्र-यमादि, वरुण, अग्नि,\nअश्व देवता, कुबेर, यज्ञ। इस प्रकार एक दूसरे के अधीन है और विभिन्न स्तरों पर कार्य करता है\nप्रबंध कर रहे हैं. इस प्रकार शरीर नामक इस अद्भुत मशीन को नियंत्रित करने वाले देवताओं के बारे में जागरूकता,\nजिसके माध्यम से ज्ञान साधना-तारात्मक ज्ञान यज्ञ, जो भगवान की ओर ले जाता है।\n\nयज्ञ में कोई अच्छाई या बुराई नहीं होती। कौन सा यज्ञ किसके लिए उपयुक्त है?\nवह चेहरे से हासिल करता है. हर कोई सब कुछ नहीं कर सकता. किसके लिए क्या?\nयदि यह अच्छा लगता है, यदि यह उपलब्धि के लिए अनुकूल है, तो इसका उसी प्रकार पालन किया जाना चाहिए। बलिदान से\nजो अपने जीवन के हर कदम पर आराध्य यज्ञमूर्ति भगवान की ओर बढ़ता है\nभगवान की आराधना करके वह अपने जीवन के कल्मषों को धो देता है\nस्वच्छ जीवन जीते हैं।",
  "4.29": "अपान जुह्वति प्रणाम प्राण अपानं तथा अपरे।\n\nप्राण अपान गति रुद्धवा प्राणायाम परायणः - प्राणायाम के अभ्यासकर्ता कम हैं।\nजीवन और मृत्यु की गति को रोकता है और अपान में जीवन की रक्षा करता है। जीवन में\nअपान.\n\nयोग में एक अद्वितीय अभ्यास साधना प्राणायाम है। कुछ लोगों के लिए, प्रहयाम जीवन में एक उपलब्धि है।\nजीवन और मृत्यु को यज्ञ के रूप में भगवान को अर्पित करना, प्राणायाम द्वारा भगवान की पूजा करना-\nअपान में प्राण को मारना। इसका सम्बन्ध कुम्भक से है। शरीर के अंदर से\nप्रश्वास 'रेका' है; ऑक्सीजन युक्त स्वच्छ हवा का साँस लेना\n'पूरक'. प्राण शक्ति को अपने हृदय कलश में रखना - \"कुंभक\" अत्यंत प्रभावशाली है।\n\nइससे एकाग्रता, स्वास्थ्य और दीर्घायु बढ़ती है। सामान्यतः मनुष्य का जीवनकाल उसका होता है\nनिर्णय श्वास पर आधारित है। एक प्राकृतिक सांस हर चार सेकंड में एक होती है\nसाँस लेना (संपूर्ण और पूरक)। मनुष्य का जीवन काल सौ वर्ष का होता है\n'77 करोड़, 76 लाख सांस'. अगर आप 4 सेकंड की बजाय हर 8 सेकंड में सांस लेते हैं\nयदि वह ऐसा करता है, तो वह 200 वर्षों तक जीवित रह सकता है। इस विगत प्राणायाम के कुछ अभ्यासकर्ता\nआज भी आरोग्यपूर्णा हिमालय में सैकड़ों वर्ष पुरानी है\nपेशेवर हैं.\nस्वामीराम (ओ1/176 1 1/7218)/80 11251079) ने अपने अनुभव से कहा।\nप्राणायाम से प्राणशक्ति बढ़ती है। इससे दूसरे की बीमारी भी हो जाती है\nठीक किया जा सकता है. इसे छुएं या 700008 डायल करें। हाथ के स्पर्श मात्र से डर लगता है,\nरोग, शोक, पागलपन, अंधापन सब ठीक हो सकते हैं। इस कारण एक से दूसरे\nआशीर्वाद देते समय सिर पर हाथ रखा जाता है। इससे जीवन शक्ति महान् से है\nछोटों के लिए बह रहा है. इस प्रकार प्रजायाम में अनेक सिद्धियाँ संभव हैं। इसका मुख्य कारण मन है\nईश्वर में निवास करता है. कृष्ण इसे यज्ञ कहते हैं।\n\nशक्ति अपान ऊपर से नीचे की ओर, मूलाधार से सहस्रार तक उर्ध्व मुख के रूप में प्रवाहित होती है\nबहती हुई ऊर्जा ही प्राण है। कुंभक हृदय में इन दो शक्तियों का निलंबन है। पूर्णतः\nउसके दाहिने नथुने से सांस छोड़ें और उसके बाएं नथुने से बाहर छोड़ें\nशुद्ध वायु को इस सीमा तक लेना कि वह फिर प्रवेश न कर सके, प्राण शक्ति\nहृदय में ऊर्जा का रुक जाना ताकि वह ऊपर न जाए, अपान नीचे न जाए - कुम्भक।\nयह प्राणायाम परायण द्वारा किया जाने वाला यज्ञ है। प्रभु कृपया मुझे एकाग्रता प्रदान करें,\nमुझे अपनी उपलब्धि जारी रखने में मदद करने के इरादे से साँस लेना\nयज्ञ. [नोट: गुरु के मार्गदर्शन के बिना प्रायाम का प्रयास नहीं किया जाना चाहिए]",
  "5.2": "भगवानुवाच- भगवान ने कहा\n\nसंन्यासः कर्मयोगः च निःश्रेयसा करौ उभौ |\n\nतयो तु कर्म संन्यासात् कर्मयोगः विशिष्यते - कर्म संन्यास और कर्म योग\nदोनों अच्छे तरीके हैं. इनमें कर्मयोग कर्मसंन्यास से भी बढ़कर है।",
  "4.39": "श्रद्धावान लबते ज्ञानं तत् परः संयत् इन्द्रियः।\n\nज्ञानं लब्ध्वा परम शांतिमा अचिरेण अधिगच्छति - इंद्रियों को वश में रखें; साभार\nजो मुझे परमात्मा मानता है, वह शीघ्र ही ज्ञान प्राप्त कर सुख का स्थान मुक्ति प्राप्त कर लेता है\nमिलता है\n\nहमारे पास जागरूकता है. जागृत करने के लिए। केवल अध्ययन ही पर्याप्त नहीं है. हमारे लिए एक बात\nआश्वस्त होने के लिए, हमें पहले ईमानदारी की आवश्यकता है। यहां समर्पण की भावना सर्वोपरि है। मैं हूं\nव्यक्ति को सबसे पहले इस अहंकार को त्यागना चाहिए कि जो ज्ञात है वह बड़ा है, और उससे बड़ा कुछ भी नहीं है।\nमुझे यह विश्वास करने की आवश्यकता है कि जो मैं नहीं जानता वह सच हो सकता है। संसार का सत्य हमारा है\nआस्था पर आधारित नहीं. इस संसार में हम जो कुछ भी जानते हैं वह केवल एक बहुत छोटा सा हिस्सा है। हमारे लिए\nपरिश्रम यह जानना है कि एक सत्य है जो ज्ञात नहीं है। हमारे जीवन का लक्ष्य ज्ञान एवं सत्य है\nसमझना होगा. ज्ञान की प्यास के साथ-साथ इन्द्रियों की सूक्ष्मता पर भी नियंत्रण होना चाहिए। जब ये मामला है\nउससे मानसिक बोध, आत्म-साक्षात्कार-अंततः सर्वोच्च का बोध होता है। इस कदम से\nअपरोक्ष ज्ञान सिद्धि बन जाता है। और इसी से सर्वदा ज्ञान देने वाला प्रभु\n(मोक्ष) संभव है.\n\nअज्जश्चश्रद्धधनश्च संशयात्मा विन्यशति |\nनायं लोकोषस्ति न परो न सुखं संशयात्मनः",
  "5.8": "प्रलापन विस्रुजन होम मिशन मिनट्स |\nइन्द्रियानिन्द्रियार्थेषु वर्तन इति धारयन्",
  "5.1": "अर्जुन उवाच-अर्जुन ने पूछा:\n\nसंन्यासं कर्मं कृष्णं पुनः योगं च संसारसि |\n\nयत् श्रेयः एतयोः एकम् तत् मेइ ब्रूहि सुनिश्चितम् - कृष्ण ने एक बार कर्मसंन्यास किया था।\nप्रशंसा; पुनः कर्म योग. मुझे यकीन है कि दोनों में से कौन बेहतर है\nकहो\n\nअर्जुन पूछता है: \"हे कृष्ण, आप एक बार युद्ध करें और फिर से कर्मन्यास करें।\nयदि कर्मसंन्यास का अर्थ कर्मत्याग है तो यह एक दूसरे के विपरीत हैं।  इसमें\nस्पष्ट कहो कि क्या श्रेयस्कर है।” लड़ते समय द्वंद्व होता है",
  "4.13": "चातुर्वर्ण्यम मया सृष्टम गुणकर्म विभाग।\n\nतस्य कर्तारम् अपि मम विद्धि अकर्तारम् अव्यम् -- त्रिगुण और कर्म का\nछाँटकर चार रंगों का एक समूह बनाया जाता है। मैं कभी नहीं बदला\nजान लें कि ऐसा करने से वास्तव में कुछ नहीं होगा। (मैंने उसे नहीं बदला\n(यह जान लो कि उसी ने बनाया, और मुझे किसी ने नहीं बनाया)\n\nकृष्ण कहते हैं: \"मैंने गुणकर्म के अनुसार चार वर्णों की रचना की\"। हमारे लिए\nजैसे चार वर्ण ज्ञात हैं- ब्राह्मण, क्षत्रिय, वैश्य और शूद्र। परमेश्वर के इस वचन को भूल जाओ\nव्याख्या करने वाले अधिक हैं। यदि ईश्वर ने स्वयं चार रंग बनाये तो यह जाति भारत छोड़ देगी\nऐसे लोग भी हैं जो सवाल करते हैं कि दूसरे देशों में ऐसी कोई चीज़ क्यों नहीं है. मूलत: कृष्ण ने यहां जो कहा है\nजाति के बारे में नहीं बल्कि चारों वर्णों के बारे में। वर्ण और जाति भी जटिल हैं\nप्रयोग संस्कृत में एक शब्द के कई अर्थ होते हैं। प्रति शब्द अनेक\nआयामी होना कभी-कभी हमें भ्रमित कर देता है। जाति के दो अर्थ होते हैं.\nमूल त्रिमूर्ति के लिए एक सहज गुण प्रकृति (जन्म के समय प्राप्त जीवन प्रकृति)।\nचिंतित) वह वर्ण है; दूसरी वह जाति है जिसके घर में (ब्राह्मण के घर में) जन्म हुआ है\nजो लड़का पैदा हुआ वह ब्राह्मण लड़का है, जो लड़का क्षत्रिय के घर पैदा हुआ वह क्षत्रिय लड़का है)। यह सूक्ष्म\nयदि हम नहीं जानते तो हम यहीं भ्रमित हो जायेंगे। तो इस श्लोक में वर्ण का अर्थ मूल जन्म है\nवर्ण का अर्थ है रंग. मनुष्य का रंग कैसा होता है? \"उसका रंग खुल गया।\"\nआमतौर पर हम कहते हैं. किसी का असली व्यक्तित्व सामने आ जायेगा\n\nखुलासा किया जाएगा. यहां रंग कहने का एक और कारण है. हमारी प्रकृति में रंग है [it\nरंग हमारी आँखों के लिए अदृश्य]।  सात्विक-श्वेत;  रजस-लाल; तमसा-काला. इस प्रकार रंग की प्रकृति\nयह भी दर्शाता है कि हमारी प्रकृति हमारे भीतर एक शक्ति है। हमारी भावनाओं के अनुसार\nहमारा शरीर रंगीन किरणें उत्सर्जित करता है [(जो सामान्य मानव आंखों को दिखाई नहीं देती हैं)।\nक्रोधित होने पर चेहरे पर लाल किरण; मन प्रसन्न हो तो हरी किरण; ज्ञान की गहराई को जानना\nऋषि के शरीर से एक नीली किरण. इस प्रकार रंग हमारे आंतरिक स्वभाव को दर्शाता है। यह\nइसका कारण भगवान नीलमेघश्याम हैं जो ज्ञानी हैं।\nउपरोक्त विवरण को जानने से हमें एक बात स्पष्ट रूप से समझ में आती है। जिस घर में जाति का जन्म हुआ\nऔर माता-पिता पर आश्रित होकर आ रहे हैं। रंग हमारी आंतरिक दुनिया है - हम स्वयं\nमूल प्रकृति. यह रंग दुनिया के हर कोने में पाया जा सकता है। भारत में शास्त्री\nइसे पहचानकर उन्होंने इसे ब्राह्मण, क्षत्रिय, वैश्य और शूद्र नाम दिया। जाति\nजन्म के आधार पर लेकिन वर्णों को गुणक्रम के आधार पर विभाजित किया जाता है। एक ब्राह्मण के घर पैदा हुआ लड़का\nब्राह्मण जाति का एक लड़का. परन्तु वह स्वभाव से क्षत्रिय हो सकता है; एक घर में चार\nवर्ण संतान भी पैदा हो सकती है. वेदव्यास, जिनका जन्म एक महान कन्या से हुआ था, एक महाब्राह्मण थे। ये है\nयह रंग पर निर्भर करता है. उन्हीं वेदव्यास के पुत्र, महान ज्ञानी-विदुर 'क्षतकेलसादव'\nबेटा). यह सामाजिक राजनीति से आता है! स्वभाव और कर्म के अनुसार प्रभु\nजन्म के साथ ही जीवन को एक रंग दिया जाता है।\nरंग के बिना समाज सुचारु रूप से नहीं चल सकता। पुरुषोक्त में ये चारों वर्ण अपने-अपने वर्ण के हैं\nकर्म के अनुसार शरीर को चार भागों में बांटा गया है:\n\nब्राह्मणोस्य मुखमासित् | बहु राजन्यः कृतः |\n\nउरू तदसया यद्वैश्यः | पद्भ्यगं शूद्रो अजायता॥\nउन्होंने उस पैर की, जो शरीर से पांच फुट का है और पूजा में महान है, शूद्र से तुलना की। ये है\nशरीर का आधार. शूद्र का अर्थ है दुःख में डूबा हुआ। उसमें कोई राजकुमारी नहीं है.\nलेकिन दूसरों की सेवा करने की सेवा गुणवत्ता महत्वपूर्ण है (567/06 063॥1॥)। जिसमें यह गुण नहीं है\nएक आदमी नहीं. कोई भी एकरंगी नहीं है. हर किसी में सारी प्रकृति होती है. कैसा स्वभाव है हमारा\n(133]010/)) हम उस वर्ण के हैं। शूद्र स्वभाव इतना महत्वपूर्ण है कि यह\nप्रकृति के बिना प्रकृति का कोई मूल्य नहीं है। हमेशा हम. कर्म सेवा कर रहे हैं\nइसे जुनून के साथ करना चाहिए. उदाहरणार्थ: जो समाज सेवा की भावना से ब्राह्मण बना\nज्ञान तो देना ही होगा. अन्यथा यह ज्ञान नहीं होगा.\nउन्होंने वैश्य की तुलना शरीर की कमर से की। क्योंकि उनका स्वभाव व्यापार और है\nवाणिज्य (1066001)।    आमतौर पर वैश्यों की जीवन पद्धति अतीत की तरह एक है\n\nवे एक शहर से दूसरे शहर घूमते थे और अपना व्यवसाय करते थे। तो उन्हें\nकमर की तुलना में.\n\nक्षत्रियों का स्वभाव अपनी भुजाओं के बल पर समाज की रक्षा करना और शासन करना है (19080401 318)\nओ0/7171507001) उनके विकास के कारण उनकी तुलना भुजा से की गई है।\n\nअब ब्राह्मण स्वभाव नहीं रहा; इनके द्वारा धर्म ज्ञान का मार्गदर्शन (॥/156018) हुआ। उसके लिए\nसिर की तुलना में. जो स्वभाव से ब्राह्मण है वह इंद्रियों को वश में करके सदैव ईश्वर का चिंतन करता रहता है।\nझूठ के बिना जियो, मुखौटे के बिना जियो, हमेशा आंतरिक पवित्रता प्रकट करो - ये मूल गुण हैं\nहोगा\n\nइस प्रकार इन चारों रंगों के मेल से ही एक आदर्श समाज का निर्माण हो सकता है। यहाँ\nश्रेष्ठता और हीनता की भावना अच्छी नहीं है। सभी मोक्ष के योग्य प्राणी हैं। यह एक आध्यात्मिक वर्गीकरण है\nऔर व्यवस्था. 'यह शाश्वत जीवन की मूल प्रकृति के अनुरूप है\nकृष्ण ने कहा, कर्म के अनुसार, मैंने इस धरती पर सृजन किया।\n\nएक बुनियादी बात जो हमें यहां जानने की जरूरत है वह यह है कि - जीवन भगवान सृष्टि पिल्ला द्वारा बनाया गया है।  जिंदगी\nऔर जीवन का स्वभाव शाश्वत है. जीवन की प्रकृति के अनुसार उसे शरीर, ऊर्जा, संसार की आवश्यकता होती है\nनिर्माण करो, इसे अस्तित्व दो। जीवन के विकास के लिए जीवन दो, बोओ\nईश्वर पालनकर्ता है. ऐसा भगवान ही सबका भगवान है। ऐसे प्रभु का कोई दूसरा रचयिता नहीं है।\nवह हर चीज़ का कारण है लेकिन उसके कारण कोई अन्य चीज़ नहीं है। \"अपरिवर्तनीय मैं\nकृष्ण ने अर्जुन से कहा कि मैंने ही इसका निर्माण किया है और मेरा निर्माण किसी ने नहीं किया है\nकहते हैं\n\nन मम कर्माणि लिम्पन्ति नाम कर्म फले स्त्रा |\nइति मम योइ9भिजानाति कर्मभिर्न स बध्यते",
  "5.6": "हे महाबाहो, कर्मयोग के बिना केवल संन्यास प्राप्त करना कठिन है। किन्तु कर्मयोगयुक्त मुनि — शीघ्र ही ब्रह्म को प्राप्त कर लेता है।\n\nकर्मयोग के बिना संन्यास — यानी मन में राग-द्वेष बनाए रखते हुए बाहरी कर्म छोड़ना — दुःखदायक है और सफल नहीं होता। कर्म करते हुए उसे भगवान् को समर्पित करना — द्वन्द्व-विजय का मार्ग है। ऐसा कर्मयोगी शीघ्र ही ब्रह्म तक पहुँचता है।",
  "5.10": "ब्रह्माणि अध्याय कर्माणि संगम त्यक्त्वा करोति यः।\nलिप्यते न सः पापेन पद्मपात्रम् इन अम्भास-कर्मों को भगवान को समर्पित कर दो और गाँठ हटा दो।\nएक कर्ता पाप से चिपकता नहीं है - बिल्कुल पानी के साथ सूरजमुखी की तरह।\n\nहम पूजा के अंत में \"श्री कृष्णार्पण मस्तु\" कहते हैं। इसका अर्थ है “उस प्रभु में।”\nसमर्पित\"। अर्पण करने का अर्थ है \"यह कर्म मेरे माध्यम से भगवान की पूजा के रूप में मेरा है\n\"उसने स्वयं इसे मोक्ष के लिए बनाया\" संकल्प। इस प्रकार जब हम कर्म करते हैं\nकर्म का दाग भी हमसे नहीं लगता। 'मैं, मेरा, मुझसे' का अहंकार\nचला जाता है यह एक सुखद आश्चर्य है। भले ही कमल का पत्ता पानी में हो\nजैसे पानी अपने आप में चिपकता नहीं, कर्म के साथ रहो, कर्म करो, कर्म करो।\nइस दृष्टिकोण से ही अनासक्ति संभव है।",
  "5.5": "यत् सांख्यैः प्राप्यते स्थानं तत् योगेः अपि गम्यते।\n\nएकम् सांख्यम् च योगम् च यः पश्यति सः पश्यति - प्रबुद्ध योगियों के निवास के लिए।\nकर्मयोगी भी चलते हैं। जो यह जानता है कि ज्ञान और कर्म के मार्ग का लक्ष्य एक ही है\nवह जो वास्तव में जानता है.\n\nबुद्धिमान आदमी। कर्म न केवल स्वयं के लिए बल्कि विश्व का मार्गदर्शन करने के लिए भी होता है\nकरना होगा. क्योंकि समाज उनका अनुसरण करता है। यह उनके लिए सामाजिक है\nउत्तरदायित्व अतः ज्ञान और कर्म एक दूसरे के पूरक हैं। यह ज्ञानी और कर्मज्ञ है\nपथ का लक्ष्य एक ही है. जान बूझकर कर्म करने का सुख, देवता, और\nकर्म प्रधान ज्ञान से कर्म करने वालों का लक्ष्य एक ही है - वह प्रभु। यहाँ\nयह कहना व्यर्थ है कि कर्मसंन्यास कर्मयोग से भिन्न है। ये दोनों एक दूसरे हैं\nपूरक वह जो इस सत्य को जानता है वह 'जानने वाला' है।\n\nसंन्यासस्तु महाबाहो दुखमप्रुमयोगतः |\nयोगयुक्तो मुनिर्ब्रहा त चिरेनाधिगच्छति",
  "4.31": "यज्ञ शीर्ष अमृता भुजः यान्ति ब्रह्म सनातनम् |\n\nन अयं लोक: अस्ति अयज्ञस्य कुतः अन्यः कुरुसत्तम् - यज्ञ में आहुति देने के बाद क्या बचता है\nजो लोग अमृत (यज्ञ फल का अमृत) पीते हैं वे शाश्वत भगवान को प्राप्त करते हैं। ओ\nकुरुश्रेष्ठ, जिसके पास कोई त्याग नहीं है उसके पास कोई संसार नहीं है। उस संसार का शब्द क्या है?\n\nयज्ञ में भगवान को आहुति देने के बाद जो बचता है उसे 'अमृत' कहा जाता है। यह हमें मृत्यु से परे बनाता है\nजीवन के हर क्षेत्र में इस प्रकार जीना क्रमिक है\nहम जाते हैं और उस प्रभु से जुड़ते हैं जो कभी नहीं बदलता, शाश्वत और शाश्वत है।\n\nयहां 'सनातन' की एक और ध्वनि है. प्राणायाम व्रत करने से ही मोक्ष होता है\nसनातन (नतन-नदाना) अर्थात ध्वनि नहीं मिल पा रही है। ब्रह्म सनातन का अर्थ है सर्वव्यापी,\nवैदिक भगवान. ऐसे भगवान को शास्त्र के माध्यम से जानने के यज्ञ से ही मुक्ति है\nसंभव है अन्यथा कोई फायदा नहीं. वेदों में वर्णित गुणों को जानकर पूजा करें\nकर्ता, वह जो वेद पढ़ता है और उससे जानता है, वह जो जानता है और दूसरों को बताता है, इत्यादि\nहासिल कर लेंगे. यज्ञ में ज्ञान, अनन्य भक्ति और समर्पण आवश्यक है।\n''जिसके जीवन में यह दृष्टिकोण नहीं है, जो जीवन में यज्ञ को नहीं अपनाता, वह यहां भी नहीं आता\nवह व्यर्थ में रहता है - समर्थक की कोई और बात नहीं है, ”कृष्ण कहते हैं।\n\nयहां कृष्ण अर्जुन को 'कुरुसत्तम' कहकर संबोधित करते हैं। आप कुरुवंश में सबसे महान हैं\nनिष्क्रिय हुए बिना सक्रिय रहें; उनका जन्म एक ऐसे परिवार में हुआ था जो स्वयं बलिदानों में शामिल था\nआप जो बुद्धिमान हैं, सात्विक हैं - 'युद्ध को यज्ञ बनाओ' यही वाणी है इस सम्बोधन में।\n\nएवम बहुविधा यज्ञं वितत् ब्राह्मणो मुखे।\nकर्मज़ान विधि तं सर्वनेवं ज्ञात्वा विमोक्ष्यसे ॥302॥\n\nएवम बहुविध यज्ञः वितः ब्राह्मणः मुखे\n\nकर्मज़ान विधि तं सर्वं एवं ज्ञात्वा विमोक्षणसे-इतने प्रकार के यज्ञ।\nप्रभु के मुख में फैले हुए हैं। जान लें कि ये सब कर्म के कारण हैं। इस प्रकार\nयदि तुम जानोगे तो तुम्हें रिहा कर दिया जाएगा।\n\nयज्ञ के अनेक पहलू हैं। जीवन में कोई भी कदम ईश्वरीय चेतना के साथ उठाया जाता है,\nजब जीवन की यात्रा ईश्वर की ओर चलना हो तो वह यज्ञ बन जाती है। कैसा बलिदान है\n\nयदि यह किया भी जाए, तो यह प्रभु के सामने आएगा... वही सभी चीजों का प्रबंधक है\nईश्वर एक है, विविधता केवल हमारे दृष्टिकोण और कर्म में है।\n\nहमें अपने कर्म के अनुसार यज्ञ करना है। कर्म त्याग कर प्रभु की आराधना करें\nअगर आप कहें कि ये कर देंगे तो ये संभव नहीं है. हम अपने कर्तव्य कर्म में भगवान हैं\nदेखना ही त्याग है. इस दृष्टिकोण से हम जो भी कर्म करेंगे वह हमें मुक्ति देगा\nपथ की ओर ले जाता है.\n\nअब तक कृष्ण कर्म-यज्ञ, उसका प्रकार, उसका स्वामी-इस विषय में विस्तार से बताया गया है\nहमने यह भी देखा कि यज्ञ में मूलतः बाह्य और आन्तरिक यज्ञ होता है।\nइन दोनों प्रकार के यज्ञों में से कौन सा अधिक महत्वपूर्ण है और क्यों - कृष्ण इस पर आगे चर्चा करेंगे\nवह श्लोक में बताते हैं.\n\nश्रेयान् द्रव्यमयद् यज्ञज ज्ञानयज्ञः परन्तप |\n\nसर्वं कर्म [5] कालम् पार्थ ज्ञाने परिसमाप्यते",
  "5.4": "सांख्य योग पृथक बलः प्रवदन्ति न पण्डितः।\n\nएकम अपि स्थितः सम्यक उभयोः विन्दते फलम् - ज्ञान और कर्म के विभिन्न मार्ग।\nजो लोग कहते हैं [एक भिक्षुओं को और दूसरा संसारियों को]1 वे बचकाने [मूर्ख] हैं;\nज्ञात नहीं है। जो किसी भी मार्ग पर सही ढंग से चला है वह दोनों का फल प्राप्त करेगा।\n\nजैसा कि पहले बताया गया है कर्मसंन्यास और कर्मयोग, कृष्ण यहाँ सांख्य का उपयोग करते हैं (ज्ञान-5/11ता9!\n\n156017) और योग का वर्णन करता है (अनुष्ठान-5/1108 730009)। शास्त्र में सांख्य (सम्यक)।\n\nप्रसिद्धि) गणित नहीं है; वह शुद्ध आत्मत्त्वविज्ञान है - ईश्वर का ज्ञान। ये पूरा अंक किसका है\nउसे पता है कि दुनिया कैसे चल रही है. जो लोग यह नहीं जानते वे कृष्ण बचकाने हैं और\nउनका कहना है कि उनकी बातों का कोई आधार नहीं है.  ऐसा कहकर कृष्ण कहते हैं\nयथा \"एकमप्यस्थितः सम्यगुभयोरविन्दते फलम्\"। इसका मतलब है “आप कोई भी हों\nयदि अच्छी तरह से अभ्यास किया जाए, तो इसका अर्थ है दोनों का फल प्राप्त करना।' यहाँ हम फिर से हैं\nयह भ्रमित करने वाला हो सकता है. इसका अर्थ है केवल ज्ञान या केवल कर्म का अभ्यास करना\nऐसा नहीं है कि जब हम कर्म अच्छे से करते हैं तो जान-बूझकर करते हैं। वही\nअच्छी तरह से सूचित होने का अर्थ है जो ज्ञात है उसे लागू करना। तो एक\n'ज्ञानप्रधान' एक और 'कर्मप्रधान' हो सकता है। लेकिन एक दूसरे का पूरक है। कौन\nजो इसे जानते हैं वे पंडित हैं और उन्हें सच्चा फल मिलता है।\n\nयत् नमः प्राप्यते स्थानं तद् योगैरपि गम्यते |\nएकं सांख्यं चयोगंचयः पश्यति स पश्यति",
  "5.11": "योगीजन — शरीर से, मन से, बुद्धि से और केवल इन्द्रियों से — आसक्ति त्यागकर — आत्मशुद्धि के लिए कर्म करते हैं।\n\n'केवलैः' — केवल — बिना 'मैं करता हूँ' के भाव के। 'आत्मशुद्धये' — आत्मशुद्धि के लिए। यही कर्मयोग का रहस्य — शरीर, मन, बुद्धि सब कर्म में लगे हैं, किन्तु 'मैंपन' नहीं। जैसे अग्नि लकड़ी जलाती है किन्तु राख नहीं पकड़ती — वैसे ही योगी कर्म करता है किन्तु उसका फल नहीं पकड़ता।",
  "5.7": "योगयुक्तः विशुद्ध आत्मा विजिता आत्मा जिता इन्द्रियः।\n\nसर्व भूत आत्मभूत आत्मा कुर्वन् अपि न लिष्यते - कर्मयोग में लीन, प्रबुद्ध\nएक प्रकार का, एक प्रकार का विजेता। वह जो इन्द्रियों पर भी विजय प्राप्त कर लेता है। वह भगवान है जो सभी जीवित प्राणियों का पालन-पोषण करता है\nवह जो जानता है कि वह राजा है। यदि ऐसा होता भी है, तो भी यह टिकेगा नहीं।\n\nजो व्यक्ति कर्मयोग में संलग्न होता है वह शुद्ध मन से शुद्ध कर्म का अभ्यास करता है\nयदि आप मन को जीतना चाहते हैं तो आपको भगवान की कृपा की आवश्यकता है। जो मन को जीत लेता है वह इंद्रियों को जीत लेता है\nजीतता है - जिससे आत्मा शुद्ध होती है। तब यहोवा जो सब वस्तुओं पर दया करता है वह मेरा है\nआत्मा का बोध हो गया है. सर्वशक्तिमान, सर्व-नियंत्रक भगवान भी मेरे भीतर हैं, वे हैं\nवह विश्व निर्देशक के रूप में दुनिया में भरे हुए हैं। संसार को नियंत्रित करने वाली अनंत शक्ति अदृश्य है\nइस अनुभूति के साथ कि मेरा जीवन रूप भी भर गया है, मैं सभी चीजों में वास कर रहा हूं\nजब हम भगवान में मन लगाकर कर्म करते हैं तो कर्म हमसे चिपकता नहीं है।\n\nकर्मसंन्यास और कर्मयोग को मिलाकर कर्मानुष्ठान जीवन में करना चाहिए\nकृष्ण ने बताया कि इस प्रकार के कर्म का हमारे दैनिक जीवन में क्या अर्थ है\n\nवह अगले श्लोक में स्पष्टीकरण देते हैं।\n\nनैव किंचित् करोमीति युक्तो मन्येत तत्तवित् |\n\nपस्यां शृण्वं स्पृशं जिप्रन्नश्चन गच्छन स्वपं श्वासन्",
  "4.35": "तत् विद्धि प्रणिपथेन परिप्रश्नेन सेवया |\n\nउपदेक्ष्यन्ति ते ज्ञानं ज्ञानिनः तत्त्वदर्शिनः ॥\n\nयत् ज्ञात्वा न रेमोहं एवं यस्यसि पांडव |\n\nयेन भूतानि अश्शेन द्रक्ष्यसि आत्मानि अथ उ मयि -- पांडव, जिसे जानकर\nक्या तुम फिर कभी इस तरह बहकाओगे नहीं; जिससे सभी प्राणी मोहित हो जाते हैं\nअन्तर्यामीयादा ([हर जगह] जो मुझमें देख सकता है, ऐसा ज्ञान वास्तविक और ज्ञात है\nवे आपको बताएंगे. पहुंचें, आसपास पूछें, सेवा में शामिल हों और इसे जानें।\n\nज्ञान प्राप्त करने के लिए, \"आपको बुद्धिमानों का अनुसरण करना चाहिए; सत्य का एहसास करना चाहिए\nकृष्ण कहते हैं दार्शनिकों से ज्ञान प्राप्त करो। किताबें पढ़ने से ही ज्ञान मिलता है\nनहीं आ रहा. यही हमारा एहसास होना चाहिए. \"7% 15 31 11100721 11050, ॥॥ 15 101\n17101180121\"। सत्य हमारा आदर्श होना चाहिए। सभी वैदिक मंत्र खुपियों के लिए हैं।\n(11861078! 0051051100) न्यूटन से गुरुत्वाकर्षण बल\nजैसा सोचा था. इस कारण हमें सबसे पहले सत्य के प्रति समर्पण करना होगा; सच देखा\nदार्शनिकों का समर्थन करना चाहिए.\n\nआमतौर पर जिन बुद्धिमानों को सत्य का एहसास हो गया है, वे ज्ञान के योग्य नहीं हैं\nपढ़ाना नहीं. इसी कारण से कृष्ण कहते हैं: \"यदि आप दार्शनिकों को देखें, तो उन्हें, उनकी पीठ को मत छोड़ें\nदस, उन्हें लुभाओ, उनके सामने अपने आप को योग्य साबित करो। आपका अनोखा\nइच्छा को उन्हें समझाने दो, उनके प्रति समर्पण करो।'' यहां 'प्रणिपात' यानी\nआठों अंगों को नमस्कार है। सिर, छाती, हाथ, पैर सभी भक्ति भाव से भूमि को स्पर्श करें।\nएक स्तोत्र (वचन) के माध्यम से मन में अत्यंत आदर भाव से किया गया प्रणाम - 'अष्टांग नमन'।\nऐसे समर्पण करो *केदकी केदकी, ध्यान से सुनो और जानो'' कृष्ण कहते हैं। 'दार्शनिक\n\nसेवा करो, उनसे ज्ञान प्राप्त करो, उनसे कर्म करो' कृष्ण अर्जुन के माध्यम से\nहमें जो सन्देश दिया.\n\nएक बार जब आप दार्शनिकों से ज्ञान प्राप्त कर लेते हैं, तो मोह के लिए कोई जगह नहीं रहती। यहाँ अर्जुन है\nजो सता रहा है वह ज्ञान पर पड़ा हुआ मोह का पर्दा है। कृष्ण ने इसके लिए अर्जुन को 'पांडव' कहा\nपते यहां 'पांडा' का अर्थ है ज्ञान (जैसे: पांडा उल्लव पंडिता), पांडव का अर्थ है\nजिसने ज्ञान प्राप्त कर लिया हो। अब पाण्डु का अर्थ है 'सफेद रंग'। यही सात्त्विकता का लक्षण है। 'आप स्वयं हैं\nयहां यह संबोधन 'ज्ञानी और सात्विक' को दर्शाता है।\n\nएक बार सत्य का बोध हो जाए तो मोह का जाल दूर हो जाता है। यह वापस आएगा\nसंभावना नहीं है. इस अवस्था में सभी जीव हर चीज़ के लिए आत्मा (भगवान) पर निर्भर होते हैं\nयह चेतना जागृत होती है कि नियमशक्ति ही भगवान है। यह सब भ्रम\nभुला दिया जाएगा. स्वार्थ, दुःख, संशय सब दूर हो जाते हैं और समता उत्पन्न होती है। प्रभु\nअणु के भीतर अणु, सबके भीतर छवि और वह महानता से परिपूर्ण है\nमहान सर्वव्यापकता. सत्य को जानो कि सब कुछ उसकी इच्छा से होता है।\nजिसने स्वयं को भगवान में समर्पित कर दिया है उसे जीवन में कोई भय नहीं है।\n\nकहा जाता है कि कर्म ज्ञान से करना चाहिए, ज्ञानी से ज्ञान प्राप्त करना चाहिए तभी मोक्ष संभव है\nबात समझ में आ गई. लेकिन जिन पापियों ने यह जानने से पहले कई पाप कर्म किए हैं\nगति क्या है? कृष्ण कहते हैं कि इससे डरने की जरूरत नहीं है। इस विषय में कृष्ण की प्रतिज्ञा |\nआइए अगले श्लोक में देखें.",
  "4.33": "श्रेयन् द्रव्य मयात् यज्ञात ज्ञानयज्ञः परन्तप |\n\nसर्वं कर्म ए[ए]खिलं पार्थ ज्ञाने परिसमाप्यते- हे परंतप, संपत्ति\nज्ञान यज्ञ होमिम के बाह्य यज्ञ से श्रेष्ठ है। हे पार्थ, संगावदा [तिलविनेदुरू थिरा\nलघु] सभी कर्म ज्ञान में पूर्ण होते हैं।\n\nवास्तव में पूर्णतया बाह्य त्याग और निरा आन्तरिक त्याग जैसी कोई चीज़ नहीं होती। हम हैं\nकरने के कार्य के पीछे जागरूकता है। आन्तरिक यज्ञ के साथ-साथ एक अनुष्ठान भी है। इन दोनों में से\nअन्तरंग यज्ञ का अधिक महत्व है। क्योंकि हम मानसिक रूप से ध्यान, बाहरी क्रिया कर रहे हैं\nइसके बिना मन में एक विशेष शक्ति का निर्माण होता है। लेकिन जागरूकता के बिना किया गया कर्म व्यर्थ है!\nइस कारण कर्म के पीछे जागरूकता बहुत जरूरी है। इसलिए हमें जानबूझ कर कर्म करना होगा।\nकेवल भौतिक, यदि इसके पीछे कोई ज्ञान नहीं है, यदि यह ज्ञात नहीं है, तो इसका कोई अर्थ नहीं है। कौन\nकर्म तभी प्रभावी होता है जब वह ज्ञात हो। इस कारण से, एक बुद्धिमान बलिदान\nमहत्वपूर्ण है. इस श्लोक में कृष्ण अर्जुन को परंतप कहकर संबोधित करते हैं। यहाँ यह है\nइस सम्बोधन का एक विशेष अर्थ होता है। इस शब्द की व्याख्या दो तरह से की जा सकती है। मोटे तौर पर\nपरंतप का अर्थ है 'शत्रुओं को परास्त करने वाला नायक'। यहां अर्जुन द्वारा किया गया यज्ञ है\nशत्रु दमन उस यज्ञ के पीछे ज्ञान का सहयोग है। तो यह ज्ञानयज्ञ बन जाता है-\nकोई रसायनज्ञ नहीं. क्योंकि अर्जुन परंतप है - 'वह जो सदैव परमेश्वर की चिंता करता है'। यहाँ 'वह मेरा है\n\n'दुश्मनों को दबाना है और सत्ता हासिल करनी है' वाली अप्रोच नहीं है. ये है\nयज्ञ ईश्वर की आराधना का एक रूप है।  अन्याय के खिलाफ लड़ना अर्जुन का कर्तव्य है,\nखुशियाँ उस प्रभु पर निर्भर हैं। ऐसा तब होता है जब युद्ध इसी दृष्टिकोण से लड़ा जाता है\nज्ञान बन जाता है. यह विशेषण परंतप यहाँ कर्म को ज्ञान के रूप में वर्णित करता है\nयह इंगित करता है कि इसे परिवर्तित किया जा सकता है।\n\nयह समझाते हुए कि यह बुद्धिमानी क्यों है, कृष्ण कहते हैं: \"सर्वं कर्म अ[अ1खिलम्।\nपार्थ ज्ञाने परिसमाप्यत्। यहाँ 'सर्वम्' और 'अखिलम्' शब्दों की पुनरावृत्ति होती है\nलेकिन इसके पीछे एक खास मतलब है. एक मंत्र में कितने अक्षर, कितने\nसंचार का प्रकार महत्वपूर्ण है. यहाँ \"सर्वं कर्म[$]खिलम्\" दो हैं\nप्रकार के आधार पर पदावनत किया जा सकता है। एक- “सर्व कर्म अखिलम्” और दूसरा “सर्व कर्म।”\n'अकिलम'। सभी उपादानों से सिद्ध सर्व कर्म को 'सर्व कर्म अखिलम' कहा जाता है।\nइसका मतलब है कि सभी कर्म उत्तम हैं। कृष्ण कहते हैं, एक कर्म पूरा करो।\nकोई भी कर्म तभी पूर्ण होता है जब वह जान-बूझकर किया जाए। कर्म के साथ-साथ\nज्ञान चाहिए. यही ज्ञान की उत्कृष्टता है। कर्म ज्ञान से करो; कर्म करो और ज्ञान प्राप्त करो। तब\nयह एकदम सही है। भागवत में ज्ञान के बिना यज्ञ का घोर विरोध किया गया है। वहाँ\nजो व्यक्ति बिना यह जाने होम करता है कि वह होम में अग्नि को आहुति क्यों दे रहा है\nवह पागल है और धुआँ खाकर मर जाता है।' कर्म के पीछे ईश्वर चेतना\nबहुत ज़रूरी। अन्यथा यह उलटी हुई नाव की तरह है। इसके पीछे किया गया कर्म सफल होता है\nकेवल तभी जब जागरूकता हो.\n\nदूसरा अर्थ है 'आ-खिलम' जो कि अविद्या कर्म है। यहां 'खिलम' का मतलब टुकड़ा है। बिना ज्ञान के\nयदि सभी कर्मों को एक साथ जोड़ दिया जाए, तो भी यह ज्ञान के सामने एक छोटा सा कण है। सब बिना ज्ञान के\nकर्म. यदि जुड़ भी जाए तो कर्म ज्ञान के सामने नगण्य है।     हमारा कर्म\nकर्म ज्ञान के लिये करना चाहिये न कि कर्म के लिये। लेकिन आजकल\nदुःख की बात है कि ज्ञान के लिए कर्म करने वालों की संख्या कम होती जा रही है।\n\nयहाँ कृष्ण अर्जुन को \"पार्थ\" कहकर संबोधित करते हैं। जैसा कि पहले बताया गया है, पार्थ का अर्थ है\nजिसने पलायन देखा है, जिसने ज्ञान के सागर के पार किनारा देखा है; वेदार्थ का सेवन करें\nजिसने किया \"हे महान ऋषि, यह कर्म जिसे आप महसूस करते हैं वह सिर्फ कर्म नहीं है\nज्ञानयज्ञ की वाणी इस संबोधन में है। यहां कुछ ऐसा है जिसे हमें फिर से याद करने की जरूरत है\nइसका मूल अर्थ यह है कि अर्जुन एक महान ऋषि हैं। लेकिन कभी-कभी महान संत भी\nसब कुछ भ्रमित और भुला दिया गया है। अर्जुन यहाँ उसी अवस्था में है। यह केवल अस्थायी है\nस्क्रीन, कृष्ण उस स्क्रीन को हिला रहे हैं।\n\nयह स्पष्ट हो गया कि ज्ञान के बिना कर्म व्यर्थ है। लेकिन ये\nज्ञान प्राप्त करने का उद्देश्य क्या है? कृष्ण इस प्रश्न का उत्तर अगले श्लोक में देते हैं।\n\nतद् विद्धि प्रणिपथेन परिप्रश्नेन सेवया |\nउपदेसाक्ष्यन्ति ते ज्ञानं ज्ञानिनसत्त्वदर्शिनः 134।",
  "5.3": "जो न घृणा करता है न कामना करता है — उसे नित्यसंन्यासी जानो। हे महाबाहो, द्वन्द्वरहित ऐसा व्यक्ति सुखपूर्वक कर्मबन्धन से मुक्त होता है।\n\nअर्जुन के संन्यास-बनाम-कर्म के प्रश्न का कृष्ण का उत्तर — वास्तविक संन्यास कर्म छोड़ना नहीं, राग-द्वेष छोड़ना है। जो संसार में रहते हुए भी द्वेष नहीं करता और कामना नहीं करता — वही सच्चा संन्यासी। यही गीता का क्रान्तिकारी सन्देश।",
  "4.24": "ब्रह्मा अर्पणं ब्रह्मा हविः ब्रह्मा अग्नौ ब्राह्मण हुतम्।\n\nब्रह्म एव तेन गन्तव्यं ब्रह्म कर्म समाधान-अर्पणवु भगवन्त (भगवान् में अर्पण)।\nभक्तिपूर्ण हविसु भगवंत [हविसु जो भगवान हैं]। प्रभु में जो अग्नि स्वरूप है\n[प्रभु की वशीभूत अग्नि में] स्वयं भगवान द्वारा जलाया गया। विभिन्न सांद्रता के साथ\nकर्म का विग्रह भी भगवान है [भगवान के अधीन]\n\nअभिमान यज्ञ के साथ ज्ञान की स्थिति में कर्म करना कैसा होता है इसका उत्तर\n\"ब्रह्मार्पणं ब्रह्मविः\"। यहां अर्पणा को इस प्रकार समझा जा सकता है। हम हैं\nहम भगवान को अग्नि में हविसा अर्पित करते हैं - यह एक भेंट है। एक भूखे आदमी के लिए भोजन\nदो—यह एक भेंट है। हम एक योग्य वर को कन्यादान करते हैं - यह एक भेंट है। एक है पैसा\nजब वह संकट में होता है तो हम उसकी सहायता करते हैं—यह एक भेंट है। यहाँ देने वाला भगवान है,\nलेने वाले के भीतर ही लेने वाला है। सब कुछ भगवान की इच्छा के अनुसार होता है.\nइच्छा का अर्थ है कुछ देना। अर्पण करने की क्रिया। किसी भी वस्तु की इच्छा की जा सकती है। दान का\nद्रव्य-हविस्सु, द्रव्य-हविस्सु को यज्ञ में अग्नि के समक्ष अर्पित किया जाता है। जब हम पैदा होते हैं तो कुछ भी नहीं\nहम लेते नहीं, सब कुछ इसी प्रकृति से मिलता है, हम देते हैं\nइच्छा भी उस प्रभु के अधीन है। यहां 'मेरा' हास्यास्पद है.\n\nअग्नि के द्वारा हम पदार्थ को अर्पित करते हैं। यहां अग्नि का अर्थ मात्र जड़ अग्नि नहीं है।\nसंस्कृत में अग्नि का अर्थ अग्नि का प्रशंसक देवता है, जो चेतना है। इसी कारण अग्नि\nगवाह के रूप में उपयोग किया जाता है (जैसे: गवाह के रूप में शादी करना)। कभी भी आलस्य का साक्षी न बनें\nउपयोग करने में असमर्थ. इस अग्निदेवता के भीतर वह भगवान तारक शक्ति के रूप में है। यहाँ\nदेना, क्या देना है, देने का कार्य, देने का स्थान - सब कुछ भगवान के अधीन है। सभी कार्रवाई में\nवहां ईश्वर की उपस्थिति है. कोडाटक्का सामग्री में। यह उसकी उपस्थिति के कारण है\nउपयोगी हो जाएगा। जो भगवान ज्ञानस्वरूप हैं, वे अग्नि और भक्तिरूपी आहुति में विद्यमान हैं\nस्वीकार करता है यदि हम भगवान की पूजा करते समय इस दृष्टिकोण के साथ कार्य करते हैं\n\"ब्रह्मैव तेन गंथव्यम्\" - जाओ और भगवान से जुड़ जाओ। क्योंकि \"ब्रह्मकर्मसमाधिना\" -\nसब कुछ सर्वशक्तिमान प्रभु के अधीन है।\n\nयहां ब्रह्मर्पण का अर्थ है भगवान के लिए सभी कार्य। दुनिया की सभी चीजें\nउस प्रभु ने बनाया। हम केवल वही उपयोग करते हैं जो प्रकृति में निर्मित है। अग्नि\nवह प्रभु के अधीन कार्य करता है। 'हम जो करते हैं वह उस प्रभु की प्रेरणा है। हम हैं\nकिया गया सभी कर्म ब्रह्मकर्म है। वह कर्म ही ईश्वर की पूजा है' - यह कर्म के बारे में है\nजो ज्ञान हमारे पास होना चाहिए. हम जो कर्म करें उसमें कोई स्वार्थ नहीं होना चाहिए। वही भगवान की पूजा है\nबनना चाहिए. यज्ञ केवल अग्नि की क्रिया नहीं है। हमारे जीवन\n\nजब हम भगवान बन जाते हैं, तो जीवन में हमारे सभी कार्य बलिदान बन जाते हैं। हमारा जीवन\nहमारा जीवन एक महान बलिदान है जब यह ईश्वर के चिंतन में समर्पित होता है। भगवान के बारे में सोचे बिना\nस्वार्थवश किया गया अग्निहोत्र तो व्यापार मात्र है। पौरोहित्य भी ऐसा ही है। जानने\nतभी यह वास्तविक पुरोहितवाद है, अन्यथा यह महज़ एक घोटाला है!\n\nअब तक कृष्ण ने कर्मों के प्रकार बताये हैं। सब कुछ भगवान की पूजा के रूप में किया जाता है\nकार्य ने यज्ञ के विचार का भी विश्लेषण किया। आगे यज्ञ का व्यापक अर्थ है\nकृष्ण बताते हैं. जैसा कि पहले बताया जा चुका है, अग्नि में की गई पूजा ही एकमात्र यज्ञ नहीं है। देना,\nएक ओर हमारे बीच पूजा-पाठ, ज्ञान दान, अन्न दान जैसे अच्छे कार्यों में शामिल हो रहे हैं\nआपके पास जो कुछ है उसे उन लोगों के साथ बांटकर जीना जिनके पास नहीं है, सब कुछ त्याग है। . निम्नलिखित श्लोक में\nकृष्ण हमें यज्ञ का एक सार्वभौमिक चित्र देते हैं।\n\nसामान्यतः यज्ञ दो प्रकार के होते हैं। एक आंतरिक त्याग और दूसरा बाह्य त्याग। इंटीरियर में\nभगवान की निरंतर पूजा (देवपूजा); . चित्त-मन...ईश्वर के साथ\nजुड़ना (एकजुट होना) और स्वयं को प्रभु को अर्पित करना-यह\nएक उत्तम मानसिक बलिदान. दूसरे प्रकार से यज्ञ दो प्रकार के होते हैं ज्ञानमय यज्ञ\nऔर अनुष्ठान बलिदान. इन सभी व्याख्याओं को कृष्ण ने निम्नलिखित श्लोकों में समझाया है।\n\nदैवमेवपरे यज्ञं योगिनः पर्युपासते\n125.\n\nदैवं एव अपरे यज्ञं योगिनः पर्युपासते |\n\nब्रह्मा अग्नौ अपरे यज्ञं यज्ञेन एव उपजुह्वति- कुछ अभ्यासकर्ता इसे भगवदुपासा कहते हैं।\nमानस यज्ञ किया जाता है।\nस्वरूप भगवान की पूजा करके यज्ञ नमक भगवान की बाह्य आहुतियों से आहुति दी जाती है\nपूजा करता है.\n\nकुछ योगी (साधक) जो भगवान की आराधना के मार्ग पर चलते हैं, भगवान को बलि चढ़ाते हैं।\nपूजा करता है. अर्थात उनका यज्ञ भगवान की निरंतर पूजा है।\nइसके लिए किसी बाहरी सहायक उपकरण की आवश्यकता नहीं है। यह यज्ञ का एक ध्यानात्मक रूप है। यह बाहरी उपकरणों के बिना किया जाता है\nयज्ञ सबसे बड़ा यज्ञ है। यह एक ऐसा यज्ञ है जिसे आमतौर पर सबसे उन्नत अभ्यासकर्ताओं द्वारा किया जा सकता है।\nयह समस्त बाह्य उपादानों को त्यागकर मन से किया जाने वाला परम ज्ञानमय यज्ञ है।\n\nयज्ञ का दूसरा प्रकार अग्नि के समक्ष किया जाने वाला कार्मिक यज्ञ है। यह सामान्य है\nमनुष्य अनुसरण करते हैं। जहां भगवान मौजूद हों वहां अग्नि के मुख में भगवान को अर्पण करना\nकरने की उपासना बाह्य यज्ञ है। ये बहुत महत्वपूर्ण है. वेदों में भगवान की पूजा के लिए\nसबसे महत्वपूर्ण प्रतीक अग्नि को कहा जाता है। अग्नि कभी अशुद्ध नहीं होती. अग्नि के स्पर्श से अपवित्र\nभी पवित्र हो जाता है. अगर हमारे मन में भगवान को कुछ खिलाने की इच्छा है\nयह केवल अग्नि द्वारा ही किया जा सकता है। हमारी आंखों के सामने आने वाले सभी प्रतीकों में अग्नि भी है\nसबसे महान वैदिक काल की खुशियों का निष्कर्ष है। अग्निदेव जलती हुई आग में, उसके भीतर\nप्राण, प्राण के भीतर भगवान। इस अनुसन्धान यज्ञ में भगवान का नाम लिया गया है, यज्ञ से ज्ञान\nभक्ति वैराग्य के साथ उत्कृष्ट आह्वान के साथ आराधना।\n\nश्रोत्रादीनेन्द्रिय्ये संयमग्निषु जुह्वति।\n\n0\n\nशबदीन सिघान्या इन्द्रियाग्निशु जुह्वति",
  "5.12": "युक्तः कर्मफलं त्यक्त्वा शांतिं आप्नोति नैष्ठिकीम |\n\nअयुक्तः काम करना फले सकाः निबद्द्या ते-योग, जो कर्म फल के लगाव को जानता है और शुद्ध हो जाता है।\nउसे शांति प्राप्त होती है... एक गैर-योगी फल से थक जाता है, उसकी लालसा करता है\nउसे गिरफ्तार कर लिया जायेगा.\n\nजो स्वयं को कर्मयोग के लिए समर्पित करता है, भगवद चेतना में कर्म करता है-ज्ञानानंद\nउसे परम मोक्ष की प्राप्ति होती है। यदि हम किसी फल की इच्छा से कर्म करते हैं\nइसका मतलब यह नहीं है कि इसका कोई परिणाम नहीं निकलेगा. लेकिन हम जानते हैं कि वह फल हमारे लिए कितना उपयोगी है\nहमारे पास नहीं है और यह पूर्ण फल नहीं है. कर्म बिना परिणाम के किया जाता है\nहमें वह सब कुछ मिलता है जिसकी हमें आवश्यकता होती है। हम कर्म की इच्छा के बिना कर्म में हैं\nयदि संलग्न हैं, तो शुद्ध आंतरिक चेतना के साथ कर्म करते रहें और उससे ज्ञान प्राप्त करें\nभगवान की कृपा का भागी बनकर मोक्ष प्राप्त किया जा सकता है।\n\nकर्म योग के बिना 'मैं अपने लिए काम कर रहा हूं, यह मेरी संपत्ति है, मैंने जिसके लिए काम किया है वह मेरा है।\nसुख के लिए खर्च करेंगे, कोई भगवान हमारी मदद नहीं करेगा आदि आत्मा\nजब हम एकाग्र भाव से कर्म करते हैं तो कर्म हमें बांधते हैं। एक मूक जानवर\nऐसे भी नहीं रहता. उदाहरण के लिए, एक कौआ: यदि वह कोई खाद्य पदार्थ देखता है, तो वह उसे खा लेता है\nएक समूह को बुलाया जाता है और साझा किया जाता है और खाया जाता है। यहाँ तक कि एक समय बाघ और शेर जैसे क्रूर जानवर भी\nजब उनका पेट भरा होता है तो वे कभी भी स्वार्थी कार्य नहीं करते। लेकिन इंसान\nहम स्वार्थी होकर जीते हैं। हमें और कितना मिलेगा! वह जो इस तरह रहता है\nसंसार के चक्र में फंस जाता है और अपमानित हो जाता है।\n\nसर्वकर्माणि मनसा संन्यासस्य *स्टे सुखं वाशी।\n\nनवद्वारे शुद्ध देहि नैव कुर्वन् कारायण",
  "5.19": "एह एव तैह जितः सर्गः यशं समये स्थितम् मनः।\n\nनिर्दोषं हि समं ब्रह्म तस्मात् ब्राह्मणी ते स्थितः - ईश्वर अपने एक रूप में।\nजिन्होंने इसे लगाया, उन्होंने ही यह जीवन जीता है। ईश्वर सर्वत्र निराकार एवं एकरूप है। इसलिए\nजो लोग इसे जानते हैं वे भगवान में स्थापित हो जाते हैं।\n\nसर्वव्यापी भगवान सभी चीजों में व्याप्त है। बुलाया\nजब हमारा मन अनुशासन में लग जाता है तो जन्म और मृत्यु से परे मोक्ष का द्वार हमारे लिए खुल जाता है।\nभगवान जिस भी पदार्थ में हों, उनमें कोई दोष नहीं है, वे सर्वत्र दोषरहित हैं। कौन\nअधिष्ठान में होते हुए भी वह निर्लिप्त है। यह वहां भरा हुआ है. यह जानने वालों का मन\n\nप्रभु में विश्राम करो. इसलिए उन्हें शाश्वत मोक्ष के लिए दोबारा गिरफ्तार नहीं किया जाता है\nमिलेगा\n\nपिछले श्लोक में, कृष्ण ने भगवान के स्वरूप के आध्यात्मिक दर्शन के बारे में बताया। अगला\nइसके अलावा श्लोक में बताया गया है कि हमें अपने सामाजिक जीवन में समभाव कैसे लाना चाहिए\nवह यह समझाते हैं\n\nप्रहृष्येत् प्रियं प्राप्य नोड्विजेत् प्राप्य चाप्रियम् |\n\nस्थिरबुद्धिरसमुहो ब्रह्मविद ब्राह्मणी स्थितः",
  "5.22": "ये हि समस्पर्श जह भोगः दुख योनय; यह क्या है?\nआदि अन्त वन्तः कौन्तेय न तेषु रमते बुद्ध - विषय वस्तु से मिलने वाले सुख।\nगृहनगर जो आते हैं और पलक झपकते ही बह जाते हैं। कौन्तेय, जो जानते हैं वे इसकी सराहना नहीं करते।\n\nबाहरी स्पर्श से मिलने वाले परमानंद (संपर्क) के अनुभव से हमें कितना आनंद मिलता है?\nहमें लौकी के सुख के लिए कद्दू के दुःख सहने पड़ रहे हैं\nहम तैयार रहेंगे. आज समस्त सांसारिक अपराधों का यही कारण है। क्षणिक सुख की चाह में गिरना\nरोजमर्रा की जिंदगी में हमें ऐसे लोग मिल जाते हैं जो पूरी जिंदगी खराब कर देते हैं।\nइस तथ्य को जाने बिना कि जो हमें बाहर से खुशी के रूप में दिखाई देता है, वही अंडा है जो दुःख को जन्म देता है।\nहम उसे खुशी के रूप में वापस ले लेते हैं। हर बाहरी ख़ुशी के पीछे दुःख का अंधकार छिपा होता है\nकठोर है. बाह्य सुख-सुख तो क्षण मात्र है। जब तक यह आया\nनालियाँ. बुद्धिमान व्यक्ति इन बाह्य सुखों की चाह में नहीं रहता।\n\nकुछ लोग आध्यात्मिकता के बारे में कहते हैं: \"हमें अब आध्यात्मिकता की आवश्यकता क्यों है; यह सब साठ के दशक की शांति है।\"\nऊपर\"। कृष्ण अगले श्लोक में बताते हैं कि यह गलत क्यों है।",
  "5.27": "यतेन्द्रियमानोवृत्तिर्मुनिर्मोक्षपरायणः |\nविगतेच्छभयक्रोधो यः सदा मुक्त एव सः",
  "5.13": "सर्व कर्माणि मनसा संन्यासस्य अस्ते सुखं वासी।\n\nनव द्वारे शुद्ध देहि न एव कुर्वन न कारायण - मानसिक रूप से सभी कर्म बंधनों का त्याग करना।\nजो इंद्रियों पर विजय प्राप्त कर लेता है वह आरामदायक महसूस करता है - इस नौ दरवाजों वाले पुर में; कुछ नहीं कर रहा, कुछ नहीं\nबिना किये\n\nकृष्ण कहते हैं कि सभी कर्मों का मानसिक रूप से संन्यास लो। यह बहुत ही महत्वपूर्ण शब्द है.\nकृष्ण यहां 'कर्म त्याग' नहीं कह रहे हैं, वे सिर्फ मन में कर्म त्यागने को कह रहे हैं। वह है\nकर्मों के विषय में मन में फलदा संगा; मानसिक स्वतंत्रता के भ्रम को दूर करें।\nमानसिक रूप से 'मैं', 'सनागोस्कार' के विचार को त्याग दें। 'जीवन भर किसी भी समय\nकिसी भी कर्तव्य में कोई स्वतंत्रता नहीं है. माधवाचार्य ने अपने सभी ग्रंथों में इसे दोहराया है\nकहा. इसे मानसिक रूप से अपनाना ही वास्तविक कर्मसंन्यास है।\n\nप्रभु हमें इस नौ दरवाजे वाले महल (सिद्ध मानव शरीर) के भीतर बिठाएं।\nवह हमसे कर्म कर रहा है। 'मुझे इस शहर में रखो, मेरे साथ मेरे सबसे अच्छे दोस्त बनो\nवह प्रभु खड़ा होकर मेरी मुक्ति के लिए कर्म कर रहा है, यही कर्म योग है।\nहमने कृष्ण द्वारा कर्म योग के बारे में समझाए गए अद्वितीय ज्ञान योग को देखा। इस प्रकार कर्म\nऐसा करने से यह भगवान की पूजा और ज्ञान के मार्ग का हिस्सा बन जाता है।\nजब ज्ञान के साथ कर्म किया जाता है तो कोई भी क्षुद्र कार्य व्यर्थ नहीं जाता, वह योग बन जाता है।\nयहां कृष्ण कहते हैं, 'बिना कुछ किए, बिना कुछ किए।' आमतौर पर हमारे पास नौकरी होती है\nयदि किया गया, तो 'मैंने यह किया', 'मैंने कहा कि यह हुआ' सभी जगह\nहम आपको बताएंगे. हम चाहते हैं कि चार लोग ऐसा कहें। लेकिन बुद्धिमान ऐसे ही होते हैं\nयह नहीं कहता कि 'भगवान् ने मेरे हाथों में कुछ किया है', 'भगवान् ने वही किया है जो मुझमें है',\nवे 'भगवान ने उन्हें प्रेरित किया' इत्यादि के बारे में बात करते हैं। इसका कारण बुद्धिमान पुरुष हैं\n'मैं एक स्वतंत्र रचनाकार हूँ' की चेतना विकसित नहीं हो पाई है। यह ज्ञानी और अज्ञानी का है\nअंतर कर्म के दृष्टिकोण में है।\n\nये सब जानने के बाद हमारे सामने एक सवाल है. सब कुछ भगवान है\nयदि उसे हमारे हाथ में अच्छा काम करना है तो वह बुरा काम क्यों करता है?\nवह बुरे कर्मों का कर्ता है लेकिन हमें इसकी सज़ा क्यों मिले? हम दुखी क्यों हैं? मैं चाहता हूं\nजब यह जानबूझकर किया जाता है तो मैं इसका निर्माता क्यों नहीं हूं? यह मेरे लिए काम क्यों नहीं कर रहा है? सब\nयदि ईश्वर ऐसा करेगा तो मुझे परिणाम कैसे मिलेंगे? आदि प्रश्न. यह हर किसी को परेशान करता है\nप्रश्न ये परेशान करने वाले प्रश्न हैं, लेकिन ये सही प्रश्न नहीं हैं। यह तब होता है जब विज्ञान का सार ज्ञात नहीं होता है\nप्रश्न आएंगे. निम्नलिखित श्लोकों का गहन विश्लेषण हमारे प्रश्न का उत्तर देगा\nमिलेगा\n\nन कर्तृत्वं न कर्माणि लोकस्य सृजति प्रभु।\n\nकर्मफलसंयोगम् प्रकृति में अग्रणी है",
  "5.16": "600381 8000800) अलग, हम जो करते हैं वह अलग है। इस कारण से\nकुछ लोग बाहर से कुछ कहते हैं और अंदर से उसके विपरीत करते हैं।\nयहां तक ​​कि दुर्योधन ने भी कहा, \"मैं जानता हूं कि मैं जो कर रहा हूं वह गलत है\"।\nयहां हमें जो कहा गया है उस पर ध्यान देना होगा. वह जानता था कि धर्म क्या है। हालाँकि वह है\nअपने स्वभाव के अनुसार धारण किया। तो हमारी समझ अलग है, हमारा कर्म अलग है। हमारा स्वभाव हम सबका है\nअध्ययन, बुद्धि, बुद्धिवाद को एक तरफ रख दें और हमें प्रकृति के अनुसार कार्य करने को कहें\nपत्ते यही बात कृष्ण यहाँ \"प्रकृति के प्रणेता\" के रूप में कह रहे हैं। आपका स्वभाव कैसा है-\nआपकी प्रवृत्ति ही ऐसी है. भगवान तुम्हें उसी के अनुसार बड़ा करेंगे। कौन सा किसका\nयदि कोई प्रकृति है, तो उन्हें एक जैसा होना चाहिए, दूसरे जैसा नहीं। अगर आम का फल खट्टा हो जाए\nयह एक ख़राब फल है, इमली का फल जितना खट्टा होगा उतना ही अच्छा है। इसलिए तमस\nतमस के समान होना उनका स्वाभाविक धर्म है। जिसका जैसा स्वाभाविक स्वभाव होता है, वैसा ही स्वाभाविक होता है\nप्रकृति में साधना का कार्य मुक्त भगवान द्वारा किया गया था। हर चीज़ का फल\nवह दाता है. उसे कभी गिरफ्तार नहीं किया गया.\n\nइस प्रकार यह श्लोक हमारे सभी संदेहों का उत्तर है। हमारा संदेह गहरा है. मन को\nजो संदेह आता है उसे दूर किया जा सकता है लेकिन जो संदेह मन में आता है (17891901031 60000\nकाबू पाना मुश्किल. मनोविज्ञान के प्राचीन लेखकों के अनुसार इसे 'स्थिरसासंशय' कहा गया है।\nहमारे भौतिक संसार में 'मैं अन्य सभी से अधिक चतुर हूँ' कहा जाता है\nआपको अवगत कराता है. इस कारण हम अपने मन को सत्य की ओर अभ्यस्त नहीं कर पाते\nयह हमें विश्वास नहीं देता. हम जो कुछ भी करते हैं, हम उसे जानते हैं और उस पर विश्वास करते हैं\n\nकरना चाहिए उसके लिए हर कदम पर शास्त्रीय भावना का महत्व है।  मेरा मतलब है, प्रकृति\nअर्थात् वह कौन सी शक्ति है जो मेरे स्वभाव को संचालित करती है, जो हाथ पकड़ती है और फल है\nजब आप जानते हैं कि देने वाला कौन है, आदि, तो अहंकार के लिए कोई जगह नहीं है।\n\nयहां हमारा एक प्रश्न है. भगवान हमें सज़ा क्यों देते हैं? भगवान हमें सज़ा देते हैं\nदेना घृणा से नहीं है, बल्कि उसके पीछे अपार-अनंत करुणा है। माँ बच्चे को सज़ा देती है\nदेने के पीछे दयालुता कुछ ऐसी ही है। जीवन में आने वाले दुखों से ही जीवन है\nपकाया जाएगा. हमें जीवन में आने वाली गर्मी की तपिश के लिए तैयार रहना चाहिए, बेंदु\nपरिपक्व होना चाहिए. जो जीवन में कठिनाइयाँ नहीं देखता वह कभी आगे नहीं बढ़ता। उसके लिए दूसरे की ख़ुशी-\nदुःख समझ में नहीं आता. जब जीवन कठिन हो तो कठिन होता है। यह वही है जो प्रभु हमें देते हैं\nसज़ा के पीछे दया. हमारे पतन के पीछे मुक्ति का बीज छिपा है। दुःख के पीछे\nख़ुशी का बीज है. इस प्रकार शास्त्रीय दृष्टि से देखने पर सम्पूर्ण विश्व के पीछे की सार्वभौमिक शक्ति मह है\nकरुणामूर्ति के रूप में हमारी रक्षा करना। चेतावनी आती है. एक बच्चा जिसमें जागने की ताकत नहीं है\nजिस प्रकार एक माँ हमारी देखभाल करती है, उसी प्रकार भगवान सदैव हमारी रक्षा करते हैं। ये है\nआध्यात्मिक पथ पर अंतर्ज्ञान स्थिर रहना चाहिए।",
  "5.23": "शक्नो ति इहा एव यः सोधुम् प्राक् शरीर विमोक्षणात्\n\nकाम क्रोध उद्भ वाम वेगम सः युक्तः सः सुखे नरः - वासनाओं का आवेग - यहाँ,\nएक सच्चा योगी वह व्यक्ति है जो इस मानव शरीर को हटाए जाने से पहले सहन कर सकता है;\nसच्चा सुख।\n\nकेवल इस शरीर में ही हम अपने सांसारिक सुख-स्पर्शी मोह पर काबू पा सकते हैं।\nयह शरीर को चीज़ों का स्पर्श और चीज़ों पर विजय पाने की क्षमता है\nजबकि शरीर है. ईश्वर हमारे लिए निर्णय करता है कि क्या सही है और क्या गलत\nउन्होंने बुद्धि दी है. ऐसी विचार शक्ति का प्रयोग करने से पहले शरीर गिर गया\nमनुष्य को इन्द्रिय संयम का अभ्यास करना चाहिए। यह एक दिन में आगे बढ़ना और पूरा करना है\nइससे कोई फर्क नहीं पड़ता. इसके लिए निरंतर उपलब्धि की आवश्यकता होती है। यह कारनामा तब करना चाहिए जब शरीर मजबूत हो।\n\nमनुष्य को परेशान करने वाली मूल समस्या काम और क्रोध है। इस काम-क्रोध की गति हम सबकी है\nबुद्धि को आगे बढ़ाने और आगे खड़े होने के लिए पर्याप्त मजबूत। यह ऐसा है जैसे आप बरसात के मौसम के दीवाने हैं\nइससे पहले कि यह चलन खत्म हो जाए, इसे रोकें। इसे कौन रोक सकता है?\nवे कहते हैं \"सा युक्तः स सुखी नरः\" कृष्ण... जो काम-क्रोध, बाह्य का आश्रय नहीं लेता।\nवह जो स्पर्श का विरोध करता है और खुद को आंतरिक अनुभव के लिए उजागर करता है वह वास्तव में खुश है।\n\nहमारा आंतरिक अनुभव क्या है? ऐसा आनंद साधक अपने भीतर ही पा सकता है\nकृष्ण अगले श्लोक में बताते हैं कि अनुभव क्या है।",
  "5.24": "यः अन्तः सुखः अन्तः हमामः तथा अन्तः ज्योतिः एवयः।\n\nसः योगी ब्रह्म निर्वाणम् ब्रह्मभूतः अधिगच्छति - जो आंतरिक सुख की इच्छा करता है और पाता है,\nजो भगवान को देखकर अंदर से खुश होता है उसके अंदर भगवान की रोशनी होती है\nजो पूर्ण है, ऐसा साधक जो भगवान में विश्राम करता है, जिसने अमर शरीर प्राप्त कर लिया है।\n\nकार्यभार संभाला\n\nमनुष्य को सुख नहीं आंतरिक सुख चाहिए। इस श्लोक में 'सुख'\nऔर 'आराम' दो शब्दों का प्रयोग किया जाता है। इन दोनों शब्दों में सूक्ष्म अंतर है।\nजब हमारी इच्छाएँ पूरी हो जाती हैं या हम जो चाहते हैं वह है \"आराम\"; इच्छाएँ\n\nख़ुशी नहीं है. जब किसी चीज़ की कमी होती है, तो परेशानी, कठिनाई का समाधान होता है, कुछ\nखुशी तब है जब आप गर्मी से बच जाएं। यहाँ कृष्ण कहते हैं: \"अध्यात्म योग का अभ्यासी,\nजो व्यक्ति परिणाम प्राप्त करता है और प्राप्त करता है, वह मानसिक रूप से भगवान में रहता है। वह अंदर है\nवह आरामदायक रहेगा.     साधक के भीतर भगवान को देखना-\nआरामदायक है; काम क्रोध छोड़ देता है—प्रसन्न होता है; वह लौ उसके अंदर\nजब उसे अपने भीतर उस महान प्रकाश का एहसास होता है, तो वह भगवान को पा लेता है और भगवान में विश्राम कर लेता है।\n\nलभन्ते ब्रह्मनिर्बाणमृषयः क्षणेकल्माशः |\nछिन्नद्वैधयात्मनः सर्वभूतहिते रतः",
  "5.25": "लभन्ते ब्रह्मनिर्बाणं खुशाय; कमजोर कल्माशाह |\nछिन्न द्वैदः यतात्मनः सर्वभूतहिते रतः - सभी दोष दूर हो गए, द्वंद्व दूर हो गया,\n\nजो ज्ञान का भंडार है\nजो जानते हैं वे भगवान के शाश्वत स्वरूप को प्राप्त कर लेते हैं।\n\nसच्चे उपलब्धिकर्ता वे हैं जो अपने भीतर उत्पन्न होने वाले संदेह और द्वंद्व से परे खड़े होते हैं। वह है\nवे हमेशा अपना ध्यान अंदर ही रखते हैं। वे जो खुशी चाहते हैं वह 'आंतरिक' है\nखुशी'. वह बाहरी सुख की इच्छा किए बिना सदैव सभी प्राणियों का भला चाहता है\nवे भगवान के रूप में निवास करते हैं और उनसे जुड़ जाते हैं।\n\nकामक्रोधवियुक्तानां यतिनासं यतचेतसाम |\nअभितो ब्रह्मनिर्बाणं वर्तते विदितात्मनम्",
  "4.42": "इसलिए, हे भारत — अज्ञान से उत्पन्न, हृदय में बैठे इस संशय को — ज्ञान की तलवार से काटकर — योग में स्थित हो जाओ और उठ खड़े हो।\n\n'ज्ञानासिना' — ज्ञान की तलवार। 'हृत्स्थम्' — हृदय में स्थित। 'संशयम् छित्त्वा' — संशय काटकर। 'योगमातिष्ठ' — योग में स्थित हो। 'उत्तिष्ठ' — उठ जाओ।\n\nचौथे अध्याय का समापन — ज्ञान और कर्मयोग दोनों साथ लेकर अर्जुन को उठने का आह्वान। 'भारत' — इस संबोधन में भरतवंश के कर्तव्य की याद।",
  "5.26": "काम क्रोध वियुक्तानां यतिसाम् यतचेतसाम् |\n\nअभितः ब्रह्मनिर्बानम् वर्तते विदिता आत्मानम्... प्रलोभनों पर विजय पाने के लिए कठिन प्रयास करें।\nउनके लिए जिन्होंने लात मारी है, उनके लिए जिन्होंने मार्ग पर विजय प्राप्त की है, उनके लिए जो भगवान को जानते हैं, भगवान का शाश्वत रूप हर जगह है\nभरा हुआ है\n\nजिन्होंने काम और क्रोध को पूरी तरह से त्याग दिया है और पूर्ण संयम प्राप्त कर लिया है उनके लिए सब कुछ हर जगह है\nभगवान प्राणियों में भी प्रकट होते हैं। उसे किसी सांसारिक क्लेश का दुःख नहीं है। उसका\nमन में भगवान का वास है जो सर्वव्यापी और शाश्वत है।\n\nउन्होंने बाहरी सुख से हटकर आंतरिक सुख की ओर मुड़ने का संदेश दिया\nअगले श्लोक में कृष्ण ने संक्षेप में ध्यान का वर्णन किया है।\n\nस्पर्शं कृत्वा बहिर्बाहंश्चक्षुश्चवंतरे भ्रुवोः।\n\nप्रहपानौ समौ कृत्वा नासाभ्यन्तरचारिणौ",
  "5.17": "तत् बुद्धयः तत् आत्मानः तत् निष्ठाः तत् परायणः |\n\nगच्छन्ति अपुनः वरदं ज्ञान निर्धूता कल्माशः - जो उसमें स्थापित है, वही भगवान है।\nजो लोग उस पर विश्वास करते हैं, उसमें बने रहते हैं, उसके प्रति समर्पण करते हैं, उसे पाते हैं और मर जाते हैं\nखोया हुआ व्यक्ति ऐसी जगह चला जाता है जहाँ से वापस आना संभव नहीं होता।\n\nयहां कृष्ण ने अज्ञान को दूर करने का उपाय बहुत सुंदर ढंग से बताया है। सबसे पहले\nबुद्धि को भगवान में रखना (तत् बुद्धयः); हमारा दिमाग सभी चीजों को समझता है,\nबुद्धि निर्णय करती है. यदि हम अपना मन भगवान पर स्थिर रखें, तो वह हमारा है\nबुद्धि में आकर बैठते हैं। इसके लिए हमारे पास ईश्वर के प्रति जागरूकता है\nखेती की जानी चाहिए. प्रभु की सामग्री की निरंतर सिद्धि से हम प्रभु में अपने हैं\nजब बुद्धि स्थिर हो जाती है तो भगवान हमारी बुद्धि में बस जाते हैं।\n\nअपनी आत्मा, अपना मन भगवान को समर्पित कर दो (तत् आत्मानः); वह तुम्हारा स्वामी हो,\nआप भगवान हैं जो हमेशा मेरा मार्गदर्शन करते हैं, मेरा जीवन उनके नियंत्रण में है\nप्रार्थना करते रहें कि चीजें शुभ होंगी।'\n\nईश्वर की निष्ठा के बिना कुछ भी नहीं किया जा सकता। निष्ठा का अर्थ है भक्ति।\nइसलिए सदैव भगवान की भक्ति करनी चाहिए। कोई भी ध्यान, भक्ति बिना भक्ति के\nकोई फायदा नहीं. एक बार हमें भगवान के बारे में ज्ञान हो जाए तो भक्ति अपने आप आ जाती है।\nज्ञान के बिना भक्ति - मुदभक्ति। जिनके पास ज्ञान तो है परन्तु भक्ति नहीं है उनका ज्ञान क्या है?\nकोई फायदा नहीं, यह सूखी छात्रवृत्ति जैसा लगता है।\n\nइस प्रकार, जब मन-बुद्धि भगवान में स्थित हो जाती है और बुद्धिमान भक्ति का अभ्यास किया जाता है, तो सबसे ऊपर\nमहान शरण प्रभु (तत् परायणः) का बोध होता है। इससे तो परिवार ही सब कुछ है\nभ्रम दूर हो जाता है. जैसा कि पुरंदर दास ने कहा: “वहां हमारा है, यहां है\nबस\"। इसका मतलब यह है कि यह परिवार शाश्वत नहीं है और जब हमें यहां से जाना होगा\nपता नहीं तो 'मेरा' का अहंकार क्यों? यह पलायनवाद नहीं है, हम कुछ भी नहीं हैं\nइसे छोड़ना ज़रूरी नहीं है, लेकिन यह सिर्फ इस भ्रम को छोड़ना है कि सब कुछ वैसा ही है। भगवान ने दिया है,\nजब तक दिया जाता है, तब तक दिया जाता है। उसी प्रकार हम भी कोई भक्त देवता हैं\nअस्वीकार मत करो. वे प्रभु का परिवार हैं जो हमें प्रभु से जुड़ने का मार्ग दिखाते हैं।\nलेकिन वे सब कुछ नहीं हैं.\n\nसबसे बढ़कर, वह वैराग्य की जागरूकता के साथ आपके पास आए जो हर किसी के लिए शरण होनी चाहिए\nकर्तव्य को भगवान का उपहार बनाओ। भागो मत, परिवार में रहो, भगवान क्या है\nजो दिया गया है उसे स्वीकार करो. 'सर्वोच्च उद्धारकर्ता' के रूप में अपना सर्वस्व उसमें समर्पित कर दें। इस प्रकार\nजीने से हमारी आत्मा पर चिपका मैल धुल जाता है और मन स्वच्छ हो जाता है। फिर\nज्ञान चमकता है - प्रभु का अहसास। यह शाश्वत है, कभी वापस नहीं आएगा\nजीवन से मोक्ष प्राप्त किया जा सकता है।\n\nविद्याविनयसम्पन्ने ब्राह्मणे गवि हस्तिनी |\nशुनि चैव स्वपाके च पण्डितः समदर्शिनः",
  "6.7": "ज्ञानविज्ञानत्रिप्पतात्मा कूटस्थो विजितेन्द्रियः |\nयुक्ता इत्युच्यते योगी समालोष्टाश्मकंचनः",
  "5.9": "न एव किंचित् करोमि इति युक्तः मन्येत तत्तवित्।\n\nपश्यन् सृण्वन् स्पृशं जिफरान अशदं गच्छन स्वपन श्वासन ॥\n\nप्रलापं विसृजन गृह्नां अनमिशन निमिन अपि।\n\nइन्द्रियाणि इन्द्रिय अर्थेषु वर्तमान्ते इति धारयण - एक सच्चा अभ्यासी कुछ भी नहीं है।\nआपको पता होना चाहिए कि आप क्या नहीं कर रहे हैं- देखते हुए, सुनते हुए, छूते हुए, सूंघते हुए, खाते हुए,\nकरवट लेते समय, सोते समय, सांस लेते समय, छोड़ते समय, खर्च करते समय, खरीदारी करते समय, दरवाजा बंद करते समय,\nआराम करते समय भी - यह महसूस करना कि इंद्रियाँ अपने काम में लगी हुई हैं।\n\nभगवान की पूजा करना ही हमारे जीवन में कार्यान्वयन नहीं है। हमारा प्रत्येक कदम एक है\nकर्म योग होना चाहिए. ईश्वर की आराधना केवल किसी विशेष समय के लिए नहीं होती। हमारा\nसम्पूर्ण जीवन यज्ञमय होना चाहिए। यज्ञ को कन्नड़ में 'बेलुवे' कहा जाता है। क्या यही हमारा अस्तित्व है?\nबंटवारा होना चाहिए.\n\nकर्मानुष्ठान कहता है, \"मैं स्वयं कुछ नहीं कर रहा हूं, लेकिन मेरा स्वैच्छिक कार्य है\nउसे इस सच्चाई का एहसास हो गया होगा कि मुझे यहां कोई आजादी नहीं है. हमें क्या करना चाहिए\nहम ऐसा नहीं कर सकते, हम जो चाहते हैं वह हमें नहीं मिलता, इसलिए हमें आज़ादी नहीं है। ये है\nयह कुछ ऐसा है जिसे हर कोई अनुभव करता है। लेकिन हमारे सामने सिर्फ कार्रवाई हो रही है.\n\n'मैं ऐसा कुछ पाना चाहता हूं, मैं ऐसा इसलिए कर रहा हूं क्योंकि मैं ऐसा कुछ पाना नहीं चाहता\nमैं इसे अहंकार के कारण नहीं कर रहा हूं; मेरे भीतर का भगवान यह कर रहा है।'\nदार्शनिक जानता है. इसलिए कुछ भी नहीं में \"मैं, मेरा\" का अहंकार\nउसके पास यह नहीं है. सब कुछ भगवान की इच्छा से होता है, लेकिन यहां हम स्वतंत्र हैं\nवह इस सत्य को जानकर अपने कार्य करता है कि वह सृष्टिकर्ता नहीं है।\n\nपश्यन-देखना, श्रवण-सुनना, स्पृशन-स्पर्श करना, जिफ्रान-सूँघना, अश्नान-\nभोजन करते समय, गच्चन-करवट लेते समय, स्वपन-सोते समय, स्वसन-सांस लेते समय, प्रलपना-बोलते समय,\nविसरुजन-विघटन, गृहण-प्राप्ति, निष्कासन-उद्घाटन, निमिन-समापन, आदि।\nएक दार्शनिक जानता है कि अपने सभी कार्यों में वह कुछ नहीं कर रहा है। उदाहरण के लिए-\nहम आंख से फूल की सुंदरता का स्वाद चखते हैं; इसकी सुगंध लें\n\nआनंद लेना; उस फूल को छूने से हमें ख़ुशी मिलती है। यह फूल किसने बनाया, उसके लिए\nसुंदरता तो प्रभु ने ही दी है। जिसने हमें उस फूल को देखने की आंख दी (वह जन्मांध था)।\nयह योग अस्तित्व में नहीं है)। यदि यह दृष्टिकोण हो तो देखने-स्पर्श करने-महसूस करने की क्रिया में 'मेरा' कहा जाता है\nअहंकार के लिए कोई जगह नहीं है. एक जैसा खाना: इस दुनिया में एक समय के भोजन के लिए इतने सारे लोग हैं\nवे बिना गति के दूसरों के सामने हाथ फैलाकर रहते हैं। लेकिन हमारे लिए ईश्वर त्रिगुणात्मक है\nयह उनमें से एक है जब वह यह समझकर खाता है कि उसने उस पर एहसान किया है\nबलिदान बन जाता है. इनु-नींद: नींद में हम भगवान के करीब होते हैं। लेकिन उससे सावधान रहें\nहमारे पास नहीं है. यदि आपको बिल्कुल भी नींद नहीं आती तो क्या होगा? अगर पूरी रात सपने में ही बीत जाए तो? ये हम से है\nसांस लेना भी मुश्किल है. जैसे हमारा जन्म नहीं हुआ है. साँसें चलने लगीं। नींद में भी\nहमारी श्वास क्रिया हमारे बिना निरंतर चलती रहती है। लेकिन ये सांसें कब रुकेंगी?\nहमें पता नहीं। इस प्रकार प्रत्येक कार्य में उस सार्वभौमिक शक्ति के प्रति दृष्टिकोण ही वास्तविक कर्म योग है।\nभगवान ने हमें एक अनमोल हाथ दिया है। जानवरों के चार पैर होते हैं. उसके सिर पर कोई हाथ नहीं\nयदि कोई प्राणी बैठ कर खून भी चूस ले तो उसे हांकने के लिए उनके पास कोई हाथ नहीं है। बहुत कीमती\nभगवान ने हमें काई से बचा लिया है। पलकें सबसे संवेदनशील आंख की रक्षा करती हैं,\nये आंखों को लगातार खुलने-खुलने से बचाते हैं। यदि आंख में कोई मलबा गिर जाए\nयह आंखों में पानी की आपूर्ति करके आंखों की रक्षा करता है जैसा कि हमारे पास नहीं है। इस अनोखी मशीन का डिज़ाइन\nभगवान मूर्तिकार हैं.\n\nहमारी प्रत्येक इंद्रिय कामुक देवताओं द्वारा नियंत्रित होती है\nहमने पहले इस मुद्दे का विश्लेषण किया है। उदाहरण के लिए सूर्य नेत्र और चंद्र कान\nदेवी सुपर्णी-वरुणि-पार्वती शब्द-स्पर्श-गन्ध की प्रशंसक देवियाँ हैं। कट्टर\nदेवता के रूप में गरुड़ शेष रुद्र हैं। इस प्रकार हमारे कार्य के पीछे एक अद्भुत आध्यात्मिक शक्ति काम कर रही है\nकर रहा है\n\nब्रह्मन्याध्याय कर्माणि संगं त्यक्त्वा करोति यः।\n\nलिप्यते नासा पापेन पद्मपत्रमिवाम्भसा",
  "6.1": "भगवान उवाच - भगवान ने कहा:\n\nअनाश्रितः कर्मफलं कार्यं कर्म करोति यः।\n\nसः संन्यासी च योगी च न निः अग्निः न च क्रियाः - कर्म के फल के लिए न्यास करो, कर्तव्य करो\nकर्ता ही सच्चा साधु और सच्चा योगी होता है। ऐसा कोई नहीं जो आग में न जलता हो,\nऐसा नहीं जिसने कर्म छोड़ दिया हो.\n\nआम तौर पर हम दो समूहों में विभाजित हैं, कर्मयोगी और संन्यासी\nयहां कृष्ण दुनिया के विचार से बढ़कर हैं कि कौन संन्यासी हैं और कौन कर्मयोगी हैं\nइस श्लोक में एक अलग ही विवरण हमारे सामने प्रस्तुत किया गया है। कृष्ण कहते हैं: \"अनसृतः कर्मफलम्\"\nवह है। हम आम तौर पर संन्यासी हैं, कर्म कर्ता हैं\nहम घर जैसा महसूस करते हैं। लेकिन कृष्ण कहते हैं कि हर किसी को कर्म योगी होना चाहिए और\nकि हर किसी को साधु बनना चाहिए. ऐसा नहीं है कि एक ही है। एक साधु\nइसका अर्थ है हम जो कुछ भी करते हैं उसे ईश्वर को अर्पित करना, कुछ न करना।\n'सम-न्यास' भगवान को सभी कर्मों का अर्पण है। यहाँ एक बहुत ही महत्वपूर्ण बिंदु है\nइसका अर्थ है कर्म के फल की इच्छा को पूर्ण प्रभु के हृदय में स्थापित करना।\nसंन्यास का मतलब अपने परिवार को छोड़कर जंगल में जाना नहीं है। कर्म योग करना चाहिए.\n''कार्यं कर्म करोति यः'' जिससे जो कार्य होगा, वही करेगा।\nक्या करना चाहिए। इसी कारण संन्यास और कर्मयोग दोनों एक हैं। असली\nसंन्यासी कर्मयोगी होता है और सच्चा कर्मयोगी संन्यासी होता है। इसके अलावा\nजैसा कि हम जानते हैं कि अग्नि का त्याग, कर्म का त्याग करने वाले ही संन्यासी हैं\nया योगी नहीं.\n\nसाधु कभी निष्क्रिय नहीं होता. सबकी अपनी-अपनी क्रिया है। ब्रह्मचारी\nयदि अध्ययन, गुरुकुलवास, गुरु शूरुषे आदि कार्य, ग्रह आतिथ्य,\nवह परिवार का ख्याल रखता है. इस प्रकार हर किसी के कर्म होते हैं।\n\nयं संन्याससमिति प्राहुर्योगं तं विद्धि पाण्डव |\nनह्यसंयस्तसंकल्पो योगी भवति कश्चन",
  "5.21": "अबुशतरशेषु सक्त आत्म विंदाति आत्मानि यत् सूक्ष्मम् |\n\nसः ब्रह्मयोग युक्त आत्मा सुखं अक्षयं अश्नुते - जो बाहरी सुखों से जुड़ा नहीं है।\nजिस प्रकार का सुख मिलता है [भगवान् को याद करते समय] वह सुख ही सुख होता है\nएक साधक जो भगवान से संतुष्ट है वह हमेशा इसका आनंद उठाएगा।\n\nसंसार में सुख के पांच साधन हैं। रूप, रस, गंध, स्पर्श, ध्वनि। इस बारे में\nभावना गलत नहीं है. इच्छित वस्तु की प्राप्ति में आनंद तो होता है, परंतु उससे भी अधिक\nमुख्य रूप से इसे छोड़ने में बहुत आनंद आता है। ये जानना जीवन में बहुत जरूरी है\nजैसा कि सूत्र ज्ञात है. हम जिस तरह से जीते हैं वह 'कल की खुशी के लिए आज कष्ट सहना' है\nकल कभी नहीं आता. कल के लिए मरना हमारा जीवन नहीं होना चाहिए।\nप्रभु को पाने में बहुत आनंद है और यह हमें सदैव प्रसन्न रखता है\nकृष्ण ने यहां सत्य की व्याख्या की है। एक बार हम अपने अंतर्मन से खुश हो जाएं\nअगर कोई अनुभव करने लगे तो उसे पता चल जाएगा कि बाहरी सुख में कुछ भी नहीं है। हमारे भीतर\nइसमें छुपी हुई ख़ुशी है, वह ख़ुशी जो बाहरी सुखों के त्याग से देखी जा सकती है।\n\nकभी-कभी हम अपने आंतरिक आनंद का अनुभव करते हैं। कभी-कभी मुझे पता नहीं चलता\nलेकिन सभी को 'बहुत ख़ुशी' का अनुभव हुआ है. यह हमारा आंतरिक स्व है\nआनंद उमड़ पड़ता है। बाहरी खुशी तब होती है जब हम इस आनंद को पहचानना और उसका आनंद लेना सीखते हैं\nन्यूनतम दिखाई देगा. बाहरी सुख के स्पर्श के बिना हम किस प्रकार नींद में हैं\nव्यक्ति को जाग्रत जीवन में आनंद की तरह आंतरिक आनंद का अनुभव करना सीखना चाहिए।\nइससे बाहरी सुख की भावना दूर हो जाती है।\n\nजैसा कि उपनिषद कहते हैं, \"बाहरी सुख का त्याग करने से आंतरिक आनंद का एहसास होता है\nउत्पन्न होता है और उसमें अमरता होती है”। हम न चाहने का आनंद \"चाहते\" हैं।\nअर्थ में नहीं. जरूरत हमारे लिए हमेशा 'बेड़ी' है। जरूरत हमारे सामने है\nसमस्याओं की एक शृंखला लाता और रोकता है। “सभी बाहरी इच्छाओं को खोने में\nकृष्ण कहते हैं कि मनुष्य के सुख का कोष छिपा हुआ है। इच्छाएं कम होने पर मनुष्य खुश रहता है\nरहता है\n\nबाहरी खुशी को छोड़ना ही काफी नहीं है, बल्कि आंतरिक खुशी को पकड़ना भी काफी है। बस इतना ही\nअनंत आनंद. कृष्ण कहते हैं: \"ब्रह्मयोगयुक्तात्मा सुखमक्षयामश्नुते\"।\nभगवान के ध्यान में व्यक्ति को भीतर से आनंद का अनुभव होता है - वही साधक को मिलता है।\nभगवद को अपने अंतरतम में स्पर्श करके साधक निरंतर उससे अनंत सुख का आनंद लेता है।\n\nखुशी हमारे अंदर है. यह एक मानसिक स्थिति है. हम अपने भीतर की ख़ुशी को नहीं पहचान पाते\nहम बाहरी ख़ुशी के पीछे संघर्ष करते हैं। एक लोक कथा ऐसा कहती है. खुद एक बूढ़ी औरत\n\nवह रात को घर पर कुछ पैसे गिरा देती है। लेकिन उसके घर का दीपक\nलगाने के लिए तेल नहीं है. एक बूढ़ी औरत जिसने गली में स्ट्रीट लैंप की रोशनी देखी और वह सड़क पर आई\nवह घर पर छोड़े गए पैसे की तलाश कर रही है। जब उनसे इसका कारण पूछा गया तो उन्होंने कहा, ''घर में रोशनी नहीं है\nलेकिन रोशनी यहां है, इसलिए मैं उसे ढूंढ रही हूं'' बुढ़िया का जवाब था! हम सभी\nइस तरह. सच्ची खुशी भीतर है, लेकिन हम इसका आनंद लेते हैं\nबाहरी दुनिया में!\n\nये हि संस्पर्शजा भोग दुःखयोनय एव ते |\nआद्यन्तवंतः कौन्तेय न तेषु रमते बुधः",
  "5.20": "न प्रहृष्येत् प्रियं प्राप्य न उद्विजेत् प्राप्य च अप्रियम् |\n\nसिरा बुदिः असम्मुधाः ब्रह्मवित् ब्रह्मानि सीताः - जब सुख आए तो संतुष्ट नहीं होना चाहिए; जब दुःख आता है\nछी धी छी\n\nसिकुड़ो मत.. ऐसा व्यक्ति दृढ़ निश्चयी होता है. जो जागने से नहीं चूकता. वह भगवान की तरह है.\nवह प्रभु में विश्राम करता है।\n\nहमारा जीवन सुख और दुख का एक चक्र है। किसी को केवल सुख ही दुःख नहीं है\nकभी नहीं. चाहे आप कितने भी अमीर क्यों न हों, जीवन में हमेशा कठिन क्षण आते रहेंगे।\nइसी प्रकार, जो लोग कठिनाई में हैं उनके पास भी खुशी के क्षण होते हैं। जीवन खुशियों और दुखों की बाढ़ है।\nइस श्लोक में कृष्ण कहते हैं: \"हमें सुख और दुःख के द्वंद्व में समभाव रखना चाहिए\"।\nआमतौर पर जब हमारी कोई पसंदीदा चीज़ काम करती है तो हम ख़ुश हो जाते हैं। हमें जो पसंद नहीं है, वह है हम\nजब अवांछित घटनाएँ घटती हैं, तो हम ढह जाते हैं और उत्तेजित हो जाते हैं।\nयह निश्चित ही एक ऐसी स्थिति है जो हमें अपने जीवन में देखनी पड़ती है। कृष्ण कहते हैं: “इनमें से कुछ भी न होने दो\nमन को शांत रखना चाहिए. निःसंदेह जो आवश्यक है\nस्वीकार किया जाना चाहिए.  अगर आप उसे छोड़ कर बैठ जाएं और सोचें कि ऐसा नहीं होना चाहिए, वैसा नहीं होना चाहिए।\nअस्पष्ट। यह मनोविज्ञान है. इसका मतलब यह है कि खुशी आने पर उसे महसूस नहीं करना चाहिए\nऐसा नहीं है कि जो जैसा है उसे वैसे ही स्वीकार करो, लेकिन बहुत ज्यादा उतावले मत बनो। जीवन में\nव्यक्ति को यह मानसिकता विकसित करनी चाहिए कि सब कुछ आता है और चला जाता है, कुछ भी स्थायी नहीं है।\nअगर हम किसी चीज से बहुत ज्यादा जुड़ जाते हैं तो वह हमसे दूर हो जाती है\nअसहनीय. इससे हम मानसिक रूप से विचलित हो जाते हैं। उससे भी छोटा\nहमारा मन छोटी-छोटी बात के लिए आत्महत्या जैसा जघन्य पाप करने को तैयार हो जाता है।\nइसलिए जीवन में सफलता का सूत्र यह है कि किसी भी चीज की चिंता किए बिना जो मिलता है उसे पा लिया जाए\n\nयह अनुभव करने के लिए कि दुनिया वैसी नहीं है जैसी हम चाहते हैं - हम वैसे हैं जैसे दुनिया है। इसमें आपका स्वागत है\nजब आप बिना तनाव के रहना सीख जाते हैं तो दिमाग मजबूत हो जाता है।\n\nएन\n\nआध्यात्मिक दृष्टि से मृत्यु हमें प्रिय क्यों है?\nयह कहते हुए कि यह वास्तव में अच्छा है] बुरा नहीं कहा जा सकता। जैसे\nजरूरी नहीं कि अच्छा हो. कभी-कभी जो हमारे लिए बुरा होता है वह हमारे लिए अच्छा होता है। लेकिन यह है\nहमें पता चलने में बहुत देर हो चुकी है. हमारे जीवन में आने वाली हर घटना हमारी अगली घटना होती है\nविकास का समर्थन करता है. यदि किसी मनुष्य में प्रारब्धकर्म है तो वह पतित हो जाता है\nउसे वह सारी खुशियाँ मिलें जो वह चाहता है! उस खुशी में मंत्रमुग्ध होकर वह वही करें जो उसे नहीं करना चाहिए\nपतित हो सकता है; कठिनाई जीवन बदलने वाली हो सकती है। यह प्रसंग कठोपनिषद् में है\nव्यंग्यपूर्वक कहते हैं: \"प्रयो मंडो योगक्षेमदवृणिते\" (1-2-2)। “मीठा\nऔर जब दोनों की बात आती है, तो पसंदीदा कौन चुनता है—उसे\n\"छात्र।\"\n\nहमें जो पसंद है वह जरूरी नहीं कि आरामदायक हो, इसलिए उसके लिए उड़ान भरना व्यर्थ है। इसी तरह\nजीवन में कुछ अप्रत्याशित घटित होने पर भ्रमित होने की जरूरत नहीं है।\nयह भविष्य में हमारे लिए अच्छा होगा. अधिकांश लोगों ने इसका अनुभव किया है।\nहम सोच रहे हैं, \"ऐसा क्यों है? ऐसा नहीं होना चाहिए था\" लेकिन भविष्य में यह हमारे कारण है\nएक समस्या सामने आती है. लेकिन यह जानने में बहुत देर हो चुकी है। इन सबके कारण\nजब सुख आता है तो सुख का भ्रम नहीं रहता, जब दुःख आता है तो कोई व्याकुलता नहीं रहती। दोनों के प्रति समभाव रखें.\nऐसा भाव रखें कि भगवान ने मुझे जो दिया है, उसे मैं ईमानदारी से अनुभव करूंगा। मानसिक\nभ्रमित मत होइए. ऐसा कहा जाता है कि भगवान जानता है कि जीवन में क्या अच्छा है और क्या बुरा\nजागरूक व्यक्ति अपना मन सुख-दुःख में नहीं लगाता। इसके बजाय उसका दिमाग\nप्रभु में रोपा। भगवान हमारी माँ है. जैसे किसी बच्चे की देखभाल करना\nबच्चे का ख्याल रखता है माँ से आने वाले सभी विचार बच्चे को पसंद नहीं आते। लेकिन माँ\nवह बच्चे के उद्धार के लिए बच्चे में वह कार्य करती है। वहाँ जैसा महत्वपूर्ण नहीं है, जो है\nहिता महत्वपूर्ण है.",
  "6.2": "यं संन्यासं इति प्रौह योगं तम विधि पांडव।\n\nन हि असन्नयस्थ संकल्पः योगी भवति कश्चन-वही संन्यास है।\nपाण्डव, इसे योग के रूप में जानो। जो कोई 'संन्यास' की इच्छा नहीं रखता वह देहधारी है\nकर्मयोगी नहीं हो सकते.\n\nसंन्यास भी एक योग है. कर्म फलत्यागा भी कर्म योगी का योग है जो कर्म कर सकता है\nएक मुख भगवत पूजा की दृष्टि से भगवान को सब कुछ अर्पित करें\nऐसा कर्म सात्विक की उपलब्धि है। संन्यास का अर्थ है भगवान में काम-संकल्प\nकाम अर्पण का अर्थ है 'करना चाहना', संकल्प का अर्थ है 'करना'\nकामसंकल्प वर्जिता-संन्यास का निर्णय करना।      यहां कृष्ण समझा रहे हैं\nयह आश्रम से जुड़ा मामला नहीं है. यह उपलब्धि के बारे में है. उपलब्धि का\nयह कृष्ण का मुख है कि योगी को भिक्षु बनना चाहिए और भिक्षु को योगी बनना चाहिए\n\nसंदेश\n\nजब हम उपलब्धि हासिल करते हैं तो कर्म भी होना चाहिए और परिणाम भी। जब यह मामला है, हर कोई\nक्या आपने किसी भी कर्म को किया जाने वाला कर्म माना है? पेशेवरों का\nसामाजिक कर्तव्य क्या है? एक अभ्यासकर्ता को समाज के साथ कैसे बातचीत करनी चाहिए? कर्म का अंत\nवो? उपलब्धि और कर्म के बीच क्या संबंध है? यह उपलब्धि में कैसे योगदान देता है? ये सब\nकृष्ण अगले श्लोक में प्रश्नों का उत्तर देते हैं।\n\nअरुरुक्षोर्मुनेर्योगं कर्म वर्णनमुच्यते |\nयोगारूढ़स्य तस्यैव शमः वर्णनमुच्यते",
  "6.11": "तत्रैकग्राम मनः कृत्वा यशचितेन्द्रियक्रियाः |\nउपविषय$सने युंज्यद् योग मात्माविशुद्धये",
  "6.4": "यदा हि इन्द्रिय अरथेसु कर्म अनुषज्जते।\nसर्व संकल्प संन्यासी योगारूढ़ाः तदा उच्यते - सभी कर्म उत्तरदायित्व\nभगवान, जब कोई व्यक्ति कामुक विषयों और कर्मों से लगाव खो देता है\n\nउसे लगता है कि वह लक्ष्य प्राप्ति का है।\n\nअपरोक्ष ज्ञानी की विशेषता का वर्णन करते हुए, कृष्ण कहते हैं: “यदा हि न इंद्रिय अरथेसु न\n\"कर्मसु अनुषज्वते\"। यानी उन चीजों में जो अपरोक्ष ज्ञानी की इंद्रियों को पसंद आती हैं\n(ध्वनि, रूप, रस, गंध, स्पर्श या किसी भी चीज़ से जुड़ा नहीं। वह क्रिया है\nकरता है लेकिन उस पर अड़ा नहीं रहता. उपलब्धि की राह पर चलने वाले अभ्यासी कड़ी मेहनत करते हैं\nयदि इंद्रियों को संयमित कर लिया जाए तो अपरोक्ष ज्ञानी के लिए यही स्वाभाविक धर्म होगा। खुग्वेद में\nजैसा कि कहा जाता है \"नरसिम्हा दुनिया के नियंत्रक हैं। उनकी इच्छा मेरी इच्छा हो। उनके दिल में\nचाहत जो भी हो, वो मेरी भावना हो। इसके विपरीत मेरा कोई इरादा नहीं होना चाहिए।”\nअपरोक्षज्ञान मार्ग चाहता है। उसे इंद्रियों के माध्यम से कुछ भी अनुभव नहीं करना चाहिए\nयह नहीं चाहिए, यह नहीं चाहिए. संवेदी अनुभव से प्रभावित\n\nइसमें कोई चिपकना नहीं है. वह हर चीज़ को तटस्थ भाव से देखता है। हम समुद्र तट पर हैं\nअगर आप बैठ कर समुद्र को देखें तो वहां कई तरह की लहरें उठती हैं. हम उन तरंगों को देखते हैं\nआनंद ले रहे हैं. वहां आने वाली स्क्रीन पर हमारा कोई नियंत्रण नहीं है. लहर कैसे आई?\nतटस्थ होकर आनंद लेने में भी आनंद है। जीवन के सागर में कष्ट, सुख और पीड़ा है\nहर चीज़ लहरों की तरह आती और चली जाती है। इस पर हमारा कोई नियंत्रण नहीं है. समुद्र की एक लहर\nइस जीवन की लहर को स्वाभाविक रूप से देखकर खुश हो जाओ और खुशी से जियो\nअप्रत्यक्ष ज्ञान की विशेषता.\n\nइस अध्याय में कृष्ण ध्यान की पूरी प्रक्रिया को आगे बताते हैं। उसके लिए हमारा\nमन को कैसे सुसज्जित करें, योगी बनना है तो क्या करें?\nप्रस्ताव अगला श्लोक है.\n\nउद्धारेदात्मन$55त्मानं न*त्मानमवसादयेत |\nअते तमवे हत्मनो बन्धुरते तमवे रिपुरात्मनः",
  "6.13": "एच\nयू\nएच\nयू\n\nप्रशान्तात्मा विगतभिर्ब्रह्मचारिव्रते स्थितः |\n\nमनः संयम्य मचित्टो युक्त असित मत्परः",
  "5.14": "न कर्तृत्वं न कर्माणि लोकस्य सृजति प्रभु |\n\nन कर्मफल संयोगं सभवः तु प्रवर्तथे -- जीवन जड़ नहीं है; कार्य करने में सक्षम. हालाँकि\nवह दुनिया के किसी भी कार्य के लिए, पाप-पुण्य के लिए और उसके परिणामों के लिए ज़िम्मेदार नहीं है।\n(भगवान ने जीव जगत को कर्म, पाप-पुण्य तथा कर्मफल प्राप्ति का स्वामित्व नहीं दिया)।\nजीवन की प्रकृति अपना कार्य कर रही है। भगवान यह सब कर रहे हैं]।\n\nपूर्व विश्लेषित सभी प्रश्नों का उत्तर इस श्लोक में पहेली के रूप में निहित है। जाहिरा तौर पर\nयह नहीं जानता; वहाँ तभी जब एक-एक शब्द पर विज्ञान के ज्ञान से मनन किया जाता है\nउत्तर मिल जायेगा.\n\nभौतिक संसार के लिए जीव-प्रभु में स्वैच्छिक क्रिया है, लेकिन यह लेखकत्व नहीं है। जीवन जड़ है\nतुलनात्मक रूप से: जड़ में कोई सोचने की शक्ति नहीं होती - लेकिन जीवित में सोचने की शक्ति होती है; जड़ को\nवहाँ कोई बुद्धि नहीं है—लेकिन जीवन है; दोनों का कोई कार्य नहीं है. कर्म, पाप-पुण्य तथा कर्मफल की प्राप्ति\nजीव जगत को स्वामित्व ईश्वर द्वारा नहीं दिया गया है। जीवन भर के लिए कोई डेटा स्वतंत्रता भी नहीं है। [उदाहरण के लिए:\nएक राजा अपने बेटे को देश के एक हिस्से पर स्वतंत्र रूप से शासन करने का अधिकार देता है\nडेटा स्वतंत्रता]। लेखकत्व को ठीक से समझना इसके पीछे की समझदारी है\nशास्त्रीय प्रक्रिया को जानें.\n\nसंसार में तीन प्रकार की शक्तियाँ हैं। केवल क्रिया ही लेखकत्व का एक रूप है। ये है\nजड़ता भी है. उदाहरण के लिए 'थन दूध देता है'; यहां थन से दूध निकालने का काम होता है\nलेकिन वह सबसे महत्वपूर्ण कार्य है. दूसरा बौद्धिक कार्य है. गैर स्वतंत्र\nस्वैच्छिक लेखकत्व-यह जीवित लोगों के लिए है, लेकिन वास्तविक महत्वपूर्ण लेखकत्व नहीं है। स्वतंत्र\nस्वैच्छिक कार्य ही सच्चा लेखकत्व है। यह केवल ईश्वर में ही विद्यमान है। जीवन के लिए\nकर्म में भी कोई स्वतंत्र इच्छा नहीं है। जीवन के स्वामी. इसलिए वह भगवान नहीं है.\nउदाहरण के लिए पालने में एक बच्चा। इसमें बुद्धि है, खाने की इच्छा है, लेकिन\nकोई आज़ादी नहीं. यह वही खाता है जो इसकी माँ इसके मुँह में डालती है। यह एक स्वैच्छिक लेकिन स्वतंत्र कार्य है-\nकोई स्वैच्छिक कार्य नहीं. अब फल के बारे में उसी उदाहरण के साथ: माता-पिता\nबच्चे को 'ईश्वर को नमस्कार करो' कहा जाता है तो बच्चे को यह पसंद नहीं आता\nमामले में पिता. माँ, बच्चे को खाना खिलाओ. या यदि आवश्यक हो तो भगवान को दंडित करें\nवे उसे झुकाते हैं, फिर बच्चा झुकता है। यहां प्रणाम करने वाले पिता-\n\nचाहे मां ही क्यों न हो, फल बच्चे के लिए ही होता है। इसी प्रकार जीवन के भीतर अदृश्य भगवान 'जीवन' विराजमान है।\nक्रिया को नियंत्रित करता है. यद्यपि वह भगवान ही है जो हमारे माध्यम से कर्म करता है\nकर्म का फल हमारे लिए है भगवान के लिए नहीं।\n\nइस दृष्टांत को आगे बढ़ाते हुए एक और प्रश्न मन में आता है। “प्रभु हमारे हैं\nमुखेना बुरे काम क्यों करता है? माता-पिता कभी भी बच्चे में बुराई नहीं करते,\nइसी तरह, भगवान हमारे अंदर भला क्यों नहीं कर सकते?\" वह है। यह है\nएक ऐसी हरकत जो दुनिया से भी ज्यादा अजीब लगती है. उदाहरण के लिए एक शिक्षक, वह उसका पाठ है\nबिना किसी भेदभाव के सभी बच्चों के लिए प्रवचन समान है। सिखाता है लेकिन एक\nयदि आप किसी पाठ को बहुत जल्दी समझ लेते हैं, तो दूसरा पाठ बिना समझे ही ख़त्म हो सकता है; दूसरा\nग़लत समझा जा सकता है. यह शिक्षक की गलती नहीं है, यह छात्र का स्वभाव है\nसम्बंधित मामला. कृष्ण कहते हैं \"स्वभावस्तु प्रवर्तते\"। यह एक दुर्लभ बात है.\nजैसा कि पहले उल्लेख किया गया है, जीवन शाश्वत है, यह ईश्वर द्वारा निर्मित नहीं है। इस शाश्वत जीवन के लिए\nएक अभूतपूर्व प्रकृति है जो शाश्वत है (கா01651/அரான்ரு஥்஥॥/). वह जीवन उस प्रकृति की तरह है\nहोता है\n\nजीव का जीव स्वभाव के रूप में कार्य करने का अर्थ है: उदाहरण के लिए, एक आम का बीज एक पेड़ बन जाता है\nवह केवल आम का फल देता है, कटहल का नहीं, यही उस बीज का स्वभाव है। जीवन है\nशरीर वृक्ष का बीज है। उस बीज का मूल गुण ही उस शरीर के माध्यम से प्रकट होता है\nअब और नहीं। जीव मुख्यतः अपनी प्रकृति के अधीन है। हम जैसा चाहते हैं वैसा करते हैं\nयह संभव नहीं है, जैसा हमारा स्वभाव है और वैसा ही हमारा निर्णय। मूलतः वास्तविक प्रकृति की तरह\nहमारी धारणा; हम इसके खिलाफ काम नहीं करेंगे. इस स्वभाव के कारण\nयदि वह सात्विक बन जाता है, तो उसके सभी विचार सात्विक गुण के प्रभाव में होते हैं। राजासन\nयह विचारधारा राजस गुण के प्रभाव में है। प्रकृति के साथ जन्मा और पला-बढ़ा समाज\nयदि प्रभाव है भी तो उसकी अभिव्यक्ति क्षणिक होती है। यह अधिक से अधिक एक जन्म तक ही सीमित है, लेकिन अंततः\nजो कुछ बचा है वह जीवन का स्वभाव है।\n\nजीवन से शाश्वत रूप से जुड़ी हुई प्रकृति - सात्विक राजस और तमस का संयोजन। सात्विकस\nइसका मतलब है कि उनमें सात्विक गुण अधिक होते हैं। वह उस समूह से संबंधित है जिसमें गुणवत्ता प्रधान है\nजब तक ये तीन प्रकार के जीव अपने स्वभाव के अनुसार आचरण नहीं करते,\nएक स्वतंत्र लेखक जो यह तय करता है कि इसे कैसे करना है और खुद को आकार देता है\nऐसा नहीं है.\n\nप्रकृति हमारे अधीन नहीं है और उस प्रकृति की अभिव्यक्ति मेरी स्वतंत्रता में नहीं है। वो फिर\nप्रकृति कैसे व्यक्त होती है? प्रकृति के अनुसार विकास किसके अधीन है? प्रकृति को वह शक्ति\n\nयह कहां से आया था? इन सभी प्रश्नों का उत्तर इस श्लोक में दिया गया है। उसके लिए हम इस श्लोक में\nएक और छिपा हुआ अर्थ देखना चाहिए. हमारा कोई लेखकत्व नहीं है और कर्म का परिणाम भी वही है\nआने की आजादी नहीं है.  उसने स्वयं बीज बोया और एक पेड़ बन गया\nजीवन में फल उत्पन्न करने की शक्ति नहीं है। स्वतंत्र भगवान सृष्टि नामक एक उद्यान का निर्माण करें, वहाँ एक है\nएक माली की तरह वह जीवन का बीज बोता है। उसी से वह वृक्ष बनता है जिसे हमारा शरीर कहते हैं\nउगता है और उससे कड़वा, खट्टा या मीठा फल जीवन के समान होता है\nव्यक्त किया। .. तो एक बुरा कर्म (कड़वा) एक अच्छा कर्म (मीठा) है। हमारा\nप्रकृति पर निर्भर, भगवान पर नहीं. एक माली के तौर पर, यह काली मिर्च के पौधे के लिए मसालेदार है\nपानी की निकासी नहीं होती. वह उस पौधे को भी सभी पौधों की तरह पाल-पोसकर बड़ा करता है। लेकिन यह मसालेदार है\nअपनी प्रकृति के अनुसार फल देता है। इस प्रकार भगवान जीवन की शाश्वत प्रकृति के अनुसार हैं\nजैसी कार्रवाई हुई, कार्रवाई हुई.\n\nकभी-कभी हम जो सोचते हैं उसके विपरीत कार्य करते हैं। क्योंकि हमारा मन और\nबुद्धि विक्र श्रृंखला (",
  "5.18": "विद्या विनय सम्पूर्णे ब्राह्मणे गवि हस्तिनी।\n\nशुनि च एव स्वपाकाय च पंडितः समदर्शिनः - सच्ची पांडित्य-विद्वता,\nब्राह्मण वर्ण, गाय, हाथी, कुत्ता, होलागेदि मनुष्य में भी एक समान है।\nभगवान के दर्शन हो सकते हैं.\n\nकई लोगों को यह श्लोक समझ में नहीं आता या फिर कई लोग इसे गलत समझ लेते हैं।\nयहां कृष्ण ने एक और पहलू का वर्णन किया है जो एक साधक की पूजा में मौजूद होना चाहिए।  यह है\n\nबहुत ही आत्मविश्लेषणात्मक कविता. यहां तीन प्रकार की मानव स्थिति और तीन हैं\nकृष्ण ने ऐसे पशुओं की स्थिति का वर्णन किया है। मनुष्यों में : विद्याविनयसम्पन्ना, ब्राह्मण तथा\nस्वपका जानवरों में: गाय, हाथी और कुत्ता।\n\nवह जो मनुष्यों में ज्ञान के शिखर पर पहुंच गया है और सबसे बड़ा 'विद्या विनयसम्पन्ना' है। वेद\nब्राह्मण वह है जो सच्चे मन से किसी अंग का ध्यान करता है और उसकी पूजा करता है। (यहाँ कह रहा हूँ\nब्राह्मण-ब्राह्मणवर्ण; जाति नहीं. इस पर हमने विशेष रूप से पिछले अध्याय में चर्चा की है)। संपूर्ण\nवेदज्ञ वह है जो वेदों को पढ़ता है और उस वैदिक पद्धति को जीवन में अपनाता है। वेद\n'वैदिक अर्थज्ञ' जो आंतरिक अर्थ को जानता है - वह \"विद्या विनयसम्पन्ना\" है\n\nमनुष्यों में सबसे नीच श्वपाक है। स्वपका का अर्थ है कुत्ते का मांस खाने वाला।\nइसका मतलब है कि उसमें कोई संस्कार नहीं है, वह पेट के लिए कुछ न कुछ खाता रहता है। यह मानव है\nये तो दरिंदगी की पराकाष्ठा कहने जैसा है. इस प्रकार सर्वोच्च शैक्षणिक उपलब्धि,\nउसके नीचे ब्राह्मणवर्ण है, सबसे नीचे स्वपाक है।\n\nपशुओं में गवा (गाय) सबसे महान पशु है। उसके बाद मध्य हस्तिनी (हाथी), अंत में कुत्ता।\nपूर्वजों ने निष्कर्ष निकाला कि जो कुछ भी मन को शुद्ध करता है वह 'शुद्ध' है।\nउदाहरण के लिए, हिरण और बाघ की खाल मन को एकाग्र करने में मदद करती है। पृथ्वी पर सबसे बुरा\nध्यान के दौरान कंपन को हमारे शरीर में प्रवेश करने से रोकने के लिए इस त्वचा का उपयोग किया जाता है\nउपयोग किया जाता है इसलिए यह शुद्ध और महान है... इसी प्रकार गाय; इस जानवर में\nवहां सदैव सात्विक स्पंदन (॥/॥॥00) होता है। गाय में एक और महान कारक\nअर्थ: इस संसार में सभी प्राणियों का संयम। लेकिन गाय का गोबर और मूत्र श्रेष्ठ है। इस प्रकार\nगाय सबसे महान पशु है। गृह प्रवेश के समय सबसे पहले गाय को घर के अंदर लाना चाहिए\nयही कारण है.\n\nप्राचीन लोग कुत्ते को सबसे निम्न वर्ग का मानते थे। जैसा कि हम जानते हैं कि कुत्ता उसका है\nएक घरेलू जानवर जो अपने मालिक के लिए अपनी जान देने को तैयार रहता है। लेकिन यह बहुत तामसिक है\nनाड़ी वाला एक जानवर (93401)। इसलिए कुत्ते से कोई भी चीज़ हमारे मानसिक विकास को पोषित नहीं करती\nनहीं, इसी कारण से पूर्वजों द्वारा कुत्ते को सबसे निचले स्थान पर रखा गया था। कभी कुत्ता नहीं\nयही कारण है कि इसे घर में शामिल नहीं किया जाता है। इस प्रकार पशुओं में गाय श्रेष्ठ है, हाथी मध्यम है और कुत्ता श्रेष्ठ है\nकम से कम.\n\nयहाँ कृष्ण कहते हैं: \"पंडितः समदर्शिनः\"। वह है। पंडित एक समान हैं\nइसका मतलब है होना. वे प्रत्येक में हैं, उनके भीतर भगवान की विशिष्टता है\nअभिव्यक्ति देखें. चाहे वह गाय हो, चाहे कुत्ता हो, चाहे कोई पढ़ा-लिखा व्यक्ति हो या कुछ भी।\nक्योंकि भगवान सर्वव्यापी हैं, वे सबके अंदर हैं। बस उनका एक्सप्रेशन अलग है.\n\nवह हर जीवित प्राणी में एक अद्वितीय और असाधारण गुण है।\nअभिव्यक्त करता है। उदाहरण के लिए: छुआ हुआ ऋषि पौधा (Touch-me-not) किसी को नहीं चाहिए\nइस उगने वाले पौधे में महान औषधीय गुण हैं। इस पौधे (बिना फूल) को धुंधले कपड़े में बांध लें\nयदि आप इसे दलिया के साथ पकाते हैं, तो उस दलिया को खाएं या इस पौधे का काढ़ा पीएं,\nबवासीर (॥5) बिना किसी सर्जरी के ठीक हो जाती है। इसी प्रकार मधुमक्खी:\nइस छोटे से कीड़े में फूल से रस चूसने और शहद बनाने की असाधारण क्षमता होती है। हमारा\nतकनीकी रूप से, शहद को कृत्रिम रूप से नहीं बनाया जा सकता है।\n\nइस संसार में जो कुछ भी उत्पन्न होता है वह एक अद्वितीय ऊर्जा, नियंत्रणकारी ऊर्जा से भरी होती है\nअपरोक्ष ज्ञानी हर जगह भगवान जनेश्वर को देखते हैं। चाहे वो कुत्ता हो या गाय\nचाहे वह कुत्ता पालने वाला हो या कोई पढ़ा-लिखा व्यक्ति। पंडिता- प्रत्येक वस्तु में उसी प्रभु की महिमा है\nदिखता है\n\nवह सर्वव्यापी है, परम शुद्ध है, सब से परिपूर्ण है, अनासक्त है, एक है\nभगवान, जो पदार्थ को अद्वितीय शक्ति प्रदान करते हैं, ने इस अनंत संसार की रचना की\nऐसा करो और इसे हमारी आंखों के सामने रखो. प्रत्येक वस्तु में ईश्वर की ऐसी महिमा देखो\nसंपर्क किया जाना चाहिए. वह सर्वज्ञ, सर्वव्यापी है-\nअनुसन्धान - अप्रत्यक्ष ज्ञान कि वह सर्वव्यापी है, प्रत्येक परमाणु-कण में व्याप्त है\nसमदर्शन चाहता था.\n\nएहैव तिर्जितः सर्गो येषाम् साम्ये स्थितम् मनः।\n\nनिर्दोषं हि समं ब्रह्म तस्माद् ब्राह्मणी ते स्थितः",
  "5.29": "भोक्परं यज्ञ तपसं सर्वलोक महेश्वरम्।\n\nसुहृदं सर्व भूतानां ज्ञात्वा माम् शान्तिं खच्छति -- होमम्स-वृत्तस\nबुनने वाले के रूप में, सभी संसारों के स्वामियों के अग्रज के रूप में, सभी प्राणियों के बुनकर के रूप में\nजो मुझे जानता है वह मुक्ति, आनंद का स्थान प्राप्त करता है।\n\nवह भगवान सभी यज्ञों का वाहक है। [यहाँ यज्ञ का अर्थ केवल अग्नि में किया गया यज्ञ नहीं है,\nपहले वर्णित सभी प्रकार के यज्ञ]। हविसू हम देवताओं के नाम पर यज्ञ में अर्पित करते हैं\nसाथ ही उस देवता के भीतर अन्तर्निहित भगवान के प्रति समर्पित होने की भावना भी\nकी पेशकश की जानी चाहिए. देवता भगवान को अर्पित किये बिना की गई किसी भी इच्छा को स्वीकार नहीं करते हैं।\nहमारे हर कदम में ईश्वर के प्रति दृष्टिकोण होना चाहिए। वह सर्वशक्तिमान है,\nअनुशासन ध्यान में यह बहुत महत्वपूर्ण है कि सभी क्रियाओं का नियंत्रक, सब कुछ उसी का है।\nशारीरिक, मानसिक, मौखिक रूप से अटल दीक्षा होनी चाहिए। कितने समय के लिए\nबेईमानी न बोलने की दीक्षा, मन में सदैव सत्य का गहराई से विचार करना,\nसदैव सबके प्रति दयालु रहो - यही तपस्या है। जिसे हम प्रभु को भूल जाते हैं\nपूजा व्यर्थ है.\n\nकुछ लोगों के लिए, भगवान डर है! यहां कृष्ण कहते हैं: 'सुहृदं सर्व भूतानाम'।\nप्रभु से कभी मत डरो। उससे अच्छा कोई दोस्त नहीं है. हमेशा हम\nभगवान प्रेम करने, हमें लगातार अंदर और बाहर भरने और हमारी रक्षा करने की शक्ति हैं। सब लोग\nइसका तरीका यह है कि उन्हें उनकी क्षमताओं के अनुसार बड़ा किया जाए और गलती होने पर उन्हें सुधारने के लिए दंडित किया जाए\n'सुह्रुत' वह प्रभु है जो दिखाता है, सदैव करुणा से उभारता है। ऐसा दयालु व्यक्ति अकेला खड़ा रहता है\nध्यान में यह ज्ञान बहुत महत्वपूर्ण है। ज्ञानानंद जो इस विचार को जानते थे और उन्होंने इसका पालन किया\nकृष्ण कहते हैं कि उन्हें परम मोक्ष मिलेगा।\n\nइति पंचमो*$ध्यायः\nपाँचवाँ अध्याय समाप्त हो गया।\n\nचिंता मत करो\n\nअध्याय छह\n\nकृष्ण, जिन्होंने पिछले अध्याय में मुख्य रूप से भगवान की पूजा की उपलब्धि का वर्णन किया था, अब छठे हैं\nअध्याय में उन्होंने ध्यानयोग और ध्यानसमाधि को तालस्पर्शी के रूप में समझाया है।\n\nभगवान का वचन\nअनाश्रितः कर्मफलं कार्यं कर्म करोति यः |\nसा संन्यासी चयोजिचाना निराग्नि रणा चक्रः ॥1॥\n\nभगवान उवाच - भगवान ने कहा:\n\nअनाश्रितः कर्मफलं कार्यं कर्म करोति यः।\n\nसः संन्यासी च योगी च न निः अग्निः न च क्रियाः - कर्म के फल के लिए न्यास करो, कर्तव्य करो\nकर्ता ही सच्चा साधु और सच्चा योगी होता है। ऐसा कोई नहीं जो आग में न जलता हो,\nऐसा नहीं जिसने कर्म छोड़ दिया हो.\n\nआम तौर पर हम दो समूहों में विभाजित हैं, कर्मयोगी और संन्यासी\nयहां कृष्ण दुनिया के विचार से बढ़कर हैं कि कौन संन्यासी हैं और कौन कर्मयोगी हैं\nइस श्लोक में एक अलग ही विवरण हमारे सामने प्रस्तुत किया गया है। कृष्ण कहते हैं: \"अनसृतः कर्मफलम्\"\nवह है। हम आम तौर पर संन्यासी हैं, कर्म कर्ता हैं\nहम घर जैसा महसूस करते हैं। लेकिन कृष्ण कहते हैं कि हर किसी को कर्म योगी होना चाहिए और\nकि हर किसी को साधु बनना चाहिए. ऐसा नहीं है कि एक ही है। एक साधु\nइसका अर्थ है हम जो कुछ भी करते हैं उसे ईश्वर को अर्पित करना, कुछ न करना।\n'सम-न्यास' भगवान को सभी कर्मों का अर्पण है। यहाँ एक बहुत ही महत्वपूर्ण बिंदु है\nइसका अर्थ है कर्म के फल की इच्छा को पूर्ण प्रभु के हृदय में स्थापित करना।\nसंन्यास का मतलब अपने परिवार को छोड़कर जंगल में जाना नहीं है। कर्म योग करना चाहिए.\n''कार्यं कर्म करोति यः'' जिससे जो कार्य होगा, वही करेगा।\nक्या करना चाहिए। इसी कारण संन्यास और कर्मयोग दोनों एक हैं। असली\nसंन्यासी कर्मयोगी होता है और सच्चा कर्मयोगी संन्यासी होता है। इसके अलावा\nजैसा कि हम जानते हैं कि अग्नि का त्याग, कर्म का त्याग करने वाले ही संन्यासी हैं\nया योगी नहीं.\n\nसाधु कभी निष्क्रिय नहीं होता. सबकी अपनी-अपनी क्रिया है। ब्रह्मचारी\nयदि अध्ययन, गुरुकुलवास, गुरु शूरुषे आदि कार्य, ग्रह आतिथ्य,\nवह परिवार का ख्याल रखता है. इस प्रकार हर किसी के कर्म होते हैं।\n\nयं संन्याससमिति प्राहुर्योगं तं विद्धि पाण्डव |\nनह्यसंयस्तसंकल्पो योगी भवति कश्चन ॥2॥\n\nयं संन्यासं इति प्रौह योगं तम विधि पांडव।\n\nन हि असन्यास्थ संकल्पः",
  "6.8": "जिता आत्मानः प्रशांतस्य परम आत्मा समाहितः |\n\nठंडा, गर्म, खुश, उदास, उदास, उदास, अपमानित।\n\nज्ञान विज्ञानं तृत्पा आत्मा कूटस्थः विजिता इन्द्रियः\n\nयुक्तः इति उच्यते योगी समलोष्ठ अश्म कंचनः-बगेई [भक्ति के साथ भगवान के लिए]\nभगवान उस व्यक्ति में बस जाते हैं जो जीत जाता है, जो चीजों की ओर रुख किए बिना भगवान में लीन रहता है।\nवह सर्दी-गर्मी, सुख-दुःख और मान-अपमान जैसे द्वंद्वों के प्रति उदासीन है।\nजो खड़ा हो सके; जो ईश्वर-चेतना से परिपूर्ण है; वह जो इंद्रियों को नियंत्रित करता है।\nमिट्टी, पत्थर, सोना सब उसके लिए एक हैं। ऐसे योगाभ्यासी को लगता है कि वह लक्ष्य से जुड़ा है।\n\nजब भक्ति के माध्यम से भगवान की कृपा प्राप्त होती है, तो मन सबसे पहले उनमें ही स्थित होता है। क्या दिमाग है\nवह इवेंट में भी घबराते नहीं हैं. \"परमात्मा समाहितः\" - उसके हृदय में ईश्वर\nवह आता है और बस जाता है और चला जाता है। हम जब चाहें तब उनका अंतर्ज्ञान संभव है। ऐसे प्रभु\nकृष्ण यहाँ फिर बताते हैं कि द्रष्टा के परोक्ष ज्ञान का प्रभाव क्या होता है।\n\nमुख्यतः अप्रत्यक्ष ज्ञान इन्द्रियों को कभी कष्ट नहीं देता। उनका कभी अपमान नहीं हुआ\nढहता नहीं. उनके लिए अपमान कोई बड़ी बात नहीं है. जो इस अवस्था में पहुँच गया है, वह तैयार है\n\nउसे लगता है कि वह इतना निर्दयी है कि उसे हर चीज एक समान नजर आने लगती है। धन-कनक\nवह सब कुछ चाहता है और उससे दूर रहता है। (कोई रामकृष्ण परमहंस की आत्मकथा पढ़ता है\nहम अपरोक्ष ज्ञानी की मनःस्थिति को समझते हैं)।\n\nअगले श्लोक में कृष्ण ध्यान की प्रस्तावना के रूप में एक योगी की मनःस्थिति क्या होनी चाहिए, इसका वर्णन किया गया है\nएक बहुत ही महत्वपूर्ण बात बताते हैं.\n\nसुहृन्मित्रार्यदासिनामध्यस्थदवेस्याबन्धुषु |\n\nसाधुष्टपि च पापेषु समबुद्धिर्विशिष्यते",
  "6.18": "यदा विनयतम चित्तं आत्मानि एव अवतिष्ठे।\nनिश्रः सर्व कामेभ्यः युक्तः इति उच्यते तदा-चेन्न गी आंतरिक रूप से भगवान में तपा हुआ।\nजब वह स्थिर हो जाता है, जब सभी वासनात्मक इच्छाएं दूर हो जाती हैं, तो वह 'ध्यानी' बन जाता है।\n\nयोगाभ्यास से योगी का अवचेतन नियंत्रित होता है। आमतौर पर हमारे मूड में\nअतीत की बुरी यादें हमें हमेशा सताती रहती हैं। कुछ नफरत, कुछ प्यार\nइन सबको छोड़कर, योगी केवल भगवान को ही अपने आंतरिक आसन पर बैठा सकता है। इस प्रकार\nजब आप ऐसा करते हैं, तो आप हमेशा अपने हृदय में प्रभु को देखते हैं। उस प्रभु के दर्शन के बाद और कुछ नहीं\nमुझे नहीं लगता कि मुझे इसकी जरूरत है. क्योंकि ईश्वर उन सभी चीज़ों में सबसे महान है जिनकी हम इच्छा करते हैं।\nजब आंतरिक आनंद का झरना खुल जाता है, तो छोटी-छोटी बाहरी इच्छाएं बुझ जाती हैं\nवह एक ध्यानी हैं.\n\nयथा दीपो निवतस्थो नेंगते सोपमा माता |\nयोगिनो यशचित्तस्य युंजतो योगमात्मनः",
  "6.21": "सुखम् अत्यान्पिकम् यत् तत् बुद्धि ग्रह्यम् अतिन्द्रियम् |\nवेत्ति यत्र न च एव अयं स्थितः चलति तत्वतः |",
  "6.20": "यत्र उपरामते चित्तं निरुद्धं योग सेवया।\n\nयत्र च एव आत्मान आत्मानं पश्यन आत्मानि तुष्यति ॥|\nसुखम्मत्यन्तिकं यत्तद् बुद्धि गृह्यमतिन्द्रियम् |\nवेत्ति यत्र चैवयं स्थितश्चलति तत्वतः",
  "5.28": "स्पर्शं कृत्वा बहिः बहुहं चक्षुः च एव अंतरे भ्रुवोः।\n\nप्राण अपानौ समौ कृत्वा नासा अभ्यन्तर चारिणौ |\n\nयत इन्द्रिय मनः वृत्तिः मुनिः मोक्ष परायणः |\n\nविगत इच्छा भय क्रोध यः सदा मुक्तः एव सः - बाह्य भौतिक संबंधों को छोड़कर,\nटकटकी की भौहें ऊपर उठाएं, प्रहपान कुम्भक में मंच की ओर बढ़ रहे हैं\nमुक्ति के लिए इंद्रियों और मन की अनियमितताओं को संतुलित करें, नियंत्रित करें\nवह जो लालायित है, जिसने इच्छा-शर्मिंदगी-चिंता से छुटकारा पा लिया है। ऐसा साधक सदैव होता है\nमुक्ता सही है.\n\nयदि हम अपने मन को नियंत्रित करना चाहते हैं तो सबसे पहले बाहरी दुनिया में अपनी इंद्रियों को नियंत्रित करें\nआंदोलन को नियंत्रित किया जाना चाहिए. \"स्पर्शं कृत्वा बहिः बहान्\" - परिधीय नियंत्रण\nबिना कर्म किये मन को वश में नहीं किया जा सकता। इसके लिए बाह्य जगत रूप-रस-स्पर्श-\nध्वनि-गंध नामक सुख के भ्रम को बाहर ही छोड़ देना चाहिए। साथ ही अनजाने में हमारे भीतर भी\nइस संसार की अनुभूति से भरा हुआ, जो सत्य को देखने में बाधक है\nबाहर फेंक देना चाहिए. आमतौर पर जब हम ध्यान के लिए बैठते हैं तो हमें कुछ न कुछ दिखाई देने लगता है।\nसुंदर, भयानक, आदि। इससे डरने की कोई जरूरत नहीं है। ये सब हम ही हैं\nअनावश्यक विचार जो हमें भर देते हैं। जब वो बाहर जाते हैं तो हमें ऐसे ही दिखाते हैं\nजब आप बिना दृढ़ता के हासिल करना जारी रखेंगे तो धीरे-धीरे ये सभी विचार दूर हो जाएंगे\nमन पवित्र हो जाता है. यह रातोरात नहीं होता, इसके लिए निरंतर प्रयास की आवश्यकता होती है।\nएक बार अंतःकरण स्वच्छ हो जाए तो उसमें कुछ भी प्रतिबिंबित हो सकता है।\n\nध्यान का एक अन्य महत्वपूर्ण पहलू अन्नमयकोश (शरीर) को स्थिर करना है। शरीर\nयदि मन चलायमान हो तो एकाग्रता असंभव है। उसके लिए हम (6760 316 521001) खड़े हैं\n006), हमें अपने शरीर को संभावित आसन (105/9) में स्थिर करना चाहिए। कृष्ण कहते हैं:\nजैसे \"चक्षु च एव अंतरे भ्रुवोः\"। यानि हमारी दृष्टि हमारी दोनों भौंहों के बीच में होती है\nरोपण.यह. विद्वानों के अनुसार यदि कठिन हो तो नाक के अग्रभाग को भी चुना जा सकता है\nकहते हैं)। हमारी दोनों भौंहों के बीच आज्ञाचक्र है, जहां हम अपनी दृष्टि इस ऊर्जा पर केंद्रित करते हैं\nकेंद्र चेतन हो जाता है. इससे अन्नमय कोष स्थिर होता है।\n\nअन्नमयकोश के बाद प्राणमयकोश आता है। “प्राण अपानौ समौ कृत्वा नासा अभ्यन्तर\nचारिनौ”- हमारे भीतर वायु की निरंतर गति होती रहती है; इस आंदोलन को स्थिर करना\nइसे कुम्भक कहा जाता है। यह 2 प्रकार का होता है। एक आंतरिक और दूसरा बाह्य.\nअन्तःकुम्भक में पहले सारी भीतरी वायु बाहर निकालो और फिर कितनी अधिक\nजितना हो सके ताजी हवा लें और अपनी सांस रोककर रखें। [इस तरह\nगुरु से प्राणायाम सीखा। अवश्य- अन्यथा इससे खतरा है]।\nबाहरी कुम्भक में आंतरिक वायु को पूरी तरह बाहर निकालकर उसी स्थिति में सांस लें\nबंद हो जाएगा। अंतकुंभक आमतौर पर हृदय रोग वाले लोगों के लिए खतरनाक है। वे हैं\nबाह्यीकरण किया जा सकता है. इस प्रकार कुम्भक द्वारा प्राणमयकोश स्थिर होता है। अगला कदम\nमनोमय और विज्ञानमयकोश। हमारा मन चंचल है, वह स्थिर नहीं रहता, वह\nस्थिर किया जाना चाहिए. वह जोर देकर कहते हैं, ''इस रास्ते पर मैं सफलता हासिल करूंगा और हासिल करूंगा.''\nमन को इसके प्रति अभ्यस्त होना चाहिए। इससे मन भगवान की ओर एकाग्र हो जाता है। यह शर्त\nहम पंचभय के रूप में उच्चतम अवस्था तक पहुँच सकते हैं। यहां का आनंद असीमित है। यह\nयदि हम अवस्था में सुख का अनुभव करते हैं तो बाहरी जगत में सुख के पीछे हमारा मन होता है\nकभी नहीं बहती. मन भगवान में विश्राम करता है. इसी से हमारी इच्छा-भय-क्रोध सब होता है\nनहीं होगा. कृष्ण कहते हैं, ''ऐसा साधक सदैव स्वतंत्र होता है।''\n\nअन्नमयकोश, प्राणमयकोश, मनोमयकोश और विज्ञानमयकोश\nहम एक सूक्ष्म आत्मनिरीक्षण को परिपक्व करके अपने भीतर प्रभु के दर्शन कैसे देख सकते हैं?\nकृष्ण ने समझाया कि इसे प्राप्त किया जा सकता है। अगले श्लोक में हम उसे कभी नहीं देख पाएंगे\nवह बताते हैं कि भगवान को कैसे देखा जाए।\n\nभोक्तारं यज्ञतपसं सर्वलोकमहेश्वरम् |\n\nसुहृदं सर्वभूतानां ज्ञात्वा मां शांतिमृच्छति",
  "6.16": "न अति अश्चतः तु योगः अस्ति न च इषाहमं अनश्नतः |\nनच अति स्वप्न सिलस्य जाग्रत: न एव च ​​अर्जुन- हे अर्जुन, भूखे पेट के लिए ध्यानयोग।\nनहीं कर सकते बहुत ज्यादा खाने की कोई जरूरत नहीं है. बहुत ज्यादा उनींदापन भी नहीं. बिना नींद के।\n\nएक पेटू व्यक्ति ध्यान नहीं कर सकता। जब पेट में अधिक भोजन हो जाता है तो दिमाग सुस्त हो जाता है।\nइसलिए अत्यधिक पेटू मत बनो। ज्यादा खाना खाना अच्छा नहीं है. यह\nकिसी कारण से आतिथ्य में जबरदस्ती सेवा करना गलत है। वही सदैव सत्य है\nयदि आप नहीं खाएंगे तो पोषण की कमी के कारण शरीर ढह जाएगा। प्रभु का\nबोध इस शरीर के माध्यम से होता है. इसलिए हम नियमित रूप से नियमित भोजन करते हैं\nमौसम के अनुसार खाएं और अभ्यास करें।\n\nखान-पान के साथ-साथ हमारी नींद की आदत भी नियमित होनी चाहिए। हम कैसे अभ्यास करते हैं\nहमारा मन वैसा ही है जैसा हमने किया है। ज्यादा सोना कभी भी अच्छा नहीं होता. बेशक, वह उसी तरह सो गया\n\nध्यान करना संभव नहीं है. नियमित भोजन और नींद हमारे स्वास्थ्य और ध्यान के लिए आवश्यक है।\n\nयुक्ताहारविहारस्य युक्तचेष्टस्य कर्मसु |\n\nयुक्तस्वप्न वबोधस्य योग भवति दुःखः",
  "6.24": "शनैः शनैरूपर्मेद बुद्धाय धृतिगृहिताय |\nआत्मसमस्थं मनः कृत्वा न किंचिदपि चिन्तयेत्",
  "5.15": "न अदत्ते कस्यचित पापं न च एव सुकृतं विभुः।\n\nअज्ञानेन अवृतं ज्ञानं तेन मुह्यन्ति जन्तवः - जिसका जीवन निर्जीव से भी अधिक है।\nपाप भी दूर नहीं हो सकता;  सदाचार भी. [किसी भी जीव के पाप और पुण्य की तरह\nईश्वर के साथ नहीं।] ज्ञान अज्ञान से ढका हुआ है। लोग इससे मंत्रमुग्ध हो जाते हैं.\n\nइस श्लोक को 'जीवन' के पक्ष में और 'भगवान' के पक्ष में दो रूपों में देखा जा सकता है।\nजब 'जीवन' के संदर्भ में देखा जाता है, तो विभु शब्द का अर्थ अद्वितीय, विविध, विभिन्न आदि होता है।\nइच्छा, विचार, ज्ञान से युक्त जीवन जड़ न होकर अद्वितीय है। भिन्न-भिन्न जन्मों में भिन्न-भिन्न\nजो जीवन एक जीवित प्राणी के रूप में जन्म ले सकता है, वह एक ही जन्म में कई रूपों में देखा जा सकता है।\nउदाहरणार्थ: वह जो मनुष्य बन गया। एक अमीर आदमी आनंद में रह सकता है,\nहो सकता है रास्ते में हो. कोई व्यक्ति एक महान विद्वान या एक अज्ञानी मूर्ख के रूप में जी सकता है\nजी सकते हैं इस प्रकार की विविधता जीवन में है—इसलिए जीव विभु। एक जन्म में पैदा हुआ\nमृत्यु तक हमारे पास कई मंजिलों में कई किस्में हैं। क्या महसूस कर सकते हैं\n\nजो अमीर था वह सब कुछ खो सकता है और गरीबी को प्राप्त कर सकता है। फिर हम यह\nहम किसी चीज़ के पीछे कारण ढूंढते हैं। आमतौर पर सबसे पहला काम हम करते हैं\nकिसी ज्योतिषी के पास जाकर प्रश्न पूछना। इस तरह पूछे जाने पर वह कोई है\nवे कहते हैं कि तुम्हें जादू-टोना (/1॥0100721) आदि के कारण हानि हो रही है।\nलेकिन यहाँ कृष्ण कहते हैं: \"तुम किसी का पाप वगैरह लेने नहीं आओगे\nसद्गुण हमें उपलब्ध नहीं है। हम जो कुछ भी अनुभव करते हैं वह हमारे द्वारा किए गए कार्यों का परिणाम है। यह\nयहां यह स्पष्ट है कि यह जानना गलत है कि हम किसी दूसरे के कारण खराब हो गए हैं।\nयदि हां, तो क्या जादू-टोना आदि करना संभव नहीं है, क्या यह सच है कि इससे परेशानी होती है?\nअर्थात्-कोई भी जादू-टोना तब तक हमारी रक्षा करता है, जब तक हमारे सुकृत का फल हमारी रक्षा करता है\nकरते कुछ नहीं हैं। ज्योतिषी यही कहते हैं “तुम्हारा ग्रह अच्छा था इसलिए अब तक कुछ नहीं\nनहीं, लेकिन अब यह ख़राब है” आदि। यहाँ ख़राब ग्रह का अर्थ है हमारा पाप\nइसका मतलब है कि फल किनारे वाला है. तो जो भी हमारे ऊपर कृत्रिम प्रयोग करेगा, उससे\nहमारे बेवफा होने के लिए हमें अतीत में बेवफा होना चाहिए। परिणामस्वरूप यहाँ यह हमारे पास है\nयह अनुभव में आता है. हमारे दोषों, हमारी गरीबी, हमारी अज्ञानता, बीमारी आदि के लिए\nकिसी दूसरे व्यक्ति को यह दिखाना ग़लत है कि उनसे ऐसा हुआ है. जैसे-जैसे बीमारी हमारे लिए बदतर होती गई\nयदि किसी के पास इसका अनुभव करने का प्रारब्धकर्म है तो कोई भी इसे चूक नहीं सकता। इसके लिए\nकिसी दूसरे पर बैठना गलत है. मैं किसी के पाप का फल हूँ\nऐसा नहीं लगता कि मुझे अपने पाप कर्मों का फल भोगना पड़ेगा।\n\nभक्त की ओर से पुजारी द्वारा किया गया कर्म भक्त को मिलता है; पुत्र द्वारा पिता के लिए किया गया कर्म पिता के लिए ही होता है\nआ सकता है...यह. एक दूसरे के लिये. कर्म हो गया. यह अनुष्ठान\n(॥060807) को छोड़कर हम जो अनुभव करते हैं वह हमारे अपने कार्यों का परिणाम है\nकिसी और का नहीं.\n\nचूँकि लोगों को उचित ज्ञान नहीं होता इसलिए वे जानते हैं कि 'मुझे किसी और ने परेशान किया है।'\nइन सबका कारण कर्म के बारे में, जीवन के बारे में, ईश्वर के बारे में उचित ज्ञान का अभाव है।\nज्ञान अज्ञान से ढका हुआ है और इसलिए गलतफहमी और मोह है\nहमें भ्रम ने घेर लिया है.\n\nइस श्लोक के दूसरे पक्ष को देखें तो 'विभु' का अर्थ है सर्वशक्तिमान, सर्वव्यापी\nप्रभु. इस अर्थ में देखें: ईश्वर का कोई कर्म नहीं है। वह जीवन है\nवह प्रकृति में अंतराल की पहचान करता है और तदनुसार विकास देता है। वह कभी नहीं\n\nपक्षपातपूर्ण नहीं. (503! 0630701! 08 टी181टी3! 15 6150 ग्राम/71172000)। पाप और पुण्य दोनों का लेप\n\nउसके पास यह नहीं है. लेकिन भगवान का यह कर्म सिद्धांत, उनकी सर्वशक्तिमानता, और उनकी वैराग्य, जो\nबहुत से लोग जागरूकता नहीं जानते—इसलिए वे ईश्वर के बारे में भ्रमित हैं।\n\nहम हमेशा इस विषय पर रहते हैं कि 'हमारी कोई स्वतंत्र सत्ता नहीं है, हम उसके अधीनस्थ हैं'\nहम भ्रमित हो जाते हैं. यदि सब कुछ ईश्वर ने किया है तो हम पाप कर्म क्यों करें\nयह प्रश्न अधिकांश लोगों को परेशान करता है। कर्म के इस सिद्धांत का आप कितना भी अध्ययन कर लें\nसमझ नहीं आता यह जागरूकता की कमी के कारण है। यह ज्ञान केवल पढ़ने से नहीं आता।\nइसे समझना, अनुभव करना और मनाना चाहिए। इससे कृष्ण भ्रमित नहीं हुए\nउन्होंने अगले श्लोक में बताया है कि कोई मौका नहीं है.\n\nज्ञानेन तु तदज्ञानं यशं नष्टात्मनः |\nतेषामादित्यवज ज्ञानं प्रकाशयति तत् परमं ॥16॥\n\nज्ञानेन तु तत् अज्ञानं यशं नाशिताम् आत्मानः |\nतेषाम् आदित्य वत ज्ञानं प्रकाशयति तत् परम - भगवान के ज्ञान से अज्ञान।\nवह मिटे हुए का बोध-सूर्य की भाँति परत्व को प्रकाशित करता है।\n\nकेवल एक ही तरीका है जिससे हम अपनी उलझन सुलझा सकते हैं। ज्ञान पथ पर\nपूरा करो और सच जानो. हमारी समस्या हमारे भीतर का जीवन है\nप्रकृति में ज्ञान है - लेकिन यह अज्ञान से ढका हुआ है। हम अपने जीवन का स्वभाव हैं\nहमने इसे अज्ञानता के बक्से में मजबूती से बंद कर रखा है। ज्ञान के लिए आवरण अज्ञान है और वह हमारे लिए अज्ञान है\nढक्कन हटाना पसंद नहीं है.\n\nहमें सबसे पहले जानने वाली बात यह है कि 'मेरा मतलब क्या है'। जबकि मुझे यह पता है\nमुझे पता चलेगा कि मेरी सीमा क्या है, मेरी ताकत क्या है, मेरी कमजोरी क्या है। हमारी इंद्रियों का स्वामित्व\nहम नहीं; हम जैसा कहते हैं हमारा दिमाग वैसा नहीं सुनता। तो मैं इन सबके साथ हूँ,\nकिसी ने यह सब यहाँ रख दिया है; अनुभव मेरे द्वारा महसूस की गई समझ से आता है\nजागरुकता पैदा होती है... जो ये इंद्रियाँ देते हैं, जो इनसे अनुभव करते हैं\nजब वह इसे समझता है, तो उसे पता चलता है कि वह केवल ईश्वर का प्रतिबिंब और मूल छवि है\nउठता है.\n\nकृष्ण हमें बताते हैं कि हम कैसे अपनी अज्ञानता का पर्दा हटाकर ज्ञान का मार्ग अपना सकते हैं\nयहां समझाया गया. \"ज्ञान आग की तरह है। ज्ञान की चिंगारी हमेशा आंतरिक होती है।\"\nखूब चमकें. तब यह अज्ञानता का पर्दा जल जायेगा।” निरंतर\nकेवल आंतरिक ध्यान ही हमारे आंतरिक ज्ञान को प्रकाशित कर सकता है। बाह्य श्रवण,\nअध्ययन इसका पूरक है। एक बार अज्ञानता का पर्दा हमें जलाकर सत्य को नष्ट कर देता है\nसाकार हो जायेगा. 'मैंने यह किया' पर गर्व करने का कोई तरीका नहीं है। इस ज्ञान का\nकृष्ण कहते हैं कि अग्नि सूर्य की चमक से भी बड़ी है। बाहरी दुनिया सूर्य कैसे है?\nयह ज्ञान आंतरिक जगत् को ज्यों का त्यों प्रकाशित करता है। यह अप्रत्यक्ष ज्ञान है\nऔर यह ज्ञान ईश्वर की प्राप्ति की ओर ले जाता है।\n\nजब हम कृष्ण की यह व्याख्या सुनते हैं तो हमें लगता है कि हमें भी अप्रत्यक्ष ज्ञान प्राप्त करने की आवश्यकता है।\nलेकिन वह कैसे? यदि अप्रत्यक्ष ज्ञान आना हो तो हमें क्या करना चाहिए? यह अगला है\nकृष्ण ने श्लोक में समझाया.\n\nतद् बुद्धयस्थात्मनस्थाननिष्ठास्तत् परायणः |\nगच्छन्त्य पुनर्वृत्तिं ज्ञाननिर्धूतकला हाः",
  "6.19": "यथा दीपः निवतस्थः न इंगते स उपमा मता।\n\nयोगिनः यशचित्तस्य युञ्जतः योगमात्मनः - बिना हवा वाले स्थान पर दीपक नहीं बुझता।\nयह कुछ इस तरह है: यह ध्यानमग्न योगी के लिए है जो आंतरिक स्व को नरम करता है और भगवान का ध्यान करता है\nरूपक\n\nउस योगी के मन में, जिसने अपने मन को हवा रहित स्थान में जलने वाली आग की लौ की तरह तेज कर लिया है,\n\"ईश्वर के बारे में मन का योग (आत्मयोग)' स्थिर है। यह हिलता नहीं है।\n\nयत्रोपरमते चित्तं निरुद्धं योगसेवया |\n\nयत्र चैव$त्मान55त्मानं पश्यनात्मनि तुस्याति।",
  "6.22": "यं लब्ध्वा च अपरं लाभं मन्यते न अधिकं ततः।\nयस्मिन स्थितः दुःख गुरुना अपि विचल्यते॥\n\nतम् विद्याद् दुःखसंयोगवियोगं योगसंजविथम |\nसा निश्चयेन योक्तव्यो योगोनिर्विन्नचेतसा।",
  "6.10": "योगी युन्जिता शतधाम आत्मानं रहसि स्थितः |\n\nअकाकी यत चित्त आत्मा निराशी अपरिग्रह - योग का अभ्यासकर्ता एकांत में अकेला बैठता है,\nअपने मन को संयमित करो, इच्छा मत करो, किसी चीज को मत छुओ, हमेशा समाधि की ओर जाओ\nपंक्तिबद्ध किया जाना चाहिए.\n\nध्यान के मार्ग में निपुण व्यक्ति मन को निरंतर ध्यान योग में लगाता है\nऔर ध्यान केंद्रित करने का प्रयास करें. यदि भीड़ हो तो ध्यान का अभ्यास करना असंभव है। यह\nइसी कारण से प्राचीन लोग ध्यान के लिए सुबह का समय निर्धारित करते थे।\n\nअगर आप सुबह सूर्योदय से छियानवे मिनट पहले ध्यान के लिए बैठते हैं, तो पूरी प्रकृति\nयह शांतिपूर्ण होगा. यह ऋतु मन को एकाग्र करने के लिए सबसे अनुकूल ऋतु है। यह\nइसे \"ब्रह्ममुहूर्त\" कहा जाता है [सूर्योदय से छियानवे मिनट (चार घंटे) पहले।\nशुरुआत अड़तालीस मिनट (दो घंटे? ब्रह्ममुहूर्त। उदाहरण के लिए) से\nसूर्योदय 5:44 पर लेकिन ब्रह्ममुहूर्त 4:08 से 4:56 तक]। इस मुहूर्त की देवी\nब्रह्मा चतुर्गुण हैं। वह हमारी इच्छा का देवता है. तो यह ऋतु जप, स्मरण और ध्यान की है\nएक महान समय। ध्यान एक अत्यंत अंतरंग क्रिया है। यहाँ केवल भगवान है\nऔर केवल साधक जीव ही होना चाहिए. तीसरा पार्टनर आ गया तो परेशानी होगी. एक प्रदूषित\nमानसी (0॥6196 11176) का व्यक्ति उसके आस-पास का माहौल खराब कर देगा। उसके लिए ध्यान का अभ्यास करें\nअभ्यास करते समय सदैव एकान्त में ही अभ्यास करें। हमारी इच्छा और मन\nइसे नियंत्रण में रखकर, मन में कोई इच्छा या इच्छा न लाते हुए, संतुष्ट मन से ध्यान करें\nकपड़े पहनने चाहिए.\n\nअगले श्लोक में ध्यान के लिए बैठने का स्थान कैसा होना चाहिए और कैसे बैठना चाहिए, इसका वर्णन किया गया है\nकृष्ण बताते हैं.\n\nशुचौ देशे प्रतिष्ठितप्य स्थिरमसनमात्मनः |\nनाथ्युच्छितं नाथिनीचं चेलाजिनकुशोत्तरम्",
  "6.3": "अरुरुक्षो मुनेः योगं कर्म उच्यते |\n\nयोग आरुधस्य तस्य एव शमह वरानम् उच्यते - जो व्यक्ति उपलब्धि की सीढ़ी चढ़ता है, उसके लिए लक्ष्य तक पहुंचना।\nकर्मयोग [कई प्रकार की जनसेवा] ही इसका कारण प्रतीत होता है। भगवद् समाधि जब वह लक्ष्य हो\n[सार्वजनिक सेवा से विश्राम और भगवान में ध्यानपूर्ण भक्ति] से खुशी में वृद्धि होती दिख रही है।\n\nइस श्लोक के दो आयाम हैं. साधक को अपना नित्यकर्म कहाँ तक और कहाँ तक करना चाहिए\nजहां कोई छोड़ सकता है वह एक आयाम है, दूसरा सामाजिक तौर पर कर्ता है\nयह श्लोक बताता है कि कर्तव्य क्या है।\n\nएक साधक जिसने अभी तक सिद्धि प्राप्त नहीं की है, जो सिद्धि के पथ पर है, वह उसी अवस्था में सभी विहितकर्म करता है\nकरते ही होंगे, कुछ भी छोड़ा नहीं जा सकता. जब वह तैयार हुआ तो उसने भगवान को समाधि की अवस्था में पाया\nभीतर से दिखाई देता है. उस अवस्था में बाकी कर्मों की अपेक्षा उसके हृदय में भगवान होते हैं\nदृश्यमान कर्म महत्वपूर्ण है. जिस व्यक्ति ने ज्ञान प्राप्त कर लिया है वह हमेशा समाधि की स्थिति में रहता है\nक्या उसे बाहरी दुनिया में आना ही नहीं चाहिए। तब उनका मुख्य कर्म शास्त्र श्रवण था,\nमंत्र जप, प्रवचन आदि। अत: विहितकर्म का निषेध अप्रत्यक्ष ज्ञान तक ही सीमित है\nउदाहरण के लिए, एक अपरोक्ष ज्ञानी ध्यान में बैठा है।  वह अपने अंदर ही है\nप्रभु के दर्शन किये और उस आनंद में डूब गये। भोर-सूर्योदय हो चुका था\nसमय हमारा मानना है कि वह स्नान और ध्यान करते समय ध्यान में नहीं बैठे थे\nउसे जगाना ग़लत था. यदि वह ध्यान नहीं करेगा तो कोई कर्म दोष नहीं होगा।\nक्योंकि पूजा तो भगवान के दर्शन के लिए है। लेकिन वह पहले से ही ईश्वर का दर्शन है\nप्राप्त हो रहा है इस प्रकार अप्रत्यक्ष ज्ञान की कोई कर्म प्रतिबद्धता नहीं है। समाधि अवस्था से बाहर आने के बाद\nइरातक्का कर्तव्य का अर्थ है ईश्वर की स्तुति, प्रवचन, अध्ययन, जप आदि।\n\nइस श्लोक के एक और आयाम का वर्णन माधवाचार्य ने बहुत सुंदर ढंग से किया है\nगीतात्पर्य में बताया गया है। यह मुख्य रूप से इस बारे में है कि एक अभ्यासकर्ता को सामाजिक रूप से कैसा व्यवहार करना चाहिए\nबताते हैं कि आचार्य ने कर्म को अनोखा अर्थ दिया है।\nकर्म का अर्थ है कर्म। कारा का अर्थ है राजस्व (06॥))। हम जानते हैं कि राजस्व क्या है\nजो किया जाना चाहिए वह है \"कर-मा'। हम भगवान के राज्य में नागरिक हैं। इसके लिए, हम उसके हैं\nदेने का कर्म. यह सच है कि हम किसी मनोकामना से मंदिर में चढ़ावा चढ़ाते हैं\nराजस्व नहीं. भगवान ऐसा नहीं चाहते. वह कर्म जो ईश्वर हमसे चाहता है\nजरूरतमंदों की देखभाल करना. यह उसकी प्राप्ति में तब तक है जब तक कोई साधक अप्रत्यक्ष साधक नहीं बन जाता\nएक बड़ी उपलब्धि. सभी प्राणियों के प्रति दया और सेवा बहुत महत्वपूर्ण है।\nऐसा योग शास्त्र में भी कहा गया है। ये चार हैं मैत्री, करुणा, मुदिता और उपेक्षा\n\nमनोवृत्ति अभ्यासी में होनी चाहिए। गठबंधन का अर्थ है सज्जनों का साथ। जहां अच्छाई है वो उनकी है\nस्नेहा जब तुम दुख देखते हो तो दया और सहायता होती है - दया।  दूसरे का उद्धार देखें\nखुश रहना प्यारा है. बुराई से दूर रहना लापरवाही है। लेकिन बुरे लोगों से मत लड़ो\nबिना किसी शिकायत के उनकी संगति से दूर रहना लापरवाही है। इस प्रकार यह एक अभ्यासी के जीवन में है\nएक महान सामाजिक कर्तव्य. एक सिद्ध (योगारूढ़) हमेशा अंतर्मुखी होता है।\nउसकी यह सामाजिक प्रतिबद्धता नहीं है (नहीं हो सकती)। उनकी ख़ुशी की वजह\n'शायद। इसका मतलब यह है कि मन हमेशा भगवान में ही लगा रहता है। दूसरा इसके विपरीत है\nउसका कोई कर्म नहीं है.\n\nइस प्रकार कृष्ण ने कहा कि लोक सेवा एक साधक का अभिन्न अंग होनी चाहिए\nश्लोक में स्पष्ट रूप से कहा गया है। योगारूढ़ की कोई सामाजिक प्रतिबद्धता नहीं है, वह\nवह अपने भीतर भगवान को देखता है। जब कृष्ण ने ऐसा कहा, तो हमारे पास एक प्रश्न है\nउठ सकते हैं ऐसे अप्रत्यक्ष ज्ञान को कैसे पहचानें। अगला श्लोक यह है\n\nहमारे प्रश्न का उत्तर रूप में है।\n\nयदा हि नेन्द्रियार्थेषु न कर्मस्वानुशज्जते |\n\nसर्वसंकल्प संन्यासी योगरूढ़स्थदोच्यते",
  "6.26": "यतः यतः निश्चरति मनः चंचलं शिवनम् |\n\nतत: तत: न्याम्य एतत् आत्मानि एव वशं नयेत् - बिना अकड़न के ऊपर कैसे बढ़ें,\nजहाँ कहीं भी वह बहती थी, वह दोनों ओर से वापस लुढ़क जाती थी और प्रभु में स्थिर हो जाती थी\nलाया जाना चाहिए\n\nहमारा मन बहुत चंचल है. इस कारण यह द्वीप की ओर बहती रहती है। यह जहां भी है\nयदि वह फिसल जाए, तो ईश्वर नामक तटबंध लगा दो, ताकि ईश्वर में उसका पैर न टिके।\nइसके लिए निरंतर प्रयास की आवश्यकता है.",
  "6.30": "सर्वभूतस्थितं यः मम भजति एकत्वं स्थितः |\nसर्वथा वर्तमान: अपि सः योगी मयि वर्तते - जो सभी प्राणियों में समान रूप से मेरी पूजा करता है, वह किसी भी स्थिति में मुझमें ही रहता है।\n\nकृष्ण कहते हैं: \"जिस तपस्वी के पास निरंतर भक्ति है और यह एहसास है कि भगवान हर जगह एक समान हैं, चाहे वह कोई भी हो, वह मुझसे जुड़ने के लिए बाध्य है।\" जिसके पास अपरोक्ष ज्ञान है वह कभी भी भगवान से दूर नहीं जाता। वह मोक्ष प्राप्त करता है और भगवान में निवास करता है।",
  "6.6": "उद्धरेथ आत्मान आत्मानं न आत्मानं अवसादयेत |\n\nआत्मा एवहि आत्मानः बन्धुः आत्मा एव रिपुः आत्मानः - शक्ति से [भगवान की कृपा से]\nजीवन को ऊपर उठाना होगा; जीवन बर्बाद नहीं करना चाहिए. प्रभु स्वयं जीवन का मित्र है;\nइस प्रकार [भगवान] जीवन का शत्रु है।\n\nजैसा कि पहले बताया गया है, आत्मा शब्द के कई अर्थ हैं। आत्मा का अर्थ है शरीर, मन, जीवन,\nईश्वर है इस प्रकार ये सभी अर्थ इस श्लोक में आत्मा शब्द से जुड़े हैं\nबहुत सी बातें स्पष्ट हो जाती हैं. \"उद्धरेथ आत्मान आत्मानं न आत्मानं अवसादयेत\"\nअर्थात मन ही हमारे पतन का कारण है।  हमारी मुक्ति का कारण मन है।  इसलिए\nकृष्ण कहते हैं, मन (आत्मान) से जीवन (आत्मानम) तक मुक्ति का मार्ग खोजें। कभी नहीं\nमन को नीचे मत भेजो. एक मन जो आत्मा (जीवन) के अंत की ओर ले जाता है।\nढीला मत छोड़ो. ऊपर ले जाना। यदि मन नीचे चला जाता है तो वह हम हैं\nरसातल में धकेल कर चला जाता है। \"उस मन को और ऊपर भेजो। जो मन ऊपर जाता है, वह तुम्हें और ऊपर उठाता है।\"\nमन के साथ अपने जीवन स्वरूप का उद्धार करता है। मन जीवन सापेक्ष है,\nमन ही शत्रु है. इसलिए यदि आप सफलता प्राप्त करना चाहते हैं तो अपने मन को सापेक्ष बना लें।\nयदि मन आपका शत्रु बन जाए तो आपके जीवनकाल में कोई मुक्ति नहीं है। उसके लिए पहले बुद्धि से\n\nकृष्ण का संदेश मन को प्रशिक्षित करना और उसे जीतना है। मन को जीतना ही सब कुछ है\nशांत, कोई भ्रम नहीं. यह ध्यान के लिए एक शर्त है।\n\nजब हम कृष्ण का यह सन्देश सुनते हैं तो एक प्रश्न उठता है। जैसा कि स्वयं कृष्ण ने पहले कहा था\nहमारे हाथ में कुछ भी नहीं है. ईश्वर की कृपा के बिना हम कभी भी अपने मन को मुक्त नहीं कर सकते\nनियंत्रित नहीं किया जा सकता. तो हम अपने मन को कैसे नियंत्रित कर सकते हैं? ये हमारा है\nइस श्लोक में इस प्रश्न का उत्तर है। इस श्लोक में आत्मा का अर्थ सर्वोच्च है\nजब हम देखते हैं तो हमें अपने प्रश्न का उत्तर मिल जाता है। “उद्धरेथ आत्मान आत्मानम्” अर्थात्\n\"आत्मा (जीवन) को आत्मा (स्वयं ईश्वर से) से मुक्त किया जाना चाहिए। सामान्य रूप से मन\nहमारी बात नहीं सुनता. मन कहता है \"मैं यह नहीं कर सकता\"। परन्तु प्रभु हमारे लिये\nउन्होंने हमें बुद्धि दी है, हमें उसका उपयोग करना चाहिए। उस प्रभु में बुद्धि लगाओ\n“मुझे सद्बुद्धि दो, मोक्ष के, सिद्धि के मार्ग में मेरा मार्गदर्शन करो\nउस प्रभु से प्रार्थना करते रहो, \"मुझे शांति दो।\" वह हमारा सबसे प्रिय है\nपरोपकारी भाई. वही निःस्वार्थ, शाश्वत, अविभाज्य, नित्य संबंधी है। वह है\nनिश्चय ही वह हमारी प्रार्थनाओं को क्षमा करेगा और हमारे मन में आकर विराजमान होगा।\n\nवह स्वयं को उसी प्रकार प्रकट करता है जैसे हम ईश्वर को देखते हैं। देवदूत उसे\nएक बुद्धिमान व्यक्ति के रूप में देखा गया - वह उन्हें एक बुद्धिमान व्यक्ति के रूप में दिखाई दिया और उन्हें बचाया। राक्षस वह हैं\nवे उससे नफरत करते थे, यह जानते हुए कि वह हत्यारा और शत्रु है - वह उन्हें शत्रु के रूप में दिखाई देता था।\nतो कृष्ण कहते हैं: \"आत्म एव रिपुः आत्मानः\"। इसका मतलब है कि हम अहंकार से बहुत दूर हैं\nगलत होने पर वह हमारा दुश्मन लगता है। अगले श्लोक में इस पर और भी बहुत कुछ है\nप्रकाश डालता है.\n\nबन्धुरात्मा$5त्मानस्तस्य येन*तमैव*त्मान जितः |\nअनात्मनस्तु शत्रुत्वे वर्तते*तमैव शत्रुवत् 16\n\nअनात्मनः तु शत्रुत्वे वर्तते आत्मा एव शत्रुवत् - क्या जीवन बुद्धिमानी से निपटाया जाता है।\nजो [भक्ति से भगवान] को जीत सकता है [जिससे जीवन संयमित होता है], ऐसा\n[भगवान] जीवन भर का मित्र है। जो भगवान को नहीं पा सकता वह भगवान है\nशत्रु के समान शत्रु।\n\nजिसने प्रभु को जीत लिया है वह प्रभु के प्रेम का पात्र है) वह उसका रिश्तेदार है।\nईश्वर के प्रेम के योग्य होने के लिए, हमें उसकी कृपा की आवश्यकता है। उसे अपनी कृपा से तृप्त करो\nवह उन लोगों का रिश्तेदार है जो प्यार के हकदार हैं। जो लोग ईश्वर से मुँह मोड़कर आगे बढ़ गये\nसदैव ईश्वर से दूर जाना। वह उन लोगों के लिए शत्रु के समान है जो उससे मुँह मोड़ लेते हैं और उससे घृणा करते हैं\nदेखो, इस कारण नित्य प्रभु से प्रार्थना करो। “एक रिश्तेदार के रूप में मेरे पास आओ\nबस जाओ, मुझे सही रास्ते पर ले चलो, मुझे अपनी ओर मोड़ो और मुझे आगे ले चलो”\nप्रार्थना और समर्पण हमारे मन को उस पर स्थिर कर देते हैं। ये है\nध्यान की ओर पहला कदम. इस प्रकार मन को वश में करने के लिए भगवान की कृपा प्राप्त करने का एक प्रयास\nआइए देखें कि निम्नलिखित श्लोक में ऐसा करने पर क्या होता है।\n\nजितात्मनः प्रशांतस्य परमात्मा समाहितः |\nशीतोष्टसुखदुःखेसु तथा मनापमानयोः",
  "6.15": "युञ्जन एवं सदा आत्मानं योगी नियत मनसः |\n\nशांतिम् निर्बान परमम् मत संस्थम् अधिगच्छति - इस प्रकार भगवान सदैव हैं\nवह सुख जो ध्यान करने वाला शरीर छोड़ने के बाद मार्ग को पकड़कर रखता है, मुझमें निवास करता है\nमहसूस होता है\n\nइस अध्याय में अब तक कृष्ण ने मन से किये जाने वाले ध्यान की व्याख्या की है। बाह्य भाव\nध्यान मन और आत्मा को शांत करने, नियंत्रित करने के बारे में है। इससे परे\n'तुरियावस्ताबा'। आत्म-साक्षात्कारी जीवन हमारे मन को पूरी तरह से शांत करके प्रत्यक्ष होता है\nप्रभु के दर्शन की अवस्था अत्यावश्यक अवस्था है। इस श्लोक में कृष्ण स्थिति का संकेत देते हैं।\nयह विचार यहीं रहस्य में छिपा हुआ है।\n\nध्यान में हम जो देखते हैं वह प्रत्यक्ष भगवान नहीं बल्कि भगवान का प्रतीक है। क्योंकि मन\nज्ञानस्वरूप भगवान को कोई प्रत्यक्ष रूप से अनुभव नहीं कर सकता। सीधे भगवान से\nसाक्षात्कार के लिए व्यक्ति को ध्यान से परे चेतना की अवस्था में जाना होगा। जीवित आँख से\nभगवान का दर्शन करना चाहिए. मन को मन के द्वारा निरंतर भगवान पर स्थिर करो\nध्यान में भगवान के मानसिक स्वरूप का दर्शन कर मन को शांत करना चाहिए। तब\n\nचेतना की अवस्था जागृत होती है. इस अवस्था में आत्मा प्रभु का मिलन बन जाती है। फिर\nइससे ईश्वर का प्रत्यक्ष दर्शन हो सकता है। जो ध्यानी इस अवस्था तक पहुँच जाता है वही सच्चा योगी होता है\nमहसूस होता है\n\nजीवन अपनी प्राप्ति के पथ पर जो सबसे बड़ा आनंद प्राप्त कर सकता है, उसकी पराकाष्ठा है-\nप्रभु की प्राप्ति. आनंद की कोई अन्य जागरूकता, कोई अन्य दृष्टि नहीं है। इस तरह\nजिस व्यक्ति को भगवान का एहसास हो गया है वह फिर कभी इस संसार बंधन में नहीं फँसेगा।  वह है\nप्रभु में स्थिर रहने से उसे मोक्ष मिलता है।\n\nकृष्ण पूछते हैं कि समाधि का अभ्यास करने वालों की जीवनशैली कैसी होनी चाहिए\nसमझाता है. यह वर्कआउट सिर्फ ध्यान का पूरक नहीं है। हमारे अध्ययन के लिए, हमारे\nस्वस्थ जीवन के लिए यह अनुशासन बहुत महत्वपूर्ण है। हमारे प्रत्येक कार्यान्वयन के लेखक\nतदनुसार डिजाइन किया गया। लेकिन आज हमारे पास यह AIHC नहीं है. एकादशी\nचाहे उपवास हो या कोई अन्य अभ्यास, इसे ध्यान के पूरक के रूप में अपनाया जाना चाहिए। यह\nबिना ज्ञान के. बस यंत्रवत. कोई भी कार्यान्वयन जो पालन करता है वह हमें ऊपर उठाता है\n\nले जाने में असमर्थ.",
  "6.5": "उद्धरेथ आत्मान आत्मानं न आत्मानं अवसादयेत |\n\nआत्मा एवहि आत्मानः बन्धुः आत्मा एव रिपुः आत्मानः - शक्ति से [भगवान की कृपा से]\nजीवन को ऊपर उठाना होगा; जीवन बर्बाद नहीं करना चाहिए. प्रभु स्वयं जीवन का मित्र है;\nइस प्रकार [भगवान] जीवन का शत्रु है।\n\nजैसा कि पहले बताया गया है, आत्मा शब्द के कई अर्थ हैं। आत्मा का अर्थ है शरीर, मन, जीवन,\nईश्वर है इस प्रकार ये सभी अर्थ इस श्लोक में आत्मा शब्द से जुड़े हैं\nबहुत सी बातें स्पष्ट हो जाती हैं. \"उद्धरेथ आत्मान आत्मानं न आत्मानं अवसादयेत\"\nअर्थात मन ही हमारे पतन का कारण है।  हमारी मुक्ति का कारण मन है।  इसलिए\nकृष्ण कहते हैं, मन (आत्मान) से जीवन (आत्मानम) तक मुक्ति का मार्ग खोजें। कभी नहीं\nमन को नीचे मत भेजो. एक मन जो आत्मा (जीवन) के अंत की ओर ले जाता है।\nढीला मत छोड़ो. ऊपर ले जाना। यदि मन नीचे चला जाता है तो वह हम हैं\nरसातल में धकेल कर चला जाता है। \"उस मन को और ऊपर भेजो। जो मन ऊपर जाता है, वह तुम्हें और ऊपर उठाता है।\"\nमन के साथ अपने जीवन स्वरूप का उद्धार करता है। मन जीवन सापेक्ष है,\nमन ही शत्रु है. इसलिए यदि आप सफलता प्राप्त करना चाहते हैं तो अपने मन को सापेक्ष बना लें।\nयदि मन आपका शत्रु बन जाए तो आपके जीवनकाल में कोई मुक्ति नहीं है। उसके लिए पहले बुद्धि से\n\nकृष्ण का संदेश मन को प्रशिक्षित करना और उसे जीतना है। मन को जीतना ही सब कुछ है\nशांत, कोई भ्रम नहीं. यह ध्यान के लिए एक शर्त है।\n\nजब हम कृष्ण का यह सन्देश सुनते हैं तो एक प्रश्न उठता है। जैसा कि स्वयं कृष्ण ने पहले कहा था\nहमारे हाथ में कुछ भी नहीं है. ईश्वर की कृपा के बिना हम कभी भी अपने मन को मुक्त नहीं कर सकते\nनियंत्रित नहीं किया जा सकता. तो हम अपने मन को कैसे नियंत्रित कर सकते हैं? ये हमारा है\nइस श्लोक में इस प्रश्न का उत्तर है। इस श्लोक में आत्मा का अर्थ सर्वोच्च है\nजब हम देखते हैं तो हमें अपने प्रश्न का उत्तर मिल जाता है। “उद्धरेथ आत्मान आत्मानम्” अर्थात्\n\"आत्मा (जीवन) को आत्मा (स्वयं ईश्वर से) से मुक्त किया जाना चाहिए। सामान्य रूप से मन\nहमारी बात नहीं सुनता. मन कहता है \"मैं यह नहीं कर सकता\"। परन्तु प्रभु हमारे लिये\nउन्होंने हमें बुद्धि दी है, हमें उसका उपयोग करना चाहिए। उस प्रभु में बुद्धि लगाओ\n“मुझे सद्बुद्धि दो, मोक्ष के, सिद्धि के मार्ग में मेरा मार्गदर्शन करो\nउस प्रभु से प्रार्थना करते रहो, \"मुझे शांति दो।\" वह हमारा सबसे प्रिय है\nपरोपकारी भाई. वही निःस्वार्थ, शाश्वत, अविभाज्य, नित्य संबंधी है। वह है\nनिश्चय ही वह हमारी प्रार्थनाओं को क्षमा करेगा और हमारे मन में आकर विराजमान होगा।\n\nवह स्वयं को उसी प्रकार प्रकट करता है जैसे हम ईश्वर को देखते हैं। देवदूत उसे\nएक बुद्धिमान व्यक्ति के रूप में देखा गया - वह उन्हें एक बुद्धिमान व्यक्ति के रूप में दिखाई दिया और उन्हें बचाया। राक्षस वह हैं\nवे उससे नफरत करते थे, यह जानते हुए कि वह हत्यारा और शत्रु है - वह उन्हें शत्रु के रूप में दिखाई देता था।\nतो कृष्ण कहते हैं: \"आत्म एव रिपुः आत्मानः\"। इसका मतलब है कि हम अहंकार से बहुत दूर हैं\nगलत होने पर वह हमारा दुश्मन लगता है। अगले श्लोक में इस पर और भी बहुत कुछ है\nप्रकाश डालता है.\n\nबन्धुरात्मा$5त्मानस्तस्य येन*तमैव*त्मान जितः |\nअनात्मनस्तु शत्रुत्वे वर्तते*तमैव शत्रुवत् 16\n\nबन्धुः आत्मा अता त तस्य येन आत्मा एव आत्माना जितः।\n\nअनात्मनः तु शत्रुत्वे वर्तते आत्मा एव शत्रुवत् - क्या जीवन बुद्धिमानी से निपटाया जाता है।\nजो [भक्ति से भगवान] को जीत सकता है [जिससे जीवन संयमित होता है], ऐसा\n[भगवान] जीवन भर का मित्र है। जो भगवान को नहीं पा सकता वह भगवान है\nशत्रु के समान शत्रु।\n\nजिसने प्रभु को जीत लिया है वह प्रभु के प्रेम का पात्र है) वह उसका रिश्तेदार है।\nईश्वर के प्रेम के योग्य होने के लिए, हमें उसकी कृपा की आवश्यकता है। उसे अपनी कृपा से तृप्त करो\nवह उन लोगों का रिश्तेदार है जो प्यार के हकदार हैं। जो लोग ईश्वर से मुँह मोड़कर आगे बढ़ गये\nसदैव ईश्वर से दूर जाना। वह उन लोगों के लिए शत्रु के समान है जो उससे मुँह मोड़ लेते हैं और उससे घृणा करते हैं\nदेखो, इस कारण नित्य प्रभु से प्रार्थना करो। “एक रिश्तेदार के रूप में मेरे पास आओ\nबस जाओ, मुझे सही रास्ते पर ले चलो, मुझे अपनी ओर मोड़ो और मुझे आगे ले चलो”\nप्रार्थना और समर्पण हमारे मन को उस पर स्थिर कर देते हैं। ये है\nध्यान की ओर पहला कदम. इस प्रकार मन को वश में करने के लिए भगवान की कृपा प्राप्त करने का एक प्रयास\nआइए देखें कि निम्नलिखित श्लोक में ऐसा करने पर क्या होता है।\n\nजितात्मनः प्रशांतस्य परमात्मा समाहितः |\nशीतोष्टसुखदुःखेसु तथा मनापमानयोः",
  "6.9": "सुह्रुत मित्र अरि उदासीन मदस्थ हठ्या भयावहशु।\n\nसाधुषु अपि च पापेषु समबुद्धिः विशिष्यते - जो कठिन समय में बिना किसी परवाह के धारण करता है।\nवे जो चेतावनी देते हैं, वे जो सावधान करते हैं, वे जो न तो अच्छे हैं और न ही बुरे, वे जो दोनों के लिए खड़े हैं,\nउद्धारकर्ता, धर्मी, अच्छा और बुरा - सभी मूल रूप से ज्ञान के रूप हैं\nजो समभाव से देखता है [वह जो सभी का उनके मूल्य के अनुसार सम्मान करता है]\nबाकी\n\nसंतुलित मन के बिना कोई ध्यान नहीं कर सकता। किसी के बारे में कुछ\nयदि मन में विचार घूमने लगें तो ध्यान करना असंभव है। दुनिया में कई तरह के\nवहाँ लोग हैं. उदाहरण के लिए सुहृतस - अर्थात अच्छे हृदय वाले। कैसा पारस्परिक व्यवहार है\nकुछ लोग ऐसे भी होते हैं जो न चाहते हुए भी हर किसी की मदद करते हैं। इसके बाद 'मित्र'- सदैव अपने प्रिय को\nसहायक, वह जो गलती होने पर हमें सुधारता है। स्वीकृतियाँ: एक भयानक शत्रुता जो मार डालती है\nसफल लोगों के पास नफरत करने का कोई कारण नहीं है। उदासीन: वे न तो अच्छे हैं और न ही बुरे।\nमध्यस्थ: जो अच्छा करने पर अच्छा करता है, बुरा करने पर बुरा करता है। नफरत: कोई\nअसहनीय (ga8866)। अंत में रिश्तेदार (16180%65)। इस प्रकार मानव जाति में\nअच्छे और बुरे भरे पड़े हैं।\nदेवता तो साधु ही होते हैं, असुर तो पापी ही होते हैं, लेकिन मनुष्यों में ये दोनों ही हैं\nविशिष्ट समूह पाए जा सकते हैं)। सबसे पहले, अगर हम ध्यान में भगवान को देखना चाहते हैं\nहमें इन सभी प्रकार के लोगों के प्रति अपने अंदर समभाव का भाव विकसित करना चाहिए। एक\nकिसी व्यक्ति का व्यवहार उस वातावरण के कारण होता है जिसमें वह बड़ा हुआ है या समझ की कमी के कारण होता है\nयह जानकर कि वह आया है, उसे यह ध्यान रखना चाहिए कि उसके मन में कोई बुरी भावना न हो।\nकोई हमें दुश्मन की तरह परेशान कर सकता है. इसका कारण उनका और हमारा है\n\nकर्म हो सकता है. वह इस जीवन में उस भूमिका को निभा रहा है जो भगवान ने उसे दी है\nजब हम उसे भाव में देखते हैं तो हमें घृणा नहीं होती। जब कोई दूसरा हमें डांटता है तो हम\nघबराओ मत. \"भगवान ने उन्हें जो भूमिका दी है उसे वह बहुत अच्छे से निभा रहे हैं\"\nहमें यह महसूस करना चाहिए. चाहे रिश्तेदार हो, चाहे दुश्मन हो, चाहे कोई भी हो। ध्यान के दौरान\nमन में शुद्ध समभाव स्थापित करना चाहिए। इस अवस्था में ध्यान के लिए बैठने पर यही सब होता है\nउस प्रभु को बिना सामने आये भी देखा जा सकता है। यहां ध्यान रखने योग्य एक बात आंतरिक है\nसमानता को बाहरी दुनिया में व्यावसायिक तौर पर लागू नहीं किया जा सकता. हम व्यवसाय के रूप में हैं\nमैत्री, करुणा, मुदिता और उपेक्षा ये चार मानसिक अवस्थाएँ हैं जिनका पहले उल्लेख किया गया है\nखेती की जानी चाहिए. सभी के साथ समान व्यवहार करने का अर्थ है उन्हें उनके स्थान पर रखना\nदेखना बिजनेस जगत का नजरिया है. पिता पिता के समान, पुत्र पुत्र के समान\nतलाश करना, बुराई से दूर रहना (बाद में व्यापारिक दुनिया... भीतरी)।\nसंसार में हमें प्रत्येक व्यक्ति में उसके भीतर के प्रभु को ही देखना चाहिए। यह ध्यान के लिए है\nपूर्वापेक्षा मन की स्थिति. मानसिक रूप से ध्यान से सारा लगाव हटा दें\nबैठना चाहिए. ध्यान में पिता, माता, गुरु, शिष्य, शत्रु, मित्र आदि सभी की श्रेणियां नहीं होतीं\nअकेला, यह केवल ज्ञानस्वरूप जीव है - जिसके भीतर भगवान की छवि है। यह ध्यान के लिए है\nमन की वांछित स्थिति.\n\nइस प्रकार ध्यान की पूर्व तैयारी बताकर कृष्ण ध्यान के लिए उनके ठीक सामने बैठ गए\nविधि बताते हैं.\n\nयोगी युन्जिता सत्समात्मनं रहसि स्थितः |\nअकेले यसचित्तात्मा निराशिरापरिग्रह:",
  "6.17": "युक्त भोजन विहारस्य युक्त चेष्टा सय कर्मसु।\nयुक्ता स्वप्ना अवबोधस्य योगः भवति दुख हा-- तक्का तिनिसु-तिरुगता, तक्कतेह कायका, तक्कन्ते\nजिसने निद्रा-जागरण प्राप्त कर लिया है वह ध्यान योग से दूर है।\n\nयोगाभ्यास करते समय हमारी दिनचर्या अनुशासित होनी चाहिए।  नियमित भी\nउचित आहार बहुत महत्वपूर्ण है। सात्विक भोजन का सेवन मन को ध्यान के लिए तैयार करता है\nध्यान का पूरक. कुछ खाद्य पदार्थ हमारे दिमाग पर बुरा प्रभाव डालते हैं। उदाहरण के लिए\nप्याज और लहसुन. हालाँकि इनमें औषधीय गुण हैं, यह बात हमारे मन में है\nप्रभावित भोजन. जिस दिन हम ज्यादा प्याज या लहसुन खाते हैं वह दिन हमारे लिए बुरा होता है\nस्वप्न देखना इस बात का प्रमाण है कि यह आहार मन पर प्रभाव डालता है [लेकिन डॉ\nअगर स्वास्थ्य कारणों से इसे औषधि के रूप में लेने की बात कही जाए तो इसे खाने में कोई दिक्कत नहीं है\nनहीं, क्योंकि अध्ययन के लिए राशि से पहले स्वास्थ्य की आवश्यकता होती है]। ऐसे ही वे लोग हैं जो वेदों का अध्ययन करते हैं\nमन खराब करने वाला भोजन न करें। साथ ही हमारे शरीर से लेकर दिमाग तक को पोषण देता है\nयहाँ कृष्ण सात्विक पोषण देने वाले भोजन को \"युक्ताहार\" कहते हैं।\n\nअपने दिमाग को उतना आराम देना बहुत ज़रूरी है जितना हमें चाहिए। लेकिन यह विराम\nआलसी मत बनो. मन को विश्राम देते समय क्या विचार करें?\nबिना कुछ किए पूरा आराम देना चाहिए। तब मन ध्यान के पूरक के रूप में कार्य करता है।\n“युक्तचेस्तस्य कर्मसु” वह कार्य है जो हमें व्यवस्थित ढंग से करना है\nहमें इसे स्वयं करना होगा. किये जाने वाले कार्यों में आलस्य नहीं करना चाहिए।\n\nशास्त्रीय स्वच्छ नियमित आहार, उचित नींद और उचित समय पर जागना,\nनियमित परिश्रम और आराम - जब \"योगो भवति दुःख\" हो - कोई कष्ट नहीं\nआनंदमय जीवन संभव है.\n\nध्यान मन को एक स्तर पर लाता है। जब मन शांत होता है तो हम बाहरी दुनिया में होते हैं\nसुख-दुख को वैराग्य से देखने की आदत बन जाती है। इससे जब ख़ुशी मिलती है\nदुःख आने पर न उड़ना, न रसातल में गिरना। सुख-दुःख, हार-जीत का द्वंद्व\nजीवन में समता ध्यान योग से आती है।",
  "6.14": "समं काया शिरः शोकं धारयं अचलं स्थिरः।\n\nसम्प्रेक्ष्य नासिका अग्रं स्वं दिशः च अनवलोकायन |\n\nप्रशांत आत्मा विगतेः ब्रह्मचारिवृत्ते स्थितः |\n\nमनः संयम्य मत चित्तः युक्तः असिता मत परः - पीठ-सिर-गर्दन को बिना झुकाए सीधा रखें।\nअकड़ा हुआ बैठा है, इधर-उधर नहीं देख रहा है, सीधे अपनी नाक की नोक पर चीजों को देख रहा है\nबिना प्रवाह के स्वभाव वाला, निर्भीक, ब्रह्मचारी, स्वयं को भगवान मानने वाला\nसमाधि भीगकर प्राप्त करनी चाहिए।\n\nध्यान के लिए बैठते समय हमारा शरीर कमर से ऊपर तक एक सीधी रेखा में होना चाहिए। पीछे\nधनुष, गर्दन, सिर. झुका हुआ नहीं होना चाहिए. शरीर को स्थिर रखना चाहिए. थोड़ा सा\nहिलाओ मत. ऐसे बैठे बिना मन की स्थिरता असंभव है। मन ही यह शरीर है\nजैसे घड़े में पानी. बर्तन हिल जाए तो मन में पानी तरंग पैदा कर देता है। इससे\nएकाग्रता भंग होती है.\n\nशरीर में एक और महत्वपूर्ण अंग है आँख। शरीर को स्थिर करने के बाद आंख को स्थिर करें।\nकिसी भी दिशा में कोई आकृति न देखते हुए दृष्टि को नाक की नोक पर स्थिर और एकाग्र करना\nदृष्टि दूसरी ओर स्थिर रखनी चाहिए\nकरने की अधिक संभावना है)।\n\nइस प्रकार जब ध्यान की स्थिति आ जाती है तो मन शांत हो जाता है। बिना किसी भ्रम के\nइस अवस्था में हमें एक अजीब, अवर्णनीय आनंद की स्थिति का अनुभव होता है। ये सब हमारे लिए है\nडर भी दूर हो जाता है. ध्यान का एक अन्य महत्वपूर्ण पहलू ब्रह्मचर्य है\nपालन-पोषण यहाँ ब्रह्मचर्य शब्द के तीन अर्थ हैं। परब्रह्म की ओर दीक्षा-\nब्रह्मचर्य; सतत वेदाध्ययन-ब्रह्मचर्य; जो परिवार के सदस्य हैं. नियमित सेक्स\nपालन [सेक्स से बहुत आसानी से और नियमित रूप से हटने की क्षमता\nसेक्स] और विरक्तियों का सेक्स-मुक्त जीवन (आभासी ब्रह्मचर्य)-ब्रह्मचर्य। प्रभु\nसदैव परमेश्वर के प्रति अटूट भक्ति के साथ, भगवान पर पूर्ण विश्वास के साथ\nव्यक्ति को भगवान को आत्मसात करके समाधि प्राप्त करनी चाहिए और कभी हिम्मत नहीं हारनी चाहिए।\n\nध्यान का प्रभाव क्या है? हमें ध्यान क्यों करना चाहिए? उत्तर अगला श्लोक है!\n\nअगली कविता का विश्लेषण करने से पहले यहां वह कविता है जो आमतौर पर हर किसी को परेशान करती है\nआइए सबसे सामान्य प्रश्न का विश्लेषण करें। युद्ध के मैदान में खड़े अर्जुन के लिए कृष्ण भगवद गीता\nउपदेश दिया. ऐसे में वह ध्यान के लिए, ध्यान के लिए, ध्यान के लिए बैठेगा\nविधि का उल्लेख क्यों करें? क्या जरूरत थी? यह एक सामान्य प्रश्न है जो हर किसी को परेशान करता है।\nदरअसल, अर्जुन के पास ये सवाल नहीं थे, अर्जुन का सवाल अलग था. उस प्रश्न का उत्तर\nजब आम तौर पर देते समय ध्यान का प्रश्न सामने आता है, तो कृष्ण पूरे तंत्रिका समुदाय की मदद करते हैं\nसंपूर्ण ध्यान प्रक्रिया समझाई। युद्ध के मैदान में कृष्ण अर्जुन के प्रति बहुत संवेदनशील हैं\nहमें नहीं पता कि उन्होंने पढ़ाया या नहीं. लेकिन व्यास महर्षि ने इसका रहस्योद्घाटन कर दिया\nएक अध्याय के रूप में हमारे समक्ष प्रस्तुत है।  अर्जुन को भगवद्गीता का उपदेश देना\nबनाते समय कृष्ण के सामने सिर्फ अर्जुन ही नहीं थे; सम्पूर्ण सात्विक नाड़ी समुदाय। सब\nसात्विक लोगों को सत्य का मार्ग दिखाने के उद्देश्य से ही गीता का उपदेश दिया गया था। यह स्रोत है\nहम स्मरण कर सकते हैं कि श्री कृष्ण ने इसी उद्देश्य से एक बार फिर उद्दावन को गीता का उपदेश दिया था।",
  "6.39": "एतन्मे संशयं कृष्ण छेत्तुमर्हस्यशेषतः ।\nत्वदन्यः संशयस्यास्य छेत्ता न ह्युपपद्यते ॥\n\n'हे कृष्ण, इस मेरे संशय को पूर्णतः काटने में आप ही समर्थ हैं — आपके अतिरिक्त इस संशय का काटने वाला कोई नहीं।'\n\nअर्जुन का यह विनम्र स्वीकृति — भगवान् ही एकमात्र उत्तर दे सकते हैं। 'त्वदन्यः' — आपके अतिरिक्त। 'न उपपद्यते' — सम्भव नहीं। भक्त की शरणागति — यही प्रश्न का उचित समापन।",
  "6.27": "प्रशांत मनसं हि एनं योगिनं सुखं उत्तमम् |\n\nउपैति शान्तराजसं ब्रह्मभूतं अकलमशम् - वस्तुओं की ओर न बहते हुए, हैयदा।\nऐसा व्यक्ति, जिसने रजोगुण की गर्मी को जान लिया है, वह भगवान में रहने वाले व्यक्ति के समान है\nयोगी प्रसन्नता से अभिभूत हो गया।\n\nएक बार जब हमारा मन भगवान में स्थित हो जाता है, तो यह भ्रम का घोंसला बन जाता है\nशांत हो जाओ.  जिस व्यक्ति ने यह उपलब्धि हासिल कर ली है, उसे किसी भी मूर्ख व्यक्ति द्वारा परेशान नहीं किया जाएगा।\nइस अवस्था में हमें पता चलेगा कि जीवन में सबसे बड़ी सच्ची खुशी क्या है जिसे हमें अनुभव करना चाहिए।\nयहां उस राजसिक सुख में कभी निराशा नहीं होती जिसकी मन आमतौर पर इच्छा करता है। इस हालत में\nहम स्वच्छ हो जाते हैं. यह एक वास्तविक तह है. मन की शुद्धता प्राप्त किए बिना एक बाहरी तह\nऐसा करने से कोई फायदा नहीं है. शुद्ध मन के लिए कुछ भी मील नहीं है! मन\nमाडिया होने पर उसके माइली बनने की कोई संभावना नहीं है। यह अपने जीवनकाल में मानव है\nप्राप्य परमानंद की स्थिति.\n\nयुञ्जन एवं सदात्मनं योगी विगतकलमशः |\n\nसुखेन ब्रह्मासंस्पर्शमत्यन्तं सुखमश्नुते",
  "6.28": "युञ्जन एवं सदा आत्मानं योगी विगत कल्मशः |\nसुखेन ब्रह्मासमस्तर्शं च्यं सुखं अश्नु ते - इस प्रकार नाशवान और हमेशा भगवान की पूजा करते हैं।\nजो साधक आराम से ध्यान करता है उसे ईश्वर का अनुभव करने का परम आनंद प्राप्त होता है।\n\nकृष्ण यहां दूसरे प्रकार से भगवद अनुभूति का आंतरिक आनंद हैं\nसमझाया. कृष्ण कहते हैं \"युञ्जन एवं सदात्मनं योगी विगतकलमशः\"। कृष्ण का\nयह शब्द दो रूपों में पाया जाता है। सबसे पहले “विगतकलमश सूर्य आत्मानम्\nयुञ्जन* और दूसरा \"आत्मानं युञ्जन सुं विगतकलमशः\"। हम पहले हैं\nमनुष्य को अशुद्ध मन से भगवान का दर्शन करना चाहिए। फिर भगवान का ध्यान करें\nबर्बाद हो जाना चाहिए. एक बार प्रभु के ध्यान के लिए मन को शुद्ध कर लें\nदेखा जा सकता है लेकिन जैसे ही हम प्रभु के अनुभव से नीचे आते हैं, हमारा मन तमस से भर जाता है\nक्षतिग्रस्त हो सकता है. उसके लिए सदैव भगवद् अनभूति में स्थित रहना चाहिए। इसका मतलब है एक दिन में चौबीस\nइसका मतलब यह नहीं कि वह घंटा ध्यान में बीते। हमेशा भगवान की शरण में रहने के बजाय। जब ये मामला है\nमन सदैव स्वच्छ रहता है। इस प्रकार जब ईश्वर की दृष्टि मजबूत हो जाती है, तो अभ्यासी सहज हो जाता है\nउसे प्रभु के प्रत्यक्ष दर्शन का परम आनंदमय अनुभव प्राप्त होता है।\n\nअगले श्लोक में कृष्ण ने ध्यान की प्रक्रिया का वर्णन किया\nवह बताते हैं कि क्या करना चाहिए. ईश्वर का अर्थ वास्तविक दुनिया से परे कहीं है\nइसे वैकुंठ में अंतपुरा के एक कमरे में बैठे व्यक्ति के रूप में नहीं देखा जाता है। भगवान का\nयहां कृष्ण बताते हैं कि हमारा दृष्टिकोण क्या होना चाहिए।",
  "6.37": "अयतिः श्रद्धाय उपेतः योगात् चलिता मनसः |\nअप्राप्य योगसमसिद्धिं काम गतिं कृष्ण गच्छति - कृष्ण, निष्ठा है - प्रयास नहीं। ध्यान आपके मन को बदल देगा। ऐसे व्यक्ति के लिए क्या किया जा सकता है जो योगसिद्धि प्राप्त नहीं कर सकता?\n\nजिसने योग की प्राप्ति में सफलता प्राप्त कर ली है, जिसने ध्यान करने की कोशिश की है, जिसने एक बिंदु तक परिश्रमपूर्वक ध्यान केंद्रित करने की कोशिश की है, लेकिन किसी कारण से पूर्ण लक्ष्य तक नहीं पहुंच पाया है - अंतवना पडेनु? क्या इन लोगों को सिद्धि नहीं मिलती?",
  "6.33": "अर्जुन उवाच-अर्जुन ने पूछा:\n\nयः अयं योगः त्वया प्रोक्तः समयेन मधुसूदन |\n\nएतस्य अहम् न पश्यामि चंचलत्वात् स्थितं स्थिरम् - मधुसुदा, तुम समदर्शी हो।\nध्यान योग कहा. मैं सोचता हूं: चूंकि मन चंचल है, इसलिए इसमें दृढ़ रहो\n\nनहीं कर सकता\n\nअर्जुन भगवान कृष्ण को 'हे मधुसूदन', सात्विकों को आनंद देने वाले कहकर संबोधित करते हैं।\nकहते हैं: “आपने जो संक्षेप में ध्यान की विधि बतायी है उसे हम कैसे अपना सकते हैं\nक्या यह संभव है? ध्यान एक पूर्णतः मानसिक प्रक्रिया है। लेकिन हमारा मन अशांत और चंचल है.\nऐसे मन को वश में रखकर आप इस स्थिर ध्यान योग को प्राप्त कर सकते हैं\nअर्जुन कहते हैं कि यह संभव नहीं है।",
  "6.38": "कच्चित् उभय विभ्रष्टः छिन्न अभ्रं इव नश्यति |\nअप्रतिष्ठः महाबाः विमूधा ब्राह्मणः पथि - हे महाबाहो, अथाह, भगवान के।\nजिसने रास्ते में अपना लक्ष्य खो दिया है, वह बादल के टुकड़े की तरह न इधर, न उधर, गायब हो जाएगा।\n\nऐसे लोगों का जीवन इसके बिना, एहसान के बिना, बादल के एक टुकड़े की तरह होता है जिसकी दूसरी तरफ कोई छाया नहीं होती।\nक्या यह बिना बरसे ही बर्बाद हो जायेगा? ज्ञान शक्ति है\nऐसे बूढ़ों के साथ आप क्या करते हैं, जो वसीयत का स्वरूप हैं?\n\nएतन्मे संशयं कृष्ण चचेतुमर्हस्यशेषतः।\n\nत्वदन्यः संशयस्यास्य चचेता न ह्यपापद्यते",
  "6.44": "गरीब अभ्यास तेन एव ह्रियते हि अवसः अपिसः।\n\nजिज्ञासुः अपि योगस्य शब्दब्रह्म अतीवर्तते - अतीत के अभ्यास के बल से प्रभावित हुए बिना,\nउसका रास्ता बहता है. जो ध्यान योग को जानना चाहता है वह शब्द ब्रह्म से भी परे है\nपरब्रह्म से जुड़ता है।\n\nयदि उसका जन्म वैदिक घर में नहीं हुआ है तो भी वह अपने पूर्व जन्म की उपलब्धियों के कारण होता है\nहमारे बिना हमारा मन उपलब्धि की ओर बहता है। यह प्रहलादन और पिंगले की कहानी है\nएक अच्छा चित्रण. यदि आत्मा में अध्यात्म के प्रति सदैव एक तीव्र, अत्यंत उत्कट चिंता बनी रहे\nवह शास्त्र पढ़ने वालों से भी ऊपर उठ जाता है।",
  "6.43": "तत्र तं बुद्धिसंयोगं लबते पूर्व शोधितम् |\nयतते च ततः भूयः संसिद्दौ कुरुनन्दना--इस जीवन में भी पिछले जीवन का ज्ञान नष्ट हो जाता है।\nवापस हो जाता है. कुरुनंदन, फिर से सिद्धि के लिए प्रयास करता है।\n\nउसने अपने पिछले जीवन में जो कुछ भी हासिल किया था वह उसके अवचेतन मन में समाहित था\nउपयुक्त वातावरण मिलते ही वह सचेत हो जाता है। यह जन्म पिछले जन्म का विकास है\nविकास का उत्तरार्ध. यदि पिछले जन्म में इतना विकास न हुआ हो\nघबराने और इसे यहीं से शुरू करने की जरूरत नहीं है. पिछले जन्म का\nसंस्कार हमेशा हमारे साथ है और उस संस्कार के साथ हम उपलब्धि की राह पर हैं\nजारी रखना चाहिए. ध्यान योग एक जन्म की उपलब्धि नहीं है।\n\nपूर्वभ्यसेन तेनैव ह्रियते ह्यवशोपि सः।\n\nजिज्ञासासुरपि योगस्य शब्दब्रह्मातिवरते",
  "6.42": "या योगिनं एव कुले भवति धीमतम।\nऔर नमस्ते. दुर्लभ तारां लोके जन्म यत् ईदृशम्... या विद्वान योगियों का।\nउनका जन्म एक परिवार में हुआ है. इस प्रकार का जन्म संसार में अत्यंत दुर्लभ है।\n\nकृष्ण आगे कहते हैं: यदि योगी नहीं, तो योगी के घर में जन्म लूंगा।\nइससे वह गर्भ से ही योग में दीक्षित हो जाएगा। पिछले जन्म में उनकी उपलब्धि क्या थी\nयदि वह किसी सीढ़ी पर चढ़ा है तो वह उस सीढ़ी तक आसानी से पहुंच सकता है और वहां से अगला कदम हासिल कर सकता है\nउसे मौका मिलेगा. यह आध्यात्मिक उपलब्धि की विशेषता है। एक जन्म में दो कदम\nयदि चढ़ गए तो अगले जन्म में सीधे तीसरी सीढ़ी पर कदम रखें। इससे कोई भी उपलब्धि\nव्यर्थ नहीं- इस बात से कभी निराश नहीं होना पड़ेगा। ऐसे परिपक्व जीव योगसिद्ध के घर में\nजन्म से ही उसे वंशानुगत सात्विक ऐंठन (691680 101065) है और\nवायुमंडल (8£41017॥1217131 109099) उपलब्ध है। और उन्होंने वहां अपना कारनामा कर दिखाया\nजारी है. योगियों के घर में जन्म लेना संसार में अत्यंत दुर्लभ है। उपलब्धि की राह पर\nयह सौभाग्य केवल ऊंचे लोगों के लिए है।\n\nतत्र तं बुद्धिसंयोगं लबते पौर्वदैहिकम |\nयतते च थातो भूयः समसिद्दौ कुरुनन्दना",
  "6.41": "प्राप्य पुण्यकृतं लोकं उपित्वा षष्ठीः समः।\nशुचिनम् श्रीमतम् गेहे योग भ्रष्टा ह अभिजयते-ऐसे योग भ्रष्टा नु पुण्यवंतर\nलोकों को प्राप्त करने के बाद, वह लंबे समय तक वहां निवास करता है, और फिर उन लोगों के घर में रहता है जो पवित्र और समृद्ध हैं\n\nपैदा है\n\nयोग का अभ्यास करें, भगवान सी का ध्यान करने का प्रयास करें, किसी कारण से कुछ कदम उठाएं,\nमनोविकृति के कारण या जीवन के अंत के कारण जो इसे वहीं रोक देता है उसकी भी उपलब्धि नहीं होती\nव्यर्थ नहीं. कृष्ण ने इसका कारण पिछले अध्याय (अ-2; श्लो-40) में बताया है। उसके लिए\nवह यहां फिर से जोर देकर समझाते हैं. कृष्ण कहते हैं कि यदि उपलब्धि बीच में ही रुक जाए तो उसका कोई महत्व नहीं है\nकोई समस्या नहीं. क्योंकि ऐसा व्यक्ति उन लोगों के समान है जिन्होंने अपने शरीर का त्याग करने के बाद पुण्य कमाया है\nसंसार को प्राप्त करता है. धरती पर वापस आकर लंबे समय तक वहां की खुशियों का आनंद उठाएं\nउनका जन्म एक स्वच्छ समृद्ध वैदिक घर में हुआ है। उसके पास किसी भी सांसारिक सुख का अभाव है\nजंगली नहीं उसे योगाभ्यास के लिए सर्वोत्तम वातावरण मिलता है।\n\nया योगिनामेव कुले भवति धीमतम\nएतद्दि दुर्लभत्रं लोके जन्म यदिदृशम्",
  "6.34": "चंचलं हि मनः कृष्ण प्रमादि बल वत थमतम |\n\nतस्य अहं निग्रहं मन्ये वयो इव सु दुष्करम् - कृष्ण, क्या तुम इतने चंचल नहीं हो? हमें\nआश्चर्यजनक रूप से कठोर और मजबूत। इसे पकड़कर रखना हवा को पकड़ने के समान है\nमेरी भावना\n\nमन बड़ा चंचल है, एक विषय से दूसरे विषय की ओर उड़ता रहता है। मेरा मन हमेशा मैं ही हूं\nयह अच्छा लगता है लेकिन मैं इसे काम में नहीं ला सकता। वह दूसरों को अपनी इच्छानुसार झुकाता है\nप्रकृति मन है. यह हमारे भगवत संकल्प को कुचल कर अपना अधिकार बना लेता है\nबनाता है और छोड़ देता है. ऐसे मन को कोई आम आदमी कैसे दबा सकता है? उड़ाना\nजिस प्रकार हवा को मुट्ठी में रखना असंभव है, उसी प्रकार मन को नियंत्रित करना असंभव है\nअर्जुन कहते हैं कि यह मेरी भावना है।\n\nअर्जुन का यह प्रश्न आंशिक रूप से इस अध्याय के अब तक के हमारे प्रत्येक पाठक के लिए है\nपढ़ते समय ये याद आता है. \"यह हमारे लिए नहीं है\" या \"यह हमारे लिए नहीं है\"\nआमतौर पर यह पहला विचार होता है जो हमारे दिमाग में आता है। यहां जानिए ये वजह\nहमारे प्रतिनिधि \"नर\" ने नारायण से इस प्रकार प्रश्न किया। अब नर के प्रश्न पर कृष्ण ने क्या कहा?\nआप सभी ये जानने को उत्सुक हैं कि वो क्या जवाब देंगे. क्योंकि हमारे पास वह है\nअपने चंचल मन को त्याग कर भगवान में स्थित होने का संकल्प है।\nलेकिन डर है कि वह मन बहुत मजबूत है! आइये हमारे प्रश्न का उत्तर देते हैं कि वह मधुसूदन क्या है?\nआइए इस अध्याय के अगले भाग में इसका उत्तर देखें।",
  "6.23": "तम् विद्यात् दुःखसंयोग वियोगं योगसंज्जितम् |\nसः निश्चययेन युक्तव्यः योगः अनिर्विन्नचेतसा॥\n\nइस अवस्था में ध्यान से मजबूत हुआ आंतरिक शरीर बाहरी चीजों की ओर प्रवाहित नहीं होता है। यहाँ\nवह अपने भीतर भगवान को देखकर प्रसन्न होता है।\nवह इंद्रियों द्वारा अप्राप्य, भीतर खिलने वाले पारलौकिक आनंद का अनुभव करता है। यह\nजो दृढ़ रहता है वह प्रभु द्वारा कभी भी द्रवित नहीं किया जाएगा। इसे पाने के बाद कोई अन्य कमाई\nइससे ज्यादा कुछ नहीं. जो यहां खड़ा होगा उसे कोई भी बूढ़ा व्यक्ति परेशान नहीं करेगा। यही तो है\nमनुष्य को समस्त पापों से मुक्ति का योग जानना चाहिए। वापस चीजों से थक गया\nपरिवर्तित व्यक्ति को आवश्यक रूप से इस योग में वश में किया जाना चाहिए।\n\nक्या होता है जब मन बाहरी दुनिया से संपर्क खो देता है और भगवान में बस जाता है\nअर्थ- कृष्ण कहते हैं: \"उपरमते चित्तम\" का अर्थ है उस परम आनंद में मन।\nरुक जाता है. उस आनंद से अलग न होने की चाहत आती-जाती रहती है।\nआमतौर पर मन तुरंत इस अवस्था में नहीं जाता. इसमें बहुत मेहनत लगती है. एक प्रयास करें\nकई जन्मों के प्रयास के बिना एक बार में इस अवस्था तक पहुँचना असंभव है। निरंतर\nयोगाभ्यास द्वारा चित्तवृत्ति पर अंकुश लगाना चाहिए। यानि हमारा मन\nरोका जाना चाहिए. इसे अवरुद्ध कर दो ताकि यह कहीं भी न बहे, मानो भगवान में इसका कोई स्थान नहीं है\nकरना चाहिए\n\nजब हम आत्म-साक्षात्कारी हो जाते हैं तो हमें अभूतपूर्व आनंद का अनुभव होता है। यह सर्वोत्तम है\nएक आनंददायक अनुभव. भक्त की भगवान के प्रति भक्ति और भगवान का भक्त के प्रति स्नेह दोनों\nजब 'निर्भया' का प्रदर्शन किया गया. अन्तर्चक्षु से ध्यान की अवस्था में भगवान जो अन्तर्यामय हैं\nदेखना ही ध्यान का अनुभव है। हम यहाँ जो देख रहे हैं वह उस प्रभु की महिमा है जिसे मन ने नहीं देखा है\nस्वरूप यह ईश्वर का ही प्रतीक है। यदि हमें ईश्वर को वैसा देखना है जैसा वह वास्तव में है\nहमें प्यार करना चाहिए. जब भगवद कृपा बन जाती है तो हमारा स्वरूप भगवान की ओर देखता है। यह है\nबहुत भावुक अवस्था. इस अवस्था में मन पूरी तरह शांत और सीधे तौर पर आत्म-निहित होता है\nप्रभु को स्वयं की आँखों से देखना। यह स्थिति पूर्ण संतुष्टि दे सकती है.\nउसी अवस्था में यह सत्य समझ में आता है कि इन्द्रियों से प्राप्त सुख सापेक्ष होता है। ये जुनून\nआनंद का अनुभव करने के बाद दोबारा चढ़ने या उतरने की इच्छा नहीं होती।\nजिसे प्रभु का पूर्ण अनुभव है वह कभी भी किसी भी सांसारिक कष्ट से परेशान नहीं होता।\nयह मानव जीवन में प्राप्त की जा सकने वाली सर्वोच्च स्थिति है। हम एक वास्तविक आनंद हैं\nदेखने के लिए इस भावुक अवस्था तक पहुंचना होगा।\n\nउपर्युक्त विचार को सुनकर कुछ लोग भ्रमित हो जाते हैं और सब कुछ एक ही बार में इसी स्थिति पर छोड़ देते हैं\nवे पहुँचने के साहसिक कार्य पर निकल पड़ते हैं। लेकिन अगर आप ऐसा करते हैं तो आपको कभी सफलता नहीं मिलेगी. बस स्थिर\nयह आनंद सिद्धि से ही प्राप्त किया जा सकता है। सांसारिक सुखों का आनंद लें\nजब ऐसा लगे कि खुशी काफी हो गई है, तो व्यक्ति को ध्यान की गहराई में जाने का प्रयास करना चाहिए। अन्यथा जोखिम.\n\nसंकल्पप्रभां कामनासक्त्वा सर्वनाशेषतः।\n\nमनसैवेद्रियग्रामम् विनियम्य समन्ततः",
  "6.32": "सर्वभूतस्थितं यः मम भजति एकत्वं स्थितः |\nसर्वथा वर्तमान: अपि सः योगी मयि वर्तते - मैं सभी प्राणियों में समान रूप से मौजूद हूं।\nजो जानता है और पूजा करता है, चाहे उसकी स्थिति कुछ भी हो, वह मुझ में है।\n\nकृष्ण कहते हैं: “यह निष्कर्ष कि भगवान सर्वव्यापी हैं, हर जगह एक समान है\nनिरंतर भक्ति वाला साधक, चाहे वह कोई भी हो, मुझसे जुड़ता ही है। अप्रत्यक्ष\nजिसने ज्ञान प्राप्त कर लिया वह कभी भी ईश्वर से दूर नहीं जाता। प्रभु में उसे मोक्ष मिल गया\nबस जाता है.\n\nआत्मौपम्य सर्वत्र समं पश्यति यो$अर्जुन |\n\nसुखम्वा यदिव सुखमसयोगी परमो मतः ॥ॷ32॥\n\nसुखं वा यदि वा दुःखं सः योगी परमः मतः - सुख हो या दुःख, सभी को इसकी आवश्यकता होती है -\nहे अर्जुन, जो व्यक्ति इच्छाओं को अपने समान देखता है, वह बहुत बड़ा उपलब्धिकर्ता है\nयही निष्कर्ष है.\n\nकृष्ण ने हमें पहले भी समदृष्टि के बारे में बताया था। यहाँ मुख्य रूप से सात्विक लोग हैं,\nएक साधक कैसे भगवान के भक्तों के साथ समदर्शन विकसित करता है\nसमझाया. सबसे महान योगी जानते हैं कि अन्य लोग भी उनके जैसे हैं। हम लोगो को\nवह इस सत्य को जानता है कि जो दुःख देता है, वह दूसरों को भी दुःख पहुँचाता है\nमालूम है हर किसी को सुख और दुःख है, मेरी तरह उन्हें दुःख पसंद नहीं है\nपेशेवर लोग सावधानी बरतते हैं। जो दूसरे को उतना ही दुःख देता है जितना अपना दुःख\nवह देखता है, जो दूसरों की खुशी और सफलता को अपनी सफलता मानकर खुश होता है\nवह योग के बहुत बड़े अभ्यासी हैं।\n\nभगवद् भक्तों में भगवान की विशेष उपस्थिति होती है। इसलिए जब हम उनके सुख-दुख पर प्रतिक्रिया देते हैं\nयह उनके भीतर भगवान की पूजा बन जाती है।\n\nइस अध्याय में अब तक कृष्ण ने ध्यान के बारे में विस्तार से बताया है। इसमें कृष्ण का वर्णन है\nएक अत्यंत सामान्य कठिनाई जो सभी ने देखी है वह है \"चंचल मन का होना।\"\nहम इसे नियंत्रित करते हैं और समभाव विकसित करते हैं', क्या यह वास्तव में संभव है? अगला\nश्लोक में, अर्जुन ने कृष्ण के रूप में हम सभी से यह प्रश्न पूछा है।\n",
  "6.31": "सर्वभूतस्थितं यः मम भजति एकत्वं स्थितः |\nसर्वथा वर्तमान: अपि सः योगी मयि वर्तते - मैं सभी प्राणियों में समान रूप से मौजूद हूं।\nजो जानता है और पूजा करता है, चाहे उसकी स्थिति कुछ भी हो, वह मुझ में है।\n\nकृष्ण कहते हैं: “यह निष्कर्ष कि भगवान सर्वव्यापी हैं, हर जगह एक समान है\nनिरंतर भक्ति वाला साधक, चाहे वह कोई भी हो, मुझसे जुड़ता ही है। अप्रत्यक्ष\nजिसने ज्ञान प्राप्त कर लिया वह कभी भी ईश्वर से दूर नहीं जाता। प्रभु में उसे मोक्ष मिल गया\nबस जाता है.\n\nआत्मौपम्य सर्वत्र समं पश्यति यो$अर्जुन |\n\nसुखम्वा यदिव सुखमसयोगी परमो मतः ॥ॷ32॥\n\nआत्मौपम्येन सर्वत्र सम्म पश्यति यः अर्जुन।\n\nसुखं वा यदि वा दुःखं सः योगी परमः मतः - सुख हो या दुःख, सभी को इसकी आवश्यकता होती है -\nहे अर्जुन, जो व्यक्ति इच्छाओं को अपने समान देखता है, वह बहुत बड़ा उपलब्धिकर्ता है\nयही निष्कर्ष है.\n\nकृष्ण ने हमें पहले भी समदृष्टि के बारे में बताया था। यहाँ मुख्य रूप से सात्विक लोग हैं,\nएक साधक कैसे भगवान के भक्तों के साथ समदर्शन विकसित करता है\nसमझाया. सबसे महान योगी जानते हैं कि अन्य लोग भी उनके जैसे हैं। हम लोगो को\nवह इस सत्य को जानता है कि जो दुःख देता है, वह दूसरों को भी दुःख पहुँचाता है\nमालूम है हर किसी को सुख और दुःख है, मेरी तरह उन्हें दुःख पसंद नहीं है\nपेशेवर लोग सावधानी बरतते हैं। जो दूसरे को उतना ही दुःख देता है जितना अपना दुःख\nवह देखता है, जो दूसरों की खुशी और सफलता को अपनी सफलता मानकर खुश होता है\nवह योग के बहुत बड़े अभ्यासी हैं।\n\nभगवद् भक्तों में भगवान की विशेष उपस्थिति होती है। इसलिए जब हम उनके सुख-दुख पर प्रतिक्रिया देते हैं\nयह उनके भीतर भगवान की पूजा बन जाती है।\n\nइस अध्याय में अब तक कृष्ण ने ध्यान के बारे में विस्तार से बताया है। इसमें कृष्ण का वर्णन है\nएक अत्यंत सामान्य कठिनाई जो सभी ने देखी है वह है \"चंचल मन का होना।\"\nहम इसे नियंत्रित करते हैं और समभाव विकसित करते हैं', क्या यह वास्तव में संभव है? अगला\nश्लोक में, अर्जुन ने कृष्ण के रूप में हम सभी से यह प्रश्न पूछा है।\n",
  "6.12": "शुचौ देशे प्रतिष्ठितप्य स्थिरं आसनं आत्मानः |\n\nन अति उच्ची तम न अति नीचम चेला अजिना कुसा उत्तरम्\n\nतत्र एक अग्रं मनः कृत्वा यशचित्त इन्द्रिय क्रिया; .\n\nउपविषय आसने युंजयात् योगम् आत्मा विशुद्धये - शुद्ध स्थान में, हुला (दरबे)।\nमृगचर्म पर चटाई-कपड़ा, न बहुत ऊँचा, न बहुत नीचा, न झुर्रीदार।\nअपने लिए एक सीट की व्यवस्था कर लेनी चाहिए. इसमें बैठें, अपना ध्यान इंद्रियों पर केंद्रित करें\nऔर आंतरिक योनियों को छोड़कर, शुद्ध आत्मा के लिए समाधि प्राप्त करनी चाहिए।\n\nध्यान क्षेत्र साफ-सुथरा होना चाहिए। घर में सात्विक स्पंदन (॥/8800) का स्थान\nध्यान का विकल्प चुनें. घर में ऐसे स्थान की पहचान करें जहां पहले से ही उच्च सात्विक कंपन रहा हो\nवे एक मंदिर का निर्माण कर रहे थे. दुर्भाग्य से, आज घर बनाते समय जगह कहां बचती है?\nबचे हुए को हम पूजा घर में तब्दील कर रहे हैं।' हम घर के किस हिस्से में हैं?\nसात्विक कंपन तब होता है जब बैठते समय हमारा मन सात्विक होता है\nहम आसानी से पा सकते हैं कि इसमें वृद्धि हुई है। हमारे यहां इसे \"स्वच्छ देश\" कहा जाता है।\n\nयह पर्याप्त नहीं है कि हम सात्विक कंपन के स्थान की पहचान कर लें; कितना अच्छा सात्विक है वहां\nकंपन होने पर भी अगर हम फर्श पर बैठते हैं तो फर्श में होने वाला खराब कंपन हमारे शरीर में प्रवेश कर सकता है।\nइसके लिए हम जिस बैठने की व्यवस्था पर बैठते हैं वह सही होनी चाहिए। स्थिर मुद्रा बहुत महत्वपूर्ण है.\nइसके लिए सोफे जैसी गद्दी वाली सीट का प्रयोग नहीं करना चाहिए। ये कैसा कृष्ण है\nउन्होंने समझाया कि सीट लायक है. जिस सीट पर हम बैठें वह बहुत नीची नहीं होनी चाहिए,\nयह बहुत अधिक नहीं होना चाहिए. बैठने की जगह पर सबसे पहले दरबे की चटाई बिछानी चाहिए।\nउसके ऊपर कृष्णजिना (संसार) या व्याघ्रजिना (संसार-नैष्टिक का त्यागी)\nब्रह्मचारी) को रखा जाना चाहिए। इसके ऊपर कपड़ा (रेशमी पाटे या दवली) रखें। यह ध्यान के लिए है\nबहुत बढ़िया आसन.\n\nयहां हमें डर्बे मैट का उपयोग करने के लिए कहा गया है। उससे ऊपर, दरबे व्यर्थ बढ़ता है\nघास लेकिन दरबेह में वातावरण में बुरी आत्माओं को नियंत्रित करने की एक महान शक्ति है। उसके लिए\nदर्बे को यज्ञ-यागादि में अंगूठी के रूप में और बुरी ऊर्जा के नियंत्रक के रूप में पहना जाता है\nयज्ञ कुण्ड के चारों ओर दरबे लगाया जाता है। ध्यान के दौरान हमें कोई बुरी आत्मा नहीं आती\nयहां डर्बे मैट हमें परेशान न करने में मदद करता है। कृष्णाजी और पट्टे\nहमें एक महान सात्विक कंपन देता है। यह जमीन से हमारे शरीर तक होने वाला एक बुरा कंपन है\nप्रवेश रोकें. हममें से कुछ लोग लकड़ी की मेज का उपयोग करते हैं। लेकिन\nफर्श पर बैठते समय हमारे शरीर का कुछ हिस्सा फर्श को छूने की संभावना होती है। उसके लिए कृष्ण\nउक्त ऊपरी आसन अत्यंत उपयुक्त है। हम इस प्रकार की सीट बनाने में सक्षम थे\nभंगी में सीधा बैठना चाहिए (103/[6)। ऐसी सीट पर जबरदस्ती बैठाना जो हम नहीं कर सकते\nबैठना ध्यान के लिए अनुकूल नहीं है। आमतौर पर वज्रासन बहुत प्रसिद्ध है। इस आसन में हमारा शरीर\nयह सीधा है और ध्यान के लिए अच्छा है। इस बात को कृष्ण आगे विस्तार से बताते हैं।\n\nजैसा कि ऊपर बताया गया है, आसन तैयार होते ही ध्यान करना संभव नहीं है। सीट का\nव्यक्ति को उचित आसन पर बैठकर मन को भगवान की ओर एकाग्र करना चाहिए। इसे \"एकाग्रता\" कहा जाता है।\nइस शब्द के दो अर्थ हैं. एका*अग्र-बाण जैसा एक ही लक्ष्य। इसका क्या अर्थ है, उस पर लक्ष्य साधें\n\nउत्तर उसी शब्द में निहित है. \"एषा एव करोतिति एकाग्रह- कोई व्यक्ति जो इस संसार की रचना-स्थिति है-\nमन को उसमें स्थिर करना संहार-नियम-ज्ञान-बंध-मोक्ष का कारण है\nएकाग्र।  बचपन से पाली गई आदतों को छोड़कर उन्होंने खुद को एक नई आदत में बदल लिया\nदिमाग को समायोजित होने के लिए बहुत समय की जरूरत होती है। इस प्रकार मन तुरंत ध्यान के लिए बैठ जाता है\nध्यान केंद्रित न कर पाने से किसी को भी चिंतित नहीं होना चाहिए। निरंतर प्रयास, कभी हार नहीं मानना\nएकाग्रता तभी संभव है जब इसे चालला से हासिल किया जाए।\n\nएक बार मन एकाग्र हो जाए 'यशचित्त इंद्रिय क्रिया:' - सभी बाहरी इंद्रिय क्रिया\nपूर्णतया बंद होना चाहिए। अर्थात इस अवस्था में हमें बाहरी ध्वनि, बाह्य ध्वनि सुनाई नहीं देती\nनाक पर मत मारो. अगर हमें कोई मच्छर काट भी ले तो हमें दर्द का एहसास नहीं होता. यह है\nनींद की तरह; नींद में हमें भीतर की दुनिया का पता नहीं चलता, लेकिन ध्यान में भीतर की दुनिया जागती है\nदुनिया जाग रही है. इस प्रकार बाहरी क्रिया और फिर मन को शांत करना\nनियंत्रित किया जाना चाहिए. हमारे मन में बहुत सारे विचार होते हैं। लेकिन वो सब पहले रिकॉर्ड किया गया था\nव्यक्ति को चीजों को अकेला छोड़ देना चाहिए और केवल भगवान के गुणों के पहलू पर ध्यान देना चाहिए।\n\nइस प्रकार, हमें अपने मन और मनोदशा को नियंत्रित करने के लिए जन्म-जन्मांतर की उपलब्धि की आवश्यकता है। कुछ ये हैं\nउपलब्धि के लिए लगातार प्रयास करने से सफलता न मिलने पर निराशा होती है। लेकिन अतीत में\nजैसा कि कहा गया है, अध्यात्म में हमारा उठाया हुआ एक लड़खड़ाता कदम भी व्यर्थ नहीं जाता। इसी जन्म में सिद्धि\nयदि संभव नहीं हो सका, तो निश्चित रूप से अगले जन्म में हमारी उपलब्धि वहीं होगी जहां वह इस जीवन में थी\nयह वहां से शुरू होता है (कृष्ण इसे बाद में विस्तार से बताते हैं)। तो कभी नहीं\nनिराश न हों, बस प्रयास करते रहें।\n\nइस प्रकार, एक बार जब हमारा मन और आत्मा नियंत्रण में आ जाते हैं, तो हम उसी स्थिति में होते हैं\nधारण किया जाना (अनज्याद योगम्)। इस अवस्था में हमारे प्रबुद्ध स्व के लिए\nमैल धुल जाता है और आत्मशुद्धि हो जाती है। ऐसी पवित्र आत्मा द्वारा पवित्र किया गया\nभगवान को देखा जा सकता है.\n\nअगले श्लोक में कृष्ण की ध्यान भंगी (बैठने की मुद्रा) की और भी स्पष्ट तस्वीर\nदेता है\n\nमन कयाशिरोग्रीवं धारयन्नचलं स्थिरः |\nप्रेक्ष्य नासिकाग्राम स्वं दिशश्वनवलोकायन",
  "6.45": "योगी समशुद्ध किल्बिषः प्रिययत् यत्मानः।\n\nअनेक जन्मसिद्ध ततः याति परम गतिम् - ध्यान में संलग्न होने के साधक प्रयास का।\nपरिणामस्वरूप, उन्होंने सभी प्रकार के किलुबू खो दिए और कई जन्मों की उपलब्धियों के माध्यम से सिद्धि प्राप्त की और एक बुजुर्ग बन गए\nप्रभु से जुड़ जाता है.\n\nजैसा कि पहले बताया गया है, हमारी उपलब्धि कई जन्मों की है। सबसे पहले हमारे अंदर संकल्प उत्पन्न हुआ, उससे संकल्प उत्पन्न हुआ\nअगले जन्म में प्रभु ने हमें उत्तम वातावरण दिया, जहाँ हम भीतर की गंदगी से छुटकारा पाने का प्रयास करते हैं\nधुलकर, उपलब्धि से आया निर्मल ज्ञान। इस ज्ञान और सिद्धि से अनेक जन्म\nतब भगवान को शब्द-ब्राह्मण से परे देखा जा सकता है।  और इस प्रकार यह अंदर से भावुक हो गया\nचिंतित जिज्ञासु शास्त्र विद्वानों से परे मोक्ष तक पहुँच सकता है।\n\nउपलब्धि में सबसे महत्वपूर्ण है आंतरिक जगत की उपलब्धि। बाहर स्नान, पूजा, होम,\nहवन, चाहे कुछ भी करे, जो शेष रहता है वह भीतर का संसार है। यह अगला है\nकृष्ण श्लोक में बताते हैं.\n\nतपस्विभ्यो5धिको योगी ज्ञानिभ्यो8प मातोंधिकः |\nकर्मिभिष्ट ढिको योगी तस्माद् योगी भवार्जुन",
  "6.40": "भगवान उवाच- भगवान ने कहा:\n\nपार्थ न एव एह न अमूत्र विषाणः तस्य विद्यते |\n\nन हि कल्याणकृत कश्चित् दुर्गतिं तत् गच्छति- पार्थ, उनकी उपलब्धि व्यर्थ नहीं है, यहाँ और\nपिता के पक्ष में, जो अच्छा करेगा उसे कभी बुराई नहीं मिलेगी।\n\nअर्जुन के प्रश्न पर कृष्ण का उत्तर बहुत आशाजनक है। कृष्ण कहते हैं: “जो लोग सिद्धि के पथ पर हैं\nयहां या वहां खोने के लिए कुछ भी नहीं। हे मेरे प्रिय मित्र, शुभकामनाएँ\nऐसा करने वालों का कभी बुरा नहीं होगा। यह प्रकृति का नियम है. यहाँ कृष्ण हैं\nअर्जुन को पार्थ कहकर संबोधित करते हैं। पार्थ का अर्थ है जो परावा (किनारे) को जानता है।\nसिद्धि के पथ पर कदम रखने वाले को भले ही भगवान के दर्शन तुरंत न हों, सदैव होते हैं\nबीच में नहीं डूबता. वह उपलब्धि से परे किनारे से जुड़ जाता है। अच्छा\nजो लोग उस पर चलते हैं उनके लिए एक अच्छा मार्ग उन लोगों के लिए कभी बुरा नहीं होता जो उस पर चलते हैं। हममें से कुछ\n\nयह कहते हुए: “मैंने अपने जीवन में कभी कोई बुरा काम नहीं किया, कभी किसी को दुःख नहीं पहुँचाया\nमैं नहीं चाहता था, लेकिन भगवान ने मेरे साथ ऐसा क्यों किया?” वह है। हमने जिंदगी में कुछ भी *बुरा* नहीं किया,\n'कोई बुराई नहीं गिनती' यह बात केवल इसी जीवन तक सीमित है। लेकिन जीवन की गति अनंत है. इतना ही\nएक बाढ़ जो जन्म-जन्मान्तर बहती रहती है। हमारे इस जीवन में कोई न कोई त्रासदी या कठिनाई है\nयदि ऐसा होता है तो अवश्य ही हमारा कोई अन्य कार्य रहा होगा जो इसका कारण है। सबसे ख़राब\nजो नहीं करेगा उसका अनिष्ट नहीं होगा। जो अच्छा करता है उसका भला नहीं होता\nनहीं होगा। यह हर समय सच है. इसका कोई अपवाद नहीं है. कृष्ण ने पूछा कैसा लगा?\nसमझाता है.\n\nप्राप्य पुण्यकृतं लोकानुपित्वा षष्ठीः समाहा।\n\nशुचिनं श्रीमत गेहे योगभ्रष्टो$*भिजायते",
  "7.1": "मयि आसक्तमनाः पार्थ योगं युञ्जन् मदाश्रयः ।\nअसंशयं समग्रं मां यथा ज्ञास्यसि तच्छृणु ॥\n\nभगवत्ज्ञान-योग का उपक्रम। पार्थ — मन मुझमें आसक्त करके, मदाश्रयः — केवल मेरी शरण लेकर, योग में तत्पर होकर — निःसन्देह मुझे पूर्णतः जानोगे।\n\nमन को पहले साधने की आवश्यकता है — फिर भगवान् में आसक्ति। 'मत्तः परतरं नान्यत्' — यही ज्ञानयोग का आधार। कृष्ण स्वयं उपदेश देंगे — 'ज्ञानं विज्ञानसहितं सम्पूर्ण रूप से' — इसे सुनो।",
  "6.36": "असंयता आत्मन योगः शुक्त्रपः इति मेई मतिः।\nवस्या आत्मा तु सदाचं शाक्यः आवप्तम् अशतः - जो स्वयं को संयमित नहीं करता, उसे समाधि नहीं मिलेगी।\nयही मेरा निष्कर्ष है. जो व्यक्ति अपने मन को सदैव वश में रखता है वह व्यापक रूप से समाधि प्राप्त कर सकता है।\n\nजो अपने आलस्य के कारण, बुरी सांसारिक इच्छा के कारण इस प्रकार प्रयत्न नहीं करता\nउसे कभी दफनाया नहीं जाएगा. मन को ब्रह्मचर्य के विचार और अभ्यास से संयमित करें\nहम जिस मन से काम करना चाहते हैं, हमें उसी मन से काम करना है। जब यह हो जाये तो समाधि\nयहां कृष्ण ने वचन दिया है कि इसे हासिल किया जा सकता है।\n\nकृष्ण के इस उत्तर में हमें ध्यान का विचार मिला। लेकिन अब हम सभी के लिए एक और\nएक प्रश्न उठता है. यानी हम संसार में पूरी तरह से उपलब्धि के पथ पर हैं\nअगर मैं समाधि प्राप्त किए बिना या अपने इस जन्म की आधी उपलब्धि के बाद बीच में खड़ा हो जाऊं\nअगर यह ख़त्म हो गया तो मैं क्या करूँगा? क्या इस जीवन की उपलब्धि व्यर्थ है? मैं प्रभु से जुड़ता हूं\nक्या यह असंभव है? अगले श्लोक में अर्जुन कृष्ण से यही प्रश्न पूछता है।\n\nअर्जुन उवाच |\nआयतिः श्रद्धायोपेथो योगचलितमानसः |\n\nअप्राप्य योगसमसिद्धिमं कं गतिं कृष्ण गच्छति 137।\n\nअर्जुन उवाच-अर्जुन ने पूछा:\n\nअयतिः श्रद्धाय उपेतः योगात् चलित मनसः।\n\nअप्राप्य योगसमसिद्धिमं काम गतिं कृष्ण गच्छति-कृष्ण, परिश्रम है-प्रयास नहीं।\nध्यान आपके मन को बदल देगा। ऐसे व्यक्ति के लिए क्या किया जा सकता है जो योगसिद्धि प्राप्त नहीं कर सकता?\n\nयोग की सिद्धि प्राप्त हुई, ध्यान करने का प्रयत्न किया, एक सीमा तक\nउन्होंने लगन से ध्यान केंद्रित करने की कोशिश की, लेकिन किसी कारण से वह पूर्ण लक्ष्य तक नहीं पहुंच सके - उन्होंने कहा\nमैं क्या गा सकता हूँ? क्या इन लोगों को सिद्धि नहीं मिलती?\n\nकचिन्नोभयविभ्रष्टश्चिन्नभ्रमिव नश्यति।\n\nअप्रतिष्ठो महाबाहो विमुहो ब्राह्मणः पथि",
  "7.3": "सहस्रों में कोई एक सिद्धि के लिए यत्न करता है; यत्न करने वालों में कोई एक सिद्धि पाता है; सिद्ध पुरुषों में भी कोई एक मुझे तत्त्वतः जानता है।\n\nभगवद्ज्ञान की दुर्लभता तीन स्तरों में है। प्रत्यक्षज्ञान भगवान् के अनुग्रह से ही सम्भव है — अपने प्रयत्न से पूर्ण नहीं होता।",
  "6.29": "सर्व भूत स्तफं आत्मानं सर्व भूतानि च आत्मानि।\n\nएकशते योग युक्त आत्मा सर्वत्र समदर्शनः - सभी अभ्यासी ध्यान के लिए सुसज्जित हैं\nवह प्राणियों में भगवान को देखता है और सभी प्राणियों को भगवान में देखता है। हर जगह\nजो प्रभु है वह एक ही दिखता है।\n\nभगवान ब्रह्मा को हम परमात्मा कहते हैं। वह क्या है? हर समय\nब्रह्म वह विशालता है जो सभी देशों में व्याप्त है। सर्वव्यापक सर्वव्यापक के रूप में\nईश्वर काल, देश, गुण और शक्ति में अनन्त है। यहाँ कृष्ण कहते हैं:\nयथा ''सर्वभूतस्थमात्मानम्''। कहने का तात्पर्य यह है कि यह सभी जीवित प्राणियों में अंतर्निहित है\nभगवान वहाँ है. इतना ही नहीं, \"सर्व भूतानि च आत्मानि\" का अर्थ है कि सभी जीवन भगवान में हैं।\nइसका पूरा अर्थ है: भगवान हमें अंदर और बाहर भर देते हैं। हम इसी की पूजा करते हैं\nकरते समय जानने योग्य महत्वपूर्ण बिंदु. ध्यान योग का अभ्यासी भगवान का होता है\nसमग्रता को देखने का यही तरीका है.\n\nयद्यपि भगवान समस्त जीवन में व्याप्त हैं, एक साधक उन्हें \"सर्वत्र समदर्शनः\" के रूप में देखता है - अर्थात\nएक समान दिखता है. भगवान का अवतार, उनका आवेश, सन्नी धन, गुण, कृति, रूपा सब हैं\nअक्षुण्ण कोई अंतर नहीं है. वह एक है, भीतर और बाहर सबमें व्याप्त है।\nबाइबल में ईश्वर के बारे में कोई जो कहता है वह कहता है “॥\n18)/ 58) \"17 (1700077 15 17 07 5(0/' 071 178 0185 1/11! 180888 )/00; 1! 10)/ 58)/ 10 )/04 \"1! 15 17 17\n\n503' [81 (18 150 5111 0180088 ]/टी. एयू201089 \"17 (1700017 15 1751068 01 »/टी 316 1! 15 0875168 08\n\n50'. सभी धर्मग्रन्थों का अर्थ एक ही है। इस प्रकार भगवान सर्वव्यापक एवं सर्वव्यापक हैं\nअनुसन्धान हमारी दैनिक पूजा में होना चाहिए।\n\nयो माम् पश्यति सर्वत्र सर्वं च मयि पश्यति।\n\n130\n\nयः मम पश्यति सर्वत्र सर्वं च मयि पश्यति |\nतस्य अहं न प्राणश्यामि सः चामेना प्रणस्यति - जो मुझे हर जगह देखता है और\nमैं उन्हें उधार नहीं दे सकता जो मुझमें सब कुछ देखते हैं; वे मुझसे उधार भी नहीं ले सकते.\n\nकृष्ण आगे कहते हैं: “जिसके पास सबमें मैं हूं और सब मुझ में है\nवह मुझे कभी नहीं देख पाएगा. मैं उनके योग स्वास्थ्य के लिए हमेशा जिम्मेदार हूं।' वही\nजैसे \"मैं उसकी भलाई का ख्याल रखूंगा\"।\n\nइस प्रकार भगवान का घनिष्ठ संबंध, चेतावनी कि 'भगवान हमें कभी नहीं छोड़ेंगे'\nहम सदैव सचेत रहते हैं। जैसा कि पहले उल्लेख किया गया है, ईश्वर वैसा ही है जैसा हम उसे देखते हैं\nउस तरह. इस कारण हमारे अंदर की यह जागरूकता जीवन में कभी भी समस्या का समाधान नहीं कर पाती है\nहमें यह समझ नहीं आया. यद्यपि यह प्रारब्धकर्म से आता है, एक अदृश्य हाथ हमें पकड़कर रखता है\nअनुभव. \"एक है जो मेरी रक्षा करता है, वह मेरे योग-कल्याण का ख्याल रखता है,\nसाहस आता है, कहता है, 'मुझे क्यों डरना चाहिए?' कोई बुरा विचार दूर हो जाएगा. सामाजिक\nप्रतिक्रियाओं, आलोचनाओं, अपवादों, अपमानों, किसी भी चीज़ से परेशान नहीं।\nभक्त को कभी भी यह महसूस नहीं होता कि भगवान ने उसे त्याग दिया है। भगवान सदैव अपने सबसे प्रिय भक्त से ही होते हैं\nदूर नहीं जायेंगे. इसके लिए भगवान को 'भक्तपराधीन' कहा जाता है। इस पर विस्तार से\nकृष्ण अगले श्लोक में बताते हैं.\n\nसर्वभूतस्थितं योमं भजत्येकत्वमस्थितः |\nसर्वथा वर्तमनोई*प स योगी मयि वर्तते",
  "7.7": "मुझसे परतर कुछ नहीं — धनञ्जय। यह सब मुझमें पिरोया है — जैसे सूत में मणियाँ।\n\nचित्प्रकृति, जड़प्रकृति, जीव-जगत्, ब्रह्माण्ड — सब भगवान् के आश्रित। सूत्र अदृश्य है, मणियाँ दृश्य — वैसे ही भगवान् अदृश्य, जगत् दृश्य। भगवान् अन्तर्बाह्य व्याप्त होकर सब धारण करते हैं।",
  "7.2": "ज्ञानम् — भगवान् का माहात्म्यज्ञान; विज्ञानम् — भगवान् का प्रत्यक्ष अनुभव। उपनिषद् में — 'यस्मिन् विज्ञाते सर्वमिदं विज्ञातं भवति' — यही कृष्ण प्रतिज्ञा करते हैं।\n\nज्ञान विज्ञानसहित — केवल शास्त्रज्ञान नहीं, साक्षात्कारसहित। जिसे जानने से यहाँ फिर जानने योग्य कुछ नहीं रहता — भगवद्ज्ञान समस्त ज्ञान का पर्यवसान है।",
  "6.46": "तपस्विभ्यः अधिकः योगी ज्ञानीभ्यः अपि माताः अधिकः |\n\nकर्मिभ्यः च अधिकः योगी तस्मात् योगी भव अर्जुन - ध्यान योग के अभ्यासी के लिए उपवास\nव्रतसाधकों से भी अधिक जैसे; उनसे भी ज्यादा जो नग्न ध्यान योग की विधि जानते हैं\nयही निष्कर्ष है. कर्म योगियों से भी अधिक. अतः हे अर्जुन, तुम!\nध्यानी बनो.\n\nजो व्यक्ति अपने हृदय में एकाग्रता रखकर भगवान का ध्यान कर सकता है, वह तपस्वी है\nकृष्ण कर्ता से भी बड़े हैं. यहां तप का अर्थ है वह अनुष्ठान जो हम करते हैं। शरीर\nदण्ड, एकादशी व्रत, ब्रह्मचर्य आदि बाह्य सैकड़ों अनुष्ठान,\nजो व्यक्ति आंतरिक रूप से ध्यान करता है वह होम-हवन करने वाले की तुलना में भगवान को अधिक प्रिय होता है।\nकृष्ण कहते हैं कि वह ऋषियों से भी महान हैं। वह तो ध्यान की बात है, केवल शास्त्र की बात है\nध्यान करने वाला ज्ञाता से बड़ा होता है। जो लोग आज अध्यात्म की बात करते हैं\nपाए जाते हैं, लेकिन सच्चे ध्यानयोगी बहुत दुर्लभ हैं(\"7108 398 10%/202)/5\n110ए520[5 01 11105000), 0! 10! I11105000[5”- (101/7/08116 707680, '!/31600)।\n\nहममें से कुछ श्रमिक हैं। यज्ञ-याग करना, अग्नि के माध्यम से भगवान की पूजा करना\nजो लोग यह कर्म करते हैं उन्हें अपने भीतर भगवान के दर्शन करने होते हैं। इसी प्रकार मूर्ति पूजा.\nहमारी पूजा केवल भगवान की छवि के प्रति समर्पित नहीं होनी चाहिए बल्कि अपने भीतर के भगवान को देखने के लिए भी समर्पित होनी चाहिए\nहमारे पास ऐसा ज्ञान होना चाहिए जो मदद का संकेत हो। बाह्य पूजा मानसिक पूजा के बिना पूजा है\nनहीं तो बस कर्मतानागी के रूप में। वह जो मन की पूजा करता है न कि वह जो बाहरी पूजा करता है\nध्यान करने वाला महान है. “तो आप जीवन में, आंतरिक ध्यान में एक ध्यानी बन जाते हैं\nउस ध्यान में लग जाने के बाद आपके बाहरी क्रियाकलापों का आप पर कोई प्रभाव नहीं पड़ेगा। फिर युद्ध भी\nयहां तक कि भगवद की भी पूजा की जाएगी” कृष्ण का अर्जुन को संदेश है।\n\nयोगिनामपि सर्वेषां मद्गाथेनान्तरात्मान |\n\nश्रद्धावान् भजते यो मम स मयुक्तमो मतः",
  "7.13": "त्रिगुणात्मक भावों से यह सारा जगत् मोहित है — इसीलिए वे मुझे नहीं जानते जो इनसे परे और अव्यय हूँ।\n\nमाया गुणात्मिका — गुणों के व्यापार से मोह उत्पन्न होता है। माया-तरण में ही भगवद्दर्शन।",
  "7.14": "भगवान् की यह माया — दैवी, गुणमयी, दुस्तर। स्वयं के प्रयत्न मात्र से माया-तरण सम्भव नहीं।\n\nजो मुझे ही शरण लेते हैं — वे इस माया को तर जाते हैं। अनन्य शरणागति ही एकमात्र उपाय है।",
  "7.6": "जड़ और चित् — ये दोनों ही समस्त जगत् की योनि हैं। सब जीव इन्हीं से उत्पन्न हैं।\n\nअहम् — भगवान् — कृत्स्न जगत् के प्रभव और प्रलय दोनों हैं। लक्ष्मी-नारायण ही समस्त जगत् के माता-पिता हैं। जड़प्रकृति के विकार जैसे गर्भ में बढ़ते हैं — वैसे ही जीव-जड इन प्रकृतियों से परिपक्व होते हैं।",
  "6.25": "संकल्प प्रभावं कामं त्यक्त्वा सर्वान् असेषातः।\n\nमनसा एव इन्द्रिय ग्रामम् विनियम्य सामन्था॥\n\nशनैः शनैः परमेत बुद्ध्वा धृति गृहितया।\n\nआत्मसम्स्थं मनः कृत्वा न किंचित् अपि चिन्तयेत् - मन में उत्पन्न होने वाली सभी इच्छाएँ\nपूर्णतः त्याग देना चाहिए; इन्द्रियाँ मन में हर जगह से भरी हुई हैं\nनियंत्रण में रखा जाना; दयालुता को बुद्धिमानी की भावना के साथ चीजों से धीरे-धीरे बाहर निकालना चाहिए जो रोती नहीं है;\nइसे प्रभु में रखना चाहिए. किसी और चीज़ की चिंता मत करो.\n\nफिर कृष्ण यहां मन को भगवान में स्थित करने की विधि बताते हैं। कृष्ण कहते हैं:\nजैसे \"संकल्प प्रभावं कामां त्यक्त्वा सर्वान् असेषातः\"। हम इसके पीछे हैं\nदेखा है हमारी सभी समस्याओं की जड़ हमारे संकल्प हैं। संकल्प मन में हैं\nक्या करना है इसका निर्णय. इससे पहले कि हम कोई भी एक काम करें\nहम इसे मानसिक रूप से करते हैं। आज यहाँ जरूर जाना, अमुक-अमुक से वहाँ मिलना\nहमारे दिमाग में एक शेड्यूल बना हुआ है कि ऐसा कुछ मिलेगा, वगैरह-वगैरह, ऐसे हजार\nसंकल्प, उन्हें पूरा करने की ख्वाहिशें हजार। “यह इसी तरह किया जाना चाहिए\n'होने की इच्छा. जीवन वह जीवन है जिसकी हम अपने मन में कल्पना करते हैं\nबाह्य जगत् में रूपरेखा को मूर्त रूप देने का प्रयास। इस प्रकार हजारों संकल्प और\nअगर मन में इच्छा भरी हो तो मन को उससे आगे सोचने की इजाजत मिलती है\nनहीं होगा.  मन केवल इच्छा-इच्छा है। कुछ का सपना (संकल्प),\nसोच रहा हूँ कि करूँ या न करूँ, सफल होऊँ या न करूँ।\nइससे भ्रमित हो रहे हैं। मन इससे आगे नहीं जा सकता. कृष्ण कहते हैं\n\"पहले अपने संकल्पों को जाने दो\"। ये संकल्प थिरुका के सपने की तरह हैं। और कितना\nजैसे-जैसे हमारे मन में संकल्प आता है, वैसे-वैसे उससे निराशा, विकर्षण भी आता है। फिर कुछ नहीं\nसोच नहीं सकता!\n\nचाहत मन का स्वाभाविक गुण है, चाहत के बिना कोई जीवन नहीं है। उसके लिए, इसे पूरा होने दें\nहमें चाहना सीखना होगा और अपने अन्य इरादों को छोड़ना होगा। यही सफलता का सूत्र है.\nइस तथ्य पर अनावश्यक सपनों की मीनार बनाने में कि आप जो चाहते हैं वह नहीं मिलेगा, जो आप चाहते हैं वह नहीं होगा\nकोई मतलब नहीं है. हमारा संकल्प तो एक ही है - ''ईश्वर की इच्छा कुछ ऐसी हो''।\nजैसा कि माधवाचार्य द्वादश स्तोत्र में कहते हैं:\n\nकुरु भुङ्क्षव च कर्म निजं नियतं हरिपाद विनम्रीय सदाचम् |\n\nहरिरेव परो हरिरेव गुरुः हरिरेव जगत् पितृमातृगतिः॥ 3.1\n\nअपने हिस्से का कर्म करो, वापस आओ। हरि चरण को न चूकें। एक अलग जो मेरा है\nकोई संकल्प नहीं. जैसा कि वेदों में कहा गया है, \"भगवान की इच्छा मेरी इच्छा हो, उनकी इच्छा हो।\"\nमेरी इच्छा पूरी हो, और मेरी इच्छा प्रभु की इच्छा के अनुरूप हो।' इसलिए वहाँ\nअपस्वर नहीं छोड़ता. जब हमारी इच्छा ईश्वर की इच्छा से मेल खाती है (588 0\" 125013102)\nबाली के संगीत में मेलोडी रची बसी है. कृष्ण कहते हैं: \"सर्वान् अशथः।\"\nइसका मतलब यह है कि आप अपने सभी संकल्पों को पूरी तरह छोड़ दें। प्रभु की इच्छा के विरुद्ध एक\nहमें संकल्प नहीं करना चाहिए. ''जो कुछ भी आप (भगवान) चाहते हैं वह मेरा संकल्प है'-यह एक है\nएक योगी को जिस एकमात्र संकल्प में संलग्न होना चाहिए वह है ध्यान।\n\nवसीयत जहां भी उठे उसे रोक देना चाहिए। संकल्प का जन्म मन से होता है! हम अपने हैं\nमन को लगातार इस तरह समझाना चाहिए: “कोई पागलपन भरा निर्णय मत लो, यदि तुम ऐसा करोगे तो यह तुम्हारे लिए होगा\nयदि आपको यह नहीं मिलता है, तो आपको इसे न पाने की चिंता करनी होगी - इसलिए इन पागल इरादों को छोड़ दें।\"\nवह है। ऐसे ही मन को समझाते रहो (460 50995800) और उसे वश में कर लेना चाहिए। पेशेवरों का मार्गदर्शन करें\nटालना मन है, रास्ता बढ़ाना मन है। तो यह बात मन से कहते रहें\nअगर वहाँ है तो यह अंततः इसे स्वीकार कर लेगा।\n\nयदि हमें अपने पागल संकल्प को छोड़ना है, तो सबसे पहले अपने इंद्रिय समुदाय को त्यागना होगा\nनियंत्रण में रखना होगा. हमें अपने अंदर अच्छे संस्कार पैदा करने चाहिए। इसके लिए वापस\nछोटे बच्चों को अनेक आध्यात्मिक अनुष्ठान सिखाये गये। छोटी उम्र में दिमाग कच्चा होता है\nमिट्टी की तरह. कुछ भी कहा जाए, उसकी सच्चाई समझ में आ जाएगी. मन की गुणवत्ता ही हम हैं\nजब एक तरफ से जाम लग जाता है तो वह दूसरी तरफ फिसल जाता है। कृष्ण कहते हैं:\n\"मन को भटकने न दें; सभी संकल्पों का त्याग करें और भगवान ने जो प्रदान किया है उसे स्वीकार करें।\nप्रसाद के रूप में स्वीकार करें;  इसका आनंदपूर्वक आनंद उठाओ;  जो नहीं है उसे चाहना\nचाहो तो रोओ मत.\n\nजैसा कि पहले उल्लेख किया गया है, मन को एक बार में नहीं बदला जा सकता है। यह बहुत धीमा है\nघुमाया जाना चाहिए. व्यक्ति को धीरे-धीरे मन को उस परम आनंद की ओर मोड़ना चाहिए। इसके लिए “आपका विश्लेषक\nअपनी बुद्धि का प्रयोग करें, ”कृष्ण कहते हैं। इसके लिए हिम्मत और साहस की जरूरत है. जब तक मैं लक्ष्य तक नहीं पहुंच जाता\nबुद्धि(€07410401) और धृति(€06959) जिन्हें विचलित नहीं किया जा सकता, बहुत महत्वपूर्ण हैं। इस प्रकार तर्क से परे\nमन को अविवेकी प्रभु में स्थिर करना चाहिए। मन सबसे पहले हमारा स्वभाव है\n\nपहचानो और वहीं रहो और फिर उस प्रभु में रहो जो साकार है। एक बार तय हो गया\nमन को किसी अन्य चिंता में डाले बिना वहीं स्थिर कर देना चाहिए।\n\nयतो यतो निश्चरति मनश्चञ्चलमस्थिरम् |\nततस्थतो नियमायितदात्मन्येव वशं नयेत्",
  "7.17": "इन चारों में ज्ञानी विशिष्ट है — नित्ययुक्त, एकभक्तिपरायण। ज्ञानी कुछ माँगता नहीं — केवल भगवद्भक्ति ही उसका लक्ष्य। इसीलिए भगवान् को ज्ञानी अत्यन्त प्रिय है — और ज्ञानी को भगवान् प्रिय।\n\nयह परस्पर प्रीति भक्तिमार्ग का सार है।",
  "6.47": "योगिनाम अपि सर्वेषाम् मत गतेन अन्तः आत्माना।\nश्रद्धावान भजते यः माम् सः मेय युक्त तमः मतः - मुझे निष्ठापूर्वक खोजो।\nमेरा निष्कर्ष यह है कि जो मेरी पूजा करता है वह अन्य सभी योगियों से बड़ा योगी है।\n\nमेडिटेशन करते समय हम अपने मन को किसी भी चीज़ पर केंद्रित करते हैं\nकुछ ऐसे भी हैं जो कई छोटे देवताओं और भूतों की पूजा करते हैं।\n\nलेकिन कृष्ण कहते हैं: “जो अकेले भगवान का ध्यान करता है वह सभी से बेहतर है\nएक वरिष्ठ योगी के रूप में. भगवान के अलावा किसी और चीज का ध्यान करने से कोई फायदा नहीं है।\nहमारे ज्योतिषी आमतौर पर कहते हैं कि 'ऐसे ग्रह के लिए ऐसे देवता की पूजा करो'।\nकहते हैं कि इसका अर्थ है उस चिह्न में भगवान को देखना। कोई देवता\nयदि कोई पूजा करते समय उस प्रतीक रूप में भगवान की पूजा नहीं करता है तो यह सत्य है\nयोग नहीं होता.  ध्यान में केवल ईश्वर आदि सभी को देखने की इच्छा\nप्रत्येक प्रतीक में उसका दर्शन करना ही सबसे बड़ा योग है। जब हम इस तरह रहते हैं, तो हमारा जीवन एक है\nयोग बन जाता है.\n\nइति षष्टो$5ध्यायः\nछठा अध्याय समाप्त हो गया\n\nयहां भगवद गीता का पहला शतक (पहले छह अध्याय) समाप्त होता है। प्रभु के इस शतक में\nकृष्ण द्वारा उपासना एवं सांख्य ज्ञान का वर्णन | जान-बूझकर प्रभु की आराधना करें\nगीता का पहला श्लोक इस प्रक्रिया का वर्णन करता है। इसके बाद भगवान की पूजा करें\nकरने की सामग्री (250600) और भगवान की महिमा - इसका विवरण आता है।\n\nचिंता मत करो\n\nअध्याय सात\n\nपिछले छह अध्यायों (प्रथम शतक) में बताया गया है कि कृष्ण साधक बन चुके व्यक्ति को कैसे सिद्धि में लगना चाहिए।\nकर्म क्या होना चाहिए, ध्यान कैसा होना चाहिए आदि भगवान को जानने के उपाय बताए।\nदूसरा शतक (ए-7 से 12) वह भगवान है जिसे हमें उपलब्धि के माध्यम से जानना है\nउनके $*ध्य का रूप, विभूति, महिमा, महिमा बताना संभव है।\n\nइस अध्याय में हम सीखेंगे कि ईश्वर को अपनी जागरूकता की पूर्ण सीमा तक कैसे जाना जाए\nकृष्ण उसे समझाते हैं। यदि आप कुछ भी जानते हैं, तो आप सब कुछ जान लेंगे\nविज्ञान यहां पाया जा सकता है। अष्टकोणीय चरित्र का निर्माण; नादसृष्टि; सृजन के कार्य में\nयहां कृष्ण चेतना की प्रकृति, श्रीतत्व और उसके महत्व की व्याख्या करते हैं। जल, सूर्य, चंद्रमा,\nआकाश, पृथ्वी, अग्नि; आत्मबल, वायु, तपस्या हर चीज़ में भगवान की विभूति कैसे छिपी है\nयहां जो संहिताबद्ध और समझाया गया है उसका संक्षिप्त विवरण\nविशेषकर जैसा कि अध्याय दस में देखा जा सकता है]। त्रिगुणात्मक जगत् में हमारा जीवन;\nयहां कृष्ण माया की दुनिया और उससे बाहर निकलने का रास्ता बताते हैं। दुष्कर्मों का\nऔर जिस प्रकार के गुणी सज्जन हैं; उनमें और उनकी भक्ति में महान बात क्या है; ज्ञान और भक्ति से\nयह अध्याय मुक्ति कौन प्राप्त करता है आदि के आध्यात्मिक विज्ञान की व्याख्या करता है। यह\nअध्याय की शुरुआत भगवान की अमृता नुदी से होती है।\n\nभगवान का वचन\nमय्यासक्तमनः पार्थ योगम् युञ्जन मदाश्रयः |\nअसंशयं ग्रुन्तं माम् यथा ज्ञानस्य तच्च नु ॥1॥\n\nभगवान उवाच- भगवान ने कहा:\n\nमाई असक्त मनः पार्थ योगम् युञ्जन मत आश्रयः |\n\nअसंश्यं ग्रुन्तं मम यथा ज्ञानस्य तत् श्रृणु -पार्थ, मेरा हृदय भर दो।\nप्यार करना, खुद को चुनौती देना, योगाभ्यास में संलग्न होना, निश्चित रूप से पर्याप्त जागरूकता\nपूछो तुम मुझे कैसे जान सकते हो.\n\nवह हमारे मन को पागल या बैल की तरह वश में कर उसे उपलब्धि के पथ पर आगे बढ़ाता है\nऊपर, प्रभु में कभी न डगमगाने वाले, दृढ़ और गहरी भक्ति के साथ, अहंकार का त्याग करते हुए,\n\nपूर्ण समर्पण के साथ (हमेशा जागरूक रहें कि हम ईश्वर के अधीन हैं),\nअपने आप को पूरी तरह से भगवान के प्रति समर्पित करने और ध्यान योग में संलग्न होने के बाद,\nकृष्ण से पूछें, \"कोई भगवान को ज्ञान की पूर्ण सीमा तक कैसे जान सकता है?\"\n\nज्ञानं ते$*हं सविज्ञानमिदं वक्ष्यम्यशेषतः\nयज ज्ञात्वा नेहा भूयोकन्याज ज्ञातव्यामवशिष्यते ॥2॥\n\nज्ञानं ते अहम् स विज्ञानं इदं वक्ष्यामि अशतः |\n\nयत् ज्ञात्वा न एह भूयः अन्यत् ज्ञातव्यं अवसिष्यते - मेरी महानता जानने योग्य है।\nमैं तुम्हें बीज सहित पूरी बात बताऊंगा. इस मामले में फिर से जान रहे हैं\nजानने को कुछ भी नहीं बचा.\n\nहर कोई जानता है क्या",
  "6.35": "भगवान उवाच- भगवान ने कहा:\nअसंश्यं महाबाहो मनः दुर्निग्रहं चलम् |\n\nआदतन तू कौन्तेय वैरागेण च गृह्यते -महावीर, बिल्कुल हाँ; एक प्रकार का लचीला,\nपकड़ पर अड़े रहो.  अत्रे कौन्तेय, यत्नी समारादु में लौट आओ और वैराग्य के साथ करो\nकसकर पकड़ सकते हैं.\n\nकृष्ण कहते हैं: “आप जो कहते हैं उसमें कोई संदेह नहीं है\nयह कोई आसान काम नहीं है, लेकिन अभ्यास और समर्पण से इसे धीरे-धीरे हासिल किया जा सकता है।”\nबिना प्रयास के हम कुछ भी हासिल नहीं कर सकते। हर चीज़ में प्रयास की आवश्यकता होती है। हम अपने हैं\nजैसा हमारा मन कहता है, हमने नाचने की आदत बना ली है। जैसा कि हमने कहा, सिवाय इसके कि\nहम कभी भी मन को सुनने की कोशिश नहीं करते। यहां कृष्ण वैराग्य और\nवह अभ्यास के दो बिंदुओं पर जोर देते हैं। वैराग्य का अर्थ है किसी चीज़ का पक्ष लेना\nयदि मन बहना नहीं चाहता तो उसे मन को खिलाए बिना दूर रखा जाता है (9966)। भगवान हमारे लिए\nक्या अच्छा है और क्या बुरा, यह जानने के लिए उसने बुद्धि दी है। वह ज्ञान\nअपने मन को बुराई से दूर रखने के लिए इसका प्रयोग करें। दुष्ट मन से परिचय\nनहीं कर रहा हूँ. इस प्रकार, जो कुछ भी हमारे विकास में बाधा डालता है, वह मन से है\nपरित्याग वैराग्य है। इसके अतिरिक्त निरंतर एकाग्रता का अभ्यास न चूकें\nकृष्ण कहते हैं कि इससे हम निश्चित रूप से मन को नियंत्रित कर सकते हैं।\nआमतौर पर हम अपने दिमाग को हर दिन अनावश्यक प्रशिक्षण देते हैं। उदाहरण के लिए\nहमारे कीमती समय में टेलीविजन पर आने वाले कुछ दैनिक धारावाहिक,\nहम अपना मन पूरी तरह से फिल्मों आदि में लगाते हैं। हमारे लिए आध्यात्मिक\nधर्मग्रंथ पढ़ने का समय नहीं! ईश्वर की आराधना करते समय भी वह हमारे पास है\nसीरियल के अगले भाग को लेकर चिंतित हूं. जब हम रात को बिस्तर पर जाते हैं तो कोई बुरी किताब पढ़ते हैं,\nकोई ख़राब टीवी शो देखकर सोने की बजाय, कोई अच्छा आध्यात्मिक ग्रंथ पढ़ने की आदत डालें\nहमें यह करना होगा और जो हम नहीं चाहते उससे छुटकारा पाना होगा। ये तो एक ही है\nबस एक उदाहरण. यदि हम अपनी दैनिक गतिविधियों पर बारीकी से नजर डालें तो हम ऐसे ही हैं\nऐसे हजारों उदाहरण हैं.\n\nमन उस चीज़ पर अधिक ध्यान नहीं देता जो वह नहीं जानता। लेकिन एक बार आप इसका स्वाद चख लीजिए\nतुम्हें जाने नहीं देंगे. इसका एक अच्छा उदाहरण शराब का सेवन है। उसके लिए जो कभी शराब नहीं पीता\nशराब घिनौनी लगती है. लेकिन एक बार हम मन ही मन अनचाही शराब जबरदस्ती पी लेते हैं\nजब इसका परिचय दिया जाता है तो हमारा मन कहता है, \"आपने इसे एक बार पी लिया है, अब और कुछ नहीं।\"\nऐसा नहीं होगा-पीओ'' कहते हैं! इसका असर क्या होता है, यह यहां बताने की जरूरत नहीं है।\n\nएक और बड़ी गलती जो हम करते हैं वह है उस पर ध्यान केंद्रित करना जो हम नहीं चाहते। “कोई या कुछ\nमानो हो गया''-जब इस तरह का कोई शब्द हमारे कानों में पड़ता है तो हम मन ही मन ऐसा सोचते हैं\nबिना यह सोचे कि जानने का क्या फायदा, हम उस मामले में पड़ जाते हैं। एक बार सिर हिलाओ\nयदि रख दिया जाए तो मन उसे दोबारा जाने नहीं देगा। सब कुछ पीछे छोड़ दो और उस चीज़ पर वापस आ जाओ। इसलिए\nकिसी विषय पर प्रतिबद्ध होने से पहले उसके बारे में सचेत निर्णय लें\nमन को गलत विचार के पीछे भागने से रोकना चाहिए। इसका एक अच्छा उदाहरण ग्रीक है\nदेश सुकरात द्वारा विचार-विमर्श के तीन स्तरों की एक कहानी (716 500/8165)\n711015 91107 7650. एक बार सुकरात का एक परिचित आया और उसने सुकरात से इस प्रकार कहा\nकहते हैं: “क्या आप जानते हैं कि मैंने आपके मित्र के बारे में क्या सुना है? ( 00 08 704/ 4/02! | ]t5! 1058 80001\n5089 119767)।” सुकरात तुरंत कहते हैं, “एक क्षण रुकें (1016 01 3 1117019); तुम मेरे हो\nमित्रा के बारे में कुछ भी कहने से पहले मैं तीन बातें जानना चाहता हूं.\nसबसे पहले, क्या आपके पास वास्तविक जानकारी है कि आप क्या कहने जा रहे हैं?\n30501010/5t98 172! 5/13! )/0टी 398 200! 10 161 716 15 ॥8?)\"। फिर व्यक्ति कहता है: \"नहीं...\nलेकिन मैंने यह प्रश्न पूछा...(“!10, 301431/1 ]t5! 1038 800411 218...)”। अभी\nसुकरात पूछते हैं: \"तो आप बात को ठीक से नहीं जानते(50 )/0टीए 600! 783!1)/ 1104/18\n1 5 868 09 100 वैसे भी, क्या आप जो कहना चाहते हैं वह एक बहुत अच्छा विचार है? (15 5/3)/0t\n378 83000! 10 1011 735 2000! 17)/ 11016 5017900170 90067)\"। फिर व्यक्ति कहता है: \"नहीं, ऐसा है।\nअच्छा विचार नहीं है—इसके विपरीत (॥0, 01 17 00788...'' अंत में सॉट्रेट्स पूछते हैं:\n\"क्या आप जो कहने जा रहे हैं वह मेरे लिए उपयोगी है? (15 08! 06 1521 10\n161 778 2000! 17)/111076 00170 10 0ए 508 10 7197)”। फिर व्यक्ति कहता है \"नहीं (110, 10! 783)\"\nवह है. अब सुकरात कहते हैं, “आप जो कहने जा रहे हैं वह सच नहीं है, अच्छा है\nकोई विचार नहीं, कोई उपयोगी विचार भी नहीं। आप मुझे फिर से क्यों बता रहे हैं? (8 508! 08 531!\n10 161! 17 15 10110 148 109 0008 709 2401 5011, /1)/101! 11 10 17 2! 80)”\n\nप्रिय मित्रों, यहाँ हमें यह सीखने की आवश्यकता है कि मन अच्छा नहीं होता\nप्रतिबद्ध होने से पहले सामग्री को तीन बार फ़िल्टर करना सीखें। न चाहने के मामले में\nवैराग्य विकसित करें और मन की एकाग्रता का अभ्यास करें। यह\nजो लोग इस मार्ग पर चले हैं उनके लिए ध्यान कभी भी असंभव नहीं है।",
  "7.4": "पृथ्वी, जल, अग्नि, वायु, आकाश, मन, बुद्धि, अहंकार — यह मेरी अपरा प्रकृति आठ प्रकार की जड़ है।\n\nसृष्टि से पूर्व समग्र जगत् सूक्ष्म रूप से भगवान् के उदर में था। फिर महतत्त्व, अहंकार, पञ्चतन्मात्रा, पञ्चभूत — इस क्रम से स्थूल सृष्टि हुई। यह सब भगवदधीन जड़प्रकृति है।",
  "7.5": "अपरा (जड़प्रकृति) से ऊपर — परा प्रकृति जीवभूता — यह चित्प्रकृति है, श्रीतत्त्व है। जिसके आधार से यह समग्र जगत् धारित है।\n\nजड़प्रकृति के लिए निमित्तकारण भगवान्, उपादानकारण जड़प्रकृति स्वयं। चित्प्रकृति के लिए — लक्ष्मी माँ रूप में, भगवान् पिता रूप में — दोनों मूलकारण हैं।",
  "7.11": "बलवानों का कामराग-रहित बल — मैं; भूतों में धर्माविरुद्ध काम — मैं।\n\nभगवान् निःस्वार्थ बल और धर्मसम्मत काम देते हैं — काम-राग-युक्त बल नहीं। जहाँ विशुद्धता है वहाँ भगवान् हैं।",
  "7.10": "सब जीवों का सनातन बीज — मुझे जानो। बुद्धिमानों की बुद्धि — मैं; तेजस्वियों का तेज — मैं।\n\nभगवान् हमारी प्रत्येक योग्यता के स्रोत हैं। जो कुछ भी उत्तम गुण हमारे भीतर है — वह भगवत्प्रदत्त है।",
  "7.12": "सात्त्विक, राजसिक, तामसिक — जो भी भाव हैं, वे सब मुझसे ही उत्पन्न होते हैं। किन्तु मैं उनमें नहीं — वे मुझमें आश्रित हैं।\n\nगुण भगवान् से भिन्न नहीं — भगवान् गुणों को स्वातन्त्र्य से प्रवर्तित करते हैं। जीव गुणों से बद्ध, भगवान् गुणेश्वर।",
  "7.22": "वह जीव उस श्रद्धा से उस देवता की आराधना करता है और उससे कामनाएँ पाता है — किन्तु वे फल भगवान् द्वारा ही विहित हैं।\n\nदेवता निमित्त हैं, भगवान् परमनियन्ता — सब फल भगवदाज्ञा से ही।",
  "7.18": "चारों उदार हैं — महात्मा। किन्तु ज्ञानी विशेषतः — 'आत्मैव मे मतम्' — वह भगवान् को अपने आत्मा के समान प्रिय है।\n\nयुक्तात्मा — भगवान् में स्थित; मामेव अनुत्तमां गतिम् — भगवान् को ही परमगति मानता है। ज्ञानी के लिए भगवान् साधन नहीं — स्वयं लक्ष्य हैं।",
  "7.24": "अल्पबुद्धि लोग मुझे — जो अव्यय, परम माहात्म्य वाला हूँ — अव्यक्त से व्यक्त हुआ मानते हैं, मेरे परम भाव को नहीं जानते।\n\nभगवान् का देहधारण मायावत् — वास्तविक नहीं। भगवान् सदैव दिव्य, असंसारी, निर्विकार हैं।",
  "7.25": "योगमाया से आवृत — मैं सबके सामने प्रकट नहीं होता। इसलिए यह मूढ़ जगत् मुझे अज और अव्यय नहीं जानता।\n\nमाया भगवान् की अपनी है। वे जब चाहें प्रकट हों, जब चाहें तिरोहित। जिज्ञासु के लिए भगवान् प्रकट होते हैं।",
  "7.26": "भगवान् को सब कुछ ज्ञात है — भूत, वर्तमान, भविष्य। किन्तु मुझे कोई नहीं जानता।\n\nकालत्रयज्ञ। भगवद्ज्ञान उनकी कृपा से ही — स्वयं के प्रयत्न से पूर्ण नहीं।",
  "7.19": "अनेक जन्मों के अन्त में ज्ञानवान् भगवान् की शरण लेता है — 'वासुदेवः सर्वम्' — ऐसा महात्मा अत्यन्त दुर्लभ है।\n\nवासुदेव-सर्वदर्शन — केवल भगवद्दर्शन नहीं, समग्र जगत् में भगवद्व्याप्ति का दर्शन। ऐसा महात्मा सुदुर्लभ है।",
  "7.9": "पृथ्वी में पुण्यगन्ध — मेरा; अग्नि में तेज — मेरा; सब जीवों में जीवन — मेरा; तपस्वियों में तप — मेरा।\n\nप्रत्येक तत्त्व में, प्रत्येक शक्ति में, प्रत्येक जीव में — भगवान् विशेष नाम से निहित हैं। यही अन्तर्यामित्व है।",
  "7.21": "जो जिस देवता को भक्ति से पूजना चाहता है — उसकी उस देवता में श्रद्धा भगवान् ही दृढ़ करते हैं।\n\nभगवान् सर्वदेवान्तर्यामी हैं — सभी देवों की उपासना भगवान् तक ही पहुँचती है। किन्तु फल का अन्तर है।",
  "7.20": "जिनकी कामनाओं ने ज्ञान अपहृत कर लिया — वे अन्य देवताओं की शरण लेते हैं, अपनी प्रकृति के वशीभूत होकर।\n\nभगवान् से विमुखता का कारण — हृतज्ञानता, कामोपहतचित्तता। देवोपासना निन्द्य नहीं — किन्तु भगवान् को छोड़कर देवोपासना अल्पफल देती है।",
  "7.27": "जन्म लेते ही — इच्छा-द्वेषजन्य द्वन्द्वमोह — सब जीव मोहित हो जाते हैं।\n\nइच्छा-द्वेष, सुख-दुःख, लाभ-हानि — ये मोहित करते हैं। द्वन्द्वातीतता ही ज्ञानमार्ग का आरम्भ है।",
  "8.1": "अर्जुन उवाच\n\nकिम् तत् ब्रह्म किम् अध्यात्मम् किम् कर्म पुरूषोत्तम।\n\nअधिभूतं च किं प्रोक्तं अधिदैवं किं उच्यते -अर्जुन ने पूछा: पुरूषोत्तम,\nजो वह है. 'ब्रह्म'? 'अध्यात्म' है. 'कर्म' क्या है? जो\n\"अधिभूत' क्या है? 'अधिदैव' क्या है?\n\nअर्जुन ने कृष्ण से पूछा, \"तत् ब्रह्म (वह ब्रह्म) क्या है? अध्यात्म क्या है?\"\nऔर कर्म क्या है?” वह है. अर्जुन के इस प्रश्न के पीछे व्यास की भावना है\nउन्होंने इसे पकड़ कर \"पुरुषोत्तम\" विशेषण में हमारे सामने प्रस्तुत किया है। पुरूषोत्तम का अर्थ है\nवह जो क्षर (जीवन) से परे है। वह अक्षरा से उम्र में बड़े हैं. “अक्षर-अक्षर से परे खड़ा हूं\nआप ही पुरूषोत्तम हैं, आपके अतिरिक्त कोई तत्त्व नहीं है, अत: मैं जानता हूं कि आप ही आप हैं\nब्रह्मा. अर्जुन ने यह भावना व्यक्त की कि इसका स्पष्टीकरण आपसे जानना चाहिए\n'पुरुषोत्तम' विशेषण यही सूचित करता है। अर्जुन पूछता है. “कौन सा\nआप अधिभूत किसे कहते हैं? अधिदैववेन किसे कहते हैं?” वह है।\n\nअधियग्नः कथं को5त्र देहे$स्मिन् मधुसूदन |\nकर्जकाले च कथं ज्ञेयोजसि नियत्मविः",
  "7.23": "देवयाजियों का फल — अन्तवत् — नाशवान्, क्षणिक। वे देवलोक पाते हैं, पुनरावर्तन होता है।\n\nमद्भक्ता मुझे प्राप्त होते हैं — मोक्ष पाते हैं, पुनर्जन्म नहीं। भगवद्भक्ति का फल अव्यय है।",
  "7.15": "कौन भगवान् की शरण नहीं लेते? दुष्कृती — नित्यपाप-निरत; मूढ़ — ज्ञानशून्य; नराधम — मनुष्यत्व व्यर्थ करने वाले; माया द्वारा जिनका ज्ञान अपहृत; आसुरभाव-आश्रित।\n\n'आसुर' यहाँ जाति नहीं — ज्ञानविरोधी स्वभाव।",
  "7.16": "सुकृती — पुण्यशाली — चार प्रकार से भगवान् को भजते हैं। आर्त — क्लेशनिवृत्ति के लिए; जिज्ञासु — भगवत्स्वरूप जानने को; अर्थार्थी — ऐहिक सम्पदा चाहते हुए; ज्ञानी — भगवद्भक्तिपरायण।\n\nये सभी सुकृती हैं — पाप से भगवान् की शरण नहीं मिलती; पुण्य ही भगवन्मुख कराता है।",
  "8.12": "ओमित्येक्षरं ब्रह्म व्याहारं मामनुस्मरण |\nयः प्रयति त्याजं देहं स याति परमं गतिम्",
  "8.5": "अंतकाले च माँ एव स्मरण मुक्त्वा कालेबरम |\n\nयः प्रयति सः मत भावम् यति न अस्ति अत्र संशयः - अन्त में भी मैं स्वयं\nवह जो मेरे जैसे शरीर को छोड़ देता है और शरीर को छोड़ देता है, वह दुख के बिना आनंद की वास्तविकता है [अपने आप में\nइरवा] मिलता है।\n\nअर्जुन के अंतिम प्रश्न का उत्तर देते हुए, कृष्ण कहते हैं: “मृत्यु के क्षण में भी, मैं स्वयं हूं\nजो जीव लीन होकर शरीर का त्याग करते हैं वे मेरे ही समान ज्ञान रूप में मेरे पास आते हैं\nबस जाएगा. वे इस अज्ञानी और दुखी दुनिया में हमेशा के लिए हैं\nअतिसंवेदनशील नहीं. इस बारे में कभी संदेह मत करना।” यहाँ \"एंटाकेल\" का अर्थ मप्पी है\nइसका मतलब समय से नहीं है, बल्कि इसका मतलब शरीर छोड़ने का आखिरी क्षण है। शरीर\nजो आत्मा प्रभु का स्मरण करके निकलेगी उसे अपार प्रकाश दिखेगा और\nवह भावना मोक्ष की ओर ले जाती है। [जीव शरीर को छोड़ने और शरीर से बाहर आने पर\nजीवन यात्रा में मरने वाले और जीवित रहने वाले अनेक लोगों के अनुभव एकत्रित करें 12/11018 ga0006)/\n\"9 310! (/19\" लिखी पुस्तक प्रकाश डालती है)।",
  "7.28": "जिनके पाप क्षीण हो गए, जो पुण्यकर्मी हैं — वे द्वन्द्वमोह से मुक्त होकर दृढ़व्रत से मुझे भजते हैं।\n\nपुण्यसञ्चय भगवद्भक्ति का आधार है — फल के लिए नहीं, मनःशुद्धि और भक्ति के लिए।",
  "8.2": "अधियज्ञः कथं कह अत्र देहे अस्मिन मधुसूदन।\nयात्रा काले च कथं जतेयः असि नियत अतंभिः-मधुसूदन, यहीं इस शरीर में\n\"शासक कौन है? और कैसे? नियंत्रण करने वालों को अंतिम दिनों में आपको कैसे याद रखना चाहिए?\n\nआगे बढ़ते हुए, अर्जुन पूछता है: \"अधियज्ञ कौन है?\" वह है। हमारे शरीर के अंदर\nअधीक्षक कौन है और कैसे? अधियज्ञ का क्या अर्थ है? वह अर्जुन का प्रश्न है। यहाँ फिर से\nव्यास हमें अर्जुन के प्रश्न का आभास कराने के लिए \"मधुसूदन\" विशेषण का प्रयोग करते हैं\nसूचित करता है.   \"मधुसूदन\" नाम के दो महत्वपूर्ण अर्थ हैं। \"शहद\" यानी\nआनंद (!119 0855)। \"सुदा\" का अर्थ है अच्छे कर्म करने वाले सात्विक। इसलिए मधुसूदन\n\nइसका मतलब है जो सात्विक है और उन्हें खुशी देता है। \"सुदा\" का अर्थ है विनाश\nएक और मतलब है. तो यह मधुसुदा ही है जो दुष्टों के सुखों को नष्ट कर देता है। “हमारे भीतर\nआप ही सुख देने वाले हैं और आप ही दुःख देने वाले भी हैं। सभी बलिदान हमारे भीतर हैं\nआप ही नियंत्रण में हैं. तो मैं समझ गया कि आप मालिक हैं. यह मेरे लिए है\nव्यास ने यहां अर्जुन विशेषण के माध्यम से अर्जुन का अर्थ बताया है\nपूछता है “हमारे जीवन की अंतिम महान यात्रा में जीवन के शरीर से प्रस्थान के करीब\nऔर जाने का विवरण बताओ”।\n\nउपरोक्त श्लोक में प्रयुक्त दो विशेषण हैं-पुरुषोत्तम और मधुसूदन\nजब हम पिछले अर्थ को देखते हैं, तो हमें स्पष्ट रूप से समझ में आता है कि - अर्जुन के लिए, ये छह चीजें हैं\n(शब्दों का) सही अर्थ जानने के लिए। हालाँकि, इसका विवरण प्रभु से पता चलेगा\nवह जानबूझकर कृष्ण से यह प्रश्न पूछता है। हालाँकि जो जानते हैं वे आम तौर पर स्वयं को जानते हैं\nवे दूसरों को सूचित करने के इरादे से भी इस तरह के प्रश्न पूछते हैं। यहाँ स्वयं अर्जुन हैं\nसंपूर्ण मानव जाति के लिए ईश्वर के बारे में जो कुछ ज्ञात है उसकी पुष्टि करना\nकृष्णा ने ये सवाल स्पष्ट करने के लिए रखा.\n\nहम सोच सकते हैं कि \"अर्जुन युद्ध के मैदान में खड़ा होकर ऐसे प्रश्न क्यों पूछ रहा है? यहाँ।\"\nइसकी क्या जरूरत है?” वह है। युद्ध के मैदान में खड़े लोगों के लिए मृत्यु अक्सर चिंता का विषय होती है\nकिसी और को परेशान नहीं करता. अचानक मौत उनका इंतजार कर रही है. वे मृत्यु और मृत्यु हैं\nपरे की स्थिति से अवगत. मृत्यु से परे जो है वह सैनिकों के लिए बहुत महत्वपूर्ण है\nमहत्वपूर्ण है. कृष्णार्जुन के अब तक के संवाद में कहीं भी कृष्ण अर्जुन विजयी नहीं हुए हैं\nवादा नहीं किया गया. उन्होंने कहा कि धर्म के लिए लड़ना आपका कर्तव्य है. इसलिए\nयुद्ध के मैदान में अर्जुन के लिए मृत्यु और मृत्यु से परे क्या है यह एक बहुत ही महत्वपूर्ण मुद्दा है।\nआठवें अध्याय का शेष भाग अर्जुन के प्रश्न का भगवान का उत्तर है।",
  "8.11": "यथ अक्षरं वेदविदः वदन्ति विशन्ति यथ यथायः वीत रागः |\n\nयत् इच्छान्तः ब्रह्मचर्यं चरन्ति तत् ते पदं सचेण प्रवक्ष्ये - जो वेदों को जानता है\nइसे 'अक्षर' कहा जाता है जो विलुप्त नहीं है। भोग-विलास त्याग चुके साधक इसमें शामिल होते हैं। यह\nवह वरिष्ठ दर्शन समावेशन के तरीके से चिंतित है।     ऐसी मुक्ति\nचलिए मैं आपको मतलब बताता हूं.\n\nकृष्ण कहते हैं, ''वहां ध्यान करने से वह जीव जो योग की सिद्धि से स्थिर हो गया है\nइसे सहस्राब्दी तक ले जाना चाहिए।” इस दौरान ध्यान करने योग्य एक रूप\nइस पर टिप्पणी करते हुए, कृष्ण कहते हैं, \"जो लोग वेदों को जानते हैं वे इसे एक अमिट 'अक्षर' (ओंकार) के रूप में जानते हैं।\n\"सर्वशब्द वाच्य (जिसे अक्षर द्वारा दर्शाया जाता है)\" प्रभु को बड़े प्रयत्न से कहा जाता है\nसांसारिक उलझनों से मुक्त होकर साधक, जाकर उस प्रभु से जुड़ जाते हैं। “वे हैं\nवह ऐसे भगवान को जानना चाहता है और अपने जीवन में ब्रह्मचर्य अपनाना चाहता है”\nकृष्ण कहते हैं. [यहाँ 'ब्रह्मचर्य' का अर्थ शारीरिक ब्रह्मचर्य नहीं है, जैसा कि शब्दकोश कहता है\n\"ब्राह्मणि चरणम्'-ईश्वर पर स्थिर मन। ब्रह्मचर्य]। \"इससे जुड़ें।\nउस वरिष्ठ सिद्धांत को रास्ते की चिंता है. यही मोक्ष प्राप्ति की प्रक्रिया है\nमैं तुम्हें विस्तार से बताऊंगा” कृष्ण ने इस प्रक्रिया को निम्नलिखित श्लोक में कहा\nवह अर्जुन को समझाते हैं।",
  "8.7": "तस्मात् सर्वेषु महाविद्यालय मम अनुस्मार युध्य च।\n\nमयि अर्पिता मनः बुद्धिः मम एव अस्यसि असमशयः - इसलिए हर समय मेरा स्मरण करो।\nभीगते हुए लड़ो. जब आपकी सभी इच्छाएँ और निर्णय मेरे बारे में हैं, तो निश्चित रूप से मेरे बारे में\nशामिल होना\n\nभगवान को याद करने का समय नहीं है. कृष्ण कहते हैं, “मुझे हमेशा याद रखो\nकरो” प्रत्येक कर्म करते समय जो उस कर्म को कर रहा है उसे भगवान कहते हैं\nसतर्क रहें. युद्ध के दौरान भी, \"वह भगवान मेरे अंदर बैठा और उसने यह काम किया\nकर रहा हूँ, ये. \"उनका संकल्प\" युद्ध और ईश्वर की आराधना की भावना है\nधर्मान्तरित! हमारे जाने-अनजाने में किए गए गलत कार्यों में भी ईश्वर का बोध होता है।\nसमर्पण हमें पाप से कलंकित होने से बचाता है। प्रभु के स्मरण के लिए किसी भी समय\nकोई रोक-टोक नहीं...जब भी भगवान की याद आये, वही शुभ घड़ी है.  उसकी स्मृति\nजो भी आपके मन में है उसे मोड़ो. इसलिए अहंकार रहित होकर भगवान को पूजा स्वरूप याद करें\nकर्तव्य निभाना चाहिए.\n\nक्रिया में इरतक्क भाव धर्म-अधर्म का निर्धारण करता है। उदाहरण के लिए धर्मव्यादा. वह\nकसाई भी बहुत धार्मिक जीवन जीता था। क्योंकि उनका दृष्टिकोण शुद्ध था.\n“भगवान ने मुझे इस काम में लगाया है, इस जीवन में मेरा कर्तव्य मांस बेचकर गुजारा करना है\nउनका दृष्टिकोण था कि वह इसे ईमानदारी से करें और अपना जीवन आगे बढ़ाएं\n\nवह केवल अपना और अपने परिवार का भरण-पोषण करने के लिए व्यवसाय कर रहा था। इस तरह\nईमानदारी से जीवन व्यतीत करते हुए वह सुखों से भी आगे निकल गया। अतः भाव शुद्धि सबसे अधिक है\nमहान इसलिए हमें अपने मन और बुद्धि को भगवान में लगाना चाहिए। “फिर\nनिश्चित रूप से मेरे साथ जुड़ें, ”कृष्णा कहते हैं।\n\nमोबाइल फोन नंबर |\nपरमं पुरुषं दिव्यं याति पार्थानुचिन्तयं",
  "8.14": "अनन्य चेतः सदातम यः मां स्मरति नित्यशः।\nतस्य अहम् सुलभ: पार्थ नित्य युक्तस्य योगिनः - पार्थ, बिना किसी और चीज के बारे में सोचे दिन-ब-दिन।\nजो निरन्तर मुझे स्मरण करता है, जो ऐसी निरन्तर प्राप्ति से सम्पन्न होता है, मैं उसे समर्पण करता हूँ।\n\n\"उस भक्त के लिए जो निरंतर भगवान का ध्यान करता है और कभी किसी और चीज के बारे में नहीं सोचता।\nकृष्णा कहते हैं, ''मैं आसानी से वश में हो जाऊंगा।'' सदैव सिद्धि, सिद्धि में लगे रहो\nजो अंत तक पहुंच गया है वह बिना किसी अन्य प्रयास के भगवान से जुड़ जाता है\n\nमामुपेत्य पुनर्जन्म दुक्खालयमशाश्वतम।\n\nन*पुन्नुवंति महात्मनः संसिद्धिम परमं गतः",
  "8.4": "अधिभूतं क्षरः भवः पुरुषः च अधिदैवतम् |\n\nअधियज्ञः अहं एव अत्र देहे देहभृतं वर- जन्म और मृत्यु का सामूहिक ब्रह्मांड।\n[संगठित जीव] \"अधिभूत\", शरीर के भीतर शासी सिद्धांत।\nदेवता [दुनिया की सर्वोच्च प्रेरक शक्ति के रूप में \"पुरुष\" के रूप में श्रीतत्व] 'अधिदैव'। हे ज्येष्ठ जीवा,\nइस शरीर में मैं \"अधियज्ञ\" हूं।\n\nजैसा कि पिछले श्लोक में देखा गया है, अध्यात्म का अर्थ है शरीर में फंसा हुआ जीवन। इस जीवन का\nइस पांच गुना संसार के सभी विचार आनंद के लिए बनाए गए हैं\nरहस्य में शामिल है. पंचभूत की उत्पत्ति और पंचभूत से जगत का निर्माण |\nअलौकिक जड़ प्रकृति से लेकर स्थूल ब्रह्माण्ड तक, जो कुछ भी त्रिगुणात्मक है वह 'अधिभूत' है।\n\nकृष्ण कहते हैं. यथा ''पुरुषश्चाधिदैवतम्''। इस शरीर के भीतर के जीवन के लिए\nऐसे देवता हैं जो मदद के लिए शरीर में विभिन्न इंद्रियों को नियंत्रित करते हैं।\nयह एक दिव्य विज्ञान है. यह एक चेहरा है. इसे देखने का दूसरा तरीका यह है कि कृष्ण \"पुरुष\" हैं।\nउन्होंने उसे संबोधित किया. हमारे शरीर में चार \"पुरुष\" होते हैं।\nवेदपुरुष और संवत्सरपुरुष। यदि इस शरीर को खड़ा होना पड़े और चलना पड़े तो यह पुरुष शरीर बन जाता है\nशिव शक्ति चाहिए। मन जो सोचता है वह स्पंदना, पराशर, पश्यन्ति, मध्यमा और वैखरी के रूप में होता है\nयह शेष, छंद पुरुष के कारण है, कि वह वाणी की शक्ति के रूप में उभरता है। मनोमय कोष में,\nवेदपुरुष गरुड़ जो वेदान्त का विचार, मन में मानसिक शक्ति प्रदान करते हैं। हमारे लिए वेदपुरुष\nअद्वितीय वैदिक वाज्मय आपको शक्ति प्राप्त कराता है। जीवन का मूल्य, संपूर्ण\nवह चतुर्मुख ब्रह्मा हैं, जो जीवन की कला के स्वामी हैं, जो जीवन की प्रकृति को नियंत्रित करते हैं\nसालगिरह वाला आदमी. [“सं-वत्स-रा'- का अर्थ है पिता जो बच्चों का अच्छी तरह से पालन-पोषण करता है]। ब्रह्म-वायु\nजीवन को उन्नत कर सिद्धि के पथ पर लगा देता है। इस प्रकार ये पंचदेव भगवान के हैं\nफिर शरीर में मुख्य देवता। सम्पूर्ण ब्रह्माण्ड उन्हीं के द्वारा नियंत्रित होता है\nअलौकिक\n\nकृष्ण आगे कहते हैं: मैं प्रत्येक शरीर के भीतर एक रूप में हूं\nवह है. भगवान का यह स्वरूप 'अधियज्ञ' स्वरूप है।\nभोक्तारा, यज्ञ के कर्ता, कर्ता और फल देने वाले भगवान अधियज्ञ। हम हैं\nयह जानकर कि यह भगवान की पूजा का एक रूप है, किया गया सभी कर्म यज्ञ है। \"यज देव पूजयाम्\" -\nहमारे जीवन का प्रत्येक कार्य ईश्वर की आराधना है। सब कुछ हमारे शरीर के अंदर है\nभगवान जो भक्त देवताओं के माध्यम से कार्य करते हैं वह \"अधियज्ञ\" हैं।\n\nयदि हम इस श्लोक को दूसरे आयाम में देखें [पिछले श्लोक में भगवान-भगवान का स्वरूप\nऔर उसके कार्य का अर्थ विश्लेषण के रूप में है] 1 अधिभूत का अर्थ है ब्रह्म सदृश देवता।\nआध्यात्मिक संसार, जीवित प्राणी, शरीर, ब्रह्म और ब्रह्मांड सभी पारलौकिक हैं। सभी\nभगवान के बाद जो बाकी देवता हैं, ब्रह्मा *शक्ति' श्रीतत्त्व हैं जो देवताओं की माता हैं\nअधिदैव हर जगह भगवान से भरा हुआ है जो सभी जीवित प्राणियों के भीतर खड़ा है और उन्हें नियंत्रित करता है\nअधीक्षक\n\nअंतकाले च मामेव स्मरण मुक्त्वा कालेबरम |\n\nयः प्रयति स मद्भवं यति नास्यात्र संशयः",
  "8.15": "माम् उपेत्य पुनः जन दुःख आलयम अश्वत्थम |\n\nन अप्पुवंति मह आत्मानः संसिद्धिम परमं गतः - ऐसा व्यक्ति जिसने वरिष्ठ सिद्धि प्राप्त कर ली हो।\nजीवों द्वारा मुझे प्राप्त करने के बाद, इस चार दिवसीय संसार, दुगुदास के निवास, में फिर से जन्म लेना\nनहीं आता\n\nजो जीव सिद्धि प्राप्त करके भगवान से जुड़ जाता है, वह सदैव दुःखी एवं दुःखी रहता है\nइस अनित्य संसार में पुनर्जन्म नहीं होता। “जो लोग आते हैं और मुझसे जुड़ते हैं वे पवित्र आत्माएं हैं।\nसंसार में जीवन की प्राप्ति में सबसे बड़ी सिद्धि ईश्वर प्राप्ति है। यह\nजो लोग इसे प्राप्त कर लेते हैं उन्हें दोबारा पारिवारिक बंधनों में फंसने की जरूरत नहीं होती है,'' कृष्णा कहते हैं।",
  "8.9": "कवीम पुराणं अनुशासितारं अनोह अनियमसं अनुसमरेथ यः।\n\nसर्वस्य धात्रं अचिन्त्य रूपं आदित्य वर्णं तमसः परस्तात् - सर्वज्ञ,\nवह जो सबसे पहले है, सबका स्वामी है, परमाणु से भी ऊपर परमाणु है, जो सबको धारण करता है, सलाह देता है\nवह जो निरंतर खड़ा रहता है, जो सूर्य की तरह चमकता है, जो अंधेरे से परे है [हजारों] - इस प्रकार\nवह जो उससे जुड़ता है [उससे जुड़ता है]।\n\nहमारे मध्यस्थ भगवान पर ध्यान करते समय, \"चीजों से संपर्क किया जाना चाहिए\"\nकृष्ण हमें यहां बताते हैं. कृष्ण कहते हैं, \"एक कवि के रूप में भगवान की पूजा करो\"\nवह है. यहाँ कवि का अर्थ सर्वज्ञ से है। सबसे पहली चीज़ जो हमें चाहिए वह है ज्ञान। बिना ज्ञान के\nप्रसन्नता नहीं। इसके लिए सबसे पहले भगवान से ज्ञान प्राप्त करना चाहिए। दूसरे, भगवान\nकृष्ण कहते हैं पूजा को पुराणम्। पुराण का अर्थ है सबसे पहले और सबसे महत्वपूर्ण\nजो हर काल में अद्वितीय है. हमारे पुरा (शरीर) के अंदर बैठे हैं और हमारा इंतजार कर रहे हैं\nनियंत्रक के रूप में दृष्टिकोण.\n\nतीसरे हैं भगवान 'अनुशासीताराम'। यानी एक-एक नियम.\nकर्ता मेरा अस्तित्व, दुनिया में हर चीज़ का अस्तित्व-उसके नियंत्रण में है;\nएहसास करें कि भगवान प्रत्येक जीवन रूप की योग्यता के अनुसार कानून बनाते हैं\nउनसे संपर्क किया जाना चाहिए. वह प्रभु जो संपूर्ण ब्रह्माण्ड में व्याप्त है, एक परमाणु से भी बढ़कर है\nवह अणु के रूप में जीवन रूप में भरा हुआ है। “वह भगवान जो सब कुछ धारण करता है वह हमारे भीतर बैठता है\nवह पालन-पोषण कर रहा है. वह संपूर्ण ब्रह्मांड की धारण शक्ति है। वह सबके लिए है\nसमस्त मंगलों के दाता के रूप में उनका ध्यान करना चाहिए।\n\nहमें यह जानना चाहिए कि ईश्वर हमारी कल्पना से परे है। वह हमारे मन की बात है\nअछूता रूप. यदि आप ध्यान में जीवन की आंखों से भगवान को देखेंगे, तो वह जाग उठेंगे\nसूरज जैसा दिखता है. उसका रंग प्रकृति का बनाया हुआ रंग नहीं, त्रिगुना है\nअमर रंग. इस प्रकार जो भगवान को जानता है और निरंतर सोचता है वह अपने शरीर का त्याग करता है\nकरते समय वह प्रभु को याद करता है और प्रभु से जुड़ जाता है।\n\nप्रजाकाले मनसा$*चालेन भक्त्या युक्तो योगबलेन चैव |\nभ्रुवोर्मध्ये प्राणमावेश्य सम्यक शतमपरं पुरुषुमुपैथि दिव्यम्",
  "7.29": "जरा-मृत्यु से मुक्ति के लिए जो मुझे आश्रय लेकर यत्न करते हैं — वे ब्रह्म, अध्यात्म, और समस्त कर्म को जानते हैं।\n\nभगवच्छरणागति समस्त ज्ञान का द्वार है — ब्रह्मज्ञान, अध्यात्मज्ञान, कर्मज्ञान — सब भगवद्भक्ति से एकसाथ सिद्ध होते हैं।",
  "8.22": "पुरुषः स परः पार्थ भक्त्या लभ्यस्त्वनन्यया ।\nयस्यान्तःस्थानि भूतानि येन सर्वमिदं ततम् ॥\n\n'हे पार्थ, वह परम पुरुष — जिसमें सब भूत अन्तःस्थ हैं, जिससे यह सब व्याप्त है — अनन्य भक्ति से प्राप्त होता है।'\n\n'अनन्यया भक्त्या' — अनन्य भक्ति — यही एकमात्र मार्ग। 'यस्यान्तःस्थानि भूतानि' — जिसमें सब भूत स्थित। 'येन सर्वमिदं ततम्' — जिससे सब व्याप्त। यह ध्यान-योग अध्याय का परम निष्कर्ष।",
  "8.19": "भूत ग्रामः सः एव अयं भूत्वाभूत्वा प्रलीयते |\nरात्रि अगामे पार्थ प्रभावति अहा अगामे हो सकता है - पार्थ, पंचभूतों का एक ही समूह\nजब रेत फिर से जन्म लेती है, तो वह भगवान के अधिकार में विलीन हो जाती है; दिन के दौरान पैदा हुआ.\n\nसृष्टि का सार कभी नहीं बदलता। वही पंचभूत सृजन और विनाश में लौट आते हैं\nएक पहिये में घूमना. अनंत जीव, जो मोक्ष के योग्य नहीं हैं, वे भी इस चक्र में घूमते हैं। लेकिन\nजो जीवन भगवान का है वह इस चक्र से परे है।\n\nपरस्तस्माथु भावो5न्योथव्यक्तो व्यक्तत सनातनः |\nयः स सर्वेषु भूतेषु नश्यत्सु न विन्यशति",
  "8.16": "वह ब्रह्मभुवनाथ लोकः पुनः अवर्तिनः अर्जुनः।\nमम उपेत्य तु कौन्तेय रे जन्म न विद्यते - अर्जुन, ब्रह्म लोक तक सर्वथा।\nउसे संसार से भी वापस आना होगा। कौन्तेय, मेरा प्राप्त हो जाने पर ही पुनर्जन्म नहीं होता।\n\nब्रह्मा के लोक से लेकर अन्य सभी लोकों में एक दिन विनाश होगा। चतुर्गुणी ब्राह्मण\nआयु 31,104,000,0000000 (इकतीस हजार एक सौ चार हजार करोड़) वर्ष। ये है\nप्रभु के लिए एक दिन के समान! ईश्वर कालातीत है. तो कृष्ण कहते हैं “जब तुम मुझे पाओगे\nकेवल पुनर्जन्म नहीं होता.\n\nसहस्रयुगपरायणतमहार्यद् ब्राह्मणो विदुः।\n\nरथं युगसहस्रंथं तेन्होरात्रविदो जनः",
  "8.18": "अव्यक्तत् व्यक्तयः सर्वः प्रभावन्ति अहः अगमे |\nयह कैसा अव्यक्त संकेत है, जैसे रात में जल प्रलय - वह सब अदृश्य भगवान से देखा जाता है।\nवे दिन के दौरान बनते हैं, और अंधेरा होने पर उसी अदृश्य भगवान में गायब हो जाते हैं।\n\nमहाप्रलय के समय अव्यक्त भगवान से प्रकट हुआ यह संसार परमाणु रूप में था\nपुनः निर्माण के समय पुनः सूक्ष्म रूप से स्थूल रूप में जुड़ जाता है\nप्रकट होते हैं.\n\nभूतग्रामः स एवायं भूतभूत्वा प्रलीयते |\n\nरथ्र्यागामे$ संभवतः पार्थ प्रभावत्याहारागामे",
  "8.20": "परः तस्मात् तु भवः अन्यः अव्यक्तः अव्यक्त सनातनः।\nयः सः सर्वेषु भूतेषु नष्टत्सु न विन्यशति - इस दृश्य जगत से भिन्न,\nसर्वदा विद्यमान तत्त्व अव्यक्त है। यह तब भी मौजूद रहता है जब सभी राक्षस ख़त्म हो जाते हैं।\n\nजो भगवान सबसे परे है, वह विचित्र और महान है। वह शाश्वत है. हर समय\nसमस्त नैतिक जगत् के नष्ट हो जाने पर भी निर्विकार, सर्ववैदिक प्रतिपाद्य होना\n\nभगवान ही एकमात्र सिद्धांत है जो नष्ट हुए बिना सब कुछ समाहित कर लेता है।\n\nअव्यक्तो5क्षर इत्युक्तस्तमहु परमं गतिम् |\nयं प्राप्य न निवर्तन्ते तद् धाम परमं मम",
  "8.10": "यात्रा काले मनसा अचलेना भक्त्या युक्तः योगबलेना च एव |\n\nभ्रुवो मधे प्रणाम आवेस्य सम्यक सः तम परम पुरुषम उपैति दिव्यम् - अंतिम\nप्रभु के प्रति समर्पित, कभी-कभी भौहों के बीच में श्वास लेते हुए, कसकर\nउसे निश्चल रखते हुए, प्रहयाम योग के माध्यम से भी वह लीलालोलन हो गया\nव्यक्ति को परमपुरुष की प्राप्ति हो सकती है।\n\nहठ योग भगवान से जुड़ने का एक और तरीका है। ये रास्ता कठिन है. ये है\nयमनीयमान-प्रहायम-प्रत्याहार के माध्यम से भगवान तक कैसे पहुंचें। इस प्रकार से\n\nइस श्लोक में कृष्ण बताते हैं कि मोक्ष प्राप्त करने वालों को अपनी मृत्यु के समय क्या करना चाहिए\nसमझाता है. स्थिर शरीर, स्थिर प्राणमय कोष के लिए आसन प्राणायाम करें\nप्राप्त होने पर प्रत्याहार के माध्यम से उन बुराइयों को बाहर निकालो जो उसके अंदर भर गई हैं, बुरी\nध्यान भटकाने वाली चीजों से बचें और ध्यान केंद्रित करें। यह एक बहुत ही दृढ़ और कठिन उपलब्धि है।\nऐसा व्यक्ति अपने हृतकमल मध्य (अनाहत चक्र) में वहां की प्राण शक्ति के साथ रहता है।\nभृमध्या (दोनों भौंहों के बीच स्थित अजना चक्र) विशुद्धिचक्र के माध्यम से उर्ध्व मुख के रूप में।\nइसे लाकर रोका जाना चाहिए. यह प्रक्रिया बहुत कठिन है. इस संपूर्ण क्रिया में अनन्य भक्ति अत्यंत महत्वपूर्ण है। यह\nयदि जीव सहस्रार के ब्रह्मरंद्र के माध्यम से भ्रम से बाहर जाता है, तो वे प्रत्यक्ष हैं\nप्रभु से जुड़ जाता है.\n\nचूंकि हठ योग का यह रूप एक कठिन उपकरण है, इसलिए पूर्वजों ने इसे एक बहुत ही सरल उपकरण के साथ पूरक किया\nयह विधि उनके दैनिक जीवन में शामिल थी। इसका एक अच्छा उदाहरण\nओढ़वापुण्डरा.  इसका संबंध जीवन की उर्ध्व गति से है। यह पूर्ण मात्रा में है\nशरीर में ऊर्जा केन्द्रों को जागृत करने की सरल विधि। [लेकिन आज मौत क्यों\nहम नहीं जानते कि हम इसे नाम से खरीदेंगे]।\n\nउचित मार्गदर्शन के बिना हठ योग करना खतरनाक है। भागवत का दूसरा\nस्कंद ने एक अध्याय में जीव तक पहुंचने वाले चरणों का विस्तार से वर्णन किया है\nसमझाया. इस प्रकार कोई योग के माध्यम से ध्यान करके भगवान से जुड़ सकता है, या माँ से जुड़ सकता है\nएक भक्त हमेशा एक बच्चे की तरह भक्ति पर जोर देकर भगवान से जुड़ सकता है।\n\nइस प्रकार कृष्ण ने जीवन को भ्रम में लाने और रोकने की विधि समझाई, और वहां से आगे\nसहस्रार शक्ति केंद्र के द्वार से जीवन किस प्रकार बाहर निकलता है, इसके बारे में अधिक विस्तार से बताया गया है\nवह अगले तीन श्लोकों में बताते हैं।\n\nयदक्षरं वेदविदो वदन्ति विशन्ति यद् यतयो वीतरागः |\nयदिच्छन्तो ब्रह्मचर्यं चरन्ति तत् ते पदं सःक्रमेण प्रवक्षये",
  "8.23": "यत्र काले तु अनावर्तिम वर्धम् च एव योगिनः |\n\nप्रयतः यान्ति तम कालम् वक्ष्यामि भरत ख़ुशभा - भरत श्रेष्ठ, किस काल के देवता\nजो लोग रास्ते पर चलते हैं वे वापस नहीं आते और किस तरह से वापस आते हैं\nआइए मैं आपको समय की देवी के बारे में बताता हूं।\n\n''जो मनुष्य काल के अधीन होकर शरीर का त्याग करता है, उसके जीवन पर कौन से देवता शासन करते हैं।''\nआगे बढ़ाया जाएगा; जो लोग किस रास्ते पर जाते हैं वे फिर से धरती पर जन्म लेते हैं\nऔर जो भी सीधे मोक्ष प्राप्त करता है, वह मैं तुम्हें बताऊंगा, ”कृष्ण कहते हैं।\nइधर कुछ लोग समय शब्द को गलत भी समझते हैं। इस श्लोक में कृष्ण समय के बारे में बताते हैं\nवह समय नहीं है. \"काल\" देवताओं का शरीर है जो बलिदान किये गये शरीर के जीवन पर शासन करते हैं।\n\nअग्निर्जोतिरः शुक्लः षण्मासा उत्तरायणम् |\nतत्र प्रयता गच्छन्ति ब्रह्म ब्रह्मविदो जनः",
  "8.13": "सर्वद्वारनि संयम मनः हृदि निरुद्ध च।\n\nमूर्धनी अध्या आत्मनः प्राणं अशितः योग धारणम् |\n\nॐ इति एकाक्षरं ब्रह्म व्याहारं मम अनुस्मरण।\n\nयः प्रयति त्याजं देहम सः याति परमं गतिम् - सभी नाड़ी द्वारों को अवरुद्ध करें।\nभगवान को पकड़ो और अपनी सांस को अपने सिर में रखो। योग\nवह जो सिद्धि में स्थापित है, एकाक्षर 'ओम' द्वारा उच्चारित परतत्व का जश्न मना रहा है,\nमुझे आत्मसात करते हुए, जो शरीर छोड़ता है और ऊपर चढ़ता है वह बिना वापसी वाले धाम में शामिल हो जाता है।\n\nजीवन को सहस्रार की ओर ले जाते समय शरीर के अन्य सभी द्वारों को योग बल द्वारा बंद कर दिया जाता है\nबंद सहस्राब्दी दरवाजा बंद करो और खोलो और बाहर जाओ। ऐसा करते समय\nमन को उस सर्वनाश करने वाले भगवान में ही स्थिर करना चाहिए। उसका पूरा माप\nयोग का अभ्यास करें, अपनी सांस रोकें और अपने मन को भगवान पर केंद्रित करके ध्यान करें।\n\n“ओंकार प्रतिपद्यम्, मुझे ओंकार में भिगोते हुए, सहस्रार द्वार से बाहर आओ\nजो अपने शरीर का त्याग करता है वह मोक्ष (भगवान) की ओर चढ़ जाता है, जहां से वह कभी वापस नहीं लौटता\n\nजुड़ता है\"।\n\nयह उपलब्धि केवल मेहनती लोगों के लिए ही संभव है और यह बहुत कठिन उपलब्धि है। हर कोई ऐसा ही है\nयोगाभ्यास से सिद्धि प्राप्त नहीं की जा सकती। उसके लिए अगले श्लोक में कृष्ण आसान हैं\nरास्ता बताते हैं.\n\nअनन्यचेतः पाकादन्योमं स्मरति नित्यशः |\nतस्यहं सुलभः पार्थ नित्ययुक्तस्य योगिनः",
  "8.26": "शुक्ल कृष्ण गति हि एत जगतः शाश्वते मते।\n\nएकया याति अनावर्तिम अन्यया अवतारथे रे - ये दुनिया के सफेद और काले रास्ते हैं।\nविज्ञान का निष्कर्ष यह है कि अनुगला है। एक से वापस नहीं आना है. दूसरे से\nफिर से लौटता है.\n\nइस प्रकार एक प्रकाश का श्वेत मार्ग है जो मोक्ष की ओर जाता है और दूसरा संसार की ओर वापस जाता है\nअँधेरे का काला रास्ता. ये दोनों मार्ग अनंत और अनंत में सभी जीवनों के लिए समान हैं\nसिस्टम जैसा होना चाहिए. जो प्रकाश के मार्ग पर जाता है, वह लौटकर नहीं आता; जो अन्धकार के मार्ग पर जाता है, वह लौटकर नहीं आता\nवापस आऊंगा\n\nनैते सृति पार्थ जनन योगी मुह्यति कश्चन।\n\nतस्मात् सर्वेषु कालेषु योगयुक्तो भवार्जुन",
  "8.25": "धूमः रतिः तदा कृष्णः षट मसा दक्षिणायनम् |\n\nतत्र चंद्रमासम ज्योतिः योगी प्राप्य निवारते - धुएं की देवी, अंधेरे की देवी,\nकृष्णपक्ष के देवता, दक्षिणायन के छह महीनों के देवता, और दक्षिणायन के देवता - इस प्रकार\nजो साधक मर गया है वह चांदनी की दुनिया से जुड़ जाता है और वापस आ जाता है।\n\nमोक्ष के अयोग्य शरीर से बाहर आने पर जो देवता उसका स्वागत करते हैं, वे धूम्र और देवता हैं\nअँधेरे की देवी. उसके बाद कृष्णपक्ष के देवता; फिर दक्षिणायन और 'दक्षिणायन छह\nमहीनों के देवता सोमलोक में जीवन प्रदान करते हैं। जीव यहाँ अपना पुण्य खो देगा\nखुशी को तब तक महसूस करें, जब तक कि आप बादलों में वापस शामिल न हो जाएं, बारिश के माध्यम से धरती पर न पहुंच जाएं\nपुरुष के शरीर के माध्यम से स्त्री के गर्भ में प्रवेश करता है और पुनः पृथ्वी पर जन्म लेता है।",
  "8.27": "न एते सृति पार्थ जनन योगी मुह्यति कश्चन |\nतस्मात् सर्वेषु कालेषु योगयुक्तः भव अर्जुन-पार्थ, इन मार्गों का अनुष्ठान क्या है?\nयहां तक ​​कि पेशेवर भी भटकते नहीं हैं. इसलिए, हे अर्जुन, हर समय बुद्धिमानी से चलना।\n\nइन दोनों तरीकों की उचित समझ होने के बाद आपको किस रास्ते पर चलना चाहिए\nजानकर अपने-अपने प्रशंसक देवताओं के साथ आगे बढ़ना चाहिए। संबंधित प्रशंसक देवता\nवे अलग-अलग स्तर पर आते हैं और जीवन को आगे ले जाते हैं। इस वजह से ख़त्म\nसमय की स्मृति में पथ और प्रशंसक देवताओं का चिंतन आवश्यक है। यह जानकर\nयदि इसका पालन और कार्यान्वयन किया जाए तो किसी भी अभ्यासकर्ता के लिए कोई भ्रम नहीं रहेगा। तो कृष्ण\nवह अर्जुन से कहते हैं - 'हमेशा इस योजना का पालन करें।'\n\nवेदेषु यज्ञेषु तपस्सु चैव दानेषु यत् पुण्यफलं प्रदिष्टम् |\nअयेति तत् सर्वमिदं विदित्वयोगी परमं स्थानमुपैथि च$द्यम्",
  "7.30": "अधिभूत, अधिदैव, अधियज्ञ के साथ मुझे जो जानते हैं — युक्तचेतस् — वे प्रयाणकाल में भी मुझे जानते हैं।\n\nमृत्युकाल कठिन — मन विक्षिप्त होता है। किन्तु नित्याभ्यासी — युक्तचेतस् — तब भी स्थिर रहते हैं। इसीलिए जीवनभर नित्यभगवच्चिन्तन अभ्यासनीय है।",
  "8.24": "अग्निः ज्योतिः अहः शुक्लः षट् मसाः उत्तरा अयनम्,।\n\nतत्र प्रयतः गच्छन्ति ब्रह्म ब्रह्मविदः जनः -अग्नि और ज्वाला [म्बिब्बरु वाहनिया]\nबच्चे]. [दोपहर की देवी के साथ] दिन की देवी, [पूर्णिमा की देवी के साथ] शुक्लपक्ष की देवी,\nउत्तरायण के छह महीनों के देवता, [देव संक्रांति के साथ] उत्तरायण के देवता- ई\nजो लोग मार्ग पर चलते हैं, जो प्रभु को जानते हैं, वे प्रभु से जुड़ जाते हैं; वापस नहीं आएगा.\n\nवैश्वानर (प्रा.)\nअग्नि और ज्योति, अग्नि के पुत्र)। ये देवता जीवन का स्वागत करते हैं और उसे आगे भेजते हैं।\nआगे के जीवन का स्वागत प्रकाश और दोपहर की देवियों द्वारा किया जाता है। यह सच्चा प्रकाश है\nअनुभव के साथ जीव आगे बढ़ता है और शुक्लपक्ष तथा पूर्णिमा के देवता तक पहुँच जाता है। वह\nफिर संक्रांति के देवता, उत्तरायण के साथ-साथ उत्तरायण के छह महीने के देवता\nजीवन को ईश्वर के पास भेजता है। इस प्रकार जो कोई इस मार्ग पर चलेगा वह कभी नहीं चलेगा\nवापस नहीं आता - शाश्वत सत्य प्रभु से मिल जाता है।",
  "9.7": "सर्वभूतानि कौन्तेय प्रकृतिं यान्ति मामिकम्।\nकल्पक्षय रे तनि कल्प अदौ विसृजामि अहम् - सृष्टि के अंत में सभी चीजें मेरी अपनी मूल प्रकृति में विलीन हो जाती हैं। मैं उन्हें सृष्टि के आरंभ से ही निर्मित करता हूँ।\n\nसृष्टि के 31,104 अरब वर्षों के बाद, महाप्रलय। यह चतुर्मुख ब्रह्मा की शताब्दी है। इसे कल्पक्षय कहते हैं।",
  "8.17": "सहस्र युग पर्यन्तं अहः यत् ब्राह्मणः विदुः।\n\nरथं युग सहस्रांतं ते अहः रत्र विदः जनः - हजारों युगों तक।\nभगवान हजारों युगों से दिन और अंधकार के रूप में जाने जाते हैं, वह दिन हैं-\nअंधेरे लोग.\n\nयद्यपि भगवान कालातीत हैं, उनकी रचना का समय उनके दृष्टिकोण के लिए भगवान का है\nहगलेंदु और प्रलय काल को भगवान की रात के रूप में भी जाना जाता है। एक हजार\nयुगचक्र संस्करण के लिए एक ब्राह्मण दिवस... युगचक्र का अर्थ है चतुर्युग - कलियुग 4,32,000\nवर्ष; द्वापर युग 8,64,000 वर्ष का है; त्रेता युग 12,96,000 वर्ष का है; कृत युग\n17,28,000 वर्ष; एक युगचक्र मिलाकर 43,20,000 वर्ष का होता है। ऐसे एक हजार\nयुग चक्र ब्रह्म का एक दिन है। अर्थात 432 करोड़ वर्ष। तो ब्रह्मा का एक दिन अर्थात\n864 करोड़ वर्ष. चतुर्मुख ब्रह्मा या सत्यलोक की आयु 100 वर्ष है। वह है\n864 करोड़ 5 360 5 100531,104,000,0000000 (इकतीस हजार एक सौ चार हजार)\nकरोड़) प्रति वर्ष। यह ईश्वर का रचना काल (दिन) है। फिर महाप्रलय. इस भीषण बाढ़ के दौरान\n31,104 हजार करोड़ वर्ष (रात)। यह ईश्वर की सृष्टि और विनाश की गणना है।\n\nजल प्रलय तीन प्रकार की होती है. 1. मन्वंतर का जलप्रलय; 2. बाढ़ 3. महाप्रलय [ये तीन\nबाढ़ के अलावा कई छोटी बाढ़ें भी आती हैं। पृथ्वी का कुछ भाग उन बाढ़ों में से एक है\nभाग नष्ट हो सकता है]। मन्वन्तर की जलप्रलय में पृथ्वी पूर्णतया नष्ट नहीं होती--किन्तु\nसभ्यता नष्ट हो जायेगी. दीनप्रलय चतुर्मुखी ब्रह्मा की रात्रि है। यानि प्रत्येक को 432 करोड़\nसाल में एक बार जल प्रलय. इस जलप्रलय में पृथ्वी पूरी तरह नष्ट हो जायेगी। महाप्रलय के अनुसार\nसाल में एक बार 31,104 हजार करोड़ और इस बाढ़ में सत्य लोक से सब कुछ\nयहाँ तक कि संसार भी सूक्ष्म परमाणु रूप में भगवान में लीन हैं।\n\nअव्यक्तद् व्यक्तः सर्वः प्रभावन्त्यहारागमे।\n\nरात्रिगमे प्रलीयते तत्तैवव्यक्तसंज्ञके",
  "8.8": "योगाभ्यास युक्तेन चेतसा न अन्य गमिना |\n\nपरमं पुरुषं दिव्यं यति पार्थ अनुचिंतन -पार्थ, एक रचना जो लीला है-\nभगवान के परम व्यक्तित्व के अभ्यास से प्रलोभित होकर, किसी और चीज़ की आंतरिक इच्छा के साथ,\nजब वह भक्तिपूर्वक ध्यान करता है, तो वह उससे जुड़ जाता है।\n\nअपने मन को भगवान पर स्थिर रखने के लिए \"निरंतर मन\" हमारे लिए बहुत महत्वपूर्ण है\nमुख्य बात. आमतौर पर हमारा मन अवांछित चीजों की ओर बहता है। लेकिन हम ऐसा करते हैं\nकेवल ईश्वर के बारे में सोचने के लिए प्रशिक्षित हों। प्रभु को चित्त से अद्वितीय बनाओ\nचिन्तन की भाँति इसका निरन्तर अभ्यास करना चाहिए। हमारा मन, बुद्धि और आत्मा ही हम हैं\nवे अभ्यास के अनुसार कार्य करते हैं। उनके लिए हम ईश्वर के विचार का अभ्यास करते हैं\nअभ्यास ही एकमात्र साधन है जिसके द्वारा मन इच्छाशक्ति को वश में करता है। जब यह हो गया तो यह हो गया\nप्रभु में बने रहना. यदि मन भगवान में विश्राम करेगा तो अंत समय में भी वह भगवान में ही रहेगा\nऐसा प्रतीत होता है कि यह केवल विचार नहीं है, यह अविचारणीय है—अर्थात् ईश्वर की वास्तविकता है\n(निरंतर) सोच। भगवान का चिंतन उसी प्रकार करना चाहिए, जैसा श्रुति में कहा गया है।\nअसत्य विचार करके कोई भगवान से नहीं जुड़ सकता।\n\nएकाग्र मन से भगवान हृतकमाला मध्यवासी का चिंतन।\nकृष्ण कहते हैं कि यह किया जाना चाहिए। महान प्रभु आपके हृदय में अतुलनीय हैं\nयहां कृष्ण का संदेश यह है कि ध्यान में जो है उसे पहचानो। प्रभु सर्वव्यापी है, सर्वशक्तिमान है,\nसर्वव्यापी, शाश्वत. ऐसे भगवान हमारे हृदय में निवास करते हैं और\nवह दिव्य है.\n\nयहां प्रयुक्त दिव्य शब्द के कई अर्थ हैं। मूल रूप से दिव्या या 'भगवान' ये शब्द 'दिवु' हैं।\nयह नामक तत्व से आता है। प्राचीन धातु पाठों में इस तत्व के सात अर्थ हैं\nदेख सकते हैं; वे हैं: 1) ध्युति 2) विजिगीषा 3) कांति 4) स्तुति 5) व्यापार 6) खेल 7)\n\nगतिशु ने हाल ही में मोदा, मद और स्वप्न के तीन और अर्थ जोड़े हैं। लेकिन ये\nप्राचीन धातुपाठ में नहीं. आइए अब उपरोक्त सात अर्थों पर संक्षेप में नजर डालते हैं।\n\n1) ध्युति: ध्युति का अर्थ है प्रकाश का रूप। सूर्य, जो प्रकाश का स्रोत है, चंद्रमा के लिए प्रकाश है\nप्रभु हमें ज्ञान के प्रकाश से भर देते हैं।\n\n2) विजिगीषा: भगवान सर्वोच्च और विजय स्वरूप हैं।\n\n3) कांति: जो केवल इच्छा से सृजन कर सकता है। जिसने हमें इच्छा दी है और यह उसका है\nयोग्यता के अनुसार पूर्ति.\n\n4) स्तुति: जिसकी सभी प्रशंसा करते हैं; जिसकी हर कोई तारीफ करता है, वही बुलंद आवाज बन जाता है\nप्रभु.\n\n5) व्यवसाय: वह जो संसार के समस्त व्यवसाय का संचालन करता है।\n\n6) खेल: सृजन-स्थिति-संहार यह भगवान के लिए एक खेल है। जन्म और मृत्यु, सभी मामले\nउसके लिए एक खेल.\n\n7) गतिषु: गति और ज्ञान देने वाले भगवान। जो हर जगह रहा है; सब कुछ जानता है;\nसबके भीतर बिम्बा के रूप में वास करने वाला परमात्मा या 'ईश्वर' है।\n\nइस प्रकार 'दिव्य' शब्द के अनेक अर्थ मिलते हैं। ऊपर \"हे भगवान\"।\nएक बार अर्थ याद आ जाए तो उसका आनंद असीमित होता है। भगवान के नाम पर बहुत कुछ\nबल है. यद्यपि हम ईश्वर के साथ हैं, फिर भी हम मानसिक रूप से उससे दूर हैं। प्रभु का\nनिरंतर चिंतन से हम उसे महसूस कर सकते हैं।\n\nइस अध्याय के अगले भाग में भगवान श्रीकृष्ण के चिन्तन का क्या अर्थ है?\nवह बताते हैं कि एक ध्यानी को भगवान का ध्यान कैसे करना चाहिए\nइसका एक उदाहरण निम्नलिखित श्लोकों में देखा जा सकता है।",
  "9.2": "राजविद्या राजगुह्यं पवित्रं इदं उत्तमम् |\n\nप्रत्यक्ष अवगमं धर्मं सु सुखं कर्तुम् अव्यम् - यह अनुभूति का राजा है। रहस्यों का\nएक रहस्य बाकी सब असली है. आँख में आँख डालकर देखने का तरीका. धारक के बारे में सब कुछ. जश्न मनाने के लिए\nआराम न बुझने वाला.\n\nकृष्ण, उस आध्यात्मिक विज्ञान के बारे में बात करते हुए जिसका उन्हें आगे प्रचार करना था, कहते हैं: “यह\nसभी विषयों में प्रमुख शिक्षा; सबसे गुप्त और सबसे पवित्र विज्ञान के रूप में\"। 'जीवित'\nशब्दवाच्य (इंद्रियों का नियंत्रक) भगवान को प्रकट करता है; दुनिया के\nयह एक विज्ञान है जो सीधे भगवान, धारण करने वाली शक्ति से संबंधित है, और साक्षात भगवद का विषय है। यह\nविद्या को जानकर भगवान को प्रसन्न करना बहुत आसान है। क्योंकि प्रभु सबसे बड़ा है\nज्ञान प्रिय है. ईश्वर के ज्ञान के मार्ग के समान कोई मार्ग आसान नहीं है। \"यह\nकृष्ण कहते हैं कि मार्ग कभी व्यर्थ नहीं जाता, इसलिए ज्ञान का मार्ग कभी व्यर्थ नहीं जाता।",
  "9.4": "मया ततम् इदं सर्वं जगत् अव्यक्त मूर्तिना |\nमत स्थानि सर्वभूतानि न च अहं तेषु अवस्थितः - यह सारा संसार मुझ मैदोरा से है।\nपूर्ण है यहां जो कुछ भी है वह सब मुझमें निवास करता है। मैं उनके पक्ष में नहीं हूं.\n\nकृष्ण कहते हैं: \"मैं वह अन्तर्यामी व्यक्ति हूँ जो पूरे विश्व में व्याप्त है।\" यहाँ प्रयोग किया जाता है\nअव्यक्तमूर्ति शब्द में अव्यक्त और मूर्ति विपरीत शब्द हैं। अव्यक्त\nइसका मतलब है कि जो दिखता है और जिसका कोई रूप नहीं है। मूर्ति का अर्थ है आकार और स्वरूप। भगवान आकाश की भाँति सर्वत्र विद्यमान हैं\nव्यापक, अव्यक्त, लेकिन वह सर्वव्यापी मूर्ति है। एक के बाद एक\nवह अनंत रूपों वाला भगवान जो एक रूप और दूसरे पदार्थ से परिपूर्ण है। कृष्ण कहते हैं:\n\"मैं हर चीज़ का आधार हूं, यह पूरी दुनिया मुझ पर निर्भर है। लेकिन मैं हूं।\"\nस्वतंत्र होकर मैं सर्वत्र परिपूर्ण हूँ।” वह है।\n\nनाच मत स्थानि भूतानि पश्य मेय योगमैश्वरम् |\nभूतभृन्न च भूतस्थो ममा$तमा भूतभावनः",
  "8.21": "अव्यक्तः अक्षरः इति उक्तः तम अहुः परमं गतिम् |\n\nयं प्राप्य न निवर्तन्ते तत् धाम परमं मम - यह अव्यक्त तत्त्व ही 'अक्षर' है।\nभगवान कहते हैं. उसे अंतिम कहा जाता है। जो लोग उसे प्राप्त करते हैं वे कभी वापस नहीं लौटेंगे।\nवह मेरा सबसे पुराना रूप है.\n\nयह अव्यक्त दर्शन ही वह सर्वोच्च स्थान है जहाँ सभी को जाकर सम्मिलित होना चाहिए। वह 'अक्षर' शब्द का मुख्य अर्थ है।\nसर्वव्यापी, सर्वव्यापी, जो चाहे दे,\nसर्वशक्तिमान, इंद्रियों का अनुभवकर्ता, सर्वशक्तिमान-भगवान. फिर से उससे जुड़ें\nपरिवार में दोबारा जन्म लेने की जरूरत नहीं है. कृष्ण कहते हैं, ''वह मेरा पुराना रूप है.''\n\nपुरुषः सः पार्थ भक्त्या अग्यस्त्रानया |\nयस्यान्थास्थानि भूतानि येन सर्वमिदं ततम् ॥202॥\n\nपुरुषः सा; परः पार्थ भक्त्या அக்க்குது तु अनन्या य |\n\nयस्य अंतस्थानि भूतानि येन सर्वं इदं ततम् - पार्थ, वह परम व्यक्तित्व।\nकेवल समर्पित भक्ति के लिए पर्याप्त है. उसके अंदर बिजली की दुनिया है. वह यह सब स्वीकार करता है\nखड़ा है\n\nभगवान सर्व शब्दवाच्य जो इस ब्रह्मांड में और पिंडदान नामक पुरा में सब कुछ नियंत्रित करते हैं।\nऐसे भगवान को लुभाने का एकमात्र तरीका भक्ति है। भक्ति के बिना क्या है?\n\nउसे कर्म से भी नहीं जोड़ा जा सकता। केवल ईश्वर प्राप्ति और मोक्ष के लिए\nसाधना अद्वितीय एकपत्नीत्व है। बाढ़ के समय, सृष्टि के समय उसके शरीर की सभी चीज़ों की रक्षा करें\nजो कार्य करना है उसे दिन के अनंत समय में अन्तर्यामी होकर करो\nउस प्रभु से सदैव प्रेम करो जो भरता है और रक्षा करता है।\n\nअत: अंत में शरीर त्याग करते समय भगवान का ध्यान कैसे करें\nकृष्ण, जिन्होंने छवि हमारे सामने रखी है, शरीर छोड़ने के बाद भगवान की ओर यात्रा करते हैं\nइस अध्याय के अगले भाग में मार्ग बताया जायेगा।",
  "8.6": "यम यम वा अपि स्मरणं भावं त्यजति अन्ते कालेबरम |\n\nतम तम एव ऐति कौन्तेय सदा तत् भाव भवितः -- कौन्तेय, अंत में क्या\nवह पदार्थ को सोखकर और उसमें निहित संस्कारों को लेकर शरीर को छोड़ देता है\nवह इसे प्राप्त करता है.\n\nकृष्ण क्यों कहते हैं कि जो जीवन यात्रा के अंतिम क्षण में भगवान को याद करते हैं वे 'मुझ' में शामिल हो जाते हैं?\nइस श्लोक में जो कहा गया है उसका उत्तर है। यहां है कृष्ण की मृत्यु के समय का चमत्कार\nवह मनोविज्ञान को हमारे सामने उजागर करता है। मृत्यु के क्षण में भगवान का ध्यान करना चाहिए\nकृष्ण कहते हैं, एक प्रयोजन है। अगला वह है जो हमें तब याद आता है जब हम शरीर का त्याग करते हैं\nवह हमें जन्म के समय ही मिल जाता है। तो यदि आप उस समय भगवान को याद करते हैं, तो भगवान\nहम शामिल होंगे. मृत्यु के अंतिम क्षण में जो विचार आता है वही अगले जीवन में निर्णायक होता है। इसलिए\nउसे याद रहता है कि अगले जन्म में वह क्या बनेगा! प्रभु से जुड़ने के लिए योग\nजो भगवान को याद नहीं करते! विज्ञान में इसके कई उदाहरण हैं। इस देश को\nवृषभदेव के पुत्र भरत की कहानी, जिन्होंने 'भरत' नाम को जन्म दिया, इस बात को स्पष्ट रूप से दर्शाती है\nबताने के लिए एक कहानी. (यह भरत दुःशांत का पुत्र भरत नहीं है, दुःशांत का पुत्र भरत ही 'भरतवंश' का मूल है\nपुरुष). धर्मात्मा भरत ने अपने पुत्र प्रया को ज्ञान प्राप्त होने पर अपनी सारी शक्ति दे दी\nउसके प्रति समर्पण करो, वानप्रस्थाश्रम स्वीकार करो और जंगल में खासियों के साथ भगवद के प्रति वफादार रहो।\nएक दिन उसे जंगल में एक हिरण का बच्चा मिला जिसकी माँ मर गयी थी। भरत वह चूजा है\nवह लाने और पालने लगा। इस कारण वह उस हिरण का सदैव पालन-पोषण करता है\nअपना समय बिताने लगे. इससे उनकी उपलब्धि रुक ​​गयी. वह हिरण का बच्चा\nएक ऐसी घटना घटी जब उन्होंने बड़े होने से पहले ही अपने प्राण त्याग दिये। उस समय भरत के लिए\nभगवान के बारे में सोचने के बजाय, उसे उस हिरण के बच्चे की चिंता हो रही थी! ताकि वह अगले जन्म में ऐसा कर सके\nहिरण के रूप में जन्मे. अत: कोई भी अप्रत्यक्ष ज्ञान पीछे नहीं छूट सकता\nयह एक उत्कृष्ट उदाहरण है. यह कहानी इस बात का ज्वलंत उदाहरण है कि कृष्ण यहां क्या कह रहे हैं।\n\nभले ही हमने जीवन भर कुछ हासिल किया है, मृत्यु के क्षण में हम भगवान को याद नहीं करते हैं\nजा सकते हैं इसके लिए जीवन भर या कई जन्मों की उपलब्धि आवश्यक है। कृष्ण कहते हैं\nयथा ''सदा तद् भाव्भाविताः''। यहां भाव का अर्थ है व्यक्तित्व। सदैव प्रभु में\nमनुष्य को एक मन से निरंतर भगवान का चिंतन करना चाहिए। अंत समय में प्रभु का\nयदि स्मृति लानी है तो मन को स्थिर प्रभु में स्थित करने का संस्कार आवश्यक है। ये छोड़ो\nयदि मृत्यु के समय भगवान को याद करते हुए जीवन व्यर्थ व्यतीत हो जाता है\nप्रभु का स्मरण नहीं आता!\n\nभीष्मचार्य ने अपने अंतिम दिनों में भगवान के बारे में कितना भी सोचा, उन्होंने केवल स्वयं को देखा\nकृष्ण जो एक बाण से घायल हैं और अपनी खोपड़ी उतार रहे हैं! आनंदस्वरूप ही भगवान का सच्चा दर्शन है\nवे नहीं कर सके. यहां वह बात है जिसे हमें महसूस करने की आवश्यकता है - चाहे हम कुछ भी करें\nइसे बहुत गंभीरता से न लें. यदि लागू किया जाए तो अंत में यह वैसा ही दिखेगा! पूरे जीवन में\nहमें कभी भी बुरी बातें नहीं सोचनी चाहिए। किसी से भी बुरा मानकर नफरत नहीं करनी चाहिए. एक\n\nनफरत करना बहुत बुरी बात है. यह हमारा पूरा जीवन बर्बाद कर देता है. बुराई से दूर रहें\nलेकिन नफरत मत करो. गहरे स्नेह के कारण किसी से घृणा करना, किसी का अपमान करना\nउनमें कुछ भी ग़लत नहीं है. लेकिन हम अपना जीवन खराब कर लेते हैं। हमें नफरत है\nसामग्री हमारे दिमाग में गहराई तक बस जाती है और हमें नीचे ले जाती है। बस इतना ही\nमृत्यु के समय अंत में, मस्तक खिलेगा! तो हम इस मुद्दे पर हैं\nसतर्क रहें. हमें किसी की आलोचना करने का अधिकार नहीं है. क्योंकि हम आंतरिक हैं\nकोई दृष्टि नहीं. हम तो बाहर से ही बात कर रहे हैं. अंदर देखें 'कौन क्या है'\nहमारे पास ताकत नहीं है. इसलिए कृष्ण कहते हैं, दूसरों का विचार छोड़ो और सदैव ईश्वर का चिंतन करो।\nएकमात्र चीज़ जिसके बारे में हमें चिंता करने की ज़रूरत है वह प्रभु हैं।",
  "8.3": "भगवान उवाच - भगवान ने कहा:\n\nअक्षरं ब्रह्म परमं स्ववहे अध्यात्मं उच्यते।\n\nभूत भव उद्भव करः विसर्गः कर्म संज्ञतः -- परमाक्षर नामक परमतत्त्व \"ब्रह्म\" है।\nजीवस्वरूप और जीव-संबंधी समष्टि पिंडदान [भगवान की मुद्रा]।\n\n``अध्यात्म'' भगवान की विभिन्न रचनात्मक गतिविधियों को संदर्भित करता है जो जीवन-निर्जीव वस्तुओं की अभिव्यक्ति की ओर ले जाती हैं।\nनाम है 'कर्म'.\n\nकृष्ण कहते हैं 'ब्रह्म' का अर्थ है 'परम ब्रह्म - परम अक्षर'। भगवान सब से ऊपर है\nहिरिडदा परमं ब्रह्म - वह सर्वोच्च है। ऐसे भगवान के बारे में जानना जरूरी है\n\"ब्रह्म\" शब्द के पीछे का अर्थ. विष्णु ने सहस्रनाम में भगवान का वर्णन इस प्रकार किया है:\n\nपरमाण यो महतेजः परमाण यो महत्तपः |\n\nपरमान्यो महद्भा ह्मा परमाण यः परायणम् ॥\nप्रभु की ज्योतियों को प्रकाश देने का स्वरूप; हर किसी की सोच का अंतिम लक्ष्य; यही समस्त ज्ञान का लक्ष्य है\nप्रभु. यहां भगवान को 'परम महा ब्रह्मा' कहा जाता है। ब्रह्म का अर्थ है जीवित प्राणी; पारब्रह्म\nअर्थात् मुक्त प्राणी; परमब्रह्म का अर्थ है श्रीतत्त्व, - शाश्वत रूप से खुली श्रीलक्ष्मी। परम मह\nब्रह्मा का अर्थ है नारायण। जो लोग भागते हैं उनके लिए भी भगवान सर्वोच्च हैं। यहां परायण का अर्थ है हम\nभक्तिमय देवता जो सहारा हैं। भगवान सभी देवताओं के स्वामी हैं। ये हम हैं\nजानने योग्य छह बातों में से एक है 'ब्रह्म' शब्द का अर्थ।\nकृष्ण आगे कहते हैं: \"स्वभावः अध्यात्मम उच्यते\"। यहां प्रकृति से तात्पर्य है\nअस्तित्व की प्रकृति और जीवन की प्रकृति। इससे पहले कि हम ईश्वर को जानें, हम हैं\nजीवन का स्वरूप जानना चाहिए। मेरा क्या मतलब है? द बेस्ट इन मी (0165 00170)\nकौन सा (117ता5 ॥011) निरंतर हमें स्वयं को जानने दो\n[लेकिन] हम अपना अधिकांश समय दूसरों को आंकने में बिताते हैं\nहम खर्च करते हैं!॥] . हमारे इस शरीर में केवल आंखें, हाथ, पैर और अन्य अंग हैं\n'मैं' के अस्तित्व का ज्ञान ही नहीं है.\nउपस्थिति जानने की जरूरत है. तो फिर उसका स्वरूप क्या है यह जानना चाहिए। [सामान्य तौर पर\nहम नहीं जानते कि हमारा जीवन स्वभाव क्या है। हम प्रभाव में रहते हैं।]\nजीवन एक अत्यंत सूक्ष्म पदार्थ है। वह हृतकमाला (!1/7105) के केंद्र में अनाहत चक्र है\n91876) शक्ति केंद्र में स्थित है। यह जीवन कमरे में जलते हुए एक छोटे से दीपक के समान है। दीपक साबुत है\nएक कमरे को रोशन करने की तरह, जीवन सूक्ष्म होते हुए भी उसकी रोशनी पूरे शरीर को रोशन करती है\nऐसा जीवन और जीवंत स्वभाव \"आध्यात्मिक\" है।\nकृष्ण आगे कहते हैं: “यह संसार भूत और भाव है - अर्थात् जीव और\n\"अक्रिय रचना\"। हम इस दुनिया में हैं. ऐसी दुनिया कैसे बनी? कब\nबनाया गया? इसके पीछे का सार क्या है? उसके कारण और कारण\nकौन शरीर से जीवन का जन्म क्यों होता है? वह महान शक्ति जो सब कुछ व्यवस्थित रखती है\n\nजब हम ऐसा सोचते हैं तो हमें एक बात का एहसास होता है - वह है कर्म का सिद्धांत। यह\nवह प्रभु ही वह मूल शक्ति है जो जीवन और जड़ जगत् की रचना करती है। उसकी कार्रवाई\nवास्तविक कार्रवाई. वास्तविक कर्म इस संसार की विविध रचना के स्रोत को जानना है\nपता चल जाएगा कि हम सभी भगवान द्वारा बनाई गई गुड़िया हैं - वह सूत्रधार हैं। हमारा कर्म वही है\nसूत्रधार के नियम का पालन। सम्पूर्ण ब्रह्माण्ड ईश्वर के अधीन घूम रहा है। भगवान की कार्रवाई\nमहाक्रिया हमारा कार्य चरखे पर चलती हुई चींटी के समान है। चींटी क्या है?\nअगर वह एक दिशा में चलता भी है, तो वह उस तरह चलता है जैसे पहिया घूमता है, न कि उस तरह जैसे चींटी चलती है। पहिया\nघूमता नहीं. इसी प्रकार संसार की गति हमारे कर्मों पर निर्णय नहीं है। यह उसका है\nलगातार टेम्पो के अनुसार चल रहा है. तो \"मैंने किया\" जैसा कि \"मैंने किया\"।\nअहंकारी होने का कोई मतलब नहीं है. इस प्रकार जड़ जगत की रचना का कारण जीवन है\nसृजन का अद्वितीय कार्य ही वास्तविक 'कर्म' है।\n\nजब इस श्लोक को दूसरे आयाम से देखा जाता है तो यह एक नये रूप में सामने आता है। यहाँ\nकोई जीवन नहीं है. ये तीनों चीज़ें ईश्वर को संदर्भित करती हैं। ब्रह्मा का अर्थ है 'भगवान';\nप्रकृति का अर्थ है ईश्वर का स्वतंत्र स्वभाव। अतः भगवान के चरित्र और धर्म का चिन्तन करना ही अध्यात्म है।\nहममें से कुछ लोग पूछते हैं. \"ईश्वर का ऐसा स्वभाव क्यों है? एक सुखी, दूसरा दुःखी,\nएक को दरिद्रता, एक को दरिद्रता, एक को नर्क, एक को स्वर्ग, यह भेदभाव क्यों।\nये बचकाना सवाल है. ऐसे तर्क से ही हमारे अंदर नास्तिकता उत्पन्न हुई है। जीवन शाश्वत है,\nभगवान ने इसे बनाया. हर जीवित प्राणी का गुण नहीं होता\nउन्हें प्रकृति के अनुसार, योग्यता के अनुसार बनाना ईश्वर का स्वभाव है।\nइसलिए यहां भेदभाव का कोई सवाल ही नहीं है. अपनी रचना के पीछे ईश्वर की स्वतंत्रता;\nनिष्पक्षता; टस से मस न होना; त्रिगुणातीतत्व- ये ईश्वर का सार हैं\nप्रकृति इसे जानना ``अध्यात्म'' है। जब आप भगवान के गुणों को जानते हैं, तो उनकी रचना क्या है\nवही कर्म समझेगा. ईश्वर की क्रिया में ज्ञान-इच्छा-क्रिया नामक तीन चरण नहीं हैं। वह है\nइच्छा क्रिया है. इसे जानना \"कर्म\" को जानना है, इस प्रकार प्रकृति, भगवान की प्रकृति\nऔर कर्म के प्रति जागरूकता - ब्रह्म, आध्यात्मिकता और कर्म।",
  "9.6": "यथा आकाशस्थितः नित्यं वायुः सर्वत्र गह महान्।\nतथा सर्वाणि भूतानि मत स्थानि इति उपाधारय - नित्य विद्यमान वायु\nसंसार के सभी अस्तित्व अगासा की तरह मुझमें हैं। कल्पना कीजिए.\n\nहवा हर जगह है. यह अंदर और बाहर दोनों है. हम हवा को नहीं देख सकते. हवा इस आकाश में है\nपूर्ण है इस प्रकार भगवान हमारे अंदर और बाहर पूर्ण रूप से विद्यमान हैं। लेकिन कुछ नहीं\nउसके पास यह नहीं है. इस संसार का सारा अस्तित्व प्रभु में है।\n\nसर्वभूतानि कौन्तेय प्रकृतं यान्ति मामिकम् |\nकल्पक्षये पुनस्तानि कल्पादौ विसृजाम्यहम् 17\n\nसर्वभूतानि कौन्तेय प्रकृतं यान्ति मामिकम् |\nकल्पक्षये रे तनि कल्प अदौ विसृजामि अहम् - सृष्टि के अंत में सभी चीजें मेरी हैं।\nयह मूल प्रकृति का है. मैं उन्हें सृष्टि के आरंभ से ही निर्मित करता हूँ।\n\nसृष्टि के 31,104 अरब वर्षों के बाद, महाप्रलय। यह चतुर्विध ब्राह्मणों में से एक सौ है\nवर्ष इसे कल्पक्षय कहा जाता है। इस महाप्रलय में सत्यलोक से सब कुछ अपना है\nवे स्थूल रूप को खो देते हैं और सूक्ष्म रूप में भगवान की अधीन प्रकृति में शामिल हो जाते हैं।\nसभी जीव भी अपना स्थूल रूप खोकर भगवान के गर्भ में प्रविष्ट हो गये\nपुनः जुड़ जाता है. 31,104 हजार करोड़. वर्ष प्रलयकाल है। फिर वापस इस रचना पर\nबनाया जाएगा. अर्थात यह सूक्ष्म रूप से स्थूल रूप में लौट आता है।",
  "9.8": "प्रकतुरं स्वं अवस्ताभ्य विसृजामि अवरापुणः।\nभूत ग्रामं इमाम कृत्स्नं अवशं प्रकृतिः वषत् - प्रकृति द्वारा निर्धारित।\nपरतंत्र [मेरे मन में] इस भंवर ब्रह्मांड में मैं अपनी प्रकृति का बार-बार उपयोग कर रहा हूं\nमैं निर्माण करूंगा\n\nप्रलय के समय में, निर्जीव और जीव सूक्ष्म जगत में भगवान के होते हैं\nवह वशीभूत प्रकृति का उपयोग करके पुनः सृजन करता है। सृष्टि और विनाश का यह चक्र ईश्वर का है\nनिरंतर. ऐसे अनन्त ब्रह्माण्ड अतीत में बनाये गये थे और अब भी अनन्त हैं\n\nयह समय के साथ चलता रहता है. इस कारण से, भगवान अनंत ब्रह्मांड के स्वामी हैं\n(इसकी चर्चा हमने सातवें अध्याय में विस्तार से की है)।\n\nक्या कर्म उस ईश्वर से जुड़ा नहीं है जो निरंतर निर्माण और विनाश कर रहा है? निम्नलिखित श्लोक में\nआइए देखें:\n\nनाच मम तनि कर्माणि निबद्ददन्ति धनंजय |\n\nउदासिनवादसीनमासक्तं तेसु कर्मसु",
  "9.10": "मया प्रध्यवनेन प्रकृतिः सुयते स चर आचारम्।\n\nहेतुना अनेना कौन्तेय जगत विपरिवर्तथे-मेरे द्वारा जो सजीव-निर्जीव वस्तुओं का साक्षी बनकर खड़ा था।\nविलीन प्रकृति उड़ती है। कौन्तेय, इसीलिए तो दुनिया बदलती रहती है.\n\nसंसार को बनाने और उसे आकार देने के लिए आवश्यक कच्चा माल प्रकृति है\nप्रकृति लक्ष्मी प्रकृति की सर्वोच्च आत्मा है। संपूर्ण सृष्टि का स्वामी प्रभु,\nक्रिया के पीछे की शक्ति के रूप में, वह जड़ और चेतन प्रकृति के माध्यम से इस सृष्टि का निर्माण करता है।\nसंसार की प्रत्येक वस्तु ईश्वर की एक अनोखी ऊर्जा से ओत-प्रोत है।",
  "9.9": "न च मम तनि कर्माणि निबद्धदन्ति धनंजय।\n\nउदासीनवत् असीनं असक्तं तेषु। कर्मसु - धनंजय, मैं करता हूं\nमैं वैसा ही रहूँगा जो ऐसा नहीं करता। मैं उन कर्मों से बंधा नहीं हूं. तो वे कर्म मुझे बांधते हैं\nनहीं डाल सकते\n\nभगवान निर्लिप्त हैं, वे कर्म अपने लिए नहीं करते। कदापि नहीं प्रभु जो स्वतंत्र है\nकिसी भी कर्म को बांधा नहीं जा सकता\nक्या आपको नहीं लगता? \"मैं अपने लिए कुछ नहीं करता और कर्म मुझसे जुड़ा नहीं है।\"\nकृष्ण स्पष्ट कहते हैं.\n\nइस श्लोक में धनंजय विशेषण का प्रयोग हुआ है। अगर आप इस नाम को व्यावसायिक तौर पर देखें\n'उन शत्रु राजाओं को परास्त करो जो प्रजा का धन, संपत्ति लूटते हैं\nधनंजय जो इस पर काबू पाते हैं और लोगों के लिए इसका अच्छा उपयोग करते हैं।' [अपने लिए दूसरे का\nछापा मारकर पैसा कमाने वाला व्यक्ति \"डाकू\" तो माना जाता है, लेकिन धनंजय नहीं।\nमहाभारत में एकलव्य इसी दूसरे समूह से थे। तो उसकी उंगली\nकाट दिया गया और कृष्ण ने स्वयं उसे मार डाला।] आध्यात्मिक का अर्थ है वास्तविक धन\nभगवान। धनंजय को ऐसे भगवान का ज्ञान प्राप्त है। हम सभी अर्जुन की तरह भगवान के हैं\nमोक्ष तभी प्राप्त हो सकता है जब व्यक्ति ज्ञान से समृद्ध हो जाए।",
  "9.3": "अश्रद्धानः पुरुषः धर्मस्य अस्य परन्तपः।\nअप्राप्य मम निवर्तन्ते मृत्यु संसार वार्मानि -- परंतप, जो इस कदम में विश्वास नहीं करते थे।\nबहुत से लोग मुझ तक पहुंचे बिना मौत के भंवर में फिसल जाएंगे।\n\nकृष्ण, जिन्होंने पहले ईर्ष्या के बारे में बात की थी, यहाँ एक और बहुत महत्वपूर्ण गुण के बारे में बात करते हैं - वही\n'परिश्रम'. जो मेहनती नहीं, उनसे कुछ भी कहना व्यर्थ है। हमारे लिए किस पर\nयदि भक्ति नहीं है तो हमारा मन उसे स्वीकार नहीं करेगा। एक बात हम समझते हैं\nयदि हम यह करना चाहते हैं तो हमें इसके प्रति प्रयत्नशील रहना होगा। \"ऐसी कुछ बातें हो सकती हैं जो मैं नहीं जानता,\nक्योंकि ऐसी बहुत सी चीज़ें हैं जो मैं नहीं जानता\" - जानना ईमानदारी की पहली बात है\nसीढ़ी (! 1105! 0 121 | 60 1701 ॥100)। हमें अपनी अज्ञानता के प्रति सचेत रहना चाहिए। तब मुझे पता नहीं था\nजानने का परिश्रम आता है। पहले हमें अज्ञात के बारे में जानना चाहिए; उसके बाद\nहमें इस संभावना के बारे में जागरूकता की आवश्यकता है कि जो कुछ हम नहीं जानते वह सत्य हो सकता है;\nइसे जानने के लिए परिश्रम की आवश्यकता होती है। इसे जानने से यह तथ्य ज्ञात हो जाता है कि कोई अज्ञात वस्तु है।\n\nज्ञान के पथ पर चलने वाले साधक को बुनियादी आस्था की आवश्यकता होती है। अविश्वासी के सामने क्या है?\nयह कहने से कोई फायदा नहीं है. कृष्ण यहाँ यही कहते हैं: “उन लोगों के लिए जिनके पास कोई भक्ति नहीं है\nकोई सच्चाई नहीं है. जो लोग संसार के पालनकर्ता, भगवान में विश्वास नहीं करते हैं, वे वे हैं जो भगवान में विश्वास नहीं करते हैं\nनहीं है. “वे आत्मा को नष्ट करने वाली तमसा या संसार के भंवर में शामिल हो जाते हैं\nकृष्ण कहते हैं.\n\nइस श्लोक में परंतप विशेषण का प्रयोग किया गया है। इसका सतही अर्थ शत्रु है\nएक ज्वलंत बहादुर बनने के लिए. हमारे जीवन के युद्ध में हमारे शत्रु हैं अज्ञान, जुनून,\nकाम, क्रोध आदि ऐसे शत्रुओं के प्रति प्रत्येक साधक समर्पित रहता है\nवह धधकती हुई आग बन जानी चाहिए, वह जलती हुई आग बन जानी चाहिए।",
  "9.14": "सततं कीर्तयन्तः मम यतन्तः च थं प्रातःः।\n\nनमस्यान्तः च मम भक्त्या नित्य युक्तः उपासते - मुझे हर दिन अपने अंदर ले चलो।\nनिरंतर मेरी प्रशंसा करते रहो और मेरे लिए संघर्ष करते रहो\nझुकना.\n\nकृष्ण कहते हैं, \"जो लोग स्वभाव से दिव्य हैं वे निरंतर मेरा जप करते हैं।\" उनमें से प्रत्येक\nक्रियाशीलता में भी भगवद् चेतना गहरी है। दूसरे अर्थ में, एक यंत्र धारण करना,\nहमेशा तार बजाना और भगवान की स्तुति करना (महर्षि नारद की तरह)।\nजो लोग खुश हैं वे स्वभाव से दिव्य हैं। वे अपने लक्ष्यों को प्राप्त करने के लिए दृढ़ निश्चयी हैं\nवह दीक्षा से, अनूठे प्रेम से पूजा करता है। दूसरे प्रकार के भक्त हैं कृष्ण\nवह अगले श्लोक में बताते हैं.",
  "9.5": "न च मत स्थानि भूतानि पश्य मेय योगं ईश्वरम् |\n\nभूतभृत न च भूतस्थः मम आत्मा भूतभावनः - मेरे पास सब कुछ है; मेरे पास कोई नहीं है\nगोंद मेरी शेष महिमा को देखो। मेरे रूप ने इन्हें आकार दिया है. समय की सलाह दी जाती है.\nहालाँकि इनमें नहीं.\n\nहमें इस बात पर ध्यान देना होगा कि कृष्ण पिछले श्लोक में और इस श्लोक में क्या कह रहे हैं। जाहिरा तौर पर\nये विरोधाभासी बयान लगते हैं. ऐसा कृष्ण कहते हैं\n\"मेरी शक्ति को जानो, मैं सभी चीजों में हूं - लेकिन कुछ भी नहीं। सभी चीजें मुझमें हैं\nलेकिन मेरे पास कोई नहीं है. यह ईश्वर की अकल्पनीय शक्ति के प्रति एक दृष्टिकोण है। भागवत में\nजैसा कि कहा जाता है “जगत में जिसे हम विपरीत कहते हैं (00888616101/) वह शुभ है।\nयदि यह धर्म है तो यह ईश्वर में लागू होता है'। यहाँ यह विपरीत धर्म कहकर\nभगवान जो बता रहे हैं.. उसका मतलब है. * मेरे पास सबकुछ है। लेकिन। जो\nमामाकारवु (180017900 मेरे पास नहीं है)। इसका मतलब यह है कि यह भगवान की अनासक्ति को दर्शाता है। वह\nकुछ भी नहीं चिपकता. वह किसी चीज़ का सहारा नहीं लेता और किसी चीज़ पर दोषारोपण नहीं करता\nउसके पास यह नहीं है. कृष्ण कहते हैं: \"यह मेरी दिव्य शक्ति है\"। यह ईश्वर की सर्वशक्तिमत्ता है।\n\nकृष्ण एक बार फिर इस बात को संक्षेप में समझाते हैं (0गा60) \"भूतभृत नच भूतस्थः\"।\nयहां 'नाचा' शब्द का प्रयोग दो शब्दों के बीच में दहलीज पर रखे दीपक की तरह किया गया है। इसका मतलब है\nइस प्रकार: “मैं सभी जीवित प्राणियों से भूतभृत-आवेशित हूं और नचभूतभृत-शून्य से आवृत हूं;\nमैं भूतस्थ हूं-सभी जीव मुझमें हैं और मैं नचभूतस्थ हूं-मैं किसी भी चीज में नहीं हूं।”\n\nकृष्ण कहते हैं: \"मम आत्म भूतभावनः\"। अर्थात् इस संसार की उत्पत्ति-स्थिति-विनाश।\nनियम-ज्ञान-अज्ञान-बंध-मोक्ष सभी भगवान से हैं। वह ज्ञानानन्द स्वरूप हैं। प्रभु\nउसका शरीर अलग नहीं है; उनके गुण भी अलग नहीं हैं. वे सभी बरकरार हैं.  यह\nपंचभौतिक और त्रिगुण्य के दायरे में हम कल्पना नहीं कर सकते।\n\nकृष्ण एक दृष्टांत के माध्यम से आगे बताते हैं कि भगवान कैसे सर्वव्यापी हैं\nवह श्लोक में बताते हैं.",
  "9.23": "ये अपि अन्य देवता भक्तः यजन्ते श्रद्धया अन्विताः।\nते अपि माम् एव कौन्तेय यजन्ति अविधि पूर्वकं - कौन्तेय, जो अन्य देवताओं का है।\nयहां तक ​​कि जो भक्त के रूप में सच्चे दिल से उसकी पूजा करते हैं, वे भी मेरे द्वारा धोखा खा जाते हैं\n\nपूजा",
  "9.12": "मोघ असः मोघकर्मणः मोघज्ञानः विचेतसः।\n\nरक्षासेम् आसुरीं च एव प्रकृतिम् मोहिनीम् श्रीतः - उनकी इच्छा पूरी नहीं होती। कर्म\nनतीजा रोशनी फीकी पड़ जाती है. वे भिन्न हैं; धोखेबाज, राक्षस-असुर\nजो तमस प्रकृति के अधीन हैं।\n\nकृष्ण यहां सोच रहे हैं कि \"भगवान ज्ञानानंद स्वरूप हैं, उनके पास पांच भौतिक शरीर नहीं हैं\"।\nवह जोर देकर कहता है. “यह सोचना पाप है कि भगवान के पास हमारे जैसे पाँच भौतिक शरीर हैं\nरास्ता\" कृष्ण कहते हैं. क्योंकि जो लोग ऐसा सोचते हैं वे सात्विक नहीं हैं। वे कभी नहीं हैं\nभगवद्भक्त नहीं है। ऐसा सोचने वालों की आध्यात्मिक प्राप्ति की सारी इच्छाएँ समाप्त हो जाती हैं\nदेवता उन लोगों से कभी प्रेम नहीं करते जो कहते हैं कि ईश्वर नश्वर है। वे हैं\nबलिदान व्यर्थ हैं. सामान्य तौर पर, आध्यात्मिक उपलब्धि में एक बाहरी व्यक्ति के रूप में उनकी स्थिति क्या है?\nइच्छा पूरी नहीं होती.\n\nजो लोग सात्विक विचार नहीं रखते या तमस से प्रभावित होते हैं वे भगवान से इसी प्रकार की भूल करते हैं\nसोचने से काम चलेगा उनके पास सोचने की शक्ति नहीं है। चाहे उसने कोई भी विज्ञान पढ़ा हो\nकोई फायदा नहीं. उनका मन आध्यात्मिकता को नहीं समझता। “ये राक्षस हैं या\nकृष्ण कहते हैं, ''असुर हैं। राक्षस स्वभाव से तामसिक होते हैं; असुर होते हैं\nराजस - जो कामुक भोग में मर्दाना दिखते हैं। उसके प्रभाव से\nजो लोग अपनी विचारशीलता खो चुके हैं वे भी ऐसा ही सोचते हैं। यह उनके लिए हमेशा स्वाभाविक है\nविचार नहीं आता. उसे हमेशा हत्या की चिंता सताती रहती है.\n\nमहात्मनास्तु माम् पार्थ दैवेम् प्रकृतिमाश्रितः |\nभजन्त्यन्यामनसो ज्ञात्वा भूतदिमाव्यम्",
  "9.15": "ज्ञानयज्ञेन च अपि अन्ये यजन्तः मम उपासते |\n\nएकत्वेन पृथक त्वेन बहुधा विश्वतः मुखम्- जागरूकता के मनसा यज्ञ द्वारा सर्वत्र कुछ।\nवे मुझ परिपूर्ण भगवान की पूजा करते हैं और उसका उपभोग करते हैं - भगवान जो हर जगह मौजूद है\nजैसा कि [एकीकृत], जैसा कि सभी से अलग [चतुर्भुज], जैसा कि विभिन्न रंगों का\n[कई मायनों में];, इस प्रकार कई मायनों में।\n\nअन्य लोग प्रभु चेतना की दुनिया में डूबे हुए हैं। उनके बाहर ध्यान में\nसंसार का कोई भान नहीं रहता। ध्यान में वे ईश्वर को कई आयामों में देखते हैं\nपूजा उनकी पूजा ध्यान से पहले एक यज्ञ है। बाह्य रूप से उन्हें महात्मा कहा जाता था\nइसे पहचानना बहुत मुश्किल है. कृष्ण कहते हैं: “ये मुझे एक बनाते हैं, अलग करते हैं, अनेक बनाते हैं\nवे देखेंगे. यहां एकत्वेण का अर्थ है इस बात की पूजा करना कि भगवान एक है।\nप्रत्येक देश, प्रत्येक जाति, प्रत्येक वोट के लिए एक भगवान नहीं। भगवान सबके लिए\nएक के रूप में पूजा करना एकत्ववेण है। पृथक्तवेण का अर्थ है सबसे विचित्र\nईश्वर को अनेक प्रकार से देखना। वह अनेक रंगों से भगवान का ध्यान करता है\nइस प्रकार देखा जाता है कि विश्वतोमुख भगवान एक हैं, चतुर्मूर्ति हैं, अनेक हैं\nमूर्तियों की तरह अनेक रंगों से पूजी जाती हैं।\n\nभगवान के पास कैसे जाएं और कैसे न जाएं, इसका ज्ञान कृष्ण ने दिया।\nइसके बाद भगवान की विभूति को अलग करें। अन्य प्रतीकों तक कैसे पहुंचें\nवह बताते हैं कि संपूर्ण ब्रह्मांड भगवान और परमाणु कणों की उपस्थिति से भरा हुआ है\nइसकी अनोखी पूजा का विवरण कृष्ण ने इस अध्याय के अगले भाग में बताया है। चलो\nआइए प्रभु से अद्वितीय ज्ञान सुनकर कृतज्ञ हों।",
  "9.11": "अवजानन्ति मम मुदः मानुषिम तनुम अश्रितम् |\n\nपरमं भवम् अजन्न्तः मम भूतमहेश्वरम् - मनुष्य के रूप में प्रकट हुए और युद्ध किया।\nवे मेरे साथ एक इंसान की तरह व्यवहार करते हैं और मेरी उपेक्षा करते हैं - उन सभी में से सबसे महान जो कभी भी और हर जगह मौजूद हैं\nमेरे अज्ञानी मूर्ख.\n\nइस श्लोक में भगवान अपने स्वभाव के बारे में कुछ ऐसा बताते हैं जो कोई नहीं बता सकता।\nभगवान के पास पंचभौतिक शरीर नहीं है. भगवान अवतार रूप में हमारे ही समान शरीरधारी हैं\nवह बस ऐसा दिखता है जैसे उसके पास यह है। वहां दिखाई देने वाले शरीर को देखना: भगवान का शरीर हमारे जैसा ही है\nजो लोग इसे अनित्य, एक दिन गिरने वाले शरीर के रूप में जानते हैं - वे स्वभाव से तमस हैं\nकृष्ण कहते हैं कि जो लोग तमस के प्रभाव में आ गए हैं वे बच्चे हैं जिन्हें भगवान की महानता का एहसास नहीं है।\n\nयहां भूतमहेश्वर विशेषण का प्रयोग किया गया है। भगवान की महिमा बताना विशेष है\nशब्द शब्द को सामूहिक रूप से देखें: भूत का अर्थ है सभी जीवित प्राणी। उन्हें शुभकामनाएँ\nब्रह्मा देवता (भूतेश)। इन देवताओं में सबसे महान श्रीलक्ष्मीभूतमहेश हैं)। जैसे कि\nजो भगवान लक्ष्मी के वर हैं, वे \"भूत महेश्वर\" हैं। . वही शब्द बनाएं. यदि आप देखें\nभूत महान* ईश्वर: ब्रह्मा सभी राक्षसों पर महान हैं और उन सभी को नियंत्रित करते हैं।\n, सर्वोच्च-सर्वशक्तिमान भगवान। दूसरा मार्ग है भूत-महत*ईश्वर। यहाँ एक भूत है\nअर्थ: जन्म या मृत्यु के बिना अनंत काल, उत्कर्ष के कगार पर। महत् का अर्थ है: समय में,\nएक ऐसा सिद्धांत जो स्वभाव और गुणवत्ता से उत्तम है। ईश्वर का अर्थ है: सर्वशक्तिमान भगवान। इस प्रकार यह\nयह विशेषण भगवान के गुणों को अनेक रूपों में व्यक्त करता है।\n\nमोघशा मोघकर्मणो मोघज्ञानं विचेतसः |\nरक्षासीमासूरिं चैव प्रकृतिं मोहिनीम सृतः।",
  "9.21": "ते तम भुक्त्वा स्वर्ग लोकं विशालं क्षीणे पुण्ये मर्त्य लोकं विशन्ति।\nएवं तीन धर्मं अनुप्रपन्नः गता अगतम् काम कामः लभन्ते - वह व्यापक है\n\nसग्गीगारा की भूमि खोजने के बाद, पुण्य समाप्त होने पर वे पृथ्वी पर लौट आते हैं। इस प्रकार वैदिक कर्मों की दुहाई\nहोक्कू इच्छाओं की पीठ पर इधर-उधर भटकता रहता है।\n\nस्वर्ग की इच्छा से पवित्र कर्म करने वाले त्रैविडियन स्वर्ग में शामिल होते हैं और वहां सभी प्रकार के सुखों का आनंद लेते हैं\nजैसे ही वे अपने अच्छे कर्मों का फल भोगते हैं, वे फिर से पृथ्वी पर जन्म लेते हैं। इस वजह से\nवह सबसे बड़ी मुक्ति और प्रभु की ओर से है। वंचित रह जायेंगे. वह हमेशा\nवे इच्छाओं के चक्र में फंस जाते हैं। उनसे एक बहुत ही अलग कदम है प्रतिभागियों का:\n\nअनन्यश्चिन्तयन्तो माम् ये जनः पर्युपासते |\nतेषाम् नित्यभियुक्तानां योगक्षेमन् वहाम्यहम्",
  "9.19": "तपामि अहं अहं वर्षम् निगृह्णामि उत्सृजामि च।\n\nअमृतं च एव मृत्युः च सत् असत् च अहम् अर्जुन - मैं जलता हूं। मैं वर्षा हूं\nमैं इसे आने से रोकता हूँ; मैं बारिश कराऊंगा. मैं मृत्यु को रोकूंगा; मैं मर जाऊंगा. हे अर्जुन,\nदृश्य कार्य, अदृश्य कारण सब मुझसे ही हैं। मेरे जैसा\nमैं 'असत्' हूं क्योंकि दूसरा भी है।''\n\nभगवान सूर्य में मौजूद हैं, जीवनदाता हैं, जो सौर ऊर्जा को पृथ्वी तक पहुंचाते हैं। समय-समय पर\nवही है जो वर्षा कराता है; वह असमय वर्षा को रोकने वाले भी हैं। बारिश\n\nयह प्रभु की ओर से है कि जब वर्षा होनी चाहिए तब नहीं होती, वर्षा जब नहीं होनी चाहिए तब होती है। देख रहे हैं\nईश्वर क्रिया के पीछे की कारण शक्ति है।\n\nईश्वर वह अमृत है जो हमारे जीवन में जीवन फूंकता है। जब जीवन समाप्त हो जाए तो सांस लेना बंद कर दें\nवह फोन करने वाला भी है. संक्षेप में कृष्ण कहते हैं, “देखा (सत्) और अदृश्य (असत्)।\n\"मैं वह शक्ति हूं जो पूरे विश्व पर शासन करती है।\" यह सूक्ष्म रूप से भगवान कृष्ण हैं\nएक विस्तृत चित्र परिशिष्ट में दिया गया है। यहां पूरी तरह से प्रभु के पास जाने के लिए\nसारी बात छुपी हुई है.\n\nआगे, कृष्ण दो मुख्य प्रकार के भक्तों (अपने भक्तों में, संतों) का वर्णन करते हैं।\nवे त्रैविद्या और भागवत हैं।\n\nत्रि\n\nते पुण्यमासद्य सुरेंद्र लोकमश्ना ते दिव्यं दिवि देवभोगं",
  "9.20": "विद्या माम् सोमपः पूतपापः यज्ञैरिष्ट्वा स्वर्गतिं प्रत्यन्तमे।\n\nत्रि\n\nते पुण्यं आशिता सुरा इंद्र लोकं आशा ती दिव्यं दिवि देवा भोगन - त्रिविद्या\nतीन वेदों को मोरेहोका हम्बलिगा कहा जाता है। अपने नारदी को अपमानित करना, सोमरस के नशे में धुत्त होना पाप है\nइससे छुटकारा पाओ और आसान रास्ता पूछो. उस गाथा में उन्होंने पुण्य के फलस्वरूप देवेन्द्र की भूमि में प्रवेश किया\n\nशाकाहारियों की भक्तिपूर्वक बलि खाई जाती है।\n\nविद्याः माम् सोमपः पूत पापाः यज्ञेयः इष्ट्वा स्वः गतिम् प्रत्यन्ते |\n\nत्रिविद्या अर्थात त्रिपथगामी! उन्होंने प्रभु के साथ कई बातें साझा कीं। वह है\nवे स्वर्ग की इच्छा और सांसारिक इच्छा को सामने रखकर स्वयं को भगवान के प्रति समर्पित कर देते हैं। वेदों में इनके लिए\nकहा गया कर्मखंड ही मायने रखता है। ज्योतिष्टोमय याग जैसा याग केवल स्वर्गीय है\nइसे इच्छा से करो, ईश्वर की इच्छा से नहीं बल्कि स्वर्ग की इच्छा से। इस प्रकार भक्ति करो\n\nपरिणामस्वरूप वे इंद्र की भूमि के स्वर्ग में शामिल हो जाते हैं और वहां आनंद का अनुभव करते हैं।",
  "9.13": "महा आत्मनः तु मम पार्थ दैवीम प्रकटुरं अश्रितः |\n\nभजन्ति अनन्य मनसः ज्ञात्वा भूत आदिम अव्यम् - हे पार्थ, सात्विक स्वभाव के अग्रज\nमनुष्य यह जानकर कि मैं समस्त नाशवान ब्रह्माण्डों का अविनाशी कारण हूँ, उसी प्रकार मैं ही हूँ\nपूजा करता है\n\nपिछले श्लोक में आसुरी और आसुरी प्रकृति का वर्णन करने वाले कृष्ण यहाँ दिव्य हैं\nचरित्र का वर्णन करता है. दैवीय प्रकृति वाले सदैव ज्ञान, प्रकाश और सत्य के मार्ग पर चलते हैं\nजो लोग यात्रा करते हैं वे भगवान को जानने के लिए भाग्यशाली हैं। भगवान ने उन्हें \"महात्मा\" कहा।\nवह कहता है। भगवान को उससे बड़ा प्रेम है. कृष्ण कहते हैं, “उन्होंने मुझे अद्वितीय बनाया\nवह मन से जप करता है।” हम भगवान से प्यार करते हैं और भगवान हमसे प्यार करते हैं\nप्रेम करना ही सच्चा भजन है। जो लोग स्वभाव से दिव्य हैं वे भगवान को छोड़कर नाशवान हैं।\nवे इस सत्य को जानते हैं कि एकमात्र ईश्वर ही शाश्वत सत्य है। भगवान और दुनिया में उनका\nकेवल ज्ञान ही अपरिहार्य है। बाकी सब कुछ (पैसा, संपत्ति, सोना, शक्ति, आदि) बेकार है। नाशवान\nधन भगवान और उनका ज्ञान है. महात्मा वे हैं जो ईश्वर के बारे में इस प्रकार सोचते हैं।\n\nइस श्लोक में विशेषण 'पार्थ' है। कृष्ण ने अर्जुन से कहा, \"प्रथिया के पुत्र\"।\nसम्बोधन का अर्थ सतही होता है। शास्त्रीय दृष्टि से व्युत्पत्ति (₹॥/1301001081//)\nइस विशेषण के पीछे एक अलग आध्यात्मिक अर्थ है। “प्रथा-विस्तारे' धातु.कौन सा\nजो व्याप्त है, जो हर जगह व्याप्त है वह \"प्रथा\" है। यह भगवान की सर्वव्यापकता है\nयह उन लोगों को इंगित करता है जो इस सत्य को समझते हैं कि ईश्वर सर्वव्यापी है और उन्हें हर जगह देखते हैं\n'पार्थस'. दूसरे अर्थ में वेदार्थभूत भगवान अपने गुणों का सदैव पान करते हैं\nऐसा करने वाले 'पार्थ' हैं. हम सबको वेदार्थ पीकर पार्थ बनना चाहिए। हर जगह\nइस संबोधन के पीछे भाव यह है कि हम अपने भीतर सर्वव्यापी शक्ति को देखें\nसंदेश\n\nदैवी प्रकृति वाले किस प्रकार भगवान की पूजा करते हैं?\nकृष्ण अगले श्लोक में बताते हैं.\n\nसताकं किर्तयन्तो माम् यतन्तशश्च थमवृतः |\nनमस्कान्तश्च माम् भक्त्या नित्ययुक्त उपासते",
  "9.29": "समः अहं सर्वभूतेषु नाम वथ्यः अस्ति नाप्रियः।\n\nये भजन्ति तू मम भक्त माई ते तेषु च अपि अहम् - सभी प्राणी मेरे साथ एक हैं। मेरे लिए\nन कोई शत्रु, न कोई मित्र. परन्तु जो भक्ति से मुझे प्रसन्न करता है, वही मेरा अधिकार है;\nमैं उनका हूं.\n\nभगवान की न तो किसी से दुश्मनी है और न ही किसी से दोस्ती। वह प्यार करता है\nव्यक्ति नहीं बल्कि व्यक्ति में ज्ञान और भक्ति है। जो इसके योग्य है वही प्रभु है\nवे भक्ति भाव से पूजा करते हैं. भगवान सच्चे भक्तों के प्रति समर्पण कर देते हैं।\n\nअपि चेत सुदुराचारो भजते मामनन्यभाक् |\n\nसाधुरेव स मन्तव्यः सम्यग् व्यवहारितो हिसः",
  "9.26": "पात्रं पुष्पं फलं तोयं यः में भक्क्य प्रयच्छति।\n\nतत् अहम् भक्ति उपहृतं अश्नामि प्रयता आत्मानः - जो एक पत्ता है, एक फूल है,\nवह भक्ति से मुझे पानी देता है, मैं उसकी भक्ति का उपहार हूं\nनाल्मे से खरीदूंगा.\n\nसर्वोच्च भगवान की पूजा के लिए जो कुछ भी आवश्यक है वह निरपेक्ष है\nसंलग्न (17100/671670), और \"मन से पूजा करना\"।\nयदि आप तुलसी का पूरा पत्ता या फूल अर्पित करेंगे तो भगवान प्रेमपूर्वक इसे स्वीकार करेंगे।\nयहां कुछ भी नहीं है, न सोने का आसन, न चांदी का कड़ाही, न पंचपात्र। घर पर,\nबगीचे में जो कुछ है उसे अर्पित करो। यदि घर में दूध न हो तो श्रद्धापूर्वक एक गिलास पानी पी लें\nसमर्पित करें लेकिन जब तक इसके पीछे पवित्रता है, कृष्ण कहते हैं \"यो मेई भक्त्या प्रयच्छति\"।\nवह है। ईश्वर जो चाहता है वह है हमारा अंतरतम प्रेम और ईमानदारी\nबाहरी महिमा नहीं. \"तदहं भक्कुपहृतमश्नामि प्रयतात्मनः\" - \"आपने मन को मुझमें डाल दिया।\"\nबस जाओ, श्रद्धापूर्वक जो कुछ दिया जायेगा, मैं स्वीकार कर लूँगा।” कृष्ण.\nरामायण में शबरी की कहानी भगवान के इसी वचन का उदाहरण है।\n\nयत् करोशि यदाश्नासि यझुनोशि ददासि यत् |\nयत्तपस्यासि कौन्तेय तत् कुरुष्ठ मदारपनम्",
  "8.28": "वेदेषु यज्ञेषु तपसु च एव दनेषु यत् पुण्यफलं प्रदिष्टम्।\n\nअयेति तत् सर्वं इदं विदित्वा योगी परम स्थान उपैति च आद्यम्-वेद\nयदि तुम पढ़ते हो, यज्ञ करते हो, तप करते हो, दान देते हो, तो क्या पुण्य है?\nएक अभ्यासी जो इसे जानता है वह कही गई सभी बातों से परे है; सबसे पहले वरिष्ठ साइट\n\nकार्यभार संभाला\n\nअंत में, कृष्ण कहते हैं - सबसे बड़ा ज्ञान यह समय का अंत है\nवह जागरूकता. सभी शास्त्रों में यज्ञ-दान-तप के माध्यम से पुण्य ने जो कहा है, उसका यही अंत है\nसमय की मृत्यु के रहस्य की जागरूकता इन सभी पुण्य फलों से परे है। तो सबसे बड़ा\nउपलब्धि एक अंतिम समय का विचार है। इसी कारण मृत्यु के लिए जीवन से अधिक विचार की आवश्यकता होती है।\n\nमृत्यु शुभ नहीं है. यह हमारा भ्रम है कि मृत्यु एक दुखद अनुभव है। शरीर के अंदर होते हुए भी शारीरिक\nशरीर के सारे कष्ट जीवन से जुड़े हुए हैं। मृत्यु का अर्थ है इस स्थूल शरीर से मुक्ति।\nतो सूक्ष्म शरीर में जीवन पिंजरे से बाहर आता है और आकाश में स्वतंत्र रूप से उड़ता है\n\nपक्षी की तरह इसी कारण से मृत्यु का भय पीछे छूट जाता है और अंतिम समय में शुभता का उदय होता है\nदेवता अनुसन्धान हमारे जीवन में निरंतर बना रहना चाहिए।\n\nइति अष्ट मोध्याय\nआठवां अध्याय समाप्त हो गया\n\nक्या यह सच है?\n\nअध्याय नौ\n\nज्ञान का अर्थ है ईश्वर के प्रति जागरूकता (5011108! 5156009)। हमारा मन ईश्वर की ओर जाता है जो सब कुछ जानता है\nज्ञान प्रवाहित होता है. ईश्वर को सर्वोच्च, सर्वज्ञ, सर्वज्ञ आदि जानना ही ज्ञान है। वह\nफिर उसके विवरण के प्रति जागरूकता ही विज्ञान (विशिष्ट ज्ञान) है। ज्ञान ईश्वर का गुण है.\nभगवान ज्ञानी, आनंदमय, सुंदर, दयालु आदि हैं\nसंपूर्णता को विस्तार से समझना एक विज्ञान है (6\"01651/4560071 0 006)। हम हैं\nईश्वर को पूर्णतः नहीं जाना जा सकता। लेकिन प्रत्येक जीवन अद्वितीय है\nजागरूकता का एक स्तर है. हर किसी को एक जैसी बात नहीं पता चलती. उनके स्तर के अनुसार\nईश्वर को जानना विज्ञान है (1761/16टी81 6101टी51/ए 5150013 0 06 )। इस प्रकार प्रभु\nयदि ज्ञान से परम को जानना है तो वह परम तत्त्व ही उसका विस्तार है\nउनकी योग्यता के अनुसार उन्हें विभिन्न कोणों से देखना ही विज्ञान है। इस प्रकार\nइस तथ्य के करीब पहुंचकर कि ईश्वर अस्तित्वहीन होने के बजाय अजीब है\nसाकार हो जायेगा.\n\nसातवें अध्याय में कृष्ण ने अर्जुन से कहा- ''मेरी महानता का जाना जाना उसका बीज नहीं है।\nमैं तुम्हें पूरी बात बताऊंगा. ये जानना इस मामले में फिर अलग है\nकुछ भी जानना बाकी नहीं है” (ए-7, श्लो-2)। इस अध्याय में फिर से यहाँ\nज्ञान विज्ञान के बारे में बताते हैं! . ऐसा क्यों कृष्ण भूल गए कि उन्होंने पहले क्या कहा था?\nसमझा रहे हैं?! नहीं, उसके कुछ कारण हैं। वह एक बार कही गई बात को क्यों दोहरा रहे हैं?\n\"एक अलग आयाम में बोलना\"। तो यहाँ जो कहा गया है वह पहले कही गई बात की व्याख्या है\nऔर रचनात्मकता. वहां संक्षेप में बताया गया है, यहां दूसरे तरीके से कुछ नए अर्थ दिए गए हैं\nकृष्ण बताते हैं. यदि हम ईश्वर का मूल चिंतन एक बार अपने मन में कर लें\nनहीं जा रहा! अगर आप इसके बारे में सोचते रहेंगे तो यह कहीं न कहीं चला जाएगा! जब पूछा गया,\nजब आप इसे पढ़ते हैं तो आपको लगता है कि आप सब कुछ जानते हैं। लेकिन कुछ देर बाद आपको याद भी नहीं रहता!\nइसके लिए आपको संस्करण बनाते समय एक अलग आयाम में सोचना होगा। इस अध्याय में कृष्ण\nपहले बताए गए ज्ञान को समझने का हमारा तरीका अलग-अलग पहलुओं से अलग-अलग है\nआयाम में समझाता है.\n\nयुद्ध के मैदान में एक सैनिक के रूप में खड़े व्यक्ति की मानसिक स्थिति आध्यात्मिक चिंतन के लिए बहुत अनुकूल होती है\nकरीब होगा. इस वजह से, कृष्ण ने युद्ध के मैदान में आध्यात्मिकता को उजागर किया। अर्जुन बहुत है\nएक महान ऋषि. सदैव भगवद चिंतन करना ही देवता है। उसके अलावा\nयुद्ध के मैदान में रुकना, मानसिक रूप से उसे जन्म और मृत्यु की इस लीला से परे ले जाना,\n\nमानसिक रूप से तैयार हो जाओ - कृष्ण वेदांत कहते हैं। ऐसे क्षण में भगवान के पास\nअगर बता दिया जाए तो जल्द ही दिल भर जाएगा. यहां तक कि हम अपने दैनिक जीवन में भी वही हैं-\nग़लत, धर्मों का टकराव जारी रहेगा. ऐसे युद्ध की स्थिति में हमारे लिए\nअध्यात्म को समझना.\nभगवान का वचन\nइदं तु ते गुह्यतमन् प",
  "9.1": "भगवान उवाच- भगवान ने कहा:\n\nइदं तु ते गुह्यतमं प्रवक्ष्यामि अनुसूयवे€।\n\nज्ञानं विज्ञान सहितं यत् ज्ञात्वा मोक्षसे अशुभत् - यह भी बहुत है\nछुपाने के लिए कुछ. बिना चिल्लाए कह रहा है कि वह सराहना कर रहा है: जानें और जानें। यह\nजानकर मैं जाल से छूट जाऊँगा।\n\nकृष्ण कहते हैं: “मैं तुम्हें भगवद के सिद्धांत के बारे में फिर से बताऊंगा; सबसे गुप्त पूजा\nमैं आपके सामने तथ्य उजागर कर रहा हूं.' यह हर किसी के लिए खुला नहीं है.\nजो लोग भगवान की पूजा करने की अनोखी इच्छा रखते हैं, उनके लिए मेरे पास भगवान के अलावा कुछ भी नहीं है।\nयह उन लोगों के सामने कहा जाना चाहिए जिनका मन ना कहने का है और जो भगवान के लिए तरसते हैं\nवाणी सबसे गुप्त रहस्य करने वाली बात। \"मैं तुम्हें यह बता रहा हूँ\"\nकृष्ण कहते हैं. इधर अर्जुन इस विषय को जानने के लिए जिज्ञासु एवं योग्य हैं, अतः कृष्ण\nवह उसे यह महत्वपूर्ण बात बताता है। केवल वे ही जिनके पास योग्यता है और सुनने की इच्छा है\nयही शिक्षा दी जानी चाहिए. यह हर किसी को नहीं दिया जाता.\n\nयहाँ कृष्ण ने \"अनसूयावे\" शब्द का प्रयोग किया है। एक आदमी जो वेदांत पढ़ता है और\nजो गुण वेदांत का अध्ययन करने के बाद भी मौजूद रहने चाहिए (ए63) - \"अहंकार\" (69019557959)।\nवेदांत का अध्ययन करने से कोई लाभ नहीं है। वेदांत का अध्ययन करने से पहले अहंकार नहीं करना चाहिए।\nयदि आप जानते हैं कि \"मैं भगवान के सामने कुछ भी नहीं हूं\", तो कोई घमंड नहीं होगा। वेदांत पढ़ें “मैं हूं\nयदि 'महान ज्ञान' का अहंकार आ जाए तो यह ईश्वर को पढ़ने और खो देने जैसा है। लेकिन आज हम हैं\nहम किसी न किसी अहंकार के अधीन हैं। ज्ञान का अभिमान, शक्ति का अभिमान, धन का अभिमान\nअहंकार, सुंदरता का अहंकार, यौवन का अहंकार, ऐसी बहुत सी चीजें हैं हम\nभूतिया. हम वेदांत को जानने के योग्य तभी हैं जब हम इससे छुटकारा पा लेंगे\n\nप्राप्त किया जायेगा. जब तक हम अहंकार से भरे हैं, वेदांत हमारे लिए है\nउपयोगी नहीं.\n\nज्ञान का अभिमान सभी अभिमानों में सबसे खतरनाक है। हालाँकि, अन्य अहंकारों का अंत होता है\nज्ञान के अहंकार का कोई अंत नहीं है. ''यदि 'मैं विद्वान हूं' का अभिमान मन में आ जाए तो वह महान है\nमनहूस! \"ईर्ष्या\" अहंकार की संतान है। यह ईर्ष्या वह आग है जो हमें जला देती है। उसके लिए\nकन्नड़ में इसे 'हॉट्टेकिचू' कहा जाता है। यह हमारे व्यक्तित्व को नष्ट कर देता है। उन लोगों के लिए\nवेदांत बेकार है. “तुम्हें ईर्ष्या नहीं है, इसीलिए तुम्हारे पास यह रहस्य है\nकृष्ण कहते हैं.\n\nयुद्ध के मैदान में खड़े व्यक्ति के लिए ईर्ष्या रहित होना बहुत बड़ी बात है। नफरत-ईर्ष्या\nयुद्ध के मैदान में अहंकार हमेशा प्रचुर मात्रा में होता है। जो इस पर विजय प्राप्त कर लेता है वह सबसे महान है।\nयहाँ कृष्ण कहते हैं: “यह जानकर, आपका मन भगवान के प्रति शुद्ध है\nआप जो चाहते हैं वह संभव है।” जब ज्ञान आता है तो हमारे अंदर का मैल धुल जाता है और मन दूर हो जाता है\nशुद्ध हो जाता है. हमारा सबसे बड़ा धन आनंदमय स्वच्छ मन है। ऐसे मन में\nभगवान प्रकट होते हैं. अहंकार-ईर्ष्या से रहित मन \"वासुदेव\" इत्यादि है\nमन द्वारा देखे गए भगवान \"वासुदेव हैं। शुद्ध मन से ज्ञान, ज्ञान से आनंद।\"\nआनंद की इस अवस्था से, पंचभौतिक शरीर और संसार से मुक्ति और\nमोक्ष\n\nहमारे पास तीन वर्ण हैं जो पंचभूति हैं। इन तीन बाड़ों के भीतर आत्मज्ञान\nवहाँ स्वयं है. लिंगशरीर, सूक्ष्म शरीर और स्थूल शरीर आत्मा को ढके हुए हैं\nबाड़े. हम इन तीनों ने अपनी कमीजें उतार दीं और अशुभ से मुक्त हो गए,\nयहां कृष्ण 'मोक्ष्यसे$शुभत्' भगवान के समक्ष रूपात्मक वास्तविक अवस्था में खड़े हैं।\n[हम मंदिर में भगवान के सामने अपनी शर्ट उतारते हैं- \"भगवान्।\"\nसामने रखे सभी बाड़ों को भगवान के सामने हटाकर सुखाया जाएगा\nका मुख्य अर्थ है. हमने भगवान के सामने जो भी मुखौटे लगाए हैं वे सभी उनके हैं\nऔर खुलना चाहिए. तब वह अपने आप को हमारे सामने खोल देता है।] इस प्रकार पंचभौतिका\nभगवान ने अर्जुन को शरीर से मुक्ति और मोक्ष का ज्ञान दिया\nआइए देखें कि निम्नलिखित श्लोक में क्या कहा गया है।",
  "9.18": "गतिः भर्ता प्रभुः साक्षी निवासः शरणं सुह्रुत।\n\nप्रभावः प्रलयः स्थानम् धनं बीजम् अव्यम् - जो मुक्ति के लिए जाना जाए। सब\nवह जो उत्तरदायित्व वहन करता हो। हर चीज़ का स्वामी. जो सब कुछ प्रत्यक्ष देख सके। सबका घर. निःशुल्क भी समर्थन.\nअनिमित्ता एक रिश्तेदार है. सृष्टि-राज्य-प्रलय का कारण। वह जो दुनिया को बाढ़ में ले जाता है। फिर से दुनिया का\nवह जो अभिव्यक्ति का कारण बनता हो। अमर।\n\nरिश्तों के बारे में पहले बात करने के बाद, कृष्ण यहां विभिन्न प्रकार के लगावों का उल्लेख करते हैं। अलग\nइस प्रकार समाज में एक दूसरे से सहायता मिलती है। संकट के समय राजा की ओर से सुरक्षा\nआश्रय, दुखियों को सांत्वना देना, मित्रता आदि आसक्ति ये सब भगवान के हैं\nधर्म को कृष्ण कहा जाता है।\nजब किसी के पास घर नहीं होता, रहने का कोई मौका नहीं होता, \"मैं हूं\" ही सुरक्षा है\nऐसा करने वालों को 'गति' कहा जाता है। वास्तव में गति का अर्थ अंतिम गति है। सिर्फ परिवार में ही नहीं\nभगवान गतिः, जो मोक्ष में भी आश्रय हैं, वे अच्छे हैं, और जब हम गलत करते हैं, तो वे बुरे होते हैं\nभी। सारी जिम्मेदारी उठाना, दुनिया में हर कोई जो करता है, उसमें उसकी भलाई है\nप्रभु ही वह है जो बुराई को देख सकता है। वह हमारे सभी अंतरतम रहस्यों को जानता है।\nवह सर्वव्यापक तथा सर्वद्रष्टा सच्चा साक्षी है।\nकृष्ण कहते हैं \"अहम् निवासः\"। जैसा कि ईशावास्योपनिषद कहता है:\nईशावास्यं इदं सर्वं यत् किंच जगत्यं जगत् |\nतेन त्यक्षेण भुंजीतः मा गृधः कस्य स्विद् धनम्]\n\nहम प्रभु के घर में रहते हैं। इसमें एक घर बनाओ जिसे ये दुनिया कहते हैं\nईश्वर वह परमधाम है जिसने हमें आश्रय दिया है और हमारे रहने की व्यवस्था की है। वह सबके लिए है\nसहारा ऐसा भगवान एक प्रिय मित्र (सुहृत) है जो संकट के समय में हमें सुरक्षा (शरण) देता है।\nदोस्त दो तरह के होते हैं. सखा और सुह्रुत. 'सखा' का अर्थ है साथी। सदैव आपके साथ हैं।\nसुह्रुत का अर्थ है वह जो हमारे हृदय की बात सुनता है और हमारा हितैषी है चाहे वह दूर हो या निकट।\nप्रभु वह हैं जो हमारे हृदय में निवास करते हैं और सदैव हमारे हृदय के द्वार पर रहते हैं\nउत्तरदायी दयालुता.\n\nपरिशिष्ट में कहने के बाद, कृष्ण मानव शक्ति को पीछे छोड़ते हुए, देवताओं की शक्ति की व्याख्या करते हैं।\nवह कहते हैं \"प्रभावः प्रलयः स्थानं धनं बीजमव्यम्\"। हममें से बहुत कम लोग जानते हैं\nसृष्टिकर्ता-ब्रह्मा, राज्य-विष्णु और संहारक-शिव के रूप में। यहाँ कृष्ण स्पष्ट रूप से कहते हैं: “मैं हूँ\nप्रभावः-प्रलयःस्थानम्\"। संसार की रचना का मूल कारण भगवान हैं। सृष्टि के अंत में यह\nसंसार के नष्ट होने और सृष्टि से लेकर विनाश तक ब्रह्माण्ड की स्थिति के लिए, यह मूल रूप से ईश्वर था\nकारण\n\nवह भगवान ही हैं जो प्रलय के समय सभी प्राणियों को नाजुक स्थिति में अपने पेट में धारण करते हैं।\nवह सूक्ष्म चीज़ जो फिर से अंकुरित और खिलती है और ऐसे बीज बोती है जो कभी नष्ट नहीं होते\nअव्यय-भगवान्।\n\nइस प्रकार संसार की सारी क्रियाएँ, लौकिक, लौकिक, अलौकिक, रिश्ते-नाते, लगाव।\nसब कुछ समझाने के बाद कृष्ण समय-समय पर ऐसी बातें और भी समझाते हैं।",
  "9.30": "अपि चेत सु दुराचारः भजते माम् अनन्य भाक |\n\nसाधु एव सः मन्तव्यः सम्यक व्यवसितः हि सः - जो अन्यत्र स्थिर हुए बिना स्वयं को मेरे प्रति समर्पित कर देता है।\nआचरण कितना भी बुरा क्यों न हो, उसे मूलतः अच्छा ही जानना चाहिए। क्योंकि वह निश्चित है\nअसली वाला.\n\nसच्चे भक्त प्रायः दुष्ट नहीं होते। अकास्मत सात्विक है\nयद्यपि किसी आदिम कर्म के कारण एक जन्म में उसके साथ दुर्व्यवहार हुआ था, फिर भी वह मूलतः है\nवह सर्वश्रेष्ठ होगा. क्योंकि उन्होंने अनेक जन्मों में भगवत्प्राप्ति की है। यह है\nभले ही हम आम लोग इसे नहीं देख सकते, भगवान इसे देखते हैं। वह भगवान की नजर में है\nअच्छा लगता है. इस कारण हमें किसी को भी हल्के में नहीं लेना चाहिए। एक बुरा\nरास्ते में चलने के कई कारण हो सकते हैं. वह सात्विक भी हो सकता है. लेकिन उसका\nप्रारब्ध कर्म ने शायद उसे उस मार्ग पर चलने के लिए प्रेरित किया होगा। जिसे अच्छा लगा\nकृष्ण अगले श्लोक में कहते हैं कि वह हमेशा उस रास्ते पर नहीं चलेंगे।",
  "9.24": "अहं हि सर्वयज्ञानं भोक्ता च प्रभुः एव च।\n\nन तू मम अभिजानन्ति तत्त्वेन अत: च्यवन्ति ते - मैं सभी पूजाएँ करने वाला नहीं हूँ।\nक्रेता और कंडक्टर. दरअसल वे मुझे ठीक से नहीं जानते. तो प्रवर्तन\nगिर जायेगा\n\nजैसा कि पहले चर्चा की गई है, कुछ लोग अपनी इच्छाओं की पूर्ति के लिए देवताओं से प्रार्थना करते हैं\nमुख्य रूप से पूजा की जाती है (भगवान के अलावा)। सवाल यह है कि जब आप ऐसा करते हैं तो क्या होता है\nहम उठ सकते हैं. इससे पहले कृष्ण ने कहा था कि 'मैं ही वह हूं जो हर चीज में मौजूद हूं।' किसको\nभले ही इसकी मुख्य रूप से पूजा की जाती है, यह भगवान के कारण है। यहां समस्या है पूजा\nजिनको वो जागरूकता नहीं है. यह एक गलत दृष्टिकोण है. भक्ति अनजाने में की गई\nयह पूर्ण भक्ति नहीं हो सकती. दूसरे की जानकारी के बिना की गई पूजा. हम कभी नहीं\nउत्थान नहीं किया जा सकता. कृष्ण कहते हैं, “इस प्रकार की पूजा से पुण्य अर्जित करने के बजाय, योग्यता कर्म है\nऐसा लगता है मानो वह फिसल कर गिर गया हो।\" इसलिए जो भी पूजा करें उसमें परतत्व का ध्यान रखें\nयह तभी सार्थक है जब किया जाए। जिसकी पूजा की जाती है, उस पूजा का फल मिलता है\n\nस्वयं भगवान. क्योंकि भगवान सभी यज्ञों के चरम हैं। यज्ञ के पीछे यही यज्ञपुरुष है\nरहस्य के रूप में, पुरुषसूक्त कहता है \"यज्ञेन यज्ञ मयाजंता देवः\" - यज्ञ से यज्ञ नमक।\nप्रभु की आराधना. बलिदानों के भगवान, बलिदानों के भगवान, बलिदानों के भगवान\nहम आराधना के माध्यम से प्रभु से जुड़ सकते हैं।\n\nफिर भी समाज में हम अनेक प्रकार से देवताओं की पूजा करते हैं\nहम देखेंगे. वे उस देवता की पूजा करने में समर्पित हैं। ऐसे करें पूजा\nकर्ता की गति क्या है? कृष्ण इसका उत्तर अगले श्लोक में देते हैं।\n\nयान्ति देवव्रत देवं पिथा न यान्ति पितृव्रतः |\nभूतानि यन्ति भूतेज्या यन्ति मद्याजिनोअपि मां",
  "9.22": "अनन्यः चिन्तयन्तः माँ ये जनः पर्युपासते।\n\nतेषाम् नित्य अभियुक्तानां योग क्षेमम् वहामि अहम् - बाकी सब कुछ और मुझे छोड़ दो\nविसर्जन के साथ पूजा करने वाले लोग सर्वत्र मेरी सेवा में समर्पित हैं।' उनका योग-\nमैं अपने स्वास्थ्य के लिए जिम्मेदार हूं।\n\nभागवत कुछ भी नहीं चाहते। यदि उनमें ईश्वर का विचार शेष रह जाए\nऔर कोई विचार नहीं है. वह विशिष्ट रूप से केवल भगवान की इच्छा रखता है। किसी वस्तु की इच्छा करना\nबांध गिरने पर वे पूजा नहीं करते। वह ईश्वर के अतिरिक्त कोई देवता नहीं है\nवे बलि चढ़ाकर पूजा नहीं करते। वह सभी देवताओं में से हैं\nसिर्फ भगवान ही नजर आते हैं. यह एकपत्नीत्व है; ईश्वर से जुड़ना, मोक्ष\nजिस मार्ग का अनुसरण किया जाना चाहिए।\n\nजब हम पूजा करते हैं तो संकल्प लेते हैं। यहाँ हमारी सांसारिक इच्छाएँ कभी नहीं होतीं\nइसे भगवान के सामने मत रखो. केवल ज्ञान, भक्ति, मोक्ष - यही हमारा संकल्प होना चाहिए। अनित्यता\nजब हम मनोकामना लेकर पूजा करते हैं तो हम महान फल खो देते हैं। हम लोगो को\nवह प्रभु हमसे बेहतर जानता है कि हमें क्या चाहिए और क्या नहीं\nहमें नहीं छोड़ेंगे. पूजा भगवान के प्रति एक अनोखी भक्ति ही है\nजब हम पौधे लगाते हैं तो भगवान हमसे प्यार करते हैं। कृष्ण कहते हैं. “तेषाम् नित्यभियुक्तानाम्।”\nयोगक्षेमन् वहाम्यहम्'' - मैं ऐसे भक्तों के कल्याण के लिए जिम्मेदार हूं।\nआपको आशा की क्या आवश्यकता है?\n\nयदि हम गहराई से विश्वास करते हैं कि \"भगवान हमें बचाएंगे और हमें बचाएंगे\", तो वह ऐसा करेंगे\nवह अपनी रक्षा स्वयं करता है। हमें ईश्वर में अपने विश्वास से कभी भी डिगना नहीं चाहिए।\n\nयह दृढ़ होना चाहिए. लक्ष्य केवल प्रभु से जुड़ना होना चाहिए। भगवान ने जो दिया है\nइसे एक महान उपहार के रूप में स्वीकार करें और पूरी तरह से उसके प्रति समर्पण कर दें। ऐसी स्थिति में हमारे लिए\nकभी दुःखी नहीं. जीवन आनंदमय है. जिंदगी में चाहे कुछ भी हो जाए\nयह यह जानते हुए कि यह प्रभु की इच्छा के अनुसार किया गया है, इसे खुशी से स्वीकार करने का दृष्टिकोण है\nहमारे बनो. यह मोक्ष का द्वार है।\n\nये*पन्यादेवता भक्त यजन्ते श्रद्धायतान्वितः |\nतेमपि मामेव कौन्तेय यजन्त्यविताधिपूर्वकम्",
  "9.28": "शुभ अशुभ भयः एवं मोक्षसे कर्म बंधनयेः |\n\nसंन्यास योग युक्त आत्मा विमुक्तः मम उपैश्यसि - इस प्रकार जीने पर, अच्छा-बुरा\nकर्म बंधन से बचो. फल का सुख त्याग कर कर्त्तव्य में लग गये\nकपड़े उतारो और मेरे साथ आओ।\n\nहम कोई भी कर्म 'मुझे ऐसा फल मिलेगा' और 'मुझे' के फल के साथ करते हैं\nजब अहंकार होता है कि 'मैंने यह कर्म किया है' तो वह कर्म हमसे जुड़ जाता है। उसके लिए\nपूर्वकाल में वे कर्मकर्ता बनने का संकल्प करते समय इस प्रकार कहते थे।\nभगवतो बलेण भगवतो वीरेण भगवदः तेजस |\nभगवत कर्मणा कर्मकरिष्यामि भगवतो वासुदेवस्यः ॥|\n\n\"मैं जो कर्म करता हूं वह मेरा कर्म नहीं है, यह मेरे भीतर के भगवान का कर्म है। इसके पीछे।\"\nशक्ति और सामर्थ्य सब भगवान के हैं, कुछ भी मेरा नहीं है।” यही भागवतधर्म का संकल्प है। भगवद\nकोई भी किया हुआ कर्म हमें बांध नहीं पाएगा। वेद व्यास ने ब्रह्मसूत्र में यह\nकहा: “जब प्रभु का ज्ञान अतीत से हमारे भीतर दृढ़ता से स्थापित हो जाता है\nवह ज्ञान की अग्नि सारे पापों को भस्म कर देगी।” अतः ज्ञान सबसे बड़ा है।\nइसे हम कठोपनिषद में यम और नचिकेता के बीच संवाद में देखते हैं। वहाँ\nजब नचिकेता ने यम से ज्ञान का वरदान मांगा तो यम ने उससे कहा, \"तुम्हें कितना धन चाहिए?\"\nसुनो, यदि तुम चाहो तो मैं तुम्हें एक विशाल साम्राज्य का सम्राट बना दूंगा। इस के लिए\nनचिकेता कहते हैं, ''ये सब नरक के साधन हैं, मुझे इनमें से कुछ भी नहीं चाहिए\nहमें प्रभु के बारे में जानना चाहिए।” इस प्रकार, हमारे पाप कर्म पूरी तरह से धुल जाते हैं\nईश्वर का ज्ञान ही मुक्ति का एकमात्र मार्ग है। भगवदर्पण बुद्धि द्वारा कर्म\nक्रियान्वित होने पर शुभ कर्म की शक्ति से मुक्ति संभव है। कृष्ण कहते हैं\nयथा ''संन्यासयोगयुक्तमा विमुक्तो मामापैश्यसि''। संन्यास ने कहा, यहां एक है\nयोग (टिप). भगवान को सब कुछ अर्पित करें और बिना किसी परिणाम के भगवत पूजा करें\nदृष्टि से सत्त्वगुण की प्राप्ति | संन्यास का अर्थ है भगवान में काम-संकल्प\nकाम अर्पण का अर्थ है 'करना चाहना', संकल्प का अर्थ है 'करना'\nकामसंकल्प वर्जिता-संन्यास का निर्णय करना। इस प्रकार भागवत धर्म का पालन करना आसान है\nकोई भी भगवान से जुड़ सकता है - \"निश्चित ही कोई मुझसे जुड़ेगा\" यह कृष्ण का वादा है।",
  "9.33": "किम् पुनः ब्राह्मणः पुण्यः भक्तः राजा क्षयः तथा |\n\nअनित्यम असुखम लोकम इमाम प्राप्य भजस्व मम - पुण्य के फल से ब्राह्मण बनो,\nउन भक्तों का क्या जो ख़ुशी जैसे राजा के रूप में पैदा हुए हैं? चूँकि यह अस्थिर है,\nजब मनुष्य जन्म में आनंद न हो तो मेरी पूजा करो।\n\n\"उन लोगों के लिए जो पुण्य के फल से राजा और ब्रह्म-ज्ञानी के रूप में पैदा हुए हैं और भगवान की पूजा करते हैं।\nविशेष रूप से क्या कहने की आवश्यकता है?” कृष्ण पूछते हैं. इस प्रकार उसने भगवान के सामने आत्मसमर्पण कर दिया और शरण मांगी\nसबकी रक्षा का भार भगवान पर है। इसके लिए कृष्ण हमें यहां बताते हैं:\n\"यह सोचकर संसार में मत फंसो कि यह संसार ही सब कुछ है, क्योंकि यह 'अनित्यम्' है।\nअसुखम् लोकम्”। इसमें कोई ख़ुशी नहीं है. यह स्थायी नहीं है. इसलिए शाश्वत आनंद\nप्राप्त करने के लिए मेरी शरण लो। मेरे साअमने समर्पण करो। तुम्हें बचाना मेरी ज़िम्मेदारी है”।\n\nमन्मना भव मदभा क्तो मध्याजी मां नमस्कुरु |\nमामेवैश्यसि उक्रिवमात्मानं मत्सरायणः",
  "10.1": "भगवान उवाच - भगवान ने कहा:\n\nभूयः एव महाबाहो श्रृणु मेइ परमं वाचः।\n\nयत् ते अहम प्रियमानया वक्ष्यामि हित कामया - हे महावीर, मेरी बात फिर से सुनो।\nहिरूनी, क्योंकि मैं यह तुमसे कह रहा हूं जो सुनकर प्रसन्न हैं।\n\nगुरु को ज्ञान देने में असंतोष शिष्य की प्रतिभा और गुणवत्ता के कारण होता है। यहाँ कृष्ण हैं\nवह कहता है: \"मैं तुम्हें और अधिक बताऊंगा।\" क्योंकि यहाँ जो कहा जा रहा है वह \"परमं वाचः\" है।\nकृष्ण कहते हैं. यहां 'परमाण' का मतलब सबसे बड़ी चीज है जिसे हमें जानना जरूरी है।\nयह सबसे बड़ा ज्ञान है जो पारलौकिकता की जागरूकता देता है। पूरी दुनिया को\nयह मददगार है. इससे बढ़कर कुछ नहीं है. “आप इस युद्ध भूमि में हैं\nआप खड़े होकर यह सुन रहे हैं और खुश हैं, वह खुशी आपके अंदर उमड़ रही है। उसके लिए, दुनिया\nमैं तुम्हारी भलाई के लिए तुम्हें बताऊंगा, सुनो, ”कृष्ण कहते हैं।",
  "9.31": "क्षिप्रं भवति धर्म आत्मा शाश्वत शांतिम् निगच्छति।\nकौन्तेय प्रतिजानिः न मे भक्तः प्रणस्यति - वही मार्गदर्शन करता है; अमर\nउसे ख़ुशी मिलती है. कौन्तेय, यह व्रत करो: \"मेरा भक्त कभी नष्ट नहीं होगा\"।\n\nइस प्रकार जो लोग प्रारब्ध कर्म के कारण भटक गए हैं वे स्वयं भी किसी न किसी बिंदु पर हैं\nगलत कार्य का एहसास होने पर वह सही मार्ग अपनाता है और शाश्वत मोक्ष प्राप्त करता है।\nयह निश्चित है. कृष्ण कहते हैं तुम यह शपथ लेते हो। इसका अच्छा उदाहरण अजामिलन है\nकहानी अजामिल मूल रूप से एक महान जीव थी जिसने वह किया जो एलडीए को अपने जीवन में नहीं करना चाहिए था। जैसे कि\n\nजीवन के अंत में भगवान अजामिल को सत्य का मार्ग दिखाते हैं और उसका उद्धार करते हैं। वह है\nजीवन के अंत में उसे मोक्ष की प्राप्ति होती है।\nकृष्ण अर्जुन से क्यों कहते हैं, \"तुम प्रतिज्ञा करो\" का अर्थ है - भगवान ने भक्तों को अपनी प्रतिज्ञा दी है।\nउन्होंने प्रतिज्ञा तोड़ी लेकिन भक्तों की प्रतिज्ञा कभी नहीं तोड़ी। इसका उदाहरण महाभारत है\nयुद्ध की एक घटना:\nमहाभारत युद्ध से पहले कृष्ण ने शस्त्र न उठाने की प्रतिज्ञा की थी\nइस बीच जब अर्जुन भीष्म से युद्ध करने से झिझके तो भीष्म क्रोधित हो गये\nवह रथ का पहिया पकड़ कर आगे आता है मानो उसे ही मार डालेगा! भीष्म ने यह देखा\nवह दोनों हाथ जोड़कर कहता है: \"हे भगवान, मैं आपके हाथ में पहिया ऐसे ही पकड़ता हूं।\"\nमैंने लड़ने की कसम खाई. आपने कहा था कि आप पहिया नहीं पकड़ेंगे। लेकिन अब\nतुम मेरी प्रतिज्ञा पूरी करने के लिये चक्र थाम लो। तुम अपने को भूल गये हो, परन्तु अपने भक्त को\nप्रतिज्ञा नहीं; आपके अलावा हमारे लिए और कौन है?” वह है. इस घटना में भगवान का कैसा भक्त है\nयह समझ में आ गया है.\n\nमम हि पार्थ व्यापश्रित्य येपि स्युः पापयोनयः;ह |\n\nस्त्रीयो वैश्यस्तथा शूद्रस्ते*पी यान्ति परमं गतिम्",
  "10.7": "एतम् विभूतिम योगम् च मम यः वेत्ति तत्वतः |\nसाह अविकाल्डेना. योगेन युज्यते न अत्र संशयः - यह मेरी महानता है\nजो मेरे गौरवशाली रूपों की विविधता] और गहराई को ठीक से जानता है वह शुद्ध है\nध्यान योग में स्थित हो जाता है। इसके बारे में कोई संदेह नहीं है।\n\nयदि हम वास्तव में भगवान की महानता, उनके विभिन्न रूपों, उनकी गहराई को जानते हैं\nनिःसंदेह समर्पण आएगा। ईश्वर का ज्ञान हमें आत्मविश्वास देता है।\nश्रद्धा और भक्ति से भरा हुआ मन भगवान में विश्राम करता है।",
  "10.2": "नाम विदुः सुरा गणः प्रभावं न मह खुशायः |\n\nअहं अदिह ही देवानां मह खुपीनं च सर्वसः - मेरी गहराई: [मैं ही संसार हूं\nनिर्माण की विधि देवताओं, ऋषियों या किसी अन्य को ज्ञात नहीं है। देवताओं को,\nक्या मैं हर किसी के लिए वरिष्ठ खुशियों का स्रोत नहीं हूँ?\n\nकृष्ण यहां एक बुनियादी बात कह रहे हैं। कृष्ण कहते हैं: “मेरी महिमा\nमहर्षि से लेकर ब्रह्मा तक देवता अज्ञात हैं। यहाँ 'शक्ति' शब्द तीन हैं\nअर्थ में प्रयुक्त। प्रभव का अर्थ है उत्पत्ति या उत्पत्ति; प्रभाव का अर्थ है क्षमता या\nमहानता; प्रभव जगत् की रचना है। “मेरी उत्पत्ति, मेरी महिमा और इस संसार की मेरी उत्पत्ति\nजन्मे-उन महान ऋषियों से जिन्होंने मुझे जाना, ब्रह्मादि जिन्होंने मेरा परोक्ष ज्ञान प्राप्त किया\nयहाँ तक कि देवता भी नहीं जानते,'' कृष्ण कहते हैं।\n\nयो मामजमनदिं च वेत्ति लोकमहेश्वरम्।\n\nअसमुद्धः स मर्तयेसु सर्वपापैः प्रमुच्यते",
  "9.27": "यत् करोशि यत् अश्नासि यत् जुहोशि ददासि यत् |\nयत् तपस्यासि कौन्तेय तत् कुरुष्ठ मत अर्पणम् -- कौन्तेय, तुम क्या करते हो, क्या\nतुम क्या चाहते हो, क्या प्यार करते हो, क्या देते हो, क्या खोते हो, मुझे सौंप दो।\n\nकृष्ण कहते हैं. “तुम्हें मेरे लिए कुछ नहीं करना है लेकिन तुम्हारे लिए क्या\nयदि आप ऐसा करते हैं, तो इसे मुझे पेश करें। हमारे दैनिक जीवन में करने के लिए बहुत सारे काम हैं\nअपरिहार्य कैरियर कार्य हैं। जीवनयापन में खर्चा होगा। हम भगवान के हैं\nइसे पूजा के नाम से जानना चाहिए. इसका अच्छा उदाहरण धर्मव्याधन की कहानी है। मांस बेचो\nउनके जीवन में एक दृढ़ संकल्प था। “मांस बेचना मेरे लिए आनुवंशिक है\n\nएक आदत जो आ गयी है. इसलिए मैं मांस बेचता हूं, ताकि मैं जीवित रह सकूं और अपना गुजारा कर सकूं\nमैं यह पेशा अपनाता हूं जो मेरे माता-पिता का समर्थन करने के लिए मेरे पास आया है।\nइससे मैं उतना ही कमा पाता हूँ जितना मुझे अपने जीवन के लिए चाहिए। लोग हमेशा व्यवसाय में रहते हैं\nवह यह सोचकर मांस बेचता था कि वह शोषण नहीं करेगा\nइसे ज्ञानी धर्मव्याध के नाम से जाना जाने लगा। एक ऐसी घटना घटी जब ख़ुशी मुनीस ने उनसे सबक सीखा।\nइसका मूल कारण यह है कि वह जो कर रहे थे वह ईश्वर की आराधना के रूप में किया।\nइस प्रकार हम जो काम करते हैं उसका कोई महत्व नहीं है, बल्कि वह भगवान की पूजा के रूप में किया जाता है\nदृष्टिकोण महत्वपूर्ण है.\nजो कुछ भी आपका दैनिक कर्तव्य है, उसे भगवान को अर्पित करें। इसे भगवान की पूजा बनाओ.\nभगवान के लिए पकवान भोज्य बनाने की जरूरत नहीं है. आप क्या खा रहे हैं\nप्रभु को समर्पित हो जाओ. जब ऐसा किया जाता है तो भगवान की पूजा अलग नहीं होती और\nयह कठिन नहीं होगा. भगवान के लिए कोई विशेष होम-हवन करने की आवश्यकता नहीं है। आप हैं\nआप जो भी होम करते हैं उसे \"अग्नि परगता नारायण इदं न ममः\" कहा जाता है।\nसमर्पित करें यदि आप किसी भूखे व्यक्ति को देखें तो वह वैश्वान रूपी भगवान को अपने पेट में लिए हुए है\nउस व्यक्ति को बताएं कि वह आया है और उसके भीतर वैश्वान को प्रसन्न करें\nकरो यह प्रभु की महान पूजा है।\nकृष्ण कहते हैं \"यत्तपस्यासि कौन्तेय तत् कुरुष्ठ मदारपनम्\"। यहाँ तपस्या है\n\"सोचना' या वृतानुष्ठान। उदाहरण के लिए \"संकष्टी'- इसे मनाते समय गणपति\nइसे अवतारी प्रभु के प्रति समर्पण के रूप में करें। कोई स्वार्थ नहीं है\nइस प्रकार कोई भी अनुष्ठान भगवान के सर्वोच्च व्यक्तित्व को समर्पित नहीं है\nजब आप यह जान लेते हैं तो यह सच्ची तपस्या बन जाती है। यहाँ अर्जुन से कहा गया है, “तुम्हारा कर्तव्य कर्म है\nइस श्लोक का संदेश यह है कि यह जो युद्ध आया है, इसका भी भगवान को भजन करना चाहिए\nकृष्ण ने दिया है. भागवत धर्म के कार्यान्वयन का परिणाम क्या है, इसका पालन कृष्ण करते हैं\nवह श्लोक में बताते हैं.\n\nशुभाशुभफलैरेवं मोक्षसे कर्मबन्धनैः |\n\nसंन्यासयोग्युकात्मा विमुक्तो मामुपैस्यासि",
  "10.12": "अर्जुन उवाच —\nपरं ब्रह्म परं धाम पवित्रं परमं भवान् ।\nपुरुषं शाश्वतं दिव्यमादिदेवमजं विभुम् ॥\n\n'आप परम ब्रह्म, परम धाम, परम पवित्र हैं। आप शाश्वत दिव्य पुरुष, आदिदेव, अज, विभु हैं।'\n\nअर्जुन का यह उद्गार — भगवान् की विभूतियों की लम्बी सूची सुनने के बाद। 'परं ब्रह्म' — परम सत्ता। 'आदिदेव' — देवों के देव। 'अज' — जन्मरहित। 'विभु' — सर्वव्यापी। मध्वमत में 'परं ब्रह्म' = नारायण।",
  "7.8": "जल में रस — मेरी विभूति; चन्द्र-सूर्य में प्रकाश — मेरी विभूति; सब वेदों में ओंकार — मेरी विभूति; आकाश में शब्द — मेरी विभूति; मनुष्यों में पौरुष — मेरी विभूति।\n\nप्रत्येक वस्तु में भगवान् विशेष नाम से अन्तर्यामी हैं। जल में 'रस'नामक, चन्द्र-सूर्य में 'प्रभा'नामक, वेदों में 'प्रणव'नामक, आकाश में 'शब्द'नामक, मनुष्यों में 'पौरुष'नामक।",
  "10.8": "अहं सर्वस्य प्रभावः मततः सर्वं प्रवर्तते।\nइति मत्वा भजन्ते माम् बुधः भव समन्वितः जो जानता है कि \"मैं सभी चीजों का कारण हूं,\nसब कुछ मेरे साथ हो रहा है,' उसने मुझे भक्तिभाव से भरते हुए कहा।\n\nऋषियों ने कहा, “भगवान हर चीज़ के नियंत्रक हैं, सब कुछ भगवान द्वारा बनाया गया है, सब कुछ\nइस तथ्य को समझते हुए कि यह भगवान द्वारा नियुक्त है, वह भक्तिपूर्वक पूजा करता है। “इस तरह\nजिनके पास भगवान के प्रति अद्वितीय भक्ति और सर्वोच्च ज्ञान है: उनके मन की सभी दुनियाएं मेरी हैं।\nअधीनस्थ, मैं हर चीज का कारण हूं, सब कुछ मुझसे पैदा होता है, सब कुछ मेरे द्वारा नियंत्रित होता है,\nयह जानते हुए कि सब कुछ मेरे अधीन है, वह पूजा करता है,\" कृष्ण कहते हैं।\n\nमच्चि तत् मद्गतप्राण बोधयन्तः शिक्षायम् |\nकथ्यन्तश्च मम नित्यं थुप्यन्ति च रमण्तिचा...।",
  "9.32": "माँ हि पार्थ व्यापा सृत्य ये अपि स्यूः पापयोनयः;ह |\nस्त्रीः वैश्य तथा शूद्र ते अपि यान्ति परम गतिम् - पार्थ, जिसने मेरी शरण ली है\nकिसी पाप के कारण स्त्री, वैश्य, शूद्र के रूप में उपलब्धि से वंचित होने पर भी वह ज्येष्ठ है\n\nवे मुझे परमधाम दिला देते हैं।\n\nइस श्लोक ने कुछ टीकाकारों को भ्रमित कर दिया है। इस श्लोक पर माधवाचार्य की टीका है\nजब तक यह नहीं दिया गया था, अधिकांश ने इसे गलत समझा था। इस श्लोक की सतह पर\nयह जानने का जोखिम अधिक है कि \"महिलाएं, वैश्य और शूद्र पापी हैं\"। यहाँ कृष्ण हैं\nयह महिलाओं के जीवन के बारे में नहीं है. महिलाएं पापी नहीं हैं. किसी पाप से या\nएक श्राप के कारण पैदा हुआ नर मादा \"मादा पपायोनी\" है न कि मादा पपायोनी।\nकृष्ण कहते हैं, ''हिनायोनि शायद किसी पाप से आई है, लेकिन मैं ऐसा ही हूं\nपूजा करने से मनुष्य सभी दोषों से मुक्त हो जाता है।” इसका एक अच्छा उदाहरण\nनरकासुर की बंदी सोलह हजार एक सौ स्त्रियाँ थीं। ये अग्नि के पुत्र हैं।\nउन्होंने अपना कद खो दिया और भगवान की पत्नियाँ बनने की इच्छा से पृथ्वी पर महिलाएँ बन गईं\nजिनका जन्म हुआ और वे नरकासुर के कारागार में फँस गये। कृष्ण ने उनसे विवाह किया और उनका पालन-पोषण किया।\n\nनंदगोप और यशोदा मूल रूप से देवांशसंभूत थे। 'द्रोण' वसु का ही उपनाम है\nनंदगोप एवं 'धरा' नमक वसुपत्नी यशोदे। उनका जन्म पृथ्वी पर एक वैश्य के रूप में हुआ था।\nभगवान अपने अवतार में उनके घर में पले-बढ़े और उनका पालन-पोषण किया।\nमहाचेतना विधुर हैं. वह स्वयं धर्मी है. वेदव्यास का पुत्र होने पर भी वह शापित है\nनतीजा ये हुआ कि उन्हें एक मजदूर का बेटा होने का दावा करके जीना पड़ा.\nवह दुर्योधन, भीष्म और द्रोण के घर जाने के बजाय सीधे विधुर के घर और विधुर के पास से आये।\nसाधारण सी मिठाई खाकर उसे खुश कर दिया। भगवान यहाँ जो चाहते हैं वह कोई दिखावा नहीं है\nबल्कि यह स्पष्ट हो जाता है कि यह प्रेम है। उनके लिए आत्मा महत्वपूर्ण है, मुखौटा नहीं.\nइस प्रकार कृष्ण st बन गए। कहते हैं, “पापपूर्ण कर्म या श्राप से कुछ\nजब जो लोग मेरी शरण लेते हैं, वे जो हेनायोनि के रूप में जन्म लेते हैं, वे अपने पापों से छुटकारा पा जाते हैं और मुझसे जुड़ जाते हैं”\nवह है.\n\nकिं पुनर्ब्रह्मणः पुण्यं भक्त राजर्षयस्थतः।\n\nअनित्यमसुखं लोकमिमां प्राप्य भजस्व मम",
  "9.25": "यान्ति देवव्रतः देवां पितृ-न यान्ति पितृव्रतः |\n\nभूटानि यन्ति भूतेज्यः यन्ति मत याजिनः अपि मम-देवताओं के भाड़े के लोग।\nस्वर्गदूतों से जुड़ता है. जो लोग पितरों द्वारा नियुक्त किये जाते हैं, वे पितरों में शामिल हो जाते हैं। भूत\nउपासक राक्षसों से जुड़ते हैं। जो मेरी पूजा करते हैं वे मुझसे जुड़ जाते हैं।\n\nकृष्ण कहते हैं, 'तुम जिसकी पूजा करते हो, वह तुम्हें मिलता है।' देवदूत\nजो देवताओं की पूजा करते हैं, जो पितरों की पूजा करते हैं, जो पितरों, भूतों (देवता) की पूजा करते हैं\nगण) की पूजा करने वालों को भी भूत प्राप्त होते हैं। परन्तु जो हर बात में एकचित्त है\nजो लोग भगवान को पाते हैं और ईमानदारी से उनकी पूजा करते हैं - \"वे मुझसे जुड़ेंगे\" -\nकृष्ण यहाँ आशा देते हैं। कोई देवताओं की पूजा कर सकता है और स्वर्ग प्राप्त कर सकता है, लेकिन वापस\nअजन्मे की मुक्ति नहीं. पूजा चाहे कोई भी की जाए, हर कार्य के पीछे ईश्वर का हाथ होता है\nउसे जानना और उसकी पूजा करना ही वास्तविक पूजा है। बिना जागरूकता के कभी भी हमारी पूजा न करें\nमोक्ष की ओर नहीं ले जाता. मानो ब्रह्मा समस्त देवताओं के परिवार के साथ है\nयदि तुम प्रभु की आराधना करोगे तो तुम प्रभु से जुड़ जाओगे। यह एक वैज्ञानिक प्रणाली है.\n\nअगली कविता पर आगे बढ़ने से पहले, हमें यहां एक बात स्पष्ट करनी होगी। हम हैं\nहमारे दैनिक जीवन में गणहोम, नवग्रहहोम, देव पूजा, संकष्टी आदि के रूप में।\nहम पूजा करेंगे. क्या ये ग़लत है? हम गणपति या किसी अन्य प्रतीक में भगवान हैं\nक्या पूजा करने से हमें मोक्ष नहीं मिलता? क्या सही है, क्या ग़लत है? जो है\nत्रिविद्याधर्म, भागवत धर्म कौन सा है?\n\nभागवत धर्म आज हमारे बीच से लुप्त होता जा रहा है। कोई भी प्रतीक अन्तर्यामी प्रभु का है\nपूजा करना गलत नहीं है. लेकिन इसके पीछे हमारी मंशा गलत है. उदाहरण के लिए नवग्रह होम। एक\nयदि हम किसी फल की नहीं, केवल मोक्ष की प्राप्ति की इच्छा रखते हैं, तो देवताओं का पूरा परिवार,\nनवग्रह नारायण प्रीत्यर्थ नवग्रह होम करने में कुछ भी गलत नहीं है। लेकिन वहाँ\nआइए हम \"नवग्रह को नारायण प्रसन्न के रूप में अवतरित करें और इस प्रकार नवग्रह दोष का निवारण करें\"\nजब आप उसका संकल्प कर लेते हैं तो वह त्रिविद्या धर्म बन जाता है। संकल्प करते समय कोई इच्छा नहीं\nकेवल भगवत् प्रीत्यार्थ को जोड़े बिना जो भी काम्य कर्म किया जाता है वह भागवत धर्म है।\nयदि प्रभु प्रसन्न हो तो सब कुछ तैयार है। उसने जो दिया है उसका आनंद लो,\nजो नहीं दिया गया है उसे मत चाहो. अपनी कठिनाइयों को दूर करने के लिए भगवान की पूजा न करें।\nइसके बजाय, जो आता है उसे प्रसाद के रूप में स्वीकार करें और ज्ञान वैराग्य भक्ति-मोक्ष देना जारी रखें\nप्रभु से प्रार्थना करें. आपकी सुरक्षा का भार उस प्रभु का है। इसकी चिंता मत करो.\nआपके जीवन में जो घटित हो रहा है वह कोई दुर्घटना नहीं है। इसके उन्मूलन के लिए यह ईश्वर की इच्छा है\nआप भगवान की पूजा नहीं कर रहे हैं बल्कि भगवान से जुड़ने के लिए भगवान की पूजा कर रहे हैं। यह\nउदाहरण के लिए, जब हम अपने इरादे के पीछे का दृष्टिकोण बदलते हैं, तो यह भागवत है\nएक धर्म बन जाता है. यदि कोई त्रिविद्या अपने गुरु को \"मेरे गुरु\" कहकर प्रणाम करता है, तो भागवत कहती है, \"आ।\"\nवह यह जानकर कि गुरु के अंदर भगवान विराजमान हैं और मुझे शिक्षा दे रहे हैं, नमस्कार करते हैं।\nभागवत अपने सभी कार्यों में भगवान को देखता है। वह अपने सभी कार्यों और कर्मों में मोक्ष है\nभगवान के अलावा किसी और चीज की इच्छा न करें। इनकी आराधना में मोक्ष की कामना की जाती है\nऔर कोई इच्छा नहीं बची. हमारे लिए इस ऊंचाई तक पहुंचना असंभव नहीं है।'  यह संभव है\nबस इतना ही करने के लिए प्रयास करना पड़ता है। हम जितना भगवत प्रीत्यार्थ कर्म करेंगे उतना ही\nहम मोक्ष के उतने ही करीब पहुँचते हैं। \"मुझे यह दो\" या \"यह।\"\nकभी भी 'इसे ठीक करो' के लिए न कहें। भगवान जानता है कि तुम्हें क्या चाहिए\nइसे भगवान पर छोड़ दो. बस भगवद प्रेम के लिए, मोक्ष की प्राप्ति के लिए कर्म करो।” “यह बस है\n\"केवल भीमसेना/वायुदेव के लिए\" बिना भागे और बिना किसी फल की तलाश के\nअन्यथा पूरी श्रद्धा से भगवान की आराधना करें। पूजा में मांगने की शक्ति केवल आपके पास है\nमोक्ष और ईश्वर'. इसे पाने के लिए अपनी उपलब्धि समर्पित करें। सात जो जीवन में आते हैं\nपतन, सब कुछ नश्वर है, इसके बारे में सोचे बिना, संसार से छुटकारा पाएं और मृत्युहीन मोक्ष प्राप्त करें\nशामिल होने के लिए प्रदर्शन करें. यह यहां का मूल संदेश है.\n\nभगवान की पूजा धन दौलत के बारे में नहीं है. बस शुद्ध भक्ति. भगवान की भक्ति कितनी है?\nकृष्ण निम्नलिखित श्लोक में सहजता की व्याख्या करते हैं:\n\nपात्रं पुष्पं फलं तोयं यो मे भक्त्या प्रयच्छति |\nतदहं भक्कुपहृतमश्ना मि प्रयतात्मनः",
  "10.9": "मत् चित्तः मत गता प्राहा बोध्यन्तः संसानम्।\nकथयन्तः च मम नित्यं तुष्यन्ति च रमन्ति च - अनुगला मेरे द्वारा, मेरे लिए बनाया गया है।\nजो जीवित हैं, वे मुझे एक दूसरे से जानते और जानते हैं; खुश होगे।\n\nइस प्रकार सच्चा ज्ञान और भक्ति रखने वालों के मन में सदैव भगवान के विचार भरे रहते हैं। उसका मन\nदिव्य छोड़ देता है. वे हर चीज़ में भगवान देखते हैं। यह हर इवेंट के लिए है\nवे इस ज्ञान में रहते हैं कि ईश्वर उनके पीछे है और सब कुछ उसकी इच्छा के अनुसार होगा। उसका\nमन ईश्वर की ओर उन्मुख हो जाता है। वह हमेशा भगवान के बारे में बात करता रहता है।\nवह हर चीज़ का विश्लेषण इस तरह करता है जैसे \"ईश्वर की रचना कितनी अद्भुत है\"।\nवे अपने जीवन की हर घटना को ईश्वर के उपहार के रूप में स्वीकार करते हैं।\nइनका जीवन आनंदमय रहेगा। उनमें कोई बुरे विचार नहीं होते. उसका मन\nसदैव शुद्ध. उन्होंने सांसारिक व्यापार की बातें छोड़कर ईश्वर का चिंतन किया\nहमेशा बात करने में मजा आता है.\n\nतेषाम् सत्ययुक्तानां भजताम् प्रीतिपूर्वकम् |\nददामि बुद्धियोगं तम् येन मामुपयन्ति ते",
  "10.15": "वक्षुमर्हास्यशेषेण दिव्य हात्मविभूतयः |\n\nयाभिर्विभूतिभिर्लोकनिमनस्त्रं व्याप्य तिथिसि",
  "10.14": "सर्वं एतत् खुत्तं मन्ये यत् माम् वदसि केशव |\n\nनहिते भगवान बैचिम विदुः देवः न दानवः - हे केशव, आपने मुझसे क्या कहा?\nमैं जानता हूं वह सब सच है. हे प्रभु, जिस रीति से तू उत्पन्न हुआ, हे देवता भी,\nदानदाताओं को भी जानकारी नहीं है.\n\n“मैं जानता हूँ कि आप जो कह रहे हैं उसमें कोई अतिशयोक्ति नहीं है\nवह कहते हैं, ''न तो देवता और न ही उपकारी प्रकटीकरण को जानते हैं।'' अर्जुन. देवताओं को\nईश्वर के गुणों को मापा नहीं जा सकता... दान देने वाले ईश्वर में दोष हैं\nखोज सफल नहीं रही. क्योंकि भगवान असीम रूप से अच्छा है. उसका कोई भी\nकोई त्रुटि नहीं. उसे पूरी तरह समझ पाना असंभव है. उसे भगवान के बारे में क्या कहना चाहिए?\nजब तक कोई दूसरा इसका वर्णन न कर सके. प्रभु का पूर्ण ज्ञान हो,\nउनका एक भी अवतार या अवतारों में उनकी एक भी लीला पूर्ण नहीं है\nइसे समझना कठिन है. हम यह नहीं समझ सकते कि कृष्ण ने अपने अवतार में कैसा व्यवहार किया।\nहमें यह अजीब लगता है. उन्हें जानना कोई आसान काम नहीं है. उसका एक\nआंदोलन के पीछे एक संदेश है.",
  "10.3": "यं मम अजं अनादिं च वेत्ति लोक मह ईश्वरम् |\n\nअसम्मुधा सः मर्त्येषु सर्व पापैः प्रमुच्यते - मैं अजन्मा हूं। सब कुछ चल रहा है\nवह जो सभी चीज़ों से पहले था [अमरता के माध्यम से]। समस्त लोकों के स्वामी.\nजो मनुष्य मनुष्यों में मुझे इस प्रकार जानता है, वही मोहग्रस्त है। वह पापों से बच जाता है।\n\nहममें से कुछ लोगों का एक प्रश्न है. \"यदि प्रभु ने सभी जीवित प्राणियों को बनाया,\nइसे किसने बनाया।” यदि ईश्वर को दूसरे द्वारा बनाया जा रहा है तो हम हैं\nउनको भगवान नहीं कहा जाता था. कृष्ण जानते हैं कि हमारे संदेह क्या हैं।\nइसके लिए उन्होंने इस श्लोक में हमारे प्रश्न का उत्तर दिया है। कृष्ण कहते हैं “यहाँ मम अजम\n\"अनादिम\"। यहाँ \"अज\" का अर्थ अजन्मा है। भगवान जन्म और मृत्यु से परे हैं।\nइसके लिए यदि हम जन्म और मृत्यु से बचना चाहते हैं तो हमें उनकी पूजा करनी चाहिए और उनसे जुड़ना चाहिए।\nभगवान शाश्वत हैं. यहाँ अनादि (अना*दि) का अर्थ है: “वह जो सबसे पहले सृजन और निर्माण की प्रेरणा देता है\nइसे सर्वोच्च शक्ति बनाएं जो इस सृष्टि में सभी व्यवसाय को नियंत्रित करती है।'\n\nभगवान 'लोकमहेश्वरः'। ब्रह्मा सभी देवता हैं-'लोकेश'। उनकी माता लक्ष्मी-\n'लोकेश्वरी'. वह भगवान उसके लिए भी महान हैं - 'लोकमहेश्वर'। उससे भी बड़ा एक और\nकोई सिद्धांत नहीं है. वह जन्म और मृत्यु से परे है।\n\nवह भगवान हैं जिन्होंने महर्षियों, देवताओं, सभी को बनाया। तो वे सब उसके हैं\nमहिमा का अंत नहीं देखा है. खुग्वेद में एक स्थान पर कहा गया है: न ते विष्णो\nजयामानो न जातो देव महिम्नः परमंतमपा'। यहाँ तक कि अतीत में जन्मे लोग भी,\nयहाँ तक कि इसके बाद जन्मे लोग भी भगवान की महिमा के चरम अंत को नहीं जानते और न ही जान सकते हैं।\nक्योंकि यह अनंत है.\n\nयह सृष्टि कैसे रची, यह कोई नहीं जानते। क्योंकि जलप्रलय के दौरान\nप्रभु के पेट में सब कुछ सो गया है, जिसके बाद सृजन के समय योग सबसे पहले था\nचतुर्मुख भगवान ने बनाया है। तो यह चतुर्मुख के जन्म से पहले ही शुरू हो गया था\nइस सृष्टि का निर्माण किसी ने नहीं देखा है। इसके लिए खुग्वेद में ''यदि इस सृष्टि का रहस्य जान लिया जाए।''\nएक बुद्धिमान पुत्र को पता होना चाहिए\"। वह भगवान की रचना का पहला जीवन है - 'चतुर्मुख'\nब्रह्मा'. इन सबके कारण हम सामान्य मनुष्य परमेश्वर की पूर्ण महिमा हैं\nयह जानना असंभव है. आचार्य ने यह कहा: “बहु चित्र जगत् बहुदाकारनात्\nअस पराशक्तिरनन्त गुणः परमः”। यह ईश्वर की रचना की दुनिया है\nयह जितना महान है—वह रचनाकार भी उतना ही महान होगा। अतः भगवान अनन्त हैं\nउसे समझना और उसकी पूजा करना ही मोक्ष का एकमात्र मार्ग है। भगवान के बारे में ये सच्चाई\n\"असामुधा\" के नाम से जाना जाता है। वह सदैव बिना किसी भ्रम के सभी से और सभी में प्रेम करता रहता है\nवह प्रभु को देखता है। \"इस सत्य का अभ्यास करने वाला सभी पापों से बच जाता है\"\nयह कृष्ण का वचन है.",
  "10.11": "तेषाम् एव अनुकंपार्थम् अहं आज्ञा जम तमः।\n\nनाशयामि आत्म भव स्थ ज्ञान दीपेण भास्वत - मैं उनकी करुणा से बाहर हूं, उनकी\nरास्ते में खड़ा होकर, मैं चमकते हुए ज्ञान के प्रकाश से अज्ञानता के अंधेरे को दूर करता हूं।\n\nईश्वर हमें स्वार्थी कारणों से नहीं बचाता। बल्कि हमसे ऊपर\nदया के कारण. वे उस भक्त पर दया करते हैं जो अनन्य भक्ति से उनकी पूजा करता है\nहमें बचाता है. वह हमें न केवल बुद्धि देता है, बल्कि सदैव हमारी बुद्धि भी देता है\nवह तमस (अज्ञान) का कफन हटाने वाला भी है। ईश्वर की सहायता के बिना हम हैं\nमन-बुद्धि में घुसे अज्ञान के परदे को हम स्वयं दूर नहीं कर सकते। तीन गुना\nइस अंधकार को केवल भगवान ही दूर कर सकते हैं। इससे हम सत्य को सत्य के रूप में ग्रहण करते हैं\nप्रभु हमें भक्ति से भर सकते हैं, हमारे स्वभाव को जागृत कर सकते हैं, दयालु बन सकते हैं\nवह दृष्टि देता है, हर प्रकार से प्रकाश देता है, सत्य का दर्शन कराता है। इसके लिए\nहमें यह कहते हुए उसके प्रति समर्पण करना चाहिए, \"हे प्रभु, मेरे भीतर के अंधकार को दूर करो। भीतर के अंधकार को।\"\nकितना भी रख-रखाव करके पढ़ लो, कोई फायदा नहीं। जब आप धर्मग्रंथ पढ़ते हैं तो सत्य\nईश्वर में समर्पण जानना महत्वपूर्ण है।\n\nइस समय, कृष्ण की सलाह सुनकर अर्जुन स्तब्ध हो गए। वह युद्ध के मैदान में है\nवह भूल जाता है कि वह खड़ा है और उसे केवल कृष्ण ही दिखाई देने लगते हैं। अगला\nचार श्लोकों में अर्जुन का भगवान अर्जुन की अनंत शक्ति के प्रति दृष्टिकोण\nहम इसे अभिव्यक्त होते देखते हैं।",
  "10.17": "कथं विद्यां अहं योगिन त्वं सदा परिचिंतयं |\n\nकेशुकेषु च भावेषु चिन्त्यः असि भगवान माया-सर्वसमर्थक, अनुगला आपका कैसे समर्थन करता है?\nक्या मैं परिवेश को जान सकता हूँ? हे भगवान, चीजों में चीजें कैसी हैं?\nक्या मुझे याद रखना चाहिए?\n\nइस संसार की प्रत्येक वस्तु में एक अद्वितीय गुण के पीछे भगवान की विभूति निहित है।\nयहाँ अर्जुन भगवान से प्रार्थना करता है: “आप कहाँ हैं, सर्वशक्तिमान?\nमैं जानता हूं लेकिन मैं खुद नहीं। जब मैं कोई चीज़ देखता हूँ तो मुझे उसके पीछे की भगवद् शक्ति का स्मरण हो आता है\nमुझे आना है। मैं किसी भी वस्तु में आपकी पूजा कर सकता हूं - वह मैं हूं\nजानना चाहिए\"।",
  "10.10": "तेषाम् सचदा युक्तानां भजताम् प्रीति पूर्वकम्।\nददामि बुद्धियोगं तम् येन माम् उपयन्ति ते - मैं स्वयं धन्य हो गया हूँ।\nमैं ज्ञान का वह मार्ग उन लोगों को प्रदान करता हूं जो प्रेम से इसका सेवन करते हैं। इस वजह से वे मैं हूं\n\nशामिल हो जायेंगे\n\nइस श्लोक में \"सतत्ययुक्तानाम्\" में आने वाले 'यक्ति' शब्द के संस्कृत में कई अर्थ हैं।\nअर्थ हैं. तरकीब यह है कि बिना भटके, बिना फिसले, बहुत योग्य अनुष्ठान करके जीना है,\nयुक्ति वैदिक अध्ययन को समझने की है जो भगवान के दृष्टिकोण का पूरक है। प्रभु में\nमन को स्थिर करने की युक्ति है। यहाँ कृष्ण कहते हैं: “भगवान् किस बुद्धियोग से\nयदि जुड़ना संभव हो तो ऐसा विचार करने वाले मन को श्रद्धापूर्वक विचार करना चाहिए\nमैं तुम्हें बुद्धि, निश्चित ज्ञान दूँगा। प्रेम से भगवान को समर्पित कर दिया\nजब प्रभु की सेवा की जाती है तो प्रभु स्वयं ही प्रभु से जुड़ने का मार्ग दिखाते हैं।\n\nतेषामेवेनुकम्पार्थमहमज्जनजं तमः।\n\nनाशयमात्मभावस्थो ज्ञानदीपेन भास्वत",
  "10.18": "वस्त्रेण आत्मानः योगं विभूतिम च जनार्दन।\nभूयः कथय त्रिष्ठिः हि सृन्वतः न अस्ति मेइ अमृतम्--हे जनार्दन, अपनी गहराइयों को भी फैलाओ।\nस्वरूपों का माहात्म्य और भी अधिक बताइये। मैं इस सुधा से पर्याप्त मात्रा में नहीं मिल सकता।\n\nअर्जुन ने कृष्ण से पूछा, \"मुझे अपनी विभूति के बारे में और बताओ।\" प्रभु का\nविभूति मुख्यतः चार प्रकार की होती है। (1) साक्षात विभूति: यहां भगवान हमारे लिए अपने अद्वितीय रूप में हैं\nपृथ्वी पर प्रकट होता है. उदाहरण के लिए: भगवान के अवतार. (2) जातीयता\nनिर्माता उदाहरण के लिए: चंद्रमा, सितारों का राजा। यहां चंद्र सितारों की जाति से नहीं बल्कि वह से संबंधित है\nसितारों का राजा. (3) स्वजाति की सृष्ट प्रभा। उदाहरणार्थ: देवताओं में इन्द्र, प्रकाश में सूर्य। (4)\nस्वजाति एकदेशीय सृष्ट प्रभा। उदाहरण के लिए: पांडवों में अर्जुन। इस प्रकार इन चार प्रकार से\nभगवान के विभूति रूप अनंत हैं। हम यहां हर चीज़ की पूजा नहीं कर सकते.\nइसके लिए अर्जुन उपासना उपयोगी है, \"अपनी भावनाओं को विस्तार से कहें\"\nवह कृष्ण से पूछता है।\n\nकृष्ण का संदेश सुनकर अर्जुन आनंद के सागर में तैर रहा है। वह कहता है: “मैं हूं\nमैं अमृत पी रहा हूं, मुझे नहीं लगता कि यहां काफी है. यह स्वास्थ्यप्रद है, कीवी",
  "10.6": "महर्षयः सप्त पूर्वे चत्वः मानवः तथा |\n\nमत भवः मनः जाः यशं लोकाय इमः प्रजाः -- प्रथम मन्वन्तर के सात\nमण्डी महर्षि (मरीचि, अत्रि, अंगिरस, पुलस्क्रु, पुलह, क्रतु और वशिष्ठ), पहले चार\nमनु [स्वायंभुव, स्वारोचिष, उत्तम और रैवत], चतुर्मुख के मानस पुत्र।\nवह नन्नी 0डेल हैं।\nजो देवता 'मनु' कहलाते हैं वे सब मेरे ही हैं; मेरी इच्छा से जन्म लो\nजो आया।] संसार के ये सभी लोग उसकी संतानें हैं।\n\nहम जानते हैं कि संपूर्ण ब्रह्मांड ईश्वर द्वारा बनाया गया था। यहाँ हम कृष्ण हैं\nउपासना में जानने योग्य मुख्य बिन्दु बताते हैं। प्रथम मन्वन्तर के पक्षधर\nऔर पहले चार मनुओं का उल्लेख यहाँ कृष्ण ने किया है। हर मन्वंतर के लिए अलग\nविशेषज्ञ हैं. यह पहला मन्वंतर है जो देव भेद में सोलहवीं कक्षा में आता है\nख़ुशीमण्डल में सप्तर्षि बहुत महान हैं। पुराण एवं महाभारत का मोक्षधर्म पर्व\nदेखा जाए तो यहां \"महर्षय: सप्त पूर्वे\" चतुर्मुख, निर्माता के लिए है\nसमझा जाता है कि इसका तात्पर्य सहायक सप्तब्रह्मा से भी है। [यहां सूक्ष्म रूप से भृगु तथा\nकुशल को शामिल किया जाना चाहिए। मनसा के दसवें पुत्र नारद ब्रह्मचारी थे। इसलिए सृजन\nविस्तार में उनका नाम शामिल नहीं... ये सात खुशियां और भृगु-दक्षारांश\nइन्हें प्रजापति कहा जाता है। उनके द्वारा भगवान चतुर्मुख की रचना करें\nसप्तर्षियों की रचना हुई। सृष्टि में सबसे पहले मनुष्य की वंशावली मनु से उत्पन्न हुई\nउन्हीं से मनु वंश का उदय हुआ। इस सब के कारण पहले चार\nमन्वंतर के स्वामी और सुपरर्षि मुख्य रूप से पूजे जाने वाले हैं।\nसंसार के ये सभी लोग उन्हीं की संतानें हैं।\n\n'मनु' का एक और अर्थ है. भगवान का गण भी 'मानुस'\nवे कहते हैं कि तत्त्वभिमानी देवताओं के चार मुख्य प्रकार हैं। ये मनुष्य के चार हैं\nदेवता जो प्रकृति को नियंत्रित करते हैं (ब्राह्मण, क्षात्र, वैश्य, शूद्र)। यह हम में से प्रत्येक में है\nप्रकृति चार हैं. हम वही हैं जो प्रकृति ने हममें बढ़ाया है। उस वर्ग से\nहम कॉल करेंगे. इसके अलावा \"मनु\" जीव के चार वर्ग हैं: देवताओं से सभी देवता\nख़ुशियों की विरासत से ख़ुशियाँ (इंसान), \"इंसान\" पैदा कीं, ये\nमनुष्य विरासत से. उपासना में यह ध्यान रखने योग्य बात है।\n\nएतम् विभूतिम योगम् च मम यो वव्वेत्रि तत्त्वतः |\n\nसोथविकल्ब्देन योगेन युज्यते नात्र संशयः",
  "10.19": "भगवान उवाच- भगवान बोले:\n\nअवस्था ते कथैष्यामि दिव्यः हि आत्मा विभूतयः |\n\nकुरुश्रेष्ठ की संपत्ति मुख्य रूप से मवेशियों और भेड़ों के सामने है, भाले! मेरा अलौकिक\nमुझे कुछ विभूति रूपों का चयन करने दीजिए। मेरी कास्टिंग का कोई अंत नहीं है.\n\nसंस्कृत में 'हंता' शब्द खुशी और विस्मय व्यक्त करने के लिए इस्तेमाल किया जाने वाला शब्द है। कृष्ण\nअर्जुन की रुचि देखकर वह उनकी 'भले' कहकर प्रशंसा करते हैं।\n\nआज वेदांत को कोई सुनना नहीं चाहता. \"हमारे पास समय नहीं है\" स्लिप\nमानसिक रूप से बढ़े हुए हैं, उन्हें 'नो टाइम' पसंद नहीं है\nढकने के लिए इस्तेमाल किया जाने वाला शब्द! अगर हमें यह पसंद है, तो समय होगा! यहां कृष्ण को अर्जुन की चिंता है\nवह सराहना करते हुए कहते हैं, ''मैं आपको वह जरूर बताऊंगा जो आप सुनना चाहते हैं.''\nभगवान की विभूति दिव्य एवं अनंत है। यह पूरा नहीं कहा जा सकता.\nयहां भगवान कृष्ण की विभूति का संक्षिप्त सारांश दिया गया है जिसकी हमें मुख्य रूप से पूजा करनी चाहिए\nकिया और कहा.\n\nयहाँ 'कुरुश्रेष्ठ' विशेषण का प्रयोग हुआ है। स्वयं भगवदुपासना के मार्ग पर\nइसमें शामिल अभ्यासकर्ता कौरव हैं। यह अध्यात्म के लिए आवश्यक न्यूनतम योग्यता है। “आप आध्यात्मिक हैं\nउपलब्धि में उच्च. आप इस उपलब्धि को लेकर चिंतित हैं. बेशक आपको करना चाहिए\nइस सम्बोधन के पीछे \"मैं आपको बताऊँ\" की भावना है।\n\nअहमात्मा गुडाकेश सर्वभूतशयस्थितः |\nअहमदिश्श्च मध्यमं च भूतानामंता एव च",
  "9.34": "मत मनः भव मत भक्तः मत याजी माम् नमस्कुरु |\nमम एव एश्यसि युक्त्वा एवं आत्मानं मत परायणः - मुझे दिखाओ। मुझे\n\nबहुत सारा प्यार। मेरी पूजा करो. मुझे झुकना। मेरे लिए रास्ता व्यवस्थित करो\nजब रोऊंगा तो अपने आप में शामिल हो जाऊंगा.\n\nहमें अपने जीवन में केवल एक ही चीज़ हासिल करने की ज़रूरत है वह है अपना मन ईश्वर पर केंद्रित रखना\nबस जाओ व्यापार जगत में हजारों विचार हमें नहीं बचा सकते।\nवे हमें वापस पतन की ओर ले जाते हैं। अत: उन सबको मन में छोड़ दो\nप्रभु का भर जाना चाहिए। सदैव प्रभु से प्रेम करो। तुम कितने काले हो?\nजितना आप ईश्वर से प्रेम करते हैं, उतना ही ईश्वर भी आपसे प्रेम करता है। श्री सूक्त में\n\"त्वान्मा भजस्व पद्माक्षी, येन सौख्यं लभाम्यहम्\" कहकर मैं आपकी पूजा करता हूं।\nमैं करूंगा, तुम मुझे भजन कराओ।'' यहां भजन का मतलब भक्ति से प्रेम करना है।\n\nआप जो भी पूजा करें, उसे अपने पूरे प्रेम से भगवान की पूजा होने दें\nप्रभु का दर्शन करें. तुम्हारा सारा नमस्कार प्रभु को नमस्कार हो। ऐसा करो\nअपना मन ईश्वर में लगाओ और अपना जीवन ईश्वर-सर्वोपरि बनाओ\nभगवान महान वस्तु हों, जीवन का सार हों, हर चीज़ के स्वामी हों, निरंतर विचार की वस्तु हों।\nआपके जीवन का प्रत्येक कार्य ईश्वर की आराधना हो। फिर \"तुम मेरे साथ जुड़ो\nकृष्ण कहते हैं. यहीं पर कृष्ण ने उस पूजा की व्याख्या की जो मोक्ष की ओर ले जाती है\nनवाँ अध्याय समाप्त हुआ।\n\nइति नवमो*ध्यायः\nनवाँ अध्याय समाप्त हो गया\n\nचिंता मत करो\n\nअध्याय दस\n\nउन्होंने अर्जुन को भगवान के स्वरूप के बारे में समझाया कि हमें ज्ञान के विज्ञान की पूजा करनी चाहिए\nकृष्ण, ज्ञान की प्यास को पहचानो जो उनमें खिल गई है, पूर्ण भक्ति - विशेषकर पूजा में।\nइस अध्याय में भगवान की विभूति को अपनाने के लिए अनुसन्धान\nसमझाता है.\n\nआमतौर पर गुरु द्वारा अनमोल ज्ञान आसानी से उजागर नहीं होता है। शिष्य गुरु में\nकहा जाता है कि ऐसे मामले को तभी सुलझाना चाहिए जब वह पूरी तरह से वफादार हो, जब उसमें योग्यता हो\nशास्त्र. इस प्रकार गुरु अपने शिष्य को बिना परखे कोई भी अनमोल बात नहीं बताते।\nइसका अच्छा उदाहरण प्रश्नोपनिषद में मिलता है। छह लोग पिप्पला के करीब आये\nवे महान विद्वानों के बारे में कहते हैं:\n\nभूया एव तपसा ब्रह्मचर्येण श्रद्धाया संवस्सारं संवत्श्रुतः;\nयथाकामन् प्रश्नं पाइछता; यदि विज्ञान्यमः सर्वं हाओ वक्ष्यम इति |2|\n\n\"एक वर्ष तक परिश्रमपूर्वक तपस्या और ब्रह्मचर्य में रहो। एक वर्ष के बाद।\"\nकोई भी प्रश्न पूछें जो आपको पसंद हो. अगर मुझे पता होगा तो मैं जवाब दूंगा।\" यहाँ गुरु और शिष्य हैं\nपारस्परिक परीक्षण सामने आता है। लेकिन जब गुरु ने अपने योग्य शिष्य में पूर्ण निष्ठा को पहचान लिया।\nवह ख़ुशी-ख़ुशी अपना ज्ञान उसे बता देता है, भले ही वह इस पर सवाल न उठाए। यह\nइस स्तर पर, कृष्ण ने अर्जुन में ऐसी पूर्ण भक्ति देखी।\n\nभगवान का वचन\nभूया एव महाबाहो श्रणु मेई परमान वाचः।\nयत् तेहं प्रियमानया वक्ष्यामि हितकाम्य 1।\n\nभगवान उवाच - भगवान ने कहा:\n\nभूयः एव महाबाहो श्रृणु मेइ परमं वाचः।\n\nयत् ते अहम प्रियमानया वक्ष्यामि हित कामया - हे महावीर, मेरी बात फिर से सुनो।\nहिरूनी, क्योंकि मैं यह तुमसे कह रहा हूं जो सुनकर प्रसन्न हैं।\n\nगुरु को ज्ञान देने में असंतोष शिष्य की प्रतिभा और गुणवत्ता के कारण होता है। यहाँ कृष्ण हैं\nवह कहता है: \"मैं तुम्हें और अधिक बताऊंगा।\" क्योंकि यहाँ जो कहा जा रहा है वह \"परमं वाचः\" है।\nकृष्ण कहते हैं. यहां 'परमाण' का मतलब सबसे बड़ी चीज है जिसे हमें जानना जरूरी है।\nयह सबसे बड़ा ज्ञान है जो पारलौकिकता की जागरूकता देता है। पूरी दुनिया को\nयह मददगार है. इससे बढ़कर कुछ नहीं है. “आप इस युद्ध भूमि में हैं\nआप खड़े होकर यह सुन रहे हैं और खुश हैं, वह खुशी आपके अंदर उमड़ रही है। उसके लिए, दुनिया\nमैं तुम्हारी भलाई के लिए तुम्हें बताऊंगा, सुनो, ”कृष्ण कहते हैं।\n\nनाम विदुः सुरगणः प्रभावं न महर्षयः।\nअहमदिर्हि देवानां महर्षिणं च सर्वशः ॥2॥\n\nनाम विदुः सुरा गणः प्रभावं न मह खुशायः |\n\nअहं अदिह ही देवानां मह खुपीनं च सर्वसः - मेरी गहराई: [मैं ही संसार हूं\nनिर्माण",
  "10.16": "स्वयम् एव आत्मान आत्मानं वेच त्वम् पुरूषोत्तम |\nभूतेश देवदेव जगत पते भूतभावना।\nवक्तुम अर्हसि अश्शेन दिव्यः हि आत्मविभूतयः |\nयाभिः विभूतिभिः लोकं इमान त्वं व्याप्य तिथिसि - हे पुरूषोत्तम, आप स्वयं हैं।\nमैं तुम्हें तुमसे जानता हूं. हे सभी प्राणियों के निर्माता, सभी प्राणियों के भगवान,\nदेवताओं के स्वामी, लोकों के स्वामी, आप किन रूपों से इन सभी लोकों की रचना करते हैं?\nआपके विभिन्न रूपों की भव्यता को छोड़े बिना, जो बहुत अलौकिक हैं\nआपको समझाना चाहिए.\n\nअर्जुन कहते हैं: “तुम्हारे गुणों को देवता भी नहीं माप सकते\nरास्ता तो तुम ही जानते हो. ये आपको खुद ही कहना होगा, किसी और से नहीं\nकह नहीं सकता. क्योंकि तुम मर्दाना हो. यहाँ पुरूषोत्तम एक विशेषण है\nइस्तेमाल किया गया। पुरूषोत्तम का अर्थ है जो क्षर (जीवन) से परे है। थान अक्षरा (रिश्ता)।\nबुजुर्ग \"तुम्हारे अलावा कोई अन्य सिद्धांत नहीं है सिवाय तुम्हारे जो अक्षरों से परे है। इसलिए, यह।\"\nअर्जुन ने भावना व्यक्त की कि इसका स्पष्टीकरण आपसे जानना चाहिए\nपता बताता है.\n\nयहां अर्जुन कृष्ण- भूतभावन, भूतेश, देवदेव तथा। जगत पाटे\nसंबोधित किया। भूतभावना का अर्थ है- पांच आयामी दुनिया, सभी जीवन का निर्माण करना-\nजो जाति की उत्पत्ति-स्थिति-विनाश के लिए उत्तरदायी है। भूतेश का अर्थ है - सबको नियंत्रित करने वाला\nनियमका स्वामी. देवदेव का अर्थ है - सभी देवताओं का भगवान; सूर्योदय के लिए\nमूल ज्योति जो प्रकाश देती है। जगत पति में 'पति' का अर्थ अभिभावक होता है। वह जो उत्पन्न करता है\nप्रभु, मारने वाला भी प्रभु है। वह जन्म और मृत्यु से रहित मोक्ष दाता भी है। वह सब कुछ है\nविश्व के संरक्षक. भगवान द्वारा हमें 'संसारबंध' देना उनके पालन-पोषण और शिक्षा का एक पहलू है\nइतना ही। सामान्य तौर पर, अर्जुन को लगता है कि \"आपके बिना हम नहीं हैं, आप हर चीज के रक्षक हैं\"।\nव्यक्त किया है\n\nकथं विद्यामहं योगिस्त्रं सदा परिचिंतयं।\n\nकेसुकेषु च भावेषु चिन्त्यो*सि भगवान मया",
  "10.4": "बुद्धिः ज्ञानं असम्मोः क्षमा सत्यं दमः शमः।\n\nसुखं दुःखं भवः अभवः भयं च अभयं एव च -- बुद्धिमता, जागरूकता,\nबुराई करने की इच्छा न करना, गलत काम करने वालों पर भी क्रोध न करना, साहस, इन्द्रियों पर संयम,\nईश्वर में निष्ठा, सुख-दुःख, जन्म-मृत्यु, भय-क्रोध ये सब मुझसे ही हैं।\nउठना।\n\nयहां कृष्ण एक महत्वपूर्ण बात बताते हैं कि हमें भगवान की पूजा करते समय जागरूक रहना चाहिए।\nवह प्रभु ही है जो हमें बुद्धि, ज्ञान, अविश्वास, क्षमा, सत्यम्, दमः-शमः प्रदान करता है।\nकुछ लोगों को यह भ्रम होता है कि वे बहुत बुद्धिमान हैं। लेकिन वह उस बुद्धि पर दयालु है\nवे परमेश्वर की सच्चाई को नहीं जानते। कृष्ण कहते हैं: “वह जो तुम्हें ज्ञान देता है\nमैं ज्ञान का दाता हूँ. यहां 'ज्ञान' का अर्थ किसी चीज़ के प्रति जागरूकता से है। \"बुद्धि\" का अर्थ है\nक्या करें और क्या न करें का ज्ञान। जब हमारे पास बुद्धि और ज्ञान दोनों हैं\nकेवल यह पूर्ण है. यदि ज्ञान रहेगा और बुद्धि नहीं रहेगी तो वेद हमसे दूर हो जायेंगे। “अचरा हीनम की।”\nपुनन्ति वेदः''-यदि कोई व्यक्ति अनैतिक है, तो सभी वेद उसे त्याग देंगे। पंख\nवेदविद्या उनके पास से वैसे ही उड़ गई जैसे युवा पक्षी अपने घोंसले से उड़ जाते हैं\nयह जानना कि भक्त होना चाहिए, ज्ञान है। लेकिन जो रीति है वही है\nविवेक चेतना-बुद्धि जो अधर्म है। निस्संदेह बुद्धि-ज्ञान के साथ सत्य भी\nजानने की क्षमता 'असम्मोह' है। ये तीन मुख्य चीजें हैं जो हमें जीवन में मदद करती हैं\nखंभे. हमें यह जानना चाहिए और उस प्रभु की आराधना करनी चाहिए।\n\nचौथा गुण है \"क्षमा\"। यह सबसे बड़ा गुण है. यदि कोई हमारी आलोचना करता है - उस आलोचना में\nयदि आत्मसुधार का तत्व है तो सुधार।  अन्यथा यह सिर्फ ईर्ष्या है\nआलोचना के मामले में, बिना किसी प्रतिशोध के मामले को वहीं छोड़ देना \"माफी\" है।\n\nपाँचवाँ गुण 'सत्यम्' है। सत्यम का अर्थ है ईमानदारी। आज हम सज्जनता और सज्जनता को भूल जाते हैं\nनकाब में रहना. बेईमानी हमारे जीवन में व्याप्त हो गई है।\nईमानदारी के बिना संस्कृति की कोई भी संपत्ति किसी काम की नहीं है। एक व्यक्ति विपरीत है और\nपलट कर बात करना बेईमानी है. अगर हमें किसी दूसरे व्यक्ति का विचार पसंद नहीं आता\nया तो उन्हें सीधे बताएं या उनसे दूर रहें. हमारे अंदर ईमानदारी\n\nजब तक हम विकसित नहीं हो जाते, कोई भी विज्ञान हमें नहीं बचा सकता।\nहमें प्रभु से प्रार्थना करनी चाहिए कि वह हमें ऐसी ईमानदारी दे।\nछठा है दमाह. इसका संबंध इंद्रियों से है. हमारी इंद्रियाँ वैसी ही हैं जैसी हम कहते हैं\nनहीं पूछता वे हमें अवांछित दिशाओं में खींचते हैं। जो नहीं देखना चाहिए उसे देखकर,\nहम वह खेलते हैं जो नहीं खेलना चाहिए. ऐसा संयम दमः है। इंद्रिय दमन के लिए\nईश्वर के प्रति समर्पण ही एकमात्र रास्ता है।\n\nसातवां गुण है शमः। हमारा मन शांत है (10 06 8 01551011 51916) शमाः। आज\nहम सब अशांति में जी रहे हैं (7685101)! इसका मूल कारण हम स्वयं हैं\nमन को सांसारिक विषयों पर केन्द्रित रखना। सांसारिक विचार, मन को छोड़ दो\nजब भगवान की ओर निर्देशित किया जाता है, तो मन सहज हो जाता है। यदि जीवन में कोई समस्या है, तो \"ईश्वर है, वह है।\"\nजिस व्यक्ति को यह दृढ़ विश्वास है कि वह हार नहीं मानेगा वही इस स्थिति को प्राप्त कर सकता है। सामूहिक रूप से 'हमारी आंतरिक दुनिया\nहमें इस ज्ञान से पूजा करनी चाहिए कि सब कुछ भगवान ही है'- ऐसा यहां कहा गया है\nमूल संदेश.\n\nकृष्ण आगे कहते हैं: “सुख-दुख, जन्म-मृत्यु, भय-क्रोध, ये सभी प्रकार की चीजें।\nरास्ते मेरे कारण बनते हैं। सुख और दुःख द्वैत हैं। जीवन में दोनों\nएक साथ हैं और एक के बाद एक आते हैं. किसी की ख़ुशी दुःखी नहीं होती,\nदु:ख के बिना सुख नहीं है। यह हमारे जीवन में दिन और रात की तरह है। इस तथ्य को जानकर\nदुःख बुरा नहीं है. हमारे जीवन में उतार-चढ़ाव सामान्य बात है। जन्म और मृत्यु\nप्राकृतिक. यदि हमारे पास ज्ञान है तो भय है, यदि भय नहीं है। ये सभी भगवान के अधीन हैं।\n\nइस श्लोक में मनुष्य के मन में जो-जो भावनाएँ उत्पन्न होती हैं, उन सभी भावनाओं का वर्णन किया गया है\nकृष्ण ने हर चीज़ के पीछे भगवद शक्ति के बारे में बताया - परिवर्तन और प्रभाव। अगला\nश्लोक में, कृष्ण सात मानसिक गुणों का वर्णन करते हैं जिन्हें हमें अवश्य प्राप्त करना चाहिए।\n\nअहिंसा समता तुप्पिस्टपो दानं यशो$यशः |\nभवन्ति भव भूतानाम एवं एव पृथग विधाः",
  "10.20": "अहं आत्मा गुडाकेश सर्वभूत आशायस्थितः |\n\nअहं अदीह च मध्यम च भूतानाम अन्तः एव च-हे गुडाकेश, सभी गुणों का निवास।\nमैं वह वासी हूं जो सभी प्राणियों के हृदय में निवास करता हूं। मैं ही समस्त प्राणियों का मूल, केंद्र और मूल हूं\nअंत\n\nविभूति (6556709) का कुल सार यह है: भगवान सबमें व्याप्त हैं। कृष्ण\nकहते हैं: \"मैं हर प्राणी के भीतर आत्मा के रूप में भरा हुआ हूं। मैं सभी जीवित प्राणियों की आत्मा हूं।\"\nवह है। कुछ लोग ग़लत कहते हैं कि इस श्लोक में ''जीवात्मा-परमात्मा एक ही है''।\nलेकिन कृष्ण ने यहां जो कहा वह यह है कि 'मैं जीवित आत्मा की आत्मा से भरा हुआ हूं'\nपरन्तु 'मैं जीवात्मा हूँ' नहीं। यह प्रत्येक जीवित प्राणी में निहित है\nबिम्बारूपी का तात्पर्य भगवान से है। भगवान “सर्वशक्तिमान” हैं\nवह हृतकमाला हृदय की गुफ़ा में अन्तर्यामी बनकर खड़ी है। यह भगवान की बेटी है\nबड़ी विभूति. भगवान अनंत जीव के भीतर अनंत विभूति के रूप में प्रकट होते हैं। यह\nकारण के कारण हम प्रत्येक जीवन में प्रत्येक ऊर्जा विशेषता पाते हैं। सभी जीवित प्राणी-\nजन्म से पहले उनके भीतर एक नियंत्रक के रूप में खड़ा होना, उनकी रचना का कारण बनना, उन्हें\nविपत्ति के समय भी, हर स्थिति में, सबकी रक्षा करें, रक्षा करें\nखड़े होने और बचाव करने की शक्ति.\n\nयहाँ गुडाकेश का प्रयोग विशेषण के रूप में किया गया है। यह भी एक विभूति गमक है. 'गुडका' का अर्थ है\nनींद 'गुडाकेश' का अर्थ है नींद को जीतने वाला। अर्जुन के पास यह विशेष योग्यता थी। उसके लिए\nउन्हें इसी नाम से बुलाया जाता था. \"आप नींद पर विजय पाने की शक्ति से भरे हुए हैं\nइसी सम्बोधन में स्वर है \"मैं हूँ।\" इस अध्याय के अगले भाग में, कृष्ण अपना विशिष्ट स्वरूप हैं\nविभूति बताते हैं.",
  "9.16": "अहं क्रतुः अहं यज्ञः स्वधा अहं अहं वहहम्तम्।\n\nमंत्र अहं अहं एव अज्यम अहं अग्निः अहं हुतम - मुझसे यग। [मेरी कार्रवाई मेरी है\nमैं रूप के कारण \"क्रतु\" हूं। मेरे द्वारा यज्ञ की क्रिया |\nमेरे द्वारा [क्योंकि मैं स्वयं \"स्वधा\" द्वारा समर्थित हूं। मुझसे मनुष्यों का भोजन मिलता है\n'चिकित्सा' क्योंकि प्रोप. मंत्र मेरी ओर से [सलाहुदा द्वारा ज्ञात \"मंत्र। घी मेरी ओर से\n[\"अज्य\" क्योंकि वह सबसे बड़ा है। मेरे द्वारा आग. [स्वयं गतिहीन ब्रह्माण्ड को गति देकर\n“अग्नि. मुझ से होमदा हवमी (जैसा कि भक्त मुझे \"हुता\" कहते हैं)।\n\nशास्त्रकारों ने भगवान की आराधना के लिए तीन प्रतीक बताए हैं। वेद में वे तीन\nप्रतीकात्मक पूजा वह है जो हम हर जगह पाते हैं। वे आग प्रतिरोधी और वायु प्रतिरोधी हैं\nऔर आदिम. अग्निप्रतीक में भूस्त्र में भगवान की पूजा करें। अंतरिक्ष परत में आदित्य\nवायु के प्रतीक रूप में भगवान की मुख और अंतःकरण में पूजा। धरती पर\nमनुष्य आमतौर पर ज्ञान के मार्ग की तुलना में कर्म के मार्ग से अधिक जुड़ा होता है। ऐसे में\nज्ञान से अधिक जोर कर्म पर है। कुछ लोग सुबह से शाम तक पूजा करते हैं। लेकिन खुद\nउन्हें क्रियान्वयन की जानकारी नहीं है. ज्ञान अर्जन उसके लिए गौण है (5600768/))।\nयह मानवीय कमजोरी है. हम ज्ञान पर उतना जोर नहीं देते जितना अपनी विनम्रता पर! अज्ञात\nबाहरी कार्यान्वयन पर निर्भर रहने के बजाय पाठ प्रवचन से थोड़ा सा ज्ञान\nकमाई एक महान पूजा है जिसकी भगवान सराहना करते हैं।\n\nजो कर्म प्रधान हैं उनके लिए ईश्वर का कार्यान्वयन क्या होना चाहिए। यहां कृष्णा ने कहा\nसमझाया. कृष्ण कहते हैं: \"अहम् क्रतुः अहम् यज्ञ\"। प्रभु का\n*क्रतु' अग्नि की उपासना के लिए की जाने वाली प्रक्रिया है। यहाँ बलिदान से\nभगवान को प्रसाद चढ़ाते समय, हम यह कहकर प्रसाद चढ़ाते हैं: आज्ञा ये स्वाहा-अग्ना य इदम्ना।\nमामा प्रजापता स्वाहा प्रजापतय इदम् की माता हैं; इन्द्राय स्वाहा-इन्द्राय इदम् न\nमम सूर्याय स्वाहा - सूर्याय इदम् की माता; वयव इदम् के वयवे स्वाहा-मम;\nवरुणाय स्वाहा-वरुणाय इदं न मम, आदि। इस प्रकार भगवान को विभिन्न प्रतीकों में\nयज्ञ एक यज्ञ है. यहाँ कृष्ण कहते हैं \"मैं तुम्हारे कार्यों का नियंत्रक हूँ\"।\nहम जिस भी प्रतीक की पूजा करते हैं, वह उस देवता का अन्तर्यामी होता है\n\nप्रभु को. उदाहरण के लिए गणहोमा, चंडिकाहोमा, नवग्रहोमा आदि। हम यहाँ हैं\nऐसा कहा जाता है कि चाहे किसी भी देवता की बलि दी जाए, उस बलि का श्रेय भगवान को जाता है\nहमारे पास एक दृष्टिकोण होना चाहिए. यद्यपि भगवान ऊर्जा के कई रूपों में प्रकट होते हैं, फिर भी वे सर्वव्यापी हैं\nभगवान ही नियंता हैं. [ज्योतिषी हम पर आने वाली विपत्तियों को टालने के लिए भगवान के समान हैं\nऐसा कहा जाता है कि संबंधित शक्ति प्रतिका की पूजा की जाती है, लेकिन कई भगवानों की नहीं]। देवता का\nकेवल जब भीतर के भगवान से प्रेम किया जाता है, तो यह उस देवता और भगवान के साथ मिलन होता है।\nइसलिए, एक समय में एक दिन, एक ही देवता का प्रिय बनने के लिए कर्म नहीं करना चाहिए।\nहमारी पूजा सर्वव्यापी भगवान को समर्पित होनी चाहिए।\n\nहमारे शरीर के भीतर परोपकारी देवता हैं। सभी देवता बृहस्पति स्थित हैं। वे हैं\nभगवान का परिवार. वहाँ वह प्रभु है जो उन पर शासन करता है। ये कट्टर\nदेवताओं. ईश्वर अपनी कृपा से हमें सही रास्ते पर ले जाएं।'\nयज्ञ भगवान अन्तर्यामय की पूजा है।\n\nयदि हम नित्य पीठ में जो पूजा करते हैं वह भक्त देवताओं के लिए एक यज्ञ है,\nश्राद्ध- पितृसत्तात्मक देवताओं के लिए किया जाने वाला बलिदान। हममें से कई लोगों को ग़लतफ़हमी है. श्रद्धा\nजैसे 'जीवन पर शरीर का बलिदान होता है'। लेकिन ये सही नहीं है. श्रद्धा स्थूल शरीर को त्यागकर सूक्ष्म होती है\nयह शरीर में जीवन को नियंत्रित करने वाले 'पिता देवताओं' के साथ ऐसा करने जैसा है। विशेषकर दस\nसार्वभौमिक देवता (क्रतु, दक्ष, वसु, सत्य, काम, काल, धुरी, लोचन, पुरुरवा आर्द्रव); उनमें से\nपुरुरवा और आर्द्रावरदा पितृसत्ता (7071000) के शासन के तहत बनाये जाने वाले खाते हैं। अन्य देवताओं का\nगण दस (सौ पितरों में प्रमुख): यम, सोम, काव्यवाह (ये तीन)।\nपितृपति), सोमसद, अग्निशत्त, बहिरशद, सोमप, हविर्भुज, अज्यप,\nशुभकामनाएँ. यह जीवन की भूख को संतुष्ट करने के लिए नहीं है जिसे हम प्रत्यारोपित करते हैं। हमारे बुजुर्गों को स्वर्ग या\nनरक में जाना उनके कर्मों के कारण है न कि हमारे समर्पण के कारण। श्रद्धा\nऐसा करने का उद्देश्य यह है कि कुलपतियों के अधिकार में जीवन कुछ आकस्मिक है\n(086 01006685) प्रभाव के कारण बाधाओं का सामना कर सकता है। उस समय यह\nकर्मानुष्ठान जो समाप्त करता है वह उस सूक्ष्म शरीर में मौजूद नहीं है। उसके लिए ऐसा\nपितृ देवता जो उन्हें बाधाओं से बचाते हैं और आगे बढ़ने के लिए मदद मांगते हैं\nपूजा ही श्राद्ध है. कुल मिलाकर यह बुजुर्गों की मृत्यु के दिन की याद, उनके प्रति आभार और पितृ देवताओं का स्मरण है\nपूजा.\n\nकृष्ण कहते हैं: \"स्वधा अहम्\"। जैसा कि मंत्रों में कहा गया है, \"स्वाहा' तत्त्वभिमानी\nदेवताओं के लिए ''स्वधा'' पिता देवताओं के लिए है। श्राद्ध मेरे द्वारा पितृसत्तात्मक देवताओं के कारण होता है\nकृष्ण कहते हैं.\n\nपरोपकारी देवताओं और कुलपतियों के बाद मनुष्य। मनुष्य का मुख्य भोजन\n'चिकित्सा'. जो पौधा फल देता है और मर जाता है उसे संस्कृत में \"ओषधि\" कहा जाता है। उस पौधे का जन्म ही उसका है\nमृत्यु मनुष्य जो भी अनाज खाता है वह सभी औषधियाँ हैं। औषधि ऐसी औषधियों का समुदाय है। कृष्ण\nवह कहते हैं \"अहम् मदहोतम\"। हम जो दावासा अनाज खाते हैं वह भी वैश्वाना के रूप में धन्य है\nभीतर बैठे प्रभु को। जो औषधि देता है, उससे रोग दूर करता है, भूख मिटाता है\nभगवान रक्षक है.\n\nहम अलग-अलग मंत्रों से आहुति देते हैं। जैसा कि पहले मंत्र पता बताया गया है।\nयदि जो कुछ भी दिया गया है वह भगवान का है, तो अलग संबोधन क्यों? कृष्ण ने कहा: “अन्य\nमेरे लिए एक अलग पते पर! भगवान एक हैं लेकिन उनके रूप अनेक हैं। हम क्या हैं\nभले ही यह मंत्र द्वारा भेजा गया हो - यह पढ़े गए सभी मंत्रों से संबंधित है, शब्दशः।\nभगवान। भले ही अलग-अलग देवी प्रतीकों में अलग-अलग ऊर्जा रूपों की पूजा की जाती है\nप्रत्येक नाम स्वयं भगवान को भी संदर्भित करता है। भगवान हर चीज़ का सार है. इसके लिये\nनारियल इसका एक अच्छा उदाहरण है। जलती हुई आग की तरह, सिस्थ के साथ नारियल;\nभूसी के भीतर का अखरोट अग्नि की मध्यस्थ देवी अग्नि के समान है; खोल के अंदर नारियल की आग\nदेवता के भीतर भगवान की तरह. हमारे यहाँ हर चीज़ को नारियल या आग कहते हैं\nअसली नारियल के अंदर जैसा सार होता है, वैसी ही असली आग होती है\nअन्तर्यामी भगवान हैं. इस श्लोक में कृष्ण इसी को \"अहम् अग्निः\" कहते हैं।\n\nकृष्ण एक उदाहरण के रूप में उस महत्वपूर्ण चीज़ को लेते हैं जिसे हम बलिदान के रूप में अर्पित करते हैं\nवह कहते हैं \"अहम् एव आज्यम्\"। अज्य का अर्थ है घी। आज्ञा में देवताओं को प्रसन्न करने के लिए अद्वितीय\nशक्ति है. कृष्ण मैं होमद हवि (अहम् हुतम्) हूं जो कहता है कि मैं आज्ञा में अद्वितीय शक्ति हूं।\nवह कहता है।\n\nहविस्सु का अर्थ है भगवान को अर्पित किया जाने वाला होम द्रव्य। उस इच्छा में एक विशेष शक्ति होती है\nप्रभु से. हमारा समर्पण कभी व्यर्थ नहीं जाता. अग्नि को अर्पित इच्छा अग्नि से बाहर है\nसमाज को सूर्य की किरणों से वातावरण में चमकते सातों रंगों से मुखातिब होना\nफल देता है. हविर्हरिः भगवान हैं जो हविर्भागा को स्वीकार करते हैं। “सर्व देव नमस्कारः\nकेशवं प्रतिगच्छति”। प्रभु सभी शब्दों से पढ़े जाते हैं। तो कैसा शोर\nभले ही वह उसका है. इस प्रकार इच्छा को स्वीकार करना और भक्तों के पापों का निवारण करना\nभगवान हविर्हरिः।\n\nइस श्लोक को दूसरे आयाम से देखें तो यहां आने वाला हर शब्द ईश्वर का है\nआप बहुलता देखेंगे.\n\nक्रतुः: क्रथु शब्द का मुख्य अर्थ भगवान है। 'क्रतु' - का अर्थ है क्रिया, ज्ञान आदि।\nक्रिया स्वरूपा, ज्ञान स्वरूपा भगवन्त क्रतुः। हमारे पास विश्वास है, इच्छा शक्ति है, क्रिया शक्ति है इत्यादि\nसुविधा देना, हमारे पीछे खड़े रहना, क्रियाएं करना, ज्ञान देना भी कर्म है\nप्रभु क्रतुः जो हमें जाल से बचाते हैं। यज्ञ: यज्ञ का अर्थ है सब कुछ\nजो सर्वज्ञ भगवान को जानता है, वह सभी कार्यों द्वारा पूजा किया जाना चाहिए\nयज्ञ का मध्यस्थ। स्वधाः का अर्थ है आत्म-संयमी सर्व-नियंत्रक। दवाइयाँ:\nभगवान \"औषधः\" का अर्थ उन लोगों के लिए सहारा-मुक्ति है जो संसार तप में गिरते और लड़खड़ाते (औषरू) हैं।\nमंत्रः भगवान 'मंत्रः' उन लोगों की रक्षा करते हैं जो जानबूझकर उनके पास आते हैं।\n[मंत्र हमारी रक्षा तभी करता है जब हम उसे जानते और जपते हैं। अन्यथा यह निष्फल ही है\nप्राप्त किया जा सकता है लेकिन वास्तविक महान फल नहीं]। संभवतः इसलिए ईश्वर सबसे महान चीज़ है\nवह “अज्यः” अग्निः है; वह भगवान जो अचल वस्तु “अग्निः” हुतः को गति देता है; सभी भक्तों द्वारा।\nआहुताना के रूप में, भगवान \"हुतः\" हैं।\n\nपिता*हमस्य जगतो माता धाता पितामहः |\nवेद्यं पवित्रमोन्कार खुक सव यजुरेव च",
  "10.27": "उच्छेश्रवसं अश्वनं विधि मम अमृत उद्भवम्।\n\nइरावतं गजेंद्रहं नाराणं च नाराधिपम्-घोड़े जो समुद्र में उठे\nउच्चेश्रवस्स की महिमा, बड़ों के बीच इरावत की, पुरुषों के स्वामी की (उन्नतकीर्ति)\nजो उच्चेश्रवस में है उसे 'उच्चेहश्रवस' कहा जाता है, इरा-लक्ष्मी को 'इरावत' उसका रक्षक कहा जाता है।\nवह जो इरावत में है, उसे \"नराधिप\" कहा जाता है क्योंकि वह सभी नरों का स्वामी है]\nजान लो कि मैं हूं\n\nअतीत में, घोड़ों और हाथियों का उपयोग राजाओं द्वारा सेना के महत्वपूर्ण भागों के रूप में किया जाता था। कृष्ण हैं\nश्लोक में उन्होंने घोड़ों, हाथियों और राजाओं के बीच अपनी विशेष विभूति का उल्लेख किया है। कृष्ण कहते हैं\n\"समुद्र मंथन में अमृत लेकर पैदा हुआ घोड़ा 'उच्चेश्रवसु' है और बड़ा घोड़ा 'इरावत' है।\n\nजान लो कि मैं हूं।'' ये दो जानवर बहुत ही खास जानवर हैं, घोड़ा और हाथी\nजानवर अपनी भक्ति के लिए जाने जाते हैं। ये उस धनवान के प्रति सदैव धोखेबाज होते हैं जो उन्हें प्रेम से रखता है\nअब तंत्रिकाओं में सबसे महान, \"नराधिप\" नहीं रहा। मानव जाति के लिए एक नेता के रूप में खड़े रहें और पवित्र बनें\nजनता की परवाह करने वाले नेताओं में ईश्वर की विशेष उपस्थिति होती है। पहले राज्यभारत के रूप में कार्यरत थे\nयहां हम धर्मराज, परीक्षित आदि राजाओं को याद कर सकते हैं।\n\nभगवान के विभूतिनाम उच्चेश्रवसु, ऐरावत: और नारदीपः यहां आते हैं। \"श्रवसु\" का अर्थ है\nप्रसिद्धि, ज्ञान, कर्म. सर्वज्ञ, सर्वज्ञ भगवान की यह सृष्टि-अवस्था-\n\"उच्चेश्रवसु\" जो सदैव संहार नामक महान कार्य करता रहता है। ऐरा का अर्थ भूदेवी में होता है\nलक्ष्मी निकट है. ऐसी लक्ष्मी के पति भगवान \"ऐरावतः\" हैं। नारा, सर्वा को\nप्राणियों के स्वामी के रूप में, राजाओं के बीच विद्यमान भगवान \"नाराधिपः\" हैं।\n\nआयुधानमहं वज्रं धेनुनामस्मि कामधुक् |\n\nप्रजानाश्चास्मि कंदर्पः सर्पानामस्मि वासुकिः",
  "10.5": "अहिंसा समता तुप्पिः तपः (ए) दानं यशः अयः।\nभवन्ति भवः भूतानां मथथ एव पृथक विधः - अहिंसा, समता, संतोष, तपस्या,\n(अ)दान, (बुरा) नाम - ये सभी प्रकार की बातें मुझसे उत्पन्न होती हैं।\n\nकृष्ण कहते हैं: \"अहिंसा, समता, संतोष, तपस्या, (अ)दान, नाम, बदनामी\" मुझसे हैं।\nवह है। यहां अहिंसा और समभाव बहुत खास हैं। क्योंकि कभी-कभी हिंसा\nअहिंसा बन जाती है और असमानता समानता बन जाती है। उसके लिए यह विशेष रूप से यहां है\nकृष्ण ने प्रस्ताव रखा.\n\nपहली अहिंसा : दूसरों को नुकसान पहुंचाए बिना रहना ही अहिंसा है। यहाँ अहिंसा का अर्थ है\nहमें न केवल शारीरिक रूप से, बल्कि मन और वाणी से भी अहिंसा प्राप्त करनी चाहिए।\nउदाहरण के लिए: एक को मौखिक रूप से, दूसरे को मानसिक रूप से बदनाम करना\nगाली देना या श्राप देना भी हिंसा है। कभी-कभी हिंसा अहिंसा बन जाती है।\nउदाहरण के लिए: एक नरभक्षी बाघ एक कस्बे में कई लोगों को मार डालता है\nयदि वह शेष रहे तो उसे मार डालना अहिंसा है\nकार्यों में पाया गया]। बड़ी हिंसा को रोकने के लिए छोटी हिंसा-अहिंसा। हम हैं\nहमें अपने शब्दों, कार्यों और विचारों से दूसरों को नुकसान पहुंचाए बिना कार्य करना चाहिए।\nदूसरा गुण है समभाव (समतः): यहां समदृष्टि का अर्थ है सभी को एक रूप में देखना।\nइसका मतलब यह नहीं है कि यह योग्यता की समता है। उदाहरण के लिए: स्कूल में अच्छे से पढ़ाई करें\nएक छात्र जिसने लिखा है और दूसरा छात्र जिसने पढ़ाई नहीं की है, उन्हें समान अंक मिलेंगे\nदेना समानता नहीं है. बिना किसी बैर के, शत्रु, मित्र, देशी, परदेशी\nबिना किसी भेदभाव के योग्यता के अनुसार अंकों का वितरण ही समानता है। कौन जानता है कैसे\nयदि आप उन्हें देखना चाहते हैं तो उन्हें वैसे ही देखें जैसे वे हैं। पिता को पिता, माँ को माँ,\nबृहस्पति के लक्ष्य के रूप में. इस प्रकार जो समान हैं उनका सम्मान करना समानता है।\nतीसरा गुण है संतोष: असंतोष ही मनुष्य के सभी दुखों का मूल कारण है। आज के समाज में हम\nभले ही हमारे पास घर पर हमारी जरूरतों के लिए पर्याप्त सामान है, फिर भी मीडिया में जो विज्ञापन आते हैं\nमूर्खों के रूप में, या पड़ोसियों के प्रतिद्वंदियों के रूप में, हम सतत दुःख में रहते हैं। काम\nअगर काम की इच्छा नहीं है तो वेतन कितना भी हो, दुख रहता है। जो नहीं है उसके बारे में शिकायत मत करो,\nजो था उसमें आनन्दित होना (86 000716! 51 5121940 004 1219) वास्तविक संतुष्टि है।\nचौथा है तप: जिसके तीन प्रकार हैं: काया-वाचा-मनसा तपः। काया का अर्थ है शरीर।\nशरीर के माध्यम से प्रायश्चित करने का तात्पर्य यह नहीं सुनना है कि शरीर क्या कहता है - भोजन या भोजन\nप्रकारान्तर से। जब भोजन नियंत्रित होता है तो मन नियंत्रित होता है। मन\nयदि नियंत्रित किया जाए तो शरीर स्थिर रह सकता है। इसके लिए विभिन्न नियंत्रण उपकरणों का उपयोग किया जाता है\nवृतानुष्ठान। कुल मिलाकर अहंकार बिना ईर्ष्या किये झुक सकेगा। शरीर का\nतपस्या से. अच्छा बोलना, सच्चा-स्वाभाविक रूप से; शास्त्रों का श्रवण-मन\n\nकरो, फिर आत्म-चर्चा के साथ इसका अभ्यास करो और इसे पचाकर दूसरों को इसका उपदेश करो।\nअगली पीढ़ी को देना वाचा-तपः है। सदैव मानसिक रूप से गहराई से सोचना मनसा-तपः है।\nपांचवां है (ए)दाना: दाना शब्द के संस्कृत में दो अर्थ होते हैं। एक दूसरे को \"दे\" रहा है\n\"काट दो'। यदि देने से हमारा पाप कट जाता है, तो वह दान है। हमारा नहीं।\"\nयदि पुण्य काट दिया जाए तो वह अदाना है।\n\nहमारे लिए किसी अनुपयोगी वस्तु को ले जाने के लिए दिया गया दान दान नहीं है। बहुत\nयदि आवश्यक वस्तु दूसरे के पास नहीं है लेकिन हमारे पास है तो जो हमारे पास है उसे उसके साथ साझा करें\nदेने का अभाव ही सच्चा दान है। एक व्यक्ति के पास एक समय के भोजन के लिए समय नहीं है\nयदि हमारे पास संघर्ष करते समय दो वक्त के भोजन के लिए पर्याप्त अनाज है, तो हमारे कल के बारे में\nबिना सोचे समझे उस व्यक्ति को अनाज का एक दाना दान करना ही सच्चा दान है।\n\nदान में आसन-वासना-अन्न किसी को भी दान किया जा सकता है। रहने का स्थान,\nपहनने को कपड़े, भूखों को खाना। इसे देने के लिए फिट या अनफिट होने का कोई बंधन नहीं है.\nलेकिन अन्य वस्तुएं दान करते समय यह देखें कि किसके लिए क्या आवश्यक और योग्य है\nदान करें। प्रचार के लिए दान - अदाना. बिना किसी इच्छा के ईमानदारी से\nकर्तव्य के संदर्भ में, सही देश में, सही समय पर, सही व्यक्ति के प्रति\nदान ही वास्तविक दान है।\n\nअंत में कृष्ण यहां यशः-अयः कहते हैं। ये बहुत अजीब है. एक बुरा\nअच्छा होने से सफलता अर्जित की जा सकती है। जीवन भर अच्छे कर्म करो\nअवांछित अपवाद सुनने से विपत्ति आ सकती है। यही हमारे जीवन का निष्कर्ष है\nइस कदम पर। तो इस बारे में चिंता मत करो. अपवाद होने पर क्या होना चाहिए\nकृष्ण ने हमें अपने जीवन में यह दिखाया है। कृष्ण ने शमंतक मणि की चोरी की\nइसका अच्छा उदाहरण कृष्ण के अपवाद आने पर कृष्ण का व्यवहार है।\n\nइस प्रकार, कृष्ण कहते हैं, \"ये सभी भावनाएँ मेरे कारण अस्तित्व में आती हैं।\" किसको क्या\nयह प्रभु का निर्णय है कि समय पर कौन सा भाव आना चाहिए। हमारी मन:स्थितियों में से एक\nगति भगवान के अधीन है. यह वह बुनियादी बात है जिसे हमें अपनी पूजा में जानना आवश्यक है\nसत्य यह कृष्ण द्वारा दी गई मानसिक पूजा का अद्भुत चित्रण है।\n\nमहर्षयः सप्त पूर्वे चत्वारो मानवस्तथः।\n\nमद्भव मनसा जाता येषाम् लोक इमः प्रजाः",
  "10.29": "अनंतः च अस्मि नागानं वरुणः यदसं अहम् |\n\nपित्यानं अर्यमा च अस्मि यमः संयमतम् अहम् - शेष नाग मैं हूँ।\n[मैं विलुप्त होने के कारण \"अनंत\" सी शेष में हूं।] वरुण, जल निकायों के स्वामी ([वरहिरिददा,\nना-आनंदस्वरूप को \"वरुण\" कहा जाता है और वरुण में ही जलीय जीव हैं]\nमैं अर्यमा हूं, मैं पितृ देवताओं में से हूं। [आर्य-ज्ञाता और म: ज्ञाता\nअत: मैं 'आर्यमन' हूं, मैं आदित्य आर्यमन में पितृपुरुष हूं।] दण्ड देने वालों में\n\nयम[ का अर्थ है ``यम'', यम में वह पापियों को दंड देता है\nजिम्मेदार] मैं हूं।\n\nसाँपों की प्रजातियों में सिर वाला 'नागर' होता है। बलराम के रूप में, नागर में सबसे महान \"शेष\",\nलक्ष्मण के रूप में, बहुत महान देवता शक्ति शेष जो हमेशा भगवान की शय्या पर रहते हैं। शेष पृथ्वी\n(ए/31/) परिसंचरण जो आकर्षण बल है। इस प्रकार यह कहा जाता है कि वह शेष पृथ्वी को धारण कर रहा है। जैसे कि\nप्रभु विश्राम में विशेष रूप से विद्यमान हैं। सिर वाले सभी साँपों के लिए स्रोत शक्ति के रूप में\nअवशेषों का स्वामी, अवशेषों से भरा हुआ, जो कभी नष्ट नहीं होता, \"अनंत:\" है।\n\nकृष्ण कहते हैं, \"जलीय जानवरों में, मैं वरुण हूं,\" पानी के घेरे में बहुत से हैं।\nभगवान ने वरुण को एक विशेष विभूति के रूप में भर दिया जो जलीय जानवरों को जीवन देता है। यहाँ\nआने वाले भगवान का विभूतिनाम वरुण है। इसके व्यापक आनंद स्वरूप के कारण इसे 'वरुण' कहा जाता है\nवरुण में जलचरों का स्वामी 'वरुण' भगवान हैं।\n\nदेवता शक्ति-पितृदेवता जो पृथ्वी से अपने शरीर का त्याग करने वाले जीवों को नियंत्रित करते हैं।\nउनमें से, द्वादशादित्यों में से एक, अर्यमा में भगवान एक विशेष शक्ति बन गए, उनके नेता\nखड़ा है. इसलिए ज्ञाता (आर्य) और ज्ञेय (मा) को 'आर्यमन' कहा जाता है,\nमैं कुलपिता आदित्य आर्यमन में हूं,'' कृष्ण कहते हैं।\n\nयम पापमय जीवन के नियंत्रक हैं। यम के भीतर भगवान की विशेष उपस्थिति है।\nयम पर शासन करने वाले भगवान \"यमः\" हैं। योग शास्त्र में यम शब्द अद्वितीय है\nके अर्थ में प्रयुक्त होता है। यह हमें पांच नियम बताता है जो हमें नहीं करना चाहिए। (1) हिंसा, (2) झूठ बोलना\nबताना, (3) चोरी करना, (4) अत्यधिक वासना और (5) दूसरे के सामने हाथ फैलाना।\nयह भगवान यम ही थे जिन्होंने भगवान की पूजा के मार्ग में पालन किए जाने वाले ये पांच नियम दिए।\nभगवान यम जो पूरी दुनिया को नियंत्रित करते हैं और यमधर्म को भी नियंत्रित करते हैं।\n\nप्रह्लादश्चास्मि दैतानं कालः कलैतमहम् |\nमृगाणां च मृगेन्द्रो$हं वैनतेयश्च पक्षिनम्",
  "10.32": "सर्गहं अदि अंतः च मध्यम च एव अहम् अर्जुन |\n\nअध्यात्मविद्या विद्यानं वदः प्रवादतम् अहम्।- हे अर्जुन, प्राणियों के जन्म और मृत्यु के लिए,\nमैं होने का कारण हूं. मैं जागरूकों में आध्यात्मिक जागरूकता हूं। [\"आध्यात्मिक\" जीवन के स्वामी के रूप में\nएन्निसी, मैं आध्यात्मिक विज्ञान में हूं जिसे 'विद्या' कहा जाता है क्योंकि यह ज्ञान है।] चर्चाकर्ताओं की चर्चा में।\nमैं एक तर्क हूं [सैद्धांतिक ज्ञान के लिए संचालित]। [सभी संज्ञाओं से \"वड़ा\" पढ़ें।\nबहस की।]\n\nसंसार की प्रत्येक वस्तु में भगवान की विभूति छिपी हुई है। जाहिरा तौर पर हमारे लिए\nयहाँ तक कि एक बेकार दिखने वाली चीज़ में भी एक अनोखा गुण होता है जो दूसरी चीज़ में नहीं पाया जाता (K016509\n063॥/) छिपा हुआ है. तो घास के एक तिनके से लेकर चार मुख वाले ब्राह्मण तक सब कुछ\nप्रभु की विभूति. यहाँ कृष्ण ने केवल उस समूह की विशिष्टता का उल्लेख किया है। जीवन का जन्म होता है\nवह प्रभु वही है जो पहले था, वही है जिसने जीवन के अस्तित्व का कारण बना, वही है जो अंत में संहारक के रूप में खड़ा होता है। इस प्रकार\nकृष्ण कहते हैं, \"मैं जन्म में हूं, अस्तित्व में हूं और मुझमें हूं।\" “यह मामला-ज्ञान\nकृष्ण ने यहां पार्थ को 'अर्जुन' कहा है, ऐसा करने, सात्विक बनने के अर्थ में, आप जानते हैं।\nविशेष रूप से सम्बोधित किया गया।\n\nकृष्ण कहते हैं, \"मैं चेतनाओं के बीच आध्यात्मिक चेतना हूं।\" एक आध्यात्मिकता जो भगवान को छूती है\nईश्वर ज्ञान से परिपूर्ण है। भगवान अधिक-आत्मा (अध्यात्म) जो सभी आत्माओं में विद्यमान हैं।\nआध्यात्मिक ज्ञान प्राप्त करने के लिए हमें दूसरों के साथ बातचीत करनी चाहिए। ये हमारा है\nसमझ बढ़ाने के लिए, ज्ञान की प्यास जगाने के लिए क्लासिक्स\nऐसी चर्चा में, \"वादः\" ईश्वर का वचन है, जिसे सभी नामों से पढ़ा जाता है\nभगवान वदाः।\n\nअक्षराणामकारोस्की द्वन्द्वः समासिकास्य च।\n\nअहमेवक्षायः कालो धाता$हं विश्वतोमुखः",
  "10.28": "आयुधानं अहं वज्रं धेनुं अस्मि कामधुक् |\n\nप्रजानाः च अस्मि कंदर्पः सर्पानाम् अस्मि वासुकिः - मैं हथियारों में हीरा हथियार हूं।\n[मैं वज्रायुध में ``वज्र'' के रूप में हूं क्योंकि मैं अरिवर्जिता हूं।] मैं गायों में कामधेनु हूं।\n[कामधुक को धुक से *कामधुक' कहा जाता है - इच्छा के लिए आह्वान करना। मैं कामधेनु में हूं।]\nकामदेव जो संतान उत्पन्न करते हैं [काम-सुख, दारा-कई प्रकार, पा-उन्ना \"कंदर्पा\" से\nएन्निसी कामदेव में है जिसके पास जन्म ऐंठन की शक्ति है] I. मैं सांपों से नहाया हुआ हूं।\n[वसु-सर्वत्र निवास करो, की-प्रसन्न होकर मैं वासुकि में 'वासुकि' हूं।]\n\nअस्त्र-शस्त्रों में सबसे बड़ा अस्त्र भगवान द्वारा धारण किया गया सुदर्शन है। भगवान के हथियार को छोड़कर\nसबसे बड़ा हथियार हीरा हथियार है. कृष्ण कहते हैं, \"मैं हथियारों में हीरा हथियार हूं\"। यह\nवज्रायुध इंद्र का हथियार है। भगवान ने इसे तीनों लोकों पर नियंत्रण करने की शक्ति दी।\nदधीचि नामक ऋषि ने व्रत्र को मारने के लिए भगवान के आदेशानुसार तपस्या की।\nफल को अभिमंत्रित करके बनाया गया हथियार हीरा हथियार है। बारिश होने पर दिखाई देती है बिजली-\nबिजली को वज्रायुध का प्रतीक कहा जाता है। इस हथियार में भगवान \"वज्र नमक\" के रूप में हैं\nआसन्न है. \"वर्जनात् इति वज्रः'। शत्रुनाश सर्व दोष।\nभगवान वज्र.\n\nअस्त्र के बारे में बताने वाले कृष्ण के सामने ही वशिष्ठ मुनि ने विश्वामित्र के सभी अस्त्र-शस्त्र नष्ट कर दिये।\nवह कामधेनु के बारे में बताते हैं. पशुओं में सबसे महान पशु गाय है। हमारे पूरे जीवन भर\nभगवान की अद्वितीय विभूति गाय जो हमें दूध पिलाती है और हमारा पोषण करती है। इसी कारण जब कृष्ण बालक थे\nगोपूजा का परिचय दिया गया। गाय का मल और मूत्र भी अपशिष्ट नहीं है। कुछ नहीं से\nठीक न होने वाला चर्म रोग गोमय तथा मृत्तिके (लाल मिट्टी) में स्नान करने से वह रोग ठीक हो जाता है\nघर के सामने गोबर रखने से कीड़े नहीं होंगे। गोमाया में\nवहां लक्ष्मी का वास होता है. ऐसा महाभारत की एक कहानी में कहा गया है. इस प्रकार\nगाय के अनेक उपयोग हैं. जैसा कि \"कामधुक\" का नाम है जो भगवान जो चाहता है वह देता है\nविभूति कामधेनु में खड़ी थी।\n\nइस संसार के प्राणियों में नर और मादा के बीच जन्मजात आक्षेप (5602! 69586) के रूप में कौन खड़ा है-\nकामदेव जो बच्चे पैदा करते हैं। इस कामदेव (कंदर्प) में भगवान की अद्वितीय शक्ति निहित है।\nसृष्टि में संतान उत्पन्न करने की घृणित इच्छा सभी के मन में पैदा करो\nभगवान बैठे हैं. इस कारण ईश्वर की कृपा के बिना कोई भी खेल नहीं सकता\nसत्ता से आगे नहीं आ सकते. इसे जबरदस्ती नहीं छोड़ा जा सकता. नमक के रूप में भगवान कंदर्पहा\nकामदेव से परिपूर्ण. उस इच्छा से मनुष्य को अनेक प्रकार की इच्छाएं देकर\nउन्हें संतुष्ट करके, भगवान 'कंदर्पाह' उन्हें अजीब आनंद की शय्या पर सुला देते हैं।\nकामदेव-मन्मथ के बाद, कृष्ण वासना के प्रतीक सर्प का वर्णन करते हैं। पेट\nरेंगने वाले सरीसृप को साँप कहा जाता है। वासुकी सभी सरीसृपों का राजा है।\nभगवान 'वासुकिह' नमक के रूप में खड़े हुए और वासुकि को यह पद दिया। भगवान के बिना कोई जगह नहीं है.\nसर्वव्यापी भगवान 'वासुकिः'\n\nअनन्तस्वसि नागनं वरुणो यदसमाहम् |\nपित्यनामार्यम चास्मि यमः संयमतमहम्",
  "10.34": "मृत्युः सर्व हरः च अहं उद्भवः च भिवैतम्।\n\nकीर्तिः श्रीः वाक् च नारीनम् स्मृतिः मेधा धृतः क्षमा - मृत्यु के सर्वभक्षी देवता।\n[मरने वाले के रूप में, \"मृत्यु के नाम\" के रूप में, यम का अनुचर मृत्यु के देवता में है।\nउसमें सब कुछ निगलने की शक्ति है] मैं हूं। मैं ही भविष्य का निर्माण करने वाला हूँ।\nमैं स्त्रियों में महिमा की देवी हूं;  मैं श्रीदेवी हूं; मैं वाग्देवी हूं. मैं स्मृति की देवी हूं;\nमैं सहनशक्ति की देवी हूं; शानू, धैर्य की देवी; मैं क्षमा देवी हूं.\nएन्निसी कीर्तिदेवी में है; मैं 'श्री' के रूप में श्रीदेवी में आश्रय के रूप में हूं; प्रवक्ता के रूप में \"चलना\"।\nवाग्देवी में हूँ; मैं स्मृति देवी में स्मृति के रूप में 'स्मृति' के रूप में हूं;  जागरूकता के स्वरूप के रूप में\n\n'ध्रुति'. एनीस. मैं धृतिदेवी में हूं; गलतियाँ. *क्षमा' एक क्षमाकर्ता के रूप में। एनीस\nमुझे खेद है.]\n\nहाँ, भगवान मृत्यु के देवता भी हैं जो प्रलय के दिन सब कुछ नष्ट कर देते हैं। जलप्रलय के बाद\nसृष्टि का पुनर्निर्माण भी वही करते हैं। अपनी विभूति को स्त्री रूप में बता रहे हैं\nकृष्ण यहां मुख्य रूप से लक्ष्मी, सरस्वती और भारती में अपनी विभूति का वर्णन करते हैं। वैभव,\nभाग्य, सुंदर वाणी, स्मृति, बुद्धि, दृढ़ संकल्प और धैर्य - ये संरक्षक देवता हैं\nमुख्य रूप से लक्ष्मी और सरस्वती। और भारतीय. उनमें भगवान एक स्त्री विभूति के रूप में हैं\nखड़ा है\n\nबृहत्सम तथा समनाम गायत्री छन्दसमाहम् |\nमसानं मार्गशीर्षो$*हमरुतुनं कुसुमाकरः",
  "10.22": "वेदानां साम वेदः अस्मि देवानां अस्मि वासवः |\n\nइंद्रियाणं मनः च अस्मि भूतानं अस्मि चेतना - वेदों में मैं सामवेद हूं।\n[साम- हर जगह समान है और वेद को \"सामवेद\" कहा जाता है क्योंकि यह ज्ञान का स्वरूप है\nमैं सामवेद में हूं।] मैं देवताओं में इंद्र हूं। [वासा- सभी आधारों में, जो मौजूद है-\nमैं देवेन्द्र में \"वासव'' के रूप में हूं।] मैं इंद्रियों में मन हूं।\nमैं एन्निसी के मन में हूं।] मैं प्राणियों की आत्मा हूं। [चेतस सभी प्राणियों की स्मृति की गांठ है,\nमैं: रिहाई के कारण मैं होश में हूं.]\n\nआकाश में - सूर्य, चंद्रमा, तारे, वायु - कृष्ण, जिन्होंने अपनी विभूति की बात की, यहाँ आकाश की विशेषता है\nवह उपचारात्मक ध्वनि के बारे में बताता है।  शब्द का विभूति-वेद। वेद में विष्टवेद-सामवेद।\nहालाँकि सभी वेद अद्वितीय हैं, प्रश्न यह है कि साम का विशेष रूप से उल्लेख क्यों किया गया है\nआप आ सकते हैं. वेदों में कोई भेदभाव नहीं है। परन्तु वैदिक भक्तों में भेदभाव है।\nप्राणदेव सामवेद के भक्त हैं।  शास्त्रकार कहते हैं कि सामगान ही सबसे श्रेष्ठ है\nजो मधुर गाता है वह प्राणदेव है। प्राणदेव का गीत 'समागण' भगवान को बहुत प्रिय है\nसामवेद की एक विशेषता \"नाद\" है।\nयह एक प्रयोग है कि इसमें जो भी स्वर भर दिया जाए, वह भगवान का नाम बन जाता है\nखुग्वेद और यजुर्वेद में मंत्रों और शब्दों के माध्यम से सामवेद भगवान\nयदि यह एक भजन है, तो सामवेद भगवान में ध्वनि के साथ ध्वनि का सामंजस्य स्थापित करने में अद्वितीय है।\nगुणधर्म (501651/आ0210) है। नाद के पीछे नाद से ईश्वर का दर्शन होता है\nनादोपासना.. क्योंकि मौजूदा वेद सामवेद है - विशेषकर भगवान साम में\nआसन्न है. अतः 'साम' भगवान का एक अव्यर्थ नाम है। सभी शब्द भगवद के लिए हैं\nयदि खुग्वेद यह दर्शाता है, तो न केवल ध्वनि बल्कि सभी ध्वनियाँ भगवान की बात करती हैं\nसामवेद यह दर्शाता है।\n\nभगवान 'समः' हैं और वे 'वेदः' हैं। यहां 'समः' का अर्थ सर्वत्र समान है।\n'वेदः' का अर्थ है ज्ञान स्वरूप। भगवान सामवेद को नाद के रूप में भरते हैं और उसे विभूति बनाते हैं\nकिया\n\nवेद के बाद वेदप्रतिपाद्य देवता। देवताओं में मुख्य रूप से तत्त्वभिमानी देवता हैं।\n\"वासव\" (इंद्र) मुख्य देवता हैं जो भगवान के आसन के रूप में इंद्रियों को नियंत्रित करते हैं।\n\nवह देवताओं में सबसे महान हैं। उसकी पाँच ज्ञानेन्द्रियाँ (आँख, कान, नाक,\nजीभ, त्वचा) और अधिकांश पाँच कर्मेन्द्रियाँ (हाथ, पैर, मुँह, गुदा, उपस्थ)।\nविशिष्ट हाथ (हसरया प्रशंसक देवता। अन्य सभी इंद्रियाँ अन्य जानवरों में भी मौजूद हैं। लेकिन\nकुसुरी कार्य, नृत्य, मूर्तिकला आदि भगवान के अद्भुत शिल्प केवल मनुष्यों के लिए हैं।\nमहाभारत में एक कहानी है जो हमारे हाथों की विशिष्टता के बारे में बताती है। एक बेरोजगार व्यक्ति\nतय करें कि विद्वान अपनी बेरोजगारी से तंग आकर आत्महत्या कर रहा है\nखड़े-खड़े एक लोमड़ी उससे कहती है: “हे भगवान, आपके पास काम करने के लिए दो हाथ हैं\nदिया है लेकिन जो खाना हमें मिलता है उसे खाने के लिए हमारे पास कोई हाथ नहीं है। पेट में बैठकर खून चूसते हैं\nमक्खी को भगाने के लिए कोई हाथ नहीं है. फिर भी हम जीते हैं. भले ही आपके पास इतने कीमती हाथ हों\nतुम मरने वाले नहीं हो - तुम बहुत मूर्ख हो। यह सुनकर विद्वान ने कहा.\nलौटकर आएँगे इस कहानी में हाथ का महत्व बताया गया है। काई का प्रशंसक\n\"वासव\" में भगवान निवास करते हैं, जो अन्य सभी भक्त देवताओं को नियंत्रित करते हैं\nऊर्जा से भरपूर. वैसे तो \"वासव\" नाम भगवान इंद्र में विभूति के रूप में भरा हुआ है\nइंद्र को \"वासव\" कहा जाता है।\n\nयहां भगवान का विभूतिनाम \"वसवः\" है। \"वसव' का अर्थ है वसुओं का समुदाय।\nवसुस का अर्थ है \"देवताओं का समुदाय\"। ब्रह्मांड-ब्रह्मांड में, पिंडदान में-\nभगवान वसावाह, तत्त्वभिमानी देवों के नियंत्रक हैं जो पिंडदान को नियंत्रित करते हैं। सब\nयहां तक कि आधारों में भी, भगवान अस्तित्व के रूप में “वासवः” हैं।\n\nबाह्य जगत के बाद कृष्ण हमारे आंतरिक जगत में अपनी विभूति का वर्णन करते हैं।\nमन ही मनुष्य के सभी कार्यों का कारण है। मन के बिना सब कुछ शून्य है. यह इंद्रियों का है\nगतिविधियों के लिए बुनियादी प्रेरणा. एक ऐसा माध्यम जिसके माध्यम से सभी बाहरी पदार्थ आंतरिक आत्मा को छूते हैं\n\"दिमाग\"। जो महसूस किया जाता है वह मन के माध्यम से सार्थक हो जाता है। जब हम धर्मग्रंथ पढ़ते हैं तो यह हमारे लिए एक विषय है\nचमकना मन से है. भगवान के मन के कारण के रूप में हमारे पास \"मनः\" शब्द है\nये शक्ति हमें बैठने से मिली है. मनुते इति मनः। वह जो ज्ञान का अवतार है, सभी\nज्ञाता, सर्वज्ञ, शब्द का स्वामी मानस है।\n\nमन के बाद, मन के माध्यम से जो आता है उसे समझने की शक्ति जागरूकता है (सी4/367252)।\nईश्वर हमारे भीतर है, ग्रहण करने वाली शक्ति के रूप में जो मन जो देखता है उसे ग्रहण कर लेता है\nबैठ जाओ इससे संसार को ग्रहण करने की शक्ति जागृत हो गई। संपूर्ण ब्रह्मांड के प्रति उसकी जागरूकता के साथ\nग्रहणशील, सर्वव्यापी आश्चर्य भगवान 'चेतना'। 'चेतस' का अर्थ है हमारा अवचेतन मन। हमारा\nप्रत्येक अनुभव हमारे अवचेतन में संग्रहीत होता है। मन हर चीज़ को समझने की शक्ति है\nकोट्टव 'चेतनः' नमक भगवान। यह भगवान की विभूति है।\n\nरुद्रानां शंकरस्वास्मि वित्तेशो यक्षरक्षासम् |\n\nवसूनां पावकाश्च स्मि मेरुः शिखरिणामहम्",
  "10.33": "अक्षराणां अकारः अस्मि द्वन्द्वः समासिकास्य च।\nअहं एव अक्षयः कलः धाता अहं विश्वतोमुखः - मैं अक्षरों में प्रथम अक्षर हूं। [\"ए\"\n'अकार' को 'अकार' कहा जाता है, जो अ-कार से पढ़ा जाता है।] समास के समूह में द्वैत।\n\nसमसा मैं हूं. [द्वंद्व को 'द्वैत' कहा जाता है क्योंकि इसके अंदर और बाहर दो रूप होते हैं\nमैं समसा में हूं।] मैं अविनाशी [समय में] भक्षक हूं। हर जगह सब कुछ भरा हुआ है\nमैं एक सलाहकार भी हूं.\n\nकृष्ण, जिन्होंने पहले ओंकार को शब्दों में उच्चारित किया था, यहाँ अपनी विभूति को अक्षरा में उच्चारित करते हुए कहते हैं:\nयथा \"अक्षरणमकारोस्मि\"। 'अ' भगवान के सभी गुणों का लक्षण है\nअक्षर A- का अर्थ है \"नहीं'। भगवान 'नहीं' है। इसका मतलब है कि वह कोई ऐसी चीज़ नहीं है जिसे हम जानते हैं। वह है\nदुनिया से विदेशी. ऐसा भगवान 'नहीं' है. यानी उसमें कोई दोष नहीं है. वह है\nसर्वशक्तिमान इस प्रकार सर्व-अद्वितीय, सर्व-निर्दोष, सर्व-गुण संपन्न भगवान -\nकरावाच्य का अर्थ है \"अकार से भरा हुआ\"।\n\nअक्षरा के बाद, समास के बारे में बोलते हुए, कृष्ण कहते हैं: \"द्वंद्वः समासिकास्य\"। हमारे लिए\nजैसा कि आप जानते हैं, किसी भी शब्द को एक शब्द होने के लिए दो शब्द (या एक शब्द और) होने चाहिए\nएक प्रत्यय होना चाहिए) अन्य सभी समास में एक शब्द, या दोनों शब्द (एकाधिक)।\nअपनी प्रधानता खो सकता है. लेकिन द्वैत समास में दोनों शब्द महत्वपूर्ण हैं।\nद्वंद्व के प्रमुख समास, द्वंद्व समास में भगवान द्वंद्व द्वंद्व से भरे हुए हैं।\nभगवान द्वन्द्वः हमारे अन्दर और बाहर दो रूपों से परिपूर्ण हैं।\n\nभगवान कालपुरुष जो सभी को नष्ट करते हैं, सभी की रक्षा करते हैं और उनका भरण-पोषण करते हैं\n'तत्व'. ऐसे भगवान विश्वतोमुख हैं। वह हर जगह है। उसके बिना कोई जगह नहीं है. वह अदृश्य है\nकोई छाती नहीं.\n\nमृत्युः सर्वहरश्चहामुद्ध वाश्च भिवैतम् |\nकीर्तिः श्रीर्वक च नारीणां स्मृतिर्मेध धृतः क्षमा",
  "10.31": "पवनः पावनम् अस्मि रामः अर्तभृतम् अहम्।\n\nरुषनम् मकर; च अस्मि स्रोतसम अस्मि जाह्न्वी - गतिमान वस्तुओं में वायु का शेष रहना\nमैं. [पंजगत्नु. देवताओं की पूजा, वनपसेव्य के कारण इसे 'पावना' भी कहा जाता है\nमैं हवा में हूं।] उन नायकों में से जो हथियारों से लड़ सकते हैं। मैं [खुशी से,\nअमा-अनंत और संसार का आनंद ले रहा हूं] मुझे राम के नाम से जाना जाता है।\nमैं मछलियों के बीच एक व्हेल हूं. [\"मकर\" कहा जाता है क्योंकि वह ज्ञान का दाता है\nमैं मकर में हूं।] मैं नदी में गंगा हूं। [उन लोगों के लिए जो जहत की अभिलाषाओं को त्याग देते हैं, एक रक्षक के रूप में,\nमैं गंगा में 'जाह्नवी' हूं।]\n\nकृष्ण आगे कहते हैं \"पवनः पवतमस्मि\"। 'पवन' शब्द का लोकप्रिय होना\nजिसका अर्थ है 'हवा' या वायुदेव। आकाश में चलने वाली शक्तियों में सबसे बड़ी विभूति \"वायु\" है।\nजीवन को नियंत्रित करने वाले वायु-देवताओं में भगवान पवन विशेष रूप से विद्यमान हैं। पावथे\n\nइति पावनः - का अर्थ है निरंतर गति। भगवान, जो सबके भीतर हैं,\n\nवह प्रत्येक वस्तु में अपने-अपने स्वरूप में स्थित है और निरंतर गति देता है। हमारे शरीर में उसकी गति\nरुकते ही हम 'लाश' बन जाते हैं. उपनिषद में भगवान को वनः कहा गया है। वह पा-वनः है;\nयहां 'पा' का मतलब 'रखरखाव' है। वह शक्ति जो हमें और सभी ब्रह्म देवों को पोषित करती है। वनह\nइसका अर्थ है कुछ ऐसी चीज़ जिसकी सभी द्वारा पूजा की जाए, जिसकी प्रेम से पूजा की जाए, जिसे सभी द्वारा पोषित किया जाए।\nहजारों योनियों में हजारों रूपों में निवास करने वाले, सदैव रहने वाले भगवान पवनः।\n\nउनके स्वरूप विभूति ने कहा, \"राम उन नायकों में से एक हैं जो हथियार पकड़ सकते हैं और लड़ सकते हैं।\"\nसमझाता है. कृष्ण... राम अवतार में वह भगवान के सभी अवतारों से बढ़कर हैं\nकोदण्डपाणि नामक अस्त्र का भरपूर प्रयोग करके शत्रु का दमन किया गया।\n\nराम को वि कहा जाता है। शास्त्र में नाम के कई अर्थ हैं। 'रा-अमह, मतलब\nवह जो असीम आनंदमय है और सभी को आनंद प्रदान करता है। ईश्वर का यह गुण\nरामावतार में यह स्पष्ट दिखता है। रामावतार में भगवान कहीं और नहीं हैं\nवह चोट पहुँचाने के लिए नहीं चला। कैकेयी पर जिसने उन्हें वन में भेज दिया\nसबके क्रोधित होने पर भी रामचन्द्र ने कभी बुरा शब्द नहीं कहा। इसके बजाय\nउन्होंने कहा, \"अगर मैंने तुम्हें ठेस पहुंचाई हो तो मुझे माफ कर दो\" और खुशी-खुशी जंगल की ओर चले गए।\nइस प्रकार, रामावतार एक अद्वितीय अवतार हैं जिन्होंने दूसरों की खुशी के लिए बलिदान दिया। रमी\nअरसा के भगवान सीतापति, इस अवतार में एक पुरुष और एक महिला के बीच वैवाहिक जीवन कैसा होना चाहिए,\nभाई-बहन का प्यार कैसा हो, माता-पिता और बच्चों का रिश्ता कैसा हो\nउन्होंने दिखाया है. यह भगवान अमितानंद की विभूति है जिसने दुनिया को आनंद दिया।\nव्हेल पानी की सबसे शक्तिशाली और सबसे बड़ी मछली है। कृष्ण\nवह कहते हैं \"रुषाणं मकरश्चास्मि\"। यहां मकर का मतलब व्हेल है। स्वामी मकर;\nउन्होंने क्रिया के रूप में एक विशेष विभूति के रूप में व्हेल को वह शक्ति प्रदान की। ज्ञान\nदाता (कारा) भगवान मकरः।\n\nकृष्ण कहते हैं, \"मैं नदियों में गंगा हूं।\" सबसे बड़ी नदी गंगा है। इस नदी का जल तुलनीय औषधि है\nकोई दूसरा नहीं है. गंगा स्नान से हम अपने मन को शुद्ध कर सकते हैं। जो भी वहां हैं\nगंदगी हमारी है. गंगा वह जल है जो संग्रहित करने पर कभी खराब नहीं होता। उन्होंने गंगा को यह महान शक्ति प्रदान की\nभगवान का विभूतिनाम \"'जाह्नवी'\" है। \"जाह्नु\" का अर्थ है छोड़ देना। क्षुद्र शारीरिक इच्छाएँ\nजो भगवान त्याग कर भगवान की राह पर चलते हैं उनकी रक्षा करने वाली भगवान \"जाह्नवी\" हैं।\nस्त्रीलिंग प्रतीकात्मक नाम. स्त्री के रूप में माता के समान उपदेश देने वाले प्रभु की पूजा करो\nजाह्न्वी भगवान का स्त्रीलिंग नाम है।\n\nसर्गनामादिरान्तश्च मध्यमं चैवाहमार्जुन |\nअध्यात्मविद्या विद्यानं वदः प्रवादात्महम्",
  "10.36": "देउथं छलयथं अस्मि तेजः तेजस्विनं अहम्।\n\nजयः अस्मि व्यवहारः अस्मि सत्त्वं सत्त्ववतं अहम् - मैं धोखेबाजों का जुआरी हूं।\n[मैं एक खिलाड़ी के रूप में जुआ खेल रहा हूं।] मैं नायकों का नायक हूं। [प्रकटीकरण के कारण\nमैं \"तेजस\" या पी बीरा में हूं।] विजय मैं हूं।\nश्रमिक मैं [मैं 'खेती' नामक पेशे में हूं क्योंकि यह ज्ञान है।] बुजुर्ग व्यक्ति\nगरिमा मैं हूँ.\n\nदेउता को कौरवों और पांडवों के बीच युद्ध का कारण माना जाता है। यह भ्रामक है\nसबसे बड़ी कला! भगवान एक 'देवदूत' के रूप में जुआ खेल रहे हैं। यहां भगवान का नाम 'द्युत' है। दिवु\nयानी खेल. जो भगवान सदैव सृष्टि के संहार की क्रीड़ा में लगे रहते हैं, उनका शब्द \"द्युत\" है।\nपराक्रमी की महिमा प्रभु है. भगवान जयः नमक के रूप में विजय में हैं। पूरी दुनिया में\nप्रभु विजय के प्रेरक हैं। जो किसी कार्य में उत्साहपूर्वक लगा रहता है\n\"व्यवसाय\" भगवान का नाम है. शक्ति के शासक के रूप में, वह बलवानों में \"सत्व\" का नाम है।\nबैठा है",
  "10.21": "आदित्यं अहं विष्णुः ज्योतिषम् रविः अंशुमान्।\n\nमरीचिः मरुथम अस्मि नक्षत्रनाम अहम् शशि-अदिति के बारह पुत्र [जहाँ भी\nसर्वव्यापक, सर्वव्यापी होने के कारण मैं विष्णुनामक[वामन] हूं। रोशन\nमैं रवि हूँ, शक्तियों में किरणों से चमकने वाला परम प्रकाश।\n\nमैं रावी नाम से हूं।] मारुतों की संतानों में से मरीचि प्रथम, [बाल-जल से भरपूर\nमैं सूजन और खुजली के कारण वेंटिलेशन के 'चमत्कार' में हूं।]\nचंद्रमा, नक्षत्रों का स्वामी [शा के सभी सुखों में से, शि चंद्रमा में ``शशि'' के सबसे शुभ रूप में है।\nमेरे पास उसके सितारे हैं।\n\nउनकी विभूति की बात करें तो सबसे पहले उनकी दैनिक पूजा में कृष्ण का बहुत महत्व है\nस्वरूपा विभूति से कहती है। अदिति (द्वादशादित्य) के बारह पुत्रों में से-\nविवस्वान (सूर्य), अर्यमा, पूषा, त्वष्टा, सविता, भग, धाता, विधाता, वरुण, मित्र, इंद्र,\nऔर वामन के रूप में विष्णु) एक भगवान का सच्चा अवतार हैं। वह वामन रूप में विष्णु हैं। इसलिए\nकृष्ण कहते हैं, \"मैं द्वैतों में विष्णु हूं\"। अब आदित्य का अर्थ है सभी देवता\nइसका मतलब है कि भगवान विष्णु सभी देवताओं में सर्वश्रेष्ठ हैं।\n\nइस अध्याय में आने वाला प्रत्येक नाम भगवान का विभूति नाम है। इसलिए\nप्रत्येक नाम के पीछे कई अर्थ छिपे होते हैं (60/1301001081 1368170)। इस श्लोक में\nपहले आने वाले भगवान का विभूति नाम \"विष्णुः\" है। विष्णु नाम का क्या अर्थ है?\nआइए एक संक्षिप्त नजर डालें: पुराण में, यदि आप भारत में बंदीतक्का के पौराणिक अर्थ को देखते हैं\nत्रिधातु से 'विष्णु शब्द' निष्ठान्न है। यह समझ में आ गया है. (1) दृश्य-क्षेत्र (2)\nविशति-प्रवेशे (3) वेति- प्रजानयति, गति, कांति, कदनेषु, गच्छति। इस तात्विक अर्थ में\nदेखा - विष्णु का अर्थ है सर्वव्यापी (वपु। वह हर चीज और हर चीज से बाहर है\nवह विष्णु है क्योंकि वह प्रवेश से परिपूर्ण है। इसे नारायण सूक्त में \"अन्तर बहिश्च तत\" के रूप में वर्णित किया गया है\n\"सर्वं व्याप्त नारायण स्थितः\"। अब \"वेति-विष्णुः\" नहीं... कौन-कौन\nजो शरण में आता है वह विष्णु-सर्वश्रयधाता भगवान है। 'वेति-प्रजानयति'-जो समग्र है\nवह विष्णु हैं जिन्होंने संसार की रचना की। वेति-गति'- सर्व-रक्षा करने वाला\nभगवान विष्णु 'वेति-कांति (इच्छा) - पूरी दुनिया की रक्षा और उद्धार करने का सच्चा दृढ़ संकल्प\nविष्णु मौजूद हैं. 'वेति-कादनेषु' - जो संपूर्ण जगत का नाश करता है, वह विष्णु है।\n'वेति-गच्छति' - वह जो तीन चरणों में त्रिविक्रम के रूप में तीनों लोकों में व्याप्त है।\nविष्णु. विष्णु का संपूर्ण अर्थ 'ईश्वर' है, जिसे हम विष्णु शब्द से प्राप्त करते हैं\nअनुसरण करने योग्य कुछ अर्थ। इसका उल्लेख महाभारत में एक जगह मिलता है\nनिर्वचन में कहा. यह निर्वचन कृष्ण ने भारत में अर्जुन से कहा था। कुल मिलाकर\n“सभी का आश्रय, सभी की उत्पत्ति-स्थिति-विनाश का कारण, सभी के अंदर और बाहर\nमैं पूर्ण विष्णु हूं, जिसने तीन कदमों में तीनों लोकों को नाप लिया है।”\nकृष्ण द्वारा विभूति का वर्णन |\n\nस्वरूप विभूति बोलने वाले कृष्ण बाद में विष्णु की पूजा के सबसे व्यापक प्रतीक बन गए\n'सूर्य' में उन्होंने अपनी विभूति का वर्णन किया है। हम विष्णु हैं जो गायत्री प्रतिपदा हैं\nहम धूप में पूजा करते हैं. यह सौर ऊर्जा में भगवान की पूजा है। यह प्रभु का है\nविभूति की दूसरी मंजिल. इसके लिए कृष्ण विष्णु के बाद 'रवि' का उल्लेख करते हैं। सूरज\nसबसे बड़ी ज्योति हम देख सकते हैं। सूर्य में नमक के रूप में 'रवि'\nसर्वव्यापी भगवान सौर ऊर्जा के रूप में ब्रह्मांड में व्याप्त हैं।\n\nयहां भगवान का विभूति नाम \"रविः\" है। वह रावी-राव-रवि के नाम से जाने जाते हैं। \"राव''\nइसका मतलब नाडा है. वह जो गायत्री \"रव\" द्वारा सूचित है, रविह की रोशनी को प्रकाश देता है\nप्रभु, गायत्री यथा प्रतिपद्य, सूर्य किरण में 'रवि' नमकः\nआसन्न है.\n\nअगली विभूति जो कृष्ण कहते हैं वह आकाश में वायुमंडल की एक अलग परत को विनियमित करने के बारे में है\nमरीचि मरुतों की संतान हैं। मूलतः मरुतों की संख्या उनचास है। उनमें से दस\nबहुत से हमारे पिंडदान नियम हैं। इन मरुतों का शासक\nग्रिप गैस इन उनचास मरुतों में मरीचि का नाम पुराणों में कहीं नहीं है\nनहीं आये अत: यह कहना कठिन है कि मरीचि इन उनचास मरुतों में से एक है। लेकिन\nइससे स्पष्ट है कि वह प्रभाववायु का पुत्र है। माधवाचार्य द्वारा ऐतरेय उपनिषद पर भाष्य और\nगीता-मरीचि के अर्थ को समन्वित करते हुए अठारहवीं कक्षा में भूत है।\nदेवी इसलिए, वह दिव्य पंखे (गणपति) के समकक्ष हैं। प्रभु\nजैसे मरीचिनामाका भूत वायु के प्रशंसक देवता के भीतर विभूति के रूप में खड़ा है।\n\nयहां भगवान का विभूति नाम 'मारीचि' है। लकड़ी का अर्थ है पानी. मारी का अर्थ है पानी\nपूर्ण बादल हवा में जो इस बीज को वहां ले जाता है जहां इसे भेजा जाना है\nभगवान उपस्थित होकर विभूति के रूप में विराजमान होकर वर्षा कराने की शक्ति प्रदान करते हैं\nमरीची”\n\nसूर्य में और आकाश में वायु में अपनी विभूति का उच्चारण करने वाले कृष्ण आगे के तारों के राजा हैं\nवह चंद्रमा में अपनी विभूति का वर्णन करता है। यह विजति का रचयिता है। सितारों के भगवान\nचंद्रमा सभी तारों की अधिष्ठात्री शक्ति के रूप में चंद्रमा में \"शशि\" शब्द भगवान के लिए बैठा है\nउन्होंने वह शक्ति दी.\n\nयहाँ भगवान का विभूति नाम \"शशिः\" है। जिसके पास शश है वह शशि है। 'श' का अर्थ है आनंद. शशा का मतलब है\nआनंद का आनंद—आनंद। आनंद मूर्ति जैसे आनंदमय भगवान\nचंद्रमा में बैठो. इस कारण चंद्रमा हमें सुख देता है।\n\nवेदानां सामवेदोसिरा देवानामसि वसावः।\n\nइन्द्रियानं मनश्चास्मि भूतानामस्मि चेतना",
  "10.24": "पुरोधसं च चुचम मम विद्धि पार्थ बृहस्पतिम्।\n\nसेनानिं अहं स्कंदः सारसं अस्मि सागरः - हे पार्थ, सबसे महान पुरोहित।\nमैं बृहस्पति हूं.\nमैं स्मंदा हूं.\nमैं जलाशयों में रहने वाली मछली हूं। [सा:सारा से, मैं 'सागर' नामक समुद्र में हूं।]\n\nकहने के बाद हम जिस भगवान की पूजा करते हैं उसका प्रतीक सबसे महत्वपूर्ण है\nयहाँ पुजारियों के बारे में क्या कहा गया है। कृष्ण कहते हैं, \"मेरी उपस्थिति पुजारियों के साथ है\"।\nजैसा कि खुग्वेद के प्रथम सूक्त में कहा गया है: \"अग्निमि\"ले पुरोहितं यज्ञस्य देवम्-खत्विजम्\" |\nहोता\"राम रत्न धतमन् |\"। यहाँ \"होटा\" खुग्वेद का पुजारी है, जो पहले यागा था\nवहाँ सोलह पुजारी थे। खुग्वेद के लिए: 'होता' प्रधान है और\nउनके तीन सहायक (मैत्रवरुण, अच्छवक, ग्रामस्तुथ) हैं। यजुर्वेद के लिए:\nअध्वर्यु प्रधान है और उसके तीन सहायक हैं (मंडिप्रतिप्रस्थुता, नेष्टा, उन्नेता)।\nसामवेद के लिए: उद्गाता प्रधान और उसके लिए तीन मंदीप्रस्थोता, प्रतिहर्ता, सुब्रह्मण्य)\n\nमददगार. इन सबके पर्यवेक्षक के रूप में यज्ञ में कोई कमी नहीं रहनी चाहिए\nपर्यवेक्षक सर्ववेद में पारंगत प्रधान पुजारी होते हैं। उनका नाम 'ब्रह्मा' है।\nउन्हें तीन लोगों (ब्राह्मणइच्छमसी, अग्नि येधरा, पोटा) द्वारा भी सहायता प्रदान की जाती है। इस प्रकार भगवान विशेष हैं\nउपस्थित सोलह पुरोहित यज्ञ करा रहे थे। पुजारियों की स्थिति\nसमाज में बहुत पुराना है. परंतु आज के पुरोहितों को समाज में वही दर्जा प्राप्त है जो पहले था\nकमाई नहीं. पुजारी हमसे पहले जानते हैं कि हमारे लिए क्या अच्छा है और उसी तरह हमारा मार्गदर्शन करते हैं\nजो चलने का मार्गदर्शन करता हो। ऐसे कार्य जो हमारे विकास को पूरक बनाएंगे\nगुरुस्थान में सलाहकार जो हमें विकास में मदद करने का ध्यान रखते हैं। संपूर्ण\nवे समाज के मार्गदर्शक हैं। पौरोहित्य एक बहुत ही ज़िम्मेदारी भरा काम है. एक धार्मिक\nयह पुजारी की जिम्मेदारी है कि जब पाठ्यक्रम में कोई संदेह हो तो वह समुदाय के लिए एक मार्गदर्शक के रूप में कार्य करे\nबहुत बड़ा. यदि मंत्र पढ़ते समय कुछ छूट जाता है या गलत हो जाता है तो इसके लिए पुजारी जिम्मेदार होता है\nकारण पौरोहित्य ऐसा ही एक उत्तरदायित्वपूर्ण कार्य है।  तो भगवान का विशेष है\nमौजूदगी तो है. पूरी पृथ्वी के दो महानतम पुजारी। बहुत बड़ा\nशुक्राचार्य, पुरोहित और बृहस्पतिाचार्य, देवताओं के पुरोहित।\nबृहस्पति देव विग्रह में दशम भाव में हैं। वह स्वर्ग लोक में देवी-देवताओं का है\nदेवेन्द्र के सलाहकार। देवताओं को. जो पुजारी हैं उनमें भगवान विशेष हैं\nएक उपस्थिति है. देवताओं के विवेक में इंद्र आठवीं कक्षा में और दसवीं कक्षा में हैं\nबृहस्पतिाचार्य को प्रणाम करें और अपने अंदर मौजूद भगवान के मार्गदर्शन का पालन करें\nनिकटता ही कारण है. इसकी याद दिलाने के लिए यहां कृष्ण देवेन्द्र के अवतार अर्जुन मौजूद हैं\n\"पार्थ\" कहकर सम्बोधित किया जाता है।\n\nदूसरी ओर, वेदों में बृहस्पति जीवन के देवता हैं। भारत की सरस्वती\nपति-बृहस्पति. वह ब्रह्म-वायु है. वे सभी देवताओं के पुजारी हैं। प्रभु\nवह प्राणदेव में गीत (कान्तसिरी) की विशिष्ट विभूति के रूप में निवास करता है।\n\nयहाँ भगवान का विभूति नाम \"बृहस्पति\" है। बृहत् का अर्थ है बड़ा, पति का अर्थ है स्वामी।\nब्रह्मा सभी देवताओं के स्वामी और पुरोहितों के पुरोहित भगवान \"बृहस्पति\" हैं।\nकृष्ण, जो पुजारियों के बारे में बात करते थे जो आध्यात्मिक योद्धा हैं, अब युद्ध और सुरक्षा में जीत दिलाते हैं\nऐसा करने वाले योद्धाओं में अपनी विशेष विभूति बताते हैं। देवता बृहस्पतिाचार्य हैं\nजब मार्गदर्शन में अर्जित धन असुरों द्वारा चुरा लिया जाए, तो उनसे युद्ध करो\nस्कन्द को वापस लाया गया। भगवान स्कंद नमक के रूप में खड़े होकर युद्ध का संचालन करते हैं।\nअंतरतम, जिसने स्कंद को एक सेनापति के रूप में तारकासुर का वध करने की शक्ति दी\nअंतर्यामी तत्त्व-भगवान भीतर विराजमान हैं। सेनानी की बात करें तो यहां सेनानी के रूप में कीर्ति हैं\n\nकर्नाटक के गौरवशाली सपूत *\"करियप्पा\" को कोई भी याद कर सकता है।\nसन्निदान के कारण ही एक सैन्य कमांडर में ऐसी विशेष शक्ति आती है।\n\nभगवान का विभूतिनाम स्कंदः जो यहां आया है। 'स्मंदः' का अर्थ है संपूर्ण जगत का नाश करने वाला\nशक्ति कृष्ण ने कहा, \"चावल का कटोरा पीते हुए और 'स्कंद' कहते हुए, मैं सेनापति की महिमा में हूं\"।\nकृष्ण आगे कहते हैं: \"सरसमास्मि सागरः\"। पृथ्वी पर महान धन\nयदि स्थान मेरु पर्वत है, तो रस से भरा सबसे बड़ा जलाशय महासागर है।\nकृष्ण कहते हैं, ''मैं इसमें विभूति हूं।'' कुआँ चाहे धरती के किसी भी हिस्से में खोदा गया हो\nमीठा पानी लेकिन समुद्र का पानी स्वाभाविक रूप से खारा होता है। हम नहीं जानते कि ऐसा क्यों है. रूसी\nप्रसिद्ध मनोवैज्ञानिक विलिको\"स्काई (/61105)/) ने अपनी पुस्तक \"001165 18. 00॥॥5100'\nकहते हैं: \"हम इस भ्रम में हैं कि हमने दुनिया के सभी आश्चर्यों को पार कर लिया है, लेकिन हम कुछ भी नहीं जानते हैं।\"\nवह है। आज हम नहीं जानते कि समुद्र का पानी खारा और कुएं का पानी मीठा क्यों होता है।\nभगवान ने बाकी सभी रस फलों में डाल दिये। लेकिन रसदा-रस लवणरसा नमक ही\nफल में भी नहीं - समुद्र के पानी में। ये समुद्र एक अजूबा है. ज़मीन पर जानवर\nविविधता से अधिक विविधता समुद्र में है। भगवान ने समुद्र और उसमें महासागरों की रचना की\nशब्दों से भरपूर.\n\nप्रभु विभूतिनामे सागरः यहाँ आये हैं। सारा*गरा-सागर. सार होना\nप्रभु तो वह है जो स्वीकार करता है। सबसे बड़ा सार-नमक, भगवान सगरह से भरे हुए हैं।\nसरं गरति ददातिति सागरः। संसार को जीवन का सार देने वाले भगवान सागरः।\n\nमहर्षिणं भृगुरहं गिरामस्मे चकमाक्षरम् |\n\nयज्ञानं जपयज्ञनोशस्मि स्थावरनं हिमालय",
  "10.30": "प्रह्लादः च अस्मि धैतानां कालः कलायतं अहम् |\n\nमृगनं च मृगेन्द्रः अहं वैनतेय; च पक्षिनम - वह दिति के वंश में सबसे बड़े थे\nप्रह्लाद I (वरिष्ठ आनंद द्वारा प्रह्लाद में मैं \"प्रह्लाद\" के रूप में हूं।) काला मैं लेक्कियों में से हूं।\n[चूँकि मैं हत्यारा हूँ, मैं कालादेवता में हूँ जिसे *काला' कहा जाता है।] मैं जानवरों में शेर हूँ।\n\n[जानवर: भगवान से प्रेम करने वाले भक्तों के लिए, मैं इंद्र के शत्रु के कारण 'मृगेंद्र' नामक सिंह में हूं।)\nमैं पक्षियों में उकाब हूँ। [विनता: मैं आत्मसमर्पण करने वालों के समर्थन के रूप में गरुड़ में \"वैनाथेय\" के रूप में हूं।]\n\nप्रभु की उपस्थिति कुलीन और गरीब दोनों में है। वह जो दिग्गजों को ताकत देता है\nप्रभु. आमतौर पर राक्षस ही होते हैं जो किसी का जीवन बर्बाद कर देते हैं। लेकिन ऐसे\nराजवंश की शुरुआत में पैदा हुआ प्रह्लाद बाकी सभी से अलग था। इसका कारण उसमें विद्यमान प्रभु ही है\nविशेषकर उपस्थित रहना। एक विशाल परिवार में जन्मे, उन्होंने बहुत पहले ही वह स्वभाव खो दिया था\nप्रह्लाद महान है. इस कारण वे दिग्गजों में विशिष्ट विभूति हैं। प्रह्लाद पर\nभगवान की विशेष कृपा है. जब वे गर्भ में थे तभी देवर्षि नारद के माध्यम से उन्हें अध्यात्म प्राप्त हुआ\nमैं निर्देश प्राप्त करने के लिए काफी भाग्यशाली था। उन्होंने ध्रुव की तरह पाँच वर्ष की आयु में भगवान को देखा\nपेशेवरों. भगवान ने प्रह्लाद के माध्यम से संसार को एक बहुत ही महत्वपूर्ण संदेश दिया।\n\"भगवान डरावने नहीं हैं, अगर हम प्रेम से भगवान के पास जाते हैं तो वह भी हमसे उतना ही प्रेम करते हैं।\"\nभगवान की पूजा करता दिखता है. कोई व्यवसाय नहीं, कुछ ऐसा जो हम चाहते हैं\nहमें प्राप्ति के लिए भगवान की पूजा नहीं करनी चाहिए; हमारी पूर्ण भक्ति भगवान के प्रति है\n'इस तरह भगवान की पूजा करने से हम हमेशा खुश रह सकते हैं'\nप्रह्लाद ने जग दिखाया। भगवान के विभूतिनामे प्रह्लादः यहां आते हैं। कभी नहीं\nआनंदमूर्ति भगवंत प्रह्लाद: जो दुःख से परिपूर्ण है।\n\nकृष्ण कहते हैं: \"कालः कलायतम् अहम्\"। इस दुनिया में हमेशा-हमेशा के लिए\nजो भी जन्म और मृत्यु होती है वह पूर्वनिर्धारित है। इसे कोई नहीं बदल सकता. यहाँ\nकाल शब्द के कई अर्थ हैं जैसे गणना, मृत्यु, शिव, दुर्गा, कालाग्नि आदि।\nइन सभी में भगवान की विशेष विभूति छिपी हुई है। *कला' में संज्ञा के रूप में भगवान कलाह\nपूर्ण काला शब्द 'कला' धातु से बना है। सभी गुण, सभी\nकलाह वह है जिसने अपने अंदर काबिलियत को 'तराशा' है। भगवान सभी गुणों से परिपूर्ण हैं\nसिद्धांत जब हम इस सिद्धांत को समझे बिना अहंकारी हो जाते हैं, तो वही सिद्धांत हमारा 'काल पुरुष' होता है।\nवध की ओर ले जाना. कभी-कभी हमारा उद्धार 'जीवन में' होता है और कभी-कभी यह हमारा होता है\n'मृत्यु में'; कभी हमारी 'इज़्ज़त' में, कभी हमारी 'शर्म' में.; कभी-कभी हमारा\nयदि हमारा उद्धार 'ज्ञान' में है, तो कभी-कभी हमारा उद्धार हमारे 'अज्ञान' में भी होता है। लेकिन\nहमारे 'अहंकार' से कभी मुक्ति नहीं होती। जब संसार अहंकारपूर्ण अज्ञान से भर जाता है\nभगवान 'काल पुरुष' के रूप में बड़े होते हैं। काल का दूसरा अर्थ 'समय' भी है।\nप्रत्येक कार्य के पीछे 'काल' ही कारण है। समय भगवान कलह.\n\nप्रबुद्ध अवतारों (व्यास, कपिल, दत्तात्रय, नर-नारायण, आदि) से लेकर अज्ञान तक।\n\n'कलावड़ा' भगवान, शक्तिशाली अवतारों (नरसिम्हा, वराह, राम, परशुराम, आदि) से।\nअहंकार के लिए, 'समय बन गया है'\"।\nकलाह\n\nकृष्ण, जो अपनी विभूति को संहारक शक्ति के रूप में बोलते थे, जानवरों में सबसे भयंकर और सबसे शक्तिशाली थे\nपशु में अपनी विभूति बताते हैं। पृथ्वी पर सबसे शक्तिशाली और सबसे बड़ा जानवर हाथी है। लेकिन\nजंगल का राजा मृगेन्द्र-सिन्हा ऐसे हाथी को भी मार सकता है। जानवरों में सबसे महान\nविभूति के रूप में, जो एक जानवर है, भगवान सिंह पर विराजमान हैं। भगवान का नाम यहाँ आ रहा है\n\"मृगेन्द्रः। सर्वोच्च (मृगा) जो भगवान की प्राप्ति में खड़े लोगों के लिए एक मार्गदर्शक के रूप में खड़ा है।\nभगवान 'मृगेन्द्रः'।\n\nपशुओं के बाद पक्षियों में भी प्रभु की विभूति। पक्षियों में सबसे महान पक्षी 'ईगल' है। पेट\nगरुड़ एक प्रकार का गरूड़ पक्षी है जिसके शरीर पर सफेद भाग होते हैं। भगवान का वाहन गरुड़ विनुत का पुत्र है। इसलिए\nउसे वैनतेय कहा जाता है। उन भक्तों (विनता) के समर्थन के रूप में \"वैनेतेय\" कहें जो उनके प्रति समर्पण करते हैं\nभगवान गरुड़ में विद्यमान हैं। गरुड़ भगवान को अपने कंधों पर ले जा रहे हैं-\nप्रभु की विशेष विभूति.\n\nपवनः पवनमस्मि रामः अनाभृतमहम् |\n\nरुषाणं मकरश्चास्मि श्रोतासास्मि जाह्न्वी",
  "9.17": "पिता अहम् अस्य जगतः माता धाता पितामहः |\n\nवेद्यं पवित्रं ओंकारः खुक सम यजुः एव च- मैं इस संसार का पिता, माता, पालनकर्ता हूं।\nऔर दादा. जानने से \"माँ\"। पालन-पोषण से \"धात्रु\"।\nपिता से बड़े होने के कारण उन्हें ही पूरी दुनिया को जानना चाहिए। वह जो दुनिया के लिए पवित्र है.\nजो ओंकार, खुग्वेद-सामवेद-यजुर्वेद का पाठ किया जाता है।  [ॐ'. वह है\n'ओमकारा' कहा जा रहा है. श्रद्धा के कारण \"खाक\"। समता के कारण ''सम''।\nयज्ञों द्वारा पूजित होना, “यजुस्\n\nयहां कृष्ण जीवन के रिश्तों के संबंध में भगवान की पूजा का वर्णन करते हैं। कृष्ण\n\nवह कहते हैं \"पिता अहम् अस्य जगतः माता धाता पितामहः\"। इसका मतलब है \"मैं पिता हूँ,\n\nमैं माता हूं, मैं पालनकर्ता और पिता हूं।'' जैसा कि हम जानते हैं कि कोई भी पिता बन सकता है या बन सकता है\n\nमां बन सकती हैं. लेकिन माँ और पिता दोनों अकेले रहना संभव नहीं है। यह प्रभु में है\n\nही संभव है. ईश्वर सबका पिता और सबकी माता है। पिता के भीतर \"पिता\" के रूप में,\n\nवह प्रभु माँ के भीतर 'माँ' के रूप में भरी हुई शक्ति है। हम इसकी प्रशंसा इस प्रकार करते हैं:\nत्वमेव माताच पिता त्वमेव, त्वमेव बन्धुष सखा त्वमेव\n\nत्वमेव विद्या द्रविणं त्वमेव, त्वमेव सर्वं मम देवा देवा\nगायति का मूलतः यही कार्यान्वयन है। \"तत्सवितुर्वरेण्यं भर्गः\" में भगवान ही विश्व है\nइसका अर्थ है पिता जिसने सृजन किया। सविता. इसका अर्थ है संसार को धारण करने वाला।\nप्रभु ने प्रलय के समय संसार को अपने पेट में धारण किया और सृष्टि के समय उसे धारण किया। बहुत समय तक\nपरामर्शदाता एक \"माँ\" है - इसलिए भगवान भी एक माँ है, न केवल वह, बल्कि हर माँ के भीतर\nउस माँ के मातृत्व को, उस प्रभु को जगाओ जो माँ के भीतर मातृत्व से भरा हुआ है, सब\nवह पिता ही है जो पिताओं में, यहां तक ​​कि उनके भीतर भी पितृत्व जगाता है। पिता शब्द की परिभाषा\n\"पिता\" केवल एक पारंपरिक अर्थ है। श्रुति कहती है:\n\nयोनः पिता जनितयो विधाता धामनि वेद भुवनानि विश्वा|\n\nयो देवानां नामधा एक एव तम् सम्प्रशना म्बुवना यन्तन्य ||\nयहां पिता और जनक का अलग-अलग उल्लेख किया गया है। वह हमारा पिता है, वह हमारा जन्मदाता है।\nअर्थ: वह सृष्टिकर्ता है, वह रक्षक है।\nसंसार में पुरुष स्त्री नहीं हैं, स्त्री पुरुष नहीं हैं। लेकिन ईश्वर तो सबका अवतार है. तो प्रभु\nउभयलिंग - वह स्त्रैण है। परन्तु उसमें न स्त्री का दोष है, न पुरुष का\nकोई त्रुटि नहीं है.   अतः वह भी लिंगविहीन है\nनामों में पाया जा सकता है]।\nभगवान 'धाता' हैं। वह अनन्त काल से इस संसार का पालनकर्ता एवं पालक है।\nचार मुख वाला ब्राह्मण भगवान है जो पिता का वचन है।\nयहां कृष्ण ने सिर्फ अहम रिश्ते का जिक्र किया है. इसका मतलब यह है कि सभी रिश्तों में\nयह अन्तर्यामी भगवान ही हैं जो इंद्रियों को जागृत करते हैं। हर रिश्ते के पीछे\nभगवान से रिश्ता है. लेकिन हमें वह विचार नहीं है. प्रत्येक जीवन का प्रारब्ध\nकर्म संबंध. प्रेम, द्वेष, शत्रुता सब ईश्वर के कार्यक्रम हैं।\nजब हम यह जान लेते हैं तो हमारा जीवन आसान हो जाता है। जब कोई हमसे नफरत करता है तो सिकुड़ने की जरूरत नहीं,\nजब कोई हमसे प्यार करता है तो बढ़ने की कोई जरूरत नहीं है। सब कुछ हमारा जीवन स्वभाव है और\nयहां प्रारब्धकर्म के अनुसार भगवान की लीला का स्मरण करना बहुत जरूरी है। इसके लिए एक अच्छा है\nदृष्टांत भागवत में वृत्र और इंद्र के बीच युद्ध की कहानी: इंद्र को मारने के लिए निकले\nजैसे 'वृत्र' के पिता त्वष्ठा ने एक स्वर गलत वाला मंत्र बोला - वृत्र से।\nइंद्र द्वारा मारे जाने के बजाय, इंद्र ने ही वृत्र को मार डाला। वृत्र और इन्द्र के युद्ध में |\nइंद्र ऋषि वृत्र को मारने से हिचकिचाते हैं। तब वृत्र कहता है: “शर्म।”\nमत गिरो इंद्र, मुझे मार डालो। क्योंकि इस नाटक में भगवान तुम्हें मार देते हैं\nऔर उसने मुझे मरने के लिए भी एक भूमिका दी। हमें बस इस पर अमल करना है।” इस कदर\n\nयदि हमारे पास ईचा है, तो जब हमें दूसरों द्वारा डांटा जाएगा या नफरत की जाएगी तो हम दुखी नहीं होंगे। सब कुछ भगवान का है\nजब इसे सिस्टम के रूप में जाना जाता है तो सब कुछ एक समान दिखता है। नफरत और प्यार स्वाभाविक रूप से चले जाते हैं।\nरिश्ते टूटने पर सिकुड़न नहीं होती और जुड़ने पर विस्तार नहीं होता। यह बहुत ऊंचा दर्जा है.\nकृष्ण यहां जो कह रहे हैं उसका पूरा सार यह है: सभी रिश्तों के पीछे भगवान हैं। सबमें से\nवह अंदर से 'सभी' से भरा हुआ है। उनमें से प्रत्येक रूप में, अपने-अपने कार्य हैं\nक्या यह वह विज्ञान है जिसके प्रति हमें संपर्क करना चाहिए।\n\nकर्म और संबंधों की व्याख्या करने के बाद कृष्ण अब ज्ञान के बारे में बताते हैं। कृष्ण कहते हैं “वेद्यम्\nपवित्रमोणकर खुक सम यजुरेव च”। इस नाममात्र संसार के सभी नामों में से\nमूल 'ओम्' है। कृष्ण कहते हैं: \"मैं ओमकारा हूं\"। संसार में सभी ध्वनियाँ जन्म लेती हैं\nओमकारा द्वारा. अतः भगवान सर्वज्ञ हैं।  संस्कृत के सभी शब्द ऐसे ही हैं\nओमकारा से निकलने वाली ध्वनियाँ। आइए संक्षेप में देखें कि कैसे:\n\nवैदिकवाजकय के मूल ओंकार में आठ अक्षर हैं: अकार, उकार, मकार, नाद,\nबिंदु, कला, शांत, अति शांत। इसका अर्थ है नारायण अष्ट क्षार: \"ओम नमो\nनारायणायः... ओमकारा के आठ प्राथमिक रंगों में से अक्षरा मलिका की आठ श्रेणियां\nद्वारा गठित:\n\n1. स्वर: एईईईईईईईईईईईईईईईईईईईईईईईईईईईईईईई\n\n2. क-.वर्ग: कखगघज\n\n3. चा-वर्गा: चाचाजारुए\n\n4. ता-वर्ग: ताराथराधना\n\n5. ता-वर्ग: तथाधाधना\n\n6. पा-वर्ग: पापभाभामा\n\n7. प्रारंभिक अक्षर:\n\n8. अंतिम छह अक्षर: शशशहालक्ष\n\n'अ' से 'क्ष' तक कुल इक्यावन अक्षर (अ से क्ष इसलिए अ-क्ष-र)। संपूर्ण\nसंसार के सभी शब्द इन्हीं अक्षरों के संयोजन हैं। सभी ध्वनियाँ ओमकार की हैं\nओंकार वाच्य भगवन्त सर्वशब्द वाच्य जन्म के कारण। तो सभी ध्वनियों का मूल\nपवित्र का अर्थ है ईश्वर. दोषयुक्त बातें भी केवल प्रभु की ही होती हैं\nवे केवल पवित्र अर्थ ही कहते हैं। उदाहरण के लिए दुःखद. यह तब होता है जब भगवान कहते हैं \"दुःख।\"\nइसका मतलब मालिक है.\n\nइक्यावन अक्षरों (मैट्रिक्स) से पढ़े जाने वाले भगवान के रूप भी इक्यावन हैं:\n\n1. अजा, 2. आनंद, 3. इंद्र, 3. ईशा, 4. उग्र, 5. ऊर्जा, 7. खुटंबर, 8. खगहा, 9. एल श, 10.\nलिजी, 11. एकात्म, 12. इरा, 13. ओज़ोभृत, 14. औरसा, 15. अंत, 16. अर्धगर्भ, 17.\nकपिला, 18. खपति, 19. गरुड़ासन, 20. ताप, 21. जसारा 22. चार्वंगा, 23. छंद,\n24. जनार्दन, 25. रुओतितारी, 26, इमू, 27. टंकी, 28. थाकला, 29. दारका, 30. धारी, 31.\nनतमा, 32. तारा, 33. थाभा, 34. दंडी, 35. धान्वी, 36. लचीलापन, 37. प्रो, 38, फली, 39. बलिदान, 40.\nभग, 41. मनु, 42. यज्ञ, 43. राम, 44. लक्ष्मीपति, 45. वर, 46. शांतसंवित्, 47. षडलूण,\n48. शरतमा, 49. हंस, 50. लालुका, 51. नृसिंह[नृहर्याक्ष]।\n\nओंकार मूल मूराक्षर का अ-उ-मा पद्य-गद्य-गण। यह वेद और वेदा के तीन रूप हैं\nप्रतिपद्य भगवान् कहते हैं। खुग्वेद के लिए अकार, यजुर्वेद के लिए उकार और मकार\nसामवेद से संबंधित. खगरेदा \"अग्निमि\"ले पुरोहितं यज्ञस्य देवम्-खत्विजम्\" |\nहोता”राम रत्न धतमन् |…” “ए’ कारा से शुरू होता है.और “…बराबर”\nवो मनो यथा वः सुसहसति॥” जो 'ई' में ख़त्म होता है. वहां से आगे बढ़ें\nयजुर्वेद \"इशे त्वोरजे त्वा ..\" \"ए'कारा \"......समुद्रो बंधु\" से शुरू होता है\n\"उ'कारा में समाप्त होता है। इस प्रकार ओमकारा खुग्वेद में \"अकारा और \"उकारा\" होता है\nसंपूर्ण यजुर्वेद को इंगित करने वाला संक्षिप्त (3008॥01) रूप। यहां से आगे\nसामवेद सामवेद “अग्ना आ याही ह्हहल्ला*। 'अ'कारा से शुरू करते हैं\n1411 बृह्मास्पतिरद्दधातु” का अंत “उकार” में होता है। तो 'एम' कार यहां नहीं आई। लेकिन\nजैसा कि हम जानते हैं सामवेद नाद रूप में है। ओंकार में भी \"म\" नाद का ही रूप है\nएक उभरता हुआ अक्षर- वह है संगीत। इस प्रकार ओंकार वेद का संक्षिप्त रूप है। ये हमारे लिए है\nवेदों की पहचान के लिए एक मार्गदर्शिका। तो मंत्रों में भगवान ओंकार की स्तुति की जाती है\nयह अत्यंत प्राकृष्ण है। इस संसार में इससे बड़ी कोई प्रशंसा नहीं है। इस वजह से\nओमकारा उनका विशेष (कह€1651/6) नाम है जिससे हम भगवान को बुलाते हैं।\n\nव्याहृति जब ओंकार खो जाता है, व्याहृति व्यापक रूप से गायत्री है, गायत्री अत्यधिक अंधी है।\nसूक्त, फिर तीन वेद, फिर सभी वेद। इस प्रकार प्रणव में, व्याहृति में, पुरुष में\nसूक्त में सभी वेदों में भगवान का वास बताया गया है। ओमकारा के बारे में और भी बहुत सी जानकारी\nइसका विशेष विवेचन अध्याय सात श्लोक-08) में किया जा चुका है।\n\nवेदों के शब्दों से जन्मे, दुनिया की सभी ध्वनियों और सभी सांसारिक स्वरों से भरे हुए\nभगवान ने आकाश में अनंत नाद और अनंत स्वर उत्पन्न किये। शोर से लेकर हम तक\nउस ध्वनि को समझने और समझने तथा दोहराने की विशेष शक्ति, अनंत अनुभव कराती है\nदयालु. मनुष्य में इस शब्द नमक भगवान को ज्ञान के माध्यम से जानने की विशेष शक्ति होती है\nभगवान का विशेष उपहार.\n\nभगवान 'खुक': खाक वह है जिससे हम भगवान की पूजा करते हैं। हम हैं\nमंत्रों के माध्यम से पूजा की जाती है. जिसकी पूजा की जाती है उसे 'खुक' कहते हैं\nप्रभु. जिनकी आराधना सभी मंत्रों द्वारा की जाती है।-प्रशंसनीय भगवान 'खुक'\n\nभगवान \"समः': वह जो अपने सभी रूपों में सभी को ज्ञानानंदादि गुणों से समान करता है\n\"समहा\" वह भगवान है जो उनके गुणों के बराबर और बराबर जीवन देता है।\n\nभगवान “यजस: जो सभी यज्ञों द्वारा पूजे जाते हैं, जो वेदों में मौजूद हैं।\nसर्वज्ञ भगवान \"यजुस्\",\n\nगतिर्भर्ता प्रभुः साक्षी निवासः शरणं सुह्रुत |\nप्रभावः प्रलयः स्थानं धनं बीमाम्",
  "10.40": "न अंतः अस्ति मम दिव्यं विभूतिनं परंतप।\nएषः तु थम्नतः प्रोक्तः विभूतः विस्तारः | माया-हे परंतप, मेरे दिव्य रूपों की\nमहानता का कोई अंत नहीं है. मैंने यहां अपनी कुछ ही महानताओं का नाम दिया है।\n\nकृष्ण कहते हैं: “मेरी विभूति संसार की प्रत्येक वस्तु में है\n\"नहीं।\" ईश्वर के सांसारिक आश्चर्य का कोई अंत नहीं है। इसे बढ़ा-चढ़ाकर नहीं कहा जा सकता. यहाँ\nकृष्ण सबसे महत्वपूर्ण हैं, हम... निरंतर पूजा करते हैं। करने के लिए, दैनिक\nचर्चा में क्या होना चाहिए, इसके बारे में उन्होंने बस इतना ही कहा\n\nयद्यद् विभूतिमत् सत्त्वं श्रीमदुर्जितमेव वा |\nतत्तदेववगच्छ त्वं मम तेजो$0ससम्भवम्",
  "10.41": "यत् यत् विभूति मत सत्त्वम् श्रीमत उर्जितम् एव वा |\n\nतत् तत् एव अवगच्छ त्वं मम तेजः अम्स संभवम् - समूह में रहना, सिरी में\nलंबा. जो कुछ भी ऊपर चमकता है वह मेरे महान प्रकाश की चिंगारी से है\nजानो कि यह उत्पन्न हो गया है।\n\nसामान्य तौर पर, यह वह है जो किसी व्यक्ति, वस्तु के बारे में अद्वितीय है, न कि दूसरों के बारे में\nपरमेश्वर की महिमा के प्रकाश की एक चिंगारी। यह भगवान की अनंत प्रतिभा का एक अंश है।",
  "10.39": "यत् च अपि सर्व भूतानां बीजं तत् अहम् अर्जुन |\n\nन तत् अस्ति विना यत् सत् माया भूतम् चर आचरम् - अर्जुन, सभी जीवित प्राणियों में\nउसमें जो भी अद्वितीय गुण हैं, वह शक्ति मैंने ही दी है। मुझे छोड़कर\nव्यवहार में कुछ भी स्वतः स्पष्ट नहीं है।\n\n“इस संसार में सभी पदार्थों (जड़-आत्मा) का मूल रूप और ऊर्जा\nमैं दाता हूं, ”कृष्ण कहते हैं। इस प्रकार भगवान सारी सृष्टि के बीज के रूप में खड़े हैं।\nवह वह है जो अदृश्य जीवन को दृश्य शरीर देता है। जीवन मनुष्य की अवस्था में है\nरेथा का चेहरा महिला के शरीर में डाला जाता है, जहां वह जीवन को एक रूप देता है और उसे रोशन करता है\nप्रभु. इस प्रकार इस संसार में आत्मा या नैतिकता हर चीज़ का प्रवर्तक है\nप्रभु. कृष्ण कहते हैं, ''इस संसार में ऐसी कोई वस्तु नहीं है जो मुझसे स्वतंत्र हो।'' यह है\nवैदिक परंपरा में व्याप्त भ्रम पर कृष्ण का सीधा उत्तर। जीव और भगवान एक नहीं हैं.\nजीवन ईश्वर का प्रतिबिम्ब है। सब कुछ है। परन्तु ईश्वर से पृथक किसी का भी स्वतंत्र अस्तित्व नहीं है।\n\nनन्तोइस्ति मम दिव्यं विभूतिनं परंतप |\nएषा तुद्देशथा प्रोक्तो विभूतेरविस्तारो मया",
  "10.38": "दण्डः दमयथम अस्मि नीतिः अस्मि जिगिष्टम्।\n\nमौनं च एव अस्मि गुह्यं ज्ञानं ज्ञानवतं अहम् - झुकने वालों को दंड।\nमैं [क्योंकि मैं दंड देने वाला हूं, मैं दंड नीति में हूं जिसे \"दंड\" कहा जाता है।] उन लोगों का धोखा जो जीतना चाहते हैं।\nमैं [मैं इसे 'नैतिकता' कहने में पाखंडी हूं क्योंकि यह जीत की ओर ले जाती है।] गुप्त रूप से मौन\nमैं [संतों द्वारा 'मौन' के रूप में स्तुति की गई है, मैं मौन रहता हूं।] मैं जानने वालों का ज्ञान हूं। [संज्ञानात्मक\nमुझे \"ज्ञान\" के रूप में जाना जाता है क्योंकि मैं एक मूर्ति हूं।]\n\nकृष्ण कहते हैं, \"मैं बुराई का दमन करने वाला हूं।\" इस दमनकारी शक्ति के रूप में नायकों के बीच\nभगवान बैठे हैं. दण्ड का अर्थ है दण्ड। संस्कृत में दण्ड का अर्थ शिक्षा है। लेकिन\nयहां डंडा का अर्थ दंड देना है (161151/7900)। परमेश्वर के राज्य में ग़लतियों के लिए कोई क्षमा नहीं है। हम हैं\nहमें किये गये कर्मों को महसूस करना होगा। गलत काम करने वालों के प्रति कठोर और कठोर\n\nदण्ड देने वाला भगवान \"दण्ड\" है। वह प्रभु जो विजयी शक्ति के रूप में सभी को नियंत्रित करता है\n\"भगवान जो धार्मिकता और मन के रूप में खड़ा है वह 'मौना' है। भगवान जो ज्ञाता का ज्ञाता है वह “ज्ञानः” है।\n\nमूलतः विभूतियों की सीमा यहीं समाप्त हो गई। आगे विभूति का उपसंहार है\nआइए शेष अध्याय में देखें।\n\nयच्चपि सर्वभूतानां बीजं तदाहमर्जुन |\nन तदस्ति विना यत् सन्मय भूतं चराचरम्",
  "11.2": "भवाप्ययौ हि भूतानां श्रुतौ विस्तरशो मया ।\nत्वत्तः कमलपत्राक्ष माहात्म्यमपि चाव्ययम् ॥\n\nजीवों के भव और अप्यय — उत्पत्ति और विनाश — विस्तारपूर्वक आपसे सुने। हे कमलपत्र-नयन, आपका अव्यय माहात्म्य भी सुना।\n\nअर्जुन पूर्व अध्यायों में सुने ज्ञान का सार संक्षेप करता है। 'कमलपत्राक्ष' — पद्मदल-सदृश नेत्रों वाले — सौन्दर्यसम्पन्न भगवान् का सम्बोधन। अब ज्ञानदर्शन की इच्छा प्रकट होती है।",
  "10.37": "वृषेतीनां वासुदेवः अस्मि पाण्डवनम् धनञ्जयः।\n\nमुनिनाम अपि अहम व्यासः कवीनम् उषाना कविः - वृष्टिवंश के राजाओं के बीच।\n[वसु-सर्वव्यापक, सबमें व्याप्त, देव-दिव्य स्वरूप होना] वासुदेव के रूप में\nमैंने अवतार लिया है. मैं पांडवों में अर्जुन हूं। (\"धनंजय\" को सिरी का विजेता कहें\nमैं अर्जुन में हूं।] ऋषियों के बीच ([v: सभी से सबसे प्रतिष्ठित, वह-हर जगह, सः इवाना\nपूर्ण होना] व्यास I. मैं वैज्ञानिकों में सबसे पुराना विद्वान शुक्र हूं।\n[इच्छारूपा के रूप में, मुझे ध्यातुगुरु शुक्र में \"उशनस\" कहा जाता है।]\n\nसाक्षात विभूति की बात करते हुए कृष्ण कहते हैं \"वृष्टिनां वासुदेवः अस्मि\"। यहाँ\nभगवान के विभूति नाम \"वासुदेवः। सर्वत्र अदृश्य, अन्तर्यामी का दयालु ज्ञान\nभगवान वासुदेव जो प्रकट होते हैं। कृष्ण कहते हैं कि मैं पांडवों में 'धनंजयः' हूं। ये है\nएकदेश विभूति. अर्जुन पर भगवान का विशेष प्रभार था। उसमें भगवान “धनंजयः।”\nवह नामांकित व्यक्ति के रूप में खड़े थे। धनंजयः का अर्थ है ज्ञान। प्रभु चेतना, उससे\n\nप्राप्त मोक्ष शाश्वत धन है। इसे प्रदान करने वाले भगवान धनंजय ही हैं। ऋषियों में व्यास। ये है\nईश्वर की प्राप्ति. व्यास ने वेदों को 1137 संहिताओं में विभाजित किया\nमुखेना ने हमें दिया है. वेद मुख्यतः चार हैं। काव्य संकलन खुग्वेद, गद्य संकलन\nयजुर्वेद, गणाक्षर सामवेद, अथर्व मुनि को ब्रह्मा ने उपदेश दिया था और अथर्वण ने लिखा था।\nवेद. मूलतः वेद तीन हैं परन्तु ख़ुशी परम्परा के अनुसार चार वेद हैं\nवेदव्यास ने चार ऋषियों (बैल, वैशम्पायन, सुमन्तु) से यही कहा था\nऔर जैमिनी से कहा)। इन चारों ऋषियों ने वेद को पुनः कई शाखाओं (संहिता) में विभाजित कर दिया।\nहल निकाला। खुग्वेद में 24 संहिताएँ हैं; यजुर्वेद की मुख्यतः दो शाखाएँ हैं। एक शुक्र\nयजुर्वेद और दूसरा कृष्ण यजुर्वेद। 15 शुक्ल यजुर्वेद में संहिता और कृष्ण\nयजुर्वेद में 86 संहिताएँ, कुल 101 संहिताएँ। सामवेद की 1000 शाखाएँ, एक हजार\nएक प्रकार का गायन! लेकिन आज केवल तीन (जैमिनी, राणायनी और कौतुमन)\nगणपद्धति ही प्रचलित है। अथर्ववेद की कुल 12 शाखाएँ हैं। इस प्रकार वेद 1137\n(243101*12*1000) मुनि व्यास ने संहिताओं में विस्तार किया। मानव स्वभाव की बुद्धि\nभगवान व्यासः, जिन्होंने हमारे सामने विचित्र ज्ञान का सागर खोल दिया है, वे हर जगह मौजूद हैं। बृहस्पति विशाल है\nभगवान शुक्राचार्यों के बीच \"उशना\" के रूप में खड़े थे। इस कारण शुक्र ग्रहों में से एक बन गया।\nस्थित. भगवान \"उषाण\" जो सभी कार्य अपनी इच्छा से करते हैं।\n\nदण्डो दमयतामनस्की नीतिरस्मि जिगिष्टम् |\nमौनं चैवस्मि गुह्यं ज्ञानं ज्ञानवतमहम्",
  "11.10": "अनेक मुख-नेत्र-आभरण-उद्यतायुध; दिव्य माल्य-अम्बर धारण किए हुए; दिव्य गन्धानुलेपन युक्त; सर्वाश्चर्यमय, अनन्त, विश्वतोमुख देव।\n\nविश्वरूप का वर्णन — अनन्त, सर्वाश्चर्यमय, विश्वतोमुख। प्रत्येक इन्द्रिय में विशेष देवता निहित हैं — उनका समागम विश्वरूप है। दिव्यमाल्य-अम्बर-गन्ध — मङ्गल के प्रतीक।",
  "11.5": "भगवान् उवाच —\nपश्य मे पार्थ रूपाणि शतशोऽथ सहस्रशः ।\nनानाविधानि दिव्यानि नानावर्णाकृतीनि च ॥\n\n'देखो पार्थ, मेरे रूप — सैकड़ों, हजारों — नाना प्रकार के, दिव्य, नाना वर्ण-आकार वाले।'\n\nअर्जुन ने एकवचन में माँगा — भगवान् बहुवचन में देते हैं। भगवान् के सभी रूप — मूलरूप, अवतार — सब एक ही तेज में अभिन्न। नानावर्णाकृतीनि — भिन्न रूपों में एक ही तेज।",
  "11.8": "किन्तु इन अपनी इन्हीं आँखों से मुझे देखने में समर्थ नहीं। मैं तुम्हें दिव्य चक्षु देता हूँ — मेरी ऐश्वरी योगशक्ति देखो।\n\nभगवान् स्वरूपभूत हैं — स्वरूपभूत नेत्र से ही दृश्य। बाह्यनेत्र से सूर्य का प्रकाश दीखता है, सूर्य स्वयं नहीं — वैसे ही इन्द्रियों से विभूतियाँ दीखती हैं, भगवान् ज्ञाननेत्र से।",
  "11.4": "मन्यसे यदि तच्छक्यं मया द्रष्टुमिति प्रभो ।\nयोगेश्वर ततो मे त्वं दर्शयात्मानमव्ययम् ॥\n\n'यदि आप मानते हैं कि मैं उसे देख सकता हूँ — तो हे योगेश्वर, अपना अव्यय रूप दिखाइए।'\n\nयोगेश्वर — जिनकी योगशक्तियाँ अधीन हैं। भगवान् स्वयोगमाया से विश्वरूप देते हैं — साधारण नेत्र से दर्शन सम्भव नहीं।",
  "11.1": "अर्जुन उवाच —\nमत् अनुग्रहाय परमं गुह्यम् अध्यात्मसंज्ञितम् ।\nयत् त्वया उक्तं वचः तेन मोहोऽयं विगतो मम ॥\n\n'आपके अनुग्रह से, अध्यात्म नाम के परम रहस्य को आपने कहा — उस वचन से मेरा यह मोह दूर हो गया।'\n\nअनुग्रह — नीचे के को ऊपर उठाने की इच्छा। कृष्ण अर्जुन को केवल युद्ध में सहायता नहीं करते — तत्त्वज्ञान से संसारमोह से मुक्त करते हैं। यह भगवान् के परमकारुण्य का प्रमाण है।",
  "10.25": "महा ख़ुशीहं भृगुः अहं गिराम अस्मि एकम अक्षरम।\n\nयज्ञं जपयज्ञः अस्मि स्थावरनं हिमालय; - मैं ऋषियों में भृगु हूं। [बुरे वाले\nजलकर बोले, भृगु, मैं भृगु मुनि हूं।] मैं वाज्मय में एक अक्षर ओंकार हूं।\n[सर्वोपरि, 'एका', विलुप्त होने के कारण मुझे 'अक्षरा' कहा जाता है।] यज्ञों में।\n\n1\n\nजपयज्ञ मैं हूं।\n\n0 0 1\n\nखरीदकर इसे 'यज्ञ' कहें। मैं जपयज्ञ में हूं।] मैं ठोस पहाड़ियों में हिमालय हूं।\n\n[चूंकि 'ह्री' प्रीलक्ष्‍मी का सामक रूप है और महश्री' नामवाचक रूप है।\nमैं हिमगिरी में हूं जिसे 'हिमालय' कहा जाता है।]\n\nइससे पहले हमने देवर्षि बृहस्पति के बारे में देखा था। वह स्वर्गलोक का है।\nयदि हम उनके अलावा अन्य महर्षियों को देखें - उनमें से सबसे प्रतिष्ठित, जिन्होंने भगवान को देखा\nमहान लोग. भृगु महर्षि. विश्वामित्र-वसिष्ठ. भेदभाव कक्षा में सोलहवाँ\nयदि स्थिति में हो तो भृगुमुनि अपने से पंद्रहवीं कक्षा में अग्नि के बराबर हैं।\nवह पृथ्वी पर खुशियों के आविष्कारक थे। जो भागवत में आता है\nजैसा कि कहानी कहती है, एक प्रतिनिधिमंडल के रूप में यह मापने के लिए जाएं कि त्रिमूर्ति में सबसे महान कौन है,\nभृगु एक बहुत महान ऋषि थे जिन्होंने दुनिया को उपदेश दिया कि नारायण सबसे महान हैं।\nनियोग श्रेष्ठ के रूप में भृगु पहले शिव के पास और फिर ब्रह्मा के पास जाते हैं। उनके लिए क्या है\nजब कोई पुरस्कार नहीं मिलता तो भृगु क्रोधित होकर नारायण के पास जाते हैं। विष्णु भी हैं\nजब उस पर ध्यान नहीं दिया जाता तो वह गुस्से में विष्णु की छाती पर लात मार देता है। तब भक्तवत्सल नारायण:\n\"तुमने मुझे बुलाया होता तो मैं आ जाता, इस तरह लात मारने से तुम्हारे पैर में इतना दर्द क्यों हुआ\"\nवह उनके पैर रगड़ने लगता है. तब भृगु और नारायण को अपनी गलती का एहसास हुआ\nसमर्पण। जब हमने यह कहानी देखी, तो क्या हमें नहीं पता था कि इन ऋषियों के लिए भगवान का महत्व क्या था?\nएक प्रश्न उठता है. निश्चय ही वे परमेश्वर का पूरा महत्व जानते थे। यह बस है\nयह कार्रवाई के माध्यम से सामग्री को जन-जन तक पहुंचाने का कार्य है। इसी तरह, “आप\nयह भृगु ही थे जिन्होंने भगवान को श्राप दिया था कि अवतार पृथ्वी पर दस बार गिरेंगे\nश्राप का प्रतिफल देने के लिए भगवान ने पृथ्वी पर दस अवतार लिये। लक्ष्मी\nभार्गवी का जन्म भृगु मुनि की पुत्री के रूप में हुआ था। भृगु में ऐसी अनेक विशेषताएं हैं\nहम देखेंगे. यह सब भृगु में भगवान के विशेष सन्नी दान के कारण है।\n\nयहां भगवान का विभूतिनाम 'भृगुः' है। भर्जनाथ इति भृगुः। बाढ़ के दौरान सब कुछ\nभर्जन भगवान, मुख्य रूप से भृगुहा जो भक्तों के पापों का नाश करते हैं। प्रभु\nवह अपने भक्तों के जीवन में बाधा डालने वाली बुरी आत्माओं का विनाशक है। और दुष्ट\nभगवंत भृगुः शब्द वाच्य, जो अधर्म का नाश कर धर्म की स्थापना करता है। खेतों में\nभृगु को सर्वोच्च स्थान बनाओ, जिनके बीच भृगु भगवान की वाणी है\nआसन्न है.\n\nजब हम ख़ुशियों के बारे में बात करते हैं, तो हमें आश्चर्य होता है कि ख़ुशियाँ भगवान के करीब कैसे हो गईं।\nइसका कारण है- उपासना, मन्त्र-जप सिद्धि। क्षत्रिय विश्वामित्र ने भी वेद मंत्र का जाप किया\nसिद्धि से ब्रह्मर्षि तक। यदि आप खुश रहना चाहते हैं, यदि आप खुशी पाना चाहते हैं, तो ओंकार की पूजा करें\nमनुष्य को प्रभु का एहसास होना चाहिए। दुनिया की सबसे महत्वपूर्ण और महान ध्वनि\nओमकारा. इस ओंकार में अक्षर नमक भगवान का विशेष सन्निदान है। भगवान ओमकारा\nविशेष(8/01368/6)सं. [कृष्ण ने ओमकार को इतना महत्व क्यों दिया, ओमकार में जो असाधारण है\n\nविशेषता क्या है इसका विशेष अर्थ हम सातवें अध्याय में बता चुके हैं\nहमने देखा है (ए-7, श्लोक-8)]। अविनाशी (अ-क्षर) भगवान अकेले ही सबसे बड़े हैं\nसिद्धांत तो वह अकेला है.\nकृष्ण यहां ओमकार के बाद जपयज्ञ के बारे में बताते हैं। वह कहते हैं \"यज्ञं जपयज्ञः अस्मि\"।\nकृष्ण. सभी यज्ञों में सबसे बड़ा यज्ञ जपयज्ञ है। जैसा कि पहले उल्लेख किया गया है, पूजा आग के सामने की जाती है\nयज्ञ ही नहीं. दान, पूजा (समेकन) जैसे अच्छे कार्यों में एक पक्ष से जुड़ना,\nज्ञान दान करना, भोजन दान करना, जो हमारे पास है उसे उन लोगों के साथ बांटकर जीना जिनके पास नहीं है, ये सभी एक हैं\nयज्ञ ही. सामान्यतः यज्ञ दो प्रकार के होते हैं। एक आंतरिक त्याग और दूसरा बाह्य त्याग।\nइंटीरियर में. भगवान की निरंतर पूजा (देवपूजा); चित्त-मन भगवान के साथ है\nजुड़ना (एकजुट होना) और स्वयं को प्रभु के प्रति समर्पित करना - उत्तम\nमनसा यज्ञ. इसे मन में करने वाला जपयज्ञ सबसे बड़ा होता है। इसका कारण जपयज्ञ में है\nप्रभु की विभूति.\nभगवान का विभूतिनाम 'जप' और 'यज्ञ' है। जग में हर जन्म\nभगवान जो जीवन को संजोते हैं 'जपः। क्योंकि ऐसे प्रभु को सबकी पूजा प्राप्त होती है\nजपयज्ञ में \"यज्ञ\" है।\nजप की बात करें तो, कृष्ण पृथ्वी पर सात्विक कंपन का सबसे बड़ा पौधा है\nकहते हैं पहले घर बनाते समय, जिस स्थान पर सात्विक कंपन सबसे अधिक होता है वह भगवान का कमरा होता है\nएक शहर में एक मंदिर उच्चतम सात्विक कंपन का स्थान होता है\nहिमालय पृथ्वी पर एकमात्र ऐसा स्थान है जहां सबसे अधिक सात्विक कंपन होता है। यहाँ\nचाहे हम कहीं भी बैठें, हमारा मन बहुत आसानी से भगवान के साथ जुड़ जाता है। यह शक्ति हिमालय को\nयह प्रभु की विशेष उपस्थिति से आया। यहां भगवान 'हिमालय' नमक रूप में निवास करते हैं।\nभगवान के इस विभूतिनाम का एक विशेष अर्थ है। ह्रीमा*मंदिर-हिमालय। ह्री अर्थात\nश्रीलक्ष्मी, माँ का अर्थ है देवी। भगवान हिमालय, श्रीदेवी और भूदेवी का मंदिर।\nभगवान की इस विशेष विभूति के कारण हिमालय भी आध्यात्मिक विस्मय से परिपूर्ण है।\nहिमालय में व्यक्ति के मन को बदलने और उसे आध्यात्मिकता की ओर मोड़ने की विशेष शक्ति है।\nवेदव्यास, नर-नारायण, आचार्य माधव का निवास स्थान हिमालय है। अनेक\nयह हिमालय एक रहस्यमय स्थान है जहाँ देवता निवास करते हैं। प्रभु की विभूति ही इस भूमि के लिए आश्चर्य है\nइससे ताकत मिली है.\n\nअश्वत्थः सर्ववृक्षाणां देवर्षिणां च नारदः |\n\nगंधर्वणं ​​चित्ररतः सिद्धानां कपिलो मुनिः",
  "10.13": "अर्जुनः उवाच--अर्जुन ने कहाः\n\nपरमं ब्रह्म परमं धाम पवित्रं परमं भवनं।\nपुरुषं शाश्वतं दिव्यं आदि देवं आजम विभुम् ॥\nअहुः त्वम् खुशायः सर्वे देव खपिः नारदः तथा।\n\nअसितः देवलः व्यासः स्वयं च एव ब्रविशि मेई - आप, धन्य, बड़ों से भी महान सिद्धांत हैं।\n\nवरिष्ठ सहयोग. पवन भी पवन. आप सदाचारी, परम व्यक्तित्व के रूप में,\nअपरिवर्तनशील, लीलामय, सबसे पहले देवता, अजन्मा,\nजो सर्वत्र विविध रूपों से परिपूर्ण है, उसकी प्रशंसा वे सभी करते हैं जो उसे जानते हैं। देवर्षि नारद भी.\nअसित-देवों को भी. व्यास ने कहा. क्या आप स्वयं मुझे बता रहे हैं?\n\nयहाँ अर्जुन कृष्ण को \"परमब्रह्म, परन्धम, परमपवित्र आप\" कहकर संबोधित करते हैं।\nजो सबसे बड़ा है वह ब्रह्म है। ब्रह्म शब्द के और भी कई अर्थ हैं\nउपयोग उसने यहाँ स्पष्टता के लिए 'परमब्रह्म' कहा है। “सबसे महान और\nतू परिपूर्ण है, जो विश्वास करनेवालों को ऊपर उठाता है। मेरे व्यक्तित्व की संपूर्णता को देखने के लिए मैं आपका हूं\nइस सम्बोधन में स्वर है \"अनुग्रह वरदा\"। परम धाम: 'धाम' का अर्थ है आश्रय।\nइस संसार में ऐसी कोई वस्तु नहीं है जो ईश्वर की शरण न लेती हो। “आप संप्रभु हैं, और\nहम सब आपकी प्रजा हैं, आप शरण हैं और हम आश्रित हैं” अर्थात् अर्जुन\nउन्होंने कृष्ण को 'परन्धम' कहा। भक्तिमय देवता किसी न किसी रूप में हमें आश्रय देते हैं\nपरन्तु भगवान परान्धम ऐसे देवताओं के आश्रय हैं। सभी जीवित चीजें\nअनंत यात्रा में आश्रय बनकर बचाने वाले भगवान सर्वाश्रयधाता हैं।\n\nभगवान 'पवित्र' हैं. ऐसे भगवान हम पवित्रता के प्रतीक अग्नि के समक्ष हैं\nहम पूजा करेंगे. अग्नि स्वयं पवित्र है और कभी गंदी नहीं होती। उसके स्पर्श से अग्नि\nआने वाली सामग्री को रोगाणुहीन बनाता है। भगवान हमें और दुनिया को आशीर्वाद दें\nसर्वोच्च शक्ति\n\nअर्जुन यहां वह परब्रह्म है जो उसके सभी शारीरिक संबंधों से परे उसके सामने खड़ा है\nदेख रहा है \"मैं गंदगी से भरा हूं, ईर्ष्या और अधीरता से भरा हूं। आपकी कृपा से, आपके आश्रय से।\"\nमुझे पवित्र होना चाहिए. मुझे उस ऊँचाई तक पहुँचना है और तुमसे अपनी पूर्णता प्राप्त करनी है\nअर्जुन के इस सम्बोधन में ही इच्छा निहित है।\n\nकभी-कभी हम गुस्से में आकर जरूरत से ज्यादा बातें कर बैठते हैं। इधर अर्जुन स्वयं घबराये हुए हैं\nवह सुनिश्चित करता है कि वह बात नहीं कर रहा है। यह एक अभ्यासी के लिए भगवान की पूजा में है\nबहुत महत्वपूर्ण बिंदु. क्योंकि ईश्वर के बारे में हम जो भी कल्पना करते हैं वह मात्र एक भ्रम है\nअहसास नहीं. हमारी कल्पना हमारी मनःस्थिति पर निर्भर करती है। मन में जोश\nजब भी कोई बात होती है तो नए-नए विचार आते हैं। उनमें से सभी सच नहीं हैं. तो\nयह उनकी बुद्धि के स्तर के अनुसार उनकी कल्पना है, लेकिन हमारा ईश्वर जैसा है वैसा ही है\nकोई अनुमान नहीं। इस कारण अर्जुन के यहाँ आने का विचार उसकी बुद्धि का विचार नहीं था\n\nवह सुनिश्चित करता है कि यही मामला है। देवर्षिनारद ने कहा, वह खुश हैं\nउन्हें यहां का भाषण याद है.\n\nअर्जुन कहते हैं, “ये महात्मा आपको पुरुष, सवः, दिव्यः, आदिदेवः अजः, विभुः कहते हैं।\nउन्होंने कहा. यहां प्रयुक्त प्रत्येक शब्द में ईश्वर का अनंत गुण छिपा हुआ है।\nविष्णुसहस्रनाम में हम इन सभी शब्दों को भगवान के नाम के रूप में पाते हैं। चलो, यहाँ\nआइए इन शब्दों के अर्थ पर संक्षेप में चर्चा करें:\n\nपुरुष: यहां पुरुष का मतलब पुरुष नहीं है। जो पुर में रहता है वह 'पुरुष' है। संपूर्ण\nवेदों के सर्वोत्कृष्ट सूक्तों के राजा 'पुरुषसूक्त' भगवान को \"सहस्र शीर्ष पुरुषः\" कहते हैं।\nसृष्टि के निर्माण के समय, जब कुछ भी नहीं था, ईश्वर ने इस सृष्टि की रचना की\nपुरा*शाह. भगवान पुर-उषा जिन्होंने जलप्रलय के दौरान सब कुछ जला दिया। संसार में अनंत, अनंत\nभगवान पुरा-साहा, जो समय, अनंत क्षमता, अनंत गुणों से भरे हुए हैं। बाढ़ के दौरान कुछ भी नहीं\nभगवान जो वहां नहीं थे, उन्होंने सृष्टि के समय सबसे पहले प्रत्येक को अपनी नाभि से बनाया\n\"महत्व\" बनाया। महत्व संपूर्ण विश्व का आध्यात्मिक जागरण है। अतीत में था\nसमस्त सृष्टि की स्मृति को सूक्ष्म रूप जगत के प्रेमी ब्रह्म-वायु को देना\nनिर्माण फिर देवों, पंचभूतों की रचना। इस प्रकार सकल का निर्माण हुआ\nभगवान ने ब्रह्मांड को भर दिया। प्रत्येक पिंड के भीतर एक रूप में छवि\nइसे प्रपत्र में भरकर उस पिंडदान से जो कर्म करना हो वह करो, जिससे मोक्ष मिलेगा\nभगवान पुरुष. इस प्रकार सृजन से पहले, सृजन के दौरान, निर्मित पदार्थ के भीतर, सृजन का\nप्राप्ति में, प्राप्ति से मुक्ति तक, यह हृतकमल, मध्यस्थ भगवान, सर्वत्र व्याप्त हैं।\nपूर्ण षड्लूनों से परिपूर्ण ज्ञानानंद स्वरूपा। पु-रु-शाह-पुरुष;; यहाँ 'पु' का अर्थ है\nपवित्र वह जो हमें पवित्र करता है। संसार की सभी ध्वनियों में से 'रु' का अर्थ 'रुवंती' है\nजो पढ़ा हुआ हो। 'शह' या 'सह' का अर्थ है सार्वभौमिक सिद्धांत जो सभी चीजों में व्याप्त है।\nइस प्रकार, भगवान का नाम पुरुषः कई तरीकों से भगवान का आह्वान करने के लिए उपयोग किया जाता है\nनाम.\n\nशाश्वत: शाश्वत, अनंत समय में अपरिवर्तनीय\nआनन्दस्वरूपा भगवन्ता सवस्ताः।\n\nदिव्या: दिव्या शब्द के कई अर्थ हैं। मूल रूप से दिव्य या 'भगवान' ये शब्द हैं 'दिवु'\nतत्त्व से व्युत्पन्न. प्राचीन धातु पाठों में इस धातु के सात अर्थ देखे जा सकते हैं;\nवे हैं: 1) ध्युति 2) विजिगीषा 3) कांति 4) स्तुति 5) व्यापार 6) खेल 7) गतिषु।\n\n1) ध्युति: ध्युति का अर्थ है प्रकाश का रूप। सूर्य, जो प्रकाश का स्रोत है, चंद्रमा के लिए प्रकाश है\nप्रभु हमें ज्ञान के प्रकाश से भर देते हैं।\n\n2) विजिगीषा: भगवान सर्वोच्च और विजय स्वरूप हैं।\n\n3) कांति: जो केवल इच्छा से सृजन कर सकता है। जिसने हमें इच्छा दी है और यह उसका है\nयोग्यता के अनुसार पूर्ति.\n\n4) स्तुति: जिसकी सभी प्रशंसा करते हैं; जिसकी हर कोई तारीफ करता है, वही बुलंद आवाज बन जाता है\nप्रभु.\n\n5) व्यवसाय: वह जो संसार के समस्त व्यवसाय का संचालन करता है।\n\n6) खेल: सृजन-स्थिति-संहार यह भगवान के लिए एक खेल है।\n\n7) गतिषु: गति और ज्ञान देने वाले भगवान। जो हर जगह रहा है; सब कुछ जानता है;\nवह जो सबके भीतर बिम्बा के रूप में निवास करता है वह दिव्य या 'देव' है।\n\nआदिदेवः: जिनके लिए इस संसार की उत्पत्ति-स्थिति-संहार ही लीला है, वे आदिदेवः हैं। प्रभु यह\nवह जो तब भी मौजूद रहता है जब दुनिया मौजूद होती है और जब यह मौजूद नहीं होती है। वह सबसे ऊपर है. सब\nवह वही है जो समय में भी संसार के सभी कार्यों का संचालन करता है। इस प्रकार सब कुछ भीतर है, सब कुछ\nभगवान आदिदेव जो कर्मों का आचरण करते हैं।\n\nअजः 'न जायते इति अजः; 'जा' का अर्थ है जन्म; अ*जाह-अजाह का अर्थ है अजन्मा। अजन्मा\nनाभि में उत्पन्न चतुर्मुख को अजा कहा जाता है। ऐसे चतुर्भुज के भीतर अन्तर्निहित, सृष्टि\nवह ईश्वर जो बिना जन्में ही सृष्टि करता है, सब कुछ बनाता और नष्ट करता है। सब लोग\nभगवान के बच्चे, लेकिन उनका जन्म किसी से नहीं हुआ। क्योंकि उसका कोई जन्म और मृत्यु नहीं है।\nअजः का अर्थ सर्वव्यापी भी है। अ*जा-अजाह. यहां 'ए' का मतलब 'नहीं' है।\nया नहीं! यानी वह ऐसी चीज़ नहीं है जिसे हम जानते हों. उसमें कोई दोष नहीं है.\nदूसरे अर्थ में अजः का अर्थ है वह जो किसी से पैदा नहीं हुआ है - बल्कि सभी में पैदा हुआ है!\nक्या आपका मतलब इसके विपरीत है? हाँ, ईश्वर किसी से जन्मी कोई चीज़ नहीं है। लेकिन छवि\nवह हर गर्भ में एक रूप में निवास करता है और एक साथ कई रूपों में जन्म लेता है।\nगर्भवती स्त्री के गर्भ में भगवान एक छवि के रूप में जन्म लेते हैं।\n\nविभु: वैश्य-भवति- का अर्थ है विभिन्न रूपों में मानवरूपी व्यक्ति। पूरी दुनिया में सर्वशक्तिमान\nभगवान विभु से परिपूर्ण.\n\nयहां अर्जुन ने विशेष रूप से देवर्षि नारद, असित-देवल और व्यास के नामों का उल्लेख किया है।\nक्योंकि अर्जुन ने उसे देखा था और भगवान के बारे में बात करते हुए सुना था। नारद\nहम उस महान ज्ञान को जानते हैं। देवभेद में वे चौदहवें हैं\nवे सीढ़ियों पर हैं. जब धर्मराय के दरबार में भगवान की अग्रपूजा आयोजित की गई तो उन्होंने आकर प्रार्थना की\nभगवान का आनंद. स्नायु समुदाय में अज्ञान का नाश करो, ईश्वर का ज्ञान करो\nनारद दाता हैं, अंतर्ज्ञान की देवी (181107) जो हमें सत्य से अवगत कराती हैं। आज्ञा का पहिया\n\nजागृत होने पर हमें नारद के दर्शन होते हैं। क्या करें, क्या करें\nजो सहज भाव से उत्तर देते हैं कि ऐसा नहीं करना चाहिए। असित-देवता\nवैदिक काल के आनन्द द्रष्टा के रूप में। उसने धर्मरायण की सभा में आकर उससे कहा\nअर्जुन ने उन्हें उपदेश देते देखा था। अब और नहीं व्यास: वेदों को विभाजित करें, हमारे लिए\nभगवान के अवतार जिन्होंने अठारह पुराण, महाभारत, पंचवेद दिये। “ये सब\nअर्जुन कहते हैं कि आप मुझे वही बता रहे हैं जो महात्मा ने कहा था। इस प्रकार\nअर्जुन यह सुनिश्चित करता है कि वह जो अनुभव कर रहा है वह सिर्फ एक भ्रम नहीं है।",
  "10.26": "अश्वत्थः सर्व वृक्षानां देवर्षिणां च नारदः |\n\nगंधर्वनं चित्ररतः सिद्धनं कपिलः मुनिः - सभी वृक्षों का पुष्पित वृक्ष।\nमैं हूँ।\nमैं ख़ुशी से संतुष्ट नहीं हूँ. [नारा: नारा की सभी इच्छाओं के दाता के रूप में, उन्हें ``नारद'' कहें\nमैं नारद में हूं।] मैं गंधर्वों का स्वामी चित्ररथ हूं। [छवि:-आचार्य, रथ-तेरी में चलते हुए\n'चित्ररथ'. एनीस. मैं गंधर्व राजा के रथ पर हूं।] योगसिद्धों में [का-सुखरूप के रूप में,\nदलाली करके, और चापलूसी करके] मैं कपिल मुनि हूं।\n\nकृष्ण कहते हैं: \"सभी वृक्षों में मैं अश्वत्थ हूं\"। अश्वत्समरा आज अवलोकन में\nदेखने वाले के लिए कोई उपयोग का पेड़ नहीं. यदि प्रभु ने इस वृक्ष को महत्व न दिया होता\nहमें इस पेड़ के बारे में कुछ नहीं पता था. आओ हम इस वृक्ष का फल खाएँ,\nएक सुगंधित फूल भी नहीं. इस लकड़ी से फर्नीचर नहीं बनाया जा सकता.\nव्यापक रूप से बढ़ता हुआ और आसपास के क्षेत्र पर कब्जा करने वाला यह पेड़ जाहिर तौर पर लोगों के लिए एक जंगल है\nदेने वाला पेड़! लेकिन यहाँ कृष्ण कहते हैं: \"वृक्षों के समुदाय में सबसे महान वृक्ष अश्वत्थ है\"। क्यों\nइस पेड़ का महत्व क्या है, यह जाने बिना ही आज हम इसकी पूजा करते हैं\nकुछ लोग इसे नजरअंदाज कर देते हैं. इस पेड़ को घर से दूर लगाना चाहिए क्योंकि यह सौभाग्य लाता है\nकहीं मन्दिर में पेड़ लगाने वाले भी हैं। आज ज्यादातर लोग इस पेड़ का महत्व नहीं जानते हैं।\nबरगद, अरली और अत्ति इन तीन वृक्षों को प्राचीन लोग बहुत महत्व देते थे। [बेंद्रा का\nउनके बगीचे में उगे इन तीन पौधों को देखिए- “हमारे बगीचे में तीन भगवान हैं\nयहां बनंजय को याद है कि उन्होंने दिल से कहा था कि वह फॉर्म में आए हैं]।\nपूर्वकाल में यज्ञ के समय शमी और अरणी (अरली) समिता को मथकर उससे अग्नि प्रज्वलित की जाती थी।\nतारसी आग पैदा करती थी. अरली समिता का प्रयोग मुख्य रूप से यज्ञ में किया जाता है।\nअश्वत्थामा समित का प्रयोग यज्ञ में, वहां जलने वाली अग्नि का, शायद ही किया जाता हो\nलौ से एक अनोखी ऊर्जा निकलती है. जैसे सूर्य की किरणों में सात रंग होते हैं\nअग्नि में सात रंग हैं। मुंडका उपनिषद में, काली, आग की लौ के सात रंग,\nकराली, मनोजवाचा, सुलोहितायचा, सुधूम्रवर्ण, स्फुलिंगिनी, विश्वरुचि।\nअग्नि के इन सात रंगों को सूर्य की किरणों के सात रंगों के साथ समन्वयित करने को कहा है\nयज्ञ ही वायुमण्डल में अपना प्रभाव लाता है। इस क्रिया के लिए अश्वत्सस्मिता एक महत्वपूर्ण उपकरण है।\n\nआज, कई लोगों के पास अश्वत्थामा में देवता की उपस्थिति है। वे इसके पास आते हैं।\nज्योतिषियों का कहना है कि अश्वत्थ प्रदक्षिणा तब आती है जब संतान न हो। पता नहीं ऐसा क्यों है\nलोग इन सब बातों को अंधविश्वास कहकर बात करते हैं. दुनिया के सभी पेड़ों से भी ज्यादा\n\nऑक्सीजन देने वाला वृक्ष अश्वत्थ है। ऐसी शुद्ध हवा में सांस लेने से पेट के दोष ठीक हो जाते हैं\nआज विज्ञान भी यह स्वीकार कर चुका है कि ऐसी सम्भावना है। पूर्वकाल में खुशियाँ अश्वत्थ वृक्ष की थीं\nवह पैर के पास बैठकर वेदों का अध्ययन करते थे। इस प्रकार भगवान की विशेष विभूति अश्वत्थ वृक्ष में है\nपेड़ को ऐसी कई विशेष शक्तियां दी गई हैं।\n\nयहाँ भगवान का नाम *'अश्वत्थचः'' है। वेदों का उपदेश करने वाले भगवान के विशेष\nघोड़े के रूप में अवतार हयग्रीव है। 'अश्वत्थ' भगवान को संदर्भित करता है जो घोड़े की तरह थे और वेदों का प्रचार करते थे।\nकहा जाता है\n\nकृष्ण आगे कहते हैं \"देवर्षिणं च नारदः\"। नारद के गंधर्वों में से एक। लेकिन\nभगवान की विशेष उपस्थिति से वह बहुत ऊंचाई पर पहुंच गये और देवर्षि बन गये। नारद जी\nबड़ी उपलब्धि से प्राप्त हुआ। पिछले ब्रह्मकल्प में नारद का जन्म एक गरीब परिवार में हुआ था। उसका\nमां खुशी-मुनिगल आश्रम में रहकर काम करती थीं। वह एक छोटा बच्चा था\nख़ुशी का आध्यात्मिक संवाद सुनकर बड़ा हुआ। जब वह पांच साल का था तो उसकी मां एक सांप थी\nवह काटती है और मर जाती है। जैसा कि जानने वाले कहते हैं- \"हमें यह बताने के लिए कि भगवान \"नाथ\" हैं।\nभगवान सबसे पहले हमें 'अनाथ' बनाता है''।\nइसी साल से वह खुशी से प्राप्त ज्ञान से उपलब्धि हासिल करना शुरू कर देता है। लेकिन उस जन्म में उसके लिए\nप्रभु के दर्शन नहीं होंगे. लेकिन उसने भगवान की आवाज 'सुनी'। “मैं इस जीवन में\nदेखने की कोशिश मत करो. अगले कल्प में तुम सदैव मुझे देखोगे।” फिर उसने कहा\nउन्होंने ब्रह्मकल्प में नारद के रूप में जन्म लिया और भगवान की महान कृपा प्राप्त की।\n\nनारद हमारे अंतर्ज्ञान की प्रशंसक देवी। जैसा कि अतीत की कहानियों में देखा गया है\nअगर कुछ अच्छा करना होता तो नारद आकर बताते। उदाहरण के लिए\nयह नारद ही थे जिन्होंने वाल्मिकी को रामायण लिखने के लिए कहा था। यहां हमारा एक प्रश्न है.\nअब नारद क्यों नहीं आ रहे, हमें मार्गदर्शन क्यों नहीं मिल रहा। हम नारद हैं\nबुलाएँगे तो आज भी ज़रूर आएँगे! \"नारद' का अर्थ है हमारी आंतरिक आवाज (1!t1073 11850)।\nयदि हम अपनी आत्मा की पुकार सुनेंगे तो नारद वहीं बोलेंगे। हम अपने भीतर हैं\nयदि हम संदेश सुनने का अभ्यास करें तो हमारा अचेतन मन खुल जाता है। इससे 'इस तरह\nएक संदेश (01/116 !1955899) दिखाई देगा। यह अशरीरवाणी या अन्तर्वाणी है। यही तो है\nनारद. भले ही उन्हें देखा न जा सके, फिर भी उन्हें सुना जा सकता है। यह सारी अनोखी शक्ति नारद को है\nयह परमेश्वर की विशेष उपस्थिति से आया है।\n\nयहां भगवान का विभूतिनाम \"नारदः\" है। नारा (नारा-ध्याति) की अज्ञानता को दूर करते हुए, उन्होंने\nभगवान नारद स्नानकर्ता (नारा-ददाति) हैं।\n\nनारद के बाद कृष्ण ने गंधर्वों में अपनी विशेष विभूति बताई। कृष्ण कहते हैं\n\"मैं गंधर्व की छवि हूं।\" उपदेवता गण जो संसार के सेवक के रूप में कार्य करते हैं\nगंधर्व. ये संक्रमण के देवता हैं. इस गण के राजा चित्ररथ हैं। \"राजा साक्षात् देवता है\"\nऐसा कहा जाता है कि भगवान चित्ररथ में विशेष विभूति के रूप में विद्यमान हैं। यहाँ आये\nभगवानं विभूतिनामा 'चित्ररथ:'। विचित्र रथ वाले भगवान चित्र के समान हैं। भगवान का वाहन-\nगरुड़. यह बाकी सभी गाड़ियों से अलग है. ऐसे रथ में भगवान का चलना एक चित्र के समान है।\nकृष्ण कहते हैं \"सिद्धानं कपिलो मुनिः\"। इतिहास में दो कपिलमुनि दिखाई देते हैं।\nदोनों ने सांख्य कहा। लेकिन जो ईश्वर को नहीं मानता. तो यह यहाँ है\nकपिलमुनि-कपिला वासुदेव। सांख्य मूलतः संसार को देने वाले भगवान के अवतार थे।\nस्वायम्भुव मनु की कन्या देवभूति और कर्दम प्रजापति का विवाह\nभगवान का एक अवतार जो प्रकट हुआ। वेदव्यास ने कपिल ने जो कहा था उसे भी हमारे सामने प्रस्तुत किया\nसंसार को नवीनता देने वाले भगवान का अवतार \"कपिलवतार\" है।\n\nयहां भगवान का विभूतिनाम \"कपिला' है। का-पी-ला; वह जो पूरी दुनिया का पालन-पोषण करता है), और\nलयवर्ण (ला), आनंदमूर्ति (का) भगवान कपिला। सदैव पीने वाला आनंद,\nभगवान \"कपिला\" जिन्होंने अद्भुत अंक के माध्यम से संसार का रहस्य उजागर किया।\n\nख़ुशी, ब्रह्मर्षि, देवर्षि, महर्षि आदि ब्रह्म तेजस्सु और वेदाध्ययन करते हैं,\nतपस्या, यज्ञ-सबकुछ के बारे में बात करने के बाद, कृष्ण अगले श्लोक में क्षात्र तेजस के बारे में बात करते हैं।\nउचेस्रवसमाश्वनं विधि मामामृतोद्भवम्.|\nछी भी\n\nऐरावतं गजेंद्रं नाराणं च नाराधिपम्",
  "10.23": "रुद्रानां संकरः च अस्मि वित्त ईशाः यक्षरक्षासम् |\n\nवसूनं पावकः च अस्मि मेरुः शिखरिनं अहम्-रुद्रस [ग्यारह] प्रमुख रुद्र हैं।\nमैं [शाम-सुख के प्रति करुणा के कारण शंकर में ``शंकर'' हूं।] यक्ष-रक्षासार\nबल का स्वामी कुबेर है (विट्टा-सिरी, ईशा-ओडेय, तथाकथित 'विट्टेशा' कुबेर में है।\nयक्ष-राक्षस के स्वामित्व में] मैं हूं। मैं [आठ] वसुओं में अग्निदेव हूं।\n['पावक' का मतलब पावना से 'पावक' है। मैं अग्नि में हूं।] मैं चेलुकोडी की पहाड़ियों में मेरु हूं।\n[मैं मेरु गिरि में \"मेरु\" के रूप में इरु-दूसरे मकसद के कारण हूं, मा-था।]\n\nमन में अपनी विभूति की बात करने वाले कृष्ण यहां मन के प्रशंसक शिव में हैं\nविभूति बताते हैं. कृष्ण कहते हैं: \"रुद्रों में शंकर सानु हैं\"। रुद्र ग्यारह हैं\nलोग रायवत, ओज, भव, भीम, वामदेव, उग्र, वृषाकपि, अजैकपथ, अहिर्बुद्दी, विरुपाक्ष,\nऔर महादेव, गणप्रधान के भगवान। (इन एकादश रुद्रों के अनेक नाम हैं।\nउन्होंने अलग-अलग स्थानों पर अलग-अलग नामों का उल्लेख किया है)। 'रुद्र' जो हमारे मन को नियंत्रित करता है-\nमहादेव या शिव. उनका नाम 'शंकर' है। रुद्र का अर्थ है रोदयति इति रुद्र-दुःखः\nइसका मतलब है देने वाला. भगवान केवल दुष्टों को ही दुःख देते हैं। दूसरे अर्थ में\nदेखा जाए तो- रुजं द्रवयति इति रुद्र: यानी हमारे अंदर की बीमारी को ठीक करो\nसुख देने वाला। मूलतः यह रोग मानसिक है। यदि हमारा मन मजबूत होगा तो हम बीमार नहीं पड़ेंगे।\nयदि आपमें यह दृढ़ संकल्प है कि यदि कोई बीमारी आती है तो आप उसका मुकाबला कर सकते हैं - उस बीमारी पर ध्यान दें\nइलाज योग्य.\n\n'शंकर' का अर्थ है खुशी, खुशी देने वाला। जीवन में स्वस्थ शरीर का बहुत महत्व है\nमहान् सुख किसी भी अच्छे कर्म को करने के लिए स्वस्थ शरीर की आवश्यकता होती है। 'रुद्र'\nशरीर पुरुष यदि इस शरीर को खड़ा होना और चलना है, तो यह शिव शक्ति के कारण है जो शरीर में शरीर पुरुष है। हमारा\nमन में बैठो और मानसिक अशांति दूर करो, स्वस्थ शरीर दो, सुख दो\nरुद्र दाता हैं। खुग्वेद शिवस्तुति में शिव की स्तुति \"भिषक्तं त्वा भिषजम्\" कहकर की गई है।\nइसका मतलब है \"आप डॉक्टरों के डॉक्टर हैं\"। इसी कारण शिव को 'वैद्यनाथ' भी कहा जाता है।\nरुद्र को महादेव क्यों कहा जाता है इसके कई कारण हैं। यहां 'देव' का अर्थ है इंद्रिय\nदेवं इन्द्रियम्)। शिव सभी कामुक देवताओं में सबसे महान हैं। देवता\nविवेक से देखा जाए तो - यदि ग्यारह में से दस रुद्र अठारहवीं कक्षा में हों।\n\nपाँचवीं कक्षा में शिव उससे कहीं अधिक ऊँचे हैं। भगवान शिव के संहार कर्म में\nएक बहुत बड़ी शक्ति जो वायु देव की सहयोगी के रूप में सहायक है। भगवान शंकर\nनमक के रूप में शिव में खड़े हैं। हमें भगवान, भगवद की आराधना के मार्ग पर ले जाना\nरुद्र वह है जो मन को बोध के लिए प्रशिक्षित करता है। तो यह भगवान की बहुत बड़ी कृपा है\nविभूति\n\nयहाँ भगवान का विभूतिनाम \"शंकरः\" है। \"शम\" का अर्थ है ख़ुशी, \"कारा\" का अर्थ है दयालु।\nआत्म-आनंद आत्म-आनंद का एक रूप है, जो दुखी संसार की निंदा करता है- जो हमें मुक्ति देता है\nभगवान \"शंकरः\",\n\nकृष्ण ने भगवान शिव के बारे में कहा कि वे हमारे लिए आंतरिक धन के प्रशंसक हैं, फिर बाहरी धन के\nकोडुवा ने कुबेर में अपनी विभूति का वर्णन किया है। हमारा शरीर एक प्रशंसक और बाहरी है\nफैन कुबेर. उनके शासन में यक्ष और राक्षस हैं। यक्ष का अर्थ है तंत्रिका\nजो लोग निर्दयतापूर्वक मांस खाते हैं। राक्षस यक्षरियों से बेहतर हैं। लेकिन ये भी\nक्रूर. हमें उनसे अपनी रक्षा करनी होगी.\n\nयहां भगवान का विभूतिनाम 'वित्तेशा' है। विट्टा का अर्थ है सिरी, ईशा का अर्थ है मालिक। प्रभु\n\"वितेश\" कुबेर में था, जिसने उसे यक्ष-राक्षस का अधिकार दिया और उसे बाहरी बना दिया।\nउसे धन-संपत्ति का स्वामी बना दिया। यह कुबेर में भगवान की विशेष विभूति है।\n\nवेदों में देवतागण पर विचार करें। करते समय आदित्य-वसु-रुद्रगण तीन हैं\nवे एक साथ आते हैं. यह भी तीन सत्रों में भगवान को दिया जाने वाला प्रसाद है\nमंदिर में भगवान के लिए. भगवान के अष्टवास में रहने के लिए प्रातःकाल में अष्टाक्षर\nगायत्री मंत्र से आहुति दी जाती है। मध्याम की एकादश का संबंध रुद्र से है।\nइसके लिए यहाँ एकादश अक्षर 'त्रिष्ठुप' का प्रयोग किया गया है। द्वादशादित्यों का सायंकालीन सत्र\nसे संबंधित इसके लिए वे दोहरे अक्षर \"जगति\" कृष्ण आदित्य और रुद्र का उपयोग करते हैं\nके बारे में कहा. अब यहां वसुओं के बारे में बोलते हुए, वे कहते हैं: \"वसुओं में, 'अग्नि' मैं हूं।\" वसुस\nआठ लोग. द्रोण, प्राण, ध्रुव, अर्क, अग्नि दोष, मध्य और विभावसु। उसके पास और भी बहुत कुछ है\nएक नाम है. पांचवें अग्नि में वैश्वानर, वह्नि, जातवेद, हुताशन, पावक, अनल, दहन है।\nआदि का नाम दिया गया है। यदि अन्य सभी वसु देवता भेद में अठारहवीं कक्षा में हैं तो 'अग्नि'\nवह उनसे ऊँची पंद्रहवीं कक्षा में है। भुस्त्र में भगवान का सबसे बड़ा उपासक\nप्रतीकात्मक अग्नि. भगवान अग्नि, वह शक्ति जो संपूर्ण विश्व को पवित्र करती है, 'पावकः' नमक के रूप में\nकुतु ने उन्हें यह महान पद दिया।\n\nअग्नि में भगवान का तेज है। चमक में प्रकाश की शक्ति है, ऊष्मा की शक्ति है। और\nइसमें दाहक शक्ति भी होती है. इसके अलावा इस तेज में पाचन शक्ति भी होती है। वह पदार्थ जो अग्नि के संपर्क में आता है\n\nपावन बन जाता है. अग्नि में ही वह भगवान है जिसने अग्नि को ऐसी प्रतिभा दी, वह संसार को पवित्र करेगा\nपापी. जो भगवान सबको पवित्र करते हैं, वे देवताओं के भी अवाक (रक्षक) हैं।\n\nमेरु पर्व में पृथ्वी पर धन के निवास कृष्ण से पहले वित्तेश कुबेर के बारे में बताया गया है।\nविभूति बताते हैं. मेरु पर्वत को हेमाद्रिचिन्नादा बेट्टा कहा जाता है)। बस इतना ही\nवसुओं का निवास. कृष्ण कहते हैं: \"पहाड़ियों में मैं मेरु हूं\"। हिमालय में एक पर्वत\nस्वामीराम ने रैंक में धन के बारे में कहा, जिसे केवल मनुष्य ही जानता है, “64176 50\n11111818)/97 1251975” ने पुस्तक में अपना अनुभव साझा किया। युद्ध में\nजब संपूर्ण धन नष्ट हो जाता है तो धर्मराय पर्वत श्रृंखला में गड़े धन को लाकर उसका त्याग कर देते हैं\nमहाभारत में कहा गया है कि उन्होंने ऐसा किया। यह हिमालय में तपस्या की कुछ प्रथाएँ हैं\nयोगी भी जानते हैं. मेरु ऐसे धन का घर है.\n\nयहां भगवान का विभूतिनाम मेरुः है। मा*मेरु-मेरु. सर्व भाव से सर्व\nभगवान महान माता महालक्ष्मी के प्रेरक भी हैं। ऐसे भगवान के लिए\nकोई अन्य प्रेरणा नहीं है. अतः \"मेरुः\" भगवान का एक उपनाम है।\n\nपुरोधसं च मुखं माम् विद्धि पार्थ बृहस्पतिम् |\n\nसेनानिनामहम् स्कन्दः सारसमासि सागरः",
  "11.16": "अनेक बाहु-उदर-मुख-नेत्र वाले; सर्वत्र अनन्तरूप आपको देखता हूँ। हे विश्वेश्वर, हे विश्वरूप — न अन्त, न मध्य, न आदि देखता हूँ।\n\nविश्वेश्वर विश्वरूप — दोनों नामों से भगवान् की सम्पूर्णता कही। अनन्तरूप — सर्वदिशाव्यापी — आदि-मध्य-अन्तरहित। यह अनन्तता भगवान् का नित्यस्वभाव है।",
  "11.14": "तब विस्मय में डूबे, रोमाञ्चित धनञ्जय ने देव को शिर से प्रणाम कर, कृताञ्जलि हुए बोले।\n\nविस्मय-हर्ष-भय-भक्ति — सभी एकसाथ। रोमाञ्चित — भक्त के भगवद्दर्शन का स्वाभाविक भाव। धनञ्जय — विश्वरूपदर्शनरूपी धन पाने वाला।",
  "11.9": "संजय उवाच —\nहे राजन्, इस प्रकार कहकर महायोगेश्वर हरि ने पार्थ को परम ऐश्वर रूप दिखाया।\n\nसंजय — व्यास द्वारा प्रदत्त दिव्यदृष्टि से — स्वयं भी विश्वरूप देखता है, इसीलिए प्रत्यक्षदर्शी की तरह वर्णन करता है। 'महायोगेश्वर' — समस्त योगशक्तियों के ईश — यह विशेषता भगवान् की ही है।",
  "11.3": "एवमेतद्यथात्त्वमात्मानं परमेश्वर ।\nद्रष्टुमिच्छामि ते रूपमैश्वरं पुरुषोत्तम ॥\n\n'हे परमेश्वर, जैसा आप अपने विषय में कहते हैं वह सत्य है' — अर्जुन श्रद्धावान् है।\n\nकिन्तु — ऐश्वर रूप — जगत् के ईश्वर का परमरूप — देखना चाहता हूँ। पुरुषोत्तम — क्षर-अक्षर से परे — इस संबोधन से भगवान् का सर्वोत्तमत्व स्वीकृत है।",
  "11.12": "यदि आकाश में एकसाथ हजार सूर्य उदय हों — वह प्रकाश उस महात्मा के प्रकाश के समान हो भी सकता है या नहीं।\n\nभगवान् का तेज सहस्र सूर्यों से भी अधिक — क्योंकि सूर्य का तेज भगवत्तेज से ही उत्पन्न है। ध्यानयोगी भगवान् को सहस्रसूर्यतेज के रूप में देखते हैं।",
  "11.15": "अर्जुन उवाच — हे देव, आपके शरीर में सभी देवों को, सभी भूतविशेष-समूहों को देखता हूँ। ब्रह्मा को ईश को — कमलासन पर बैठे — सभी ऋषियों को और दिव्य नागों को।\n\nब्रह्माणम् ईशम् — चतुर्मुख ब्रह्मा शिव की जाँघ पर बैठे हैं — क्योंकि शिव ब्रह्मा की जाँघ पर बैठते हैं, ब्रह्मा उनसे ऊपर। तारतम्यसहित समग्र सृष्टि का दर्शन।",
  "11.13": "उस समय पाण्डव ने देवदेव के शरीर में अनेक प्रकार से विभक्त समग्र जगत् एकत्र देखा।\n\nमध्वाचार्य के मत में — उस विश्वरूपदर्शन के समय त्रिलोकों में सभी अर्हत् जीवों ने एकसाथ दर्शन किया — केवल अर्जुन को नहीं। 'देवदेव' — देवों के भी देव — इससे भगवान् की परमत्व सिद्ध होती है।",
  "11.26": "धृतराष्ट्र के सभी पुत्र — सब राजसमूहों के साथ — आपके मुखों में प्रवेश कर रहे हैं।\n\nकाल निरपेक्ष — न कुलभेद, न पक्षभेद। भगवान् कालपुरुष — सभी को समान भाव से स्वीकार करते हैं।",
  "10.35": "बृहत्सं मा तथा समं म गायत्री छंदसम अहम्।\n\nमसानम मार्गशीर्ष अहं खुतुनम कुसुमाकरः - साम गीतों में सबसे महान।\nमैं सामा का गीत हूं. [सर्वव्यापी होने के नाते, स-सर्वस्तु और, अमा-समझदार।\n\"मैं 'बृहत्साम' सी बृहत्साम 1 में हूं। छंदों में मैं गायत्री हूं। [गया''\nमैं गायकों के त्रय के कारण गायत्री छंद में \"गायति\" के रूप में हूं]।\nमुझे ['हेडिंग'' कहा जाता है क्योंकि यह सड़क के अंत में है। मैं मार्गशिरामाहा में हूं।]\nमैं पत्रों में बसंत हूं. [कु:बुरा, सु-अच्छा, मा-ज्ञान, कर-देता है \"कुसुमाकर\"\nएन्निसी वसंत खुथु में है।]\n\nसामान कई प्रकार के होते हैं. सप्त स्वर का प्रयोग कर गायन केवल सामवेद में है। यह खुग्वेद है\nयजुर्वेद में नहीं. सभी समास में सप्तस्वर का कोई उपयोग नहीं है। इस तरह सप्पास्वरा के साथ एक समा में\nकृष्ण कहते हैं, \"मैं बृहत्साम का गीत हूं।\" यहाँ भगवान का नाम \"बृहत्समः\" है\nवह भगवान जो हमारे लिए व्यापक, सर्वोत्कृष्ट और समझ से बाहर है, वह \"बृहत्समः\" है।\n\nश्लोक के रूप में एक अनोखा अर्थ, आध्यात्मिक सन्देश से परिपूर्ण-\nतुकबंदी यह अपनी राय को लयबद्ध तरीके से व्यक्त करने का एक तरीका है। मुख्य रूप से छंदशास्त्र में\nछन्द सात हैं। 24 अक्षर गायत्री, 28 अक्षर उष्जिक, 32 अक्षर अनुष्टुप, 36 अक्षर\nबृहती, 40 अक्षर वाली पंक्ति, 44 अक्षर वाली त्रिष्टुप और। 48 अक्षर ब्रह्मांड. इन तुकबंदी में\n'गायत्री' वह छंद है जिसमें भगवान की विशेष विभूति है। यह भगवान का नाम भी है.\n\n'गायताम् त्रायते इति गायत्रीः। जो कोई इस मंत्र से भगवान की स्तुति करता है\nवह उनकी रक्षा करता है. गायत्री छन्द सात छन्दों में प्रथम छन्द है। आठ\nअक्षरा के तीन पैरों वाली गायत्री हर चीज के पंचांग (9m4768800) के समान है। अधिकांश खुग्वेद\nमंत्र गायत्री छन्द में हैं। गायति को सभी वेदों की 'वेदमाता' माना जाता है\nमंत्र \"गायत्री\" छंद में है। इस प्रकार गायत्री अन्य छंदों का जनक है।\nगायत्री एक मंत्र है जिसमें आध्यात्मिकता का मौलिक पहलू है। धूप में\nभगवान की स्तुति करो, सौर मंडल में हमारा जीवन-सिद्धांत, सौर ऊर्जा को हम तक पहुंचाना\nगायत्री करती है. \"सौर ऊर्जा से उत्पन्न सम्पूर्ण ब्रह्माण्ड का नियंता हमारी आत्मा है\nहमारे हृदय कमल में 'धी' शक्ति का योग है जो शक्ति भगवंत को प्रेरित करता है।'\nगायत्री चिंतन का मंत्र है। गायत्री का प्रयोग आमतौर पर वैदिक छंद (801050061/) के रूप में किया जाता है।\nइसका कोई सांसारिक उपयोग नहीं है. गायत्री की यह अद्वितीय स्थिति भगवान की विशेष विभूति से प्राप्त हुई।\n[एक बात जो हमें यहां जाननी चाहिए: ऐतरेय उपनिषद में बृहती चंदासनु महान है।\nऐसा कहा. इसका कारण यह है कि गायत्री को प्रशंसक देवता भेदभाव में देखा जाता है\nसंरक्षक देवता लक्ष्मी, सरस्वती, भारती, गरुड़ और अग्निपत्नी स्वाहा हैं। भारी तुकबंदी\nदेखा जाए तो लक्ष्मी, सरस्वती, भारती, गरूड़ और बृहस्वतिपत्नी तारा पूजक हैं।\nचूँकि अग्निपत्नी स्वाहा, देवता भेदभाव से तारा देवता भेदभाव में उच्च है\nवहां ऐसा कहना जरूरी है. यह जानने से कोई भ्रम नहीं रहता।]\n\nकृष्ण कहते हैं, \"मैं महीनों का मार्गदर्शक, चरणों का वसंत हूं।\" मार्गशिरामास-मास में\nपहला महीना; कार्तिक आखिरी महीना है. इस कारण कार्तिक मास (मार्गशिरा मास) में\nपहले) दिवाली मनाएं. कृतज्ञता के साथ एक वर्ष विदा कर रहा हूँ\nदिवाली का महत्व मार्गशिरा को आगरा-हयाना कहा जाता है। हयाना का मतलब महीना होता है. आगरा यानी\nपहला वाला. इस माह में हम गीता जयंती मनाते हैं। इस कृष्ण से लेकर अर्जुन तक\nजिस माह में इस गीत का उपदेश किया गया उसे मार्गशिरा भी कहा जा सकता है (इस पर और अधिक शोध होगा)\nज़रूरी)। इस माह में विभूति के रूप में विराजमान भगवान का विभूतिनामा 'मार्गशीर्ष' है। साधना\nवह प्रभु, जो उस मार्ग का सिरा है जिस पर हमें चलना है, वह \"मार्ग का मुखिया\" है।\nकृष्ण कहते हैं कि मैं वसंत ऋतु में 'कुसुमाकर' हूं, जब पेड़ उगते हैं। सबसे बुरे के लिए\nजो भगवान कुस्सितव हैं और सज्जनों को अच्छा ज्ञान प्रदान करते हैं, वे \"कुसुमाकरः\" हैं।",
  "11.17": "किरीटधारी, गदाधर, चक्रधर, तेजोराशि, सर्वत्र दीप्तिमान् — ज्वलदग्नि-सूर्यसम प्रभा वाले, अप्रमेय, दुर्निरीक्ष्य रूप देखता हूँ।\n\nकिरीट-गदा-चक्र — भगवान् के नित्य नाम-रूप। अप्रमेय — जिसका माप नहीं। दुर्निरीक्ष्य — जिसे सहकर देखना कठिन।",
  "11.11": "अनेकवक्त्र-नयनम्, अनेकाद्भुतदर्शनम्, अनेकदिव्याभरणम्, दिव्यानेकोद्यतायुधम् — भगवान् के प्रत्येक अङ्ग में एक-एक देवता का निवास है — यही अन्तर्यामित्व का दर्शन है।",
  "11.6": "देखो — बारह आदित्य, आठ वसु, एकादश रुद्र, दोनों अश्विनी, मरुद्गण — और हे भारत, देखो बहुत-सी ऐसी अद्भुत वस्तुएँ जो पहले कभी नहीं देखीं।\n\nसमस्त देवता भगवान् के विश्वरूप की विभूतियाँ हैं। भगवान् सर्वदेवान्तर्यामी — सब देव भगवान् के नियमन में हैं। तारतम्यक्रम — बृहस्पत्यादि उत्तम — सभी भगवन्मुख से सृष्ट।",
  "11.22": "रुद्र, आदित्य, वसु, साध्य, विश्वेदेव, अश्विनी, मरुत्, उष्मपा (पितर), गन्धर्व, यक्ष, असुर, सिद्धगण — सभी विस्मित होकर देख रहे हैं।\n\nसम्पूर्ण देवतारतम्य — विश्वरूपदर्शन के समय — विस्मय से खड़े हैं। तारतम्यक्रम में बृहस्पत्यादि उत्तम — सभी भगवान् के नियमनाधीन।",
  "11.19": "आदि-मध्य-अन्तरहित, अनन्तवीर्य, अनन्तबाहु, शशि-सूर्यनेत्र — ज्वलदग्निमुख, स्वतेज से समग्र विश्व को तपाते हुए आपको देखता हूँ।\n\nअनन्तवीर्यम् — असीमित शक्ति। शशिसूर्यनेत्रम् — चन्द्र-सूर्य जिनके नेत्र। दीप्तहुताशवक्त्रम् — प्रज्वलिताग्नि-सदृश मुख। भगवान् के गुण अनन्त — किसी का माप सम्भव नहीं।",
  "11.7": "मेरे इस शरीर में — एक स्थान में — सचराचर समग्र जगत् देखो। और जो कुछ और देखना चाहो — वह भी यहीं देखो।\n\nविश्वरूपदर्शन का महिमा — समग्र जगत् भगवान् के शरीर में दीखता है। मध्वाचार्य के मत में — उस दर्शन में त्रिलोकों में सभी अर्हत् जीवों ने एकसाथ दर्शन किया।",
  "11.20": "आकाश-पृथिवी के बीच का यह स्थान — तथा सभी दिशाएँ — आप अकेले से व्याप्त हैं। हे महात्मन्, आपका यह अद्भुत उग्र रूप देखकर तीनों लोक व्यथित हैं।\n\nभगवान् सर्वत्र एक — अनेक नहीं। एक का ही अनन्त व्याप्तन। उग्ररूप देखकर त्रैलोक्य में भय — किन्तु भक्त के लिए आनन्द।",
  "11.18": "आप अक्षर परम वेदितव्य हैं। आप इस विश्व के परम आश्रय हैं। आप अव्यय शाश्वतधर्मगोप्ता हैं। आप सनातन पुरुष हैं — ऐसा मेरा मत है।\n\nप्रत्येक पद में भगवान् के सर्वोत्तमत्व को अर्जुन स्वीकार करता है। अव्यय — विकाररहित। शाश्वतधर्मगोप्ता — सनातनधर्म के रक्षक। सनातनः पुरुषः — अनादिकालसिद्ध।",
  "11.21": "ये देवसमूह आपमें प्रवेश कर रहे हैं, कुछ भयभीत होकर कृताञ्जलि से स्तुति कर रहे हैं। महर्षि-सिद्धसमूह 'स्वस्ति' कहकर पुष्कल स्तुतियों से स्तव करते हैं।\n\nभय से और भक्ति से — दोनों प्रकार का भगवद्दर्शन। पापियों के लिए उग्र, भक्तों के लिए आनन्दप्रद — एक ही रूप का द्विविध अनुभव।",
  "11.24": "आकाशस्पर्शी, दीप्त, अनेकवर्ण, व्यात्तानन, दीप्तविशालनेत्र — आपको देखकर मेरी अन्तरात्मा व्यथित है — हे विष्णो, धृति नहीं पाता, शम नहीं।\n\nअन्तरात्मा व्यथित — धृति न विन्दामि — शम नहीं। 'विष्णो' — सर्वव्यापिन् — इस संबोधन में सार्थकता — जो सर्वत्र व्याप्त उसके उग्रदर्शन से सर्वत्र भय।",
  "11.28": "जैसे नदियों के बहुत से जलवेग समुद्र की ओर ही बहते हैं — वैसे ही नरलोक के ये वीर आपके ज्वलित मुखों में प्रवेश कर रहे हैं।\n\nपुण्यजीवों की गति — भगवन्मुखप्रवेश — नदी-सागर-संगम की तरह आनन्दमय। सागर में नदी विलीन — मोक्ष में जीव भगवान् में। किन्तु मोक्ष में अभेद नहीं — जीव-भगवान् भेद नित्य (द्वैत-मत)।",
  "11.29": "जैसे पतंगे प्रदीप्त ज्वाला में नाश के लिए वेग से प्रवेश करते हैं — वैसे ही लोग भी नाश के लिए आपके मुखों में प्रवेश कर रहे हैं।\n\nपतंगे भय से नहीं — आकर्षण से अग्नि में जाते हैं। पापी भी भय से नहीं — कर्मफल से भगवन्मुख में जाते हैं। प्रारब्धकर्म के नाश के लिए जीव भगवन्मुख में — यही काल का स्वरूप।",
  "11.33": "इसलिए उठो — यश प्राप्त करो। शत्रुओं को जीतकर समृद्ध राज्य भोगो। मैंने ही इन्हें पहले से मार दिया है — हे सव्यसाचिन्, निमित्तमात्र बनो।\n\nसव्यसाचिन् — उभय हस्त कुशल धनुर्धर। भगवान् का निर्णय पूर्वसिद्ध — युद्ध भगवत्कार्य — अर्जुन केवल माध्यम।",
  "11.27": "भयानक दंष्ट्राकरालानि मुखों में वे त्वरा से प्रवेश कर रहे हैं। कुछ दाँतों के बीच विलग्न — चूर्णित उत्तमाङ्गों सहित दिख रहे हैं।\n\nभीष्म, द्रोण, कर्ण — युद्धमरण का पूर्वदर्शन। अर्जुन भगवान् के मुख में विनाश देखता है। यही 'काल' शब्द का यथार्थार्थ — सर्वसंहार नित्य।",
  "11.30": "ज्वलित मुखों से सब ओर से समग्र लोकों को ग्रसते हुए चाट रहे हैं। आपका उग्र तेज जगत् को तेज से भरकर प्रतप रहा है — हे विष्णो।\n\nविष्णो — सर्वव्यापिन् — आपकी दीप्ति विश्व को जला सकती है। प्रलयकाल — भगवान् सब संहरते हैं — नई सृष्टि के लिए।",
  "11.23": "हे महाबाहो — आपका महान् रूप — अनेक मुख-नेत्र, बाहु-ऊरु-पाद, उदर, अनेक दंष्ट्राओं से भयानक — देखकर लोक व्यथित हैं, मैं भी।\n\nकरालम् — भयावह। अर्जुन स्वयं भी व्यथित। भगवान् के अङ्गाङ्गों में सृष्टिक्रिया — विराट्पुरुष का वर्णन — 'मुखं ब्राह्मणाः' — श्रुति के अनुसार।",
  "11.25": "कालानलसम भयावह दंष्ट्राकरालानि मुखानि देखकर — दिशाएँ नहीं जान पाता, शर्म नहीं मिलता। हे देवेश, हे जगन्निवास — प्रसन्न हों।\n\nदेवेश जगन्निवास — कृपा करें — एकमात्र शरण। नरसिंह के दंष्ट्रावली-सदृश विश्वरूप के करालमुख देखकर दिग्भ्रम। भक्त की शरणागति — 'प्रसीद' — एकमात्र।",
  "11.36": "अर्जुन उवाच — हे हृषीकेश, यह उचित है कि आपके कीर्तन से जगत् हर्षित और अनुरक्त होता है। राक्षस भयभीत होकर दिशाओं में भागते हैं — सभी सिद्धसमूह नमस्कार करते हैं।\n\nहृषीकेश — इन्द्रियों के स्वामिन् — इस संबोधन में सार्थकता। मध्वाचार्य के मत में — विश्वरूपदर्शन के समय त्रिलोकों में सभी अर्हत् जीवों ने एकसाथ दर्शन किया — इसीलिए सिद्धसमूह का नमस्कार।",
  "11.31": "मुझे बताइए — आप कौन हैं, इस उग्ररूप में? हे देववर, आपको नमस्कार। प्रसन्न हों। आदिपुरुष आपको जानना चाहता हूँ — आपकी प्रवृत्ति नहीं समझ पाता।\n\nभय-भक्ति-आनन्द-मिश्रित अर्जुन का सरल प्रश्न — 'आपका उद्देश्य क्या है?' भगवान् काल हैं — उत्तर देंगे।",
  "11.37": "हे महात्मन्, वे आपको क्यों न नमें — ब्रह्मा से भी श्रेष्ठ, आदिकर्ता को? हे अनन्त देवेश जगन्निवास — आप अक्षर, सत्-असत्, और उससे भी परे।\n\nआदिकर्त्रे — जिनसे ब्रह्मा भी उत्पन्न, उन्हें। ब्रह्मा से भी श्रेष्ठ — ब्रह्मा की शक्ति भगवत्सामर्थ्य को नहीं जीत सकती। सत्-असत् परम — व्यक्त-अव्यक्त से परे।",
  "11.38": "आप आदिदेव, पुराणपुरुष, इस विश्व के परम आश्रय। वेत्ता और वेद्य दोनों। परम धाम। हे अनन्तरूप, आप से यह विश्व व्याप्त है।\n\nआदिदेव — देवों के देव। पुराणपुरुष — सनातन। वेत्ता वेद्यश्च — ज्ञाता और ज्ञेय दोनों। अर्जुन उत्तरोत्तर भगवद्गुणों का अनुभव करते हुए स्तुति करता है।",
  "11.32": "भगवान् उवाच —\nकाल हूँ मैं — लोकों को क्षय करने वाला, प्रवृद्ध। लोकों को समेटने के लिए यहाँ प्रवृत्त हूँ। आपके बिना भी — इन प्रत्यनीक-स्थित सभी योद्धाओं का होना नहीं होगा।\n\n'काल' — 'कल' धातु — सर्वसंचालक, सर्वसमाहर्ता। भगवान् कालपुरुष — नित्यप्रवृत्त। भगवान् ने निर्धारित किया — अर्जुन निमित्तमात्र।",
  "11.35": "संजय उवाच — केशव का वचन सुनकर, कृताञ्जलि कँपते किरीटी ने, नमस्कार करके — सगद्गद, भीतभीत, प्रणाम करके — पुनः कृष्ण से बोले।\n\nगद्गद — कण्ठरोध से। भीतभीत — भयभक्तिमिश्रित। किरीटी — मुकुटधारी महावीर — भगवत्समक्ष नतमस्तक।",
  "11.34": "द्रोण, भीष्म, जयद्रथ, कर्ण — तथा अन्य योधवीरों को — मेरे द्वारा हत — आप मारो। विक्षुब्ध न हों — युद्ध करो — रण में शत्रुओं को जीतोगे।\n\nमेरे द्वारा हत — अर्जुन केवल भौतिकसाधन। जिनका मरण निश्चित — उन्हें मारने में पाप नहीं — क्योंकि जीव अविनाशी (BG 2.19)।",
  "11.52": "[बन्नञ्जे के अध्याय 11 में कुल 35 श्लोक हैं। यह प्रविष्टि OCR-त्रुटि से उत्पन्न। 11.51 के साथ ही अध्याय 11 का समापन होता है।]",
  "11.39": "वायु, यम, अग्नि, वरुण, शशाङ्क, प्रजापति — आप ही हैं। प्रपितामह भी आप। हजार बार नमः, पुनः-पुनः नमः नमः।\n\nवायु = बल-ज्ञानरूप; यम = नियन्ता; अग्नि = गतिप्रद; वरुण = भक्तवरेण्य; शशाङ्क = आनन्दस्वरूप। प्रत्येक नाम में भगवन्नामार्थ। सहस्रकृत्वः — बार-बार, अनगिनत बार।",
  "11.45": "किरीटधारी, गदाधर, चक्रहस्त — आपको उसी रूप में देखना चाहता हूँ। हे सहस्रबाहो, हे विश्वमूर्ते — चतुर्भुज रूप धारण करें।\n\nसहस्रबाहु रूप देखकर — चतुर्भुज रूप की इच्छा। भक्त का हृदय — उग्र से नहीं — सौम्य भगवद्दर्शन चाहता है।",
  "11.41": "आपके माहात्म्य को न जानते हुए — प्रमाद से या प्रेम से — 'हे कृष्ण हे यादव हे सखे' — ऐसा जो कुछ आग्रहपूर्वक मैंने कहा, और विहार-शय्या-आसन-भोजन में — एकान्त में या सामने — जो अवहेलना की — हे अप्रमेय अच्युत — उन सबके लिए क्षमायाचना करता हूँ।\n\nपिता-पुत्र, सखि-सखि, प्रिय-प्रिया — तीन सम्बन्धों का उल्लेख कर क्षमायाचना। भगवत्सम्बन्ध तीन प्रकार का हो सकता है।",
  "11.49": "संजय उवाच — वासुदेव ने यह कहकर अर्जुन को अपना कृष्णरूप दिखाया। महात्मा ने पुनः सौम्यवपु धारण कर भयभीत को आश्वासन दिया।\n\nमहात्मा वासुदेव — सौम्यरूपधारी — अर्जुन को आश्वस्त करते हैं। वासुदेव — वसुदेवपुत्र — किन्तु अर्थ — सर्वत्र वासुदेव।",
  "11.54": "अनन्या भक्त्या — इस प्रकार — ज्ञातुं, द्रष्टुं, तत्त्वेन प्रवेष्टुं — शक्यः हूँ।\n\nपरंतप — तीन शक्तियाँ — ज्ञान, दर्शन, प्रवेश (मोक्ष) — अनन्यभक्ति से ही। यही विश्वरूपाध्याय का सार।",
  "11.55": "मत्कर्मकृत्, मत्परम, मद्भक्त, सङ्गवर्जित, सर्वभूतेषु निर्वैर — जो ऐसा है वह मुझे प्राप्त होता है।\n\nपाँच लक्षण — (१) भगवत्कार्यरत; (२) भगवान् ही परम; (३) अनन्यभक्ति; (४) अनासक्ति; (५) सर्वभूतों में द्वेषरहित। ये पाँच विश्वरूपयोग का, गीता का निष्कर्ष हैं।",
  "10.42": "या बहुना एतेन किम ज्ञातेन तव अर्जुन।\n\nविषभ्य अहं इदं कृत्स्नम एक अनशेन स्थितः जगत - या, हे अर्जुन, सब कुछ जानकर।\nक्या हुआ? यह सार है: मैं इस पृथ्वी की दुनिया को अपने एकमात्र तत्व से गले लगाता हूं और धारण करता हूं\nसंचालन\n\nप्रत्येक को अलग-अलग जानना असंभव है।   ऐसा करने की कोई जरूरत नहीं है.\nभगवान हर चीज़ के भीतर अद्वितीय शक्ति हैं। हर चीज़ में भगवान की विभूति निहित है।\nकृष्ण कहते हैं, \"मैं अपनी शक्ति के एक अंश से संपूर्ण ब्रह्मांड में व्याप्त हूं\"।\nवह है। जैसा कि पुरुष सूक्त कहता है:\n\nपडोस्य विश्व भूटानी| त्रिपादस्यामृतं दिवि|\n\nत्रिपादुर्ध्व उदयितपुरुषः। पादोसयेहभवथु नः।\n\nततो विष्टमव्यक्रमत्.| ससाननशाने अभि |\n\nईश्वर का केवल एक चौथाई भाग ही इस संसार में व्याप्त है। एक स्वादिष्ट तीन-चौथाई\nभग दिव्यलोक (मुक्तलोक) में रहता है। “दुनिया के सभी पदार्थों को अंदर और बाहर भरें\n\nभगवान श्रीकृष्ण के विभूति नामक इस अध्याय में कहा गया है कि मैं ब्रह्मांड का स्वरूप हूं\nयह ख़त्म हो गया है.\n\nइति दशमो*ध्यायः\nदसवाँ अध्याय ख़त्म हो गया\n\nचिंता मत करो\n\nअध्याय ग्यारह\n\nयह अध्याय बताता है कि भगवान की पूजा करते समय उनके बारे में कैसे सोचना चाहिए\nअध्याय यह भगवान का विश्वरूप दर्शन अध्याय है। कृष्ण द्वारा अर्जुन को दिव्यनेत्र की कृपा प्रदान करना |\nवह अपना विश्वरूप दिखाता है। यहाँ उस ब्रह्माण्ड का वर्णन है। यहाँ व्याप्त है,\nसर्वव्यापी, सर्वशक्तिमान भगवान के बारे में कैसे सोचा जाए, इस पर मार्गदर्शन है।\nईश्वर के स्वरूप की तुलना किसी सांसारिक अनुभव से नहीं की जा सकती। बस इतना ही\nएक अलौकिक अनुभव. यह अध्याय उस अद्भुत अनुभव का वर्णन करता है।\n\nहर कोई भगवान के विश्व स्वरूप का ध्यान नहीं कर सकता। लेकिन हर जगह\nध्यान योग में प्रत्येक व्यक्ति पूर्ण रूप से ईश्वर का किंचित दर्शन प्राप्त कर सकता है। कैसे\nजैसे कृष्ण ने अर्जुन को अपना विश्वरूप दिखाया, वैसे ही ध्यान में उन्होंने हमें भी अपना रूप दिखाया\nउसे यह दिखाना चाहिए. यह वह रूप नहीं है जो बाहरी जगत में दिखता है। हम अपनी आंतरिक आँखें खोलते हैं\nव्यक्ति को बैठकर ध्यान करना चाहिए, व्यक्ति को भगवान के प्रति समर्पण करना चाहिए। जिज्ञासावश पुकारने पर भीतर से क्या?\nयदि सहानुभूति आती है, तो यह सांसारिक सहानुभूति से परे है।\n\nइस अध्याय में भगवान के वचन कम हैं। यहां उन लोगों के शब्द हैं जिन्होंने कृष्ण के सार्वभौमिक रूप को देखा। वे हैं\nजो दिख रहा है उसे सुनकर हमें प्रभु के दर्शन का प्रयास करना चाहिए। यह हमारा आंतरिक स्व है\nआध्यात्मिक अनुभूति के पूरक के रूप में हमें ध्यान के मार्ग पर ले जाना अत्यंत आवश्यक है\nअध्याय आओ, व्यास से भगवान के अद्वितीय विश्व स्वरूप का वर्णन सुनो\nआइए आभारी रहें.\n\nअध्याय में प्रवेश करने से पहले हमें एक बात जाननी होगी। हममें से कुछ के लिए\nएक गलतफहमी है. “अर्जुन को भगवान का संदेश समझाने के लिए कृष्ण उनके पास हैं\nविश्वरूप दर्शन तो करना ही था. “भले ही उन्हें स्वयं भगवान कृष्ण ने निर्देश दिया हो\nअर्जुन को यकीन नहीं हो रहा था कि अब हम क्या कर सकते हैं? हमारे लिए विश्वरूप दर्शन कौन है?\nसोचने वाले भी हैं, लेकिन ये हमारी ग़लतफ़हमी है. अर्जुन के लिए\nप्रभु का संदेश दृढ़ विश्वास से भरा था। यह बात इस अध्याय के प्रथम श्लोक में है\nजान लेंगे अर्जुन कहते हैं \"मोहोयम विगतो मम\" - \"आपकी महिमा को जानना ही मेरा सब कुछ है\nसंशय भी बीत गया'. इससे जो समझा जा सकता है वह है अर्जुन का भगवान अर्जुन के प्रति दृष्टिकोण\nजो चाहिए वह केवल देखना और धन्य होना है, प्रमाण के लिए नहीं। आम तौर पर\nमानव स्वभाव है कि कुछ सुनने के बाद उसे देखना स्वाभाविक है\nइच्छा अर्जुन ने भी कृष्ण के समक्ष ऐसी ही इच्छा रखी। अगले चार\nश्लोक में यह विचार स्पष्ट रूप से समझ में आता है।\n\nअर्जुन उवाच |\nमदनुगृहाय परं गुह्यमध्यात्मसंज्ञम्।\nयश त्वयोक्तं वाचस्तेन मोहो$यं विगतो मम ॥1॥\n\nअर्जुनः उवाच- अर्जुन ने कहाः\n\nमत् अनुग्रहाय परमं गुह्यं अध्यात्म संज्ञिथम्।\n\nयत् त्वया उक्तं वाचः तेन मोहः अयं विगतः मम -- मुझ पर दया करो,\nआपने अध्यात्म का पुराना रहस्य निभाया। मैं उस शब्द से दुखी था.\n\nअर्जुन कहते हैं: “अपनी कृपा से मुझे आध्यात्मिकता का सबसे गहरा विचार दीजिए\nकहा।\" यहां \"अनुग्रह\" का अर्थ है-उनमें से कम से कम का मार्गदर्शन करना और उन्हें ऊपर उठाना\nबुजुर्ग छुटकारा पाना चाहते हैं। “मैं भटकने ही वाला था",
  "11.40": "आगे से नमः, पीछे से नमः — हे सर्व, सर्वतः नमः। हे अनन्तवीर्य अमितविक्रम — आप सब में व्याप्त हैं, इसलिए आप ही सब हैं।\n\nसर्वतः नमः — भगवान् सर्वत्र हैं — इसीलिए सर्वदिशाओं से नमस्कार। 'ततः असि सर्वः' — इसीलिए आप ही सब हैं — विश्वरूप का सार।",
  "12.6": "ये तु सर्वाणि कर्माणि मयि संन्यस्य मत्पराः ।\nअनन्येनैव योगेन मां ध्यायन्त उपासते ॥\n\n'जो सभी कर्म मुझे समर्पित करके, मत्परायण होकर, अनन्य योग से मुझे ध्यान करते हुए उपासना करते हैं —'\n\nयह सगुण-भक्ति का प्रकार। 'सर्वाणि कर्माणि मयि संन्यस्य' — सब कर्म मुझे अर्पण। 'अनन्येन योगेन' — अनन्य योग से। 'मां ध्यायन्तः' — मुझे ध्यान करते हुए। यह भक्त की सर्वोत्तम स्थिति।",
  "11.48": "मेरे इस भयावह रूप को देखकर व्यथित न हों — विमूढ़भाव न करें। भयरहित, प्रसन्नमनस् होकर — वही मेरा वह रूप पुनः देखें।\n\nभगवान् करुणालु — अर्जुन का भय देखकर सान्त्वना देते हैं। प्रीतमनाः — आनन्दित मन से — पुनः भगवद्दर्शन।",
  "11.44": "जो पहले कभी नहीं देखा, उसे देखकर हर्षित हूँ — और भय से मन व्यथित भी है। हे देव, वही रूप दिखाइए। हे देवेश जगन्निवास — प्रसन्न हों।\n\nआनन्द और भय एकसाथ। देव — वही पूर्वपरिचित रूप दिखाइए। जगन्निवास — सर्वत्र निवासी — देवेश — प्रसन्न हों।",
  "11.43": "इसलिए प्रणाम करके, काया झुकाकर — ईश, ईड्य आपको प्रसन्न करता हूँ। हे देव — जैसे पिता पुत्र की, सखा सखा की, प्रिय प्रिया की — वैसे ही क्षमा करने योग्य हैं आप।\n\nतीन सम्बन्धों से क्षमायाचना। भगवान् सभी भावों में आश्रय देते हैं — पिता की तरह, मित्र की तरह, प्रेमी की तरह।",
  "12.3": "येतु अक्षरं अनिरदेश्यं अव्यक्तं पर्युपासते।\nसर्वत्रगम अचिन्त्यं च कूटस्थम् अचलम् ध्रुवम् - अव्यक्त और अविनाशी सिद्धांत। अकथनीय, अकल्पनीय सिद्धांत. अगासा बस गया है और हर जगह भरा हुआ है। अस्थिर, अचल परतत्त्व।\n\nयहां कृष्ण अव्यक्ततत्व लक्ष्मी की पूजा का वर्णन करते हैं। संसार की नीति और ईश्वर की भक्ति में अंतर है। आमतौर पर दुनिया में मां अपने बच्चों की गलतियों को माफ कर देती है और पिता उन्हें सजा देता है। लेकिन माता श्री लक्ष्मी की पूजा और भगवान की पूजा में इसका विपरीत होता है। पूजा में कुछ कमी है\nमाँ गलतियाँ माफ नहीं कर सकती, लेकिन भगवान करता है। इसी कारण अक्षर की पूजा कठिन है।",
  "11.47": "वेदाध्ययन, यज्ञ, दान, क्रिया, उग्रतप — किसी से भी इस प्रकार का रूप मनुष्यलोक में तुम्हारे अतिरिक्त किसी ने नहीं देखा — हे कुरुप्रवीर।\n\nभगवद्भक्ति ही — न अन्यकोई साधन — इस दर्शन का हेतु। वेद-यज्ञ-दान-तप ये सब अप्रत्यक्ष साधन — प्रत्यक्ष भक्ति ही परमसाधन।",
  "11.50": "अर्जुन उवाच — हे जनार्दन, आपका यह सौम्य मानुष रूप देखकर अब चेतन हो गया हूँ, स्वाभाविक स्थिति में आ गया हूँ।\n\nजनार्दन — जन-अर्दन — सब पापों का नाशक। सौम्यरूप देखकर चेतन। प्रकृतिं गतः — स्वाभाविक स्थिति प्राप्त। उग्रदर्शनजनित भय — सौम्यरूप से दूर।",
  "12.13": "अद्वेष्टा सर्वभूतानां मैत्रः करुण एव च ।\nनिर्ममो निरहंकारः समदुःखसुखः क्षमी ॥\n\n'जो सब प्राणियों से द्वेष नहीं करता, मैत्री और करुणा वाला, निर्मम, निरहंकार, सुख-दुःख में सम, क्षमाशील है —'\n\nयह गीता के 'प्रिय भक्त' के लक्षणों की श्रृंखला का आरम्भ। 'अद्वेष्टा' — किसी से भी द्वेष नहीं। 'मैत्रः करुणः' — मित्रभाव और करुणा। 'निर्ममः निरहंकारः' — ममता-अहंकारशून्य।",
  "12.5": "क्लेश अधिक तारः तेषाम् अव्यक्त असक्त चेतसाम् |\nअव्यक्त हि गतिः दुःखं देहवद्लिह अवप्यते - उन लोगों के लिए जो निर्वैयक्तिकता की पूजा की सराहना करते हैं।\nथकान अधिक है. अव्यक्त के माध्यम से मुक्ति का मार्ग अभ्यासी के लिए एक कठिन चक्कर है।\n\nवह शक्ति की पूजा करने वालों को मोक्ष प्रदान करती हैं। लेकिन पूजा अदृश्य की\n\"अधिक तारा क्लेश:\" करने वालों के लिए उपासना बहुत कठिन है। यह सीधा रास्ता छोड़ देती है।\nजैसे चक्कर लगाकर भगवान तक यात्रा करना। अभ्यासकर्ताओं को इसे बड़ी कठिनाई से प्राप्त करना पड़ता है।\n\nनिम्नलिखित श्लोकों में, कृष्ण बताते हैं कि सीधे भगवान की पूजा करना कितना आसान है।\nयह भगवान द्वारा हमें दिखाया गया भक्ति का आसान मार्ग है।\n\nये तु सर्वाणि कर्माणि मयि संन्यास्य मत्परः |\nअनन्येनैव योगेन माम् ध्यानं उपासते",
  "11.42": "हे चर-अचर जगत् के पिता — पूज्य, गुरु, सबसे श्रेष्ठ गुरु। तीनों लोकों में न तुल्य, न अभ्यधिक — हे अप्रतिमप्रभाव।\n\nसभी गुरु ज्ञान देते हैं — भगवान् तो अज्ञान को ही नष्ट करते हैं और स्वयं ज्ञानस्वरूप हैं — इसीलिए गुरुर्गरीयान्।",
  "11.46": "भगवान् उवाच — हे अर्जुन, मेरे प्रसन्न होने से आत्मयोग से यह परम रूप — तेजोमय, विश्वमय, अनन्त, आद्य — जो तुम्हारे अतिरिक्त किसी ने पहले नहीं देखा — दिखाया।\n\nमया प्रसन्नेन — भगवान् के प्रसाद से — न अन्य किसी प्रयत्न से — विश्वरूप मिलता है। अर्जुन एकमात्र — इस दर्शन से कृतार्थ।",
  "11.51": "भगवान् उवाच — यह रूप जो तुमने देखा — सुदुर्दर्शम् — देवता भी इसके नित्य दर्शन की कामना करते हैं।\n\nन वेदों से, न तप से, न दान से, न यज्ञ से — ऐसा दर्शन सम्भव नहीं — जैसा तुमने मुझे देखा।\n\nअर्जुन ने जो पाया — देवता भी चाहते हैं। भगवद्भक्ति ही एकमात्र — विश्वरूपदर्शन का हेतु — यही विश्वरूपाध्याय का सार।",
  "12.18": "समः शत्रौ च मित्रे च तथा मानापमानयोः ।\nशीतोष्णसुखदुःखेषु समः सङ्गविवर्जितः ॥\n\n'शत्रु और मित्र में सम, मान-अपमान में सम, शीत-उष्ण-सुख-दुःख में सम, और आसक्ति से रहित।'\n\nप्रिय भक्त के लक्षणों की श्रृंखला जारी। 'समः शत्रौ च मित्रे च' — शत्रु-मित्र में भेद नहीं। 'मानापमानयोः' — सम्मान और अपमान में समभाव। 'सङ्गविवर्जितः' — आसक्ति से रहित।",
  "12.11": "अथ एतत् अपि अशक्तः असि कर्तुम् मत योगम् आश्रितः |\n\nसर्वकर्म फल त्यागम् ततः कुरु यत् आत्मवान् - यदि ऐसा नहीं किया जाता तो सभी प्रकार के\nमुझे भी कर्म अर्पण करने का पराक्रम करो। फिर सब कर्मों का मार्ग कड़ा करो\nनिष्फलता का त्याग करें।\n\nयदि ऊपर बताए अनुसार सभी कर्म भगवान को अर्पित करना संभव नहीं है,\nयदि हर चीज़ को भगवान की पूजा के रूप में करना संभव नहीं है, तो किसी की पूजा करें - लेकिन\nअंत में, कृष्ण कहते हैं कि कर्म की इच्छा किए बिना सभी कर्म भगवान को अर्पित कर दो। यहाँ\nकृष्ण ने कर्मफल के त्याग और अर्पण पर जोर दिया।\n\nश्रेयो हि ज्ञानमभ्यासज ज्ञानद ध्यानं विशिष्यते |\nध्यानात् कर्मफलत्यागस्वगच्छनथिरन्तरम्",
  "12.10": "आदतें अपि असमार्थः असि मत कर्म परमः भवः।\nमत अर्थं अपि कर्माणि कुर्वान सिद्धिं अवप्स्यसि च - यदि ध्यान भी असंभव है, तो मेरा\nपूजा-पाठ के कार्यों में शामिल हों.   कर्म को मेरी पूजा समझो...\n\nहासिल किया जा सकता है।\n\nकुछ लोगों के पास कितना भी अभ्यास हो, एकभक्ति संभव नहीं है। आध्यात्मिक पथ की प्राप्ति में\nमन के लिए एक जन्म का अभ्यास पर्याप्त नहीं है। हालाँकि कभी-कभी पूरे जन्म का अभ्यास किया जाता है\nएकाग्रता नहीं आ पाती. दयालु कृष्ण उनसे कहते हैं: “आप जो कर्म करते हैं\nइसे स्वार्थ के लिए मत करो, इसे भगवान की पूजा करने के इरादे से करो।” उसका दैनिक\nप्रत्येक कार्य को भगवान की पूजा के रूप में भक्तिपूर्वक करें, आध्यात्मिक मार्ग में सिद्धि प्राप्त करें\nमिल सकता है\n\nअथैतादप्यशक्तो$च कर्तुम मदयोगमाश्रितः |\n\nसर्वकर्मफलत्यागं ततः कुरु यतात्मवान्",
  "12.8": "मयि एव मनः अधातश्री मयि बुद्धिम निवेशाय।\nनिवसिष्यसि मयि एव अतः उर्ध्वं न संशयः - मुझे बताओ। मुझमें प्रकाश रखो.\nपरिणामस्वरूप, मैं अपने आप में स्थापित हो जाऊँगा। इसके बारे में कोई संदेह नहीं है।\n\nकृष्ण कहते हैं: अपने मन को मुझमें स्थिर करो। \"आधना\" का अर्थ है बीज बोना या\nस्पार्किंग मन को भगवान की भक्ति की चिंगारी से प्रज्वलित कर चमकाना चाहिए। भक्तिपूर्ण\nबीज को विकसित होने के लिए पोषित करना चाहिए। निश्चययज्ञ को बुद्धि में सुदृढ़ करना चाहिए। हमेशा ऐसा ही मन रखो\nभगवान में स्थापित होने पर व्यक्ति बिना किसी कष्ट के भगवान से जुड़ सकता है। यह शक्ति है\nईश्वर की आराधना उपासना से कितनी अधिक सरल है, इसकी व्याख्या। प्रभु की आराधना करना\nनियामक प्रतिबंध बहुत कम है. उदाहरण के लिए विष्णुसहस्रनाम पारायण। विष्णुसहस्रनाम\nचिंतन के लिए कोई निश्चित समय सीमा नहीं है। किसी भी समय कोई भी\nविष्णुसहस्रनाम का पाठ कर सकते हैं। विष्णुसहस्रनाम सभी रोगों का इलाज है। भगवान के विचार में\nअनजाने में हुई चूक क्षमा योग्य है।\n\nनारायण की पूजा का अर्थ है लक्ष्मी के साथ नारायण की पूजा। नारायण\nउपासकों को लक्ष्मी और अन्य देवताओं की अलग-अलग पूजा करने की आवश्यकता नहीं है।\nलक्ष्मी और सभी देवताओं को जो सबसे प्रिय है वह भगवान की पूजा है। नारायण\nसभी देवता साधक को उसके साधना पथ में सहायता करें\nहमें ऊँचा उठाता है... जब हम यह जान लेते हैं तो हम अपनी आराधना में सहज हो जाते हैं\nएकता हासिल की जा सकती है. भक्ति को इस तरह से मजबूत किया जा सकता है।\n\nअथ चित्तं समाधातुम न शक्नो इशि मयि स्थिरम् |\nअभ्यासयोगेन ततो मामिच्च*पतुम धनन्जय",
  "12.12": "श्रेयः हि ज्ञानं हैभयत् ज्ञानात ध्यानं विशिष्यते |\n\nध्यानथ कर्म फल त्यागः त्यागत शांतिः अनन्तरम् - जागरूकता अचेतन अभ्यास से कहीं अधिक है।\nखोखला ज्ञान जानने से बेहतर है जानना और मनन करना। कर्मफल रहित ध्यान खाली ध्यान से बेहतर है\nअधिशेष ऐसे ध्यान का अगला चरण मुक्ति है।\n\nबिना ज्ञान के ध्यान से ज्ञान बेहतर है। ज्ञान की आध्यात्मिक प्राप्ति में। बुनियादी\nआवश्यकता है (96783/909! 7681671600. ज्ञान के बिना ध्यान या कर्म करना व्यर्थ है।\nबिना समझे किया गया परिश्रम अंध परिश्रम बन जाता है। इसी प्रकार श्रद्धा के बिना समझ अहंकार है।\nतो आपको जानना होगा, आपको जानना होगा और विश्वास करना होगा। केवल समझ ही पर्याप्त नहीं है. ज्ञान के बजाय ज्ञान के साथ\nध्यान पर. सबसे उत्तम कर्म का त्याग है।  तो पहले जानें, जानें और अभ्यास करें\nलेकिन अपने ध्यान को कर्म-मुक्त ध्यान बनने दो। इस तरह की जीवन शैली से\nगर्भपात संभव है.\n\nकृष्ण ने बताया कि भगवान की पूजा अब तक कैसी होनी चाहिए, फिर तो हम भगवान हैं\nयदि हम प्रशंसा का जीवन जीना चाहते हैं तो हमें अपने जीवन को कैसा आकार देना चाहिए\n\nबताते हैं कि पाठ्यक्रम और क्रियान्वयन कैसा होना चाहिए।\n\nअद्वेष्टा सर्वभूतानां मैत्रः करुणा एव च।\n\nनिर्ममो निरहंकारः समदुःखसुखः क्षमि",
  "12.7": "ये तु सर्वाणि कर्माणि मयि संन्यास मत परः |\n\nअनन्येन एव योगेन मां ध्यानतः उपासते ॥\n\nतेषाम् अहं समुद्धर्ता मृत्यु संसार सागरत्।\n\nभवामि नचिरत पार्थ मय्यावेशिताचेतासम् - कुछ हैं: वे सभी मुझमें किए गए हैं।\n\n1\n\nप्रस्ताव देंगे. उन्होंने ही मुझे बनाया है. उनकी उपलब्धि का लक्ष्य कोई और नहीं बल्कि मैं हूं। मेरी बहन 6 साल की है\n\nभिगोकर सेवन किया जाता है। हे पार्थ, जो लोग मुझे प्रिय हैं, मैं उन्हें शीघ्र ही मार डालूँगा\nसमुद्र से मुक्त हुआ.\n\nकृष्ण कहते हैं: “मुझसे जुड़ने का सबसे आसान साधन है- तुम जीने के लिए क्या हो\nयदि आप कार्रवाई कर रहे हैं, तो इसे मुझे पेश करें। यहां कृष्ण जो कह रहे हैं, वह हम हैं\nप्रत्येक कार्य के पीछे जो दृष्टिकोण होना चाहिए, प्रभु ने यह कार्य मुझे दिया है\nबना दिया - यही निष्कर्ष है कि वे अवतरित हैं। जब हम ऐसे हैं, तो हम परमेश्वर के हैं\nपुर्हनुग्रह को सौंपा जा सकता है। यहां हमें सबसे महत्वपूर्ण चीज़ ईश्वर की आवश्यकता है\nअनन्य भक्तिभाव से पूजा करते हैं। हमारी उपलब्धि, भावना में कमी हो सकती है\nदमन चाहे जितना कठिन हो, सार्वभौमिक परोपकार। शायद नहीं, विचार में\nचूक हो सकती है, एकाग्रता की कमी हो सकती है. लेकिन यहाँ कृष्ण का वचन है\n\"मेरे प्रति समर्पण करो, अपना मन मुझ पर केन्द्रित करो - मैं तुम्हें ऊपर उठाऊंगा।\" हमारा\nजब भगवान मन में स्थापित हो जाते हैं, तो भगवान हमें जन्म और मृत्यु के इस सागर से मुक्त कर देते हैं\nबचाव के लिए जिम्मेदार.",
  "12.9": "अथ चित्तं समाधातुम् शक्नोशि मयि स्थिरम्।\n\nअभियोगसेना तथा मम इच्छा आपटू डेंजया - धनंजय, एक बार मुझमें\nयदि आंतरिक भाग को सख्त करना संभव नहीं है, तो सैंडिंग के अभ्यास का उपयोग करें\nअपनेपन की इच्छा पैदा करें।\n\nमन में प्रभु भक्ति है, बुद्धि में प्रबुद्ध भक्ति का अंकुर है। फिर भी\nजब स्थिर स्मृति न आ रही हो, मन स्थिर न हो तो क्या करें? शास्त्र में\nजैसा कि कहा गया है:\n\nस्मार्टव्यः सदाचं विष्णुः विस्मर्तव्यो न जातुचित् |\nसर्वे विधि निषेधस्स्युह एतयोरेव किंकरः ॥\n\nइसका अर्थ है 'हमें सदैव भगवान को याद रखना चाहिए, भगवान को कभी नहीं भूलना चाहिए।'\nसभी निषेध भी यही कहते हैं। इस अखंड प्रभु में मन नहीं रुकता\nस्मृति संभव नहीं है. कृष्णा बताते हैं कि ऐसी स्थिति में क्या करना चाहिए।\n“प्रार्थना करें कि आप मुझे मन को एकाग्रता में लाने की शक्ति दें।\nकृष्ण का वचन है कि मार्ग में वह जो भी इच्छा करेगा उसे पूरा करने का उत्तरदायित्व मेरा है।\nयदि अभ्यास और इच्छाशक्ति हो तो एकाग्रता अवश्य संभव है। हम बच्चों को कैसे प्रशिक्षित करें?\n\nबीआर\n\nइसका अभ्यास करें. यदि आप सिखाते हैं, तो हमारे मन को प्रसन्न करें और हमें ज्ञान बताएं\nअभ्यास करना चाहिए. जब आप ऐसा करते हैं तो मन एक आदत बन जाता है। पहले हम\nसांसारिक. धन के पीछे भागना बंद करो और भगवान का अनमोल खजाना जीतो\n\nआभारी होना।\n\nआदतपे5प्य समरथोसि मत्कर्मपरमो भव |\n\nमदार्थमपि कर्माणि कुर्वन् सिद्धिमवाप्स्यसि",
  "12.17": "यः न हृष्यति न वेति न शोचति न कांक्षति |\nशुभ अशुभ परित्यागी भक्तिमान् यः सः मेइ प्रियाः -बंद नहीं होता; नफरत नहीं करें; कराहता नहीं;\nअच्छे-बुरे की परवाह नहीं करना चाहता, ऐसा भक्त ही मेरा प्रिय है।\n\nयहां पहले बताए गए कुछ विचारों की पुनरावृत्ति है। आमतौर पर एक से अधिक चीज़ें\nकिसी बात को स्पष्ट करने और उस पर ज़ोर देने की अतिरेक। यहाँ कृष्ण हैं\nकहते हैं: जब कुछ अच्छा किया जाए तो रुकें नहीं और किसी और की तलाश करें\nनाराज मत होइए. बहुत खुश रहो कि तुम्हें यह मिल गया, इस बात पर दुखी या नफरत मत करो कि तुम्हें यह नहीं मिला। जीवन में ज्ञान\nभक्ति वैराग्य शुभ है. बाकी हर चीज के फायदे और नुकसान का विश्लेषण न करें। इस दुनिया में\nकुछ भी आकस्मिक नहीं है. यहां होने वाली हर घटना कुछ ऐसी होती है जिसके बारे में हम पहले नहीं जानते थे\nवहाँ एक कारण है। इसके लिए मृत्यु यह निर्णय नहीं कर पाती कि वह शुभ है या अशुभ। यह जानकर\n\nकृष्ण कहते हैं कि जीवित भक्त ही मुझे प्रिय है।\n\nसमः शत्रौ च मित्रे च तथा मनापमानयोः |\nशीतोष्टसुखदुःखेसु समः संगविवर्जितः",
  "12.1": "अर्जुन उवाच - अर्जुन ने पूछा:\n\nएवं सचदा युक्तः ये भक्तः त्वम् पर्युपासते।\n\nये च अपि अक्षरं अव्यक्तं तेषाम् के योगवित्तमः - इस प्रकार निरंतर प्राप्ति से\nजो लोग आपकी सेवा करते हैं वे अविनाशी निर्वैयक्तिकता (श्रत्व) के भक्त और उपासक हैं। उनमें से कौन\nउनमें से अधिकांश.\n\nइसके मुख पर यह श्लोक भगवान की पूजा का एक विशिष्ट रूप है और नहीं\nनिराकार भगवान की पूजा करना जो रूपों से प्रकट नहीं होता है - दोनों में से क्या उचित है\n\nसुना हुआ लगता है. लेकिन इस श्लोक में अर्जुन जो मूल प्रश्न पूछ रहा है वह अलग है। यह\nमाधवाचार्य ने इसका अनोखा वर्णन किया है।\n\nवे सभी जो ईश्वर के बारे में सोचते हैं, जरूरी नहीं कि वे ईश्वर के भक्त हों...भगवान के बारे में सोचते हों\nकरने के लिए आवश्यक घटक प्रेम है। ज्ञानमय प्रेम ही भक्ति है। पूर्व समय में\nसबके घर में भगवान के कमरे में एक मूर्ति होती थी. जो उनकी पूजा के लिए है\nइष्ट, इष्टदेवता की मूर्ति है। अगर हम इस पहलू का विश्लेषण करें कि मूर्ति ऐसी क्यों है\nज्ञात होता है कि वे इसकी पूजा करते थे। यहां सबसे पहले हम इस पर काम करते हैं कि हमारा दिमाग कैसे काम करता है\nआपको करने का विचार जानने की आवश्यकता है। आँखें जो देखती हैं, उसे मन नहीं समझता।\nउदाहरण के लिए, यदि हम यह जानते हुए कि ईश्वर 'सबसे सुंदर' है, अपनी आँखें बंद करके ध्यान में बैठ जाते हैं\nमन हमें वह सुन्दर चीज़ दिखाता है जो हमने देखी है! इसके लिए\nपूर्व भगवान में हमारे जैसे गुण हैं, लेकिन वह किसी इंसान की तरह नहीं हैं\nउन्होंने अपनी मूर्ति नहीं देखी. इस मूर्ति का स्मरण करें और अपनी आँखें बंद कर लें\nयदि हम ईश्वर के गुणों का ध्यान करेंगे तो हमें केवल वह मूर्ति ही दिखाई देगी, अपनी नहीं\nकोई परिचित नहीं. इससे ध्यान करना आसान हो जाता है। मन एक व्यक्ति है\nव्यक्ति निश्चिंत होकर भगवान को मूर्ति के रूप में देखना शुरू कर देता है। इस कारण प्रभु\nसोच को एक रूप की आवश्यकता होती है।\n\nजैसा कि हम जानते हैं माता श्री लक्ष्मी को श्रीतत्व, अक्षरा, अव्यक्त, प्रकृति, ह्री आदि नामों से जाना जाता है।\nनाम से पुकारा गया. भगवद्गीता में ही इस प्रकार का सम्बोधन अनेक स्थानों पर मिलता है।\nजैसा कि कठोपनिषद में कहा गया है \"महतः परमव्यक्तमव्यक्तत्पुरुषः परः\"। अर्थात् महत्व के बजाय\nभगवान् पुरुष अव्यक्त तत्त्व से श्रेष्ठ हैं। यहाँ स्पष्ट रूप से हमारे लिए है\nज्ञातव्य है कि माता श्री लक्ष्मी अदृश्य, अक्षरा हैं।\n\nआपने शास्त्रों के द्वारा जो अपने गुण बताये हैं, उनका मन में निरन्तर चिन्तन करते रहना\nआपके विशेष रूप की महिमा को जानकर और उसके प्रति भक्ति विकसित करके\nपूजा करना अच्छा है; अथवा श्रीतत्त्व जो कि क्षरातीत (अक्षर) है) की पूजा करना अच्छा है।\nअर्जुन का प्रश्न है कि कौन सा मार्ग सर्वोत्तम है।",
  "13.5": "इस विषय को बुद्धिमान पुरुष भी एक-एक करके कहते हैं। यह उनका अनुभव है\nसीमित है. ब्रह्मसूत्र में जो कहा गया है उसे समझना आसान नहीं है। बिलकुल सच\nसुनो, मैं खुद एक फील्ड एक्सपर्ट हूं।\n\nमहाभूतन्याहंकारो बुद्धिरव्यक्तमेव च।\n181\n\nइच्छा वेतः सुखं दुःखं संघतश्चचेतना धृतिः |\nएतत् क्षेत्रं समसेन सविकारमुदाहृतम्",
  "13.4": "खपिभिः बहुधा गीतं छन्दोभिः विधाभिः पृथक।\nब्रह्मसूत्रपादैः च एव हेतुमाद्लिः विनिश्चितैः - विभिन्न मंत्रों से सुख।\nइसे विभिन्न प्रकार से गाया गया है। साथ ही युक्ति से निर्णय करते हुए वेदांत सूत्र के शब्द भी।\n\nइस विषय को बुद्धिमान पुरुष भी एक-एक करके कहते हैं। यह उनका अनुभव है\nसीमित है. ब्रह्मसूत्र में जो कहा गया है उसे समझना आसान नहीं है। बिलकुल सच\nसुनो, मैं खुद एक फील्ड एक्सपर्ट हूं।\n\nमहाभूतन्याहंकारो बुद्धिरव्यक्तमेव च।\n181\n\nइच्छा वेतः सुखं दुःखं संघतश्चचेतना धृतिः |\nएतत् क्षेत्रं समसेन सविकारमुदाहृतम्",
  "13.1": "भगवान उवाच- भगवान ने कहा:\n\nइदं शरीरं कौन्तेय क्षेत्रं इति अभिधीयते।\n\nएतत् यः वेत्ति तम प्राहु क्षेत्रज्ञः इति तत् विदः- यह चरित्र जो भगवान के शरीर के समान है।\nसंसार को *क्षेत्र' कहा जाता है। जो लोग इसे जानते हैं वे *क्षेत्रज्ञ' कहलाते हैं।\n\n'फ़ील्ड' शब्द का कोई विशिष्ट अर्थ नहीं है। इस श्लोक में क्षेत्रम् शब्द का क्या अर्थ है?\nकृष्ण ने इशारा किया है समझने का. क्षेत्र का अर्थ है 'इदं शरीरम्'\nकृष्ण. तो यहाँ क्षेत्र का अर्थ है जीवन का निवास, पिंडदान से लेकर ब्रह्मांड तक\nसब कुछ हाँ है. इस ब्रह्मांड के लिए 'क्षेत्र और शरीर' वुडू अन्वार्थनमा (6॥860) है।\nजो क्षेत्र को व्यापक रूप से जानता है वह क्षेत्र विशेषज्ञ है। जैसे कि अगले श्लोक में कौन\nचलो देखते हैं.\n\nक्षेत्रज्ञं चापि माम् विधि सर्वक्षेत्रेषु भारत |\n\nक्षेत्रक्षेत्रज्ञयोर्जनं यत् तज ज्ञानं मातं मम",
  "12.15": "यस्मात् उद्विजते लोकः लोकतश्च उद्विजथेचय |\n\nहर्ष अमरषा भय उद्वेगैः मुक्तः यः सः च मे प्रियः - जो किसी से आहत न हो।\nजो किसी को दुःख नहीं पहुँचाता, जो क्रोध से बिगाड़ नहीं करता, जो क्रोध नहीं करता, जो अज्ञानी है,\nजो घबराता नहीं, वही मेरा प्रिय है।\n\nदूसरा हमें देखकर घबरा न जाए.. और हम दूसरे को\nघबराओ मत. किसी को भी हमें और दूसरों को देखने के लिए अधीर नहीं होना चाहिए\nदेखिए, हमें अधीर नहीं होना चाहिए. इसे प्राप्त करने के लिए जब हम दुनिया से बिना शर्त प्यार करते हैं\nसंभव है प्रभु हमसे तब प्रेम करते हैं जब हम वही करते हैं जो उन्हें प्रसन्न करता है। भगवान\n\nप्यार करने वालों को पूरी दुनिया प्यार करती है।\n\nहमें भय और चिंता से मुक्त होना चाहिए। जो नहीं करना चाहिए उसे करने में\nआनन्द मनाओ; जब कोई दूसरा वही करता है जो उसे करना चाहिए तो ईर्ष्या करना बुरी बात है।\nसाधक को हर्ष अमर्ष से मुक्त होना चाहिए। कुछ डरावना और गलत मत करो\nजब आप ऐसा न करें तो घबराएं नहीं। यदि हम दूसरों को संदेह की दृष्टि से देखते हैं, तो वे भी हमें संदेह की दृष्टि से देखते हैं\nसंदेह की दृष्टि से देखा जाने लगा। जब हम दूसरों पर भरोसा नहीं करते, तो वे हम पर भरोसा नहीं करते।\nइस तनाव से (17685100)। तनाव से हमारे शरीर में कई तरह की बीमारियाँ घर कर जाती हैं\nहमें भगवान पर भरोसा करना सीखना चाहिए और निःस्वार्थ और निश्चिंत होकर जीना चाहिए।\n\"एक साधक जो जीवन में सभी से प्यार करता है; एक साधक जो भय और चिंता पर विजय प्राप्त करता है वह मैं हूं\nप्रिय” कृष्ण कहते हैं।\n\nअनापेक्ष शुइचिरदक्ष उदासीनो गतव्यतः।\n\nसर्वारंभपरित्यागी यो मद्भ क्रसमे प्रियः",
  "13.3": "तत् क्षेत्रं यत् च यद्रिक च यत् विकारी यतः चयत् |\n\nसः च यः यत् प्रभावः च तत् समासेण मे श्र्णु - वह क्षेत्र कौन सा है? यह कैसा है?\nइसकी विकृतियाँ क्या हैं? इसकी प्रेरक शक्ति कौन है? वह कैसा है उसकी ताकत क्या है? यह\nमुझसे ध्यान से पूछो.\n\nसबसे पहले फ़ील्ड क्या है? ब्रह्माण्ड और पिण्डदण्ड कैसे और किससे बना है?\nइसकी प्रकृति क्या है? यह कैसे परिवर्तित होता है? ये बदलाव\nकैसे के बारे में किसके द्वारा? यह सब मेरी ओर से सूत्रबद्ध, संक्षिप्त, मजाकिया तरीके से\nसुनो\n\nखशीभिर्बहुधा गीतं छन्दोभिर्विविधैः पृथक।\n\nब्रह्मसूत्रपादैश्चैव हेतुमादभिर्विनिश्चितैः",
  "13.9": "माई चाणन्याओ भक्तिरव्याभिचारिणी\nविविक्तदेशसेवित्वमराथिर्जनासाधि",
  "13.10": "अध्यात्मज्ञाननित्यत्वं तत्त्वज्ञानार्थदर्शनम् |\nएतज ज्ञानमिति प्रोक्तम्ज्ञानं यदातोह्न्यथा",
  "13.2": "क्षेत्रज्ञं च अपि माम् विधि सर्व क्षेत्रेषु भारत।\n\nक्षेत्र क्षेत्रज्ञो ज्ञानं यत् तत् ज्ञानं मातं मम - हे भारत, सभी क्षेत्रों में।\nयह जानो कि मैं ही निवास करने वाला *क्षेत्रज्ञ' हूं। वास्तविक 'ज्ञान' क्षेत्र और क्षेत्र विशेषज्ञों का ज्ञान है\nमेरी राय\n\nभगवान वह क्षेत्रज्ञ हैं जो अंदर और बाहर, सभी क्षेत्रों में पूर्ण हैं। जीव ही क्षेत्र है।\nसच्चा ज्ञान संसार के प्रति जागरूकता है; प्रभु चेतना ब्रह्मांड में व्याप्त है। हम इस दुनिया के भीतर हैं\nआप कैसे हैं यह ब्रह्मांड हमसे किस प्रकार बंधा हुआ है? उस विश्वात्मा ने यह संयम हटा दिया है\nहम प्रभु से कैसे जुड़ सकते हैं? यह जागरूकता ही ज्ञान है। जैसा कि हमने पिछले अध्याय में बताया है\nपंद्रह. हम बाड़ों की जेल में हैं। लेकिन यह सज़ा नहीं, शिक्षा है. इस गिरफ्तारी से\nयदि आप बचना चाहते हैं, तो आपको उस क्षेत्रज्ञ को जानना होगा जो मुक्तिदाता है। यह जागरूकता ही वास्तविक ज्ञान है।\n\nतत् क्षेत्रं यच्च यद्रिक च यद् विकारी यतश्च यत् |\nसच्च यो यत् प्रभश्च तत् समासेण मे शृणु",
  "13.13": "सर्वतःपनीपादं तत् सर्वतः अक्षि शिरः मुखम्।\nसर्वतः श्रुतिमत लोकाय सर्वं अवर्त्य तिष्ठति-सर्वत्र इसके अंग; हर जगह\nआंखें-सिर-मुंह; इसे हर जगह सुनें; यह दुनिया के भीतर की हर चीज़ को कवर करता है।\n\nभगवान हर जगह है. उसके सर्वत्र हाथ-पैर हैं; पूरे कान, चेहरे, मुँह पर,\nआँख\nअलग शब्द इल्लाह 'मुंह' को दर्शाता है)। इस कारण हम प्रभु को नहीं जानते\nकुछ नहीं कर सकते. वह सर्वज्ञ, सर्वज्ञ, सर्वशक्तिमान है। यह सब ट्यून करें\nप्रमाणित करता है। भगवान ने ही आदि में वेदों का उच्चारण किया था। वह हर चीज़ के भीतर है\nवह बाहर ढंका हुआ खड़ा है. शाश्वत भगवान के भीतर उनके अनंत रूप हैं। हर एक को\nरूप में संज्ञानात्मक, रचनात्मक इंद्रियाँ भी होती हैं। हमारे सभी अर्थों में\nवह पूरी तरह से खड़ा है.\n\nसर्वेन्द्रियगुहाभासं सर्वेन्द्रियविवर्जितम् |\n\nअसक्तं सर्वभृचेव निर्गुणं गुणभोक्रु च",
  "12.2": "भगवान उवाच- भगवान ने कहा:\n\nमाई आवेश्य मनः ये माम् नित्य युक्तः उपासते।\n\nश्रद्धया पराया उपेतः ते मेय युक्तः तमः मतः - जिन्होंने मुझमें भर दिया, भर दो\nविश्वास के साथ. खुद को खपा रहा हूं. लगातार उपलब्धियां हासिल करने वाले-सबसे उत्तम\nविचार किया जाएगा.\n\nअर्जुन के प्रश्न का उत्तर देते हुए, कृष्ण कहते हैं: “जो सच्चे मन से मेरी पूजा करता है\nजो लोग ऐसा करते हैं, वे भगवान के सबसे महान साधक हैं। यहां परिश्रम का अर्थ विश्वास है।\nउपलब्धि में परिश्रम का बहुत महत्व है। बिना भक्ति के पूजा करने से कोई लाभ नहीं है। ये है\nमनोविज्ञान इसका एक सांसारिक उदाहरण: रोगी और चिकित्सक। यदि रोगी स्व\nयदि आपको उस डॉक्टर पर भरोसा नहीं है जो जांच करता है और दवा लिखता है, तो आपके द्वारा ली गई दवा उस पर काम नहीं करती है\nनहीं करता अगर गहरी आस्था हो - डॉक्टर जो भी दवा लिखे वह बीमारी है\nयह ठीक हो जाएगा! ये वैज्ञानिक तौर पर भी सिद्ध है. तो बस अपनी आँखें बंद करो-\nबिना आस्था के पूजा व्यर्थ है। दृढ़ निष्ठा के साथ, भगवान को जानकर\nगुणरूप का ध्यान करना सबसे बड़ी भक्ति है। पूरी ईमानदारी से, किसी भी रूप में,\nभगवान की पूजा किसी भी नाम से की जा सकती है। भगवान का अरूप\nऐसा कोई रूप, कोई नाम नहीं जो भगवान का नाम न हो। नाम-रूप जब पूर्ण ध्यान हो\nकोई समस्या नहीं. इस प्रकार भगवान कहते हैं: “जो मेरा रूप और चरित्र विशेष है\nजो सच्चे दिल से पूजा करता है, वह सबसे महान सिद्धियों में से एक है।\n\nये त्वाक्षरमनिर्देश्यमविकथाम् पर्युपासते।\nसर्वत्रगमाचिन्त्यं च कूटस्थमाचलं ध्रुवम् 13\n\nसन्नि यमेन्द्रियग्रामं सर्वत्र समबुद्धयः |\nते प्राप्नुवन्ति मामेव सर्वभूतहिते रतः ॥4॥\n\nयेतु अक्षरं अनिरदेश्यं अव्यक्तं पर्युपासते।\n\nसर्वत्रगं अचिन्त्यं च कुतस्थं अचलं ध्रुवम् ॥\n\nसन्नियम्यैन्द्रिय ग्रामं सर्वत्र सम बुद्धयः।\n\nते प्राप्नुवन्ति मम एव सर्व भूत हिते रतः - अव्यक्त और अविनाशी सिद्धांत। अवाक,\nएक अकल्पनीय सिद्धांत. अगासा बस गया है और हर जगह भरा हुआ है। अस्थिर उदासीनता\n\nसिद्धांत सर्वत्र समभाव से सभी प्राणियों के प्रति भलाई, इंद्रियों पर लगाम रखना\nजो लोग स्वेच्छा से ऐसी निर्वैयक्तिकता का उपभोग करते हैं वे भी मेरे साथ जुड़ जाते हैं।\n\nयहाँ कृष्ण निर्विशेष लक्ष्मी की पूजा का वर्णन करते हैं। विश्वनीति भी ईश्वर की है\nउपासना में भी अन्तर है। दुनिया में एक माँ हमेशा अपने बच्चे ही होती है\nवह गलती माफ कर देती है और पिता दंड देते हैं। लेकिन मां श्रीलक्ष्मी की पूजा और आराधना भगवान द्वारा की जाती है\nपूजा में इसका विपरीत होता है। पूजा में यदि हो जाये कोई भूल माँ\nवह माफ नहीं कर सकती, लेकिन भगवान माफ कर देते हैं।' इसी कारण अक्षर की पूजा कठिन है। यहाँ\nकृष्ण उन बिंदुओं के बारे में बताते हैं जो देवी लक्ष्मी के उपासकों को जानना चाहिए। यह\nइस श्लोक में अनेक विशेषणों का प्रयोग करते हुए वर्णन किया गया है। उसका अमर शरीर है\nपत्र; हमारी बुद्धि के लिए अदृश्य प्रकृति अनिश्चित है; लक्ष्मी अव्यक्त हैं. यह\nसभी गुण भगवान पर भी लागू होते हैं।\n\nवह लक्ष्मी ही हैं जो आकाश में निवास करती हैं, जो संसार की रचना का सिद्धांत हैं और जो संपूर्ण ब्रह्मांड के विस्तार के लिए उत्तरदायी हैं। स्थिर\nऔर वह जो शाश्वत है वह सदैव भगवान के चरणों की पूजा करती है। ऐसी शक्ति\nदेवता की आराधना के लिए कठोर इन्द्रिय संयम आवश्यक है। सभी समभाव से\nयहां दोष रहित दर्शन, पूजन आवश्यक है। [जैसे ललिता\nसहस्रनाम पारायण. यहां थोड़ी सी चूक भी अर्थहीन होगी।] यह\nइस प्रकार कोई भी व्यक्ति नियमित रूप से अवैयक्तिक पूजा के माध्यम से भगवान से जुड़ सकता है। लेकिन\n\nकृष्ण कहते हैं कि यह कोई आसान तरीका नहीं है।",
  "12.16": "अनापेक्षः शुचिः दक्षः उदासीनः गतव्यथाः।\n\nसर्वरामपरित्यागी यः मत भक्तः सः मेई प्रियः - जो कुछ भी नहीं चाहता, संक्षेप में\nजो सतर्क है, जो कुछ भी नहीं पहनता, जो परेशान नहीं है, जो भगवान का उपासक नहीं है।\nवह जो किसी भी कार्य में संलग्न नहीं होता, [भगवान् को सब कुछ मैं-मेरा मानकर अर्पित करता हूँ\nहम्मू भगोड़ा], मेरा ऐसा भक्त मुझे प्रिय है।\n\nइस श्लोक में कृष्ण ने उन छह गुणों के बारे में बताया है जो उनके भक्त में मौजूद होने चाहिए, जो भक्ति के पूरक हैं।\n\n(1)अनापेक्षा: यह चाहना नहीं है कि यह चाहना है। किस क्षणिक सुख से!\nशाश्वत मोक्ष के मार्ग पर चलना, जो आता है उसका अनुसरण किए बिना। आपको क्या मिला?\nइसमें आनंद लेना-यह अवांछनीय है।\n\n(2) शुचिः : स्वच्छ एवं स्वतंत्र होना। यह तह है. मुँह में बुरे शब्द, मन में बुरे\nसोचा, मील में गंदगी है - यह मील में है। सबसे पहले हमें अपने मन की गंदगी को धोना होगा।\nइसका पूरक है बाह्य सफ़ाई। इसके लिए हम शांति पाठ में कहते हैं: “ओम भद्रं कर्णेभिः\nश्रीनुयाम देवः भद्रं पश्येमक्षभिर्यजत्र ह अस। आइए अच्छे पर नजर डालें,\nचलो अच्छी बात करें, अच्छा सोचें। यह एक वास्तविक तह है.\n\nमैडी के बारे में दो और प्रसिद्ध छंद हैं:\n\nअपवित्रः पवित्रोवा सर्ववस्थं गतोपिव |\nयः स्मरेथ पुण्डरीकाक्षम् स बभाभ्यन्तरः शुचिः॥\n\nऔर\nअतिनिलाघनश्यामन् नलिनायतलोचनम् |\nस्मरामि पुण्डरीकाक्षम् तेन सना तो भावम्यहम्।\nउन्होंने कहा कि यहां पुंडरीकाक्ष का स्मरण करना चाहिए. यह भगवान का एक विशेष नाम है.\nपुण्डरीकाक्ष का अर्थ है केन्दवर जैसी आँखों वाला। प्रभु की दृष्टि सदैव बनी रहती है\nकेन्दवारा गुलाब की तरह खिलता और आह भरता है। आमतौर पर जब हम सबसे ज्यादा खुश होते हैं\nहमारी आँखें चौड़ी हो गईं. परन्तु ईश्वर सदैव आनन्द का स्रोत है। प्रभु प्रेम से देखो\nमुझे देखते हुए मैं उनकी आंखों से बहती कृपा की धारा में हूं\nउसकी कृपा की कृपा मुझ पर बह रही है। मैंने कहा कि मैंने इसमें शराब पी है\nदृष्टिकोण साफ़ है. इस प्रकार हमें भगवान की कृपा से अंदर और बाहर से जुड़ना चाहिए।\n(3) दक्ष: हमारे अंदर अपने मन को ईश्वर की ओर निर्देशित करने की क्षमता होनी चाहिए। वह हमारा बाह्य प्रयास है\nक्या हमें भीतर से उसके पास नहीं जाना चाहिए? बाह्य क्रिया ही हमारी आंतरिक उपलब्धि है\nबस इतना ही. हमें प्रभु से कैसे जुड़ना है इसकी समझ और बुद्धि होनी चाहिए।\n(4)उदासीनता : अंतर्मुखी होना। किसी भी बाहरी कार्रवाई पर जोर न दें, उसकी मांग न करें।\nउदाहरण के लिए- आपके परिवार में किसी को किसी चीज़ की इच्छा है\nइसे पूरा करने के लिए वे किसी तरह की पूजा कर रहे हैं। ऐसे में ये फायदेमंद होता है\nयह कहकर इसके विरोध में खड़ा होना कि भगवान की पूजा करना गलत है, ठीक नहीं है। जो कुछ भी है वह ईश्वर का है\nसेवा; प्रार्थना करें कि यह प्रभु से जुड़ जाए। बिना किसी मांग के सबके साथ रहना\nसीखो\n(5) गाथाव्यथा: बिना बोर हुए हमेशा खुश रहना।\n(6) सर्वारंभपरित्यागी: भगवान की सर्वोच्चता के विपरीत किसी भी पहल में संलग्न न होना।\nसभी स्टार्टअप शुरू से करना बंद करें। हर चीज के अंत में कृष्णार्पणमस्तु\nउसे प्रभु में अर्पित करो।\nकृष्ण कहते हैं, 'जो भक्त मुझे इन गुणों से प्रेम करता है, वह मुझे प्रिय है।",
  "13.12": "ज्ञेयं यत् तत् प्रवक्ष्यामि यत् ज्ञात्वा अमृतं अश्नुते।\n\nअनादि मटचरं ब्रह्म न सत् तत् न असत् उच्यते - जिसे जानकर व्यक्ति मृत्यु पर विजय प्राप्त कर लेता है।\nऐसा \"जनेय\" मैं कहता हूं: अजन्मा, [शरीर से पैदा भी नहीं हुआ] ज्ञान है।\nदृश्यमान पृथ्वी-जल-अग्नि से भिन्न; अदृश्य हवा हवाओं से भिन्न होती है।\n\nयहाँ कृष्ण ज्ञान के माध्यम से सीखे जाने वाले ज्ञान के बारे में बताते हैं और कहते हैं:\n\"जो शब्द व्यक्त नहीं कर सकते, तुम क्या ज्ञान जानते हो।\"\n\nअमरता का स्वाद चखो—जो मैं तुमसे कहता हूं।'' भगवान अनादिमत!\nउसका पाँच अनित्य तत्वों का कोई स्वरूप नहीं है। वह ज्ञानानन्द स्वरूप हैं।\nईश्वर के गुण अनन्त हैं। प्रभु हमारे लिए गुणों से परिपूर्ण हैं\nपरिपूर्णता का दाता. वह सर्व-रक्षक है, उससे बड़ा कोई सिद्धांत नहीं है। जैसे\nहम ईश्वर को पूर्णतः नहीं जान सकते। यह वही है जिसके बारे में हम जानते हैं। फिर भी\nसाथ ही हम अपनी क्षमता के अनुसार उसे सही मायने में जान सकते हैं।\n\nसर्वतःपाणिपादं तत् सर्वतोकाक्षीशिरोमुखम् |\nसर्वथाश्रुतिमल्लोके सर्वमावृत्य तिष्ठति",
  "12.4": "भगवान ने इस दुनिया की रचना की और पंद्रह बाड़ों के इस संसार में जीवन रखा। यह\nपंद्रह बाड़ें हैं:\n\n1. परिश्रम की बाड़: वह बाड़ जिसे हटाया नहीं जा सकता- परिश्रम जो जीवन के स्वभाव से आता है। और नंगा किया जाना है\nएक बाड़-रेखा परिवार, ईमानदारी जो उस वातावरण के प्रभाव से आई जिसमें वह बड़ा हुआ।\n\n2-6. पंचभूतों की बाड़: पृथ्वी-जल (अन्नमय कोष) अग्नि-वायु-आकाश (प्राणमय कोष)।\n7. इंद्रियों की बाड़: पांच ज्ञानेंद्रियां और पांच कर्मंद्रियां।\n\n8. डराने-धमकाने की बाड़: ऐसा दिमाग जो बुरा सोचता है\n\n9. धान की बाड़: भोजन\n\n10. शुक्राणु बाड़: ताकत\n\n11. तप: यह विचार कि यह वैसा ही होना चाहिए (जैसा कि थिरुका के सपने में था)।\n\n12. मंत्र: किसी के सपने को साकार करने का मंत्र।\n\n13. कर्मः : सपने को प्राप्त करने के लिए किया गया कर्म।\n\n14. संसार: स्टिरा-चारा संपत्ति (मैंने बनाई है, संपत्ति जो मेरी है)\n\n15. नमदा बेली : कीर्ति(!13738 318 18776)।\n\nइन पंद्रह बाड़ों के अंदर फंसा हुआ सोलहवां *क्षर' जीवन के लिए उपरोक्त है\nलक्ष्मी चित प्रकृति का सत्रहवाँ रूप हैं जिन्हें बेली नामक कमीज पहनाकर इस संसार में भेजा गया है। वह है\nविद्वान पुरुष. अक्षरों से परे भगवान अठारहवें पुरुष हैं। वह है\nमर्दाना गीता में अब तक भगवान ने जिस मुख्य बात पर जोर दिया है वह यही है\n\"जो भक्तिपूर्वक मेरी पूजा करता है वह इस संसारबंध से मुक्त हो जाएगा और मुझसे जुड़ जाएगा।\"\nयहाँ जो प्रश्न हमारे सामने आता है वह यह है - सत्रहवाँ श्रीतत्त्व, भगवान से क्यों छूट गया है\nपूजा नहीं करनी चाहिए? माँ पिता से भी अधिक दयालु होती है। वह माँ जिसने हमें विवाह के बंधन में बाँधा\nक्या पूजा करने से हमारा उद्धार आसान नहीं हो जाता? कौन सा तरीका अधिक उपयुक्त है? -यह है\n\nएक सामान्य प्रश्न जो हर किसी के मन में आता है। स्तुति में कहा गया है कि श्रीतत्त्व की आराधना से मुक्ति संभव है\nऐसा कहा गया है. उदाहरण के लिए, यह तब कहा जाता है जब मंगलारती के दौरान सभी लोग भगवान की पूजा करते हैं और इसका पाठ करते हैं\nनिम्नलिखित श्रीसूक्त पंक्तियाँ:\n\nश्री जात: श्री अनिरयः श्रेयं व्यो जनित्रभ्योद्दधातु |\nश्रीयं वासनाः अमृतत्वमयां भजंति सद्यस्समिधा मिथद्यौं ||\n\nजैसा कि यहां कहा गया है: \"श्रीतत्व की पूजा करने के लिए हमारा जन्म हुआ है। श्रीतत्व।\"\nवह उपासक को धन और साहस प्रदान करती हैं। श्रीतत्त्व उपासना\nजिन्होंने अमरत्व प्राप्त किया। जैसे दम्पति श्रीतत्त्व की पूजा करते हैं\nइच्छा पूरी होगी. वह मुक्तिवादी है”।\nइससे स्पष्ट है कि मोक्ष भी मिल सकता है। भगवान पुरूषोत्तम की पूजा और\nश्रीतत्व या अक्षर उपासना इनमें से कौन सी विधि अधिक उपयुक्त है? यह यहां हम सभी के लिए एक प्रश्न है।\nयह अध्याय हमारे प्रतिनिधि अर्जुन द्वारा भगवान के समक्ष हमारा प्रश्न रखने से संबंधित है\nशुरू होता है. दूसरे शतक के अंतिम अध्याय में केवल बीस श्लोक हैं। अध्याय\nयद्यपि संक्षिप्त, यह अध्याय असाधारण सामग्री वाला अध्याय है। भगवान यहाँ हैं\nयदि हम बताए गए विचारों को अपने जीवन में अपना लें तो हमारा जीवन सार्थक हो जाएगा।\nआइये जानते हैं इस अध्याय में उल्लिखित अद्वितीय गुण-भक्ति संदेश।\n",
  "12.14": "अद्वेष्टा सर्वभूतानां मैत्रः करुणाः एव च।\n\nनिर्ममः निरहंकारः समदुःखसुखः क्षमी॥\n\nसन्तुष्टः सदथं योगी यतात्मा ததுந்தைநிச்சியம்।\n\nमयि अर्पिता मनः बुद्धिः यः मत भक्तः सः मेः प्रियः - जिसके मन में किसी भी जीवित प्राणी के प्रति कोई शत्रुता नहीं है।\nनेहिगा, जो दुःख देखकर पिघल जाता है, जो मैं-मेरा का अभिमान नहीं करता, जो सुख में विस्तार नहीं करता,\nजो कष्ट से नहीं हटता, जो धैर्य नहीं खोता, जो ध्यान में सदैव संतुष्ट रहता है\nजो प्रतिबद्ध है, जो किसी मार्ग पर दृढ़ता से कायम है, जो एक सैद्धांतिक निर्णय द्वारा तय किया गया है, मार्ग-ज्ञान\nमेरे अंदर जो भक्त है - ऐसा मेरा भक्त मुझे प्रिय है।\n\nभगवान जिस मानवीय व्यवहार की प्रशंसा करते हैं, उसका वर्णन करते हुए, कृष्ण पहले कहते हैं: “अद्वेष्टा\nसर्वभूतानाम्”। इसका मतलब है किसी से नफरत नहीं करना. यह भगवद्भक्ति में होना चाहिए\nपहला गुण. नफरत दो तरह की होती है. एक अच्छा (उनका उद्धार देखकर)\nदूसरे से नफरत करना बुरे से नफरत करना है (उनकी बुराई देखकर)। नफरत आएगी\nअधीरता और ईर्ष्या के कारण. दूसरे की समृद्धि देखकर दुःख उठाना ही घृणा है।\nअच्छा या बुरा - अधीर मत होइए। प्यार वहीं करें जहां अच्छाई हो, दोस्ती हो\nबड़े हो जाओ, दुष्टों को दूर छोड़ दो; अच्छाई, अच्छे लोगों से प्यार करो। दूसरे की कठिनाई\nपाया और विलीन हो गया. मैं, मेरा और मुझसे का अभिमान त्याग दो। “ईशावास्यम्\nइदं सर्वम्' - वह भगवान हर चीज का स्वामी है। यह भाव इसलिए है क्योंकि यह उसने दिया है\nजैसा भी हो...कैसे। जिस प्रकार बहुत अधिक अहंकार अच्छा नहीं है, उसी प्रकार अहंकार भी अच्छा नहीं है।\nपुरंदर दास (060166 81800/1600) की तरह प्रेम में स्वतंत्र रहें। पुरंदर दास के पास एक है\nएक बेटा था. उन्होंने प्यार से उसकी देखभाल की. एक दिन प्रिय पुत्र मर गया।\nफिर उन्होंने कहा, \"तोते का कोई पिंजरा नहीं होता - जो तोता आपने दिया था, वह आपसे जुड़ गया है।\"\nरहते थे. हम सुख और दुःख देखते हैं। एक संतुलन बनाना होगा. जब ख़ुशी आती है\nउड़ो मत. जब उदासी आती है तो आपको बिना गिरे उससे निपटना होता है। दूसरों के लिए खेद महसूस करना\nजैसा हो सकता है वैसा रहने दें। कोई बदला नहीं. [न्यायाधीश और अधिकारी गलत काम करने वालों को दंडित कर सकते हैं। इतना ही\n\nउसका कर्तव्य है - कोई बदला नहीं है]।\n\nकृष्ण आगे कहते हैं: \"संतुष्टः सदाचम योगी यतात्मा थमनिश्चयः\"।\nमन की एक अवस्था जो किसी भी इंसान को आरामदायक रहने के लिए चाहिए वह है 'दुख के बिना'।\nजीवन में हमारे सभी दुःखों का कारण दुःख ही है। बजाय इसके कि जो नहीं है उससे दुखी हों\nजो आपके पास है उसमें संतुष्ट रहें। आपके पास जो कुछ है उसी में संतुष्ट रहने का अभ्यास करें। हमेशा\nयोगी बनो. योगी के यहाँ अनेक अर्थ हैं। विभिन्न आसनों का अभ्यास करना योग नहीं है।\nयोग मन को एकाग्र करने की एक प्रक्रिया है। हम बंदरों की तरह रेंगते हैं\nमन को रोकना हवा को रोकने के समान है। यह बहुत अजीब है. दिमाग फिसल जाता है\nहम केवल तभी जानते हैं कि क्या हो रहा है जब यह चला जाता है। सबसे पहले ऐसी सोच रखना बंद करें\nरीढ़ की हड्डी को सीधा रखकर स्थिर बैठने का अभ्यास - आसन (यव)\nआसन ठीक है)। फिर प्राणायाम के माध्यम से आंतरिक विचार को जागृत करना\nयोग. योग भगवान को स्वच्छ मन में बैठाना है, जीवन में जीवन का प्रबंधन करना है\nयोग को जो रास्ता मिला है, उसे निष्ठापूर्वक कर रहा है। इस कदर\nहमें अभ्यास द्वारा अपने मन को वश में करना होगा। जो किसी भी चीज़ को बुरी नजर से नहीं देखता\nअभ्यास अपने आध्यात्मिक पथ पर दृढ़ रहें। चाहे कुछ भी हो दृढ़ संकल्प के साथ आगे बढ़ें\nआगे बढ़ें, मन को प्रभु के लिए तरसने दें। मन को प्रभु को जानने दो। “ऐसा कौन है\n\nजो लोग मुझसे (भक्त) प्यार करते हैं वे मेरे लिए प्रिय हैं, ”कृष्ण कहते हैं।\n\nयस्मान्नो यिदविजते लोको लोकनो यिदविजतेचा यः |\nहर्षमर्षभ्योद्वेगैर्मुक्तो यशाचामे प्रियः",
  "13.14": "वह समस्त इन्द्रियों के विषयों को प्रकाशित करता है — किन्तु स्वयं भौतिक इन्द्रियों से रहित है। किसी से अनासक्त होकर सबका धारण करता है। त्रिगुणातीत है — फिर भी गुणों का भोक्ता है।\n\nयह भगवान् के क्षेत्रज्ञत्व का विरोधाभासी वर्णन। वे सब इन्द्रियों को चेतना देते हैं — स्वयं के भौतिक इन्द्रिय नहीं। सबका बोझ उठाते हैं — किसी से चिपकते नहीं। त्रिगुणों से परे हैं — फिर भी उनका अनुभव करते हैं। यह 'अचिन्त्य' — कारण-तर्क से परे — भगवान् का स्वभाव है।",
  "13.15": "बहि अन्तः च भूतानां आचारं चरम एव च।\n\nस्कृत्वात् तत् अविज्ञानं सुदृढ़ं च अंतिकाय च तत् - वह प्राणियों के बाहर है; अंदर\nवहाँ है; फिर भी हर जगह घूम रहा हूं. यह एक अणु के बजाय एक अणु है; वह अकेला ही जानकारीपूर्ण है।  बस इतना ही\nदूर होकर भी सबके करीब है।\n\nभूत का अर्थ है संपूर्ण ब्रह्मांड, सभी जीवित प्राणी (पिंडंद)। भगवान इस ब्रह्मांड के भीतर हैं\nबाहर तो भरा हुआ है. जैसा कि नारायण उपनिषद में कहा गया है, “अंतरबहिश्च तत्-सर्वम् व्याप्य।\nनारायणः स्थितः”। वह प्रभु जो हममें व्याप्त है और हमारे भीतर और बाहर व्याप्त है-\nनारायण. एक छोटे से जीव से लेकर भीतर और बाहर चतुर्गुण ब्रह्म तक\nईश्वर पूर्ण है. वह हमारे भीतर एक मध्यस्थ के रूप में हमारा मार्गदर्शन कर रहा है\nऔर हमारे बाहर खड़े होकर हमें सम्भाला है। बुद्धिमानों के लिए उनके अंतरतम में एक दर्शन\nप्रभु जो देता है वह अज्ञानियों के लिए खुला है। सर्वव्यापी भगवान अचल है लेकिन वह अनंत है\nरूप सदैव गतिशील रहते हैं। ईश्वर संपूर्ण नैतिक जीवन में पूर्ण रूप से विद्यमान है।\nप्रभु कण-कण में भरे हुए हैं। ईश्वर सर्वज्ञ है परन्तु सर्वज्ञ नहीं। प्रभु का\nहम विस्तार से जान सकते हैं लेकिन पूरी तरह से नहीं।  हम हैं\nसमुद्र में एक छोटी मछली की तरह. यह समुद्र की विशालता को कैसे नहीं जान सका?\nइस प्रकार, संसार का कोई भी जीव भगवान को पूर्ण रूप से नहीं जान सकता। क्योंकि यह हमारा है\nमन अकल्पनीय रूप से सूक्ष्म और विशाल है।\n\nअविभक्तं च भूतेषु विभक्तमिव च स्थितम् |\n\nभूतभारत च तज ग्नेयं गृहस्थ प्रभावविष्णुच",
  "11.53": "भगवान् उवाच —\nसुदुर्दर्शमिदं रूपं दृष्टवानसि यन्मम ।\nदेवा अपि अस्य रूपस्य नित्यं दर्शनकाङ्क्षिणः ॥\nन अहं वेदैः न तपसा न दानेन न च इज्यया ।\nशक्यः एवंविधः द्रष्टुम् दृष्टवान् असि मां यथा ॥\n\n'जो मेरा रूप तुमने देखा — वह सुदुर्दर्शम् है। देवता भी इस रूप को सदा देखने की कामना करते हैं। वेदों से, तपस्या से, दान से, यज्ञ से — ऐसा दर्शन सम्भव नहीं जैसा तुमने देखा।'\n\nविश्वरूपदर्शन केवल अनन्य-भक्ति से सम्भव — यही इस अध्याय का सार।",
  "12.19": "समः शत्रुौ च मित्रे च तथा मन अपमानयोः।\n\nशीत, गरम, सुखी, दुःखी, उदास, संगविवर्जितः।\n\nतुल्य निंदा स्तुतिः मौनी सन्तुष्टः येना केनाचित्।\n\nअनिकेतः स्थिर मतिः भक्तिमान् मे प्रियः नरः - जो शत्रु-मित्रों में भेदभाव नहीं करता; सम्मान-\nजो अपमान, सर्दी-गर्मी, सुख-दुख को समान रूप से देखता है; कुछ नहीं के लिए\nगैर-अनुयायी; जो प्रशंसा को तिरस्कार के रूप में देखता है; विचारमग्न; जैसा भी हो\nइस बीच वह संतुष्ट था; एक ओर वह जो भगवान के प्रति सचेत होकर अस्थिर है\nमुझे ऐसा कठोर व्यक्ति-भक्त पसंद है।\n\nआमतौर पर हम हैं. शत्रु या सहयोगी होने की भावना पर जोर दें\nहमें इसकी आदत हो जाएगी. जो हमारी प्रशंसा करते हैं वे हमारे मित्र हैं, जो हमारी निन्दा करते हैं वे हमारे शत्रु हैं।\nयह हमारी मूर्खतापूर्ण चाल है. दोस्ती के पीछे नफरत हो सकती है, नफरत के पीछे दोस्ती हो सकती है।\nहम यहां याद कर सकते हैं कि पुरंदरदास ने \"निंदकार अवश्य होना चाहिए\" गाया था।\nदुर्व्यवहार करने वाले हमारी गलती है. कर्म करने से हमारे जो निंदनीय दोष होते हैं उनका फल मिलता है\nस्तुति करने वाला हमारे अंदर की भलाई का फल है\n\nहिस्सा मिलेगा. अत: सिद्धि के मार्ग में प्रशंसा करने वालों की अपेक्षा निंदक अधिक सहायक होते हैं।\nइस कारण किसी को शत्रु या मित्र समझकर उसकी आलोचना करना घृणा है\nबंधे मत रहो. विकार से दूर रहो. अच्छे चरित्र से प्यार करें. कहाँ\nअच्छाई का साथ है); दुःख देखकर घुलना (करुणा); दूसरे का\nखुशी पाकर खुश हो जाओ (मुदिता); बुराई (उपेक्षा) से दूर रहें। मूलतः\nशत्रु-मित्र विभाजन की कोई आवश्यकता नहीं है। हर किसी में भगवान देखें. सांसारिक शत्रु-मित्र का भाव\nछोड़ दो\n\nसम्मान मिलने पर फूले नहीं। अपमान होने पर सिकुड़ें नहीं. लज्जा को जीतो.\nइससे कोई फर्क नहीं पड़ता कि कोई और क्या कहता है.  महत्वपूर्ण यह है कि हमारी आत्मा क्या है।\nजब कोई दूसरा हमारी प्रशंसा करता है तो जो गुण हमारे पास नहीं है वह हमारे पास आकर शामिल नहीं होगा। इसी तरह एक और\nहम बिछड़ कर नीचे नहीं जाते. हमें प्रशंसा को लेकर सावधान रहना चाहिए. उसके कारण\nहमारे भटकने की सम्भावना अधिक है। शर्म के मारे हम गलत रास्ता छोड़कर सही रास्ते पर चल पड़ते हैं\nबढ़ने की संभावना है.\n\nसुख और दुख को समान रूप से देखें। कोई भी वस्तु हमें सुख या दुःख नहीं दे सकती। वह वस्तु\nजो अनुभूति हम देखते हैं वह हमें सुख और दुख देती है। तो सर्दी-गर्मी जैसी खुशी-\nदुःख को समान रूप से देखने का अभ्यास करें।\n\nहम सोचते हैं कि ये सब मनुष्य की वृत्तियाँ हैं॥15॥700. लेकिन यह प्राकृतिक धर्म नहीं है. हम हैं\nचिपकना हमें उन गुणों से भर देता है जो हम नहीं चाहते। इसलिए\nप्रशंसा और उपहास पर तुरंत प्रतिक्रिया न करें। चुप रहो मामले पर ध्यान करो.\nजल्दी मत करो. जितना हो सके उतना कम बात करें। सोचो और बोलो.\nजो आपके पास है उसमें संतुष्ट रहें। स्थिर गतिमान वस्तुओं के पीछे (!128176 05 00181)।\nमत जाओ प्रभु ने तुम्हें जो दिया है उसमें खुशी से जियो। भक्ति भाव से\nजब हम ईश्वर के प्रति समर्पण करते हैं तो हम अपनी उपलब्धि के पथ पर इस ऊंचाई तक पहुंच सकते हैं। \"इस कदर\nकृष्ण कहते हैं, गुणों वाला भक्त मेरा प्रिय है।\n\nयतु धर्ममृतमिदं यथोक्तं पर्युपासते |\nश्रद्धान मत परम भक्तस्ते5तिव मे प्रियः",
  "13.18": "इति क्षेत्रं तथा ज्ञानं ज्ञेयं च उक्तं समासतः |\nमत भक्तः एतत् विज्ञानाय मत भावय उपद्यते - इस प्रकार *क्षेत्र'-'ज्ञान' और 'ज्ञेय'\nऐसा लग रहा था जैसे संक्षेप में कहा गया हो. जो मेरा भक्त बनेगा वह मुझमें बना रहेगा।\n\nइस श्लोक में कृष्ण ने अब तक जो कुछ कहा है उसका सारांश देते हुए कहते हैं: “यह क्षेत्र है\nज्ञान के साधनों के बारे में, ज्ञान के इन साधनों के माध्यम से जाने जाने वाले भगवान के बारे में\n(17 3 16616) कहा गया था। सृजन, निर्मित संसार, संसार निर्माण का तरीका,\nसृष्टिकर्ता प्रभु- यदि आप यह जान लें तो फिर कुछ भी जानने को शेष नहीं रहता। पूर्ण\nकृष्ण कहते हैं, ''जो भक्त आस्था और भक्ति के साथ इसे महसूस करता है, वह मुझसे जुड़ जाता है।''\nज्ञान और भक्ति हमें मोक्ष की ओर ले जा सकते हैं।\n\nअगले श्लोक में कृष्ण मौलिक सृष्टि के विचार और उसके दृष्टिकोण की व्याख्या करते हैं। यह\nश्लोक अध्यात्म दुनिया में सृष्टि के बारे में सभी भ्रमों का कृष्ण का उत्तर है। सघन रूप से\nइस श्लोक के माध्यम से कृष्ण ने सब कुछ हमारे सामने प्रस्तुत कर दिया है।\n\nप्राकृत पुरुषं चैव विद्या नदी उभावपि |\nविकरणश्च गुणान्श्चेव विद्धि प्रकृत्सम्भवान्",
  "13.8": "इन्द्रिय अर्थेषु वैराग्यम् अनहंकारः एव च।\n\nजन्म मृत्यु ज़रा व्याधि दुःख दोष अनुदर्शनम् - कामुक मामलों में\nअव्यक्त, अकल्पनीय, जन्म-मृत्यु की दुविधाओं से परिपूर्ण।\nजीवन के दोषों से सावधान रहें,-\n\n(10) इंद्रियार्थेषु वैराग्य: इंद्रियों को बाहरी दुनिया और मन की ओर बहने से रोकता है।\nप्रभु में विश्राम. इसे शमा-धमा कहा जाता है. सांसारिक मामलों के प्रति संवेदना\nइसे बहने से रोकना धर्म है और इसे भगवान की ओर प्रवाहित करना शमा है।\nजब इंद्रियाँ भगवान के प्रति जागरूक होती हैं, तो वे किसी और चीज़ की ओर नहीं बहती हैं। एक सांसारिक ध्वनि, स्पर्श,\nरूप, रस और गंध से घृणा। उदाहरण के लिए, जीभ लचीली होती है। हममें से कुछ लोग घर पर हैं\nअगर ठीक से पकाया भी जाए तो भी ये ठीक नहीं है, ये ठीक नहीं है वगैरह-वगैरह.\nइस तरह की नौटंकी छोड़ो. यहां जो कुछ भी रखा गया है वह बिना किसी चाहत या आवश्यकता के भगवान का है\nइसे प्रसाद के रूप में स्वीकार करना सीखें। ऐसे प्राप्त करें शमा-धमा।\n\n(11) अहंकार : यह सभी गुणों में सबसे बड़ा है। हमारे पास जो भी गुण है वह हमारा है\nअहंकार के आगे व्यर्थ. अहंकार (₹60) हमारे सभी गुणों को नष्ट कर देता है।\nअहंकार के बिना अन्य गुणों का कोई अस्तित्व नहीं है। इसलिए कृष्ण इसे यहां \"एव-चा\" के रूप में जोर देते हैं।\nकहा 'मैं विद्वान हूं, मैं कार्यान्वयनकर्ता हूं, मैं पागल हूं' और इस प्रकार हम पर अहंकार करते हैं\nयह हर मामले में प्रेतवाधित है। इस प्रकार, यदि हम अहंकारी हो जाते हैं, तो हमारा कार्यान्वयन कार्यान्वयन है\nऐसा नहीं होगा जहां अहंकार राज करता है, वहां उपलब्धि व्यर्थ हो जाती है। जहाँ अभिमान है\nकोई ईश्वर नहीं है-अर्थात् हम अहंकार के कारण ईश्वर से विमुख हो जाते हैं। इस वजह से\nयह कहना बंद करें, \"मैंने यह किया, यह मेरे द्वारा किया गया। भगवान ने इसे मेरे हाथों से किया।\"\nउसे कृतज्ञता दिखाओ.\n\n(12) जन्म मृत्यु ज़रा व्याधि दुःख दोष अनुदर्शनम्: जीवन को अंतर्दृष्टि से देखो।\nयह जीवन जन्म और मृत्यु के दो किनारों के बीच बहने वाली एक नदी है। यह\nबाढ़ में रोग, शोक, शोक और शोक की लहरों का सिलसिला। यह हमारा जीवन है\nउद्देश्य क्या है, ईश्वर ने हमें क्यों बनाया, मानव जन्म को कैसे सार्थक बनाया जाये\nउसका पालन करें. भोजन निद्रा भय मिथुन एक समान जीवन नहीं है। जानवर भी ऐसा करते हैं\nअनुभव करो अतः धर्मग्रंथों को पढ़ो और सत्य के अनुरूप सच्चा दर्शन बनाओ।\nकेवल सांसारिक सुख की आशा में जीना बंद करो-सत्य की प्राप्ति के लिए, प्रभु की खोज करो।\nशामिल होने के लिए जियो. सारी सांसारिक सुख-संपदा निसा की है। इसके परे सार है\nप्रभु को जानो और उसकी ओर कदम बढ़ाओ।",
  "13.21": "पुरुषः प्रकृतिस्थः हि भुंक्ते प्रकृतिजां गुणन |\n\nअरुणम गुनासंग अस्य सात असत योनि जन्मसु - प्रकृति, प्रकृति से बंधा हुआ जीवन\nवह सुख-दुःख आदि कर्मों को भोगता है। अच्छे और बुरे समय में जन्म लेना\nजीवन का कारण त्रिगुणों के समान ही है।\n\nप्रकृति निर्मित शरीर में ईश्वर हैं, देवता हैं। लेकिन शरीर में जो है वह सुख और दुःख है\nभोक्ता-जीव। शरीर का निर्माण प्रकृति द्वारा किया गया है। जीवन उसका है\nस्वभाव के अनुसार, पूर्व जन्म के कर्मों के अनुसार उसे इस जन्म में शरीर मिलता है।\n\nजैसा कि पहले उल्लेख किया गया है, जब जीव अपना शरीर छोड़ता है, तो वह गहराई से अवशोषित करता है -\nइसका अगला जन्म उसी के अनुसार तय होगा। अच्छी या बुरी योनि में\nजीवन के उत्पन्न होने के तीन कारण।",
  "13.16": "अविभक्तम् च भूतेषु विभक्तम् एव च ​​स्थितम् |\nभूतभर्त्रु च तत् ज्ञेयं गृहस्थ प्रभावविष्णु च - सभी प्राणियों में एक समान; हालाँकि\nयह किसी अन्य चीज़ की तरह ही विविध है। सभी प्राणी संजोते हैं; भक्षण\nऔर यह जानना चाहिए कि जन्म के समय जो अच्छा होता है वही होता है।\n\nईश्वर इस संसार के प्रत्येक जीवन में एक छवि के रूप में निवास करते हैं। एक के बाद एक\nवह जीवन में अनेक रूपों में विद्यमान है। यहाँ प्रत्येक जीव एक केन्द्रक है। लेकिन भगवान\nकेवल अखण्ड। ईश्वर जो सर्वत्र है वह एक है लेकिन हम अलग-अलग हैं\nबस यही दिखता है. इसका एक अच्छा उदाहरण भगवान के अवतार -परशुराम, वेदव्यास हैं\nऔर भगवान कृष्ण. यहां भगवान ने हमें एक साथ तीन रूपों में दर्शन दिये। हालाँकि वैसा ही\nवह भी हमें तीन के रूप में दिखाई दिये। वह समस्त जीवन के साथ-साथ समस्त जीवन के भीतर भी है\nवह इसे ले गया है. ईश्वर सभी का निर्माता है और एक दिन वह अपनी रचना को नष्ट कर देगा\nवह कर्ता है. विनाश के बाद सृष्टि का पुनर्निर्माण भी वही करते हैं।\n\nज्योतिषमपि तज ज्योतिषमसः परमुच्यते |\nज्ञानं ज्ञानं ज्ञानगम्यं हृदि सर्वस्य विष्ठितम्",
  "12.20": "यतुधर्म अमृतं इदं यथा उक्तं पर्युपासते |\n\nश्रद्धाधानः मत परमः भक्तः ते अतिव मे प्रियः - यह भक्ति ही धर्म मोक्ष का साधन है।\nजो लोग यहां बताए अनुसार योग का अभ्यास करते हैं, वे मेरी महानता में विश्वास करते हैं और मुझमें चलते हैं -\nवह मुझे बहुत पसंद है.\n\nहमारी भक्ति कैसी होनी चाहिए, भक्त में क्या गुण होने चाहिए यह इसका अमृत है।\nकृष्ण, जिन्होंने धर्म की व्याख्या की है, यहाँ निष्कर्ष निकालते हैं: “उपासना जैसा कि यहाँ बताया गया है\nमेरे लिए, जो लोग ऐसा करते हैं, जो लोग सद्गुण विकसित करते हैं, जो लोग भक्ति के साथ अभ्यास करते हैं, वे भक्त हैं\nप्रिय।”\nइति द्वादशो*ध्यायः\nबारहवाँ अध्याय समाप्त हो गया\n\nक्या यह सच है?\n\nअध्याय तेरह\n\nयह भगवत गीता के तीसरे अध्याय का पहला अध्याय है। गीता का यह तेरहवाँ अध्याय एक है\nएक असाधारण अध्याय. इन पिछले बारह अध्यायों में जो कुछ कहा गया है, उसे एकत्रित करें\nइस अध्याय में जो कहा गया है वही करो. पिछली दो शताब्दियों में देखी गई चीज़ों से भरपूर\nविश्लेषण यह अध्याय. निर्जीव संसार, प्रकृति से बंधा हुआ, प्रकृति से पलायन\nवांछित जीवन. मोक्ष के लिए ज्ञान की खोज और प्राप्ति - ये सभी बातें\nजैसा कि हमने पिछले अध्यायों में देखा है, उन सभी का एक संग्रह (सर्वत्र)।\nसंक्षेप में) यह अध्याय। यह अध्याय गीता का सबसे बोधगम्य अध्याय है।\n\nयहाँ शुरुआत में एक श्लोक है. इस अध्याय में आगे जो बताया जाएगा वह स्वयं ही स्पष्ट किया जाएगा\nएक श्लोक जिसमें अर्जुन कृष्ण से जानना चाहते हैं। यह श्लोक पढ़ता है:\n\nप्रकृतिं पुरुषं चैव क्षेत्रं क्षेत्रज्ञमेव च |\nएतद् वेदितुमिच्छामि ज्ञानं ज्ञेयं च केशव ॥*॥\n\nअर्थ – “केशव, मैं जानना चाहता हूँ: प्रकृति, पुरुष, क्षेत्र,\nक्षेत्रज्ञ, ज्ञान और ज्ञान”।\n\nदरअसल यह श्लोक भगवत गीता का श्लोक नहीं है. इस श्लोक का कोई भी प्राचीन भाष्यकार नहीं\nभजन नहीं माना जाता. कई लोगों के अनुसार यह प्रक्षिप्तपश्लोक* है। गाने में\nकुल मिलाकर सात सौ श्लोक हैं। इसीलिए इस गीत को 'सप्तशती' कहा जाता है। [इसके लिए\nवदिराज ने अपनी युक्तिमल्लिका में वेदव्यास का उल्लेख किया है जिन्होंने ब्रह्मसूत्र और भगवद गीता की रचना की थी।\n\"सूत्रसप्तसाथिपते\" कहकर सम्बोधित किया गया है। यह भगवत गीता है जिसमें ऐसे सात सौ श्लोक हैं।\nउपरोक्त श्लोक को जोड़ने पर कुल सात सौ एक श्लोक बनता है। इस श्लोक में आगे\nपिछले अध्याय के अंत में कहीं भी कृष्ण का उल्लेख नहीं किया गया है जो पूछे गए प्रश्न के लिए प्रासंगिक है। यह\nइस वजह से, अर्जुन द्वारा यहां यह प्रश्न पूछने की संभावना नहीं है। अतः यह श्लोक प्रक्षिप्तश्लोक है।\nयह गीता के सात सौ श्लोकों में सम्मिलित नहीं है।\n\nसीधे कृष्ण अर्जुन को क्षेत्र और क्षेत्र का शास्त्रीय अर्थ\nयह अध्याय एक स्पष्टीकरण से शुरू होता है।\n\nभगवान का वचन\nइदं शरीरं कौन्तेय क्षेत्रमिथ्यभिधीयते |\nएतद् यो वेत्ति तं प्राहुः क्षेत्रज्ञ इति तद्विदः ॥1॥\n\nभगवान उवाच- भगवान ने कहा:\n\nइदं शरीरं कौन्तेय क्षेत्रं इति अभिधीयते।\n\nएतत् यः वेत्ति तम प्राहु क्षेत्रज्ञः इति तत् विदः- यह चरित्र जो भगवान के शरीर के समान है।\nसंसार को *क्षेत्र' कहा जाता है। जो लोग इसे जानते हैं वे *क्षेत्रज्ञ' कहलाते हैं।\n\n'फ़ील्ड' शब्द का कोई विशिष्ट अर्थ नहीं है। इस श्लोक में क्षेत्रम् शब्द का क्या अर्थ है?\nकृष्ण ने इशारा किया है समझने का. क्षेत्र का अर्थ है 'इदं शरीरम्'\nकृष्ण. तो यहाँ क्षेत्र का अर्थ है जीवन का निवास, पिंडदान से लेकर ब्रह्मांड तक\nसब कुछ हाँ है. इस ब्रह्मांड के लिए 'क्षेत्र और शरीर' वुडू अन्वार्थनमा (6॥860) है।\nजो क्षेत्र को व्यापक रूप से जानता है वह क्षेत्र विशेषज्ञ है। जैसे कि अगले श्लोक में कौन\nचलो देखते हैं.\n\nक्षेत्रज्ञं चापि माम् विधि सर्वक्षेत्रेषु भारत |\n\nक्षेत्रक्षेत्रज्ञयोर्जनं यत् तज ज्ञानं मातं मम ॥2॥\n\nक्षेत्रज्ञं च अपि माम् विधि सर्व क्षेत्रेषु भारत।\n\nक्षेत्र क्षेत्रज्ञो ज्ञानं यत् तत् ज्ञानं मातं मम - हे भारत, सभी क्षेत्रों में।\nयह जानो कि मैं ही निवास करने वाला *क्षेत्रज्ञ' हूं। वास्तविक 'ज्ञान' क्षेत्र और क्षेत्र विशेषज्ञों का ज्ञान है\nमेरी राय\n\nभगवान वह क्षेत्रज्ञ हैं जो अंदर और बाहर, सभी क्षेत्रों में पूर्ण हैं। जीव ही क्षेत्र है।\nसच्चा ज्ञान संसार के प्रति जागरूकता है; प्रभु चेतना ब्रह्मांड में व्याप्त है।",
  "13.22": "उपद्रष्टा अनुमन्ता च भर्ता भोक्ता महेश्वरः |\n\nपरमात्मा इति च अपि उक्तः देहे अस्मिन् पुरुषः परः - सब कुछ देखने वाला, सब कुछ देखने वाला।\nइच्छानुसार। सर्व-संचालन, सर्व-वाहक, सर्व-व्यापक-सर्वशक्तिमान\nईश्वर इस शरीर में जीवन के साथ सर्वोच्च व्यक्तित्व है।\n\nजब चित्त प्रकृति भौतिक शरीर से शरीर बनाती है, तो जीव उस शरीर में रहता है और इंद्रियों का आनंद लेता है\nदुःख सहना- सबको चलाने वाले के रूप में, सबके ऊपर और सबके करीब\nसाक्षात् दर्शन देने वाला भगवान पूर्ण व्यक्तित्व है। वह हमारे कर्म को जानता है। किस तरह का\nजो जानता है कि कर्म से क्या होगा। वह अन्दर बैठकर इस शरीर को प्रेरणा देता है\nखड़ा है तो निकल जायेगा तो शरीर गिर जायेगा। वह हमारे भीतर कितना दु:ख का स्पर्श है\nआनंद भोक्ता जो हमेशा बाहर आनंदित रहते हैं।",
  "13.25": "अन्ये तु एवं अजन्न्तः श्रुत्वा अन्येभ्यः उपासते।\n\nते अपि च अतितरन्ति एव मृत्युं श्रुतिपरायणः - अब भगवान को इस प्रकार नहीं जानना।\nकुछ लोग जानने वालों से सुनकर पूजा करते हैं। जो सुनने पर भरोसा करता है वह सिद्धि लेकर भी चलता है\nबड़े हो जाओ और मृत्यु पर विजय प्राप्त करो।\n\nजनता, जो उपरोक्त किसी भी तरीके से हासिल नहीं कर सकते-दूसरों से सुनते हैं और सीखते हैं\nवह उपलब्धि की पहली सीढ़ी चढ़ सकता है। यह प्राप्ति के पथ पर सबसे निचला है\nसीढ़ी पर भी वह निरंतर सुन रहा है, ध्यानमग्न है, ध्यानमग्न है, अहंकारशून्य है, ज्ञानी है।\nउस ज्ञान को प्राप्त करके, कोई व्यक्ति ध्यान में भगवान को देख सकता है। आम आदमी के लिए यही कृष्ण हैं\nमोक्ष का मार्ग दिखाया। इस प्रकार उन्होंने श्रवण और आराधना से मृत्यु पर विजय प्राप्त कर ली\nप्रभु से जुड़ सकते हैं.",
  "13.20": "कर्म का कारण क्रिया है\n\nपुरुषः सुखः दुखानां भोक्पतवे हेतुः उच्यते - शरीर और इंद्रियों के निर्माण में।\nजड़प्रकृति [चेतना प्रकृति का श्री तत्व] कारण है। सुख-दुःख के अनुभव में\nजीर्णपरमाता ते कारण है।\n\nइस श्लोक में कृष्ण ने दो बातें कही हैं. हमारा एक शरीर है. शरीर में प्रसन्नता\nदु:ख भोग का अनुभव करने के लिए पांच इंद्रियां हैं। इस प्रकार शरीर, शरीर में इन्द्रियाँ-\nइंद्रियों के माध्यम से सुख और दुख का आनंद - यही जीवन है। उसने जीवन भर पहले ऐसा किया था\nकर्म के अनुसार कारण का लेखकत्व | अर्थात भगवान हमारे कर्म के अनुसार हैं\nजन्म के समय एक रूप दिया गया। हमारे माता-पिता हमारे शरीर के निर्माण की नींव हैं।\nहमारा शरीर प्रकृति से बना है। जगन्माता ही वह हैं जिन्होंने हमें माँ के गर्भ में यह रूप दिया\nश्रीलक्ष्मी. लक्ष्मी भगवान के लिए एक शरीर बनाती है। इस प्रकार शरीर के अंग और\nजीव इंद्रियों को प्राप्त कर उनसे सुख और दुख का अनुभव करता है। परमपुरुष\nभगवान जीवन को सुख-दुख का अनुभव कराते हैं। इस प्रकार शरीर में आत्मा और\nयदि जड़ प्रकृति शामिल है, तो भगवान स्वयं अवतार के रूप में जीवन के जुनून का अनुभव करते हैं\nवह खड़ा होकर देता है.\n\nपुरुषः प्रकृतिस्थो हि भुंक्ते प्रकृतिजां गुणं।\n\nकारण गुणसंगोअस्य सदास्द्योनिजाना सु",
  "13.17": "ज्योतिषं अपि तत् ज्योतिः तमसः परमं उच्यते |\n\nज्ञानं ज्ञानं ज्ञानगम्यं हृदि सर्वस्य विष्ठितम् - यह सभी प्रकाशों में सबसे बड़ा प्रकाश है।\nअँधेरे से परे. यह ज्ञान का एक रूप है. वह स्वयं को जानता है। जानबूझकर\nप्राप्य है. ऐसा लगता है कि यह हर किसी के दिल में बसता है।\n\nकृष्ण ने अब तक जो समझाया है, उसे अपने ध्यान में देखना हमारे लिए कठिन है। इसीलिए कृष्ण\nउन्होंने कविता में भावनात्मक रूप से अपना वर्णन किया है। भगवान अंधकार के बिना प्रकाश है. उस प्रकाश के लिए एक\nकोई अवधि नहीं. यह अनंत है. महाज्योति वह भगवान हैं जो सभी ज्योतियों को प्रकाश देते हैं। भगवान\nजब हम आंखें बंद करके बैठते हैं तो हम ध्यान में अपनी पसंदीदा वस्तु या व्यक्ति को देखना चाहते हैं\nदेखा जा सकता है तो हमें उस व्यक्ति/वस्तु के भीतर ईश्वर को देखने का प्रयास करना चाहिए।\n(क्योंकि भगवान सर्वव्यापी है - वह हर चीज़ के अंदर और बाहर दोनों है)। बाद\n\"भगवान सूर्य में हैं, सौर ऊर्जा उनकी देन है\" का दृष्टिकोण रखना चाहिए। के बाद\nसूर्यमंडल के मध्य में भगवान के चरणों को देखने का प्रयास करना चाहिए। वह पैर का अंगूठा\n\nध्यान में हम देखते हैं कि प्रकाश सिरे से फूटकर हमारे हृदय में प्रवेश कर चमक रहा है\nअनुभव करना चाहिए. यह वह प्रक्रिया है जिसके द्वारा हम ध्यान में कदम दर कदम ईश्वर को देखते हैं। प्रभु यह\nजिसने संसार की सभी ज्योतियों को प्रकाश दिया। हमारे भीतर स्वयं को प्रकाशमान करने की क्षमता होना\nकेवल भगवान के लिए. ईश्वर का प्रकाश अंधकार से परे है। यह ज्ञान स्वरूप प्रकाश है।\nईश्वर ही ईश्वर का पूर्ण ज्ञाता है। हम उसे पर्याप्त शक्ति के साथ जान लेंगे\nप्रयास तो करना ही होगा. भगवान हमारे हृदय में निवास करते हैं। वह सबसे अजीब है\nहमारे हृतकमल के केंद्र में सूक्ष्म से भी सूक्ष्म वास है। हमारे पास ऐसा भगवान है\nइसे केवल भक्ति ज्ञान के माध्यम से ही महसूस किया जा सकता है।\n\nइति क्षेत्रं तथा ज्ञानं ज्ञेयं चोक्तं समासतः |\nमदभा क्ष एतद् विज्ञानाय मद भावयोपपद्यते",
  "13.26": "यावत संजयते किंचित् सत्वं स्थावर जंगमम् |\nक्षेत्र क्षेत्रज्ञ संयोगत तत् विद्धि भरतर्षभा -- भरतर्षभा, स्थिर-गतिशील प्राणियों में से कौन सा\nजान लें कि यदि जन्म हुआ भी है, तो वह क्षेत्र [श्रीतत्त्व] और क्षेत्र, भगवान के सहयोग से है।\n\nइस संसार में जो कुछ भी जन्मा है, सभी स्थावर-जंगम जड़ जगत् हैं और\nइसके उपासक प्राकृत देवी मिलकर इसे क्षेत्र कहते हैं। ये सब जानता है\nप्रभु जो क्षेत्र विशेषज्ञ हैं। तो क्षेत्र भगवान द्वारा निर्मित संपूर्ण जीवित शरीर है\nविश्व समस्त सृष्टि का निर्माण लक्ष्मी नारायण के सहयोग से हुआ था। वे इस दुनिया के हैं\nपहला जोड़ा. तो सबके माता-पिता नारायण और श्रीलक्ष्मी हैं। “यह जानकर\n\nतुम असली भरतर्षभ बन जाओगे,'' कृष्ण कहते हैं।\nजिसमें पूर्ण भक्ति है वही भरतर्षभ है।\n\nसमं सर्वेषु भूतेषु तिष्ठन्तं परमेश्वरम् |\n\nविनाश्यत्स्वविनश्यन्तं यः पश्यति स पश्यति",
  "13.23": "यः एवं वेत्ति पुरुषं प्रकृतिं च गुणैः भी।\nसर्वथा वर्तमान: अपि न सः भूयः अभिजायते - इस प्रकार प्रकृति-पुरुष गुणों से युक्त है।\nचाहे कोई अपना जीवन कैसे भी जिए, उसका दोबारा जन्म कभी नहीं होता।\n\nशाश्वत प्रकृति (जड़ और आत्मा), सभी का कारण भगवान का परम व्यक्तित्व है\nअधीनस्थ जीव जो गुणों सहित इसका एहसास करता है वह ज्ञानी है। इतना बुद्धिमान आदमी बाहर से कैसा होता है\nदिखावे के बावजूद सत्य की अनुभूति से उसे मोक्ष की प्राप्ति होती है। यहाँ बाहरी\nकृष्ण ने इस बात पर जोर दिया कि ज्ञान संस्कारों से अधिक महत्वपूर्ण है। मुखौटे के जीवन से कुछ भी नहीं\nकोई फायदा नहीं. उससे परे सत्य की प्राप्ति है। जब सच्चाई का एहसास होता है\n\nस्वयं ही यह अहसास हो जाता है कि सांसारिक संसार कितना निरर्थक है। ज्ञान से परे\nकोई अन्य पवित्र उपकरण नहीं है. कर्मानुष्ठान में अकास्मात् च्युति ज्ञान के मार्ग पर है\nइसका यात्री पर कोई असर नहीं पड़ता. ज्ञान उसका मार्गदर्शन करता है और उसे रोकता है\nउसे मोक्ष की प्राप्ति होती है.\n\nकृष्ण ने कहा कि प्रकृति और पुरुष को गुणों सहित जानना ही मोक्ष का मार्ग है। यदि ऐसा है\nइसे जानने का तरीका क्या है? कृष्ण इसे अगले दो श्लोकों में समझाते हैं।\nप्रभु से जुड़ने के कई तरीके हैं। हर किसी के लिए सब कुछ नहीं. क्योंकि जैसा कि कोई जानता है\nकिसी और को पता नहीं चलेगा. आइए कृष्ण की इस व्याख्या को सुनें।\n\nध्यानेन*त्मानि पश्यन्ति केचिदात्मनमात्मना |\nअन्ये समख्येन योगेन कर्मयोगेन चापरे",
  "13.24": "ध्यानेन अता त् पश्यन्ति केचित् आत्मानं आत्माना |\nअन्ये सांख्येन योगेन कर्मयोगेन च अपारे - कुछ लोग ध्यान के माध्यम से भगवान को पाते हैं।\nवह अपने आप में अलग दिखते हैं. कुछ वैज्ञानिक ज्ञान के माध्यम से. कुछ कर्म योग के माध्यम से.\n\nसिद्धि प्राप्त करने के लिए सबसे पहले हमें साधना की आवश्यकता है। हीनायोनि पूर्ण नहीं है\nयदि आप एक शरीर में पैदा हुए हैं, तो आप कुछ हासिल नहीं कर सकते। सबसे पहले हमें इंसान बनना होगा।\nशरीर में रहने वाले पुरुष बनना चाहिए)। इसके लिए ''मानव जन्म महान है, इसे बर्बाद करो।''\nइसे मत खरीदो, मूर्खो! \"दशहरा के गीत। यदि किसी के पास सिद्धि के लिए आवश्यक साधना शरीर नहीं है\nकुछ भी संभव नहीं है.\n\nकुछ लोग अपनी योग्यता और ईश्वर की कृपा के कारण जन्मजात ज्ञान के साथ पैदा होते हैं।\nउसके पास ज्ञान है. ऐसे लोग अपने जीवन की योग्यता से अपने जीवन स्वरूप के भीतर - बिम्बारूपी होते हैं\nभगवान के दर्शन हो सकते हैं. ऐसे लोग हमेशा बिना किसी अध्ययन के भगवान का अनुसरण करते हैं\nभीतर देखना-प्रभु से जुड़ता है।  ब्रह्मा सर्व देवता देवांश हैं\nसम्भूत इस प्रकार अपनी आँखें बंद करके भगवान को देख सकते हैं और उनसे जुड़ सकते हैं।\n\nकुछ लोग पहले शुद्ध आत्मतत्त्व विज्ञान के माध्यम से भगवान को जानते हैं। जीवन,\nईश्वर को जानना ही सांख्ययोग है। ऐसे ज्ञान प्राप्त करें, आत्मज्ञान प्राप्त करें, ध्यान प्राप्त करें\nइसके माध्यम से वे प्रभु को पाते हैं और प्रभु से जुड़ जाते हैं।\n\nकुछ अन्य लोग अपने निरंतर कर्मानुष्ठा द्वारा शारीरिक शुद्धता प्राप्त करते हैं, जो कि भगवान का है\nशिष्य बनें, ज्ञान प्राप्त करें, ध्यान में प्रभु को खोजें और प्रभु से जुड़ें।",
  "13.35": "[बन्नञ्जे गोविन्दाचार्य के भाष्य में अध्याय 13 में 34 श्लोक हैं। यह 13.35 उनके पाठ में नहीं है — पिछले श्लोक में समाहित। अध्याय 13 का सार — क्षेत्र-क्षेत्रज्ञ विभाग तथा ज्ञान से मुक्ति — इसी के साथ पूर्ण होता है।]",
  "13.19": "प्रकृतिं पुरुषं च एव विद्धि अनादि उभौ अपि |\n\nविकारं च गुणं च एव विद्धि प्रकृति संभवन् - प्रकृति [शारीरिक और मानसिक प्रकृति] और\nजान लें कि पुरुष [जीव और ईश्वर] दोनों अजन्मे हैं। मैक्रोफॉर्म और गुणत्रय\nजानो कि प्रकृति का कार्य है।\n\nभगवान ने किसी भी जीव या प्रकृति की रचना नहीं की है। प्रकृति, आत्मा प्रकृति,\nपरमपुरुष (भगवान), अवन्तरपुरूष (जीवित प्राणी) सभी शाश्वत हैं। संसार का अर्थ है\nप्रकृति की विकृति. एक बच्चे के जन्म का मतलब यह नहीं है कि जीवन का निर्माण हुआ है। जीवन भर के लिए एक\nआकृति निर्माण. जीव एक आकृति बनाता है जहाँ पिता के शरीर का चेहरा माँ के गर्भ से जुड़ता है\nइस तरह मिलता है. भगवान प्रकृति के माध्यम से प्राणियों के लिए एक आकार बनाते हैं।\nसृष्टि के स्रोत पर भी, लक्ष्मीनारायण दुनिया के निर्माण के लिए माता-पिता के रूप में खड़े थे\nउसने चलाया। सृष्टि के आरंभ में जीव-जन्तु देवी लक्ष्मी के गर्भ में थे। लक्ष्मी देवी परमपुरुष\nवह भगवान के गर्भ में थी. सृष्टि के मूल में लक्ष्मी की खोपड़ी से होमी, भगवान हैं\nचतुर्मुख ब्रह्मा की उत्पत्ति नाभि से हुई। इस कारण चतुर्विध ब्रह्म\nकहा जाता है कि उनका जन्म लक्ष्मी के सिर और भगवान की नाभि से हुआ है। कुल मिलाकर\n\"जो प्रकृति जगत् का कारण है, वह नित्य है; उस प्रकृति से निर्मित जीवन भी शाश्वत है।\"\nदैनिक; इस प्रकृति और जीवन का कारण लक्ष्मीनारायण शाश्वत हैं; दुनिया\nइसका अर्थ है प्रकृति की अव्यवस्था\"। यही मुख्य बिंदु है जिसे हमें यहां जानना आवश्यक है।\n\nराशि से पहले सृष्टि के विस्तार के लिए आवश्यक ऊर्जा का निर्माण हुआ। एक ही प्रकृति का सबसे सूक्ष्म\nअसामान्य गुण. इस ऊर्जा कंपन से पूरी दुनिया बुझ गई। आकार दिया हुआ\nमाँ लक्ष्मी; जो आकार है वह जीवित प्राणी है; नारायण आकार के दाता हैं। इस कारण चतुर्मुख\nब्रह्मा से लेकर सभी दिव्य प्राणी लक्ष्मीनारायण की संतान हैं।\n\nउपरोक्त श्लोक में कृष्ण ने पुरुष और प्रकृति के बारे में बताया। [पुरुष का अर्थ है जीवात्मा और\nईश्वर प्रकृति अर्थात् भौतिक प्रकृति और आध्यात्मिक प्रकृति है]। सृजन प्रक्रिया में ये चार भूमिकाएँ\nकृष्ण हमें अगले तीन श्लोकों में स्पष्टीकरण देते हैं। पहले श्लोक में (slo-\n20) कृष्ण जीवात्मा-परमात्मा, जड़प्रकृति-चेतनप्रकृति का संपूर्ण विवरण देते हैं।\nफिर (श्लोक-21) केवल जड़प्रकृति और जीवात्मा का वर्णन देता है, तीसरा\nश्लोक (श्लोक-22) में सृजन की प्रक्रिया में। परमपुरुष और चेतनप्रकृति के चरित्र का\nवह स्पष्टीकरण हमारे सामने रखता है।",
  "13.27": "समं सर्वेषु भूतेषु तिष्ठन्तं परमेश्वरम्।\n\nविनश्यत्सु अविनाश्यन्तं यः पश्यति सः पश्यति - वह जो सभी प्राणियों में एक समान है।\nसर्वशक्तिमान ईश्वर - वह जो रोने पर भी नहीं मरता। वह जो उसे जानता है \"वास्तव में।\"\nज्ञाता\",\n\nसर्वशक्तिमान भगवान जो सभी जीवित प्राणियों के भीतर एक समान हैं, परम-ईशा-वर हैं। हम किसके आदेश हैं\nमदद नहीं कर सकता लेकिन आज्ञा का पालन कर सकता हूँ; क्या पालन करना हमारा कर्तव्य है; यह हमारे बिना हमारे भीतर जो है उसका पालन करता है\nअज्ञातशक्ति- \"ईशा-वर'। का अर्थ है दार्शनिक देवता। ऐसे दार्शनिक देवता भी\nनियंत्रण करने वाला भगवान परमेश्वर है। ऐसा कोई प्रभु कहीं बैठकर हम पर शासन नहीं कर रहा है। वह है\nवह जो हमारे भीतर है वह हमें नियंत्रित कर रहा है। वह हमारे भीतर स्वतंत्र है और हमें आगे बढ़ाता है\nसंचालन [पूर्वजों ने मंदिर में तात्तिरायण के माध्यम से लोगों को यह संदेश दिया\nदिया]... भगवान मुक्ता56मुक्ता नियमका। हर वक्त सब उसके हैं\nयोग्यता के अनुसार, संबंधित वस्तु की प्रकृति के अनुसार, वह अन्तर्यामी और प्रेरक है\nप्रभु. ईश्वर की सत्ता में कोई श्रेष्ठ या निम्न नहीं है। हाथी में भगवान वही चींटी में भगवान है\nअलग नहीं. परंतु क्योंकि उनकी उपस्थिति में, उस उपस्थिति के अधिष्ठान में अंतर है\nफर्क आ जाता है. हमारे शरीर में ईश्वर की छवि अविनाशी है। वह नष्ट हो गया,\nकोई गिरावट नहीं.  कोई दुःख नहीं. वह अपूर्ण नहीं है. जो इस सत्य को जानता है वही यथार्थ है\nजानकार. इस श्लोक में वर्णित बात को पुनः अगले श्लोक में स्पष्ट करें कृष्ण\nसमझाता है:\n\nसमं पस्यां हि सर्वत्र समवस्थितमेश्वरम् |\n\nन हिंसात्मान55त्मानं ततो याति परमं गतिम्",
  "13.33": "यथा प्रकाशयति एकः कृत्स म लोकं इमाम रविः।\n\nक्षेत्रं क्षेत्रं तथा कृत्स्नं प्रकाशयति भारत -भारत, एक सूर्य एदि\nअकेले भगवान, *क्षेत्रज्ञ', ने पृथ्वी को प्रकाशित करने के लिए *क्षेत्र', ब्रह्मांड पर प्रहार किया।\nचमकता\n\nजिस प्रकार एक ही सूर्य सम्पूर्ण ब्रह्माण्ड को प्रकाशित करता है, उसी प्रकार भगवान भी सम्पूर्ण जगत को जानने वाले हैं\nप्रकाशित करता है हमें सबसे पहले ईश्वर के प्रकाश (ज्ञान) को जानना चाहिए। तब हमारे भीतर प्रकाश\nहम समझते हैं.\n\nक्षेत्रक्षेत्रयोरेवमन्तरं ज्ञानचक्षुषा |\n\nभूतप्रकृतिमोक्षं चये विदुर्यन्ति ते परमं",
  "13.28": "समं पस्यां हि सर्वत्र समवस्थितं ईश्वरम् |\n\nन हिनास्ति आत्मान आत्मानं ततः याति परम गतिम् - सर्वशक्तिमान भगवान हर जगह हैं।\nबिना उतार-चढ़ाव के.. वह एकरूप है.. जैसे. जो जानता है वह अपनी समृद्धि के लिए स्वयं है\nरास्ते में मत आओ. आगे उसे परम वचन की प्राप्ति होती है।\n\nहम अपने शरीर में स्थित हैं। लेकिन प्रभु \"समाविष्ट\" हैं। हम जो इस शरीर में हैं, इस शरीर के हैं\nकोई ज्ञान नहीं है. हम कभी नहीं जानते कि हम कहाँ हैं। हम अंदर ही अंदर सुख और दुख का अनुभव कर रहे हैं।\nलेकिन भगवान दुख अज्ञान के स्पर्श से रहित आनंदमूर्ति हैं। वह हमारे बीच के परोपकारी व्यक्ति हैं।'\nवह देवताओं के साथ सामंजस्य में ऊंचा है। दुःख और अज्ञान के स्पर्श के बिना किसी को भी भगवान द्वारा स्पर्श नहीं किया जाता है\nश्रेष्ठता या हीनता की दृष्टि से मत देखो. प्रत्येक का अपना कर्म और जीवन शक्ति है\nवह बराबरी का दिखता है. भगवान हमारे जगदीश्वर हैं जो सभी जड़-भूतों के भीतर स्थित हैं\nवह हमें जीवन की प्रकृति के अनुसार, कर्म के अनुसार संचालित कर रहा है। जब आप इस सत्य को जानते हैं, “आप\nकृष्ण कहते हैं कि आप हिंसा के बिना भी रह सकते हैं। आपकी जागरूकता के बिना, ईश्वर की जागरूकता के बिना\nजीना यातना है. एक बार \"मैं क्या हूँ\" और मेरे भीतर भगवान क्या है\nअगर आप हकीकत जान लें तो कोई हिंसा नहीं होगी. यह जाने बिना जीना अज्ञानता और दुख का जीवन है।\nजीवन में जो कुछ भी घटित होता है - \"मेरे पिछले कर्मों का परिणाम - वह भगवान है।\"\nयदि आप जानते हैं कि आपने यह किया है, तो आप बिना कष्ट के खुशी से रह सकते हैं। हम अपने मन हैं\nदुःख देना वही सुख देना। हम अपनी समझ के कारण दुःखी हैं\nलेकिन किसी और चीज़ से नहीं. उदाहरण के लिए, एक अमीर आदमी किसी कारण से अपने कब्जे में है\nसारी संपत्ति खो देता है. तब उन्होंने कहा, “यह घटना मेरे पूर्व जन्म के कर्म के अनुसार है\nघटित हुआ सब प्रभु की लीला है; वह दाता है, और वह लेने वाला है;\nवह वही है जो आज्ञा का पालन करता है; उन्होंने कहा, ''मुझे इस बारे में चिंता क्यों करनी चाहिए.''\nखुश हो सकते हैं. इसके अलावा, यदि ब्रह्मांड ऐसा व्यवहार करता है जैसे कि वह अपने सिर पर गिर गया है, तो वह हम हैं\nजैसे हमें प्रताड़ित किया गया. हमें हर चीज़ को एक दर्शक के रूप में देखने का अभ्यास करना चाहिए। प्रभु का\nजागरूकता के साथ ऐसा शांतिपूर्ण जीवन हमें सर्वोच्च मोक्ष की ओर ले जा सकता है।\n\nअगले श्लोक में कृष्ण हमें भगवान के विचार का एक और पहलू प्रस्तुत करते हैं।\nअगर हम इस श्लोक को ध्यान से देखें तो हमें सच्चाई का पता चल जाएगा। यह हम सभी में है\nएक भ्रम यह है- \"क्या मैं कर्म करता हूँ या भगवान मुझसे कराते हैं?\"\nयदि ईश्वर ऐसा कर सकता है, तो वह मुझसे कुछ बुरा क्यों करवाता है?” इस सवाल का जवाब कृष्णा ने दिया\nइसका जवाब उन्होंने इस श्लोक में दिया है. यहाँ वापस. कृष्ण ने क्या कहा\nहमें इस श्लोक को ध्यान से देखने की जरूरत है.",
  "13.32": "शरीरस्थः अपि कौन्तेय न करोति न लिप्यते - कौन्तेय, सर्वोच्च सत्ता जो कभी पैदा नहीं होती;\nजो गुणों से आसक्त नहीं है; इससे वह नहीं मरता. वह शरीर के अंदर जो कुछ भी है\nनहीं करता; इससे कुछ भी चिपकता नहीं है। जड़\nमैं किस बारे में बात कर रहा हूँ! वह सब कुछ करता है; कुछ भी नहीं चिपकता।]\n\nएकमात्र चीज जो निर्विकार है वह भगवान है। वह कभी भी किसी विशेष कारण से नहीं\nभगवान त्रिगुण्यवर्जिता का जन्म नहीं हुआ। इस कारण उसमें कभी परिवर्तन या कुरूपता नहीं आती। वह है\nयद्यपि वह सभी जीवित प्राणियों में अवतरित है, फिर भी उसे शरीर से कोई लगाव नहीं है। वह सब हममें से हैं\nकरता है लेकिन किसी बात पर अड़ता नहीं है. वह हर काम वैराग्य से करता है लेकिन\nउसका किसी भी चीज़ के लिए कोई दोष नहीं है। यह समझने के लिए कि यह कैसा है - कृष्ण एक हैं\nअगले श्लोक में वे उदाहरण देकर समझाते हैं।\n\nयथा सर्वगतं सौक्ष्मदकसं नोपलिप्यते।\nसर्वत्रवस्थितो देहे तथा$5त्मा नोपलिष्यते ॥302॥\n\nयथा सर्वगतम् सौक्ष्मत् आकाशम् न उपलिप्यथे |\n\nसर्वत्र अवस्थितः देहे तथा आत्मा न उपलिप्यथे - यद्यपि आकाश सर्वत्र है\nचूँकि यह अत्यंत लचीला है, यह किसी भी अन्य चीज़ से नहीं चिपकता - यहाँ तक कि सर्वोच्च सत्ता से भी नहीं\nसभी शरीर भरे हुए हैं लेकिन चिपचिपे नहीं हैं।\n\nहर जगह आसमान है. इसके बिना कोई जगह नहीं है. ऐसे आकाश में सर्वत्र कोई भी वस्तु कैसे चिपकी नहीं रह सकती\nफिर भी, भले ही भगवान सभी शरीरों में मौजूद हैं, फिर भी वे किसी भी चीज़ से अनासक्त हैं।\n\nयथा प्रकाशयत्येकः कृत्स्नं लोकमिमान रविः |\nक्षेत्रं क्षेत्रं तथा कृत्स्नं प्रकाशयति भारत",
  "13.31": "अनादित्वात् निर्गुणात्वत् परम आत्मा अयम् अव्ययः।\n\nशरीरस्थः अपि कौन्तेय न करोति न लिप्यते - कौन्तेय, सर्वोच्च सत्ता जो कभी पैदा नहीं होती;\nजो गुणों से आसक्त नहीं है; इससे वह नहीं मरता. वह शरीर के अंदर जो कुछ भी है\nनहीं करता; इससे कुछ भी चिपकता नहीं है। जड़\nमैं किस बारे में बात कर रहा हूँ! वह सब कुछ करता है; कुछ भी नहीं चिपकता।]\n\nएकमात्र चीज जो निर्विकार है वह भगवान है। वह कभी भी किसी विशेष कारण से नहीं\nभगवान त्रिगुण्यवर्जिता का जन्म नहीं हुआ। इस कारण उसमें कभी परिवर्तन या कुरूपता नहीं आती। वह है\nयद्यपि वह सभी जीवित प्राणियों में अवतरित है, फिर भी उसे शरीर से कोई लगाव नहीं है। वह सब हममें से हैं\nकरता है लेकिन किसी बात पर अड़ता नहीं है. वह हर काम वैराग्य से करता है लेकिन\nउसका किसी भी चीज़ के लिए कोई दोष नहीं है। यह समझने के लिए कि यह कैसा है - कृष्ण एक हैं\nअगले श्लोक में वे उदाहरण देकर समझाते हैं।\n\nयथा सर्वगतं सौक्ष्मदकसं नोपलिप्यते।\nसर्वत्रवस्थितो देहे तथा$5त्मा नोपलिष्यते ॥302॥\n\nयथा सर्वगतम् सौक्ष्मत् आकाशम् न उपलिप्यथे |\n\nसर्वत्र अवस्थितः देहे तथा आत्मा न उपलिप्यथे - यद्यपि आकाश सर्वत्र है\nचूँकि यह अत्यंत लचीला है, यह किसी भी अन्य चीज़ से नहीं चिपकता - यहाँ तक कि सर्वोच्च सत्ता से भी नहीं\nसभी शरीर भरे हुए हैं लेकिन चिपचिपे नहीं हैं।\n\nहर जगह आसमान है. इसके बिना कोई जगह नहीं है. ऐसे आकाश में सर्वत्र कोई भी वस्तु कैसे चिपकी नहीं रह सकती\nफिर भी, भले ही भगवान सभी शरीरों में मौजूद हैं, फिर भी वे किसी भी चीज़ से अनासक्त हैं।\n\nयथा प्रकाशयत्येकः कृत्स्नं लोकमिमान रविः |\nक्षेत्रं क्षेत्रं तथा कृत्स्नं प्रकाशयति भारत",
  "14.2": "इदं ज्ञानं अपसृत्य मम साधर्म्यं अगतः।\nसुरगे अपि न उपजायन्ते प्रलय न व्यथन्ति च - इस ज्ञान को प्राप्त करो और मुझसे छुटकारा पाओ।\nसृष्टि के समय समानताएँ उत्पन्न नहीं हुईं; इससे बाढ़ के समय कोई नुकसान नहीं होता है।\n\nइस श्लोक में 'अपाश्रित्य' शब्द का विशेष अर्थ है। \"अन्यत् सर्वम्\"।\nअपाहय*$श्रयाणं-अपा5श्रयणः भगवान में \"दूसरा कोई नहीं है - आप ही मेरी शरण हैं\"।\nआश्रय प्राप्त करने को यहां 'अपाश्रित' कहा जाता है। जैसा कि द्वादश स्तोत्र कहता है:\n\nकुरु भूङ्क्षश च कर्म निजं नियतं हरिपदाविनाम्रधिया शतधाम |\n\nहरिरेव परो हरिरेव गुरुः हरिरेव जगत्पितृमातृगतिः ॥ 1\nयह 'अपाश्रित्य' शब्द का मूल अर्थ बताता है। यहाँ कृष्ण कहते हैं: \"लक्ष्मी-नारायण\nजो जगत् के माता-पिता के ज्ञान से मुझे भजते हैं, वे मेरे ही समान दिव्य स्वरूप हैं\nउन्हें मिलेगा।” ऐसे लोग सभी दोष खो चुके होते हैं और त्रिविध अवस्था में होते हैं\nवह भगवान से जुड़ जाता है और भगवान में ही निवास करता है। यह संसार लक्ष्मी-नारायण द्वारा रचा गया है\nऔर जाओ और उनसे जुड़ जाओ. जो इसे जानता है वह जन्म और मृत्यु से परे हो सकता है। वह कभी वापस नहीं आया\nयह पारिवारिक बंधन अटूट है. यहाँ 'उपजायते' शब्द का प्रयोग हुआ है।  संस्कृत में\n\"उप\" का अर्थ है \"श्रेष्ठ\"। जर्मन\nयह भाषा में है. \"606ga\" है। कन्नड़ में उपरी का अर्थ है \"उप\" - \"ऊपर\"।\nदेता है]। तो \"उपजायते\" का अर्थ है श्रेष्ठ जन्म। यह प्रभु की जागरूकता है\nशारीरिक मुद्रा के साथ जन्म लेना ही उच्च जन्म है। आध्यात्मिक उपलब्धि से जन्म ऊंचा\n\"उपपीढ़ी\"। जिसने अपने जीवनकाल में इस सृष्टि के स्रोत का ज्ञान प्राप्त कर लिया उसका दोबारा जन्म नहीं हो सकता।\nवह भगवान में निरंतर बने रहने के सर्वोच्च शब्द को प्राप्त करता है।\n\nमम योनिर्महद् ब्रह्मा तसि तुस गर्भं दधाम्यहम् |\nसंभवतः सर्वभूतानां ततो भवति भारत",
  "13.29": "प्रकृति एव च ​​कर्माणि क्रियमाणानि सर्वषा |\n\nयः पश्यति तथा आत्मानं अकर्तारं सः पश्यति - सभी कर्म स्वभावतः।\nहो रहे हैं [जीवन के कर्म के अनुसार भगवान स्वयं सभी गतिविधियों में हस्तक्षेप करते हैं और नेतृत्व करते हैं]\nवह जो यह जानता है और कुछ भी करने के लिए स्वतंत्र नहीं है [भगवान के लिए एक और कारण\nवह जो जानता है कि कोई पुरुष नहीं है] वह \"वास्तव में ज्ञाता\" है।\n\nकृष्ण कहते हैं, \"जो जानता है कि 'मैं' नहीं कर रहा हूं, वह जानता है\"।\nइसलिए सबसे पहले हमें \"मैं कर रहा हूँ\" अहंकार को छोड़ना होगा। मैं हूं\nऐसा करना केवल एक व्यावहारिक सत्य है, पारलौकिक सत्य नहीं।\nउदाहरण के लिए: \"मैं बोल रहा हूँ\"। मैं यहां बोलने वाला पहला व्यक्ति हूं\nमूर्ख मत बनो. . उसके लिए। मनुष्य का शरीर उचित अंगों से युक्त होना चाहिए।\nबोलने के लिए, मेरा दिमाग चीजों को सही समय और संदेश पर सोचता है\nअग्रेषित किया जाना चाहिए. इसका मतलब है कि मुझे इसके लिए सही मस्तिष्क शक्ति की आवश्यकता है। मैं बोलने का साहस करता हूं\nअब आइए अपने आप से प्रश्न पूछें: मेरे पास एक मानव शरीर है जो बोल सकता है\nकिसने दिया? किसने मुझे विचारशील मस्तिष्क प्रदान किया और डिज़ाइन किया? समय में\nवास्तव में इस मस्तिष्क से संदेश किसने प्रसारित किया? बोलने की अद्भुत कला\nयह मुझे किसने दिया? इन सभी प्रश्नों से हम जो जानते हैं वह है: “मेरे भीतर\nयह सत्य है कि प्रभु ने खेला-मैंने खेला। यही बात भगवान यहाँ समझाते हैं\n\"प्रकृत्येव च कर्माणि क्रियमाणानि सर्वशः\"। उनकी जीव प्रकृति को।\nतदनुसार, प्रकृति (त्रिगुणों) के प्रभाव में, प्राकृत पुरुष (लक्ष्मीनारायण) हमसे।\nकर्म हो गया. इसलिए, जीवन की प्रकृति के अनुसार जो शाश्वत रूप से जीवन में आया\nउसका शरीर रचा गया; तदनुरूप उस पर वातावरण के त्रिगुणों का प्रभाव; त्रिगुणों का\nउनके सभी प्रकार के कर्म प्रभाव के रूप में हैं। इन सबका कर्ता-धर्ता- देवताओं का स्वामी,\n\nलक्ष्मी के साथ नारायण.\n\nयदा भूतपृथग् भावमेकस्थमनुपश्यति।\nतत एव च ​​विस्तारं ब्रह्म संपद्यते तदा 130।\n\nयदा भूत पृथक भावं एकस्गम अनुपश्यति।\nततः एव च ​​विस्तारं ब्रह्म सम्पद्यते तदा - सभी जीव एक ही भगवान में निवास करते हैं।\nकि, जब उसे पता चलता है कि इस प्रकार का बीज उसी का है, तो वह प्रभु से जुड़ जाता है।\n\nजीवन शाश्वत है. सृजन और विनाश तो दृश्य रूप मात्र हैं। प्रजाति\nहर एक पृथक भव है। कोई भी दो प्रजातियाँ 100% समान नहीं हैं। इनमें से कई\nजीवन का समुदाय एक ही प्रभु में है। सृष्टि के समय यह प्रभु के गर्भ से निकला\nजीवन के जो रूप आकार लेते हैं वे जलप्रलय के दौरान सूक्ष्म रूप में भगवान के गर्भ में लौट आते हैं\nहमें इसे संदर्भ में लेना होगा। इस बात को कौन समझ पाता है\nयदि वह ऐसा कर सके तो मोक्ष प्राप्त कर सकता है।\n\nअनादित्वान्निर्गुणत्वात् परमात्मकायमवियः।\n\nशारिसाथो*पी कौन्तेय करोति न लिप्यते",
  "13.30": "प्रकृति एव च ​​कर्माणि क्रियमाणानि सर्वषा |\n\nयः पश्यति तथा आत्मानं अकर्तारं सः पश्यति - सभी कर्म स्वभावतः।\nहो रहे हैं [जीवन के कर्म के अनुसार भगवान स्वयं सभी गतिविधियों में हस्तक्षेप करते हैं और नेतृत्व करते हैं]\nवह जो यह जानता है और कुछ भी करने के लिए स्वतंत्र नहीं है [भगवान के लिए एक और कारण\nवह जो जानता है कि कोई पुरुष नहीं है] वह \"वास्तव में ज्ञाता\" है।\n\nकृष्ण कहते हैं, \"जो जानता है कि 'मैं' नहीं कर रहा हूं, वह जानता है\"।\nइसलिए सबसे पहले हमें \"मैं कर रहा हूँ\" अहंकार को छोड़ना होगा। मैं हूं\nऐसा करना केवल एक व्यावहारिक सत्य है, पारलौकिक सत्य नहीं।\nउदाहरण के लिए: \"मैं बोल रहा हूँ\"। मैं यहां बोलने वाला पहला व्यक्ति हूं\nमूर्ख मत बनो. . उसके लिए। मनुष्य का शरीर उचित अंगों से युक्त होना चाहिए।\nबोलने के लिए, मेरा दिमाग चीजों को सही समय और संदेश पर सोचता है\nअग्रेषित किया जाना चाहिए. इसका मतलब है कि मुझे इसके लिए सही मस्तिष्क शक्ति की आवश्यकता है। मैं बोलने का साहस करता हूं\nअब आइए अपने आप से प्रश्न पूछें: मेरे पास एक मानव शरीर है जो बोल सकता है\nकिसने दिया? किसने मुझे विचारशील मस्तिष्क प्रदान किया और डिज़ाइन किया? समय में\nवास्तव में इस मस्तिष्क से संदेश किसने प्रसारित किया? बोलने की अद्भुत कला\nयह मुझे किसने दिया? इन सभी प्रश्नों से हम जो जानते हैं वह है: “मेरे भीतर\nयह सत्य है कि प्रभु ने खेला-मैंने खेला। यही बात भगवान यहाँ समझाते हैं\n\"प्रकृत्येव च कर्माणि क्रियमाणानि सर्वशः\"। उनकी जीव प्रकृति को।\nतदनुसार, प्रकृति (त्रिगुणों) के प्रभाव में, प्राकृत पुरुष (लक्ष्मीनारायण) हमसे।\nकर्म हो गया. इसलिए, जीवन की प्रकृति के अनुसार जो शाश्वत रूप से जीवन में आया\nउसका शरीर रचा गया; तदनुरूप उस पर वातावरण के त्रिगुणों का प्रभाव; त्रिगुणों का\nउनके सभी प्रकार के कर्म प्रभाव के रूप में हैं। इन सबका कर्ता-धर्ता- देवताओं का स्वामी,\n\nलक्ष्मी के साथ नारायण.\n\nयदा भूत पृथक भावं एकस्गम अनुपश्यति।\nततः एव च ​​विस्तारं ब्रह्म सम्पद्यते तदा - सभी जीव एक ही भगवान में निवास करते हैं।\nकि, जब उसे पता चलता है कि इस प्रकार का बीज उसी का है, तो वह प्रभु से जुड़ जाता है।\n\nजीवन शाश्वत है. सृजन और विनाश तो दृश्य रूप मात्र हैं। प्रजाति\nहर एक पृथक भव है। कोई भी दो प्रजातियाँ 100% समान नहीं हैं। इनमें से कई\nजीवन का समुदाय एक ही प्रभु में है। सृष्टि के समय यह प्रभु के गर्भ से निकला\nजीवन के जो रूप आकार लेते हैं वे जलप्रलय के दौरान सूक्ष्म रूप में भगवान के गर्भ में लौट आते हैं\nहमें इसे संदर्भ में लेना होगा। इस बात को कौन समझ पाता है\nयदि वह ऐसा कर सके तो मोक्ष प्राप्त कर सकता है।\n\nअनादित्वान्निर्गुणत्वात् परमात्मकायमवियः।\n\nशारिसाथो*पी कौन्तेय करोति न लिप्यते",
  "14.7": "रजः रागमकम् विधि तृष्णा संग समुद्धवम्।\nतत् निबध्नति कौन्तेय कर्मसंगेन देहिनम् - रजोगुण मनोरंजन, इच्छाओं और वासनाओं का मनोरंजन करता है।\nजान लें कि यह कुछ ऐसा है जो सृजन करता है। कौन्तेय, यह जीवन को कर्म के बंधन से बांधता है।\n\nराजस्सु का अर्थ है 'राग', किसी चीज़ के प्रति लगाव, इच्छाओं की डोर - ये सब\nपाँचों इन्द्रियों की इच्छा रजोगुण के प्रभाव से उत्पन्न होती है। यह तृष्णा और संगा के लिए है\nकारण यहाँ तृष्णा का अर्थ है चाह-अचानक की प्यास। संग का अर्थ है किसी वस्तु की निरंतरता\nरजोगुण का साथ इच्छा उत्पन्न करता है। उस चाहत से साथ, उस चाहत से साथ\nइसे चिपचिपा बनाता है. इस प्रकार चरण दर चरण रजोगुण हमें अलग नहीं कर सकता\nगिरफ़्तारी (निबध्नति)। इसके प्रभाव से हम ज्ञान की इच्छा से रहित कर्मसंग हैं\nचलिए शुरू करते हैं. उदाहरण के लिए: पैसे के लिए, पैसे के लिए लड़ना। संपूर्ण जीवन\nद्वंद संसार आदि की भाँति समर्पित युद्ध करना, यह राजस का गहरा बंधन है\nप्रभाव\nतमस्त्रज्ञानजं विधि मोहनं सर्वदेहिनम्।\n\nप्रमादलस्यानिद्राभिस्ताननि बधना तिभरता",
  "13.34": "क्षेत्र क्षेत्रज्ञो एवम् अन्तरं ज्ञानो चक्षुषा।\n\nभूत प्रकृति मोक्षं च ये विदुः यन्ति ते परम - क्षेत्र-क्षेत्रज्ञों के बीच का यह अंतर,\nपंचभूतों से और प्रकृति से [जीवित प्राणी को प्रकृति से] मुक्ति दिलाई।\nजो लोग ज्ञान के मार्ग पर चलते हैं वे परम को प्राप्त करते हैं।\n\nयह श्लोक इस अध्याय को समाप्त करता है। फील्ड क्या है, फील्ड एक्सपर्ट क्या है, फील्ड और फील्ड एक्सपर्ट क्या है\nइनमें क्या अंतर है; मोक्ष साधक को जीवजता जड़ से मुक्त होना चाहिए\nगुण - जो लोग इन सभी को महसूस करते हैं और उन्हें अभ्यास में लाते हैं वे सर्वोच्च भगवान रहते हैं\nशामिल हो जायेंगे\nइति त्रयोदशो*ध्यायः\nतेरहवाँ अध्याय समाप्त हो गया\n\nक्या यह सच है?\n\nअध्याय चौदह\n\nयद्यपि गीता में यत्र-तत्र उपलब्धियों का उल्लेख किया गया है, परन्तु वह ईश्वर का स्वरूप है\nमहिमा की चर्चा अक्सर होती रही है. हम भगवान की ऐसी पूजा के चेहरों का वर्णन करते हैं\nइसके बाद देखा गया. बारहवें अध्याय (श्लोक-05) में कृष्ण कहते हैं, \"श्रीतत्व की पूजा महान है\nकठिनाई, यह सीधे रास्ते को छोड़कर घूम-घूम कर ईश्वर तक यात्रा करने जैसा है, साधक यही करते हैं।\nइसे बड़ी कठिनाई से प्राप्त करना पड़ता है''-चेतावनी दी। तेरहवें अध्याय (श्लोक-26) में-\n\"जो कुछ भी सिरा और जीवित प्राणियों से पैदा हुआ है वह क्षेत्र [श्रीत्व] और क्षेत्रज्ञ [भगवान] का है।\nयह एसोसिएशन द्वारा है।” आमतौर पर जब सृष्टि की बात आती है तो ईश्वर ही सृष्टि है\nहम कहते हैं 'हो गया'। यहां लक्ष्मी का कोई जिक्र नहीं है. लेकिन पिछले अध्याय में कृष्ण\nस्पष्ट रूप से कहा गया है: \"यह सृष्टि लक्ष्मीनारायण के विवाह का फल है\"। इस रचना के कारण\nउत्पत्ति के चिंतन में एक साथ लक्ष्मीनारायण की स्तुति करना महान है। लक्ष्मी की स्तुति करते हुए\nइसके अलावा आचार्य ने कहा कि नारायण की स्तुति करनी चाहिए और लक्ष्मी की स्तुति करनी चाहिए\nयह भजन में स्पष्ट रूप से दर्शाया गया है। वहां देवी लक्ष्मी की स्तुति 'श्रीसपुति' कहती है:\nविश्वस्तिप्रथालयसर्गमहवभूति वृत्तिप्रकाशनीयमवृत्ति बंधमोक्षः |\nयस्य अपांगलवमात्रत उर्जिता स श्रीः यत्कटक्षबलवत्यजितं नमामि ॥ 1\n\nअर्थात, ''लक्ष्मि अपनी पैनी नजर के बल से ऐसे सृजन, संहार और संहार करती हैं।''\nलक्ष्मीपति नारायण को नमस्कार है। यहां लक्ष्मी का संपूर्ण भजन है\nऐसी लक्ष्मी के पति नारायण के रूप में वर्णित है। इसलिए\nलक्ष्मीनारायण की स्तुति लक्ष्मी स्तुति है, केवल लक्ष्मी स्तुति नहीं। इसके लिए मूल गीत\nअध्याय बारह, तेरह और चौदह। बारहवें अध्याय में केवल लक्ष्मी उपासना\nयदि चेतावनी है कि वह ओली है, तो यह संसार तेरहवें अध्याय में है\nलक्ष्मीनारायण के संयोग से निर्मित - अत: हम सब उनकी संतान हैं\nएक सन्देश है. सृष्टि की प्रक्रिया में लक्ष्मी का भगवान के साथ कैसा संबंध है?\nचौदहवाँ अध्याय स्पष्ट करता है। लक्ष्मी, श्री भू-दुर्गा इन तीन रूपों में सत्त्व-रजसु-\nतमोगुण की नियंत्रक शक्ति होने के कारण - उनके पुत्र सात्विक-राजस-तमस हैं।\nतीन प्रकार. इस अध्याय में पहली बार इस मुद्दे का उल्लेख किया गया है। पिछले में से कौन सा\nअध्याय में भी त्रिविद्या का वर्णन उतना स्पष्ट नहीं है। हम इन त्रिगुणों का विश्लेषण करते हैं\nहमारे अंदर के रजस और तमस पहलू को कैसे सात्विक तरीके से ठीक करें\nइस अध्याय में हम इस तथ्य को देख सकते हैं कि उपलब्धि प्राप्त की जा सकती है।\n\nभगवान का वचन\nपरं भूयः प्रवक्ष्यामि ज्ञानं ज्ञानमुत्तमम् |\nयज ज्ञात्वा मुनयः सर्वे परमं सिद्धिमितो गतः ॥1॥\n\nभगवान उवाच- भगवान ने कहा:\n\nपरं भूयः प्रवक्ष्यामि ज्ञानं ज्ञानं उत्तमम् |\n\nयत् ज्ञात्वा मुनयः सर्वे परम सिद्धिं इतः गतः - जानने योग्य सबसे महान वस्तु।\nमैं आपको और अधिक बताऊं; सभी ऋषियों ने इसे देखा और यहीं से परमपद प्राप्त किया।\n\nकृष्ण कहते हैं: \"मैं तुम्हें और बताऊंगा\"। यह बहुत ही महत्वपूर्ण शब्द है. आमतौर पर शिष्य\nगुरु आग्रह करने पर भी नहीं कहते. गुरु को शिष्य की ज्ञान पिपासा को देखकर बताना चाहिए\nमहसूस करना चाहिए और ख़ुशी से कहना चाहिए. तब वह ज्ञान शिष्य के लिए फलदायी होगा। इस प्रकार ज्ञान\nसच्चा ज्ञान वह ज्ञान है जो गुरु तृषा को देखकर प्रसन्न होकर बोलते हैं। यहाँ कृष्ण स्वयं अर्जुन से कहते हैं\nवह असाधारण ज्ञान बता रहे हैं. कृष्ण कहते हैं: “पूर्वोक्त क्षेत्र (प्रकृति-लक्ष्मी) और\nक्षेत्रनारायण) मैं और अधिक विस्तार से समझाऊंगा। क्योंकि इसे जानने की जरूरत है\nसभी का सबसे महत्वपूर्ण मुद्दा\"",
  "14.9": "' लेकिन, हिंदी में, \"टका है। जर्मन।\"\nयह भाषा में है. \"606 ग्राम\" है। कन्नड़ में उपरि का अर्थ है 'उप' - 'ऊपर'\nदेता है]। तो \"उपजायते\" का अर्थ है श्रेष्ठ जन्म। यह प्रभु की जागरूकता है\nशारीरिक मुद्रा के साथ जन्म लेना ही उच्च जन्म है। आध्यात्मिक उपलब्धि से जन्म ऊंचा\n'पुनर्जन्म'। जिसने अपने जीवनकाल में इस सृष्टि के स्रोत का ज्ञान प्राप्त कर लिया उसका पुनर्जन्म नहीं हो सकता।\nवह भगवान में निरंतर बने रहने के सर्वोच्च शब्द को प्राप्त करता है।\n\nमम योनिर्महद् ब्रह्मा तसि तुस गर्भं दधाम्यहम् |\nसम्भवः सर्वभूतानां ततो भवति भारत ॥3॥\n\nयहां कृष्ण बड़ी अजीब बात कहते हैं. यदि हम इस श्लोक को समझना चाहते हैं, तो हम\nपहले 'भा-रता' बनना चाहिए. 'रत' का अर्थ है दर्शन। हमें प्रभु में विश्राम करना चाहिए; ज्ञान का\nरास्ते पर होना; भक्ति के धनी बनो और पूर्ण दाता बनो; विनम्र होना। फिर\nसृष्टि का यह रहस्य समझ में आ गया।\n\nकिसी भी वस्तु के निर्माण के लिए एक से अधिक कारणों का होना आवश्यक है। अगर सुस्त है\nवहाँ दो कारण आवश्यक हैं, उदाहरण के लिए यदि एक घड़ा बनाना है तो एक जड़ है (74)।\n\n118161815) वांछित और आकार देने वाला कुम्हार चाहिए। वनस्पति की रचना- जड़ के भीतर भगवान\nजीवन जोड़कर. लेकिन 'आत्मा रचना' को जो गर्भ से जन्म लेती है\nपदार्थ से निर्मित होने के लिए एक नर और एक मादा की आवश्यकता होती है। वे दोनों\nएक तीसरा संघ द्वारा निर्मित होता है।\nइस श्लोक में 'योनि' और 'ब्रह्म' 'मम योनिः महत् ब्रह्मा' में आते हैं।\nशब्द वे शब्द हैं जिनके अनेक अर्थ होते हैं। किस स्थिति में कौन सा अर्थ मेल खाता है\nयह जानकर हमें श्लोक को समझना चाहिए। योनि - कारण, जन्म स्थान, पत्नी\nआदि अर्थ देता है। इसी प्रकार ब्रह्म- जीव, चतुर्मुख, लक्ष्मी, भगवान आदि अनेक हैं\nइस श्लोक में... अर्थ बताता है. योनि का अर्थ है पत्नी; इसका अर्थ है 'महत ब्रह्मा'\nश्रीलक्ष्मी जो चतुर्मुख की माता भी हैं। कृष्ण कहते हैं, “मैं चित्त प्रकृति हूं, अपनी पत्नी हूं\n(मैं लक्ष्मीना को गर्भवती करूंगा। वह गर्भ बड़ा होगा और सभी जीवित प्राणियों का निर्माण होगा।)\nयह हमारे लिए कुछ नया है. चूँकि चतुर्मुख की रचना खुग्रेडा में इस प्रकार कही गई है:\n\nतमिद्गर्भं प्रथम दधरा आपो यत्र देवः समगच्छन्त विश्वे।\n\nअजस्य नाभवध्येकमरपितं यस्मिन्विश्वानि भुवनानि तस्तुः",
  "14.4": "सर्वयोनिषु कौन्तेय मूर्तियः संभवन्ति यः।\n\nतसं ब्रह्म महत् योनिः अहं बीजप्रदः पिता-कौन्तेय, सब बसिरों में\nजो भी रूप बनते हैं- उनके लिए आत्मा ही माता है; मैं खुद ही बीज बोता हूं\nपिता\n\nसिर्फ देवदूत, सिर्फ इंसान नहीं। सभी प्राणियों के जन्म के पीछे पिता और माता के रूप में लक्ष्मी-\nनारायण हैं. प्रकृति लक्ष्मी सबकी माता-आत्मा है। नारायण वह पिता हैं जो बीज बोते हैं। धड़\nजैसा कि उपनिषद कहते हैं:\nपुमान रेतः सिंचति योपितयं बह्विः प्रजाः पुरुषात् सम्प्रसुतः ॥| 2.2.5\n\nयहां 'पुमान' का अर्थ भगवान है जो विशेष रूप से मनुष्य में मौजूद है और 'योशिता' का अर्थ है\nस्त्रियों में लक्ष्मी विशेष रूप से विद्यमान रहती हैं। जैसे ही बीज खेत में बोया जाता है, वह वहीं वास्तविक होता है\nसहनशील स्वरूप, प्रकृति के प्रशंसक, श्री लक्ष्मी में भगवान का बीजारोपण होता है।\nक्या मां लक्ष्मी उस बीज को एक आकार देती हैं. ये तरीका कितना बढ़िया है. यह\nइसी कारण से प्राचीन विद्वान गर्भवती स्त्री के शरीर को मंदिर कहते थे, उस गर्भवती स्त्री को\nजिस स्थान पर गर्भ है वह गर्भ के समान है, जो उस गर्भ के भीतर जीवन को विकसित कर रहा है।\n\nउन्हें भगवान की तरह सम्मान दिया जाता था. यह हमारे पूर्वजों के प्रत्येक कार्य में भगवान है\nभव्यता के निकट। एक महिला तब मंदिर बन जाती है जब वह गर्भवती हो जाती है। तो महिला\nसबसे बड़ा डर माँ बनने का होता है. उसकी इच्छा का अंतिम लक्ष्य मातृत्व है।\nजब वह गर्भवती होती है तो उसमें लक्ष्मी पूर्ण रूप से विद्यमान हो जाती है। इस वजह से\nविवाह लक्ष्मीनारायण की पूजा है। विवाह एक पुरुष और एक महिला का मिलन है\nलक्ष्मीनारायण समागम. यहाँ हमारा सौभाग्य है कि ईश्वर हमें एक माध्यम के रूप में उपयोग करता है\nइस तरह से निर्माण करते समय यहां कच्चे माल की एक विस्तृत श्रृंखला की आवश्यकता होती है\nइसकी व्याख्या कृष्ण ने निम्नलिखित श्लोकों में दी है।\n\nसत्त्व रजस्तमा इति गुणाः प्रकृतसम्भवः।\n\nनिबधना ति महाबाहो देहे देहिनमव्यम्",
  "14.11": "सर्वद्वारेषु देहे अस्मिन् प्रकाशः उपजायते।\nज्ञानं यदा तदा विद्यत् विवृद्धं सत्त्वं इति उता - इस शरीर में सभी इंद्रियों में।\nयह जानना चाहिए कि प्रकाश के प्रकाश हो जाने पर सत्त्वगुण पुष्ट हो गया है।\n\nजब सत्त्वगुण जागृत होता है, तो हम अपने भीतर हल्कापन महसूस करते हैं। यह सब हल्का यातायात है\nइंद्रियों के माध्यम से बाहर आता है. ज्ञान का आनंद इंद्रियों को भी भर देता है। सबसे ऊपर",
  "14.8": "तमः तु अज्ञानजं विधि मोहनं सर्वदेहिनम् |\n\nप्रमदा अलस्य निद्राभिः तत् निबध्नति भारत - जो सभी प्राणियों को अज्ञान देता है,\nजो मिथ्या है-उस तमोगुण को जानो। भरत, यह विस्मृति, आलस्य और है\nनींद से नाता जोड़ देता है.\n\nकुछ भी नहीं जानना मजेदार है. तमोगुण से अज्ञान उत्पन्न होता है। यह इतना मजबूत है कि-\nयह इस ज्ञान को रोक सकता है कि मुझे कोई ज्ञान नहीं है, कि मैं अज्ञानी हूं। ये सबसे ज्यादा है\nभयानक. जैसा कि अंग्रेजी में कहा जाता है:\n8 1001\"। जिसके बारे में मैं कुछ नहीं जानता, उसका कारण यह है कि मैं कुछ भी नहीं जानता।\nयही वह गुण है जो हर किसी को भ्रम में रखता है। तमसु वे तीन हैं जिन्हें हम अलग नहीं कर सकते\nरिश्ते हमें बांधते हैं. वे हैं नींद, सुस्ती और भूल। जागते हुए भी\nजागरूकता के बिना जीना एक गलती है। गलती करना गलत नहीं है, बल्कि गलती करना और उसे सुधारना गलत नहीं है\nयह एक गलती है. यह सब हमारे स्वभाव के कारण है।",
  "14.14": "यदा सत्वे प्रवृद्धे तु प्रलयं याति देहभृति |\nतदा उत्तमविदं लोकं अमलान प्रतिपद्य ते - जब सत्त्वगुण मजबूत हो जाता है, तो जीव\nयदि वह मर जाता है, तो उसे हिरदादा तत्त्व- ज्ञाता के परिवार में दोष रहित शरीर मिलता है।\n\nजैसा कि हम जानते हैं कि जीवन का अंतिम क्षण शरीर छोड़ना उस जीवन का अगला चरण होता है\nअंत में सात्विक विचार के साथ, आत्मा को सत्त्व के प्रभाव में छोड़ने का निर्णय लेता है\nयदि संभव हो तो, अगले जन्म में बुद्धिमानों के समुदाय में एक निर्दोष इंसान के रूप में\nहम पैदा हुए हैं. वहाँ बुद्धिमानों के बीच रहना, ज्ञान की खेती करना और फिर से ज्ञान के मार्ग पर चलना\nऊँचा चढ़ने में सक्षम। यदि हम अपने जीवनकाल में सार पर जोर देकर जियें\n\nमरते समय सत्व अवस्था में मरना संभव है। इसके अलावा ''मरते समय सात्विक\nआइए विचार के बारे में सोचें”, सत्त्व के प्रभाव में मरना असंभव है।\n\nराजसी प्रलयं गत्वा कर्म संगीषु जयते |\n\nतथा प्रलिनस्तमसि मुध्ययोनिशु जयते",
  "14.10": "रजः तमः च अभिभूय सत्वं भवति भारत।\nरजः सत्वं तमः च एव तमः सत्वं रजः तथा-भारत, सत्त्वगुण रजस्सू-तमस को दूर धकेल रहा है।\nमजबूत करता है; सत्त्व तमस रजोगुण को धक्का देता है; साथ ही सत्व-रजस को धकेल कर तमोगुण।\n\nगुणत्रयों में एक विशेष शक्ति होती है। क्योंकि इन तीनों में से कोई एक हमारा है\nमन पर नियंत्रण कर लेता है और शेष दो गुणों को बंद कर देता है (5000[655)।\nतीन गुणों में से एक गुण हमारे मन पर कब्ज़ा कर लेता है। तब हमारा मन उस गुण के पक्ष में होता है\nयह उसी के अनुसार काम करना शुरू कर देता है। त्रिगुणमणिनी लक्ष्मी। वह कुछ गुणवत्ता के लिए बनी रही\nवह दो गुणों से परे काम करने की शक्ति देती है। इस प्रकार एक गुण दो गुण रह जाता है\nबंद करें और काम करना शुरू करें.\n\nहमें यह पहचानना होगा कि कौन सा गुण हमारे अंदर चेतन है। फिर उस क्वालिटी का\nप्रभाव से होने वाली दुर्घटनाओं से बचा जा सकता है। इसकी पहचान के लिए कृष्ण ने जो तरीका अपनाया है\nवह तीन श्लोकों में समझाते हैं।",
  "14.1": "अर्थात, ''लक्ष्मि अपनी पैनी नजर के बल से ऐसे सृजन, संहार और संहार करती हैं।''\nलक्ष्मीपति नारायण को नमस्कार है। यहां लक्ष्मी का संपूर्ण भजन है\nऐसी लक्ष्मी के पति नारायण के रूप में वर्णित है। इसलिए\nलक्ष्मीनारायण की स्तुति लक्ष्मी स्तुति है, केवल लक्ष्मी स्तुति नहीं। इसके लिए मूल गीत\nअध्याय बारह, तेरह और चौदह। बारहवें अध्याय में केवल लक्ष्मी उपासना\nयदि चेतावनी है कि वह ओली है, तो यह संसार तेरहवें अध्याय में है\nलक्ष्मीनारायण के संयोग से निर्मित - अत: हम सब उनकी संतान हैं\nएक सन्देश है. सृष्टि की प्रक्रिया में लक्ष्मी का भगवान के साथ कैसा संबंध है?\nचौदहवाँ अध्याय स्पष्ट करता है। लक्ष्मी, श्री भू-दुर्गा इन तीन रूपों में सत्त्व-रजसु-\nतमोगुण की नियंत्रक शक्ति होने के कारण - उनके पुत्र सात्विक-राजस-तमस हैं।\nतीन प्रकार. इस अध्याय में पहली बार इस मुद्दे का उल्लेख किया गया है। पिछले में से कौन सा\nअध्याय में भी त्रिविद्या का वर्णन उतना स्पष्ट नहीं है। हम इन त्रिगुणों का विश्लेषण करते हैं\nहमारे अंदर के रजस और तमस पहलू को कैसे सात्विक तरीके से ठीक करें\nइस अध्याय में हम इस तथ्य को देख सकते हैं कि उपलब्धि प्राप्त की जा सकती है।\n\nभगवान का वचन\nपरं भूयः प्रवक्ष्यामि ज्ञानं ज्ञानमुत्तमम् |\nयज ज्ञात्वा मुनयः सर्वे परमं सिद्धिमितो गतः ॥1॥\n\nभगवान उवाच- भगवान ने कहा:\n\nपरं भूयः प्रवक्ष्यामि ज्ञानं ज्ञानं उत्तमम् |\n\nयत् ज्ञात्वा मुनयः सर्वे परम सिद्धिं इतः गतः - जानने योग्य सबसे महान वस्तु।\nमैं आपको और अधिक बताऊं; सभी ऋषियों ने इसे देखा और यहीं से परमपद प्राप्त किया।\n\nकृष्ण कहते हैं: \"मैं तुम्हें और बताऊंगा\"। यह बहुत ही महत्वपूर्ण शब्द है. आमतौर पर शिष्य\nगुरु आग्रह करने पर भी नहीं कहते. गुरु को शिष्य की ज्ञान पिपासा को देखकर बताना चाहिए\nमहसूस करना चाहिए और ख़ुशी से कहना चाहिए. तब वह ज्ञान शिष्य के लिए फलदायी होगा। इस प्रकार ज्ञान\nसच्चा ज्ञान वह ज्ञान है जो गुरु तृषा को देखकर प्रसन्न होकर बोलते हैं। यहाँ कृष्ण स्वयं अर्जुन से कहते हैं\nवह असाधारण ज्ञान बता रहे हैं. कृष्ण कहते हैं: “पूर्वोक्त क्षेत्र (प्रकृति-लक्ष्मी) और\nक्षेत्रनारायण) मैं और अधिक विस्तार से समझाऊंगा। क्योंकि इसे जानने की जरूरत है\nइस मामले में सबसे महत्वपूर्ण मुद्दा है।” इस संसार के निर्माण के पीछे माता-पिता के रूप में\nलक्ष्मी-नारायण हैं।  तो सिर्फ पिता की याद, या सिर्फ माँ की याद\nकरने से बेहतर है कि माता-पिता की स्मृतियों को जानें। कृष्ण कहते हैं: “यह\nआइए आपको मामला विस्तार से बताते हैं. क्योंकि यह मोक्ष प्राप्त करने वाला व्यक्ति है\nयह अवश्य जानने योग्य बात है।\nलक्ष्मी-नारायण को सृष्टि का स्रोत माने बिना मुक्ति असंभव है। “यह साधना\nयहां तक कि वे ऋषि भी जो पृथ्वी पर पैदा हुए और ब्रह्म अनुभूति प्राप्त कर चुके हैं, जानते हैं कि यह सर्वोच्च जीवन है\nसिद्धि का मोक्ष मिल गया\" कृष्ण कहते हैं। यह अगले श्लोक में बहुत स्पष्ट है\nसमझाया.\n\nइदं ज्ञानमपाश्रित्य मम सधर्म्यमगतः |\n\nसर्गे*प नोपजायन्ते प्रलयेन व्यथंति च",
  "14.13": "अपराकाः अप्रवृत्तिः च प्रमदः मोहः एव च।\nतमसि एतनि जयन्ते विवृद्धे कुरुनन्दना - हे कुरुनन्दन, जब तमसु मजबूत हो जाता है\nदेखे गए तत्व हैं: अंधकार, भयावहता, जागृति और गलतफहमी।\n\nजब तमोगुण जागृत हो जाता है तो अंदर और बाहर सब कुछ अंधकारमय हो जाता है। हमेशा सोते रहना, गलत\nकरना, अज्ञान में रहना- तमोगुण के वश में होना। सुबह सूरज उगता है\nतमोगुण जल्दी जागने नहीं देता। यही गुण हमें हमेशा सोने के लिए प्रेरित करता है। यह\nगुना हमेशा आपको अंधेरा चाहता है। हमें इसके प्रभाव से बचना है\nकुरुनन्दन होना चाहिए। खुद को किसी काम में व्यस्त रखें और उसे एक आदत बना लें\nकरना चाहिए उदाहरण के लिए: सुबह सूर्योदय से पहले उठने की आदत\nजब यह आदत बन जाती है तो मन इसे छोड़ने के लिए नहीं कहता।\n\nहममें से कुछ लोग ऐसा कहते हैं. \"मेरे पास आध्यात्मिक विचार के लिए समय नहीं है।\" लेकिन इस तरह\nअधिकांश टेलर अपनी छुट्टी के दिन, खाली समय पर हैं - सुबह से शाम तक\nआलस्यपूर्वक सोना और देर तक सोना! इस प्रकार हम वैसे हैं जैसे हम नहीं हैं\nतमोगुण कब्ज़ा और नियंत्रण कर रहा है। हम किसी भी कर्तव्य में आलसी नहीं हैं\nस्वयं को संलग्न करने से हम तमोगुण के प्रभाव से बच सकते हैं।",
  "13.11": "असक्तिः अनाभिष्टंगः पुत्र दारा गृह आदिषु |\n\nनित्यं च समचित्तत्वं इष्ट अनिष्ट उपपत्तिषु ॥\n\nमायचा अनन्ययोगेन भक्तिः अव्यभिचारिणी |\n\nविविक्त देश सवित्वं आरतीः जन म.प्र.\n\nअध्यात्म ज्ञान नित्यत्वम् तत्वज्ञान अर्थ दर्शनम् |\n\nएतत् ज्ञानं इति प्रोक्तं अज्ञानं यत् अत: अन्यथा एक अनासक्ति, बच्चों\nपसंद-नापसंद आने पर मदादी माने आदि से ज्यादा न जुड़ें\nहमेशा के लिए अनसुलझा, कहीं और। बिना हिलाए अपने प्रति अटूट भक्ति, एकांत,\nभीड़ में न मिलें, अप्रत्यक्ष ज्ञान के लिए आध्यात्मिक जागरूकता में निरंतर स्थिति\nशास्त्र का अध्ययन,|[दर्शन को दर्शनीय भगवान की प्राप्ति] यही ज्ञान और ज्ञान है।\nउपकरण. इसके अलावा अज्ञान और अज्ञान का मार्ग है।\n\n(13) असक्ति: \"शक्ति' का अर्थ है चिपकना या चिपटना (Gi530175010। यह\nहमने पहले भी कई बार इस मुद्दे पर चर्चा की है। \"सक्ते\" हमारे सभी दुखों का कारण है\nकिसी भी बात पर अड़े मत रहो. मृत्यु जन्म के समय कुछ नहीं लाती, मृत्यु के समय कुछ नहीं लाती\nनहीं ले जाऊंगा. इसलिए इस सांसारिक शक्ति से दूर रहें। जो आया वह प्रभु का है\nइसे प्रसाद के रूप में स्वीकार करें, जब भगवान की इच्छा हो तो खुश रहें।\n\n(14) अनाभिष्टंगः पुत्र दारा गृह आदिषु : अभिष्टांगः का अर्थ है अत्यधिक श्रृंगार (066:\n8801/7971). घर, पत्नी(पति/पत्नी) बच्चे आदि से ज्यादा मोह न रखें\nकृष्ण कहते हैं. यहां परिवार से मोह न रखने का मतलब है सब कुछ छोड़कर जंगल में चले जाना\nनहीं जा रहा. \"मैं इसके बिना नहीं रह सकता\" सब कुछ छोड़ देने के बारे में है। जीवन में\nदेखिये सबूत के तौर पर क्या आता है। जीवन एक खेल है, जिसमें आप हैं\n\nआप दर्शक हैं, नायक हैं। भगवान निर्देशक हैं. यहां मेरे बच्चे मेरी जिंदगी हैं, मेरे पति/पत्नी मेरे हैं\nजिंदगी, मेरी कमाई ही मेरी जिंदगी है, इसके अलावा मेरा कोई अस्तित्व नहीं है।'\nप्यार मत करो - लेकिन शिकायत मत करो, निराशा मत करो। जीवन तब है जब आप इस तरह जीना सीख जाते हैं\nखूबसूरत है अगर हमारे बच्चे हमसे दूर हैं, अगर पत्नी/पति दूर हैं तो हम अपने हैं\nधन (घर, संपत्ति आदि) की हानि से दुःख-निराशा नहीं होती। जब ऐसे जी रहे हो\nजीवन में जो भी त्रासदी आती है, हमें लगता है कि इसमें हमारी ही भूमिका है\nइसे स्वीकार करने में सक्षम हों—आघात में न पड़ें।\n\n(15) नित्यं च समचित्तत्वं इष्ट अनिष्ट उपपत्तिषु : जीवन में मनभावन घटना।\nहो सकता है, कोई अप्रिय घटना घट जाये. जब ऐसी बुराइयां आएं तो ध्यान रखें\nअपना संतुलन खोए बिना हर समय संतुलित रहना सीखें। हम बुरे हैं\nहम जो सोचते हैं वह जरूरी नहीं कि बुरा हो या जो हमें पसंद हो वह जरूरी नहीं कि अच्छा हो।\nइसलिए, जो आता है उसे पसंद या नापसंद के कलंक के बिना \"नहं कर्ता हरिः कर्ता\" के रूप में स्वीकार करना।\nसीखा: हमारे जीवन में घटित होने वाली प्रत्येक घटना ईश्वर द्वारा हमारे प्रशिक्षण के लिए बनाई गई है\nव्यावहारिक (1/30403) शिक्षा। भगवान हमें दुःख देते हैं और बुद्धिमान बनाते हैं\nसत्य को पहचानो और जियो.\n\n(16) मयि च अनन्ययोगेन भक्तिः अव्याभिचारिणी: भगवान के प्रति निरंतर शुद्ध भक्ति बनी रहे।\nप्रभु एक है, उसके नाम अनेक हैं। उनके प्रति अनन्य भक्ति रखें. यहां एकता बहुत जरूरी है.\nएक समय में एक दिन एक देवता की पूजा करना, जब एक देवता की पूजा की जाती है, तो दूसरे देवता की पूजा करना\nकई देवताओं की पूजा देवताओं के नाराज होने के डर से की जाती है\nवह व्यभिचार होगा. तो कृष्ण यहाँ कहते हैं \"आपकी भक्ति अद्वितीय और शुद्ध होनी चाहिए\"।\nउन्होंने इस बात पर जोर दिया. क्या आपको यह विश्वास हो सकता है कि ईश्वर सर्वशक्तिमान, सर्वशक्तिमान और जगत का कारण है।\nईश्वर में आस्था के बिना किसी भी धर्मग्रंथ को पढ़ना व्यर्थ है। भगवान पर पूर्ण\nविश्वास से ही ज्ञान प्राप्त किया जा सकता है\n\n(17) विविक्त देश सवित्वम्: जहां उच्चतम संभव सात्विक कंपन है, सात्विक लोग।\nइसके साथ जीने का प्रयास करें. अक्षुण्ण सात्विक स्पंदन का स्थान\nयह एक तीर्थस्थल जैसा दिखता है। ऐसी जगह पर जो अच्छी बातें बोलता है और अच्छी बातें सोचता है\nसज्जनों के साथ रहो. यदि यह संभव न हो तो यथासंभव एकांतवास का अभ्यास करें।\nचार लोगों के साथ गपशप में अपना अनमोल जन्म बर्बाद मत करो।\n(18) अरतिह जन संस्पति: जहां लोग किसी अवांछित कारण से इकट्ठा होते हैं, जैसे\nभीड़ से दूर रहें.\n\n(19) अध्यात्म ज्ञान नित्यत्वम्; आध्यात्मिक जागरूकता में बने रहें. पहला पिंडदान-\nब्रह्माण्ड को जानो, फिर उस असाधारण दिमाग के आश्चर्य को जानो जो इसे जानता है\nजानिए 'I' का क्या मतलब है (C1/367255 08 56/1)। यह जानकर, यह आत्मा\nप्रभु को जानो जो नियन्त्रण करता है। यह तत्वमीमांसा है. आपके अध्ययन का उद्देश्य अध्यात्म है\nज्ञान हो.\n\n(20) तत्त्वज्ञान अर्थ दर्शनम्: संसार के मूलभूत सत्य को जानने के लिए आपका अध्ययन\nसमर्पित रहें. उपरोक्त सभी गुणों के कारण वह सभी शास्त्रों से, सभी शास्त्रों के अधीन हो गया\nपरमपिता परमेश्वर की प्राप्ति.\n\nयहां बताए गए गुण ज्ञान और ज्ञान के उपकरण हैं। इसके अलावा कुछ भी अज्ञान है और\nअज्ञान का लक्ष्य.\n\n6\n\nकृष्ण अगले छह श्लोकों में ध्वनि की सीमा से परे ज्ञान के साधनों का वर्णन करते हैं\nवह ईश्वर का वर्णन हमारे सामने रखता है। भगवान कैसा है, उसका स्वरूप कैसा है\nकृष्ण ने दृष्टिकोण के विचार का सुन्दर वर्णन किया है। इन श्लोकों में\nहम ऐसी कई चीज़ें देख सकते हैं जो एक-दूसरे के विपरीत प्रतीत होती हैं।\nउदाहरण के लिए: भगवान निर्गुण हैं लेकिन वे सर्वशक्तिमान हैं; भगवान अचल है लेकिन वह है\nचलता है; ईश्वर निर्विशेष है लेकिन वह साकार है; परन्तु ईश्वर को जानना असंभव है\nउसे जाना जा सकता है; भगवान के पास कोई इंद्रियाँ नहीं हैं लेकिन उनके पास इंद्रियाँ हैं; वह है\nदूर लेकिन पास; इत्यादि। इस प्रकार का वर्णन भगवान से भिन्न है\nइसे कोई और नहीं दे सकता. इन सभी का स्पष्टीकरण निम्नलिखित श्लोक में पाया जा सकता है।\n\nज्ञेयं यश तत् प्रवक्ष्यामि यज ज्ञात्वा$मृतमश्नुते |\nअनादीमत परमं ब्रह्म न सत् थन्नासदुच्यते",
  "14.20": "गुणं एतां अतित्य त्र्येन देहि देहा समुद्धवान् |\nजन्म मृत्यु जरा दुक्खैः विमुक्तः अमृतं अश्नु ते-देहः ये तीन चीजें शरीर में उत्पन्न होती हैं।\nजब वह गुणों से परे हो जाता है, तो वह जन्म और मृत्यु के दुखों से मुक्त होकर अमर हो जाता है।",
  "14.15": "राजसी प्रलयं गत्वा कर्म संगीषु जयते।\nतथा प्रलिनः तमसि मूढ़ योनिषु जयते - यदि आप रजोगुण में मरते हैं तो कर्म।\nएक का जन्म क्लिंगर्स में होता है। जो व्यक्ति तमोगुण में मरता है वह अज्ञात हीनयोनियों में जन्म लेता है।\n\nरजोगुण के प्रभाव में डुड्डू-डुड्डू की तरह रहना, कर्मानुष्ठान करना जो ज्ञान का पूरक नहीं है,\nयदि आप उसी प्रभाव में मर जाते हैं, तो आपको अगले जन्म में कर्म से चिपक कर जन्म लेना होगा। अब और नहीं\nयदि आप तमोगुण के प्रभाव में जीते और मरते हैं, तो आपको अगले जन्म में हिनायोनि में जन्म लेना होगा। यहाँ\n'हिनायोनि' का अर्थ है मनुष्य भी बन सकता है। बिना किसी संस्कार के, बिना शुचिता के।\nज्ञान के बिना, मात्र मनुष्य का रूप धारण करके, मानवता की चमक के बिना मनुष्य बन जाते हैं\nजीना भी कमजोरी का जन्म है. इससे तो पशु-जन्म कितना उत्तम है। यह तमोगुण में है\nमृत्यु पर प्रभाव. [यदि कोई मृत्यु के अंतिम क्षण में रजस्सू और तमस के प्रभाव में मरता है, अर्थात\nइसका हमारे अगले जन्म पर क्या प्रभाव पड़ेगा - गजेंद्र के रूप में जन्म\nहम इंद्रद्युम और हिरण जन्मे सम्राट भरत की कहानी से सीख सकते हैं।\n5608/08/06(1877 10 1920) पुनर्जन्म पर नवीनतम शोध के बारे में जानने के लिए उनकी पुस्तकें\nऔर उनके शोध का विवरण देखें]।\n\nकर्मणः सुक्रतस्य$हुः सात्त्विकम् निर्मलम् फलम्।\n\nराजसस्तु फलम् दुःखमज्ञानं तमसः फलम्",
  "14.6": "तत्र सत्त्वं निर्मलत्वं प्रकाशकं अनामयम् |\n\nसुख संगेन बध्नति ज्ञान संगेन च अनघा - उनमें सत्त्वगुण शुद्ध है। इसलिए\nज्ञान का प्रकाश देता है; यह बीमारियों को दूर करता है. हे अनघा, वह सुख के कारण है\nऔर ज्ञान की गांठ से बंध जाता है।\n\nअपनी आँखें बंद करो और अपने अंदर देखो। आपके भीतर जो मानसिक विकास होता है,\nविचार, विचार, भावनाएँ देखें। यदि आप सत्व गुण से प्रभावित हैं-\nआप अपने भीतर एक शुद्ध, निष्कलंक, उज्ज्वल प्रकाश देखते हैं। हमारा आंतरिक अस्तित्व\nदुनिया से एक पूर्ण विद्युत कनेक्शन, एक लैंप, कई स्विच जो उस लैंप को नियंत्रित करते हैं\nक्रियान्वित किया गया। यहां लगातार बिजली की आपूर्ति हो रही है. लेकिन हमारे लिए यह स्विच कहां है?\nपता नहीं तो- सब कुछ होते हुए भी हमारे भीतर हमेशा अंधेरा ही रहता है। हम यह करते हैं\nबिल्कुल कोई फायदा नहीं. यह स्विच हमें तब मिलता है जब हमारा सत्त्वगुण जागृत होता है। उससे\nनिष्कलंक ज्ञान का प्रकाश हमारे भीतर चमकता है।\n\nजब सत्त्वगुण जागृत होता है तो हम आंतरिक आनंद से भर जाते हैं। यह अनुभव\nअधिकांश के लिए यह होगा. उदाहरण के लिए: कभी-कभी हम कहते हैं: “आज कुछ लंबा है\n\"मैं खुश हूँ।\" कोई खास वजह नहीं है. लेकिन आंतरिक आनंद बाहरी है\nयही सब हम अनुभव कर रहे हैं। यह सत्त्वगुण की जागरूकता है। ज्ञान से आ रहा है\nसभी सुख सात्विक हैं।\n\nकृष्ण यहाँ एक चेतावनी देते हैं। यदि हमारे अंदर सत्त्वगुण को जागृत करना है, तो हम\nपाप का स्पर्श होने पर सत्त्वगुण जागृत नहीं होता। उसके लिए हम पाप हैं\nदूर होना चाहिए. पाप का स्पर्श जितना बढ़ता है, सार उतना ही दूर होता जाता है।\n\nयद्यपि सत्त्वगुण मोक्ष की प्राप्ति में सहायक है, यह भी त्रिगुणों में से एक है। अत: सत्त्वगुण\nबाध्यकारी भी हो सकता है. यह हमें खुशी के बंधन और ज्ञान के बंधन से बांधता है\n\nउदाहरण के लिए रख सकते हैं: ज्ञान उपलब्धि सात्विक गुण. यहाँ वह ज्ञान है जो ईश्वर का विषय नहीं है\nयदि हम उपलब्धि के जाल में फंस जाते हैं - तो यह बंधनकारी हो जाता है। हम कुछ शोध करते हैं,\nअगर खोज में डूबे। इतना ही। हमें मोक्ष की ओर नहीं ले जा सकता. हम वही हैं\nशोध के नतीजों की खुशी में कोई भी फंस सकता है और गिरफ्तार हो सकता है.\nमोक्ष प्राप्ति में हमें सत्त्व से भी ऊपर जाना होगा। क्योंकि मोक्ष त्रिगुणात्मक है। कृष्ण यहाँ का सार हैं\nउन्होंने गुणवत्ता को \"बद्दति\" कहा क्योंकि यह बंधन एक ऐसा बंधन है जिसे आसानी से छोड़ा जा सकता है\nहमें कभी निराश मत करो. [लेकिन कृष्ण आगे कहते हैं कि रजस्सु और तमसु 'निबध्नति' हैं\nछंद में वर्णित], जो सत्त्व हमें भगवान की ओर जाने से रोक रहा है\n\nहमें उस सार से छुटकारा पाना है।",
  "14.12": "लोभः प्रद्धितः अरामवः कर्मणां अशः स्पा एहा।\n\nराजसी क्या है? जयन्ते विवृद्दे भरतर्षभ - हे भरतर्षभा, जब रजोगुण प्रबल हो जाता है\nदेखे गए पहलू हैं: कंजूसी, उन्माद, कश्ती में लिप्तता, बेचैनी।\nऔर किनारे की चाहत.\n\nरजोगुण जागृत होने पर लालच सबसे पहले हमारे अंदर प्रकट होता है। क्या बकवास है\nकरने का विचार; कृपणता, दूसरे को एक पैसा न देना आदि।\nउदाहरण के लिए कुछ लोग अपने गृह समारोह पर लाखों खर्च करते हैं। लेकिन कोई\nयदि कोई ऐसा व्यक्ति जिसके पास भोजन न हो, आकर पूछे तो उसे एक पैसा भी दान में न मिलेगा। ये है\nलालच भवभूति ने नीति शतक में ऐसे लालची लोगों के बारे में कहा है:\n\nदानं भोगो नासः तिस्रो भवन्ति गतयो वित्तस्य|\n\nयोना ददाति नाभुन्के तस्य तृतीया गतिर्भवति।।158।\nडुड्डी के विनियोग के तीन रूप हैं: दान, भोग और विनाश। लालची लोगों के पास पैसा है\nवे दूसरों को दान नहीं देते, वे स्वयं नहीं खाते, अंततः यह एक लोमड़ी-कुत्ते का विभाजन है\nनष्ट हो जायेंगे.    यह रजोगुण के प्रभाव का परिणाम है।    रजोगुण का\nप्रभावित होने पर व्यक्ति हमेशा कुछ न कुछ कर गुजरता है। दूद्दू\nकरने के लिए विभिन्न व्यवसाय; चाहे कितना भी शामिल हो, असंतोष है; वह करता है\nव्यवसाय में, यदि भगवान उसे पेट भरने के लिए भी पर्याप्त दे, तो भी संतुष्टि नहीं होगी;\nभले ही वह अपने पास आने वाले वेतन पर खुशी से रह सके, यह बात से परे है\nघरेलू वेतन से कम आदि की शिकायत करना। उनका दैनिक मंत्र है \"चाहिए-चाहिए\"।\nये सभी लक्षण तब प्रकट होते हैं जब सत्त्वगुण कुचल दिया जाता है और रजोगुण खड़ा हो जाता है।\nयहाँ व्यास ने 'भरतर्षभ' विशेषण का प्रयोग किया है।\nभारत को गर्व होना चाहिए. ऐतरेय ब्राह्मण में एक कहावत है 'वैयरवव भारतः। हमेशा\nभगवान के साथ व्यस्त रहने वाले वायुदेव को 'भरत' कहा जाता है। हमें प्राणदेव को समर्पित कर दो\nरजोगुण से बचा जा सकता है।\n\nअप्रकाशोअप्रवृत्तिश्च प्रमदो मोह एव च ​​|\n\nतमस्येतानि जायन्ते विवृद्धे कुरुनन्दना",
  "14.3": "मम योनिः महत् ब्रह्मा तस्मिन् गर्भं दधामि अहम्।\nसम्भवः सर्वभूतानां ततः भवति भारत - चेतना प्रकृति मेरी अर्धांगिनी है। उसमें सृजन\nबीज बोओ. भरत, समस्त प्राणियों का जन्म इसी से होता है।\n\nयहां कृष्ण बड़ी अजीब बात कहते हैं. यदि हम इस श्लोक को समझना चाहते हैं, तो हम\nपहले 'भा-रता' बनना चाहिए. 'रत' का अर्थ है दर्शन। हमें प्रभु में विश्राम करना चाहिए; ज्ञान का\nरास्ते पर होना; भक्ति के धनी बनो और पूर्ण दाता बनो; विनम्र होना। फिर\nसृष्टि का यह रहस्य समझ में आ गया।\n\nकिसी भी वस्तु के निर्माण के लिए एक से अधिक कारणों का होना आवश्यक है। अगर सुस्त है\nवहाँ दो कारण आवश्यक हैं, उदाहरण के लिए यदि एक घड़ा बनाना है तो एक जड़ है (74)।\n\n118161815) वांछित और आकार देने वाला कुम्हार चाहिए। वनस्पति की रचना- जड़ के भीतर भगवान\nजीवन जोड़कर. लेकिन 'आत्मा रचना' को जो गर्भ से जन्म लेती है\nपदार्थ से निर्मित होने के लिए एक नर और एक मादा की आवश्यकता होती है। वे दोनों\nएक तीसरा संघ द्वारा निर्मित होता है।\nइस श्लोक में 'योनि' और 'ब्रह्म' 'मम योनिः महत् ब्रह्मा' में आते हैं।\nशब्द वे शब्द हैं जिनके अनेक अर्थ होते हैं। किस स्थिति में कौन सा अर्थ मेल खाता है\nयह जानकर हमें श्लोक को समझना चाहिए। योनि - कारण, जन्म स्थान, पत्नी\nआदि अर्थ देता है। इसी प्रकार ब्रह्म- जीव, चतुर्मुख, लक्ष्मी, भगवान आदि अनेक हैं\nइस श्लोक में... अर्थ बताता है. योनि का अर्थ है पत्नी; इसका अर्थ है 'महत ब्रह्मा'\nश्रीलक्ष्मी जो चतुर्मुख की माता भी हैं। कृष्ण कहते हैं, “मैं चित्त प्रकृति हूं, अपनी पत्नी हूं\n(मैं लक्ष्मीना को गर्भवती करूंगा। वह गर्भ बड़ा होगा और सभी जीवित प्राणियों का निर्माण होगा।)\nयह हमारे लिए कुछ नया है. चूँकि चतुर्मुख की रचना खुग्रेडा में इस प्रकार कही गई है:\n\nतमिद्गर्भं प्रथम दधरा आपो यत्र देवः समगच्छन्त विश्वे।\n\nअजस्य नाभावध्येकमरपितां यस्मिन्विश्वानि भुवनानि तस्तुः॥ 10.82.06\nयहाँ कहा गया है कि \"ब्रह्मा भगवान के नाभि कमल से निकले\"। चतुर्मुख से जीव\nसृष्टि का निर्माण हुआ. तो हम चारों लोकों के पिता का विचार भी जानते हैं।\nवेद में अन्यत्र (अम्ब्रिनिसुक्र) कहता है:\n\nअहं सुवे पितरमस्य मूर्धन मम योनिरप्सा\n\nततो वी तिष्ठे भुवनानु विश्वो-तमौं द्यं वर्षमाननोपा स्पृशमि | 7\nलक्ष्मी यही कहती हैं: \"मैंने इस संसार के पिता चतुर्मुख को अपने माथे पर रखा है-\nबैताले से व्युत्पन्न)। यहोवा जिसने मुझे जन्म दिया वह समुद्र में है। संपूर्ण ब्रह्मांड का\nदूसरी ओर यह भी कहा जाता है कि सृष्टि की रचना शिव ने की थी। यदि आप शास्त्र प्रक्रिया को नहीं जानते तो यह सब व्यर्थ है\nभ्रमित मोक्ष प्राप्त करने वालों को इसका बारीकी से विश्लेषण करना चाहिए - तभी यह सत्य है\nसाकार हो जायेगा.\nजीव-प्रकृति-भगवान अनादि और अनंत। सृष्टि से पूर्व सारा संसार सूक्ष्म रूप में भगवान का था\nपेट में था. यदि हम इसे और अधिक बारीकी से देखें - संपूर्ण ब्रह्मांड देवी लक्ष्मी के गर्भ में था और\nलक्ष्मी भगवान के गर्भ में थीं। भगवान लक्ष्मी के गर्भ में सभी जीवित प्राणियों का बीजारोपण होता है\nकमल स्वरूप सम्पूर्ण ब्रह्माण्ड भगवान की नाभि से लेकर लक्ष्मी की खोपड़ी तक है\nइसमें चतुर्मुख के साथ-साथ सभी देवता और जीवित प्राणी अव्यक्त रूप में हैं\nइस कारण उत्पन्न हुए लक्ष्मीनारायण ब्रह्माण्ड के माता-पिता हैं। हम यहाँ हैं\nसमझने योग्य एक महत्वपूर्ण बात यह है कि सृजन एक चरण-दर-चरण प्रक्रिया है। लक्ष्मी\n\nनारायण की सभा से जो कुछ उत्पन्न होता है वह अव्यक्त रचना ही है। फिर चतुर्गुण ब्रह्मा तो यह है\nसूक्ष्म अव्यक्त संसार (जीवित प्रजाति) को मूल स्थूल रूप दिया गया है\nउन्हें पिता जैसा महसूस हुआ. और फिर इस संसार ने शिव से पूर्ण स्वरूप प्राप्त किया। यह\nयदि हम प्रक्रिया को समझ लें तो यहां कोई भ्रम नहीं है। चतुर्मुख लक्ष्मी\nखोपड़ी से जन्मा हाँ; वह भगवान की नाभि से पैदा हुआ है; वह विश्व का पिता है\nहाँ; हाँ, इस स्थूल संसार की रचना शिव ने की है; लक्ष्मी नारायण ही सब कुछ हैं\nहाँ, जीव के माता-पिता। इसके बारे में विवरण 'महाभारत तात्पर्यं निर्णयम्' में है।\nस्पष्ट रूप से समझाया गया.\n\nएक चेतना [भूति (श्रेष्ठ) जीव] के निर्माण के लिए एक पुरुष और एक महिला का मिलन आवश्यक है।\nयह एक ऐसी परंपरा है जो सृष्टि के आरंभ से ही विकसित होती चली आ रही है। दुनिया की सारी रचना के पीछे\nलक्ष्मीनारायण पिता और माता के रूप में खड़े हैं। इस बात को कृष्ण ने और भी स्पष्ट किया है\nवह श्लोक में बताते हैं.",
  "14.19": "सत्त्वं सुखे संजयति रजः कर्माणि भारत।\nज्ञानं अवृत्य तु तमः प्रमादे संजायति उता - सत्त्वगुण आनंदमय अवस्था में है। भरत,\nरजोगुण कर्म की नन्ती में है। तमोगुण चेतना को बंद कर देता है और उसे मंत्रमुग्ध कर देता है।\n\nइस श्लोक में कृष्ण ने तीन गुणों का सारांश दिया है। सत्व का मूल गुण\nउसके कारण, हमारे भीतर एक स्वाभाविक आनंद उमड़ता है। रजोगुण “कुछ भी\nयह करना ही होगा, नहीं तो जीवन में कोई खुशी नहीं रहेगी'', हमेशा पैसे के लिए लड़ते रहते हैं\nजीवन को पहनने योग्य बनाता है। तमसु हमारे पास मौजूद ज्ञान को अस्पष्ट कर देता है। उदाहरण के लिए:\nजरूरतमंदों की मदद करना, देने में प्रसन्नता - सत्त्वगुण।\nहमेशा खुश रहने के लिए खुशी की तलाश में रहते हैं, ऐसा न करें\nकरना और जीना रजोगुण है। आलस्य, तंद्रा, अज्ञान ये सब गलतियाँ हैं\nतमोगुण का प्रभाव. यह कृष्ण गीता द्वारा हमें बताया गया उच्चतम मनोविज्ञान है।\n\nये गुण हमें कैसे नियंत्रित करते हैं और हमें गिरा देते हैं\nकृष्ण ने जो सुनाया है वह हमने देखा है। यहां हमें संदेह हो सकता है. ये तीनो गुण एक साथ\nएक साथ काम करते हुए, केवल सात्विक विचार, केवल राजस विचार, केवल तमस\n\nसोचना कैसे संभव है? जब किसी के शरीर में तीन गुण मौजूद होते हैं, तो वह एक गुण होता है\nकाम करना कैसे संभव है? जब वे हमारे भीतर होते हैं तो तीन गुण मिश्रित होते हैं और एक अलग\nसात्विक स्वभाव, राजस स्वभाव, तमस स्वभाव की पहचान कैसे करें? इसका स्पष्टीकरण\nअगला श्लोक.\n\nरजस्तमाश्चभिभूय सत्वं भवति भारत।\n\nरजः सत्वं तमश्चैव तमः सत्वं रजस्तथा",
  "14.25": "मन अपमानयोः तुल्यः तुल्यः मित्र अरि पक्षियोः।\nसर्वारंभ परित्यागी गुणतितः सः उच्यते एक गरिमा ही है; अपमान भी वैसा ही है.\nदोस्तों का ग्रुप वही है; शत्रुओं का समूह एक ही है. वह इतना सांसारिक नहीं है\nशामिल नहीं. ऐसे व्यक्ति को 'गुणातीत' कहा जाता है।\n\nकोई त्रिगुणातिता को 'महान ऋषि' के रूप में बोल सकता है, कोई अन्य\n'आधा पागल'. उसका दुरुपयोग किया जा सकता है. लेकिन इसका उन पर कोई असर नहीं होता. इनके लिए\nन मित्रों से प्रेम है, न शत्रुओं से घृणा है। ये तो हर कोई है\nभगवान की भक्ति के विपरीत किसी भी गतिविधि में, जैसा वे उचित समझें\nवे बिना उलझे रहते हैं। वह स्वयं किसी दीर्घकालिक परियोजना में हैं\nशामिल नहीं.\n\nइस प्रकार उपरोक्त चार श्लोकों में कृष्ण ने निर्गुणों के स्वरूप का सुन्दर वर्णन किया है\nवर्णित हम उन लोगों को गुणपिता के रूप में पहचान सकते हैं जिनके पास यह स्वभाव है।\n\nअब तक कृष्ण ने अंतिम दो त्रिगुणों और त्रिगुणों की प्रकृति के बारे में बताया है\nश्लोक में उन्होंने बताया कि हम त्रिगुणातीत कैसे बन सकते हैं। हम सब\nजबकि प्रवृत्ति इन तीन गुणों की सीमा के भीतर है, यह हमारा काम है कि हम तीन गुणों से परे खड़े हों\nअकल्पनीय इसलिए यहां कृष्ण हमारे लिए त्रिगुणातीत बनने का एकमात्र तरीका हैं\nसमझाता है.",
  "14.16": "कर्मणः शुक्रतस्य औः सात्विकं निर्मलं फलम्।\n\nराजसः तु फलम् दुखं अज्ञानं तमसः फलम् - एक सात्विक जो अच्छी इच्छाओं से भयभीत नहीं होता।\nजो जानते हैं वे कहते हैं फल। राजसव कज्जा से दुःख मिश्रित सुख। शरारत विशेषता है\nकज्जा फल.\n\nऐसा कुछ करना शुभ है जिससे जीवन भर दूसरों की मदद हो। हमारे बीच\nजब धन है, तो वह मेरा है - यदि तुम दुखी रहते हो, तो यह दुखी जीवन की ओर ले जाएगा\n\nयह हमारा होगा. जब हम अपनी कमाई दूसरों के दुख पर खर्च करते हैं तो यह हमें सात्विक बनाता है\nफल की ओर ले जाता है. माधवाचार्य ने अपने 'गीतात्पर्य' में इस मुद्दे पर जोर दिया है\nउन्होंने कहा: \"नाना जनस्य शुश्रुषा कर्तव्य करावनमिते\" जरूरतमंदों की सेवा करना है\nमोक्ष उपलब्धि का एक पहलू है। हममें से कुछ लोग किसी को परेशानी में देखते हैं और कहते हैं: “बस इतना ही\nउसका प्रारब्धकर्म, उसे इसका अनुभव करने दो। मुझे इसकी चिंता क्यों करनी चाहिए? इस तरह\nऐसा कहकर, हम जरूरतमंद व्यक्ति के भीतर मौजूद भगवान का तिरस्कार करते हैं।\nऐसे लोगों को कभी भी ईश्वर का एहसास नहीं होगा। हमारी आध्यात्मिक प्राप्ति में जप-\nकेवल पाप ही पर्याप्त नहीं है; यहां संकटग्रस्त लोगों की सेवा भी प्रमुख है। साधक उसका है\nगीता का आदेश है कि दैनिक अनुष्ठानों के साथ इस सेवा का भी उत्सव मनाया जाना चाहिए\nमाधवाचार्य ने पैरवी की. आपके घर में कितना खाना खाया जाता है, भूखे लोगों की भूख\nशमन - बहुत मीठा. पहले इसके लिए एक परंपरा थी. पकाना,\nइसे भगवान को अर्पित करें, करीब दस मिनट तक गेट पर रुकें, फिर खाएं।\nक्योंकि इस समय यदि कोई भूखा व्यक्ति घर की गली में आता है तो सबसे पहले वह भोजन करेगा\nपहले परोसना और फिर मालिक खाना, यह रिवाज था। इश्ते  ख़ैर इससे पहले\nवे \"बलिदान\" कर रहे थे। घर के आसपास जानवरों और पक्षियों को खाना खिलाना \"बलिदान\" है।\nइस प्रकार यदि आप जीवन भर अच्छे कर्म करेंगे तो उसका परिणाम सात्विक होगा। इससे\nयदि एक जन्म में ज्ञान न मिले तो भी अगले जन्म में वह अवसर अवश्य मिलता है।\nज्ञान होते हुए भी यदि आप बुरे कर्मों में रहते हैं तो आपको हीनयोनि में दोबारा जन्म मिलेगा।\n\nहोम-हवन, दान-दक्षिणा, ब्राह्मण-पूजा - सब करो, \"वह सभी से बड़ा है\"।\nयदि अहंकार आ जाए तो वह राजसी कर्म बन जाता है। इसका फल लोभ है; एक दुखद जीवन. इससे\nअच्छे कर्म करने पर भी दुख का अनुभव करना पड़ता है। अज्ञानतावश कोई व्यक्ति तनाव पैदा करने के लिए कुछ न कुछ कर बैठता है\nकर्म से कभी ज्ञान विकसित नहीं होता। अज्ञान तमोगुण का कर्म है।\n\nहम कैसे जानते हैं कि कौन सा गुण हमारे अंदर पूरी तरह से सचेत है, इसकी व्याख्या,\nअगले श्लोक में कृष्ण निष्कर्ष के रूप में बताते हैं।",
  "14.21": "अर्जुन उवाच-अर्जुन ने पूछा:\n\nकैः लिंगैः त्रिने गुणन एतं अतीतः भवति प्रभो।\n\nकिं अचरः कथं च एतां त्रिने गुणन अतीवर्तते - हे भगवान, ये किस निशान से हैं\nवह सोचता है कि वह तीन गुणों से पार हो गया है? उसका व्यवहार कैसा है? इन तीनों के बारे में क्या ख्याल है?\nगुणों को पार करता है?\n\nअर्जुन हम सभी की ओर से कृष्ण से प्रश्न करते हैं। वह पूछता है: “तीन गुण\nजो व्यक्ति पार कर गया है उसे कैसे पहचानें? उसका निशान क्या है? उसका व्यवहार\nवह इन तीन गुणों को कैसे पार करता है?”\n\nयहाँ अर्जुन कृष्ण को \"प्रभो\" कहकर संबोधित करते हैं। “निश्चित रूप से मेरे प्रश्नों का उत्तर दो\n\nकोडबल्लावा-निनोब्बाने'' इस संबोधन के पीछे की आवाज और ''पूर्ण समर्पण'' है।\nभगवान अर्जुन ने इस प्रश्न का उत्तर निम्नलिखित श्लोक में विस्तार से दिया है।\n\nभगवान का वचन\nशं च प्रद्धतम च मोहमेव च पांडव।\n\nका\nन वेहति संप्रवृत्ति न निवृत्ति कांक्षति",
  "14.23": "उदासीनवत् असीनः गुणैः यः न विचल्यते।\n\nगुनाः वर्तमानं इति एवं यः अवतिष्ठति न इंगते - उदासीन रहता है। गुण\nआक्षेपों से अविचल. वह बेड़ा छोड़ देता है यह देखने के लिए कि उसमें गुण हैं या नहीं। वह उनकी धुन में है\nझुकता नहीं.\n\nवह सांसारिक मामलों से उदासीन रहता है। हमारी चाहत और जरूरतें हैं\nत्रिगुणों से. त्रिगुणातिता- \"ऐसा और वैसा\" नहीं चाहती।\nउनका विश्वास है कि \"भगवान जैसा चाहेंगे वैसा ही करेंगे\"। [यहाँ एक है\nहमें विषय को जानना होगा. दुनिया में क्या होता है यह हमारे नियंत्रण में नहीं है. हम हैं\nजो आप सोचते हैं कि नहीं होना चाहिए वह हो सकता है, जो आप सोचते हैं वह नहीं हो सकता।\nऐसे में व्यर्थ में यह कहकर दिमाग पर जोर डालने का कोई मतलब नहीं है कि ``ऐसा ही होना चाहिए'']।\nजब आप इस तरह रहते हैं, तो जो आप चाहते हैं वह न मिलने पर कोई गुस्सा नहीं होता, और कोई पलायन नहीं होता। मन प्रसन्न है.\n\nइन्द्रियाँ गुणों में हैं, इन्द्रियों के पीछे गुण हैं। लेकिन तीन गुना\nयह सब जानते हुए, बिना परेशान हुए, किसी भी क्रिया में [यहाँ तक कि अस्थायी क्रिया में भी]।\nबिना चपलता के रहता है।\n\nसमदुःखासुखः स्वस्थः समालोष्टा शमकांचनः |\n\nतुलकाप्रियप्रियो धिरास्तुल्यानिंदात्मसमस्तुतिः",
  "14.26": "माँ च यः अव्यभिचारेण भक्तियोगेन सेवते।\n\nसः गुणं समतित्य एतं ब्रह्मभूया कल्पते - मेरे प्रति अनन्य भक्ति सहित\nउपासक इन गुणों के बंधनों को तोड़कर भगवान की भक्ति के लिए प्रकृति के समान होता है\nएक भूमिका बन जाती है। [आत्मा प्रकृति से जुड़ जाती है]।\n\nयदि हम स्वयं त्रिगुहतीत बनने का प्रयास करें तो हमें उस प्रयास में सफलता मिलेगी\nनहीं कर सकते क्योंकि हमारी सारी सोच त्रिगुण के इर्द-गिर्द घूमती है। यह एक चक्र है. यह चक्र\nमोह से बचने के लिए उस सारथी को आना ही होगा। जैसा कि द्वादशस्तोत्र कहता है:\n“त्रिगुणातिता विधारक परितो देहि सुभक्तिम”। वह जो त्रिगुणातीतों का संरक्षण करता है\nप्रभु. इसलिए तीन गुना बनने का एकमात्र तरीका उस भगवान के प्रति समर्पण करना है।\nउस भगवान के प्रति एकनिष्ठ भक्ति से जो लक्ष्मी है - लक्ष्मी द्वारा\nमृत्यु पन्द्रह बेड़ियों से सुसज्जित होकर संसार में आई और इन सभी बेड़ियों को छीन लिया\nमाँ की गोद में लौट सकता हूँ.\n\nब्राह्मणो हि प्रतिष्ठितामृतस्यव्ययस्य च |\n\nसवस्थस्य च धर्मस्य सुखास्यैकंथिकस्य च।",
  "13.6": "महाभूतानि[महं भूतानि] अहंकारःः बुद्धिः अव्यक्तम् एव च।\nइन्द्रियाणि दशा एकं च पंच च इन्द्रिया अधियाः ॥\n\nइच्छा वेतः सुखं दुःखं संघतः चेतना धृतिः |\n\nएतत् क्षेत्रं समसेन सविकारं उदाहृतम् -- मिट्टी[पृथिवी], जल[वरुण], अग्नि[अग्नि] 1:\nगल्वा [वायुपुत्र मारीचि], बानू [अवसर की देवी, विघ्न नशा-विनायक-गणपति] -\nमहाभूत। अहंकार [रह्मवायु और शिव], बुद्धि [पार्वती], मूलप्रकृति [श्री,,\nकिवा[चंद्र.0,, त्वचा[वायुपुत्र मरुत], आँख[सूर्य], जीभ(वरुण], नाक[अश्विस],\nमुँह [अग्नि], हाथ [वायु के पुत्र नदी], पैर [इंद्र के पुत्र यज्ञ (जयता) और शंभू],\nपयु[यम], उपस्थ[शिव-गंडासा के बीच लिंग देवता; स्वायम्भुमानु-स्त्रिय के बीच] इस प्रकार दस\nइंद्रियाँ. ग्यारहवां मनसत्व [इंद्र, काम और अनिरुद्ध] और पांच इंद्रियां हैं\nविषय: ध्वनि, स्पर्श, रूप, रस और गंध[प्राण, अपान, व्यान, उदान रुद्र के पुत्र\nऔर बराबर] ये 24 सघन क्षेत्र हैं।\n\nइच्छा [श्री और भारती], घृणा [(द्वापर-शकुनि]), खुशी [मुख्यप्राण-वायु-भीम], उदासी [काली-\nदुर्योधन], समष्टिशरीरा [शरीर में प्रशंसक जीवन; सभी प्रशंसक देवता],\nस्मृति, साहस [सरस्वती और भारती] के हरहु [श्री] सात विशेष कर्म विकार हैं। इस प्रकार\nविकृति के साथ-साथ क्षेत्र को समाहित बताया गया।\n\nइन दो श्लोकों में कृष्ण क्षेत्र और क्षेत्र की विकृति का वर्णन करते हैं। अखण्ड को क्षेत्र कहा जाता है\nकृष्ण ने यहां सूत्र के रूप में समाहित इकाई के अंतर्गत जगत् के अवयवों का वर्णन किया है।\nसबसे पहले। पंचमहाभूत. इन पांचों से यह पिंडदान और ब्रह्मांड\nनिर्माण किया है। इसी कारण ब्रह्माण्ड को 'प्र-पंच' कहा जाता है। यह पंच\nमहाभूत ही जगत् के मूल हैं। पिंडदान में ये पांच महाभूत अन्नमय और हैं\nइसे प्राणमय कहा जाता है। दृश्यमान स्थूल शरीर पदार्थ और जल से बना है। जैसे कि\nस्थूल शरीर के भीतर एक अदृश्य प्राणमयकोश है। शरीर की गर्मी (अग्नि), सांस (वायु) और\nरक्त-वायु को अंदर (आकाश) जाने दें। इसके परे मन और बुद्धि है\nमनोमयकोश, और उससे भी आगे विज्ञानमयकोश-स्मृति। तो पहले दिमाग लगाओ\nअहंकार और मनोदशा. यहाँ अहंकार का अर्थ है \"मेरे अस्तित्व के प्रति जागरूकता (34/567255 0! 561)।\nअहंकार तत्व पिंडदान में मन है, जिसका अर्थ ब्रह्मांड में है।\n\nइस व्यक्त जगत की उत्पत्ति अव्यक्त है। सृष्टि की मूल अवस्था-प्रलयसागर। वह है\nअव्यक्त जगत परमाणु रूप में बिखरा हुआ है। ऐसी दुनिया में, चतुर्मुख\nमहत्व पैदा किया. \"मैं हूँ\" उन जीवित प्राणियों के लिए जो प्रलय सागर में अपने अस्तित्व से अनजान थे।\nउसका बोध ही सार्थकता का सृजन है। मन का दायरा आत्मा है. यह हमारी स्मृति की सीमा है.\n\nइस शरीर में पाँच इन्द्रियाँ हैं, पाँच। कर्मेन्द्रियाँ हैं। और ग्यारहवाँ\nकामुक मन है. कान से ध्वनि का बोध, आँख से रूप का बोध, नाक से गंध का बोध\nअवशोषण, जीभ द्वारा रस का अवशोषण, त्वचा द्वारा वायु का अवशोषण। इसी प्रकार बोलने के लिए मुँह, हाथ\nकाम करने के लिए, पैदल चलने के लिए. इन आठों को ग्रह कहा जाता है (19060/9)। फिर पेयु और\nउपस्थ (उत्सर्जक और प्रजननात्मक)। ग्यारहवाँ जो इस सब पर विचार करता है\nकामुक मन. ये सभी क्षेत्र की सामग्रियां हैं. सामूहिक रूप से यही क्षेत्र है. [यहाँ कहा गया है\nप्रत्येक इकाई के साथ उसका संरक्षक देवता भी होता है। इस पर संक्षेप में\nकहा]\n\nयह संसार सदैव परिवर्तनशील है। उसके लिये जगत् को अश्वत्थ भी कहा जाता है। घोड़ा दृढ़ है\nगतिमान एक जानवर. यह कभी स्थिर नहीं रहता. ये दुनिया हमेशा ऐसी ही है\nगति में रहना - इसे ही प्राचीन लोग अश्वत्थ कहते थे। हमारा शरीर भौतिक है\nविकृति मानसिक जगत की सारी उथल-पुथल मानसिक विकार है। विशेषकर\nहमारी इच्छा (इच्छा), (ए)द्वेष, सुख और दुख, हमारी स्मृति (चेतना), (ए)ध्रुति। ये कृष्ण का है\nक्षेत्र के स्वरूप और विकृति का वर्णन | चाहे यह विचार कितना भी विस्तृत क्यों न हो\nहम विश्लेषण कर सकते हैं. कृष्ण ने यहां सब कुछ समझाया है.\n\nयदि हम ज्ञान के मार्ग पर आगे बढ़ना चाहते हैं तो हमें कुछ नैतिकताओं को अपने आचरण में अपनाना चाहिए\n0065 08 0016000 कोड हैं। हमें उनका अनुसरण करना होगा.\nकृष्ण अगले पांच श्लोकों में पालन किए जाने वाले बीस गुणों (685010079) की व्याख्या करते हैं। यह\nजितना अधिक हम प्रत्येक गुण को अपने जीवन में शामिल करेंगे, हम उतने ही अधिक जानकार होंगे\nहो सकता है रास्ते में हो. सावधान रहें अन्यथा हमें अज्ञानता के मार्ग पर चलना पड़ेगा\nकृष्ण ने भी यहां दिया है.\n\nअमनित्वमादम्बित्वमहिंसा क्षान्तिरर्जवम्।\n\nआचार्योपासनां शौचं स्फ्य्र्यमात्मविनिग्रहः 17।\n\nअमनित्वं अदम्बित्वं अहिंसा क्षांतिः आर्जवम्।\n\nआचार्य उपासनां शौचं स्फुर्यं आत्मविनिग्रहः -- - बिंका छोड़ना, वरिष्ठता\nदिखावा न करें, चोट न पहुँचाएँ, उपदेश, सीधा भाषण, गुरुसेवा, हृदय की गोद,\nअचल निर्णय, प्रकार की कठोरता,\n\n(1)अमानित्वम्: ज्ञान प्राप्त करने के लिए हमें सम्मान की इच्छा छोड़ देनी चाहिए। खुद को\nजो लोग सम्मान और पुरस्कार पाने की आशा करते हैं उन्हें कभी ज्ञान प्राप्त नहीं होगा।\nइसके लिए हमें सबसे पहले प्रोपेगेंडा को छोड़ना होगा। सभी प्रचारों के लिए धन्यवाद\nज्ञान की पीठ पर खड़े हो जाओ - फिर ज्ञान आएगा। यदि कोई आपकी प्रशंसा करता है, तो यह उसकी उदारता है-\nवहां विनम्र रहें.\n\n(2) अदंभित्वम् : सबके सामने छोटा बनकर रहना सीखो। भव्यता का कोई प्रदर्शन नहीं. ज्ञान\nईमानदारी के पथ पर कभी न हटें। यह दिखाने के लिए कि कुछ ऐसा है जो नहीं है\nमत जाओ\n\n(3) अहिंसा: कभी भी दूसरों को दुःख न पहुँचाएँ। अगर हम किसी का मन दुखाते हैं\nऐसी कोई दवा नहीं है जो इसे वापस ठीक कर सके। तो कभी दूसरा नहीं\nचेहरा मत बनाओ(!1501). दूसरों को परेशान न करना ही अहिंसा है।\n\n(4) क्षांतिः : प्रतिहिंसा न करना। जब कोई हमें हानि पहुँचाता है तो हम प्रतिकार करते हैं\nछांटने मत जाओ. गलत काम करने वालों को सजा देने की व्यवस्था है. सांसारिक रूप से\nदेखिए, जब कोई गलत करता है तो उसे सजा देना न्यायपालिका और न्यायपालिका की जिम्मेदारी है\nयह सिस्टम है, हम नहीं. यदि हम गलत करने वालों को दंडित करने जा रहे हैं तो वह है\nकानून हाथ में लेना अपराध हो जाता है. परमेश्वर के राज्य में भी यही गलत है\nअपराधियों को सजा देने की अलग व्यवस्था है. तो तुम्हें बदला नहीं लेना पड़ेगा\nश्राप देने का कोई अधिकार नहीं है.\n\nइन उपरोक्त गुणों का एक अच्छा उदाहरण जड़भरत और रायकव मुनि हैं। उनकी जीवनी\nअगर आप इसे पढ़ेंगे तो आपको पता चलेगा कि उन्होंने अपने जीवन में इस गुण का पालन कैसे किया।\n\n(5) आर्जवम् : बिना मास्क के रहना। सीधा बोलो. बिना अंदर और बाहर के\nईमानदारी से जियो(5170611/-5173100801%0/267055)।\n\n(6) आचार्योपासनाम्: आचार्य का अर्थ है अच्छी तरह से जानना कि क्या सही है और क्या गलत है\nजो लोग इस पर अमल करते हैं. वे सत्य को खोजते हैं और उसे समाज के सामने लेकर चलते हैं\nशोमैन. ऐसे की सेवा. बुद्धिमान व्यक्ति आसानी से नहीं मिलते और मिलते भी हैं\nसामान्यतः परीक्षण के बिना ज्ञान प्रवाहित नहीं होता। चाहे कुछ भी हो, बुद्धिमानों से मुँह मत मोड़ो।\nयदि आपकी ज्ञान की प्यास गहरी है तो वे अवश्य ही आपको ज्ञान देंगे। अगर आपको ज्ञान चाहिए\nबुद्धिमानों के खुलने का इंतजार करना होगा। इसका एक अच्छा उदाहरण श्वेतकेतु और हैं\nप्रश्नोपनिषद में पिप्पला की कथा आती है।\n\n(7)शौचम् :शौच का अर्थ है स्वच्छता। इस विषय को हम पिछले अध्याय में कुछ हद तक देख चुके हैं।\nकन्नड़ में शौचम का मतलब 'फोल्ड' होता है। हमें मोड़ने की बजाय मोड़ना सीखना होगा।\n\nयदि आप नहाते हैं और गीले कपड़े पहनते हैं और किसी को नहीं छूते हैं, तो आप संक्रमित नहीं हो सकते।  यह साफ़ है\nमूलत: मन से संबंधित है। इसके अलावा, शरीर की सफाई. सांसारिक मामला\nइसे भूल जाओ और अपना मन भगवान में लगाओ। हम काया-वाचा-मनसा हैं\nमोड़ना चाहिए. यदि हमारे मन में कोई बुरा विचार आता है, यदि कोई बुरा शब्द हमारे मुँह में आता है - तो हम संकट में हैं।\nयदि जो वास्तव में काया-वाचा-मनसा मदी है वह मैलिगे के साथ है, तो वे सभी जो साथ हैं\nमोड़ सकते हैं. इसे ही पूर्वकाल में 'पंक्षिपवन' कहा जाता था\nजिस पंक्ति में आप बैठे हैं उसे मोड़ें। ज्ञान के बिना शास्त्र गोद नहीं है। ईश्वर का स्मरण\nमानसी में, जब भगवान का नाम मुंह में होता है तो हम मुंह मोड़ लेते हैं।\n\nमन को शुद्ध करने के लिए आचमन और प्राणायाम करें। “हे भगवान, आपका\nमेरी सहस्त्र धाराओं से अमृत प्रवाहित होने दो, जिससे मेरा पूरा शरीर पवित्र हो जाए।\nऐसा करो, मेरे अन्दर के सारे पाप और मैल जल कर धुल जायें\nअनुसन्धान के द्वारा, ध्यानमग्न पापापुरुष को समाप्त हो जाना चाहिए। यहाँ हमारे सिर से\nहमें अपने भीतर अमृत की धारा उतरती हुई महसूस होनी चाहिए (966! 10. प्रहयाम)।\nसारी गंदगी जल जायेगी. आचमन हमारे शरीर में भगवान की याद है। “हे पानी,\nतुम ही सुखकोश हो, तुम ही सुखधाम हो, मैं तुम्हें ही खोज रहा हूं। वह प्रभु मेरे पास आये\nहमें उनके समाधान के लिए प्रार्थना और प्रार्थना करनी होगी।” ये सब हम जानते हैं\nहम तभी मोड़ेंगे जब हम ऐसा करेंगे। भगवान को याद करो. भगवान को भूल जाओ\nप्रति मील पुंडरीकाक्ष के स्मरण के बिना आंतरिक शुद्धि असंभव है।\n\n(8) स्थिर्यम् : मन की स्थिरता (00111040॥) स्थिर्यम्। हमें अपना निर्णय स्वयं चाहिए।\nजैसा कि किसी ने कहा है कि हमें अपना निर्णय बदलकर भ्रमित नहीं होना चाहिए। हम हैं\nहमें अपने दिमाग में सोचने में सक्षम होना चाहिए। हमें जो भी प्रश्न मिले उसका उत्तर दें\nखोज करने की क्षमता हमारे दिमाग में है। \"जहाँ प्रश्न है वहाँ उत्तर है\"।\nशास्त्रों का अच्छी तरह से अध्ययन करें और अपनी समस्या का उत्तर स्वयं खोजें और कड़ी मेहनत करें\nकिसी की बात सुनें और भ्रमित हुए बिना शांत रहें।\n\n(9) आत्मविनिग्रह: इंद्रियों पर नियंत्रण ($56.001500। हमारी इंद्रियां हमारे नियंत्रण में होनी चाहिए।\nइंद्रियों को वश में करने के लिए हमें अपने मन को वश में करना होगा। मन के हाथ में\nबंदर मत बनो, अपने मन पर नियंत्रण रखो। इसके लिए अपना मन ईश्वर में लगाओ\nइसे रोकें इस प्रकार आत्म-संयम के माध्यम से इंद्रियों पर संयम प्राप्त करें।",
  "13.7": "इच्छा वेतः सुखं दुःखं संघतः चेतना धृतिः |\n\nएतत् क्षेत्रं समसेन सविकारं उदाहृतम् -- मिट्टी[पृथिवी], जल[वरुण], अग्नि[अग्नि] 1:\nगल्वा [वायुपुत्र मारीचि], बानू [अवसर की देवी, विघ्न नशा-विनायक-गणपति] -\nमहाभूत। अहंकार [रह्मवायु और शिव], बुद्धि [पार्वती], मूलप्रकृति [श्री,,\nकिवा[चंद्र.0,, त्वचा[वायुपुत्र मरुत], आँख[सूर्य], जीभ(वरुण], नाक[अश्विस],\nमुँह [अग्नि], हाथ [वायु के पुत्र नदी], पैर [इंद्र के पुत्र यज्ञ (जयता) और शंभू],\nपयु[यम], उपस्थ[शिव-गंडासा के बीच लिंग देवता; स्वायम्भुमानु-स्त्रिय के बीच] इस प्रकार दस\nइंद्रियाँ. ग्यारहवां मनसत्व [इंद्र, काम और अनिरुद्ध] और पांच इंद्रियां हैं\nविषय: ध्वनि, स्पर्श, रूप, रस और गंध[प्राण, अपान, व्यान, उदान रुद्र के पुत्र\nऔर बराबर] ये 24 सघन क्षेत्र हैं।\n\nइच्छा [श्री और भारती], घृणा [(द्वापर-शकुनि]), खुशी [मुख्यप्राण-वायु-भीम], उदासी [काली-\nदुर्योधन], समष्टिशरीरा [शरीर में प्रशंसक जीवन; सभी प्रशंसक देवता],\nस्मृति, साहस [सरस्वती और भारती] के हरहु [श्री] सात विशेष कर्म विकार हैं। इस प्रकार\nविकृति के साथ-साथ क्षेत्र को समाहित बताया गया।\n\nइन दो श्लोकों में कृष्ण क्षेत्र और क्षेत्र की विकृति का वर्णन करते हैं। अखण्ड को क्षेत्र कहा जाता है\nकृष्ण ने यहां सूत्र के रूप में समाहित इकाई के अंतर्गत जगत् के अवयवों का वर्णन किया है।\nसबसे पहले। पंचमहाभूत. इन पांचों से यह पिंडदान और ब्रह्मांड\nनिर्माण किया है। इसी कारण ब्रह्माण्ड को 'प्र-पंच' कहा जाता है। यह पंच\nमहाभूत ही जगत् के मूल हैं। पिंडदान में ये पांच महाभूत अन्नमय और हैं\nइसे प्राणमय कहा जाता है। दृश्यमान स्थूल शरीर पदार्थ और जल से बना है। जैसे कि\nस्थूल शरीर के भीतर एक अदृश्य प्राणमयकोश है। शरीर की गर्मी (अग्नि), सांस (वायु) और\nरक्त-वायु को अंदर (आकाश) जाने दें। इसके परे मन और बुद्धि है\nमनोमयकोश, और उससे भी आगे विज्ञानमयकोश-स्मृति। तो पहले दिमाग लगाओ\nअहंकार और मनोदशा. यहाँ अहंकार का अर्थ है \"मेरे अस्तित्व के प्रति जागरूकता (34/567255 0! 561)।\nअहंकार तत्व पिंडदान में मन है, जिसका अर्थ ब्रह्मांड में है।\n\nइस व्यक्त जगत की उत्पत्ति अव्यक्त है। सृष्टि की मूल अवस्था-प्रलयसागर। वह है\nअव्यक्त जगत परमाणु रूप में बिखरा हुआ है। ऐसी दुनिया में, चतुर्मुख\nमहत्व पैदा किया. \"मैं हूँ\" उन जीवित प्राणियों के लिए जो प्रलय सागर में अपने अस्तित्व से अनजान थे।\nउसका बोध ही सार्थकता का सृजन है। मन का दायरा आत्मा है. यह हमारी स्मृति की सीमा है.\n\nइस शरीर में पाँच इन्द्रियाँ हैं, पाँच। कर्मेन्द्रियाँ हैं। और ग्यारहवाँ\nकामुक मन है. कान से ध्वनि का बोध, आँख से रूप का बोध, नाक से गंध का बोध\nअवशोषण, जीभ द्वारा रस का अवशोषण, त्वचा द्वारा वायु का अवशोषण। इसी प्रकार बोलने के लिए मुँह, हाथ\nकाम करने के लिए, पैदल चलने के लिए. इन आठों को ग्रह कहा जाता है (19060/9)। फिर पेयु और\nउपस्थ (उत्सर्जक और प्रजननात्मक)। ग्यारहवाँ जो इस सब पर विचार करता है\nकामुक मन. ये सभी क्षेत्र की सामग्रियां हैं. सामूहिक रूप से यही क्षेत्र है. [यहाँ कहा गया है\nप्रत्येक इकाई के साथ उसका संरक्षक देवता भी होता है। इस पर संक्षेप में\nकहा]\n\nयह संसार सदैव परिवर्तनशील है। उसके लिये जगत् को अश्वत्थ भी कहा जाता है। घोड़ा दृढ़ है\nगतिमान एक जानवर. यह कभी स्थिर नहीं रहता. ये दुनिया हमेशा ऐसी ही है\nगति में रहना - इसे ही प्राचीन लोग अश्वत्थ कहते थे। हमारा शरीर भौतिक है\nविकृति मानसिक जगत की सारी उथल-पुथल मानसिक विकार है। विशेषकर\nहमारी इच्छा (इच्छा), (ए)द्वेष, सुख और दुख, हमारी स्मृति (चेतना), (ए)ध्रुति। ये कृष्ण का है\nक्षेत्र के स्वरूप और विकृति का वर्णन | चाहे यह विचार कितना भी विस्तृत क्यों न हो\nहम विश्लेषण कर सकते हैं. कृष्ण ने यहां सब कुछ समझाया है.\n\nयदि हम ज्ञान के मार्ग पर आगे बढ़ना चाहते हैं तो हमें कुछ नैतिकताओं को अपने आचरण में अपनाना चाहिए\n0065 08 0016000 कोड हैं। हमें उनका अनुसरण करना होगा.\nकृष्ण अगले पांच श्लोकों में पालन किए जाने वाले बीस गुणों (685010079) की व्याख्या करते हैं। यह\nजितना अधिक हम प्रत्येक गुण को अपने जीवन में शामिल करेंगे, हम उतने ही अधिक जानकार होंगे\nहो सकता है रास्ते में हो. सावधान रहें अन्यथा हमें अज्ञानता के मार्ग पर चलना पड़ेगा\nकृष्ण ने भी यहां दिया है.\n\nअमनित्वमादम्बित्वमहिंसा क्षान्तिरर्जवम्।\n\nआचार्योपासनां शौचं स्फ्य्र्यमात्मविनिग्रहः 17।\n\nअमनित्वं अदम्बित्वं अहिंसा क्षांतिः आर्जवम्।\n\nआचार्य उपासनां शौचं स्फुर्यं आत्मविनिग्रहः -- - बिंका छोड़ना, वरिष्ठता\nदिखावा न करें, चोट न पहुँचाएँ, उपदेश, सीधा भाषण, गुरुसेवा, हृदय की गोद,\nअचल निर्णय, प्रकार की कठोरता,\n\n(1)अमानित्वम्: ज्ञान प्राप्त करने के लिए हमें सम्मान की इच्छा छोड़ देनी चाहिए। खुद को\nजो लोग सम्मान और पुरस्कार पाने की आशा करते हैं उन्हें कभी ज्ञान प्राप्त नहीं होगा।\nइसके लिए हमें सबसे पहले प्रोपेगेंडा को छोड़ना होगा। सभी प्रचारों के लिए धन्यवाद\nज्ञान की पीठ पर खड़े हो जाओ - फिर ज्ञान आएगा। यदि कोई आपकी प्रशंसा करता है, तो यह उसकी उदारता है-\nवहां विनम्र रहें.\n\n(2) अदंभित्वम् : सबके सामने छोटा बनकर रहना सीखो। भव्यता का कोई प्रदर्शन नहीं. ज्ञान\nईमानदारी के पथ पर कभी न हटें। यह दिखाने के लिए कि कुछ ऐसा है जो नहीं है\nमत जाओ\n\n(3) अहिंसा: कभी भी दूसरों को दुःख न पहुँचाएँ। अगर हम किसी का मन दुखाते हैं\nऐसी कोई दवा नहीं है जो इसे वापस ठीक कर सके। तो कभी दूसरा नहीं\nचेहरा मत बनाओ(!1501). दूसरों को परेशान न करना ही अहिंसा है।\n\n(4) क्षांतिः : प्रतिहिंसा न करना। जब कोई हमें हानि पहुँचाता है तो हम प्रतिकार करते हैं\nछांटने मत जाओ. गलत काम करने वालों को सजा देने की व्यवस्था है. सांसारिक रूप से\nदेखिए, जब कोई गलत करता है तो उसे सजा देना न्यायपालिका और न्यायपालिका की जिम्मेदारी है\nयह सिस्टम है, हम नहीं. यदि हम गलत करने वालों को दंडित करने जा रहे हैं तो वह है\nकानून हाथ में लेना अपराध हो जाता है. परमेश्वर के राज्य में भी यही गलत है\nअपराधियों को सजा देने की अलग व्यवस्था है. तो तुम्हें बदला नहीं लेना पड़ेगा\nश्राप देने का कोई अधिकार नहीं है.\n\nइन उपरोक्त गुणों का एक अच्छा उदाहरण जड़भरत और रायकव मुनि हैं। उनकी जीवनी\nअगर आप इसे पढ़ेंगे तो आपको पता चलेगा कि उन्होंने अपने जीवन में इस गुण का पालन कैसे किया।\n\n(5) आर्जवम् : बिना मास्क के रहना। सीधा बोलो. बिना अंदर और बाहर के\nईमानदारी से जियो(5170611/-5173100801%0/267055)।\n\n(6) आचार्योपासनाम्: आचार्य का अर्थ है अच्छी तरह से जानना कि क्या सही है और क्या गलत है\nजो लोग इस पर अमल करते हैं. वे सत्य को खोजते हैं और उसे समाज के सामने लेकर चलते हैं\nशोमैन. ऐसे की सेवा. बुद्धिमान व्यक्ति आसानी से नहीं मिलते और मिलते भी हैं\nसामान्यतः परीक्षण के बिना ज्ञान प्रवाहित नहीं होता। चाहे कुछ भी हो, बुद्धिमानों से मुँह मत मोड़ो।\nयदि आपकी ज्ञान की प्यास गहरी है तो वे अवश्य ही आपको ज्ञान देंगे। अगर आपको ज्ञान चाहिए\nबुद्धिमानों के खुलने का इंतजार करना होगा। इसका एक अच्छा उदाहरण श्वेतकेतु और हैं\nप्रश्नोपनिषद में पिप्पला की कथा आती है।\n\n(7)शौचम् :शौच का अर्थ है स्वच्छता। इस विषय को हम पिछले अध्याय में कुछ हद तक देख चुके हैं।\nकन्नड़ में शौचम का मतलब 'फोल्ड' होता है। हमें मोड़ने की बजाय मोड़ना सीखना होगा।\n\nयदि आप नहाते हैं और गीले कपड़े पहनते हैं और किसी को नहीं छूते हैं, तो आप संक्रमित नहीं हो सकते।  यह साफ़ है\nमूलत: मन से संबंधित है। इसके अलावा, शरीर की सफाई. सांसारिक मामला\nइसे भूल जाओ और अपना मन भगवान में लगाओ। हम काया-वाचा-मनसा हैं\nमोड़ना चाहिए. यदि हमारे मन में कोई बुरा विचार आता है, यदि कोई बुरा शब्द हमारे मुँह में आता है - तो हम संकट में हैं।\nयदि जो वास्तव में काया-वाचा-मनसा मदी है वह मैलिगे के साथ है, तो वे सभी जो साथ हैं\nमोड़ सकते हैं. इसे ही पूर्वकाल में 'पंक्षिपवन' कहा जाता था\nजिस पंक्ति में आप बैठे हैं उसे मोड़ें। ज्ञान के बिना शास्त्र गोद नहीं है। ईश्वर का स्मरण\nमानसी में, जब भगवान का नाम मुंह में होता है तो हम मुंह मोड़ लेते हैं।\n\nमन को शुद्ध करने के लिए आचमन और प्राणायाम करें। “हे भगवान, आपका\nमेरी सहस्त्र धाराओं से अमृत प्रवाहित होने दो, जिससे मेरा पूरा शरीर पवित्र हो जाए।\nऐसा करो, मेरे अन्दर के सारे पाप और मैल जल कर धुल जायें\nअनुसन्धान के द्वारा, ध्यानमग्न पापापुरुष को समाप्त हो जाना चाहिए। यहाँ हमारे सिर से\nहमें अपने भीतर अमृत की धारा उतरती हुई महसूस होनी चाहिए (966! 10. प्रहयाम)।\nसारी गंदगी जल जायेगी. आचमन हमारे शरीर में भगवान की याद है। “हे पानी,\nतुम ही सुखकोश हो, तुम ही सुखधाम हो, मैं तुम्हें ही खोज रहा हूं। वह प्रभु मेरे पास आये\nहमें उनके समाधान के लिए प्रार्थना और प्रार्थना करनी होगी।” ये सब हम जानते हैं\nहम तभी मोड़ेंगे जब हम ऐसा करेंगे। भगवान को याद करो. भगवान को भूल जाओ\nप्रति मील पुंडरीकाक्ष के स्मरण के बिना आंतरिक शुद्धि असंभव है।\n\n(8) स्थिर्यम् : मन की स्थिरता (00111040॥) स्थिर्यम्। हमें अपना निर्णय स्वयं चाहिए।\nजैसा कि किसी ने कहा है कि हमें अपना निर्णय बदलकर भ्रमित नहीं होना चाहिए। हम हैं\nहमें अपने दिमाग में सोचने में सक्षम होना चाहिए। हमें जो भी प्रश्न मिले उसका उत्तर दें\nखोज करने की क्षमता हमारे दिमाग में है। \"जहाँ प्रश्न है वहाँ उत्तर है\"।\nशास्त्रों का अच्छी तरह से अध्ययन करें और अपनी समस्या का उत्तर स्वयं खोजें और कड़ी मेहनत करें\nकिसी की बात सुनें और भ्रमित हुए बिना शांत रहें।\n\n(9) आत्मविनिग्रह: इंद्रियों पर नियंत्रण ($56.001500। हमारी इंद्रियां हमारे नियंत्रण में होनी चाहिए।\nइंद्रियों को वश में करने के लिए हमें अपने मन को वश में करना होगा। मन के हाथ में\nबंदर मत बनो, अपने मन पर नियंत्रण रखो। इसके लिए अपना मन ईश्वर में लगाओ\nइसे रोकें इस प्रकार आत्म-संयम के माध्यम से इंद्रियों पर संयम प्राप्त करें।\n\nइन्द्रियार्थेषु वैराग्यमनहंकारा एव च।\nजन्ममृत्युज्रव्याधिदुःखदोषानुदर्शनम्",
  "15.4": "ततः पदं तत् परिमार्गितव्यं यस्मिन् गता न निवर्तन्ति भूयः ।\nतमेव चाद्यं पुरुषं प्रपद्ये यतः प्रवृत्तिः प्रसृता पुराणी ॥\n\nउस वैराग्यखड्ग से संसारवृक्ष काटकर वह परमपद खोजना चाहिए — जहाँ पहुँचने के बाद लौटना नहीं होता। वही मोक्ष है।\n\n'आद्यं पुरुषं प्रपद्ये' — जिनसे यह पुरातन सृष्टिप्रवाह आरम्भ हुआ, उन्हीं आद्यपुरुष लक्ष्मीनारायण की शरण लेनी चाहिए। ईश्वर-शरणागति ही संसारछेद का उपाय है।",
  "15.3": "न रूपमस्येह तथोपलभ्यते नान्तो न चादिर्न च सम्प्रतिष्ठा ।\nअश्वत्थमेनं सुविरूढमूलम् असङ्गशस्त्रेण दृढेन छित्त्वा ॥\n\nसंसार में रहते हुए संसार का सम्पूर्ण स्वरूप नहीं देखा जा सकता — न अन्त, न आदि, न प्रतिष्ठा। जैसे समुद्रतट पर बैठा मेंढक समुद्र की गहराई नहीं जान सकता।\n\nइस दृढ़मूल अश्वत्थ को असङ्ग के तीक्ष्ण खड्ग से — वैराग्य से — काटकर परमपद की खोज करनी चाहिए।",
  "15.2": "अधश्चोर्ध्वं प्रसृतास्तस्य शाखा गुणप्रवृद्धा विषयप्रवालाः ।\nअधश्च मूलान्यनुसन्ततानि कर्मानुबन्धीनि मनुष्यलोके ॥\n\nत्रिगुणों से पुष्ट इस वृक्ष की शाखाएँ ऊपर और नीचे दोनों ओर फैली हैं। शब्द-स्पर्श-रूप-रस-गन्ध — ये पाँचों विषय इसके नव-पल्लव हैं जो जीवों को निरन्तर आकर्षित करते हैं।\n\nअधः मूलानि — जीवों के कर्मानुसार अधोलोकों में भी जड़ें फैली हैं। हमारे अपने शरीर में भी — सहस्रार से लेकर नीचे तक — भगवान् व्याप्त हैं, त्रिगुण शाखावत् और पाँच विषय पल्लववत् हैं।\n\nमनुष्यलोक ही साधनाभूमि है। अतः कर्मबन्धन काटकर मूलच्छेद करना कर्तव्य है।",
  "14.22": "भगवान उवाच- भगवान ने कहा:\n\nप्रकाशम् च प्रशस्तं च मोहं ईव च पांडव।\n\nन वेहति संप्रवृत्तानि न निवर्तनि कांक्षति-पांडव, न सांसारिक प्रकाश का प्रकाश न कायका।\nहुरुपन्ना गैले, भ्रांतियान्ने  न तो - जब होता है तो नफरत करता है; जब वहाँ नहीं है तो मत चाहो।\n\nजो तीन गुणों को पार कर चुका है वह कुछ अवांछनीय घटित होने पर घृणा नहीं करता;\nकोई उस चीज़ की इच्छा नहीं करता जो वांछित है जब वह नहीं मिलती। “क्या आवश्यक है, क्या नहीं है\nभगवान मुझसे बेहतर जानता है. मुझे इसकी चिंता क्यों करनी चाहिए?\nवैराग्य उसमें है. वह जीवन में जो कुछ भी मिलता है उसका स्वागत करता है। व्यास\nमहाभारत के शांति पर्व में एक कहावत है:\nएवम अप्प्य अशुभं कर्म न भूतं न भभाति॥ 12-32-18॥\n\n\"जो होगा वह न तो अतीत में हुआ है और न ही भविष्य में होगा। जो होगा वह होकर रहेगा।\"\nनफरत करने का नतीजा क्या है कि मैं इसे नहीं चाहता?\"। तो जो त्रिगुण को पार कर गया है - 'नहीं' आता है।\nउससे नफरत मत करो; जो नहीं है उसकी कोई चाहत नहीं है.  हर चीज़ को उदासीनता से देखना, भरा हुआ\nवह बिना दिये रहता है।\n\nसंसार में कुछ लोग तत्व में रुचि रखते हैं, जबकि कुछ लोग केवल वृत्ति में रुचि रखते हैं। और कुछ के लिए क्या\nदिलचस्पी भी नहीं - यह नहीं जानते कि अंधेरा अंधेरा है। ऐसे लोग हैं जो अंधेरे में रहते हैं। ये है\nएक बहुत ही सामान्य विचार. जो लोग त्रिगुण से परे खड़े हैं वे इसे और अपने मन को देखते हैं\nविकृत नहीं करता. \"सब कुछ उसके गुणवत्ता प्रभाव के अनुसार हो रहा है\"।\n\nवे जानबूझकर और तटस्थ होकर जीते हैं। वह वही कहता है जो उसे सत्य दिखता है। लेकिन कभी बहस नहीं की\nविवाद पैदा नहीं करता. \"सब कुछ भगवान का काम है, उसने सब कुछ व्यवस्थित किया है।\"\n\"सच्चा भक्त\" कैसा होता है इसका वर्णन करते समय गीता के बारहवें अध्याय में स्वीकार करेंगे\nइस श्लोक में कृष्ण ने वही व्याख्या दी है। इसका अर्थ है- बाह्य गुण से परे\nखड़ा रहना ही सच्ची भक्ति है.\n\nयहाँ व्यास \"पांडव\" विशेषण का प्रयोग करते हैं। पांडा का अर्थ है बुद्धिमान। पांडव का अर्थ है\nजो ज्ञान को पहचान कर झुक जाता है। \"त्रिगुणातीत बनने से पहले तुम्हें पांडव बनना होगा\"\nइस विशेषण के पीछे संदेश है.\n\nउदासिनवदासिनो गुणैर्योना विचल्यते |\nगुण वर्तन्ता इत्येव योवतिष्ठति नेन्गते",
  "14.5": "सत्त्वं रजः तमः इति गुणाः प्रकृतिसम्भः |\nनिबधना ति महाबाहो देहे देहिनं अव्यम् - महाबाहो, सत्व-रजसु - तमस्सु\nएमबी ऐसे गुण हैं जो प्रकृति से उत्पन्न होते हैं। वे शरीर में अमर जीवन बांध देते हैं।\n\nप्रकृति - गुणत्रयमणि, इस संसार के सभी जीवित प्राणियों की माँ। तो हर एक\nयहां तक कि जब जीवन का जन्म होता है, तो वह सत्व-रजस्सु और तमस के तीन गुणों के साथ पैदा होता है\nइन गुणों के प्रभाव में आगे बढ़ें। तीन गुणों के बिना शुद्ध एकल गुण वाला कोई भी जीवन\nनहीं बनाया गया. ये तीन गुण हमें जड़ में भी मिलते हैं। सदैव उत्तर दिशा की ओर प्रकाश रखें\nदेने वाला अग्नि सार; जल, जो अंधकार का स्थान है, राजसिक है और सदैव नीचे की ओर खींचता है\nमृदा-तमसु. संसार की सभी वस्तुएँ इन तीनों (007%13007) का संयोजन हैं। उदाहरण के लिए सूखा.\nहमने इसे धरती (मिट्टी-तमस्सु) में बोया। वहां हमने उसे सींचा (निरु-रजसु), वह सूर्य था।\nप्रकाश (सूर्य-सत्व) को अवशोषित करके अंकुर बड़ा हुआ और फसल दी। उस फसल की कटाई करें और उसे चावल में बदल दें\nहमने किया. हमने चावल (तमस्सु) में पानी (रजस्सु) मिलाया और चावल बनाने के लिए इसे (सखा-सत्व) पकाया।\nचावल हो या भात, सब कुछ पृथ्वी, जल और अग्नि का मिश्रण है। इस प्रकार सत्त्व-रजसु तथा\nयह संपूर्ण सृष्टि तमस नामक गुणत्रयों से बनी है। प्रत्येक जीवित प्राणी जन्म लेता है\nये तीन गुण बंधनकारी हैं। इन तीनों गुणों की मात्रा हर किसी में अलग-अलग होती है\nअलग होगा. यहां तक ​​कि सबसे सात्विक मोक्षयोग्य जीवन में भी ये तीन गुण होते हैं।\nकिसी व्यक्ति में शत-प्रतिशत शुद्ध सत्त्वगुण नहीं होता। जड़ में देखा जाए तो अग्नि-सार। लेकिन\nइसके साथ ही धूम्र-रजस्सु, काष्ठ-तमस्सु। सत्त्वगुण का बोध रजस है और\n\nतमस के माध्यम से. इस प्रकार इन गुणत्रयों के बंधन के कारण, जीव-स्थूल प्रकृति में मूल नहीं है\nव्यक्ति एक शरीर के साथ पैदा होता है और उस शरीर को खोने के बाद मर जाता है। जन्म मृत्युहीन है\nमोक्ष प्राप्त करने के लिए हमें अपने साथ इन तीन आंतरिक शत्रुओं पर विजय प्राप्त करनी होगी।\n\nयहाँ व्यास ने \"महाबाहु\" विशेषण का प्रयोग किया है।\nयह महाबाहु ही हैं जो नृत्य के इन त्रिगुणों को खोदते हैं; कुसिटा को अस्वीकार करना आध्यात्मिक है\nइस विशेषण के पीछे \"शुरानगु\" की ध्वनि है।\n\nसारा ब्रह्माण्ड, हमारा यह जीवन, सब कुछ गुणत्रय की विकृति है। हमारा दिमाग, हमारी सोच, हमारी\nनिर्णय, हमारा पढ़ना, हमारा विश्वास, सभी इन गुणों से प्रभावित होते हैं। हमें सही रास्ते पर ले चलो\nये त्रिगुण हैं जो हमारा मार्गदर्शन करते हैं, और ये त्रिगुण हमें भटकाते हैं। तीन तरीकों में से कौन सा?\nहम यह निर्णय लेने में सावधानी बरतते हैं कि यदि हम मार्ग पर चलें तो अच्छा रहेगा\nअगर हम आना चाहते हैं तो हमें यह जानना होगा कि हम किस रास्ते पर जा रहे हैं। इस कारण से\nत्रिगुणों के प्रति जागरूकता हमारे लिए बहुत महत्वपूर्ण है।\n\nचार चीजें हैं जो किसी व्यक्ति को नियंत्रित करती हैं। जीव अनादिकाल से जीव के साथ है\n\"स्वभाव\" स्वरूप में सन्निहित है। सत्व, रजस्सु, तमसु - इन तीन के साथ\n'प्रभाव'. प्रकृति कभी नहीं बदलती. हमें अपने स्वभाव को पहचानना होगा।\nलेकिन हम नहीं जानते कि हमारा स्वभाव क्या है! क्योंकि इस प्रकृति पर\n'प्रभाव' ढक्कन बनकर बैठा रहता है. हम सदैव इस आवरण से प्रभावित होते हैं जो हमारा स्वभाव है\nहम भ्रमित हैं. लेकिन यह हमारा वास्तविक स्वभाव नहीं है - यह प्रभाव है। संपूर्ण\nजीवन भर हम यह नहीं जान पाते कि हमारा स्वभाव क्या है। प्रकृति क्या है\nअनजाने में हम इसके प्रभाव में आ जाते हैं और संघर्ष करते रहते हैं। इन त्रिगुणों का प्रभाव हम पर पड़ता है\nयदि हम नहीं जानते कि यह कैसे काम करता है - तो हम स्वयं को ठीक नहीं कर सकते। आज\nहम अपनी प्रकृति और सत्त्वगुण, रजस्सु और तमस को किनारे कर देते हैं\nउत्तोलन में रहना.\n\nसबसे पहले हमें खुद को ठीक करना होगा-समाज को नहीं। कितना सार है हममें; रजस तत्व\nतमस तत्व कितना है यह जानकर, अपने आचरण में सत्व तत्व का अधिक उपयोग करें,\nइसकी सामग्री को बढ़ाने का प्रयास करें. हम कहाँ हैं राजासन और अतीत में जो घटनाएँ घटीं\nहम तमस के प्रभाव में आकर भटक गये हैं। खुद पे भरोसा। आचरण, आगे. ऐसा नहीं है\nसावधान रहें. अगर हम इस मुद्दे के प्रति जागरूक हो जाएं तो हम खुद पर काफी हद तक काबू पा सकते हैं\nसुखपूर्वक रह सकते हैं.\n\nनिम्नलिखित श्लोक में कृष्ण का जीवन सत्त्व क्या है; राजस का जीवन कैसा है; तामसिक जीवन जियें\nवह बताते हैं कि यह कैसा है। जीव त्रिगुण गाँठ में फँसे, जो गाँठ\nयदि आप प्रभाव में रहना जानते हैं, तो सत्य के मार्ग पर चलने का प्रयास करें\nकृष्ण ने निम्नलिखित श्लोक में इसका बहुत सुन्दर विश्लेषण किया है।\n\nतत्र सत्त्वं निर्मलत्वं प्रकाशकामनायम्।\n\nसुखसंगेन बधना ति ज्ञानसंगेन चानघा",
  "14.24": "सम दुःखसुखः स्वस्थः सम लोषा अश्म कांचनः।\n\nतुल्य प्रिया अप्रियः धीरा तुल्का निन्दात्मा संस्तुतिः - सुख और दुःख को समान रूप से देखता है।\nवह अपने आप में रहता है. मिट्टी, पत्थर, सोना उसके लिए एक समान हैं। उपलब्धि से मजबूत हुआ\nउसका प्रिय वही है; अप्रिया वैसी ही है. एक चुटकुला भी है. स्तुति वही है.\n\nत्रिगुणातिता सभी सुखों और दुखों को समान रूप से देखती है। क्योंकि जाहिरा तौर पर हमारे लिए\nजो सुख प्रतीत होता है, जरूरी नहीं कि वह सुख ही हो। दुःख भी वैसा ही है. यह\nजब आप जान जाते हैं तो मन में यह भावना जगती है कि सब कुछ प्रभु की लीला है। फिर सब बराबर है\nहमारी देखने की क्षमता बढ़ेगी.\nजिस प्रकार हम दर्शक के रूप में नाटक में दृश्य देखते हैं, उसी प्रकार संसार में भी\nघटनाओं को दर्शक बनकर देखने की आदत डालनी चाहिए। यह आनंदमय हो सकता है,\nदुखी हो सकते हैं-लेकिन हम हैं। मनुष्य को भगवान के प्रत्येक कार्य का आनंद लेना चाहिए।\nजीवन में अस्थायी दुःख हमारे शाश्वत सुख की ओर ले जाते हैं। लेकिन वह हमारे लिए है\nपता नहीं बस इतना ही. त्रिगुणातीतों को इसका एहसास हुआ और उन्होंने सुख और दुःख को समान रूप से देखा\nखुशी से जियो.\nकृष्ण यहाँ उन शब्दों को दोहराते हैं जो उन्होंने पहले ज्ञानियों और भक्तों के लक्षणों का वर्णन करते समय कहे थे\nवह दोहराता है.  पृथ्वी त्रिगुणात्मक, अनमोल रत्न;  सोना - सब कुछ वैसा ही है. उसे\nन तो सोना और न ही रत्न कीमती माने जाते हैं। उसके लिए अनमोल है केवल ज्ञान।  यह\nक्योंकि उसे धन, मोती या सोने की कोई इच्छा नहीं है।\nनहीं लगता इसलिए वह सुख से रहता है। भागवत के तीसरे स्कंद में होता है\nएक श्लोक कहता है:\n\nयश्च मुधतमो लोके यश्च बुद्धे परमं गथा\n\nवौमभौ सुखमेधेते क्लिश्यतान्तरितो जनः ॥3-7-17॥|\nएक मूर्ख और दूसरा बुद्धिमान - कि ये दोनों संसार में सुखपूर्वक रह सकें। क्योंकि\nउन्हें पैसे से कोई प्यार नहीं है. लेकिन जो लोग दोनों के बीच में हैं वे जीवन का अर्थ नहीं जानते\nवे प्यार का शिकार हो जाते हैं और दुःख महसूस करते हैं।\nरामकृष्ण ने बताया कि कैसे बुद्धिमान लोग इस सिद्धांत को अपने जीवन में अपनाकर जीवन जीते हैं\nइसका एक अच्छा उदाहरण परमहंस की जीवनी है। मैसूर महाराजा के समय में सोदेमाथा\nदूसरी विश्वप्रियतीर्थों (वृन्दावनाचार्यों) द्वारा जीयी गयी जीवन शैली है जो स्वामी थे\nएक अच्छा चित्रण.\n\nइस श्लोक को दूसरी तरफ से देखने पर हमें एक और विशेष संदेश मिलता है।\nएक सच्चे भक्त (त्रिगुणातीत) की भगवद भक्ति उसके जीवन में आने वाले सुखों और दुखों से आती है।\nउतार-चढ़ाव नहीं होता. चाहे वह गरीबी में हो या गरीबी में, वह निरंतर भगवान की भक्ति में लगा रहता है।\nदूसरों का प्रेम-घृणा उसकी भक्ति की कसौटी नहीं है। इस प्रकार सभी त्रिगुणातीत हैं\nवे पद-प्रतिष्ठा में भी समानता के साथ रहते हैं।\n\nमनापमानयोस्तुल्यस्तुल्यो मित्ररिपक्षयोः |\n\nसर्वाम्बरित्यगि गुहातितः स उच्यते",
  "15.9": "श्रोत्रं चक्षुः स्पर्शनं च रसनं घ्राणमेव च ।\nअधिष्ठाय मनश्चायं विषयानुपसेवते ॥\n\nभगवान् प्रत्येक इन्द्रिय में विशेष रूप से अधिष्ठित हैं। 'अधिष्ठाय' — ऊपर स्थित होकर, दुःखकलङ्क से रहित। जीव सुख-दुःख में डूबकर विषय भोगता है; भगवान् 'उपसेवते' — ऊपर स्थित होकर, समस्त विषयों को निर्लिप्त भाव से अनुभव करते हैं।\n\n'एव' और 'च' दोनों एक साथ — 'एवच' — सर्वदोषरहित, सर्वकल्याणगुणपूर्ण, ज्ञानानन्दमय भगवान् का विशेषण है।",
  "15.5": "निर्मानमोहा जितसङ्गदोषा अध्यात्मनित्या विनिवृत्तकामाः ।\nद्वन्द्वैर्विमुक्ताः सुखदुःखसञ्ज्ञैर्गच्छन्त्यमूढाः पदमव्ययं तत् ॥\n\nपरमपद के अधिकारी कौन? — जो अहंकार-ममकार से रहित हैं; जिन्होंने आसक्ति जीत ली; जो निरन्तर भगवत्चिन्तन में रत हैं; जिन्होंने सभी भोग-कामनाएँ छोड़ दी हैं; जो सुख-दुःख में समभाव से स्थित हैं।\n\nलौकिक आशा ही निराशा का मूल है। जैसे दिन-रात समभाव से स्वीकार करते हैं, वैसे ही सुख-दुःख सहते हुए अमूढ़ जन उस अव्यय पद को प्राप्त करते हैं।\n\nइस अध्याय में कृष्ण जीव-जगत्-भगवत् की त्रिपुटी का रोचक वर्णन करते हैं। भगवत्चिन्तनशील जनों के लिए आगे के श्लोक विशेष महत्त्वपूर्ण हैं।",
  "15.10": "उत्क्रामन्तं स्थितं वापि भुञ्जानं वा गुणान्वितम् ।\nविमूढा नानुपश्यन्ति पश्यन्ति ज्ञानचक्षुषः ॥\n\n'गुणान्वितम्' — सर्वकल्याणगुणसमन्वित — यह शब्द स्पष्ट करता है कि यह श्लोक भगवान् के विषय में है, जीव के नहीं।\n\nजीव को देह में लाने वाले, जाग्रत्-स्वप्न-सुषुप्ति में अनुभव देने वाले, देह से निकालने वाले — सब कुछ भगवान् करते हैं। विमूढ — विपरीतज्ञानी — उन्हें नहीं देखते। ज्ञानचक्षुष् — शास्त्रपूत अन्तर्दृष्टि सम्पन्न — उन्हें आत्मा में ही देखते हैं।",
  "15.11": "यतन्तो योगिनश्चैनं पश्यन्त्यात्मन्यवस्थितम् ।\nयतन्तोऽप्यकृतात्मानो नैनं पश्यन्त्यचेतसः ॥\n\nभगवद्दर्शन के लिए केवल शास्त्राभ्यास पर्याप्त नहीं — ज्ञानपूर्वक निरन्तर ध्यानयोग-साधना आवश्यक है। जैसे किसान खेत जोतकर बीज बोता है, पर वर्षा दैव-अधीन है — वैसे प्रयत्न के साथ भगवदनुग्रह भी चाहिए।\n\nवसुदेव — शुद्धसात्त्विक मन; उसमें वासुदेव प्रकट होते हैं।\n\nअकृतात्मानः — अशुद्धबुद्धि — प्रयत्न करने पर भी भगवान् को नहीं देख पाते। 'एनम्' — आपके अत्यन्त समीप, जीवस्वरूप के अन्तर में बिम्बरूप भगवान् को — देखें। वे बाहर नहीं, भीतर ही खोजने योग्य हैं।",
  "15.12": "यदादित्यगतं तेजो जगद्भासयतेऽखिलम् ।\nयच्चन्द्रमसि यच्चाग्नौ तत्तेजो विद्धि मामकम् ॥\n\nपहले कहा था — सूर्य, चन्द्र, अग्नि मुझे प्रकाशित नहीं कर सकते; अब कृष्ण कहते हैं — सूर्य का तेज, चन्द्र का प्रकाश, अग्नि का ज्वलन — सब मेरे तेज से उत्पन्न हैं।\n\nसमस्त ज्योतियों का आदिस्रोत भगवान् हैं। वही तेज अणु-रूप में हमारे स्वरूप में स्थित होकर हमें नियमित करता है और महत्-रूप में समग्र ब्रह्माण्ड को प्रकाशित करता है।\n\nउपासना की दृष्टि से — सूर्यस्थ तेज नारायण का, चन्द्रस्थ धन्वन्तरि का, अग्निस्थ परशुराम का। प्रत्येक प्रकाशस्रोत भगवन्नाम मात्र है।",
  "14.27": "ब्राह्मणः हि प्रतिष्ठा अहं अमृतस्य अव्ययस्य च |\nशवस्थस्य च धर्मस्य सुखस्य इकांतिकस्य च -मैं स्वयं प्रकृति की शाश्वत और अपरिवर्तनीय छवि का आधार हूं-\n\nसनातन धर्म का आधार और आनंदमय मोक्ष का भी।\n\nत्रिगुण से परे खड़े होकर जीवन का स्वाभाविक-शाश्वत धर्म व्यक्त होता है। इस हालत में\nचित प्रकृति, ब्रह्मत्व (श्री लक्ष्मी भी उस प्रभु का समर्थन करती हैं) को मोक्ष में जोड़ा जा सकता है।\n\nइति चतुर्दशोता*ध्यायः\nचौदहवाँ अध्याय समाप्त हो गया\n\nक्या यह सच है?\n\nअध्याय ग्यारह\n\nयह अध्याय गीता का सबसे छोटा अध्याय है। यहाँ फलश्रुति के दो श्लोकों को छोड़कर,\nइसमें अठारह श्लोक हैं जो परिसर का हिस्सा बताते हैं। इन अठारह श्लोकों में कृष्ण ही संपूर्ण संसार हैं\nउन्होंने राज खोल दिया है. यदि महाभारत भारतीय दर्शन का प्रतीक है, तो भगवद गीता है\nमहाभारत का सार. ऐसी भगवद्गीता का सार है यह पन्द्रहवाँ अध्याय। इस अध्याय को समझें\nयदि आप ऐसा करेंगे तो आप न केवल संपूर्ण गीता, बल्कि संपूर्ण भारतीय दर्शन को समझ जायेंगे।\nइस अध्याय पर भाष्य लिखते हुए शंकराचार्य कहते हैं: “न केवलं गीतार्थः, तथास्तु\nसर्वोपि शास्त्रतः अत्र पर्यवसितः।'' ''यह सिर्फ गीता का सार नहीं है। सभी धर्मग्रंथ\nवे जो कुछ भी कहते हैं वह इस अध्याय में है।\" 18 181110550108 08 01498 116121\n1011050[/03)/15 1507 002010: 0\" 81808026 0/66। माधवाचार्य अपने अधिकांश लेखों में\nउन्होंने अध्याय के तीन श्लोकों (16, 17, 18) का उल्लेख किया है। क्योंकि इन श्लोकों में\nआचार्यों के सभी सिद्धांतों में सार समाहित है।\n\nअतीत में एक परंपरा थी. जब खाने के लिए बैठें, तो यह भोजन शुरू करने से पहले होता है\nअध्याय का श्लोक पढ़कर फिर भोजन करना। “भोजन पत्र से पहले संपूर्ण शास्त्र\n'हम पहुंचे सार के पास' उस परंपरा का कारण यही है।\nतेरहवें अध्याय में कृष्ण ने क्षेत्र और क्षेत्र विशेषज्ञों के बारे में बताया। विश्व और विश्व निर्देशक\nइस अध्याय में कृष्ण एक और पहलू के साथ, भगवान के विषय को और भी अधिक स्पष्ट करते हैं\nसमझाता है. प्रकृति और प्राकृत ब्रह्मांड, उस ब्रह्मांड और अंततः संपूर्ण को पार करने का साधन\nइस अध्याय में दर्शनशास्त्र का संग्रह है। एक अनोखा संज्ञानात्मक संदेश जिसे हमें जानना आवश्यक है\nकृष्ण ने इस अध्याय के माध्यम से बताया है.\n\nचेनानाचेतन विश्व-क्षरा'। उससे आगे चित्र है-'अक्षर'। उससे परे सब कुछ\nनियमका भगवंत-'पुरुषोत्तम'। जैसा कि बारहवें अध्याय-पंद्रह के आरंभ में बताया गया है\nबाड़ों से घिरा सोलहवाँ जीवन। उसने इस पन्द्रह को सोलह के आसपास कस लिया\nसत्रहवीं श्रीलक्ष्मी हैं। जो हमें इस बाड़ से मुक्त कर मोक्ष प्रदान करें\nपुरूषोत्तम, अठारहवाँ। [इन पंद्रह बाड़ों के बारे में विस्तार से जानने के लिए\nप्रश्नोत्तरी का छठा प्रश्न देखें। श्रद्धां खं वायुः ज्योतिः आपः पृथिवी इन्द्रियम्\nमनः | अन्नमन्नादि वीर्यं तपो मन्त्रः कर्म लोकः लोकेषु च नाम च ॥ 6-4 ये हैं\nवे पंद्रह बाड़ें]।\n\n\"अठारह' एक संख्या है जो हमारे सामने दर्शनशास्त्र का सार प्रस्तुत करती है। इस अध्याय में\nअठारह श्लोकों के माध्यम से, कृष्ण ने हमारे सामने सभी विज्ञानों का सार खोल दिया है। चलो\nआइए कृष्ण से सुनें अनोखा अध्याय.\n\nभगवान का वचन\nउर्द्वमूलमदहशखमश्वत्थं प्राहुरव्ययम् |\nछन्दमसि यस्य पर्णानि यस्तं वेद स वेदवित् ॥1॥\n\nभगवान उवाच- भगवान ने कहा:\n\nऊर्ध्वमूलं अधः शाखां अश्वत्थं प्राहुः अव्यम् |\n\nछंदंसि यस्य पर्णानि यस्तं वेद सः वेदवित् - ऊपर भगवान और ब्रह्मांड में प्रकृति।\nजनजाति। निम्नलिखित जीव-जड़ इसके शाखाएँ और टहनियाँ हैं। यह सदैव विद्यमान है[|[अ*श्वः*ठ्ठ- आज\nजैसे कि कोई कल नहीं है], [अस्व*त्थ-निरंतर गति वाला घोड़ा] एक खिलता हुआ पेड़ है। वेद\nइसकी पत्तियाँ. जो यह जानता है वह वेदों को जानता है।\n\nयह श्लोक इस बात का प्रमाण है कि भगवत गीता ही उपनिषद का सार है। कठोपनिषद में कहा गया है:\n\"उर्ध्वमूलो अवाक शाखाः एशो अश्वत्थः सनातनः\"। यहाँ इसे “ऊर्ध्वमूलम्” कहा जाता है\nअधः शाखां अश्वत्थं प्राहुः अव्ययम्”। यह एक पंक्ति है जिसमें सामग्री शामिल है.\nयहां के एक-एक शब्द में बहुत सारा दर्शन छिपा हुआ है।\n\nयदि इस पंक्ति का सीधे कन्नड़ में अनुवाद किया जाए तो, \"यह संसार एक खिलता हुआ वृक्ष है\nऊपर क्या है, शाखाएँ और टहनियाँ नीचे है”। जाहिर तौर पर यह पंक्ति\nहमारे लिए देखने का कोई मतलब नहीं है. \"खिलता हुआ पेड़\" - यह क्या है? विशेष रूप से\nकृष्ण ने अश्वत्थ वृक्ष क्यों कहा? उस पर फल नहीं आता, उस पर फूल नहीं आते, वह घर में काम नहीं आता\nयह",
  "15.17": "उत्तमः पुरुषस्त्वन्यः परमात्मेत्युदाहृतः ।\nयो लोकत्रयमाविश्य बिभर्त्यव्यय ईश्वरः ॥\n\nक्षर और अक्षर दोनों से परे — उत्तमपुरुष — वे ही परमात्मा हैं, वही भगवान् विष्णु। जो त्रैलोक्य में प्रवेश करके सब कुछ धारण करते, पोषित करते, रक्षित करते हैं — वह अव्यय ईश्वर।",
  "16.1": "अहिंसा सत्यमक्रोधस्यागः शनैरिर्पैशुनम् |\nदया भूतेष्ठालोलुत्वमर्दवं ह्रीराचपलम्",
  "15.6": "न तद्भासयते सूर्यो न शशाङ्को न पावकः ।\nयद्गत्वा न निवर्तन्ते तद्धाम परमं मम ॥\n\nवह परमधाम — जहाँ सूर्य नहीं चमकता, चन्द्रमा नहीं, अग्नि भी नहीं — वही भगवान् का परमनिलय है। सूर्य-चन्द्र-अग्नि स्वयं तेजस्वी हैं, किन्तु भगवान् के तेज से ही प्रकाशित हैं — 'तमेव भान्तमनुभाति सर्वम्' (कठो०)।\n\nसूर्य में गायत्री-उपासना, चन्द्र में धन्वन्तरि-उपासना, अग्नि में भगवत्-यजन — ये सब भगवत्-प्रतीक मात्र हैं। आत्मज्योति जागृत कर अन्तर्यामी भगवान् का आश्रय लेने वाले को ही परमधाम की प्राप्ति होती है।\n\nबृहदारण्यक में जनक-याज्ञवल्क्य-संवाद — सूर्य, चन्द्र, अग्नि, वाक् — क्रमशः प्रकाश; अन्ततः 'आत्मैवास्य ज्योतिः' — आत्मज्योति ही परमप्रकाश है।",
  "14.18": "ऊर्ध्वं गच्छन्ति सत्त्वस्थः मधे तिष्ठन्ति राजसः।\nजघन्यागुण वृत्तिस्थः अधः गच्छन्ति तमसः-सत्व ऊंचा होगा। राजस\nबीच में खड़े हो जाओ. 'अंतिम गुण' से प्रभावित तमस नीचे की ओर गिरता है।\n\nत्रिगुण की प्रकृति के बारे में बात करने वाले कृष्ण ने इस श्लोक में इसके प्रभाव के तीन चरणों की व्याख्या की है।\nसत्व में रहने वाले लोग मानसिक रूप से ऊपर उठते हैं। रजोगुण की कोई समृद्धि नहीं है।\nतमस में व्यक्ति मानसिक रूप से पतित हो जाता है। यहाँ 'उर्ध्व' शब्द विशेष है\nअर्थ है. जैसा कि कठोपनिषद कहता है:\n\n॥॥\nउर्ध्व का अर्थ है सर्वोपरि भगवान। सत्व में आरोहण का अर्थ है-\nईश्वर की ओर बढ़ना. जैसे-जैसे वह आगे बढ़ता गया वह भगवान के करीब होता गया\n\nजाता है लेकिन जो तमस में है वह भगवान की ओर पीठ करके चलता है। राजसा था\nवह अभी भी अनिश्चित स्थिति में है।\n\n'श्रीदेवी', वह शक्ति जो देवताओं को नियंत्रण में रखती है; मनुष्य को बंदी बनाने की शक्ति है \"भूदेवी\" और\n'दुर्गा देवी' राक्षसों को कैद में रखने की शक्ति हैं। सात्विक 'श्रीदेवी' की कृपा से सत्त्वमानिनी होते हैं\nएक पात्र के रूप में, व्यक्ति ऊपरी लोक [पृथ्वी के ऊपर के छह सूक्ष्म लोकों] को प्राप्त करता है\nऔर अंततः मोक्ष]; राजा अभी भी भूदेवी [भूमि और] की हिरासत में हैं\nअत्याचार] और तमस तमसलोक [पृथ्वी] से देवी दुर्गा के नियंत्रण में हैं\nनीचे दिए गए सात सूक्ष्म जगतों से जुड़ें]।\n\nन[5]न्यं गुणेभ्यः कर्तारं यदा दृष्टा 5नुपश्यति |\nगुणेभ्यश्च परमं वेत्रि मद्भा वाम सोइधिगच्छति ॥19॥\n\nन अन्यं गुणेभ्यः कर्तारं यदा दृष्टा अनुपश्यति।\n\nगुणेभ्यः च परम वेत्ति मत भावम् सः अधिगच्छति - त्रिगुणों के अलावा इन सभी प्रभावों के लिए।\nवह जो पाता है कि कोई अन्य कारण नहीं है [भगवान जो त्रिगुणों से अलग है वह सभी का स्रोत है\nवह जो कारण के रूप में जानता है] और वह जो भगवान को गुणों से परे जानता है [सत्य\nमनुष्य-वह] मुझमें निवास करता है।\n\nहमारे जीवन में जो कुछ भी घटित होता है वह इन तीन गुणों की प्रक्रिया है। हम स्वयं हैं\nकुछ नहीं करता. इसके बजाय सब कुछ त्रिगुणों के प्रभाव में चल रहा है। प्रकृति से आ रहा है,\nवे हमारे फॉर्मेट को बंद करके काम करते हैं. इसलिए। एक व्यक्ति की शक्ल\nआचरण से उसके वास्तविक स्वरूप को जानना संभव नहीं है। इस वजह से हम\nसंसार में होने वाली घटनाओं को वैराग्य से देखने की आदत डालनी चाहिए।\n\nसत्त्व से अभ्यस्त मन केवल उसी को देखता है जो सत्व से मेल खाता है। ऐसा व्यक्ति कदापि नहीं\nइसमें कोई भ्रम नहीं है कि 'मैंने यह किया।'\nकिसी भी चीज़ को कभी भी कर्ता नहीं कहा जाता है।  अतः गुण केवल निष्क्रिय गुण नहीं है। उसके लिए\nइस कविता में प्रशंसक भावना को पहचानने का संदेश है। [श्लोक 17 में हमारे पास यह है\nके बारे में चर्चा की]। लेखकत्व के अनेक प्रकार. जहां भी कोई इच्छुक कार्य हो, वही कर्ता है। ये है\nअस्तित्व केवल आत्मा के लिए है. लेकिन सच्चा लेखकत्व एक \"स्वतंत्र स्वैच्छिक कार्य\" है। यह मौजूद है\nकेवल प्रभु में. हम सभी प्रसिद्ध कहावत \"नहं कर्ता हरिः कर्ता\" को जानते हैं।\nमोक्षधर्मपर्व में इस प्रकार कहा गया है:\n\nनहं कर्ता न कर्ता त्वं कर्तायस्तु सदा प्रभु ॥\n\nसोत्$यं पचति कालो मम वृक्षे फलं इवगतम् ॥ 12-220-84\n\"तुमने यह नहीं किया है, मैंने यह नहीं किया है - \"उसने' यह हमारे द्वारा किया है\"।\nअहंकार नहीं आ सकता. इससे कोई नफरत नहीं, कोई कड़वाहट नहीं. \"मैंने किया, नन्नी 0दायता\"\nयह सिर्फ एक भ्रम है. इस संसार में जो कुछ भी होता है वह इन तीन गुणों के प्रभाव के कारण होता है\nघटित। इसके अलावा मैंने अपने लिए कुछ नहीं किया है.' यह अहसास हमें आना चाहिए.\nत्रिगुणों का प्रभाव जड़ के साथ-साथ आत्मा में भी होता है। इसके प्रभाव में ही कार्रवाई होती है।\nयदि कोई आपको डांटता है, तो इसका मतलब है कि उस समय रजोगुण सचेत रूप से काम कर रहा है\nइसका मतलब है करना. हमें उस क्षण इस जागरूकता के साथ कार्य करना चाहिए। स्वयं श्री रामचन्द्र\nउन्होंने जीवन में चलकर दिखाया है. रामायण में वाल्मिकी कहते हैं:\n\nस हि नित्यं प्रशांतं मृदुपूर्वः च भासते |\n\nउच्चामनोअपि पौरूषं नोथरं प्रतिपद्यदा ॥अयोध्या-1.15॥\nयदि कोई उनसे झगड़ा करता तो राम कभी क्रोधित नहीं होते थे। \"चलो फिर बात करते हैं\"\nमानो जा रहा हो. क्योंकि जब किसी व्यक्ति में रजोगुण काम कर रहा होता है।\nहम उनके साथ हैं. ऐसे समय आएंगे जब आपको शालीनता से काम लेना होगा। यह बहुत\nख़तरनाक इसलिए जो लोग दुःखी हैं उनके साथ राजा न बनें। तटस्थता से बहुत दूर\nरुकें (0॥ 0t! 79108 16800. तब उसका रजोगुण अपने आप नष्ट हो जाएगा. क्रोधियों के सामने.)\nअगर आप चुप रहेंगे तो उनका गुस्सा बहुत जल्दी शांत हो जाएगा। इस प्रकार जब हम इन गुणों के प्रभाव को पहचानते हैं\nहमारा जीवन भी अलग होगा.\nउपरोक्त जानना पर्याप्त नहीं है. भगवान इन त्रिगुणों से परे हैं। उसे\nयह जानने से आपको त्रिगुणों से परे खड़े होने में मदद मिलेगी। मैं उस भगवान से जुड़ने के लिए यहां हूं\nहमें इस सत्य को समझना होगा कि हमें त्रिगुणों के प्रभाव से बाहर आना होगा। “ऐसे लोग\nमन मुझमें बस जाता है और इसी कारण वे आकर मुझमें मिल जाते हैं\nकृष्ण कहते हैं.\nइस श्लोक का एक और पहलू भी है. “गुणेभ्यः अन्यं कर्तारं यदा दृष्टा अनुपश्यति तदा सः\n'न' भवति''। यहाँ \"गुणेभ्यः अन्यम्\" का अर्थ है त्रिगुणमणिनि, जो गुणों से युक्त है,\nश्री-भू-दुर्गा नाम दिया गया, जो महालक्ष्मी से भी बड़ी शक्ति है। वह असली भगवान है.\nजैसा कि मुंडकोपनिषद कहता है:\n\nयदा पश्यः पश्यते रुक्कवर्णं कर्तारमीशं पुरुषं ब्रह्मयोनिम् ॥ 3-1-3\n\nचार चेहरों का पिता कौन है, चित्रकला का स्वामी कौन है, संपूर्ण कौन है\nवेदों से पढ़ें - वही सृष्टिकर्ता है। जो यह जानता है वही सच्चा मनुष्य है।\n\nकेवल शरीर - मानव शरीर - सभी आध्यात्मिक उपलब्धियों के लिए सुसज्जित है। ऐसा शरीर\nउपयोग करने के लिए तत्पर. धर्म-अर्थ-काम से वैराग्य का अर्थ है सत्त्व-रजसु-\nतमोगुण से छुटकारा पाने और भगवान से जुड़ने के लिए। यही मानव जीवन का लक्ष्य है। \"यह\nमुझमें तीन गुण काम कर चुके हैं, मुझे इस प्रभाव से छुटकारा पाना चाहिए और ऊपर उठना चाहिए।”\nजागना केवल मनुष्य के लिए है। इस जागरूकता के कारण ही उसमें ''मद्भवाम् सोद्धिगच्छति''\nअपने मन को भक्ति ज्ञान से भरकर मोक्ष प्राप्त करता है।\n\nगुणानेथनतित्य तीन देहि देहसमुद्धवन् |\nजन्ममृत्युजरादुःखैरविमुक्तो*मृतमश्नुते",
  "16.2": "तेजः क्षमा धृतिः शौचमाद्रोहो नातिमनिता |\nभवन्ति संपदां दैवीमभिजातस्य भारत",
  "15.14": "अहं वैश्वानरो भूत्वा प्राणिनां देहमाश्रितः ।\nप्राणापानसमायुक्तः पचाम्यन्नं चतुर्विधम् ॥\n\nभगवान् वैश्वानर रूप से प्राणियों के उदर में स्थित होकर — प्राण-अपान से युक्त होकर — चतुर्विध अन्न पचाते हैं। भक्ष्य, भोज्य, लेह्य, चोष्य — ये चार प्रकार।\n\nआहार का त्रिधा विभाजन — मिट्टी का सूक्ष्म भाग मस्तिष्क, मध्य माँस-त्वचा, स्थूल मल; जल का सूक्ष्म प्राण, मध्य रक्त, स्थूल मूत्र; अग्नि का सूक्ष्म वाक्शक्ति, मध्य अस्थिमज्जा, स्थूल दाँत-हड्डी — इस प्रकार सोने की खान से भी कठिन यह कार्य भगवान् वामनरूप से हृदय में स्थित होकर सम्पन्न करते हैं।\n\nकठो० — 'मध्ये वामनमासीनं विश्वे देवा उपासते।'",
  "15.7": "ममैवांशो जीवलोके जीवभूतः सनातनः ।\nमनःषष्ठानीन्द्रियाणि प्रकृतिस्थानि कर्षति ॥\n\nजीव — भगवान् का सनातन अंश है। यह अंश दो प्रकार का है — स्वरूपांश (ज्ञानानन्दस्वभाव की दृष्टि से) और भिन्नांश (प्रतिबिम्बरूप से)। भगवान् महाज्योति हैं, जीव उनका अंश-प्रकाश। भगवान् बिम्ब हैं, जीव प्रतिबिम्ब।\n\nजीव पाँच ज्ञानेन्द्रियों और छठे मन के साथ विषयों की ओर खिंचता है। किन्तु यह कर्षण अन्तर्यामी भगवान् के नियमन से ही होता है — जीव स्वतन्त्र नहीं।\n\nकठोपनिषत् — 'अङ्गुष्ठमात्रः पुरुषोऽन्तरात्मा सदा जनानां हृदये सन्निविष्टः।' मध्वाचार्य — 'सर्वप्राणिहृदिस्थाय वामनाय नमो नमः।'",
  "15.19": "यो मामेवमसम्मूढो जानाति पुरुषोत्तमम् ।\nस सर्ववित्भजति मां सर्वभावेन भारत ॥\n\nअसम्मूढ — अहंकार-क्रोध-मोहरहित शुद्धमनस्क — जो पुरुषोत्तम भगवान् को जानता है, वह सर्वविद् है। भगवद्ज्ञान समस्त ज्ञान का मूल है।\n\nपहले आत्मसाक्षात्कार — जड से भिन्न 'मैं' चेतन इस देह में हूँ; फिर जीवबिम्ब में परमात्मसाक्षात्कार। जो ऐसे जानता है वह सर्वभाव से भजता है।\n\n'भारत' — भरत-वंशज, किन्तु अर्थ — ज्ञानतृष्णा, ज्ञानिभक्ति, प्राणदेव-निष्ठा — इनसे युक्त।",
  "15.16": "द्वाविमौ पुरुषौ लोके क्षरश्चाक्षर एव च ।\nक्षरः सर्वाणि भूतानि कूटस्थोऽक्षर उच्यते ॥\n\nचेतनजगत् में दो प्रकार के पुरुष — क्षर और अक्षर।\n\nक्षर — जिसका शरीर कभी नष्ट होता है। ब्रह्मा भी क्षर हैं — एक कल्पकाल के बाद उनका शरीर भी भस्म। ईशोपनिषत् — 'वायुरनिलममृतं अथेदं भस्मान्तं शरीरम्।' समस्त देवता, सभी जीव — क्षरपुरुष।\n\nअक्षर — कूटस्था श्रीलक्ष्मी। 'कूटस्थ' — जीव और शरीर के संयोग की हेतु। नित्यमुक्ता, ज्ञानानन्दस्वरूपदेहा, निर्लिप्ता — वे सदा अक्षरा हैं। मोक्ष में क्षर भी अक्षर हो जाते हैं, लक्ष्मी तो सदैव अक्षरा हैं।",
  "15.18": "यस्मात्क्षरमतीतोऽहमक्षरादपि चोत्तमः ।\nअतोऽस्मि लोके वेदे च प्रथितः पुरुषोत्तमः ॥\n\nक्षर से 'अतीत' — कक्षा के भीतर क्षर, भगवान् कक्षातीत। अक्षर से 'उत्तम' — लक्ष्मी से भी भगवान् सर्वोत्तम। 'अपि च' — दोनों पद मिलकर निरतिशय श्रेष्ठत्व को कहते हैं।\n\nमध्वाचार्य विष्णुतत्त्वनिर्णय-मङ्गल में — 'सदागमैकविज्ञेयं समतीतक्षराक्षरं नारायणं सदा वन्दे निर्दोषाशेषसद्गुणम्।'\n\n'लोके च वेदे च प्रथितः' — लोके = रामायण-महाभारत-पुराण-पञ्चरात्रादि में; वेदे = श्रुति में — दोनों में 'पुरुषोत्तम' नाम केवल भगवान् के लिए ही है।",
  "15.13": "गामाविश्य च भूतानि धारयाम्यहमोजसा ।\nपुष्णामि चौषधीः सर्वाः सोमो भूत्वा रसात्मकः ॥\n\n'गाम् आविश्य' — पृथ्वी में प्रवेश करके भगवान् ओजस् से — सङ्कर्षण-शेष-शक्ति से — धारण करते हैं। वराहावतार — हिरण्याक्ष द्वारा कक्षाभ्रष्ट पृथ्वी को भगवान् ने वराहरूप में पुनः स्थापित किया। उपनिषत् — 'यः पृथिवीम् अन्तरो यमयति एष आत्मा अन्तर्यामी अमृतः।'\n\n'सोमो भूत्वा रसात्मकः' — भगवान् सोमरूप से चन्द्र में स्थित होकर वनस्पतियों का जीवनरस पोषित करते हैं। संध्यावन्दन में चन्द्रमण्डलस्थ धन्वन्तरि के अमृतकलश का स्मरण — अन्तर्मलशुद्धि के लिए — यही है।",
  "16.11": "चिन्ताम् अपरिमेयं च प्रलयन्तम् उपाश्रितः।\n\nकाम उपभोग परमह एतवत इति शेषिकाः - मृत्यु के साथ नाश होने वाला, अपरिमेय।\nचिंतित। वासना ही जीवन का सब कुछ और अंत है। बस यही तो जीवन है\nआस्तिक\n\nउसके रोने का कोई अंत नहीं है. वह अपना पूरा जीवन उस चीज़ को पाने की तलाश में बिता देता है जो उसके पास नहीं है\nखर्च कर देंगे वे चिंता के गुलाम बन जाते हैं। उनकी चिंताएँ प्रलयंकारी हैं - यहाँ तक कि उनकी मृत्यु तक\nबिना पीछे मुड़े भूतिया। वह भोग का गुलाम है, कोई उसे छोड़ नहीं सकता\nअधीनता में, व्यक्ति यह जानते हुए जीता है कि जीवन का यही मतलब है।",
  "16.13": "इदमद्य मया लब्धमिमं प्राप्स्ये मनोरथम् ।\nइदमस्तीदमपि मे भविष्यति पुनर्धनम् ॥\n\n'यह आज मुझे मिला, यह मनोरथ भी पाऊँगा, यह धन है, यह भी होगा —'\n\nआसुरी स्वभाव वाले का मनोभाव — संचय, अहंकार, भोग की अतृप्त प्यास। 'इदमद्य लब्धम्' — आज यह मिला। 'मनोरथ प्राप्स्ये' — यह इच्छा भी पाऊँगा। यह संग्रहवृत्ति आसुरी सम्पत् का लक्षण।",
  "16.14": "असौ मया हतः शत्रुः हनिष्ये चापरानपि ।\nईश्वरोऽहमहं भोगी सिद्धोऽहं बलवान् सुखी ॥\n\n'वह शत्रु मैंने मारा, और भी मारूँगा। मैं ईश्वर हूँ, मैं भोगी हूँ, मैं सिद्ध हूँ, मैं बलवान् हूँ, मैं सुखी हूँ।'\n\nआसुरी अहंकार का चित्र — स्वयं को सर्वशक्तिमान् मानना। 'अहम् ईश्वरः' — मैं ही ईश्वर हूँ। 'अहम् भोगी' — मैं भोगी हूँ। यह अहंकार ही पतन का मूल।",
  "16.7": "प्रद्धितं च निवृत्तं च जनः न विदुः असुरः।\n\nन शौचं न अपि च आचारः न सत्यं तेषु विद्यते - दुष्ट लोग किस मार्ग से जाते हैं\nजानें कि क्या पकड़ना है और क्या छोड़ना है। कोई तह नहीं; अच्छा कदम नहीं; उनमें से सबसे बहादुर\nकोई शब्द नहीं.\n\nयहाँ कृष्ण राक्षसों के सामाजिक व्यवहार का वर्णन करते हैं। आसुरी प्रकृति वालों के लिए\nक्या करना है और क्या नहीं करना है, इसकी कोई जागरूकता नहीं है। इससे वे\n\nवे वही कर रहे हैं जो नहीं करना चाहिए. न्याय और अन्याय उनके लिए कोई मायने नहीं रखते. पैसा कमाना\nऔर उनकी मूल इच्छा एक विशिष्ट व्यक्ति का दर्जा अर्जित करना है। इस पैसे की वजह से\nउन्हें इसकी परवाह नहीं कि संपादन में न्याय का चेहरा होना चाहिए।\n\nमूलतः असुर प्रकृति के लोगों में स्वच्छता का अभाव होता है। एक अच्छा शब्द, एक अच्छा विचार,\nस्वच्छ शरीर उनमें से नहीं है. वह बाहर से बहुत साफ-सुथरा होने का दिखावा करता था\nजी रहे हैं वे कभी ईमानदार नहीं होते. जो भी किया जाता है दिखावे के लिए किया जाता है.\nकृष्ण की गीता में वर्णित गुणों में से एक का उदाहरण महाभारत में मिलता है।\nइसके लिए गीता को महाभारत का सार कहा जाता है। राक्षसी स्वभाव का उत्कृष्ट उदाहरण\n\"दुर्योधन\"।\n\nये राक्षसी लोग कैसे बन जाते हैं समाज कंटक, क्या है इनकी समझ? यह\nअध्याय के अगले भाग में, कृष्ण विस्तार से बताते हैं।",
  "15.8": "शरीरं यदवाप्नोति यच्चाप्युत्क्रामतीश्वरः ।\nगृहीत्वैतानि संयाति वायुर्गन्धानिवाशयात् ॥\n\nईश्वर जीव के प्रवेश और निर्गमन दोनों के नियन्ता हैं। 'अव-आप्नोति' — देहप्रवेश जीव का बन्धन है, ऊर्ध्वगमन से पूर्व अधःपात। 'उत्क्रामति' — 'उत्' उपसर्ग से मङ्गल-गमन सूचित होता है; मृत्यु अमङ्गल नहीं — ईश्वर द्वारा जीव का स्थूलशरीर से उत्क्रमण है।\n\n'संयाति' — सं = स्वेच्छा से। सब कुछ भगवान् के अधीन है, जीव न जन्म लेता है न मरता है अपने आप।\n\nजैसे वायु फूल से गन्ध अदृश्यरूप से वहन करती है, वैसे ईश्वर षड्इन्द्रियसहित जीव को देह में प्रवेश कराते और निकालते हैं। जीव की गति अदृश्य पर सत्य है।",
  "16.10": "कामम अश्रित्य दुष्बुरं दंभ मन मद अन्विताः।\n\nमोहत् गृहित्वा असत् ग्रहण प्रवर्तन्ते आशुचि व्रतः - अक्षय इच्छा की रीढ़\nपाखंड, अभिमान और अहंकार. ये लोग गंदे कर्मों के दोषी हैं\nवे धारणाओं के आधार पर जीते हैं।\n\nआसुरी मनुष्य की इच्छाओं का कोई अंत नहीं है। कितना भी आये, अभी और भी है। उदाहरण के लिए काम ही\nयदि नहीं, तो वह नौकरी चाहता है, जब उसे नौकरी मिलती है, तो वह अधिक वेतन चाहता है, जब उसे वेतन मिलता है, तो वह वेतन उसका होता है\nअगले दरवाजे वाले पड़ोसी से भी कम - अधिक वेतन, बड़ा पद वगैरह चाहने के लिए\nअगर मिल भी जाए तो भी आप संतुष्ट नहीं होते. यह प्यास तृप्त नहीं हो सकती. जैसा कि किंवदंती कहती है, कैसे\nजिस प्रकार मनुष्य की इच्छा पूरी करने के लिए पाताल को गंदगी से नहीं ढका जा सकता\nहमें कितना भी पैसा क्यों न मिल जाए, हम उसके दाहिनी ओर एक शून्य होते हैं\nहमें दुख है कि इसे शामिल करने से यह कम हो गया। और ख़ुशी को भूल जाओ.\nकठोपनिषद में - जब यम कहते हैं, \"मैं तुम्हें उतना धन दूंगा जितना तुम चाहोगे\",\nनचिकेता कहते हैं: \"न वित्तेण तर्पणियो मनुष्यिनः\"। इसका अर्थ है “मनुष्य का धन।”\n\nइच्छा कोई पूरी नहीं कर सकता।” पर्याप्त है दैवी स्वभाव, आवश्यकता\nयह राक्षसी स्वभाव है. इस प्रकार आसुरी प्रकृति इच्छाओं की पीठ है, उस किनारे की इच्छा है\nबदला लेने के लिए वे वही करते हैं जो उन्हें नहीं करना चाहिए। उनका जीवन पाखंड है. बिगुमना,\nअहंकार, नाटकीय जीवन से दूसरों को धोखा देना। ऐसे चलो\nस्वच्छता के बिना गंदा जीवन उनका है।\n\nचिंतामपरिमेयं च प्रलयंतमपश्रितः |\nकामोपभोगपरम एतववादिति शेषिकाः",
  "16.8": "असत्यम् अप्रतिष्ठम् ते जगत् औः अनिश्वरम् |\n\nअपरस्परा संबुतम् किम अन्यत कामहैथुकम - वह भगवान है जो यह सार्वभौमिक वास्तविकता है।\nवे कहते हैं कि यह कोई योगदान नहीं है [यह झूठ है]। यह ईश्वर में स्थित नहीं है [है]\nनहीं] कहते हैं. ऐसा कहा जाता है कि ऐसा कोई सर्वशक्तिमान नहीं है जो इसे नियंत्रित कर सके। क्रमशः एक से दूसरे\nमैं इस बात से सहमत नहीं हूं कि इसका जन्म हुआ. और क्या उनकी नजर में ये एक अलग तरह का मामला है. ये है\nवासना का दूध-मायाशस्का शिति।\n\nअसुर दो प्रकार के होते हैं. संसार के पास कोई सत्य नहीं है, संसार के पास कोई और प्रतिष्ठा नहीं है, संसार के पास और कोई प्रतिष्ठा नहीं है\nउनकी नास्तिक समझ है कि कोई ईश्वर नहीं है। संसार को सृजन-अवस्था-विनाश के अधीन करना\nवह जानता है कि कोई शक्ति (सत्य) नहीं है। इसलिए, वह ईश्वर रहित इस संसार का आधार है\nउनका तर्क है कि इस दुनिया को नियंत्रित करने वाला कोई भगवान नहीं है, सब कुछ एक भ्रम है। सृष्टि चक्र एक है\nउनकी मान्यता मुर्बताना का सिद्धांत है।\n\nअसुरों का दूसरा प्रकार यह है कि हम इस संसार में जो कुछ भी देखते हैं वह केवल हमारा भ्रम है\nअशक्त करने वाले। सिवाय इसके कि यह संसार हमारी इच्छाओं से विकसित हो रहा है\nउनका मानना है कि यह किसी दूसरी शक्ति का नहीं है.\n\nएतं दृष्टि मावष्टा भया अंतात्मानोल्ब बुद्धयः |\nप्रभावन्त्युग्रकर्मणः क्षय जगतोहितः",
  "16.18": "अहंकारं बलं दर्पं कामां क्रोधं च संमृतः।\nमम आत्म परेडेषु प्रद्विशान्तः अभ्यसूयः -- क्रोध, विवशता, अहंकार, इच्छा, क्रोध का निवास। जो लोग अपने और दूसरों के शरीर में मुझ पर विश्वास नहीं करते और इसका खंडन करते हैं। जो लोग दूसरों की समृद्धि से उत्साहित होते हैं।\n\nउनके मूल गुण हैं - अहंकार, दर्प, काम और रोधा। कौन मुझसे आगे निकल सकता है? यह अभिमान कि मैं बड़ा आदमी हूं। इसे धन और शक्ति का समर्थन प्राप्त है। यह दूसरों को नीची दृष्टि से देखने का एक रूप है। तट की अभिलाषाएँ, उनके पूरे न होने का क्रोध - यही उनका अस्तित्व है। कृष्ण कहते हैं: \"हर किसी के भीतर 'मैं' पर विश्वास मत करो\nयह किसी कारण से अस्थायी रूप से ईश्वर को नकारना नहीं है, बल्कि स्वभाव से ईश्वर को नकारना है। ऐसे लोग हमेशा दूसरों के ज्ञान और धन से ईर्ष्या करते हैं।",
  "16.4": "दम्भः दर्पः अभिमानः च क्रोधः पौरूष्यम एवच।\nअज्ञानं च अभिजातस्य पार्थ संपदाम आसुरीम्- पार्थ, आसुरी संपदा [बुरा आचरण]\nजातक के गुण हैं: पाखंड, अहंकार, ईर्ष्या, क्रोध, अशिष्टता और अशिष्टता।\n\nऊपर वर्णित छब्बीस दैवीय गुणों के विपरीत, इस श्लोक में कृष्ण में छह आसुरी गुण हैं\nकहा:\n\n(1) दंभ (जो चीज़ नहीं है उसका दिखावा करना): मानो जो नहीं है वह अंदर है\nअच्छाई का प्रदर्शन; अपने अंदर की बुराई को छुपाते हुए एक बहुत अच्छे इंसान की तरह व्यवहार करना\nआदि करना धृष्टता प्रतीत होता है। यह ऊपर वर्णित आर्जवम का विपरीत गुण है।\n(2) दर्प: कुछ भी गलत करने से घृणा करने की भावना। यह ह्रीं गुण के विपरीत है।\n\n(3) अतिमान (09 868/7800 08 56): स्वयं के बारे में अत्यधिक विचार; मैं बड़ा आदमी हूं\nदूसरे के प्रति भ्रमित और अनादरपूर्ण होना; कि हर किसी को उसका पैर पकड़ना चाहिए\nइच्छाएँ- ये अतिमानवीय हैं।\n\n(4) क्रोध : क्रोध एक ऐसा दुर्गुण है जिसे व्यक्ति छोड़ना भी चाहे तो नहीं छोड़ सकता। यह ऐसा है जैसे हम नहीं जानते\nएक बुराई जो हमें भटकाती है।\n\n(5) पौरूष्य: उग्र, बुरा भाषण; दूसरे के बारे में दयालुता से बात करना,\nआदि। पौरुष्य का उदाहरण।\n\n(6) अज्ञान : उपरोक्त सभी विकारों का शासक अज्ञान है। एक सच्चा साधु कभी इतना बुरा नहीं होता\nगुणों के गुलाम मत बनो.\n\nये सभी आसुरी गुण हमारे अंदर अपना घर बना लेते हैं और हमें बाहर निकाल देते हैं। तो ये\nसबसे पहले हमें विकारों से छुटकारा पाना होगा। कुरान में यह है - \"14ए 07077 08! 1017 51098\n508 03%ए 0001 61067 08” खूबसूरती से कहा गया है। अपने आप को बाहर फेंको, अपने अंदर बैठो\nवे कहते हैं कि पहले इन बुराइयों से छुटकारा पाओ जो तुम्हें बर्बाद कर रही हैं। वेद यही कहते हैं\nइस प्रकार कहा: \"यो अस्मां वेति यं वयं द्विष्टिः\" ..|[अथर्व 3-27-2|- अर्थात-\n“वह जो हमसे नफरत करता है, वह दुश्मन जिससे हम नफरत करते हैं\nइसका मतलब है धक्का देना।” यहाँ शत्रु हमारे आंतरिक शत्रु हैं, ये विकार हैं।\n\nइस श्लोक में 'पार्थ' विशेषण का प्रयोग हुआ है। \"हम बुराइयों से दूर हो जाते हैं,\nयही संदेश है कि ज्ञान के मार्ग पर चलकर सच्चा जीवन जीना चाहिए\nविशेषण के पीछे है.\n\nदिव्य सम्पद विमोक्षय निबन्धाय 8सूरि माता |\nमा शुचः सम्पदं दैवीमभिजातोहसि पांडव",
  "16.5": "दिव्य सम्पत विमोक्षय निबन्धाय आसुरी माता |\n\nमा शुचः संपदां दैवीम अभिजातः असि पांडव - अच्छा आचरण ही मुक्ति का मार्ग है।\nबुरा तमस की कैद का रास्ता. विलाप मत करो, पांडव। आप सही रास्ते पर हैं\nजो आत्मसात हो गया हो।\n\nयह समझाते हुए कि हमें दैवी संपदा का उपयोग क्यों करना चाहिए, कृष्ण कहते हैं: “दिव्य\nधन मुक्ति की ओर ले जाता है, दुष्ट स्वभाव निर्वाण की ओर ले जाता है”। यहाँ कृष्ण हैं\nउन्होंने विशेष रूप से 'वी-मोक्ष' और 'नि-बंध' का उल्लेख किया है। वी-मोक्ष उनकी प्राप्ति के लिए है\n\nतदनुसार भिन्न-भिन्न स्थानों में व्यक्तित्व का विकास एवं मोक्ष। 'नि-बंध' का अर्थ संसार बंध नहीं है। यह मतलबी है\nबंधन एक ऐसा बंधन जो हमें अंधकार में ले जाता है।\n\nकृष्ण अर्जुन के बारे में कहते हैं: “तू दैवी संपदा का आदर्श अवतार है\nआप दैवी संपदा के घर, अपने स्वभाव और जिस परिवार में पैदा हुए थे, उसकी तलाश में पैदा हुए थे\nप्रभाव एक दूसरे के पूरक हैं, इसकी चिंता मत करो।\n\nद्वौ भूत्सर्गौ लोकेहस्मिन् दैव असुर एव च ​​|\n16\n\nद्वौ भूत्सर्गौ लोके अस्मिन् दैवः असुरः एव च ​​|\n\nदैवः विस्तारश प्रोक्तः असुरं पार्थ मे श्रृणु - इस ब्रह्मांड में दो प्रकार के जीव हैं:\nदैव [बुरा] और असुर [बुरा]। कार्रवाई का तरीका बताया और कहा,\nहे पार्थ, मुझ से उस दुष्ट की कथा सुनो।\n\nइस संसार में मूल रूप से दो प्रकार के मनुष्य हैं: वे जो ईश्वर की ओर चलते हैं\nदिव्य पथ पर चलने वाले और राक्षसी पथ पर चलने वाले जो भगवान से मुंह मोड़ लेते हैं। ये दो\nअब तक के अनुभाग में हमने दैवीय प्रकृति पर विस्तार से विचार किया है। हमारा आंतरिक और\nकृष्ण ने सामाजिक व्यवहार का विस्तृत वर्णन करने के बाद यहाँ आसुरी स्वभाव का व्यवहार-\nवह शब्दों के बारे में बताते हैं. इसके माध्यम से कृष्ण हमें बताते हैं कि हमें कैसा नहीं होना चाहिए\nबताता है.",
  "16.9": "असत्यम् अप्रतिष्ठम् ते जगत् औः अनिश्वरम् |\n\nअपरस्परा संबुतम् किम अन्यत कामहैथुकम - वह भगवान है जो यह सार्वभौमिक वास्तविकता है।\nवे कहते हैं कि यह कोई योगदान नहीं है [यह झूठ है]। यह ईश्वर में स्थित नहीं है [है]\nनहीं] कहते हैं. ऐसा कहा जाता है कि ऐसा कोई सर्वशक्तिमान नहीं है जो इसे नियंत्रित कर सके। क्रमशः एक से दूसरे\nमैं इस बात से सहमत नहीं हूं कि इसका जन्म हुआ. और क्या उनकी नजर में ये एक अलग तरह का मामला है. ये है\nवासना का दूध-मायाशस्का शिति।\n\nअसुर दो प्रकार के होते हैं. संसार के पास कोई सत्य नहीं है, संसार के पास कोई और प्रतिष्ठा नहीं है, संसार के पास और कोई प्रतिष्ठा नहीं है\nउनकी नास्तिक समझ है कि कोई ईश्वर नहीं है। संसार को सृजन-अवस्था-विनाश के अधीन करना\nवह जानता है कि कोई शक्ति (सत्य) नहीं है। इसलिए, वह ईश्वर रहित इस संसार का आधार है\nउनका तर्क है कि इस दुनिया को नियंत्रित करने वाला कोई भगवान नहीं है, सब कुछ एक भ्रम है। सृष्टि चक्र एक है\nउनकी मान्यता मुर्बताना का सिद्धांत है।\n\nअसुरों का दूसरा प्रकार यह है कि हम इस संसार में जो कुछ भी देखते हैं वह केवल हमारा भ्रम है\nअशक्त करने वाले। सिवाय इसके कि यह संसार हमारी इच्छाओं से विकसित हो रहा है\nउनका मानना है कि यह किसी दूसरी शक्ति का नहीं है.\n\nएतं दृष्टि मावष्टा भया अंतात्मानोल्ब बुद्धयः |\nप्रभावन्त्युग्रकर्मणः क्षय जगतोहितः ॥19॥\n\nएतं दृष्टिं अवस्ताभ्य हानि आत्मनः अल्पबुद्धयः |\nप्रभावन्ति उग्रकर्मणः क्षय जगतः अहितः - ऐसे रुख पर आधारित, विवेका\nखोये हुए बेवकूफ-जाति के कमीने। ऐसा कठोर कदम दुनिया को नष्ट कर देगा\n\nकारण बनेगा\n\nजो लोग बुरी मानसिकता विकसित कर लेते हैं वे अपने जीवन में दुख लाते हैं और खुद को नष्ट कर लेते हैं\nवे स्वयं इसका कारण बनेंगे। यह उनका विश्वास ही है जो उन्हें नष्ट कर रहा है, वे अंधकार हैं\nवे इस बात का एहसास किए बिना ही उग्रवादी (उग्रकर्मणः) बन जाते हैं कि वे रास्ते पर चल रहे हैं। इस का\nपरिणामस्वरूप, वे संसार के शत्रु बन जाते हैं और संसार के विनाश का कारण बनते हैं। इस प्रकार की मानसिकता है-\nहमारे बीच जो लोग हैं वे असुर हैं।",
  "16.19": "एतं दृष्टिं अवस्ताभ्य हानि आत्मनः अल्पबुद्धयः |\nप्रभावन्ति उग्रकर्मणः क्षय जगतः अहितः - ऐसे रुख पर आधारित, विवेका\nखोये हुए बेवकूफ-जाति के कमीने। ऐसा कठोर कदम दुनिया को नष्ट कर देगा\n\nकारण बनेगा\n\nजो लोग बुरी मानसिकता विकसित कर लेते हैं वे अपने जीवन में दुख लाते हैं और खुद को नष्ट कर लेते हैं\nवे स्वयं इसका कारण बनेंगे। यह उनका विश्वास ही है जो उन्हें नष्ट कर रहा है, वे अंधकार हैं\nवे इस बात का एहसास किए बिना ही उग्रवादी (उग्रकर्मणः) बन जाते हैं कि वे रास्ते पर चल रहे हैं। इस का\nपरिणामस्वरूप, वे संसार के शत्रु बन जाते हैं और संसार के विनाश का कारण बनते हैं। इस प्रकार की मानसिकता है-\nहमारे बीच जो लोग हैं वे असुर हैं।",
  "16.12": "आशापाशा शतैः बद्दः कामक्रोधपरायः।\n\nयह कामभोगार्थ अन्ययेन का अर्थसंचयन है--। सैकड़ों ख्वाहिशों में फँसा हुआ\nजो पकड़े गए हैं, जिन्होंने खुद को पागल जुनून के आगे बेच दिया है। बाजार को भुगतान करना गलत है\nजो लोग सड़क से राख के ढेर हटाना चाहते हैं।\n\nवे संतुष्टि की खातिर खुद को इच्छाओं के जाल में फंसा लेते हैं\nअपने आप को वासनापूर्ण क्रोध के लिए बेचकर, वासनापूर्ण क्रोध बनकर जी रहे हैं\nइसका एक अच्छा उदाहरण पौंड्रक वासुदेव हैं। उन्होंने कहा कि उन्हें स्वयं भगवान बन जाना चाहिए\nवासना'. इसी वासना के कारण उन दार्शनिकों पर क्रोध आता है जो इसे ग़लत कहते हैं।\n\nउन्हें अपने सुखों के लिए अन्यायपूर्ण तरीकों से धन इकट्ठा करना पड़ता है\nचारों ओर प्रयास किया। वे धर्मग्रंथों में लिखी बातों को अपने हिसाब से तोड़-मरोड़ कर पेश करते हैं\nस्वेच्छा से उपलब्धि में संलग्न रहता है।\n\nये मया लब्धामिमं प्रोप्स्ये मनोरथम्।\n\nइदमस्तिदमपि मेइ भैवति पुर्नराधनम्",
  "16.16": "अनेक चित्त विभ्रान्तः मोहजला समावृतः।\n\nवर्तमान समय में यौन इच्छा कम हो जाती है। नारके असुचौ - अनेक। विभिन्न विचारों से\nभ्रमित; मोह के जाल में फँसे हुए लोग; वासना में खोया हुआ. वे हैं\nगंदगी नरक में गिरती है और पीड़ा भोगती है।\n\nवे अपने जीवन की पिछली घटनाओं को याद करके हमेशा भ्रमित रहते हैं।\nउन्हें अपनी गलतियों पर कभी पछतावा नहीं होता। सात्विक पछताते हैं, पश्चात्ताप करते हैं\nसही है, लेकिन. वह सदैव भयानक अज्ञान-मामाकार से प्रेम करता है\nजाल में फंसकर वे और अधिक भ्रमित हो जाते हैं - स्थिर नहीं। वे चाहते थे\nचीजों में लिप्त रहना और उनसे संतुष्ट हुए बिना उन्हें संग्रहित करना\nउन्हें गंदे नरक में संघर्ष करना पड़ेगा।\n\nआत्मसम्भवितः स्वब्धा धन्मनमादन्वितः |\n\nयजन्ते नमयज्ञैस्ते दम्भेविधिपूर्वकम्",
  "16.6": "दैवी सम्पत् विमोक्षाय निबन्धाय आसुरी मता |\\n\\nमा शुचः सम्पदं दैवीम् अभिजातः असि पाण्डव - अच्छा आचरण मुक्ति का मार्ग है। बुरा आचरण तमस की बंधन का मार्ग। पाण्डव, शोक मत करो। तुम दैवी सम्पद के मार्ग पर चलने वाले हो।\\n\\nकृष्ण समझाते हैं: \"दैवी सम्पत्ति विमोक्ष की ओर ले जाती है, आसुरी स्वभाव निबन्ध की ओर।\" वि-मोक्ष अर्थात् साधना के अनुरूप विभिन्न स्तरों पर व्यक्तित्व विकास और मोक्ष। 'नि-बन्ध' नीचे की ओर खींचने वाला बन्धन है जो हमें तमस के अंधकार में धकेलता है।\\n\\nद्वौ भूतसर्गौ लोके अस्मिन् दैवः आसुरः एव च | दैवः विस्तरशः प्रोक्तः आसुरम् पार्थ मे श्रृणु - इस संसार में दो प्रकार की जीव-सृष्टियाँ हैं: दैवी और आसुरी। दैवी स्वभाव का विस्तार से वर्णन हो चुका है; अब पार्थ, मुझसे आसुरी स्वभाव का वर्णन सुनो।\\n\\nकृष्ण अब आसुरी स्वभाव वालों के आचरण का वर्णन करते हैं - ताकि हम जान सकें कि हमें कैसा नहीं होना चाहिए।",
  "16.15": "इदं अद्या मया लब्धं इमं प्रोप्स्ये मनोरथम्।\n\nइदं अस्ति इदं अपि मेइ भैवती पुर्नराधनम् ॥\n\nअसौ माया हतः शत्रुह हानिष्ये च आपा रन अपि।\n\nईश्वरः अहं अहं भोगी सिद्ध अहं बलवान सुखी॥\n\nअध्यो अभिजावन अस्मि कह अन्यः अस्ति सदृशः मया |\n\nयक्ष्ये दास्यामि मोदिष्ये इति अज्ञान विमोहिताः - उन्होंने अज्ञानतावश ऐसा कहा\nगरीब आदमी: मुझे यह अब मिल गया; ये ख्वाहिश आगे भी पूरी करूंगा; ये भी\nवहाँ है; फिर ये मेरा होगा; इस नफरत को मार डाला; बाकी भी ख़त्म कर दूंगा; मैं हूँ\nसर्वशक्तिमान; मैं भोगी हूं; मैं वह हूं जिसे वह सब कुछ मिला जो मैं चाहता था; शक्तिशाली और खुश;\nमैं बीमार हूं; मैं कुलीन हूँ; मेरी तुलना किससे की जाती है? मैं यज्ञ करूंगा. दान\nमैं दूँगा, मुझे खुशी है।\n\nइन तीन श्लोकों में कृष्ण हमें बताते हैं कि राक्षसों के विचार कैसे होते हैं\nसमझाया. विचार यह है कि उन्हें सदैव धन संग्रह करना चाहिए। जब उसे यह मिल गया, तो उसने कहा, “आज के लिए बस इतना ही\nसमझ गया, कल इतना कमा लूँगा।' पैसा इकट्ठा करना उनके लिए एक लत है. खुद को\nयह विचार कि जो नहीं बना उसे मैंने ख़त्म कर दिया, जो नहीं बनेगा उसे ख़त्म कर दूँगा। मैं सर्वशक्तिमान हूँ,\nमेरे कारण इस संसार में क्या है? मेरा जन्म खुश रहने के लिए हुआ है-दुखी होने के लिए नहीं; मेरी ख़ुशी के लिए\nमैं कुछ भी करूंगा; जो लोग इसे पार करेंगे उन्हें मैं ख़त्म कर दूँगा; मैं एक तैयार आदमी हूँ;\n\nमैं अपनी सफलता के लिए जिम्मेदार हूं; मेरा जन्म खुश रहने के लिए हुआ है, जन-धन-बल\nमेरे पास है; जैसी मेरी इच्छा. मेँ चलता हूँ; पैसे से कुछ खरीदा जा सकता है; मेरे लिए\nमिलान इस दुनिया में कौन है? - आदि उनके विचार. दिखावे के लिए एक बलिदान\nयज्ञादि करना और दान देना उनका नित्य कर्म है। यह अज्ञान का नृत्य है।\nवे नहीं जानते कि यह उनके विनाश का द्वार है। वही भव्यता, वही शुभता\n\nवे इस भ्रम में रहते हैं कि\n\nवेङ्गचित्तविभ्रान्त मोहजलसमावृतः |\nप्रसक्तः कामभोगेषु पतन्ति नरके*शुचौ",
  "16.23": "यः शास्त्रविधिम् उत्स ज्या वर्तते कामकारतः |\nनासः सिद्धिं अवाप्नो ति न सुखम्ना परम गतिम् - जैसा कि विज्ञान की सीमाओं से परे कोई पसंद करता है।\nचलने वाला सिद्धि प्राप्त नहीं कर सकता। वह खुश नहीं है; कोई अतिक्रमण नहीं है.\n\nहम शास्त्र की आज्ञा के बिना ईमानदारी से नहीं जी सकते। क्योंकि\nहमें इस बात का कोई एहसास नहीं है कि क्या सही है और क्या ग़लत है। हमें जो पसंद है वही सही है\nहमें पता चल जाएगा. शास्त्र वही हैं जो हमें समझ देते हैं। दुनिया में बहुत से\nहमारे कार्यान्वयन में तथ्यों को शामिल करने के लिए केवल इच्छाशक्ति और ईमानदारी पर्याप्त नहीं है।\nयह सही है या गलत इसका निर्णय करने के लिए शास्त्रों की आवश्यकता है। हम अपने अनुभव से\n\nसम्पूर्ण विश्व को समझा नहीं जा सकता। हमारी बुद्धि सीमित है, हमारा तर्क सीमित है, हमारा विवेक सीमित है\nसीमित, हमारी ईमानदारी सीमित है. इसलिए हमारे पास पूरी दुनिया का अनुभव सीमित है\nसत्य को जाना नहीं जा सकता. इस कारण प्रभु; वेदादि शास्त्र जो उन्होंने संसार को दिये; वह\nहम बुद्धिमान व्यक्ति हैं जो धर्मग्रंथों को समझते हैं और उस ईश्वर को जानते हैं जिसने हमें बताया है\nसच जानिए. अन्यथा कोई सिद्धि नहीं है.\n\nतस्माच्छस्त्रं प्रमाणं ते कार्यकार्यव्यवस्थितौ |\n\nहूँ\nज्ञातः शास्त्रविधानोक्तं कर्म कर्थुमिहरहसि",
  "14.17": "सत्वत् संजायते ज्ञानं राजसः लोबः एव च ​​|\nप्रमदा मोहौ तमसः भवतः अज्ञानम् एव च-सत्त्व का अर्थ है ज्ञान। रजस से\nकंजूसी बढ़ती है. तामसी विस्मृति, भ्रम और संभ्रम का कारण बनती है।\n\n“सत्त्वत् संजयते ज्ञानम्” – गीता की यह पंक्ति बहुत महत्वपूर्ण संदेश देती है।\nजब किसी इंसान के लिए ज्ञान बाकी सभी चीजों से ज्यादा महत्वपूर्ण है तो मैं इसके लिए कुछ भी कर सकता हूं।'\nयदि यह दृढ़ निर्णय है कि हम हारने के लिए तैयार हैं - तो हमें इसमें कोई संदेह नहीं है कि यह सत्त्वगुण है\nइसे पूर्ण चेतना के रूप में समझा जा सकता है। इसका अच्छा उदाहरण कठोपनिषद में आता है\nयम और नचिकेता के बीच यह संवाद:\n\nएततुल्यं यदि मन्यसे वरं वृनिष्ट विटं चिराजीविकं च |\n\nमहाभूमौ नचिकेतस्त्वमेधि कामनां त्वा कंभजं करोमि। 1-24 |\nये ये काम दुर्लभ मर्त्यलोकाय सर्वं कामनाश्चंदथा प्रथ्यस्व |\nइमा रामः सरथः शनिवार्य न हीद्रिशा लंभनिया मंशीनः |\nअभिरामतृत्तभि परिचरयस्व नचिकेताशो मरणं मननुप्रकाशे ॥1-25॥\n\nयहाँ जब नचिकेता ने यम से कहा कि \"मुझे आत्म-ज्ञान सिखाओ\": \"तुम भी युवा हो, वह।\"\nकोई शिक्षा नहीं. इसके बदले मैं तुम्हें पृथ्वी का सम्राट बनाऊंगा; आप चाहते हैं\nमैं इसे उपलब्ध कराऊंगा; मैं तुम्हें जीवन और धन दूँगा,'' जावरया कहते हैं। फिर\nनचिकेता कहते हैं:\n\nश्वोभव मर्त्यस्य यदन्तके तत् सर्वेन्द्रियहम जरायन्ति तेजः |\n\nअपि सर्वं जीवितमल्पमेव तवैव वहस्तव नृत्य गीते ॥1-26॥\n\nन वित्तेन तर्पणियो मनुष्यो लप्स्यमहे वित्तमद्रक्ष्म चेत्त्व |\nजीविष्यामो यावदिशिष्यसि त्वं वरस्तु मे वरानियः स एव ॥1-27॥\nअजीर्यातममृतानामुपेत्य जीर्यन्मर्त्यः क्वदस्थः प्रजानान |\nअभिध्यायं वर्णरतिप्रमोदं अतिदिर्फ़े जीविते को रामेता ॥1-28॥\nयस्मिन्निदं विचिकित्संति मृत्यो यत्सम्पराय महति ब्रुहि नास्तत् |\nयोका$यं वरो गूढ़मनुप्रविष्टो नान्यं तस्मान्नचिकेता वृनिते ॥1-29॥\n\n\"चाहे कितना भी दो, वह कम है। हमें चाहे कितना भी जीवन मिले, हमें एक दिन मरना ही है। इसलिए\nमुझे इसमें से कुछ भी नहीं चाहिए. भले ही तुम मुझे पूरी दुनिया दे दो, मुझे यह नहीं चाहिए। मुझे पता है\nवह मनोविज्ञान \"मुझे बताओ\" चाहते हैं। यह बिना किसी प्रलोभन के वास्तविक है\nसार: जो लोग वास्तव में ज्ञान के भूखे हैं वे सब कुछ खोने के लिए कैसे तैयार हो सकते हैं\nज्ञान के मार्ग पर चलने का एक अच्छा ताजा उदाहरण स्वामी राम (1925-) हैं।\n\n1996). उनकी जीवनी हमें \"61176 11 17ए 1111813)27 !185105\" पुस्तक में मिलती है।\nआप पढ़ और समझ सकते हैं. यदि हमें शास्त्र का सच्चा ज्ञान प्राप्त करना है तो भले ही हम शास्त्र पढ़ें, हमारे अंदर सात्विकता होनी चाहिए\nअ-कार वाच्य का ज्ञान तभी होना चाहिए जब सत्त्वगुण हो। सत्त्वगुण से परिपूर्ण\nजागृत होने पर हम सच्चे ज्ञान को जानते हैं और अन्य सभी सांसारिक चीजें ज्ञान हैं\nआगे शून्य का सच पता चलेगा.\n\"राजसो लोभ एव च\" - लालच राजसी का समर्पित गुण है (उह01651/आ 03/1)।  यह\nसात्विक में नहीं पाया जा सकता।  किसी वस्तु के प्रति वासना, वस्तु न मिलने पर क्रोध,\nजैसे ही पाओ - लोभ।  इसका न तो उपयोग किया जाता है और न ही दूसरों को दिया जाता है। दान\nयह उनके लिए बहुत दूर है! हमारे पास जो कुछ है उसे बांटकर हमें जीना चाहिए\nसार यह ईशोपनिषद में खूबसूरती से कहा गया है:\n\nईशावास्यमिदं सर्वं यत्किंच जगत्यं जगत् |\n\nतेन त्यक्षेन भुंजीथा मा गृधः कस्यस्विधानम् | 1\nभगवान हर चीज का भगवान है. उन्होंने जो दिया है उसका अनुभव अवश्य करना चाहिए। बिना धन के लिए\nइच्छा मत करो. वह प्रभु संसार की समस्त सम्पत्ति का स्वामी है। इसलिए उसने जो धन दिया है\nयह 'मेरा' है, यह सोचकर लालच में जीना ठीक नहीं है। लेकिन रजोगुण बहुत ही महत्वपूर्ण दोष है\nये लालच. यह दूसरों के प्रति करुणा के बिना है, उसने जो कमाया है उसे दूसरे को दिए बिना है।\nकभी-कभी तो यह बिना खाए भी छिप जाता है। एक ख़राब गुणवत्ता जो आमतौर पर जानवरों में नहीं पाई जाती\nये लालच. यदि हमारे अंदर लोभ का गुण है तो हम इसे रजोगुण जागरूकता कहते हैं\nजानना चाहिए\n“प्रमादमोहौ तमसो भवतोइग्नामेव च”। रजोगुण से कितना लोभी, ऐसा\nतमोगुण से मोह और मोह से उत्पात... अपने आप पर अति करना\nइसे गले लगाना, उनकी गलतियों को माफ करना, जैसा कि वे कहते हैं\nझुकना, आदि। यह इतना प्रभावशाली है कि - यह हमारे ज्ञान को भी ढक लेता है,\nहमें भटकाता है. इसका एक अच्छा उदाहरण भागवत का छठा स्कंद है\nप्रथम अध्याय में अजामिल की कथा आती है। वह सात्विक ब्राह्मण थे। वह शादीशुदा था.\nएक बार जब वह पूजा के लिए फूल और तुलसी लाने जंगल में गया तो उसके मन में एक दृश्य घूम गया\nगहरा असर हुआ. उसने जंगल में दिखी एक युवती को बहकाना शुरू कर दिया।\nउसने उसके लिए शराब-मांस का सेवन किया। उसने अपनी इच्छाएं पूरी करने के लिए चोरी की।\nजो सात्विक था वह विप्र-पूर्ण-तमसना बन गया। इस कहानी को मनोवैज्ञानिक दृष्टि से देखें तो- यह\nपता चल जाएगा कि घटना क्यों हुई। अजामिल शादीशुदा था, लेकिन उसका\nघर में लैप-मील की अनेक रस्मों के कारण वह अपने आप में अंतरंग है\n\nचाहत को जबरन दबा दिया गया. ऐसा तब होता है जब हम अपनी इच्छा को बलपूर्वक रोक लेते हैं\nएक दिन ये सामने आएगा. ऐसा शास्त्रों के अनुसार बताया गया है\n\"आध्यात्मिक उपलब्धि से पहले, यदि आपके मन में सांसारिक सुख की लालसा है, तो इसका अनुभव करें,\nअजामिल ने शास्त्र का अध्ययन तो किया था, परंतु उसे शास्त्र से प्रेम हो गया।\nइससे पीड़ित का सारा ज्ञान नष्ट हो गया। उसमें तमोगुण नहीं होना चाहिए\nगलती हो गयी. जब हमारे अंदर तमोगुण प्रबल होता है तो हम पर यही प्रभाव पड़ता है।\n\nइस श्लोक में कृष्ण स्पष्ट रूप से बताते हैं कि हमारे अंदर कौन से गुण काम कर रहे हैं\nसमझाया. इस श्लोक का सारांश इस प्रकार है: यदि ज्ञान की प्यास है, तो यह सात्विक गुण है; मैं इसे स्वयं चाहता हूं\nयदि यह लोभ हो कि बाकियों को न मिले, तो यह रहस्य है; कुछ भौतिक\nयदि अत्यधिक प्रेम और स्नेह है तो यह तमस का कार्य है।\n\nसत्त्व-रजसु-तमस के लिए। एक और चेहरा है. पूजा में नई ऊर्जाओं का जिक्र करने के बाद\nभगवान के पास जाने से पहले “सम सत्त्वय नमः-राम-रजसे नमः-तम तमसे।”\nनमः\" एक मंत्र कहता है। कुछ लोग इस मंत्र को इस प्रकार भी कहते हैं: “नहीं\nसत्त्वय श्रीयो नमः-राम राजसे भुवे नमः-तम तमसे दुर्गाय नमः।” [यह\nमंत्र नहीं, मूल मंत्र: \"सम सत्त्वय नमः -राम-रजसे नमः-तम तमसे नमः\" ] यहाँ\nसम सत्वाय नमः का अर्थ सत्त्वगुण को नमस्कार नहीं है - सत्त्व मानिनिया श्री देवी को।\nनमस्कार कहो। राम राजसे नमः का अर्थ है राजो मनिनिया की भू देवी को नमस्कार। श्रीमान\nतमसे नमः का अर्थ है तमो मनिनिया की देवी दुर्गा को नमस्कार। ये तीन लक्ष्मी हैं\nप्रपत्र. लक्ष्मी के मूल स्वरूप को 'महालक्ष्मी' कहा जाता है। इस मूल स्वरूप से तीन आवेश होते हैं\nप्रपत्र.\n\nयहां तो श्रीदेवी ही हैं जो सार जगाती हैं; भूदेवी रजस को जगाने वाली हैं;\nतमोगुण को जागृत करने वाली तमोगुणी की दुर्गा देवी हैं। “सत्त्वात् संजयते\nज्ञानम्”- इसका अर्थ है: सत्त्वगुण की प्रशंसक, लक्षि का, ज्ञानी है। नारायण का ज्ञान\nअगर आप आना चाहते हैं तो आपको श्रीदेवी की कृपा चाहिए. सब जानते हैं कि 'श्रीमान' धन देता है\nलेकिन ज्यादातर लोग यही सोचते हैं कि श्रीदेवी अथाह ज्ञान संपदा की दाता हैं\nज्ञात नहीं. हां, छोटा धन है, लेकिन ज्ञान एक महान धन है - इसे देने वाला 'श्री' ही है। हमारे भीतर\nयदि ज्ञान जागृत करना है तो सबसे पहले मां के श्री रूप की पूजा करनी चाहिए। प्रभु का\nउससे ज्ञान पर दया करने को कहा जाए.\n\nजैसा कि शास्त्री...कहते हैं...मन। ईश्वर की ओर प्रवाहित होना। पहले हम\nमनोमभिमानी की प्रार्थना करनी चाहिए। शिव.मनो$भिमानी देवता। [गरुड़-सुपर्णि, शेष-\nयद्यपि वारुणी और शिव-पार्वती मनोभिमानी हैं, विशेषतः शिव मनोभिमानी हैं।\n\nशिव वह हैं जो अंधकार को दूर करते हैं और ज्ञान चाहने वालों के मन को भर देते हैं।\nपार्वती. इस कारण हमें सबसे पहले ज्ञान के लिए प्रार्थना करनी चाहिए\nशिव तत्व. जब शिव ज्ञान देते हैं तो हम चाहते हैं कि वह मन में स्मृति के रूप में बना रहे\nप्राण शक्ति (ब्रह्म-वायु, सरस्वती-भारती) की प्रार्थना करनी चाहिए। ज्ञान जो हमारे पास आया है\nप्राण शक्ति (आंजनेय) वह मुख्य शक्ति है जो इसे अमोघ (स्थिर) बनाती है। इस तरह\nवह जो स्थिर है वह फिर ऊपर जाती है और भगवान को छूती है - हमेशा भगवान की\nसाथ में लक्ष्मी देवी. ऐसी लक्ष्मी अपने सभी रूपों में जागरूकता नहीं देती। वह उसकी है\nश्रीरूप में वह धन प्रदान करती है जो ज्ञान का रूप है। 'श्री' महालक्ष्मी के अवतारों में से एक है।\nयह वह रूप है जो सत्व पर शासन करता है और दुनिया की सुरक्षा के लिए विष्णु के साथ खड़ा है। इसलिए\nज्ञान के पथ पर चलने वालों के लिए लक्ष्मी का श्री नमक अनुग्रह महत्वपूर्ण है।\nयहां ज्ञान के मार्ग पर शिव, प्राणदेव और श्रीदेवी की कृपा से मृत्यु पहले होती है\nहमने विश्लेषण किया है कि कोई भगवान से जुड़ सकता है। भूतवा के बारे में आगे विश्लेषण करने से पहले\nआइए यहां शांति मंत्र और गणपति प्रार्थना के महत्व का संक्षेप में विश्लेषण करें। कोई भी\nधर्मग्रंथों का पाठ करने से पहले हम \"ओम शांतिः शांतिः शांतिः\" का जाप करते हैं।\nहे ज्ञान के शिखर भगवान, मुझे ज्ञान (शांति) के मार्ग में लगाओ।\nयही इस शांति मंत्र का अर्थ है. इसी प्रकार हर पूजा में सबसे पहले गणपति की प्रार्थना होती है\nक्योंकि शिव-पार्वती के पुत्र गणपति आकाश के देवता हैं। यह आकाश प्रभु का है\nनाभि से निर्मित. तो गणपति हमारे नाभि देवता हैं।\n\nनाभ्य असीदन्तरिक्षं शेष्नो द्यो संवरथा\n\nपद्भ्यं भूमिर दिश श्रोत्रथ तत् लोक अकल्पयन\nहमारी नाभि के पास तीन चक्र हैं मूलाधार, स्वाधिष्ठान और मणिपुर।\nनाभि से ऊपर की ओर हृतकमल में वास्तविक उपलब्धि का शाश्वत चक्र है। नींव,\nयदि आप स्वाधिष्ठान और मणिपुर चक्र, नाभि द्वार से परे हृदय में प्रवेश करना चाहते हैं\nगणपति को खोलना चाहिए. इसके लिए हम सबसे पहले गणपति से प्रार्थना करते हैं। प्रति\nयज्ञ से पहले गणपति मंडल को लिखें और पूजा करें, फिर यज्ञ शुरू होता है। गणपति की नाभि\nजब दरवाज़ा खुलता है तो दिल अपने आप खुल जाता है। इस स्थिति को 'वृषः' कहा जाता है।\nइस अवस्था में भगवान हमारी पूजा को वर्षा के रूप में स्वीकार करते हैं। ऐसे प्रभु\nइसे 'वृषही' के नाम से भी जाना जाता है।\n\n\"रजसो लोभ एव च\" - राजस्सु का अर्थ है भूदेवी जो रजोगुण की प्रशंसक है। यहाँ भूदेवी\nवह अठारहवीं कक्षा का देवदूत नहीं है जो पृथ्वी पर शासन करता है। उस पर भी राज करो\n\n'पृथ्वी' लक्ष्मी का अवतार है। उसी से सृजन हुआ। मनोरंजन, आकर्षण, आकर्षण, आकर्षण -\nये सभी रजोगुण के मुख हैं। तो मूलतः एक दूसरे से प्रेम करना\nवांटेड-रंजन. स्त्री-पुरुष का आकर्षण ही सृष्टि का कारण है। सृजन को आवश्यक आक्षेप दें\nरजोगुण में समान आक्षेप उत्पन्न करने और उससे विमुख करने का तत्व होता है। ऐसा है रजोगुण\nभूदेवी प्रकृति की दाता हैं। मेरी संपत्ति, मेरा घर, मेरा काम, मेरा पैसा, आदि\nयह रजोगुण से आता है।\n\n\"प्रमदा मोहौ तमसः भवतः अज्ञानम् एव च\" - हमें शारीरिक रूप से नष्ट करने के लिए।\nधारण-संहारक शक्ति, तमोगुण की उपासक..दुर्गा। वह वध की ओर अग्रसर है\nवह जाने की सलाह देती है. गलत को सही जानकर गलत करना, उससे बचना\nपतन, ज्ञान की अधिकता, ज्ञान का अभाव आदि तमोगुण के प्रभाव के कारण होते हैं।\nइस प्रकार। श्री-भू-दुर्गा, सत्व-रजसु-तमस्सिना चित्रकला के तीन तत्व हैं।\nप्रशंसकों के रूप में, हम त्रिगुणों से बंधे हैं। इसलिए चित्रकला की भावना\nतीन रूप सत्त्व-रजसु और तमस्सु हैं। [यहाँ यह अर्थ क्यों करना चाहिए?\nगाने में ही एक सुराग है. इसे आगे इस अध्याय के 19वें श्लोक में देखा जा सकता है। महालक्ष्मी\nश्री-भू-दुर्गा के स्वरूप के बारे में अधिक जानकारी के लिए महाभारत तात्पर्य देखें\n\"सर्गानुसर्ग-लय-प्रादुर्भाव निर्देश\"] पढ़ें।\n\nऊर्ध्वं गच्छन्ति सत्त्वस्थ मधे तिष्ठन्ति राजसः।\n\nजघन्यागुणवृत्तस्थ अधो गच्छन्ति तमसाः",
  "15.20": "इति गुह्यतमं शास्त्रमिदमुक्तं मयाऽनघ ।\nएतद्बुद्ध्वा बुद्धिमान्स्यात्कृतकृत्यश्च भारत ॥\n\nअनघ — निष्पाप अर्जुन को — गुह्यतम शास्त्र कहा। शास्त्र सड़क पर उद्घाटित नहीं करना — जिसमें ग्रहण की योग्यता, रुचि, श्रद्धा, भक्ति हो उसी को कहना।\n\nक्षर-अक्षर-पुरुषोत्तम का त्रित्वज्ञान — यही समस्त शास्त्र का सार है। इसे जानकर — बुद्धिमान् बनता है — वेदार्थज्ञ; कृतकृत्य — जिसका कर्तव्य पूर्ण हुआ। भगवद्ज्ञान ही जीवन की सार्थकता है।\n\nइति पञ्चदशोऽध्यायः — पुरुषोत्तमयोगः।",
  "17.2": "भगवान उवाच - भगवान ने कहा:\nत्रिविधा भवति श्रद्धा देहिनं स सभावजा।\nसात्विकी राजसी च एव तमसे च इति तम श्रृणु - यह जो जीवित प्राणियों के स्वभाव से उत्पन्न होता है।\n\nआस्था तीन प्रकार की होती है: सात्विक, राजस और तमस। इसके बारे में सोचो.\n\nसाधना शरीर में जीव मूलतः तीन प्रकार के होते हैं। यह सात्विक, राजस है\nऔर तमस. इस पर हम फिर से पर्यावरण और परिवार से मनोवैज्ञानिक रूप से प्रभावित होते हैं\nहम तीन गुना परिश्रम का उपयोग करते हैं। अतः वह स्वभाव से सात्विक होते हुए भी सात्विक है\nमानसिक रूप से यह राजसिक या तामसिक हो सकता है। उदाहरण के लिए प्रारूप द्वारा\nगर्गाचार्य, जो सात्विक थे, को एक ऐसा पुत्र पैदा करना चाहिए जो तमस के प्रभाव में कृष्ण को हरा दे\nहमने तपस्या की कहानी देखी है. मानसिक रूप से आने वाला यह बाह्य प्रयास ही जन्म है\nजन्म से नहीं. लेकिन स्वरूपा श्रद्धा हर जन्म में जीवन के साथ रहती है। यह\nस्पष्टीकरण के लिए इस श्लोक में 'इवा' और 'चा' का एक साथ प्रयोग किया गया है।\nसात्विकेवा, राजसेवा या तमसेवा - यह नहीं बदलता है। इस प्रारूप के लिए बाहरी\nश्रद्धा- सात्विकेचा, राजसेचा, तमसेचा-प्रभाव से अधिकतम एक जन्म तक आती है।\nसमर्पित। कृष्ण ने अर्जुन से कहा, \"इन तीन प्रकार की भक्ति के बारे में सोचो।\"\nकहते हैं\n\nसात्वनुरूपा सर्वस्य श्रद्धा भवति भारत।\n\nश्रद्धामयो$यं पुरुषो यो यच्चधाः सवेसः",
  "17.5": "कर्षयन्तः शरीरशथं भूतग्राममचेतसः |\nमाम् चैवंतः शरीरस्थं तं विध्वा सुरनिश्च यन्",
  "16.21": "त्रिविधं नरकस्य इदं द्वारं नाशनं आत्मानः |\nकामः क्रोधः तथा लोभः तस्मात् एतत् त्र्यम् त्यजेत - ये आत्मा के नाश के तीन मार्ग हैं,\nनरक के द्वार: वासना, क्रोध और लालच। इसलिए इन तीनों से बचना चाहिए।\n\nयह श्लोक एक बहुत ही महत्वपूर्ण संदेश देता है। यह श्लोक विदुरनीति में भी है\nमहाभारत में इसका सामाजिक एवं आध्यात्मिक दृष्टि से उल्लेख मिलता है। यहाँ कृष्ण हैं\nउन्होंने आत्महत्या की ओर ले जाने वाले तीन कारकों के बारे में बताया। ये हैं काम-क्रोध-लोभ।\nकृष्ण कहते हैं, ये \"मानव नरक के द्वार\" हैं। क्रोध वासना की संतान है. हम गुस्से में हैं\nआने का मतलब है कि हमारे अंदर कई इच्छाएं अंतर्निहित हैं। हमारे लिए जब यह पूरा नहीं होता\nक्रोध महाभारत के अनुशासन पर्व में एक कथा है। एक ब्राह्मण स्त्री; उसका नाम है\nगौतमी. उसका एक ही बेटा है. एक दिन साँप के काटने से उसकी मृत्यु हो जाती है। एक एयरमैन को यह मिला,\nकूनेले ने उस सांप को पकड़ लिया और उसके सामने लाई: “मुझे बताओ, इस सांप ने तुम्हारे बेटे को काट लिया और उसे मार डाला\n\"तुम्हें कैसे मारना पसंद है?\" वह पूछता है. फिर वह कहती है: “नहीं\nब्राह्मणानं कोपोइसति कृतः कोपचा च यतना...\" 13-01-20|. \"हम ब्राह्मण हैं,\nब्राह्मण क्रोध नहीं करता, यदि क्रोध करता है तो वह ब्राह्मण नहीं है।” साँप को मारने से मुर्दा\nबेटा दोबारा जीवित नहीं रह सकता. मेरे पुत्र की मृत्यु उसके कर्मों के अनुसार हुई। क्योंकि क्रोध दुःख नहीं लाता,\n\"उस साँप को छोड़ दो,\" उसने कहा। जिनके पास यह समझ है, उनके पास कोई इच्छा-क्रोध नहीं है\nनहीं आता वह सच्चा ब्राह्मण है। \"काम-क्रोध-लोभ ने हमें इससे छुटकारा दिलाया\nनरक के तीन द्वार जो विनाश की ओर ले जाते हैं, उनसे दूर रहें, ”कृष्ण ने हमें यहां बताया\nचेतावनी दी. ये वे मूल शत्रु हैं जो हमारे व्यक्तित्व को नष्ट कर देते हैं। अन्य सभी विकार\nउनके युवा. मनुष्य इन तीन विकारों से अपना नरक स्वयं निर्मित करता है। यह\n\nतीन के अलावा इसमें भी सुख है और सुख-परा में भी।\n\nएतैरविमुक्तः कौन्तेय तमोद्वारैस्टिभिर्नरः |\nअचरत्यात्मनः श्रेयस्ततो याति परमं गतिम्।",
  "16.17": "आत्मसम्भावितः स्वभावः धन मनम मद अन्विताः |\n\nयजन्ते नमयज्ञैः ते दंभेन अविधि पूर्वकं- जो स्वधर्मी है। सिरी\nजो मान-सम्मान के अहंकार से बंधे हैं। वे यज्ञ भी करते हैं: पाखंडपूर्वक, वैज्ञानिक ढंग से\nक्रम टूट गया.\n\nउन्हें खुद पर गर्व है. “अविद्यायां अंतरे वर्तमानमनः स्वयं धीरा पंडितम्\nमैं नहीं जानता कि बाकियों के मन में उनके लिए सम्मान है या नहीं, लेकिन अपने लिए\n\nवह आत्म-महत्व का ज्ञान विकसित करता है और उससे डरता है। उनके इस बिगुमना के लिए\nइसका कारण ज्ञान नहीं, बल्कि हाथ में पैसा है; जो सम्मान लोग उन डुग्गीगोस्करों का करते हैं. वह है\nपाखंड के लिए, वैभव प्रदर्शन के लिए-बलिदान किए जाते हैं। विज्ञान है\nजागरूक नहीं; प्रभु को प्रसन्न करने के इरादे के बिना, प्रभु को भूल जाओ\nवही पूजा होगी.\n\nअहंकारं बलं दर्पं कामां क्रोधं च संमृतः |\n18.\n\nअहंकारं बलं दर्पं कामां क्रोधं च संमृतः |\n\nमम आत्मा परदेहेषु प्रद्विशान्तः अभ्यसूयः - इच्छा, बल, अहंकार, अभिलाषा,\nक्षोभों का निवास. जो लोग अपने और दूसरों के शरीर में मुझ पर विश्वास नहीं करते और इसका खंडन करते हैं।\nजो लोग दूसरों की समृद्धि से उत्साहित होते हैं।\n\nइनके मूल गुण अहंकार, लोभ, वासना और क्रोध हैं। कौन मुझसे आगे निकल सकता है?\nयह अभिमान कि मैं बड़ा आदमी हूं। इसे धन और शक्ति का समर्थन प्राप्त है। इससे\nदारपा दूसरे की ओर देखता है। किनारे की ख्वाहिशें, पूरी न होने का गुस्सा-\nयही उनका अस्तित्व है. कृष्ण कहते हैं: “वे हर किसी के भीतर ``मैं'' को नकारते हैं।\nयह किसी कारण से अस्थायी तौर पर ईश्वर को नकारना नहीं है, बल्कि प्रकृति को नकारना है\nईश्वर को नकारना. ये लोग हमेशा दूसरों के ज्ञान और धन पर नजर रखते हैं\nवे ईर्ष्यालु हैं.\n\nइस प्रकार कृष्ण ने राक्षसी लोगों की प्रकृति, उनके विचारों, उनके व्यवहार को अच्छी तरह से समझा\nवर्णित है भगवान श्रीकृष्ण ऐसे राक्षसी लोगों का क्या करेंगे? उनकी गति क्या होगी?\nवह उसका वर्णन करता है।\n\nतनाहं दविषतः क्रूरं संसारेषु नराधमन् |\n\n19.\n\nतं अहम् दविषतः क्रूरं संसारेषु नारा अधमन्।\n\nक्षेपमि अजस्रम् अशुभं आसुरीषु एव योनिषु - परतत्व से घृणा करने वाला, निर्दयी।\nमैं निरंतर अँधेरे में रहता हूँ, ऐसे नीच मनुष्य\nमैं नालों में टूट जाऊंगा.\n\nईश्वर जीवन नहीं बनाता; जीवन का सार और जीवन का स्वरूप शाश्वत है\nहम पहले से जानते हैं. असुराई प्रकृति मूलतः जीवन प्रकृति है। कैसा करेला\nइन आसुरी लोगों का जीवन स्वभाव तमस है। भगवान इसे नहीं बदलेगा. इसके बजाय\nजीवन की गति जीवन की प्रकृति के अनुसार निर्मित होती है। जो प्रभु से बैर रखते हैं,\nईश्वर इन क्रूर लोगों का एक निरंतर परिवार है जो मानव जाति से नफरत करते हैं, जो दुनिया से नफरत करते हैं\nवह उसे समुद्र में डाल देता है। इससे उन्हें दोबारा गरीब परिवार में जन्म लेना पड़ेगा।\n\nआसुरीम योनिमापन्ना मुधा जन्मनिजमानी |\nमावप्रापयिव कौन्तेय ततो यन्त्यधामं गतिम्",
  "17.1": "अर्जुन उवाच- अर्जुन ने पूछा:\n\nये शास्त्रविधिम् उत्सा ज्य यजन्ते श्रद्धया अन्वितः |\n\nतेषाम् निष्ठा तु का कृष्ण सत्त्रं अहो राजः तमः - भले ही कुछ लोग शास्त्र के आदेशों को नहीं जानते हों।\nवे विश्वास से चलते हैं. कृष्ण उनका निवास स्थान क्या है? सत्त्व, रजसे या\nक्या आप हैं?\n\nहमने वेदों का अध्ययन नहीं किया है, हम शास्त्र के विधान को नहीं जानते, बल्कि इसलिये कि हम शास्त्र को नहीं जानते\nपछतावा है; शास्त्र के प्रति समर्पण है, उसके अनुसार जीने की चाहत है। जो जानते हैं\nकहते हैं: \"यदेव विद्याया करोति श्रद्धेय..'' अर्थात \"जो कुछ भी करो, सोच-समझकर करो।\nज्ञान से किया गया कर्म सफल होता है। अन्यथा यह व्यर्थ है।” जब कोई ऐसा हो\nक्या मेहनत व्यर्थ है? यह अर्जुन का प्रश्न है.\n\nयहां \"श्रद्धा\" का अर्थ है- उस अदृश्य शक्ति के बारे में जो पारलौकिक होने के कारण हमें नियंत्रित करती है\nहमारा जो विश्वास है. अर्थ: ईश्वर में विश्वास, शास्त्र में विश्वास, पाप-पुण्य\nविश्वास वह विश्वास है कि एक सर्वोच्च शक्ति है जो सब कुछ नियंत्रित करती है। जैसा कि महाभारत कहता है:\n'कर्म का फल अवश्य होता है। विश्वास ही मानव जीवन का आधार है...जबकि यही बात है\nआस्था के साथ ईमानदारी हो और विज्ञान की समझ न हो तो उनकी जगह क्या है? “सभी को ट्रैक करो\nकर्ता (कृष्ण) ऐसे लोगों को कहाँ घसीटते हो? उनकी निष्ठा सात्विक है,\nराजस या तमसा?” अर्जुन, आप सभी के इस भ्रमित करने वाले प्रश्न पर\nकृष्ण पूछते हैं।\nभगवान का वचन\nत्रिविधा भवति श्रद्धा देहिनं स सभावजा।\n\nसात्विके राजसी चैव तमासे चेति तम श्रृणु",
  "16.22": "एतैः विमुक्तः कौन्तेय तम; द्वारैः त्रिबिः नाराः।\n\nअचरति आत्मानः श्रेयः ततः याति परम गतिम्-। कौन्तेय, भाड़ में जाए ये तीन\nगेट से भागकर, नारा वह करने में सक्षम हो जाता है जो उसके लिए अच्छा है। उससे\nवह भी बेहतर हो जाता है.\n\nमानव मेधावी आत्मा नरक के इन तीन द्वारों से बच निकली। वह मोक्ष का मार्ग है\nचिकना हो जाता है. उसे अच्छी गति मिलती है. यहां कृष्ण का अर्थ है 'मुक्त'\nइसका अर्थ सभी इच्छाओं, रजस को त्यागना नहीं है जो हमारे जीवन का अभिशाप है\nऔर तमस का अर्थ है इच्छाओं का त्याग करना। उदाहरण के लिए व्यक्ति को प्रभु से जुड़ना चाहिए\nवह एक इच्छा है. यह नरक का द्वार नहीं है. इसे छोड़ने की कोई जरूरत नहीं है. वासना के बिना कोई जीवन नहीं है.\nइसलिए यहां हमें केवल राजस और तमस पहलू को छोड़ना होगा। यह\nयह सुझाव देने के लिए 'मुक्त' के बजाय 'वी-मुक्त' कहता है।\n\nयहाँ 'काउंटी' विशेषण का प्रयोग हुआ है। “अगर हमें ज्ञान के पथ पर आगे बढ़ना है\nसंदेश एक काउंटेस बनने का है जो इस बुरी वासना-क्रोध-लोभ से घृणा करती है।\nइस विशेषण के पीछे की ध्वनि.\n\nहममें से कुछ लोगों को शास्त्र की कर्मकांडीय पद्धति की आवश्यकता क्यों है, क्या आत्म-साक्षी द्वारा जीना पर्याप्त है? सवाल यह है\nअगले श्लोक में कृष्ण शास्त्र के अनुष्ठानों के पालन के महत्व को बताते हैं।\n\nयः शास्त्रविधिमुत्स ज्य वरते कामकारतः |\nनासा सिद्धिमवाप्नोति नासुखम्ना पारंगतिम्",
  "17.3": "सत्व अनोरूपा सर्वस्य श्रद्धा भवति भारत।\n\nश्रद्धा मयाः अयं पुरुषः यः यत् श्रद्धा सः एव सः - भारत, सबकी प्रकृति के अनुसार\nआस्था भी है. यह जीवन आस्था का स्वरूप है। वह वही है जो उसका विश्वास है।\n\nजीवन के स्वभाव के अनुसार मूल भक्ति है। लेकिन कई बार ये व्यक्त नहीं हो पाता\nहो सकता है जब यह प्रकट न हो तो मन में जो भी बाहरी प्रभाव सक्रिय हो वह उसका हो\nविश्वास करना. मनुष्य ईमानदारी की कठपुतली है. जिसकी भक्ति का स्वरूप सात्विक है, वह सात्विक है;\nजिसकी भक्ति का स्वरूप राजस है, वह राजस है; जिसकी भक्ति का स्वरूप तमस है वह तमस है।\nतो जीव तीन प्रकार के होते हैं: सात्विक भक्ति वाला जीव - सात्विक जीव; राजस श्रद्धा का जीवन-\nराजसा जीव; तमसा जीव जिसमें श्रद्धा है - तमसा जीव। हम अभी भी ध्यान के साथ मन,\nजब तूरी अवस्था आ जाती है तो बाह्य श्रद्धा लुप्त हो जाती है और केवल स्वरूप श्रद्धा प्रकट होती है।\n\nयजन्ते सात्विका देवं यक्षारक्षणसि राजसः।\n\nप्रेतं भूतागहमश्च न्ये यजन्ते तमसा जनः",
  "15.15": "सर्वस्य चाहं हृदि सन्निविष्टो मत्तः स्मृतिर्ज्ञानमपोहनं च ।\nवेदैश्च सर्वैरहमेव वेद्यो वेदान्तकृद्वेदविदेव चाहम् ॥\n\n'सर्वस्य च अहम् हृदि' — भगवान् 'अहम्' शब्द-वाच्यरूप से सबके हृदय में सन्निविष्ट हैं। बाहर का रूप 'अहः', भीतर का 'अहम्'। स्मृति, ज्ञान, अपोहन (विस्मृति) — सब मुझसे।\n\n'वेदान्तकृत्' — ब्रह्मसूत्र, जो समग्र वेद का निर्णय है — उसका कर्ता मैं हूँ। 'वेदान्त' = उपनिषत् ही नहीं, 'वेद का अन्तिम निर्णय' = ब्रह्मसूत्र।\n\nभागवत उद्धवगीता में — 'माम् अभिधत्ते, माम् विधत्ते — एतावान् सर्ववेदार्थः।' वेद का प्रत्येक शब्द भगवान् को ही कहता है। मध्वाचार्य — 'सर्वप्राणिहृदिस्थाय वामनाय नमो नमः।'",
  "16.20": "असुरिम योनिम अपन्ना ह मुदः जन्मनिजमानी |\nमम अप्राप्य एव कौन्तेय ततः यन्ति अधमं गतिम्-कौन्तेय, कदुनदेय\nवे कमीने जो झाड़ियों में फिर से पैदा हुए थे, आख़िरकार वहाँ से फिर मेरे साथ नहीं आए\n\nअपमानित हो जाओ.\n\nइस प्रकार बुरे कुल में जन्म लेने वाले ये दुष्ट लोग हर जन्म में अंधे ही बनते हैं\nहर जन्म में भगवान के प्रति उनकी नफरत चरम सीमा पर पहुंच जाती है। अभिमान,\nमदा, दर्प, काम क्रोध अत्यधिक होते हैं और वे स्वयं भ्रष्ट हो जाते हैं। इनमें से कोई भी नहीं\nप्रभु का नहीं है. वह अपने जीवन की गति के अनुसार तमसलोक है\n\nशामिल हो जायेंगे\n\nकृष्ण ने राक्षसों के जीवन स्वभाव, उनके आचरण, वाणी, विचार और क्रियाकलापों की सुन्दर व्याख्या की।\nतो हमारे पास दुनिया में लोककंटक क्यों हैं? उन्हें आगे क्या गति मिलती है?\nविचार समझ में आ गया. हम जानते हैं कि हमारे बिना कब आसुरी गुणों का आक्रमण हम पर होता है\nयह अध्याय हमें जागरूकता और इससे मुक्त होने की इच्छा के साथ भगवान को पुकारने में मदद करता है।\nजीवन का स्वभाव कभी नहीं बदलता. जीवन का कोई स्वतंत्र लेखकत्व नहीं है। लेकिन जीने को तैयार हूं\nएक काम है. तदनुसार, एक निरंतर दिव्य प्रकृति - भगवान के प्रति लगाव - को विकसित करके\nहमें प्रयास करना होगा. यह प्रभु की इच्छा है कि वह फल लाए - हम इसी लिए हैं\nपरेशान मत होइए. जो अच्छा है उससे प्यार करो, जो अच्छा है उसमें संतुष्ट रहो। आपका\nसुरक्षा का भार प्रभु का है, वह आपकी रक्षा करेगा और आपकी रक्षा करेगा।\n\nत्रिविधं नरकस्येदं द्वारं नाशनमात्मनः |\nकामः क्रोधस्थथा लोभस्तसा, देतत् त्रयं त्यजेत्",
  "15.1": "ऊर्ध्वमूलं अधःशाखं अश्वत्थं प्राहुरव्ययम् ।\nछन्दांसि यस्य पर्णानि यस्तं वेद स वेदवित् ॥\n\nअश्वत्थ — संसार का प्रतीक। ऊर्ध्वमूल — ऊपर भगवान् और लक्ष्मी मूलकारण। अधःशाखा — ब्रह्मा से लेकर जीव-जड तक का तारतम्यक्रम। छन्दांसि पर्णानि — वेद इस वृक्ष के पत्ते हैं, फलप्रद और नित्य।\n\n'अश्वत्थ' के तीन अर्थ — (१) चलदल: सदा परिवर्तनशील संसार; (२) न श्वः तिष्ठति: क्षणिक जगत्; (३) आशु-वा-तथ: सर्वातिगामी भगवान् 'अश्व'नामक, जो हयग्रीव रूप में समस्त विद्या के दाता हैं।\n\n'अव्ययम्' — एक-एक लहर क्षणिक है, पर सागर में लहरों का प्रवाह नित्य है। इसी प्रकार एक संसार नष्ट होता है, दूसरा उत्पन्न होता है — संसारप्रवाह अव्यय है। इस अश्वत्थस्वरूप को जो जानता है, वह समस्त वेद का ज्ञाता है — क्योंकि सभी वेदशब्द मूलतः भगवन्नाम हैं।",
  "17.12": "अभिसन्धाय तु फलं दम्भ अर्थं अपि च एव यत् |\nइज्यते भरतश्रेष्ठ तम यज्ञं विद्धि राजसम - हे भरतश्रेष्ठ, फल की इच्छा से या\nपाखंड के लिए किया जाने वाला यज्ञ राजस कहलाता है।\n\nस्वार्थवश विशेष फल की चाह से, कपट भाव से किया गया यज्ञ राजस यज्ञ है\nऐसा प्रतीत होता है कि यदि हमें भगवान से जुड़ने के लिए कोई यज्ञ करना है तो उसे भक्ति भाव से करना चाहिए।\nहमें भगवान के प्रति समर्पित लोगों में सबसे महान (भरतश्रेष्ठ) के रूप में कार्य करना चाहिए। इसके बिना प्रमोशन के लिए\nकिया गया यज्ञ राजस यज्ञ बन जाता है।",
  "17.10": "यथायमं गतरसं पुति पर्युषितं च यत् |\nउच्छिष्टम अपि च अमेध्यं भोजनं तमसा प्रियम् - यह तमसारि का पसंदीदा व्यंजन है: अत्तु\nबासी, बेस्वाद, बासी, बासी, बचा हुआ और गंदा।\n\nतमसारि के लिए जीवन में सबसे बड़ी चीज भोजन है। वह भगवान का भोजन है\nवे बिना समर्पण के उपभोग करते हैं। नीरस, बासी, दुर्गंधयुक्त, बेस्वाद भोजन\nतमसारी को यह पसंद है. उन्हें बचा हुआ खाना बहुत पसंद है. [उदाहरण के लिए एक ही प्लेट पर कई\nलोग बचा हुआ खाना बाँटकर खाते हैं]।\n\nइस प्रकार भोजन से किसी व्यक्ति की पहचान कैसे की जा सकती है, इसकी विधि भी कृष्ण ने आगे बताई\nवह हमारे अनुष्ठानों (यज्ञ, तपस्या, दान) के माध्यम से व्यक्ति के स्वभाव को जानने की विधि बताते हैं।\n\nअफलाकांक्षि भिर्यज्ञो विधिदृष्टो ये इज्यते |\nयष्टा व्यामेवेति मनः समाधाय स सात्विकः",
  "17.17": "श्रद्धया पराय तपं तपः तत् त्रिविधं नारैः |\nअपला आकांक्षिभिः युक्तेः सात्विकं परीक्षते - ये तीन प्रकार के तप श्रद्धा से परिपूर्ण हैं,\nइसे सात्विक तप कहा जाता है जब इसे फल की इच्छा किए बिना ईश्वर की भक्ति के साथ किया जाता है।\n\nयदि किसी तप के पीछे अत्यधिक लगन हो तो वह सात्विक तप है। प्रभु का\nसब कुछ परमेश्वर की जागरूकता के साथ किया जाता है, इस इरादे से कि भगवान को प्यार किया जाएगा\nक्रिया- सात्विक क्रिया। उदाहरण के लिए, जब किसी गुरु को प्रणाम किया जाता है, तो वह गुरु का होता है\nअनुसन्धान कि मैं अन्तर्निहित भगवान को प्रणाम कर रहा हूँ। इस प्रकार हम में से प्रत्येक\n\nकर्म के पीछे भगवदर्पण बुद्धि होनी चाहिए। मन्त्र यही कहते हैं. “हे प्रभु\nजब हम गोपालकृष्ण प्रियतः-श्रीकृष्णार्पणमस्तु कहते हैं, तो हमारा भी पूर्ण समर्पण होता है\nभावना से भरपूर होना चाहिए. ऐसा तप सात्विक तप है।\n\nसत् करामाणपूजर्थं तपो दम्बेण चैव यत् |\nक्रियते तदिहा प्रोक्तं राजसं चलमधुवम्",
  "17.13": "विधिहीनं अश्रृष्टा अन्नं मंत्र हीनं दक्षिणम्।\nश्रद्धा विरथिम् यज्ञं तमसं परीचक्षते शास्त्र सम्मत नहीं है; कोई भोजन दान नहीं; कोई मंत्र नहीं है;\nकोई दक्षिणा नहीं; करने में कोई आस्था नहीं है. ऐसा यज्ञ तामस कहलाता है।\n\nमंत्र का गलत उच्चारण, क्रम से मंत्र का उच्चारण, शब्द उच्चारण\nक्या सही नहीं है- ये सब नाजायज हैं. इस प्रकार किया गया यज्ञ तामसी यज्ञ है। कोई भी\nयज्ञ में भी इसी प्रकार मूर्ति और अग्नि के माध्यम से पूजा की जाती है\nमूर्ति पूजा का बहुत महत्व है. भोजन देने से यह सबके अंदर है\nभगवान की पूजा इस चारमूर्ति की पूजा है। इस प्रकार अन्नदान, दक्षिणा के बिना (वैदिकों के लिए उनका जीवन)।\n(जो सेवा हम भरण-पोषण के लिए करते हैं) उसके बिना किया गया यज्ञ तामस यज्ञ है। इन सब से ऊपर\nपरिश्रम ही कुंजी है. भगवान के प्रति अटूट सर्वोच्च भक्ति के बिना किया गया कोई भी कार्य\nएक यज्ञ होने दो—यह हर जगह एक तमस यज्ञ बन जाता है।\n\nभोजन और यज्ञ के बाद, कृष्ण निम्नलिखित श्लोक में तीन प्रकार की तपस्या बताते हैं।\nतप मूलत: तीन प्रकार के होते हैं। हमारे आचरण में अनुशासन लाना-तपस्या;\nगहन विचार-तपस्या; मन की शुद्धि के लिए तपस्या भी एक शारीरिक दंड है। तपस्या करना\nजंगल जाने की जरूरत नहीं. आप घर पर ही तपस्या कर सकते हैं। सात्विक, राजस और तमस\nतपस्या की व्याख्या करने से पहले यहां कृष्ण के तीन मूल तत्व शरीर, वाणी और मन हैं\nअगले तीन श्लोकों में वे तपस्या की व्याख्या करते हैं।",
  "17.7": "अथरः तु अपि सर्वस्य त्रिविधः भवति प्रियाः।\nयज्ञः तपः तथा दानं तेषाम् भेदं इमाम श्रृणु - तीन खाद्य पदार्थ जो हर कोई खाता है\nतेरानागी पसंदीदा बन गया। यज्ञ भी, तप भी, दान भी। इन्हें ऐसे समझें.\n\nहम जो भोजन करते हैं वह भी त्रिगुणात्मक होता है। सात्विक, राजस और तामस भोजन। “अन्नाम\nअशीतम् त्रेधा विध्याय” (छान्दोग्योपनिषत्-5-1) के अनुसार हम जो भोजन करते हैं।\nहमारे भीतर के प्राण और वैष्णव को तीन प्रकार (सूक्ष्म, मध्य और स्थूल) में विभाजित करें।\nइसकी आपूर्ति शरीर के विभिन्न हिस्सों में की जाती है। सीधे हमारे भोजन और दिमाग पर\nएक रिश्ता है. हमारे पूर्वज यह जानते थे। इसका असर दिमाग पर पड़ता है\nउसने खाना खाने से मना कर दिया. उदाहरण के लिए लहसुन. यह एक औषधीय पदार्थ है. लेकिन ये रूटीन है\nभोजन में उपयोग के लिए निषिद्ध. क्योंकि यह हमारे बौद्धिक विकास के लिए अनुकूल नहीं है। यही तो है\nजैसे जायफल, गोरस आदि। यह अध्ययन करने वालों के लिए (औषधि के रूप में) वर्जित है\nइस्तेमाल किया जा सकता है)। इस प्रकार, पहली बार, किस प्रकार का भोजन मानव बुद्धि के लिए उपयुक्त है\nकृष्ण ने दुनिया को दिया.\n\nभोजन के साथ-साथ हमारी ईश्वर आराधना, तप, हमारी विचार प्रक्रिया, दान, जीवनचर्या,\nइन तीन प्रकारों को सभी भाषणों में पहचाना जा सकता है। अगले श्लोक में कृष्ण भोजन,\nवह बताते हैं कि त्याग, तपस्या और दान इन तीन प्रकारों को कैसे पहचाना जाए।\n\nआयुष्सत्त्वबलारोग्यसुखाप्रीतिविवर्धना |\n\nरस्यः स्निग्गाः स्थिर हृदय आहारः सात्विकप्रियः।",
  "17.16": "मनः प्रसादः सौम्यत्वं मौनं आत्मविनिग्रहः।\nभवसंशुद्धि इति एतत् तपः मनसं उच्यते -- अपने ऊपर मन, मन, मन का प्रकार\nसंयम करो और कल्याण करो- इसे मन की तपस्या कहा जाता है।\n\nऊपर बताये गये दो प्रकार के तपों में से जो महान तप है वह मन का तप है। शरीर\nऔर वाणी की तपस्या मन की तपस्या की पूरक होती है। हमारा मन सदैव प्रसन्न रहना चाहिए।\nइसे बुरे विचारों से भर दो। सीमित नहीं होना चाहिए. वह वहां हल्का होना चाहिए\nकोई क्रूरता नहीं होनी चाहिए. किसी एक विषय पर निष्कर्ष पर पहुंचने से पहले गहनता से विचार करें\nआपको सोचना होगा. किसी एक बात, एक व्यक्ति पर जल्दबाजी में प्रतिक्रिया नहीं देनी चाहिए. मन\nकरो, सोचो और बोलो. यदि हमें इस प्रकार ध्यान करना है तो हमें आत्मसंयम का अभ्यास करना होगा\nहासिल किया जाना चाहिए (अधिक विवरण के लिए ए-13, श्लो-7 देखें)। शुद्ध क्रूरता मुक्त मन के लिए\nइंद्रियों पर नियंत्रण होता है. ऐसे मन को बुरा नहीं लगता। एक हमारे बारे में है\nयदि हम बुरा भी बोलते हैं तो भी हमारे मन में उनके प्रति घृणा या क्रोध नहीं आता। ऐसा मन करो\nनियंत्रण करना मन की तपस्या है।\n\nयहां वर्णित तीन प्रकार के तपों में से प्रत्येक के फिर से तीन प्रकार हैं। सात्विक, राजस और\nतमस इसे अगले तीन श्लोकों में समझाया गया है।",
  "17.8": "आयुः सत्त्व बल स्वास्थ्य सुख प्रेम विवर्धनः।\n\nरस्यः स्निगः नथिरा हृदयः आहारः सात्विक प्रियः - ये सात्विक लोगों द्वारा पसंद किये जाने वाले खाद्य पदार्थ हैं:\nदीर्घायु, अच्छाई, सहनशक्ति, स्वास्थ्य बढ़ाता है; लंबे समय से पसंदीदा;\nइसे खाना अच्छा लगता है; स्वादिष्ट; जैसा कि दीर्घकालिक प्रभाव में होता है\n\nजैसे बार-बार वे मनमोहक होते हैं।\n\nइस श्लोक में कृष्ण सात्विक भोजन के बारे में बताते हैं। हमारी उम्र बढ़ाने के लिए क्या खाना चाहिए?\nपूरक; कौन सा भोजन हमें सौम्यता देता है; शरीर के लिए कौन सा भोजन है\n\nपोषण प्रदान करता है; कोई भी भोजन जो स्वास्थ्य प्रदान करता है वह सात्विक है\nभोजन इस भोजन को देखकर हमें बुरा नहीं लगता। यह रसदार है,\nइसका स्वाद अच्छा है. इसे खाने से हमारा पेट भर जाता है और हमें तुरंत भूख नहीं लगती।\nयह देखने में दिल को छू लेने वाला और खाने में यादगार है।\n\nएक सच्चा सात्विक जो खाता है वह सात्विक भोजन है। प्रकृति प्राकृतिक है,\nरसीला, स्वादिष्ट, फल-हंपालु, कंद-आलू, दाल-अनाज, कन्दा-जड़ें आमतौर पर\nसात्विक भोजन. शुद्ध घी (संयमित मात्रा में उपयोग करने पर) एक सात्विक भोजन है जो जीवन को बढ़ाता है।\n\nकत्तमसलवनत्युष्टतिक्षारुक्षविदहिनः।\n\nअधारा राजसस्येष्ठा दुःखशोकमयप्रदः",
  "17.20": "दाताव्यं इति यत् दानं दीयते अनुपकारिणे।\nदेशे काले च पात्रे च तत् दानं सात्विकम् स्मृतम् - कर्तव्य भी प्रत्युपकार के लिए।\nदूरदृष्टि से दिया गया दान, सही देश और समय में सही व्यक्ति को दिया गया दान सात्विक होता है।\n\nबिना किसी प्रत्युत्तर की आशा के, आत्मा आनंदपूर्वक, पूरे हृदय से, प्रेमपूर्वक,\nसही व्यक्ति को, सही समय पर, सही स्थान पर देना; यह मेरा कर्तव्य है\nदूरदर्शितापूर्वक दान करना सात्विक दान है [[अधिक व्याख्या: अध्याय सोलह का आरंभिक श्लोक]।",
  "17.15": "अनुद्वेगा करं वाक्यं सत्यं प्रिय हितं च यत्।\nस्वाध्याय अभ्यासनं च एव वाज्मयं तपः उच्यते-चिड़चिड़ा, निर्भीक, श्रवण की सराहना करने वाला\nऔर जीवन के लिए अच्छे शब्द और ग्रंथ पढ़ना शब्दों की तपस्या के समान है।\n\nजैसा कि पिछले अध्याय में चर्चा की गई है, चीजों को वैसे ही कहना सच नहीं है जैसे वे हैं। सच क्या है?\nइस श्लोक के माध्यम से कृष्ण ने हमें स्पष्टीकरण दिया है। सच्ची सज्जनता कहाँ है-\nइसकी प्रशंसा करना, इसे पूरक बनाना, इस तरह से जिससे दूसरों को ठेस पहुँचाए बिना प्रसन्न हो\nबोलना वाणी का तप है। दूसरों को प्रिय और सुखद लगने वाले शब्दों का प्रयोग करना बहुत जरूरी है\nकठिन क्योंकि अधिकतर मामलों में जो प्रिय होता है वह सुखद नहीं होता। ऐसे मामलों में चुप्पी\nकृष्ण की कथा पढ़ते समय कई बार कृष्ण ने हमसे झूठ बोला, हमें धोखा दिया\nप्रकट होगा लेकिन यह हमारे लिए है जब हम उस कार्य के पीछे की दयालुता और परोपकार को देखते हैं\nमालूम हो गया कि ये झूठ नहीं है. जब हम अपने दैनिक जीवन में बात करते हैं तो कृष्ण हम हैं\nश्लोक में उल्लिखित संदेश से अवगत होना चाहिए। बिना बोले चुप रहना ठीक है—लेकिन कुछ तो\nबोलने और फिर पछताने से कोई फायदा नहीं है. “खेले गए शब्द के पीछे जाने के लिए\nनहीं कर सकते; घायल मन को ठीक करने के लिए हमारे पास कोई दवा नहीं है।” तो एक और\nकभी भी आहत करने वाले शब्द न बोलें। व्यर्थ की बकवास में दिन न बिताकर वेदों का अर्थ,\nगीता का ध्यान, विष्णुसहस्रनाम का पाठ आदि वाणी का तप है।",
  "17.21": "यत् तु प्रत्युपकारार्थं फलं उद्दिष्य वा रे।\nदीते च परिक्षित 0 तत् राजसम उदाहृतम् - प्रत्युत्तर या फल की इच्छा के लिए,\nजो दान नहीं देना चाहिए वह राजसिक लगता है।\n\nदूसरे को भविष्य में हम पर उपकार करने दें या अतीत में किए गए उपकार के बदले में।\nजैसा देना चाहिए वैसा ही देना। दान करते समय फल की इच्छा से देना राजस दान है।",
  "17.11": "अफला आकांक्षिबिह यज्ञः विद्धिदृष्टो हाँ इज्यते |\nयश्तव्यं एव इति मनः समाधाय सः सात्त्विक; -विज्ञान के नियमों के अनुसार फल की चिंता किये बिना,\nकर्तव्य की भावना से मन को प्रसन्न करने वाला यज्ञ सात्विक यज्ञ है।\n\nयज्ञ करने वाले सभी लोग सात्विक नहीं होते। यज्ञ में तीन प्रकार के सात्विक राजस और तमस होते हैं\nविविधता है. इस श्लोक में कृष्ण ने बताया है कि सात्विक यज्ञ कैसा होता है। यज्ञ का अर्थ है\nसिर्फ अग्निकुंड में की गई पूजा ही नहीं. पीठ पर भगवान की पूजा करना भी यज्ञ है,\nमानसिक रूप से ईश्वर का ध्यान करना भी एक यज्ञ है। फल की इच्छा रहित, भगवन्\nप्रसन्ना - उनकी कृपादृष्टि मुझ पर बनी रहे, कर्मकाण्ड सात्विक होता है।\nयह एक बलिदान जैसा लगता है. यंत्रवत्, मन्त्र का अर्थ जाने बिना, किसी संकीर्ण स्वार्थवश\n\nई. एम\n\nयदि पूजा की जायेगी तो वह सात्विक यज्ञ नहीं होगा।\n\nयहाँ 'समारोहपूर्वक' कहा गया है। यह बहुत ही महत्वपूर्ण मुद्दा है. उदाहरण के लिए हम\nपूजा करते समय हम घंटियाँ बजाएँगे; शंख चलेगा. ऐसी कोई पूजा नहीं\nयदि कोई विधि है भी, तो उसे करने से पहले हमें यह समझने की आवश्यकता है कि हम ऐसा क्यों कर रहे हैं\n\nआवश्यक घंटी एक साथ जोर से नहीं बजानी चाहिए। घंटी\nइसे बनाते वक्त इसमें से ओमकारा बाहर आना चाहिए।' जब ओंकार नाद इस प्रकार उभरता है-\nजिस क्षेत्र में वह नाड़ा सुनाई देता है वहां की सभी बुरी आत्माएं और यह नाड़ा भाग जाती हैं\nदिव्य ऊर्जाओं को आकर्षित करता है. इससे पूजा के लिए स्वच्छ वातावरण तैयार होता है।\nयहां घंटी बजाकर बुरी आत्माओं के चले जाने, दैवीय आत्माओं के आने की ईमानदारी से प्रार्थना की जाती है\nओंकारण निवारण अत्यंत महत्वपूर्ण है। घंटी से अपस्वर कभी नहीं आना चाहिए। घंटी को\nएक धुन है. सप्त स्वरों में सप्त स्वर घंटियाँ होती हैं। इसे सौहार्दपूर्ण ढंग से खेला जाना चाहिए।' ये है\nओमकारा से वातावरण को शुद्ध करने की अद्भुत प्रक्रिया। यह सिर्फ एक उदाहरण है।\nइस प्रकार हमें अपना प्रत्येक कार्य सचेतन रूप से करना चाहिए; कर रहा है\nहमें कर्म में प्रसन्न रहना चाहिए। इस प्रकार किये जाने पर ही वह सात्विक यज्ञ कहलाता है।",
  "16.24": "आर\nतस्मात् शास्त्रं प्रमाणं ते कार्य अकार्य समस्तमौ |\nज्ञात्वा शास्त्र विधि उक्तं कर्म कर्तुम् एह अरहसि - उससे इच्छाओं और जरूरतों के निष्कर्ष तक।\nविनय शास्त्र आदर्श है। आइए यहां शास्त्र के नियमानुसार कर्म करें।\n\nशास्त्र सभी इच्छाओं और आवश्यकताओं का आदर्श है। ऐसा पहले हम शास्त्रों में कहते हैं\nविश्वास करना चाहिए. तब पता चल सकेगा. शास्त्र में यह करें और वह न करें\nजिन्होंने कहा है- वे बुद्धिमान हैं जिन्होंने इसके प्रभाव को जान लिया है। तो कर्म\nकृष्ण कहते हैं कि क्रम के अनुसार कर्म करो।\n\nयहाँ शास्त्र का अर्थ है चार वेद और उनके पूरक पंचरात्र, महाभारत,\nमूलरामायण, और अठारह पुराण। इसके अलावा और कुछ भी पूर्ण नहीं है\n\nपरिमाणित नहीं किया जा सकता.\n\nइति षोडशो*ध्यायः\nसोलहवाँ अध्याय समाप्त हो गया\n\nक्या यह सच है?\n\nअध्याय सत्रह\n\nकृष्ण ने गीता की शुरुआत में कर्म का वर्णन किया है: “फल के बंधन को त्यागकर भगवान की पूजा करो।\nउन्होंने \"कर्म करो\" का संदेश दिया। कर्म करते समय हमें एक बात जानने की आवश्यकता है\nएक बहुत ही महत्वपूर्ण मुद्दा यह है: क्या अच्छा है और क्या बुरा है। ख़राब\nकाम और अच्छा काम उतना सरल नहीं है जितना हम जानते हैं। हमारे लिए\nऊपर जो अच्छा काम पाया जाता है वह ख़राब काम या ख़राब काम हो सकता है\nअच्छा काम लगता है. यहां कार्य के पीछे की भावना महत्वपूर्ण हो जाती है। एक ही क्रिया\nयह अपने पूर्व भाव के अनुसार अच्छा या बुरा हो सकता है।\nउदाहरणार्थ: महाभारत युद्ध। इस युद्ध में कौरवों की तरह पांडवों ने भी भाग लिया था\nभाग लिया। पांडव सात्विक मानसिकता के थे। वे कभी भी सामाजिक रूप से स्वयं नहीं होते\nमहान पद प्राप्त करने के लिए (राजस भावना), कौरवों को नष्ट करने के लिए (तमस भावना)\nउसने भावना के कारण युद्ध नहीं किया। लेकिन दुर्योधन में केवल रजस और तमस था\nइस कारण से, पांडवों द्वारा किया गया युद्ध सात्विक युद्ध था, जबकि कौरवों द्वारा किया गया युद्ध सात्विक युद्ध था।\nतमस का युद्ध था. तो हम जानते हैं कि सत्कर्म क्या है और बुरा क्या है\nज्ञान प्राप्त करना और कर्म करना बहुत महत्वपूर्ण है। कर्म सत्व है, रजस है,\nयह तीन प्रकार के त्रिगुणों की सीमाओं के भीतर होता है जिन्हें तमस कहा जाता है। हमारा बलिदान, दान,\nतपस्या; हम जो भी भोजन खाते हैं वह इन गुणों से प्रभावित होता है। यह\nजितना संभव हो सके यह जानना कि गुण हमारे कर्म को कैसे प्रभावित करते हैं,\nकर्म सत्त्व की सीमा में रहकर करना चाहिए। यह अध्याय मुख्यतः किस दृष्टिकोण से है\nजब कर्म किया जाता है तो वह कर्म सात्विक, राजस या तामस कर्म हो जाता है\nसमझाता है.\n\nपिछले अध्याय के अंत में, कृष्ण ने कहा, \"वह जो शास्त्र के नियमों से परे जाता है वह एक सिद्धि है\nवह इसे प्राप्त नहीं कर सकता, उसके पास कोई खुशी नहीं है, कोई पूर्णता नहीं है।\" यहाँ हमारे लिए एक प्रश्न है\nजो लोग शास्त्र के नियमों को नहीं जानते - श्रद्धापूर्वक कर्म करते हैं उनकी क्या स्थिति है? वह है।\nयह अध्याय अर्जुन द्वारा हमारी ओर से कृष्ण से यह प्रश्न पूछने से प्रारंभ होता है।\nआइए हम अर्जुन के साथ जुड़ें और भगवान की शिक्षाओं को सुनें।\n\nअर्जुन का भाषण.\nये शास्त्रविधिमुत्सा ज्या यजन्ते श्रद्धाय$न्वितः |\nतेषाम् निष्ठा तु का कृष्ण सत्तामहो राजस्तमः ॥1॥\n\nअर्जुन उवाच- अर्जुन ने पूछा:\n\nये शास्त्रविधिम् उत्सा ज्य यजन्ते श्रद्धया अन्वितः |\n\nतेषाम् निष्ठा तु का कृष्ण सत्त्रं अहो राजः तमः - भले ही कुछ लोग शास्त्र के आदेशों को नहीं जानते हों।\nवे विश्वास से चलते हैं. कृष्ण उनका निवास स्थान क्या है? सत्त्व, रजसे या\nक्या आप हैं?\n\nहमने वेदों का अध्ययन नहीं किया है, हम शास्त्र के विधान को नहीं जानते, बल्कि इसलिये कि हम शास्त्र को नहीं जानते\nपछतावा है; शास्त्र के प्रति समर्पण है, उसके अनुसार जीने की चाहत है। जो जानते हैं\nकहते हैं: \"यदेव विद्याया करोति श्रद्धेय..'' अर्थात \"जो कुछ भी करो, सोच-समझकर करो।\nज्ञान से किया गया कर्म सफल होता है। अन्यथा यह व्यर्थ है।” जब कोई ऐसा हो\nक्या मेहनत व्यर्थ है? यह अर्जुन का प्रश्न है.\n\nयहां \"श्रद्धा\" का अर्थ है- उस अदृश्य शक्ति के बारे में जो पारलौकिक होने के कारण हमें नियंत्रित करती है\nहमारा जो विश्वास है. अर्थ: ईश्वर में विश्वास, शास्त्र में विश्वास, पाप-पुण्य\nविश्वास वह विश्वास है कि एक सर्वोच्च शक्ति है जो सब कुछ नियंत्रित करती है। जैसा कि महाभारत कहता है:\n'कर्म का फल अवश्य होता है। विश्वास ही मानव जीवन का आधार है...जबकि यही बात है\nविश्वास के साथ",
  "17.14": "देवा द्विज गुरु प्रज्ञा पूजनं शौचं आर्जवम् |\n\nब्रह्मचर्यम अहिंसा च शरीरं तपः उच्यते - देवता, चेतना से पुनर्जन्म लेते हैं।\nसिद्धि प्राप्त करने वालों, गुरुओं और उन लोगों का सम्मान करना जो सर्वोत्तम, स्वच्छता, सीधा चलना जानते हैं।\nब्रह्मचर्य और दूसरों को कष्ट न देना शरीर का तप माना गया है।\n\nजहां भी भगवान का प्रतीक दिखे, वहां झुकना; बुद्धिमानों को सम्मान देना; बृहस्पति के लिए\nउन अनुभवी लोगों को प्रणाम करें जिन्होंने भगवद्भूति के माध्यम से भगवान का अनुभव किया है\nश्रद्धा- ये सब शरीर तप माने गये हैं। साथ ही साफ-सफाई भी बनाए रखें\nजियो, सीधा बोलो, ब्रह्मचर्य का पालन करो। और दूसरे को. हम से\nबिना कष्ट के जीना शरीर की तपस्या है। [इस श्लोक में शौचम्, आर्जवम् का उल्लेख है\nऔर अहिंसा-सोलहवें अध्याय के शुरुआती श्लोक में इन गुणों का पूरा विवरण है\nवर्णित]। यहां ब्रह्मचर्य पालने का अर्थ है मन को भगवान पर स्थिर करना; उसके लिए\n\nवेदों का पूरक अध्ययन और शारीरिक ब्रह्मचर्य का पालन।\nशारीरिक रूप से पूर्ण ब्रह्मचर्य केवल भिक्षुओं और ब्रह्मचारियों पर लागू होता है।\nग्रह इस तरह नहीं रह सकते. अतः ग्रहों में ब्रह्मचर्य का अर्थ है-\nइसका मतलब यह है कि वे व्यभिचारी नहीं बनते बल्कि ग्रहधर्म के दायरे में रहते हैं। इस प्रकार\nप्रभु में समर्पण करो; ज्ञानी, गुरु, प्रज्ञा, स्वच्छता का सम्मान करना\nअहिंसा का पालन करना, खरा बोलना, ब्रह्मचर्य का पालन करना और जीवन जीना-\nशारीरिक तपस्या. हमें सामाजिक रूप से सभ्य जीवन जीने के लिए यह तपस्या आवश्यक है।\nये शारीरिक नैतिकताएं हैं जिनका मनुष्य को पालन करना चाहिए\n\nअनुद्वेगकारं वाक्यं सत्यं प्रियहितं च यत् |\n\nस्वाध्यायभ्यासनं चे )व वाज्मयं तप उच्यते",
  "17.22": "आदेश काले यत् दानं अप्रत्रेभ्यः च दीयते।\nअसत् कृतं अवज्ञातम तत् तमसं उदाहृतम् - चातुर्यहीन की भूमि-काल में,\nअयोग्य व्यक्तियों को अंधाधुंध दान देना तामस के समान लगता है।\n\nवह देना जो हम किसी और को नहीं देना चाहते; अयोग्य को दोष दो,\nताना देना, अपमानित करना और देना - तमसा दाना।\n\nइस अध्याय में अगला 'अर्थवाड़ा' है जो कृष्ण द्वारा अब तक वर्णित सात्विक कर्म के महत्व को बताता है\nभाग 'अर्थवाद' का अर्थ सात्विक कर्म के महत्व का प्रतिपादन है।\n\nॐ तत् सदिति निर्देशो ब्राह्मणस्तिविधः स्मृतः |\n\nब्राह्मणस्तेन वेदाश्च यज्ञश्च विहितः पुरा",
  "17.26": "सत् भवे साधुभावे च सत् इति एतत् प्रयुज्यते |\nप्रशस्ते कर्माणि तथा सत् शब्दः पार्थ युज्यते - पार्थ, 'जन्म' और 'अच्छाई'।\nसत् शब्द का प्रयोग सत् के अर्थ में किया जाता है। सत् शब्द का प्रयोग अच्छे कार्य के अर्थ में भी किया जाता है।\n\n'सत्' का एक अर्थ है. सत्-भाव का अर्थ है विनम्र होना। यह दुनिया में है\nकिसी व्यक्ति के लिए प्रयुक्त मुहावरा। जब इसका उपयोग कर्म में किया जाता है तो यह सत्-कर्म बन जाता है। ओंकार वाच्य\n'सत्'-कर्म भगवान की भक्ति में बिना किसी फल की इच्छा के किया गया कर्म है।\nभगवान के लिए जो भी कर्म किया जाए वह कर्म उत्कृष्ट होना चाहिए। वह है\nयदि यह स्वार्थ के लिए किया जायेगा तो लोग इसकी सराहना नहीं करेंगे। बल्कि त्याग द्वारा किया गया कर्म प्रशस्त है\nकर्म जैसा लगता है. इस प्रकार हम प्रत्येक शब्द का अर्थ जानते हैं और उसका ध्यान रखते हैं\nकृष्ण का संदेश है पार्थ बनो। सत् शब्द का अर्थ आगे विस्तार से बताया जायेगा\nकृष्ण श्लोक में बताते हैं.\n\nयज्ञे तपसि दाने च स्थितः सदिति चोच्यते |\nकर्म चैव तदर्थ्यं सद्त्येवभिधीयते",
  "17.19": "कड़वे अम्ल लवण अति गरम तीक्ष्ण रुक्षा विदेहिनः।\n\nअधारः राजसस्य इष्टः दुःख शोक अमाय प्रदः - ये राजस के पसंदीदा भोजन हैं:\nअत्यधिक नमकीन, खट्टा, नमकीन, बहुत गर्म, तीखा, उबाऊ और आग लगाने वाला; दुखद-\nमतली और बीमारी.\n\nयहाँ कृष्ण ने राजस भोजन का वर्णन किया है। बहुत नमकीन, बहुत खट्टा, बहुत नमकीन,\nराजसा भोजन जैसा दिखता है। बहुत अधिक गर्मी पीना; ज़ोरदार और उबाऊ\nखाना खाना; हृदय को जलाने वाले भोजन का सेवन करना- ये रजस के लक्षण हैं। ये खाना\nइसके सेवन से मानसिक और शारीरिक कष्ट बढ़ता है। यह एक ऐसा भोजन है जो बीमारी ला सकता है।\n\nमिर्च की फली सीधे खाना, इमली का फल हमेशा अधिक खाना\nबहुत अधिक नमक का उपयोग करना, गले को जलाने वाली कॉफी पीना, बहुत अधिक सरसों और मसालों का सेवन करना\nउपयोग, बिना रस वाले भोजन का सेवन (8h:0184110 9007);  आदि कुछ राजाओं के आहार के लिए\nउदाहरण\nयह रोगी को सात्विक भोजन लगता है]।\n\nयथायमं गतरसं पुति पर्युषितं च यत् |\nउच्छिष्ट मपि चामेध्यं भोजनं तमसाप्रियम्",
  "17.9": "रस्यः स्निगः नथिरा हृदयः आहारः सात्विक प्रियः - ये सात्विक लोगों द्वारा पसंद किये जाने वाले खाद्य पदार्थ हैं:\nदीर्घायु, अच्छाई, सहनशक्ति, स्वास्थ्य बढ़ाता है; लंबे समय से पसंदीदा;\nइसे खाना अच्छा लगता है; स्वादिष्ट; जैसा कि दीर्घकालिक प्रभाव में होता है\n\nजैसे बार-बार वे मनमोहक होते हैं।\n\nइस श्लोक में कृष्ण सात्विक भोजन के बारे में बताते हैं। हमारी उम्र बढ़ाने के लिए क्या खाना चाहिए?\nपूरक; कौन सा भोजन हमें सौम्यता देता है; शरीर के लिए कौन सा भोजन है\n\nपोषण प्रदान करता है; कोई भी भोजन जो स्वास्थ्य प्रदान करता है वह सात्विक है\nभोजन इस भोजन को देखकर हमें बुरा नहीं लगता। यह रसदार है,\nइसका स्वाद अच्छा है. इसे खाने से हमारा पेट भर जाता है और हमें तुरंत भूख नहीं लगती।\nयह देखने में दिल को छू लेने वाला और खाने में यादगार है।\n\nएक सच्चा सात्विक जो खाता है वह सात्विक भोजन है। प्रकृति प्राकृतिक है,\nरसीला, स्वादिष्ट, फल-हंपालु, कंद-आलू, दाल-अनाज, कन्दा-जड़ें आमतौर पर\nसात्विक भोजन. शुद्ध घी (संयमित मात्रा में उपयोग करने पर) एक सात्विक भोजन है जो जीवन को बढ़ाता है।\n\nकत्तमसलवनत्युष्टतिक्षारुक्षविदहिनः।\n\nअधारा राजसाशेषत् ॥॥19॥\n\nकड़वे अम्ल लवण अति गरम तीक्ष्ण रुक्षा विदेहिनः।\n\nअधारः राजसस्य इष्टः दुःख शोक अमाय प्रदः - ये राजस के पसंदीदा भोजन हैं:\nअत्यधिक नमकीन, खट्टा, नमकीन, बहुत गर्म, तीखा, उबाऊ और आग लगाने वाला; दुखद-\nमतली और बीमारी.\n\nयहाँ कृष्ण ने राजस भोजन का वर्णन किया है। बहुत नमकीन, बहुत खट्टा, बहुत नमकीन,\nराजसा भोजन जैसा दिखता है। बहुत अधिक गर्मी पीना; ज़ोरदार और उबाऊ\nखाना खाना; हृदय को जलाने वाले भोजन का सेवन करना- ये रजस के लक्षण हैं। ये खाना\nइसके सेवन से मानसिक और शारीरिक कष्ट बढ़ता है। यह एक ऐसा भोजन है जो बीमारी ला सकता है।\n\nमिर्च की फली सीधे खाना, इमली का फल हमेशा अधिक खाना\nबहुत अधिक नमक का उपयोग करना, गले को जलाने वाली कॉफी पीना, बहुत अधिक सरसों और मसालों का सेवन करना\nउपयोग, बिना रस वाले भोजन का सेवन (8h:0184110 9007);  आदि कुछ राजाओं के आहार के लिए\nउदाहरण\nयह रोगी को सात्विक भोजन लगता है]।\n\nयथायमं गतरसं पुति पर्युषितं च यत् |\nउच्छिष्ट मपि चामेध्यं भोजनं तमसाप्रियम्",
  "17.27": "यज्ञे तपसी दाने च सत्तीः सत् इति च उच्यते |\nकर्म च एव तत् अर्थ्यं सत् इति एव अभिधीयते - यज्ञ-दान-तपस्या में निष्ठा।\nइसे \"सत्\" कहा जाता है। भगवान के लिए किये गये कर्म को \"सत्\" भी कहा जाता है।\n\n\"सत्\" का अर्थ है यज्ञ, दान और तपस्या के माध्यम से \"सत्\" शब्द वाले भगवान की पूजा करना। इस प्रकार\nभगवान भी सत् हैं; उनके कर्म भी सत् हैं; उनके कर्म भी सत् हैं\nकर्ता भी सत् है। हम निष्काम, भगवदर्पण, भगवान से परिचित हैं\nसत-कर्म वे सभी कर्म हैं जो भगवान को प्रसन्न करने के लिए भाव से किए जाते हैं।\n\nअश्रद्धया हुतं दत्तं तपस्तप्तं कृतं चयत् |\nअसदित्युच्यते पार्थना च तत् प्रेत न इहा",
  "17.4": "यजन्ते सात्विकः देवां यक्षारक्षणसि राजसः |\nप्रेतं भूतगणां च अन्ये यजन्ते तमसा जनः - सात्त्विक पूजा का श्रेय देवताओं को दिया जाता है,\nराजाओं और राक्षसों के लिए. तमस की पूजा का श्रेय भूतों और भूतगणों को दिया जाता है।\n\nअगर हम ऊपर देखें तो इस श्लोक का कोई मतलब नहीं बनता। ऊपर, “सात्विक\nदेवताओं की पूजा होती है; रजस यक्ष-राक्षस हैं और तमस भूत-प्रेत हैं\nइसे पूजा के रूप में देखा जाएगा. लेकिन यहां जो अंतर्निहित अर्थ छिपा है वह अलग है। हमारे लिए\nजैसा कि आप जानते हैं, सात्विक, राजसरस, तमसरस - वे भगवान की पूजा करते हैं।\nया देवदूत. जादू-टोना करने वालों को छोड़कर (0/00078g) और कोई भूत-प्रेत नहीं होता-\nराक्षसों की पूजा नहीं की जाती. इसलिए यदि हम यहां मूल संदेश को समझना चाहते हैं, तो हम\nश्लोक का गहराई से विश्लेषण करना चाहिए. यहां 'देवन्' का अर्थ है: भगवान के अनेक रूप तथा\nइसका अर्थ है 'भगवान के अनुचर देवदूत'। \"यजन्ते सात्विक देवन्\" का अर्थ है - सात्विक\nइसका अर्थ है कि भगवान के दृष्टिकोण से की गई पूजा देवताओं से जुड़ जाती है। उसी प्रकार\n\"यक्षरक्षमसि राजसः\" अर्थात- राजाओं द्वारा की जाने वाली पूजा यक्ष-राक्षसों की होती है।\nराजा आमतौर पर भगवान की सर्वोच्चता से अनजान होते हैं, डर के मारे देवता हम हैं\nवह कष्ट न देने की भावना से पूजा करता है। ऐसे करें पूजा\nजब हम भगवान की पूजा करते हैं तो देवता कहे जाने वाले यक्ष-राक्षस आते हैं\nतीसरा वर्ग तमस है। वे जिसकी पूजा करते हैं वह उनकी स्थिति है\nदिखावे के लिए. उदाहरण के लिए दुर्योधन ने पांडवों द्वारा किया गया अश्वमेध यज्ञ किया\nजिस पर काबू पाने के लिए पुण्डरीक यज्ञ किया गया। इस प्रकार द्वेष के साथ तमस करना\nजो लोग आते हैं और पूजा प्राप्त करते हैं वे देवताओं के नाम पर भूत हैं।\n\nपूजा में केवल भक्ति ही मायने नहीं रखती, बल्कि यह भी महत्वपूर्ण है कि भक्ति किस प्रकार की है। भले ही आप शास्त्र न जानते हों\nसाथ ही, सात्विक निष्ठा के साथ: “हे प्रभु, मैं कुछ नहीं जानता, मैं भक्तिपूर्वक आपकी पूजा करता हूं।\nमैं ऐसा करूंगा, मेरी गलती माफ कर दो'' तो उसने समर्पण कर दिया और खुद ही पूजा करने को कहा\nभगवान स्वयं आकर स्वीकार करते हैं। परन्तु राजस स्वार्थ, अभिमान और अहंकार से होता है\nया तमसा पूजा भगवान या उनके देवताओं के अनुचर द्वारा स्वीकार नहीं की जाती है।\n\nहमारा कर्म निष्काम होना चाहिए। यहां वासना का मतलब वासना है. चाहत में कभी नहीं\nनिःस्वार्थ। हमें इस संकीर्ण भावना को त्याग देना चाहिए कि मेरे लिए क्या अच्छा है।\n\nपुणस्कार पूजा करते समय हमें किसी संकीर्ण इरादे से पूजा नहीं करनी चाहिए।\nउदाहरण के लिए: \"मेरे व्यवसाय में समृद्धि के लिए बलिदान; बेटी के लिए अच्छा दहेज।\"\nपूजा आदि करना। इस प्रकार हम अपनी इच्छाओं को भगवान में सूचीबद्ध करते हैं\nमत दो. भगवान जाने क्या होगा. क्या अच्छा है, क्या है\nकेवल वही जानता है कि क्या बुरा है। वह दे देगा. जबकि मामला यही है\nत्रासदी तब होती है जब हम अपनी इच्छाओं की इतनी संकीर्ण सूची को पकड़कर कर्म करते हैं\nअत्याचारी हम किसी कामना से भगवान की पूजा करते हैं। उस पूजा में पैसे का खर्च\nलेकिन वह इच्छा पूरी नहीं होती. फिर हमने परमेश्‍वर से नफरत की और पैसा बर्बाद किया\nवह परेशान है. तब हमारी पूजा एक व्यवसाय बन जाती है और वह है भूत-प्रेत\nभगवान की पूजा करना व्यवसाय नहीं है।\nअसस्त्रविहितं घोरं तप्यन्ते ये तपो जनः।\n\nदंभहंकारसंयुक्तः कामरागबलन्वितः",
  "18.2": "भगवान् उवाच —\nकाम्यानां कर्मणां न्यासं संन्यासं कवयो विदुः ।\nसर्वकर्मफलत्यागं प्राहुस्त्यागं विचक्षणाः ॥\n\n'कामना-पूर्ण कर्मों का त्याग — विद्वान् संन्यास कहते हैं। सभी कर्मफलों का त्याग — विचक्षण (विद्वान्) त्याग कहते हैं।'\n\nदो भेद — (१) संन्यास: कामना-प्रेरित कर्मों को छोड़ना — कर्म छोड़ना; (२) त्याग: कर्म करते हुए फलों की आसक्ति छोड़ना — फल छोड़ना। गीता का मत — त्याग श्रेयस्कर।",
  "17.18": "सत्कार मन पूजा अर्थं तपः दम्बेन च एव यत्।\nक्रियते तत् इहा प्रोक्तम् राजसम चलम् अध्रुवम् - धन्यवाद, प्रशंसा और सम्मान के लिए\nपाखंडपूर्वक किया गया तप, जिसका कोई आधार न हो, राजस कहलाता है।\n\nभगवान से परामर्श किए बिना, वह लोगों द्वारा सम्मान पाने की इच्छा से ऐसा करता है\nसभी तप राजस तप हैं। इस प्रकार कपटपूर्वक किया गया तप स्वर्ग के योग्य नहीं है।\nइतनी मेहनत का नतीजा यहां भी स्थाई नहीं होता.\n\nइस श्लोक में ईवा और चा-कारा एक साथ आते हैं। यह हमें एक खास संदेश देता है.\nयदि सुख, सम्मान और प्रतिष्ठा के लिए किया गया कार्य राजस कहलाता है; भगवदर्पण\nमन से करो तो इनाम पाओ, समझ पाने के लिए चार लोगों को ज्ञान दो\nयदि आप भावना से उपदेश देंगे तो वह राजसिक नहीं होगा। यह बताने के लिए यहां चौ\nऔर किसके द्वारा उपयोग किया जाता है।\n\nमुधाग्रहेण$त्मानो यत् पेडया क्रियते तपः |\n\nपरस्योत्स दानार्थं वा तत् तमसमुद्धहृतम् ॥19॥\n\nमूढ़ गृहेण आत्मानः यत् पेडया क्रियते तपः |\n\nपरस्य उत्सादन अर्थं वा तत् तमसं उदाहृतम् - लोभ के कारण व्यक्ति का अपना शरीर।\nअविश्वासियों को दण्ड देकर या समाप्त करके की गई तपस्या तामस तपस्या है\nऐसा लगता है\n\nग़लतफ़हमी से, भ्रम से, सर्वोच्च तक पहुंच के बिना, व्यक्ति को नष्ट हो जाना चाहिए\nबुरी भावना के कारण, अपने शरीर के भीतर भगवान की जागरूकता के बिना, शरीर को दंडित किया जाता है\nस्वनिर्मित तप तामस तप है।\n\nदाताव्यमिति यद् दानं दीयतेनुपकारिणे |\nदेशे काले च पात्रे च तद् दानं सात्विकं स्मृतम्",
  "18.3": "कुछ कहते हैं — दोष है इसलिए कर्म छोड़ना चाहिए। दूसरे कहते हैं — यज्ञ-दान-तप-कर्म नहीं छोड़ना चाहिए।\n\nदो दृष्टिकोण — (१) कर्म दोषयुक्त है इसलिए छोड़ो; (२) यज्ञ-दान-तप मत छोड़ो। कृष्ण दोनों को सुनकर निर्णय देंगे।",
  "17.23": "ॐ तत् सत् इति निर्देशः ब्राह्मणः त्रिविधः स्मृतः |\n\nब्राह्मणः तेन वेदः च यज्ञः च विहितः पुरा - ओम [संसार का वाहक और\nवह जो विश्व में व्याप्त है], तत् (वेदों के माध्यम से, केवल अप्रत्यक्ष रूप से जाना जाता है)।\nवह जो सक्षम है] शनि। [वह जो सभी शुभ गुणों से परिपूर्ण है] - ये भगवान के तीन हैं\nनाम. उन भगवान् ने ही वेद, वेदांग और यज्ञों को तैयार किया।\n\nॐ, तत् और सत् ये तीन नाम ईश्वर के हैं। प्रभु, प्रभु की याद के लिए\nइस प्रकार अनुसन्धान का उपयोग ऋषियों द्वारा आह्वान के लिए किया जाता था। प्रभु का नाम हमारा है\nनाम जैसा नहीं. उसका नाम उसका विशेषण है। ओम' भगवान को समर्पित (80165109)\nनाम यह तीन अक्षरों (ए, यू, एम) में मानव जीवन के सभी पहलुओं को बताता है।\nजिसमें सारा संसार पढ़ा जाता है, जिसमें सारा संसार गुँथा हुआ है - वही ॐ है।\nओमकारा यह कहने के लिए कि हम जो भी कर्म करते हैं वह उसे समर्पित है\nउपयोग यदि शुरुआत में 'हरिः ॐ' कहा जाए - \"आगे बस मुझे ही करना है।\"\nभगवान को समर्पित” जैसा कहा गया है। [ओमकारा के बारे में अधिक व्याख्या के लिए अध्याय-7\nश्लोक 8-9 देखें)।\n\n'ततः' का अर्थ है जो पूर्ण है। भगवान सभी गुणों के स्वामी हैं। जो पूर्ण है वही सब कुछ है\nवेदों से परिपूर्ण है. तो वह \"तत्\" है और \"सत्\" का अर्थ है दोष रहित\nॐ-तत्-सत् वैदिक काल के नाम हैं। अच्युतायनम् हम आज कहते हैं;,\nअनंतायनमः, गोविंदाय नमः भी यही अर्थ देता है। अ-च्युत का अर्थ है जो\nइसका मतलब यह है कि वह स्वभाव से ही भ्रष्ट नहीं है। उसके अतिरिक्त इस संसार का कोई अस्तित्व नहीं है। वह सब कुछ है\nसंसार का आधार. और दूसरा नाम - अनंता. जो बाहर है वह अनंत है। जिनके गुणों का अंत\nअन्यथा वह अनंत है. तीसरा नाम है गोविंदा. गो- अर्थात् वेद। संपूर्ण वेदों से\nप्रतिपद्य प्रभु-गोविन्द। यहाँ संक्षेप में - ॐ तत् सत् का अर्थ है\n“जगदाधर, समस्त गुणपूर्ण, समस्त वेद प्रतिपद्य, समस्त दोष दोरोना\n\nइसका अर्थ है 'भगवान'. ऐसे भगवान ने वेदों की रचना की, जिससे 'ज्ञानी बने'\nउन्होंने ज्ञान से कर्म करने के लिये वेदयज्ञ की रचना की और यज्ञ की रचना की।\n\nहममें से कुछ लोग इसे वेद-'पौरुषेय' कहते हैं, और अन्य वेद-'अपौरुषेय' कहते हैं।\nऐसे लोग हैं जो बहस करते हैं। सृष्टि से पहले भगवान के सर्वोच्च व्यक्तित्व द्वारा उच्चारित वैदिक पौरुषेय; ये है\nभगवान द्वारा प्रत्येक कल्प में अनन्त काल तक अपौरुषेय का उच्चारण किया जाता है।\nहाँ भी. इसलिए इस पर बहस करना व्यर्थ है.\n\nतस्मादोमित्युदाहृत्य यज्ञदानतपहक्रियाः |\nप्रवर्तन्ते विधानोक्तः सताखं ब्रह्मवादिनम्",
  "17.6": "अस्त्र विहितं घोरं तप्यन्ते ये तपः जनः |\n\nदंभ अहंकार संयुक्तः काम राग बाला अन्विताः\n\nकर्षयन्तः शरीरस्तं भूतग्रामम् अचेतसः।\n\nमाम् च एव अन्तः शरीयस्तं तं विद्धि असुरनिश्चयन् -- कुछ लोग शास्त्र के आदेशों से परे चले जाते हैं।\nबुरे पाप करो; पाखंडी और अपमानजनक ढंग से. इच्छाएँ और रुचियाँ ही उनकी उपलब्धि हैं\nसमर्थन. ऐसे शरारती लोग अपने शरीर [शरीर] में भूत क्षमा का शासन करते हैं।\nदेवतागण] की उपेक्षा की जाती है। वे शरीर के भीतर मेरी महानता को नकारते हैं। ऐसे\nजान लें कि वे तमस प्रकृति के हैं।\n\nयहां कृष्ण बताते हैं कि भक्ति का निम्नतम रूप तमसा श्रद्धा क्या है।\nकुछ लोग शास्त्र के आदेशों से परे तपस्या करते हैं। उस तपस्या के पीछे का उद्देश्य भयंकर है। यहाँ\nतपस्सु केवल ख़ुशी-मुनियों द्वारा की जाने वाली तपस्या नहीं है। जो लगन से किया जाता है\nकर्म भी तप बन सकता है [इस पर अधिक विवरण इस अध्याय के अगले भाग (श्लोक) में है\n14-19)]। तपस्या करें ताकि तपस्या करते समय हमें अच्छा महसूस हो\nसंसार की भलाई के लिए तपस्या कर सकते हैं या कर सकते हैं। उदाहरण के लिए गायत्री:\n\nयहाँ \"धियो योनः प्रचोदयात्\" में है \"हे भगवान, हम सभी को अच्छी बुद्धि दे।\"\nसात्विक भक्ति है. सात्विक संसार में सभी का भला करने की तपस्या है\nप्रायश्चित यह छोड़ो. \"मुझे केवल अच्छा दो\" राजस की पूजा है।\n\"दूसरा बिगड़े-मैं अच्छा बनूँ\" यही उपासना है। तमस ये हैं\nएक विश्व-विध्वंसक क्रूरता।\n\nशास्त्रीय तपस्या का अर्थ है: भगवान की सर्वोच्चता का एहसास करना, दूसरों के बारे में बुरा सोचना।\nबिना कुछ किये संसार में सबका भला करना ही तपस्या है। 'सर्वोत्कर्षे देवा देवस्य।'\n'विष्णो महा तत्पर्यम्' - सभी शास्त्रों में से तात्मार्यम् - का अर्थ है 'सर्वोच्च भगवान'।\nसहमत न होना शास्त्र विरुद्ध है। भावना यह है कि इसे स्वीकार करना दुनिया के लिए बुरा होगा\nमन में उठे तो अनैतिक भी हो जाता है। जो अशास्त्रीय नहीं है\nभगवान को प्रिय नहीं. स्वार्थवश दूसरे का बुरा चाहने से किया गया एक कर्म संबंधी 'जघन्य कार्य'।\nकृष्ण ने यहां चेतावनी दी है कि ऐसा लगेगा. ऐसी हरकत के पीछे पाखंड है और\nअहंकार है. यह देवताओं द्वारा कभी स्वीकार नहीं किया जाता।\n\nकुछ लोग अपने शारीरिक बल से दूसरों को वश में करने की बुरी मंशा रखते हैं\nवे पाप करते हैं. वह जो अपनी इच्छाओं, अपनी इच्छाओं में बाधा डालता है\nयदि वे उत्तर नहीं देते तो उनके मन में यह बुरा विचार आता है कि उन्हें समाप्त कर देना चाहिए। इस प्रकार\nजो लोग अभिमान, अहंकार, संकीर्ण वासना, स्वार्थ, लालच से कार्य करते हैं\nमैकरोन्स वे अपने शरीर को दंडित करते हैं और तपस्या करते हैं। लेकिन उनके लिए, उनका\nशरीर में भूतग्राम (देवताओं का समूह) का ज्ञान नहीं रहता। सारी मंडली\nउपेक्षा करो, देवताओं के भीतर भगवान की उपेक्षा करो, और एक शरीर बन जाओ\nजो क्रियान्वित करता है वह राक्षस है। उन्होंने कहा, 'इंद्रिय कर्म ही सब कुछ है-उससे परे\nवे जानते हैं कि कुछ भी नहीं है.\n\nकृष्ण का यह वर्णन देखकर हमारे-आपके भीतर (प्रभाव से पला हुआ) यह असुर\nहम जानते हैं कि कट्टरता कितनी भयानक होती है. हम अपने-अपने यहां ऐसा करते हैं\nइसे पहचाना जाना चाहिए और कार्रवाई में सुधार किया जाना चाहिए। इसके लिए कृष्ण ने निम्नलिखित श्लोक में भोजन, तप,\nदाना आदि में वे बताते हैं कि सात्विक, राजस और तमस प्रकार कैसे होते हैं।\n\nसंतुष्ट सर्वस्य त्रिविधो भवति प्रियाः।\n\nयज्ञस्थपस्थ दानं तेषां भेदमीम श्रृणु",
  "17.24": "तस्मात् ॐ इति उदाहृत्य यज्ञ दान तपः क्रियाः |\n\nप्रवर्तन्ते विधान उक्तः सदातम् ब्रह्मवादिनम् अत: शास्त्र आज्ञा के अनुसार,\nब्रह्मा के भक्तों के यज्ञ, दान और तपस्या में सदैव भगवान का नाम 'ओम' होता है।\nवे स्मृति से जुड़ते हैं।\n\nयहां कृष्ण कर्म में ओंकार के उपयोग के महत्व को बताते हैं। एक जैसा कि हम जानते हैं\nयदि वह वेदज्जा बनना चाहता है, तो उसे ओंकार की शिक्षा देनी होगी; यज्ञ के आरंभ और अंत में ओंकार\nकहना चाहिए; वैदिक जप के आरंभ और अंत में ओंकार होना चाहिए। यह सब अतीत से आता है\nअनुष्ठान. हम जो भी काम करते हैं, उसे शुरू करते समय, \"यह भगवान का है।\"\nइसे पूजा के रूप में करने का संकल्प लेना” और अंत में “मैं\nजो किया गया है उसे भगवान स्वीकार करें'' यही इसका मूल उद्देश्य है। ऐसा ओमकारा ने कहा\nकर्म करने की प्रथा अतीत से बढ़ी है। इस दृष्टिकोण से हमारे पास कोई नहीं है\nयदि कोई पारायण, होम, हवन, यज्ञ, तप, दान करता है तो भी यह सात्विक कर्म माना जाता है।\n\nतात्यानाभिसन्धाय फलं यज्ञतपहक्रियाः।\nदानक्रियाश्च विद्याः क्रियन्ते मोक्षकांक्षिभिः 125।\n\nतत् इति अनाभिसंध्या फलम् यज्ञ तपः क्रियाः |\nदान क्रियाः च विविधः क्रियन्ते मोक्षकांक्षीभिः - फल की इच्छा किये बिना मोक्ष चाहने वाले सज्जन लोग,\n\"तत्\" नामक भगवान के लिए विभिन्न यज्ञ, दान और तपस्या की जाती है।\n\nहमने पहले देखा है कि 'तत्' भगवान को संदर्भित करता है जो संपूर्ण वैदिक पाठ है।\nयहां कृष्ण बताते हैं कि हम जो कर्म करते हैं उसमें \"तत्\" का क्या अर्थ है।\nवेदमाता गायत्री का संक्षिप्त रूप है (C005001; प्रथम और अंतिम अक्षर)।\nइस प्रकार यह भगवान का मुख्य नाम गायत्री वाच्य है। कर्म में 'तत्' है\nइसमें कहा गया है कि भगवान जो फल देते हैं। 'तत्' का अर्थ है किसी भी सांसारिक फल की इच्छा न करना,\nकर्म भगवान के प्रेम के लिए किया जाता है जो बंधन से मुक्त करता है और मोक्ष देता है। बस इतना ही\nत्याग, तपस्या या दान हो सकता है। यहाँ तक कि जब बुद्धिमान लोग दान देते हैं\nवह किसी सांसारिक फल की इच्छा किये बिना दान देता है। उदाहरण के लिए अन्नदान: चावल का प्रशंसक\nलक्ष्मी; अन्नदान का अर्थ है लक्ष्मी से नारायण, दाता के भीतर वैश्वान का रूप\nसमर्पण. इसी प्रकार कन्यादान: कन्यादान के दौरान दूल्हे की संपत्ति, स्थिति,\nदान करना वेतन के बारे में नहीं है. लड़के के अंदर लड़की के बजाय लक्ष्मी\nनारायण को अर्पण करने के भाव से देना। इस प्रकार उद्धारकर्ता\n\"ईश्वर सभी चीजों का कर्ता है-उसकी पूजा ही उसका उद्देश्य है\" की कोई सांसारिक इच्छा नहीं है।\nबिना क्रिया किये. यह \"तत्' है,\n\nसद भवे साधुभावे च सदित्येतत् प्रयुज्यते |\nप्रशस्ते कर्माणि तथा सच्चभदः पार्थ युज्यते",
  "17.25": "तस्मात् ॐ इति उदाहृत्य यज्ञ दान तपः क्रियाः |\n\nप्रवर्तन्ते विधान उक्तः सदातम् ब्रह्मवादिनम् अत: शास्त्र आज्ञा के अनुसार,\nब्रह्मा के भक्तों के यज्ञ, दान और तपस्या में सदैव भगवान का नाम 'ओम' होता है।\nवे स्मृति से जुड़ते हैं।\n\nयहां कृष्ण कर्म में ओंकार के उपयोग के महत्व को बताते हैं। एक जैसा कि हम जानते हैं\nयदि वह वेदज्जा बनना चाहता है, तो उसे ओंकार की शिक्षा देनी होगी; यज्ञ के आरंभ और अंत में ओंकार\nकहना चाहिए; वैदिक जप के आरंभ और अंत में ओंकार होना चाहिए। यह सब अतीत से आता है\nअनुष्ठान. हम जो भी काम करते हैं, उसे शुरू करते समय, \"यह भगवान का है।\"\nइसे पूजा के रूप में करने का संकल्प लेना” और अंत में “मैं\nजो किया गया है उसे भगवान स्वीकार करें'' यही इसका मूल उद्देश्य है। ऐसा ओमकारा ने कहा\nकर्म करने की प्रथा अतीत से बढ़ी है। इस दृष्टिकोण से हमारे पास कोई नहीं है\nयदि कोई पारायण, होम, हवन, यज्ञ, तप, दान करता है तो भी यह सात्विक कर्म माना जाता है।\n\nतत् इति अनाभिसंध्या फलम् यज्ञ तपः क्रियाः |\nदान क्रियाः च विविधः क्रियन्ते मोक्षकांक्षीभिः - फल की इच्छा किये बिना मोक्ष चाहने वाले सज्जन लोग,\n\"तत्\" नामक भगवान के लिए विभिन्न यज्ञ, दान और तपस्या की जाती है।\n\nहमने पहले देखा है कि 'तत्' भगवान को संदर्भित करता है जो संपूर्ण वैदिक पाठ है।\nयहां कृष्ण बताते हैं कि हम जो कर्म करते हैं उसमें \"तत्\" का क्या अर्थ है।\nवेदमाता गायत्री का संक्षिप्त रूप है (C005001; प्रथम और अंतिम अक्षर)।\nइस प्रकार यह भगवान का मुख्य नाम गायत्री वाच्य है। कर्म में 'तत्' है\nइसमें कहा गया है कि भगवान जो फल देते हैं। 'तत्' का अर्थ है किसी भी सांसारिक फल की इच्छा न करना,\nकर्म भगवान के प्रेम के लिए किया जाता है जो बंधन से मुक्त करता है और मोक्ष देता है। बस इतना ही\nत्याग, तपस्या या दान हो सकता है। यहाँ तक कि जब बुद्धिमान लोग दान देते हैं\nवह किसी सांसारिक फल की इच्छा किये बिना दान देता है। उदाहरण के लिए अन्नदान: चावल का प्रशंसक\nलक्ष्मी; अन्नदान का अर्थ है लक्ष्मी से नारायण, दाता के भीतर वैश्वान का रूप\nसमर्पण. इसी प्रकार कन्यादान: कन्यादान के दौरान दूल्हे की संपत्ति, स्थिति,\nदान करना वेतन के बारे में नहीं है. लड़के के अंदर लड़की के बजाय लक्ष्मी\nनारायण को अर्पण करने के भाव से देना। इस प्रकार उद्धारकर्ता\n\"ईश्वर सभी चीजों का कर्ता है-उसकी पूजा ही उसका उद्देश्य है\" की कोई सांसारिक इच्छा नहीं है।\nबिना क्रिया किये. यह \"तत्' है,\n\nसद भवे साधुभावे च सदित्येतत् प्रयुज्यते |\nप्रशस्ते कर्माणि तथा सच्चभदः पार्थ युज्यते",
  "18.11": "देहधारी के लिए कर्मों का पूर्णतः त्याग सम्भव नहीं। जो कर्मफल का त्यागी है — वही त्यागी कहलाता है।\n\n'अशक्यम्' — शरीर में रहते हुए कर्म छोड़ना असम्भव। 'कर्मफलत्यागी' — जो फल की आसक्ति छोड़ता है — वही वास्तविक त्यागी। कर्म अनिवार्य — फलासक्ति ऐच्छिक।",
  "18.8": "दुःखरूप है इसलिए — या देहपीड़ा के भय से — जो कर्म छोड़ता है — वह राजसिक त्याग करता है — उसे त्याग का फल नहीं मिलता।\n\n'दुःखम् इति' — कर्म दुःखदायक है इसलिए। 'देहपीड़ां भयात्' — शारीरिक कष्ट के डर से। यह राजसिक त्याग — 'मुझे कष्ट है' — इस कारण छोड़ना। न सात्त्विक, न तामसिक — राजसिक।",
  "18.1": "अर्जुन उवाच —\nसंन्यासस्य महाबाहो तत्त्वमिच्छामि वेदितुम् ।\nत्यागस्य च हृषीकेश पृथक्केशिनिषूदन ॥\n\n'हे महाबाहो, संन्यास और त्याग का तत्त्व — दोनों को अलग-अलग जानना चाहता हूँ।'\n\nअठारहवें अध्याय का आरम्भ — समग्र गीता का उपसंहार। 'हृषीकेश' — इन्द्रियों के स्वामी। 'केशिनिषूदन' — केशि-दैत्य का नाश करने वाले। अर्जुन दो शब्दों का भेद पूछता है — संन्यास और त्याग।",
  "18.4": "हे पुरुषव्याघ्र, त्याग के बारे में मेरा यह निश्चित मत सुनो — त्याग तीन प्रकार का कहा गया है।\n\n'पुरुषव्याघ्र' — पुरुषों में सिंह। तीन प्रकार के त्याग — सात्त्विक, राजसिक, तामसिक — का वर्णन होगा। प्रथम कृष्ण का स्वयं का मत प्रस्तुत करते हैं।",
  "18.5": "यज्ञ, दान और तप — ये कर्म छोड़ने योग्य नहीं। यज्ञ, दान, तप — बुद्धिमानों को पवित्र करते हैं।\n\n'न त्याज्यम्' — यज्ञ-दान-तप कभी नहीं छोड़ने चाहिए। 'मेधाविनाम् अपि पावनानि' — बुद्धिमानों को भी पवित्र करते हैं। यह कृष्ण का स्पष्ट मत — केवल फलकामना छोड़नी है, कर्म नहीं।",
  "18.9": "'करना चाहिए' — इस भाव से जो नियत कर्म किया जाता है — आसक्ति और फल छोड़कर — वह सात्त्विक त्याग माना जाता है।\n\n'कार्यम् इति' — करना ही चाहिए — कर्तव्यबुद्धि से। 'सङ्गं त्यक्त्वा' — आसक्ति छोड़कर। 'फलं च एव' — और फल भी। यही सात्त्विक त्याग — भगवान् का अनुशंसित।",
  "18.15": "मनुष्य शरीर, वाक्, मन से — जो भी न्याय्य या विपरीत कर्म आरम्भ करता है — उसके ये पाँच कारण हैं।\n\n'कायेन वाचा मनसा' — तीन करण। 'न्याय्यं वा विपरीतं वा' — उचित या अनुचित — किसी भी कर्म के ये पाँच कारण। अतः अकेले जीव को कर्ता नहीं माना जा सकता — दैव (भगवान्) का योगदान अनिवार्य।",
  "18.16": "ऐसा होने पर भी जो इस (जगत्) में केवल अपने को कर्ता देखता है — वह दुर्मति अशुद्धबुद्धि के कारण नहीं देख पाता।\n\n'अकृतबुद्धित्वात्' — अशुद्धबुद्धि के कारण। 'न सः पश्यति' — वह नहीं देख पाता। जो केवल जीव को कर्ता मानता है — वह अज्ञानी है। पाँचों कारण देखने वाला — यथार्थदर्शी।",
  "17.28": "अश्रद्धया हुतं दत्तं तपः तप्तं कृतं चयत् |\n\nअसत् इति उच्यते पार्थ न च तत् प्रेत न इहा - कर्म करने में परिश्रम के बिना,\nप्रभु में ईमानदारी के बिना, किसी की मजबूरी या डर के बिना, पूर्ण विश्वास के बिना\nकरने का कार्य व्यर्थ है। बिना श्रद्धा के किया गया ऐसा दान, तप, यज्ञ अथवा अन्य कोई कार्य\n\nइसमें कर्म का कोई फल नहीं, परा में कोई फल नहीं।\n\nइति सप्तदशो$ध्यायः\nसत्रहवाँ अध्याय समाप्त हो गया\n\nक्या यह सच है?\n\nअध्याय अठारह\n\nपिछले सत्रह अध्यायों में कृष्ण ने बताया कि हमारी उपलब्धि कैसी होनी चाहिए, वह यहाँ है\nउन्होंने उपलब्धि का संदेश संग्रह के रूप में हमारे सामने प्रस्तुत किया है। इस अध्याय के अतिरिक्त\nउपलब्धि के त्रय की एक और व्याख्या भी है जो सत्रह में नहीं बताई गई है।\nयही गीत का निष्कर्ष है. यह अध्याय अर्जुन के प्रश्न से प्रारंभ होता है।\n\nअर्जुन उवाच |\nसंन्यासस्य महाबाहो तत्त्वमिच्छामि वेदितुम |\nत्यागस्य च हृषीकेश पृथक केशिनिसुदाना ॥1॥\n\nअर्जुन उवाच-अर्जुन ने पूछा:\n\nसंन्यासस्य महाबाहो तत्वं इच्छामि वेदितुम।\n\nत्यागस्य च हृषीकेश पृथक केशिनिसुदाना - महाबाहो, तप और त्याग का।\nदूरी कितनी है हे हृषिकेश, मुझे इसकी सच्चाई बताओ, हे केशिनिसुदन।\n\nकृष्ण ने पहले वैराग्य के बारे में कहा था; फिर पिछले अध्याय में यज्ञ, दान, तप\nकर्म कहा. यहां हम थोड़ा भ्रमित हो जाते हैं. तो अर्जुन कृष्ण में कर्मत्यागा\nऔर कर्मसंन्यास पूछता है कि दोनों के बीच कितनी दूरी है? त्याग और तपस्या\nयद्यपि उपरोक्त दोनों शब्दों का अर्थ एक ही प्रतीत होता है, परंतु वे भिन्न हैं।\nसंन्यास और त्याग का मूल अर्थ क्या है 9 इनकी अलग-अलग व्याख्या कैसे करें\nवह अर्जुन का प्रश्न है।\n\nयहां अर्जुन कृष्ण का प्रतिनिधित्व महाबाहो, हृषिकेश और केशिनिसुदन नामक तीन दिव्यांगों द्वारा किया गया है।\nनामों से सम्बोधित किया जाता है। यह केवल उनमें और कृष्ण में गुरुभक्ति को संदर्भित करता है\nयह प्रश्न यहाँ यह समझकर पूछा गया है कि वह वासुदेव का पुत्र नहीं है, बल्कि भगवान का पुत्र है\nयह स्पष्ट है. \"महाबाहु' का अर्थ है लंबे समय तक, कठोर, शत्रुओं का सामना करना\nतोलुगुलुल्लावा का मतलब सतही होता है। बुराई को दबाना और सभ्य की रक्षा करना, सबके अंदर\nइस दिव्य नाम के पीछे मूल अर्थ अज्ञान का नाश करने वाला, जगत का रक्षक है।\nअब 'हृषिका' का अर्थ है इन्द्रियाँ। पिंडदान के भीतर सभी इंद्रियों का नियंत्रण है\nभगवान हृषिकेश. \"केसी' का अर्थ है सूर्य की किरण; वायु देवता (एन9 खग्गेडा 10.136.07)।\n\nसौरमंडल में; प्राणदेव में ही उनका अंतरतम भक्त है; हमारी इच्छाओं को पूरा करना,\n\n*केशिनीसुदन' भगवान हैं जो हमें शक्ति से भर देते हैं। वह ब्रह्मांड और पिंडदान के भीतर संपूर्ण है\nवह महाशक्ति जो ब्रह्मांड को नियंत्रित करती है। (ज्यादातर जगहों पर 'केशिनीशुदाना' शब्द का प्रयोग किया जाता है, लेकिन\nसही शब्द केशिनिसुदन है)।\nभगवान का वचन\nकाम्यानं कर्मं न्यासं संन्यासं कवयो विदुः।\n\nभ्र भ्र\nसर्वकर्मफलत्यागं प्राहुस्वगं विचक्षणः ॥2॥\n\nभगवान उवाच - भगवान ने कहा:\nकाम्यानं कर्मं न्यासं संन्यासं कवयः विदुः |\nसर्वकर्मफल त्यागम् प्राहुः त्यागम् विचक्षणः - जो वासनापूर्ण कर्मों को त्यागना जानता है।\nइसे 'संन्यास' कहा जाता है। जो सभी कर्मों के फल को ही छोड़ना जानता है उसे \"त्याग\" कहते हैं।\nयहां उल्लिखित संन्यास गृहस्थों सहित सभी साधकों पर लागू होने वाला संन्यास है।\nतप दो प्रकार का होता है. एक है कर्म का फल, दूसरा है इच्छाओं से प्रेरित\nकर्म का ही त्याग करना। यहां त्याग का अर्थ कर्म का त्याग करना नहीं है, बल्कि क्या है\nकर्म जो भी हो, करो - बिना कोई परिणाम चाहे। अत: कर्मत्याग\nअर्थात: वेदाध्ययन का त्याग, संध्यावंदन का त्याग, वृतानुष्ठान का त्याग आदि।\nऐसा नहीं बल्कि इसका अर्थ है अच्छे कर्म करना और उसका फल न चाहना। जो\nजो भी कर्म करो, भगवत्प्रेम से करो - फल की इच्छा से नहीं।\nयहाँ दो विशेष शब्दों का प्रयोग हुआ है काव्यः और विचक्षणा। शब्दार्थ\nजो रिश्ते को जानते हैं—कवि; जो अर्थ को जानते हैं, अनुभव करते हैं और मनाते हैं\nटोही. \"कवि और संत तप और त्याग का यही वर्णन करते हैं\"\nकृष्ण ने कहा.\nवस्तं दोषवादित्यके कर्म प्रहुर्मनिशिनाः |\nयज्ञादतपहकर्म की व्यर्थ सीमा चापरे 3 है।\n\nवस्तं दोषवत् इति एक कर्म प्राहुः मनीषिणः |\n\nयज्ञादतपहकर्म के वषटं इति च अपरे -",
  "18.13": "हे महाबाहो, सभी कर्मों की सिद्धि के लिए सांख्यशास्त्र में ये पाँच कारण बताए गए हैं — उन्हें जानो।\n\n'पञ्च एतानि' — पाँच कारण। सांख्यशास्त्र — ब्रह्मसूत्र। 'सर्वकर्मणाम्' — सभी कर्मों की सिद्धि के लिए। ये पाँच — अगले श्लोक में बताए जाएंगे।",
  "18.10": "सात्त्विक त्यागी — अप्रिय कर्म से द्वेष नहीं करता, प्रिय कर्म में आसक्त नहीं होता — संशयरहित, बुद्धिमान।\n\nत्यागी का लक्षण — 'न द्वेष्टि अकुशलं कर्म' — बुरे कर्म से घृणा नहीं (क्योंकि कर्तव्य है), 'न कुशले अनुषज्जते' — अच्छे कर्म में भी आसक्ति नहीं। सात्त्विक त्यागी — शुद्धसत्त्व में स्थित, मेधावी, संशयमुक्त।",
  "18.20": "जिस ज्ञान से — विभक्त सभी भूतों में — एक अविभक्त परमतत्त्व दीखता है — वह सात्त्विक ज्ञान जानो।\n\n'अविभक्तं विभक्तेषु' — विभिन्न प्राणियों में एक अविभक्त ब्रह्म (भगवान्) देखना। यह सात्त्विक ज्ञान — सर्वत्र भगवद्व्याप्ति दर्शन। मध्वमत में — 'अविभक्त' = भगवान् (एकः), 'विभक्त' = अनेक जीव।",
  "18.23": "जो कर्म नियत है, आसक्ति-रहित, राग-द्वेष के बिना, फल की इच्छा के बिना किया जाए — वह सात्त्विक कहा जाता है।\n\nसात्त्विक कर्म — 'नियतम्' (शास्त्रविहित), 'संग-रहित', 'अनुद्वेग', 'निराशी' (फलेच्छा-रहित)। ये चार लक्षण। कर्तव्यभावना से निःसंग होकर किया गया कर्म — सात्त्विक।",
  "18.12": "त्याग न करने वालों को मृत्यु के बाद कर्म के तीन प्रकार के फल मिलते हैं — अनिष्ट, इष्ट और मिश्र। संन्यासियों को कहीं भी नहीं।\n\n'अत्यागिनाम्' — जो त्यागी नहीं। 'प्रेत्य' — मृत्यु के बाद। तीन प्रकार — अनिष्ट (बुरा), इष्ट (अच्छा), मिश्र (दोनों)। 'संन्यासिनाम् क्वचित्' — वास्तविक संन्यासियों को कभी नहीं — वे फलातीत।",
  "18.24": "जो कर्म फलकामना से, या अहंकार से, बहुत परिश्रम से किया जाए — वह राजसिक कहा गया है।\n\n'यत्तु कामेप्सुना' — फल की चाहत से। 'अहंकारेण' — अहंकार से। 'बहुलायासम्' — बहुत परिश्रम से। राजसिक कर्म — फलकामना और अहंकार दोनों से प्रेरित।",
  "18.21": "जो ज्ञान सभी भूतों में अलग-अलग भिन्न तत्त्व देखता है — वह राजसिक ज्ञान जानो।\n\n'पृथक्त्वेन तु' — पृथकरूप से। 'नाना भावान् पृथग्विधान्' — अनेक भिन्न-भिन्न तत्त्व। 'सर्वेषु भूतेषु' — सब जीवों में। यह राजसिक ज्ञान — भिन्नता देखता है, किन्तु मूल एकता (भगवान्) नहीं।",
  "18.25": "अनुभव न सोचकर, हानि-बन्धन-सामर्थ्य की परवाह न करके, मोह से जो कर्म आरम्भ किया जाए — वह तामसिक कहा जाता है।\n\n'मोहात्' — मोह से आरम्भ। 'हिंसाम् अनपेक्ष्य' — हिंसा-परिणाम सोचे बिना। 'पौरुषम् अनपेक्ष्य' — अपनी सामर्थ्य सोचे बिना। तामसिक कर्म — मूढ़तापूर्ण, परिणाम-अनालोचित।",
  "18.29": "हे धनञ्जय, बुद्धि और धृति भी — गुणों के अनुसार — तीन प्रकार की हैं — उन्हें मैं अलग-अलग सम्पूर्णतः कहूँगा।\n\n'बुद्धेः भेदम् धृतेश्च' — बुद्धि और धृति दोनों के भेद। 'गुणतः' — गुणों के अनुसार। 'पृथक्त्वेन' — अलग-अलग। यह त्रिगुण विश्लेषण का अगला चरण।",
  "18.6": "किन्तु हे पार्थ, इन कर्मों को भी आसक्ति और फल छोड़कर करना चाहिए — यही मेरा उत्तम निश्चित मत है।\n\n'एतान्यपि' — इन यज्ञ-दान-तप को भी। 'सङ्गं त्यक्त्वा' — आसक्ति छोड़कर। 'फलानि च' — और फल भी। यही 'सात्त्विक त्याग' है — कर्तव्य करो, फल-आसक्ति छोड़ो।",
  "18.7": "नियत (विहित) कर्म का संन्यास उचित नहीं। मोह से उसका त्याग तामसिक कहा गया है।\n\n'नियतस्य' — शास्त्रविहित कर्म का। 'संन्यासः' — त्याग। 'मोहात्' — अज्ञान से। 'तामस उदाहृतः' — तामसिक त्याग। मोह से — 'यह कठिन है', 'देह को कष्ट होगा' — ऐसा मानकर कर्म छोड़ना तामस है।",
  "18.19": "गुणसंख्यान शास्त्र में — ज्ञान, कर्म और कर्ता भी तीन-तीन प्रकार के गुणभेद से कहे गए हैं — उन्हें सुनो।\n\n'गुणसंख्यान' — गुणों की संख्या बताने वाला शास्त्र। ज्ञान, कर्म, कर्ता — तीनों त्रिगुणात्मक। सात्त्विक, राजसिक, तामसिक — यह विभाजन आगे होगा।",
  "18.27": "जो आसक्त, फल का लालची, लोभी, हिंसक स्वभाव, अशुद्ध, हर्ष-शोक से युक्त है — वह राजसिक कर्ता कहा जाता है।\n\nराजसिक कर्ता — आसक्त, फलार्थी, लोभी, हिंसक, अशुद्ध, हर्ष-शोक में डोलने वाला। इस कर्ता में सात्त्विक कर्ता के सभी गुणों का अभाव।",
  "18.22": "जो ज्ञान एक कार्य में — जैसे सब कुछ — अकारण, अतत्त्वार्थक और अल्प हो — वह तामसिक कहा गया है।\n\n'एकस्मिन् कार्ये' — एक छोटी वस्तु में। 'सक्तम्' — आसक्त। 'अकारणवत्' — कारणहीन। 'अतत्त्वार्थवत्' — सत्य से रहित। 'अल्पं च' — अल्प। तामसज्ञान — संकुचित, अयुक्तिपूर्ण, अवास्तविक।",
  "18.17": "जिसका भाव अहंकारयुक्त नहीं, जिसकी बुद्धि लिप्त नहीं — वह इन लोगों को मारकर भी न मारता है, और बँधता भी नहीं।\n\n'यस्य नाहंकृतो भावः' — जिसमें 'मैंने किया' का भाव नहीं। 'बुद्धिर्न लिप्यते' — बुद्धि कर्मफल से नहीं लिपती। ऐसा व्यक्ति कर्म करते हुए भी — निर्लिप्त। यही गीता का कर्मयोगी।",
  "18.36": "हे भरतर्षभ, अब तीन प्रकार के सुख सुनो — जिसमें अभ्यास से रमण होता है और जहाँ दुःख का अन्त होता है।\n\n'त्रिविधं सुखम्' — तीन प्रकार के सुख। 'अभ्यासात् रमते' — अभ्यास से आनन्द मिलता है। 'दुःखस्यान्तं' — दुःख का अन्त। सुख का वर्गीकरण — अनुभव और परिणाम दोनों पर आधारित।",
  "18.31": "हे पार्थ, जो बुद्धि — धर्म-अधर्म, कर्तव्य-अकर्तव्य को अयथार्थ रूप से जानती है — वह राजसिक बुद्धि है।\n\n'अयथावत्' — यथार्थ नहीं। धर्म को अधर्म और अधर्म को धर्म समझना — राजसिक बुद्धि। आंशिक सत्य देखती है — पूर्ण नहीं।",
  "18.26": "जो सक्त नहीं, अहंकारशून्य बोलने वाला नहीं, धैर्य और उत्साहयुक्त, सिद्धि-असिद्धि में निर्विकार — वह सात्त्विक कर्ता कहा जाता है।\n\nसात्त्विक कर्ता के लक्षण — (१) असक्त; (२) अनहंवादी (मैं करता हूँ — नहीं कहता); (३) धृतियुत; (४) उत्साहयुत; (५) सिद्धि-असिद्धि में निर्विकार। यही आदर्श कर्मयोगी।",
  "18.38": "जो सुख विषय-इन्द्रिय-संयोग से उत्पन्न होता है — आरम्भ में अमृत जैसा, परिणाम में विष जैसा — वह राजसिक कहा गया है।\n\n'विषयेन्द्रियसंयोगात्' — विषय और इन्द्रिय के संयोग से। 'आदौ अमृतोपमम्' — शुरू में मधुर। 'परिणामे विषम् इव' — अन्त में कड़वा। राजसिक सुख — सांसारिक भोग — पहले आकर्षक, बाद में पीड़ाजनक।",
  "18.35": "हे पार्थ, दुर्मेधा व्यक्ति जिस धृति से — निद्रा, भय, शोक, विषाद, मद — इन्हें नहीं छोड़ता — वह तामसिक धृति है।\n\n'दुर्मेधाः' — बुरी बुद्धि वाला। 'न विमुञ्चति' — नहीं छोड़ता। निद्रा-भय-शोक-विषाद-मद — ये पाँच तामसिक बन्धन। तामसिक धृति — इन्हें पकड़े रखती है।",
  "18.14": "अधिष्ठान, कर्ता, करण, विभिन्न चेष्टाएँ और पाँचवाँ दैव — ये पाँच कारण हैं।\n\nपाँच कारण — (१) अधिष्ठान (शरीर — कर्म का स्थान); (२) कर्ता (जीव — करने वाला); (३) करण (इन्द्रियाँ — साधन); (४) विभिन्न चेष्टाएँ (प्राण-वायु — विभिन्न क्रियाएँ); (५) दैव (भगवान् — पाँचवाँ, सर्वोपरि)। इनमें 'दैव' = भगवान् — सर्वनियन्ता।",
  "18.18": "ज्ञान, ज्ञेय और परिज्ञाता — ये तीन कर्म की प्रेरणा हैं। करण, कर्म और कर्ता — ये तीन कर्म का संग्रह हैं।\n\n'ज्ञानम्' — ज्ञान (कर्म का उद्देश्य); 'ज्ञेयम्' — जानने योग्य वस्तु; 'परिज्ञाता' — जानने वाला। ये तीन प्रेरणा। 'करणम्' — साधन; 'कर्म' — क्रिया; 'कर्ता' — करने वाला। ये तीन कर्म-संग्रह।",
  "18.34": "हे पार्थ, जिस धृति से — फलकांक्षी व्यक्ति — धर्म, अर्थ, काम को आसक्ति से धारण करता है — वह राजसिक धृति है।\n\n'फलाकांक्षी' — फल की इच्छा वाला। 'प्रसङ्गेन' — आसक्ति से। 'धर्म-काम-अर्थ' — तीन पुरुषार्थ (मोक्ष छोड़कर)। राजसिक धृति — तीन पुरुषार्थों में, मोक्ष नहीं।",
  "18.30": "हे पार्थ, जो बुद्धि — प्रवृत्ति-निवृत्ति, कर्तव्य-अकर्तव्य, भय-अभय, बन्धन-मोक्ष को जानती है — वह सात्त्विक बुद्धि है।\n\n'धर्म-अधर्म' — कर्तव्य-अकर्तव्य। 'बन्धन-मोक्ष' — संसार और मुक्ति। सात्त्विक बुद्धि — इन सबको यथार्थ रूप से जानती है। 'या वेत्ति' — जो जानती है।",
  "18.39": "जो सुख आरम्भ में भी और परिणाम में भी आत्मा को मोहित करे — निद्रा, आलस्य, प्रमाद से उत्पन्न — वह तामसिक कहा गया है।\n\n'आदौ च अन्ते च' — शुरू में भी अन्त में भी। 'आत्मनः मोहनम्' — आत्मा को मोहित करता है। निद्रा-आलस्य-प्रमाद — तीन उत्स। तामसिक सुख — हमेशा नुकसानदेह।",
  "18.28": "जो अयुक्त, असंस्कृत, हठी, धूर्त, दूसरों की जीविका नष्ट करने वाला, आलसी, विषादी और दीर्घसूत्री है — वह तामसिक कर्ता है।\n\n'अयुक्त' — योगहीन। 'असंस्कृत' — सुसंस्कारहीन। 'शठ' — धूर्त। 'नैष्कृतिक' — दूसरों की जीविका छीनने वाला। 'आलसी, विषादी, दीर्घसूत्री' — तीन अतिरिक्त दोष। तामस कर्ता — समाज को हानिकारक।",
  "18.41": "हे परन्तप, ब्राह्मण, क्षत्रिय, वैश्य और शूद्रों के कर्म — स्वभावप्रभव गुणों से विभक्त किए गए हैं।\n\n'स्वभावप्रभवैः गुणैः' — स्वभाव से उत्पन्न गुणों द्वारा। 'प्रविभक्तानि' — विभाजित। चारों वर्णों के कर्म — जन्म से नहीं, स्वभाव और गुण से निर्धारित। गीता का वर्ण-सिद्धान्त — गुणकर्मविभागशः।",
  "18.32": "हे पार्थ, जो बुद्धि — अधर्म को धर्म समझती है, और सब अर्थों को विपरीत देखती है — तमोगुण से ढकी हुई — वह तामसिक बुद्धि है।\n\n'तमसा आवृता' — तमोगुण से ढकी। 'सर्वार्थान् विपरीतान्' — सभी अर्थों को उलटा देखती है। 'अधर्मम् धर्मम् इति' — अधर्म को धर्म समझती है। तामसिक बुद्धि — सर्वथा विपरीत।",
  "18.48": "हे कौन्तेय, दोष होने पर भी अपने स्वभावजन्य कर्म नहीं छोड़ना चाहिए — क्योंकि सभी कर्म धुएँ से अग्नि की तरह दोष से ढके हैं।\n\n'सहजं कर्म' — स्वभाव से उत्पन्न कर्म। 'न त्यजेत्' — नहीं छोड़ना। 'दोषेण' — दोषयुक्त होने पर भी। 'धूमेन अग्निः इव' — जैसे अग्नि धुएँ से ढकी। कोई भी कर्म पूर्णतः निर्दोष नहीं — फिर भी करना आवश्यक।",
  "18.33": "हे पार्थ, जिस धृति से — अव्यभिचारी योग से — मन, प्राण और इन्द्रियों की क्रियाएँ धारण की जाती हैं — वह सात्त्विक धृति है।\n\n'अव्यभिचारिण्या' — जो कभी नहीं डिगती। 'धारयते' — धारण करती है। 'मनः-प्राण-इन्द्रियक्रियाः' — मन, जीवनी-शक्ति और इन्द्रियों की क्रियाएँ। सात्त्विक धृति — भक्तियोग द्वारा सतत।",
  "18.50": "हे कुन्तीपुत्र, जो नैष्कर्म्यसिद्धि है — उसे कैसे प्राप्त करके ब्रह्म तक पहुँचता है — वह सुनो — यह ज्ञान की परम भूमिका है।\n\n'नैष्कर्म्यसिद्धिम् प्राप्य' — नैष्कर्म्य प्राप्त करके। 'ब्रह्म अधिगच्छति' — ब्रह्म (श्रीतत्त्व/लक्ष्मी) तक पहुँचता है। 'ज्ञानस्य निष्ठा' — ज्ञान की परम अवस्था। मध्वमत में ब्रह्म = श्रीलक्ष्मी (अक्षर)।",
  "18.46": "जिससे सभी प्राणियों की उत्पत्ति है, जो यह सब व्याप्त है — उस परमात्मा की अपने कर्म से पूजा करके मनुष्य सिद्धि पाता है।\n\n'यतः प्रवृत्तिः भूतानाम्' — जिनसे सब प्राणियों की उत्पत्ति। 'येन सर्वमिदम् ततम्' — जिनसे यह सब व्याप्त। 'स्वकर्मणा अभ्यर्च्य' — अपने कर्म से पूजा करके। यही कर्मयोग का सर्वोच्च सत्य — प्रत्येक कर्म भगवत्पूजा।",
  "18.47": "अच्छी तरह किए गए परधर्म से — अपना स्वधर्म — दोषयुक्त होने पर भी — श्रेयस्कर है। स्वभाव से नियत कर्म करने से पाप नहीं लगता।\n\n'स्वधर्म' — अपना धर्म। 'परधर्म' — दूसरे का धर्म। 'विगुणोऽपि' — दोषयुक्त होने पर भी। 'स्वभावनियतम्' — स्वभाव से नियत। यह गीता का महत्त्वपूर्ण सिद्धान्त — स्वधर्म में दोष होने पर भी परधर्म से उत्तम।",
  "18.51": "शुद्ध बुद्धि से युक्त, दृढ़ आत्मसंयम से, शब्दादि विषयों को त्यागकर, राग-द्वेष छोड़कर।\n\n'विशुद्धबुद्धिः' — शुद्धबुद्धि। 'धृत्या आत्मानम् नियम्य' — धृति से आत्मसंयम। 'शब्दादीन् विषयान् त्यक्त्वा' — शब्दादि विषयत्याग। 'रागद्वेषौ व्युदस्य' — राग-द्वेष त्याग। यह मोक्षमार्ग के लक्षण हैं।",
  "18.49": "जिसकी बुद्धि सर्वत्र अनासक्त है, जिसने अपने को जीत लिया है, जो स्पृहारहित है — वह संन्यास से नैष्कर्म्यसिद्धि प्राप्त करता है।\n\n'असक्तबुद्धिः' — आसक्तिरहित बुद्धि। 'जितात्मा' — आत्मविजयी। 'विगतस्पृहः' — स्पृहारहित। 'नैष्कर्म्यसिद्धिम्' — कर्मातीतता की सिद्धि — नैष्कर्म्य = कर्मफलरहितावस्था।",
  "18.43": "शौर्य, तेज, धृति, दक्षता, युद्ध से न भागना, दान, ईश्वरभाव — ये क्षत्रिय के स्वभावज कर्म हैं।\n\n'शौर्यम्' — वीरता। 'तेजः' — प्रताप। 'धृतिः' — दृढ़ता। 'दाक्ष्यम्' — कुशलता। 'युद्धे अपलायनम्' — युद्ध से न भागना। 'दानम्' — उदारता। 'ईश्वरभावः' — शासन-कौशल। क्षत्रिय का कर्म — रक्षण और शासन।",
  "18.37": "जो आरम्भ में विष जैसा लगे और परिणाम में अमृत जैसा हो — वह सुख सात्त्विक कहा जाता है, जो आत्मबुद्धि के प्रसाद से उत्पन्न।\n\n'आदौ विषमिव' — शुरू में कठिन। 'परिणामे अमृतवत्' — अन्त में मधुर। 'आत्मबुद्धिप्रसादजम्' — आत्मज्ञान और बुद्धिशुद्धि से उत्पन्न। सात्त्विक सुख — साधना की कठिनाई के बाद का आनन्द — मोक्षसुख।",
  "18.45": "अपने-अपने कर्म में तत्पर मनुष्य — सिद्धि कैसे प्राप्त करता है — वह सुनो।\n\n'स्वकर्मनिरतः' — अपने कर्म में लीन। 'सिद्धिं विन्दति' — सिद्धि पाता है। यहाँ से भगवत्-पूजा के माध्यम से सिद्धि का मार्ग बताया जाएगा।",
  "18.53": "अहंकार, बल, दर्प, काम, क्रोध, परिग्रह को छोड़कर — निर्मम, शान्त — ब्रह्मभाव के योग्य।\n\n'अहंकार-बल-दर्प-काम-क्रोध-परिग्रह' — छह त्याज्य। 'निर्ममः शान्तः' — निर्मम और शान्त। 'ब्रह्मभूयाय कल्पते' — ब्रह्मभूत होने के योग्य। ये सब छोड़ने पर — ब्रह्म तक पहुँचना सम्भव।",
  "18.60": "हे कौन्तेय, जो कर्म तुम मोह से नहीं करना चाहते — वह भी तुम अपनी स्वाभाविक प्रकृति से विवश होकर करोगे।\n\n'स्वभावजेन नियतम्' — स्वाभाविक प्रकृति से नियत। 'मोहात्' — मोह से। 'अवशः अपि' — विवश होकर भी। कर्म अनिवार्य — केवल उसके भाव का प्रश्न। भगवत्शरण में करो — या मोह में करो।",
  "18.52": "एकान्त में रहकर, मितभोजी, वाक्-शरीर-मन को संयमित, नित्य ध्यानयोगपर, वैराग्यसमाश्रित।\n\n'विविक्तसेवी' — एकान्तप्रिय। 'लघ्वाशी' — मितभोजी। 'यतवाक्कायमानसः' — वाक्-काय-मन संयमित। 'ध्यानयोगपरः' — ध्यानयोग में तत्पर। 'वैराग्यम् समुपाश्रितः' — वैराग्य के आश्रित। ये सब साधनामार्ग के उपाय।",
  "18.58": "मत्चित्त होने से — मेरी कृपा से — सभी बाधाएँ पार करोगे। लेकिन यदि अहंकार से नहीं सुनोगे — विनाश होगा।\n\n'मत्चित्त' — मुझमें चित्त। 'मत्प्रसादात्' — मेरी कृपा से। 'सर्वदुर्गाणि तरिष्यसि' — सभी कठिनाइयाँ पार। 'अथ चेत् अहंकारात् न श्रोष्यसि' — अहंकार से न सुनो तो 'विनंक्ष्यसि' — नष्ट होगे।",
  "18.42": "शम, दम, तप, शौच, क्षमा, आर्जव, ज्ञान, विज्ञान, आस्तिक्य — ये ब्राह्मण के स्वभावज कर्म हैं।\n\n'शमः' — मनोनिग्रह। 'दमः' — इन्द्रियनिग्रह। 'तपः' — तपस्या। 'शौचम्' — पवित्रता। 'क्षान्तिः' — क्षमा। 'आर्जवम्' — सरलता। 'ज्ञानम्' — शास्त्रज्ञान। 'विज्ञानम्' — अनुभवज्ञान। 'आस्तिक्यम्' — ईश्वर पर विश्वास। ब्राह्मण का काम — ज्ञान-प्रसार।",
  "18.59": "'मैं नहीं लड़ूँगा' — यह जो संकल्प तुम अहंकार से कर रहे हो — वह मिथ्या है। तुम्हारी प्रकृति तुम्हें (लड़ने के लिए) नियोजित करेगी।\n\n'मिथ्या एषः व्यवसायः' — यह संकल्प मिथ्या। 'अहंकारात्' — अहंकार से। 'प्रकृतिः त्वां नियोक्ष्यति' — तुम्हारी प्रकृति तुम्हें नियोजित करेगी। जीव अस्वतन्त्र — भगवत्-प्रकृतिनियन्त्रित।",
  "18.64": "सभी गुह्यों में परम गुह्य मेरे इस परम वचन को फिर सुनो — तुम मुझे अत्यन्त प्रिय हो — इसलिए हितकारी बात कहता हूँ।\n\n'सर्वगुह्यतमम्' — सभी गुह्यों में सबसे गुह्य। 'परमं वचः' — परम वचन। 'दृढम् इष्टः असि मे' — तुम मुझे दृढ़तापूर्वक प्रिय हो। 'तततः वक्ष्यामि ते हितम्' — इसलिए हितकारी कहता हूँ। प्रेम से ही परम गुह्य।",
  "18.62": "हे भारत, सब प्रकार से उसी की शरण जाओ — उसकी कृपा से परम शान्ति और शाश्वत धाम प्राप्त करोगे।\n\n'सर्वभावेन' — सब प्रकार से। 'तम् एव शरणं गच्छ' — उसी की शरण। 'तत्प्रसादात्' — उसकी कृपा से। 'परां शान्तिम्' — परम शान्ति। 'शाश्वतम् स्थानम्' — शाश्वत धाम। यह गीता का केन्द्रीय सन्देश — भगवत्शरण।",
  "18.68": "जो इस परम गुह्य को मेरे भक्तों में कहेगा — मुझमें परम भक्ति करके — वह निःसंशय मुझे ही प्राप्त होगा।\n\n'परमं गुह्यम्' — परम रहस्य। 'मद्भक्तेषु' — मेरे भक्तों में। 'परां भक्तिं कृत्वा' — परम भक्ति करके। ज्ञान का प्रसार करना — स्वयं परम भक्ति है। गीताज्ञान देने वाला स्वयं मोक्ष पाता है।",
  "18.54": "ब्रह्मभूत होकर — प्रसन्नात्मा — न शोक करता है न काँक्षा करता है। सभी प्राणियों में समभाव से — मुझ (भगवान्) में परा भक्ति प्राप्त करता है।\n\n'ब्रह्मभूतः' — ब्रह्मभाव में स्थित। 'प्रसन्नात्मा' — प्रसन्न चित्त। 'न शोचति न काँक्षति' — शोक-कामना से रहित। 'सर्वभूतेषु समः' — समभाव। 'मद्भक्तिं लभते परां' — परमभक्ति प्राप्त होती है। मध्वमत — ब्रह्मभूत = श्रीतत्त्वप्राप्त।",
  "18.65": "मत्परायण हो, मेरा भक्त बनो, मुझे पूजो, मुझे नमस्कार करो — मेरी प्रतिज्ञा, तुम मुझे ही प्राप्त होगे — तुम मुझे प्रिय हो।\n\n'मन्मना भव' — मन मुझमें। 'मद्भक्त' — मेरा भक्त। 'मद्याजी' — मेरा पूजक। 'मां नमस्कुरु' — मुझे नमस्कार। 'माम् एव एष्यसि' — मुझे ही प्राप्त होगे। 'सत्यम् प्रतिजाने' — यह मेरी प्रतिज्ञा। 'प्रियः असि मे' — तुम मुझे प्रिय हो।",
  "18.55": "भक्ति से मुझे तत्त्वतः जानता है — मैं कौन हूँ और कितना हूँ — फिर मुझे तत्त्वतः जानकर प्रवेश करता है।\n\n'भक्त्या माम् अभिजानाति' — भक्ति से ही भगवान् को जानना सम्भव। 'यावान् यश्च अस्मि तत्त्वतः' — कितना और कैसा हूँ — तत्त्वतः। 'ततः माम् तत्त्वतः ज्ञात्वा विशते' — जानकर प्रवेश करता है। यही भागवतीभक्ति का चरम।",
  "18.63": "इस प्रकार मैंने तुम्हें गुह्यतर से भी अधिक गुह्य ज्ञान दिया है — इसे पूर्णतः विचार करके जैसी इच्छा हो वैसा करो।\n\n'गुह्यात् गुह्यतरम्' — गुह्य से भी अधिक गुह्य। 'विमृश्य' — पूर्णतः विचार करके। 'यथेच्छसि तथा कुरु' — जैसी इच्छा वैसा करो। भगवान् स्वतन्त्रता देते हैं — थोपते नहीं। यही भगवान् का महान् उदारत्व।",
  "18.61": "हे अर्जुन, सभी प्राणियों के हृदय में ईश्वर स्थित है — उन्हें माया से यन्त्रारूढ़ सब भूतों को भ्रमाता हुआ।\n\n'सर्वभूतानां हृदेशे' — सब प्राणियों के हृदय में। 'तिष्ठति' — स्थित है। 'भ्रामयन्' — घुमाता हुआ। 'यन्त्रारूढानि माययाः' — माया से यन्त्र (शरीर) पर आरूढ़। यह भगवान् का अन्तर्यामित्व — हृदयस्थ ईश्वर — जीव का वास्तविक नियन्ता।",
  "18.44": "कृषि, गोपालन, वाणिज्य — वैश्य के स्वभावज कर्म हैं। परिचर्यात्मक (सेवा) कर्म — शूद्र का स्वभावज कर्म है।\n\n'कृषि-गोरक्ष-वाणिज्यम्' — कृषि, गोपालन, व्यापार। 'परिचर्यात्मकम्' — सेवाकार्य। चारों वर्णों के कर्म — गुणों से निर्धारित। समाज के चार कार्य — ज्ञान, रक्षण, उत्पादन, सेवा।",
  "18.69": "मनुष्यों में उससे अधिक मेरा प्रिय कार्य करने वाला कोई नहीं है — और न भविष्य में उससे अधिक प्रिय कोई होगा।\n\n'प्रियकृत्तमः' — सर्वाधिक प्रिय कार्य करने वाला। जो गीता को समझकर भक्तजनों तक पहुँचाता है — वह मनुष्यों में भगवान् को सर्वाधिक प्रिय है। यह गीताशिक्षण का महत्त्व।",
  "18.71": "श्रद्धावान्, द्वेषरहित जो मनुष्य सुने भी — वह भी पाप से मुक्त होकर पुण्यकर्मियों के शुभलोकों को प्राप्त करेगा।\n\n'श्रद्धावान् अनसूयः' — श्रद्धा और द्वेषरहितता — यही सुनने के लिए न्यूनतम योग्यता। 'मुक्तः शुभान् लोकान्' — पाप से मुक्त होकर शुभलोकों को। गीतासश्रवण की न्यूनतम फल।",
  "18.75": "व्यास की कृपा से मैंने यह परम गुह्य योग — योगेश्वर कृष्ण के सीधे मुख से स्वयं कहते हुए — सुना।\n\n'व्यासप्रसादात्' — व्यास की कृपा से। 'परमम् गुह्यम् योगम्' — परम गुह्य योग = गीता। 'योगेश्वरात् कृष्णात् साक्षात् कथयतः' — योगेश्वर कृष्ण के सीधे मुख से। संजय का सौभाग्य — व्यास के अनुग्रह से प्रत्यक्ष श्रवण।",
  "18.66": "सभी धर्मों को त्यागकर — केवल मेरी शरण आओ। मैं तुम्हें सभी पापों से मुक्त करूँगा — शोक मत करो।\n\nगीता का 'चरम-श्लोक' — 'सर्वधर्मान् परित्यज्य' = सभी उपधर्मों को (स्वधर्म नहीं) छोड़कर — 'माम् एकं शरणं व्रज' = केवल हरि की शरण। 'सर्वपापेभ्यः मोक्षयिष्यामि' — सब पापों से मुक्त करूँगा। 'मा शुचः' — शोक मत करो।\n\nमध्वमत में 'सर्वधर्मान्' = उपसाधन-धर्म; 'माम् एकम्' = भगवान् विष्णु एकमात्र। यही गीता का परमसन्देश।",
  "18.74": "संजय उवाच —\nइस प्रकार महात्मा वासुदेव और महात्मा पार्थ के इस अद्भुत, रोमाञ्चकारी संवाद को मैंने सुना।\n\n'अद्भुतं रोमहर्षणम्' — अद्भुत और रोमाञ्चकारी। संजय — जो अपनी दिव्यदृष्टि से देख रहा था — इस संवाद से स्वयं विस्मित। 'वासुदेवस्य पार्थस्य' — दो महात्माओं का संवाद।",
  "18.76": "हे राजन्, केशव और अर्जुन के इस पवित्र अद्भुत संवाद को बार-बार स्मरण करके — मैं पुनः-पुनः हर्षित होता हूँ।\n\n'संस्मृत्य संस्मृत्य' — बार-बार स्मरण करके। 'पुण्यम् अद्भुतम्' — पवित्र और अद्भुत। 'हृष्यामि च मुहुः मुहुः' — पुनः-पुनः हर्षित होता हूँ। संजय का अनुभव — गीता की स्मृति मात्र से आनन्द।",
  "18.77": "हे राजन्, हरि के उस अत्यद्भुत रूप को बार-बार स्मरण करके — मुझे महान् विस्मय होता है और पुनः-पुनः हर्षित होता हूँ।\n\n'हरेः रूपम् अत्यद्भुतम्' — हरि का अत्यद्भुत रूप = विश्वरूप। 'संस्मृत्य संस्मृत्य' — बार-बार। 'विस्मयः मे महान्' — महान् विस्मय। संजय को विश्वरूपदर्शन मिला था — उसकी स्मृति से भी रोमाञ्च।",
  "18.72": "हे पार्थ, क्या यह एकाग्र चित्त से सुना गया? हे धनञ्जय, क्या तुम्हारा अज्ञानजन्य मोह नष्ट हुआ?\n\nयह गीता में कृष्ण का अन्तिम प्रश्न। 'एकाग्रेण चेतसा' — एकाग्र चित्त से। शिक्षक शिष्य से पूछता है — समझ आई? 'अज्ञानसम्मोहः' — अज्ञान से उत्पन्न मोह। 'प्रणष्टः' — नष्ट हुआ? यह गीता का परीक्षण-क्षण।",
  "18.70": "जो इस हम दोनों के धर्मपूर्ण संवाद का अध्ययन करेगा — उसके द्वारा ज्ञानयज्ञ से मैं पूजित होऊँगा — ऐसा मेरा मत है।\n\n'धर्म्यं संवादम्' — धर्मपूर्ण संवाद = गीता। 'अध्येष्यते' — अध्ययन करेगा। 'ज्ञानयज्ञेन' — ज्ञानयज्ञ से। 'इष्टः स्याम्' — पूजित होऊँगा। गीताध्ययन = ज्ञानयज्ञ = भगवत्पूजा।",
  "18.40": "पृथ्वी पर, या स्वर्ग में देवों में — कोई भी प्राणी प्रकृतिजन्य इन तीन गुणों से मुक्त नहीं।\n\n'भूमौ वा' — पृथ्वी पर। 'दिवि देवेषु' — स्वर्ग में देवों में। 'तत्त्वम् यत् एभिः तिसृभिः गुणैः मुक्तम्' — जो इन तीन गुणों से मुक्त हो — ऐसा कोई नहीं। त्रिगुण का सर्वव्यापी प्रभाव — केवल भगवान् गुणातीत।",
  "18.57": "मन से सभी कर्म मुझे अर्पण करके, मत्परायण, बुद्धियोग के आश्रय से — सदा मुझमें चित्त लगाओ।\n\n'चेतसा सर्वकर्माणि मयि संन्यस्य' — मन से सब कर्म मुझे समर्पित। 'मत्परः' — मुझे परम मानकर। 'बुद्धियोगम् उपाश्रित्य' — बुद्धियोग के आश्रय से। 'मत्चित्तः' — मुझमें चित्त। यह कर्मसंन्यास + बुद्धियोग + भक्ति का समन्वय।",
  "18.56": "सभी कर्म करते हुए — मेरी शरण में रहने वाला — मेरी कृपा से शाश्वत अव्यय पद प्राप्त करता है।\n\n'मत्प्रसादात्' — मेरी कृपा से। 'शाश्वतम् अव्ययम् पदम्' — शाश्वत और अव्यय पद = मोक्ष। 'सर्वकर्माण्यपि' — सभी कर्म करते हुए भी। यही भक्तियोग का सार — कर्म करते हुए भगवत्शरण।",
  "18.67": "यह — न तपस्वी को, न भक्तिहीन को — कभी नहीं कहना। जो सुनना नहीं चाहता उसे नहीं, और जो मेरे प्रति द्वेष करता है उसे तो कभी नहीं।\n\nकृष्ण ज्ञान-परम्परा की रक्षा के विषय में बताते हैं — किसे यह गुह्यतम ज्ञान देना। चार अयोग्य व्यक्ति — (१) अतपस्क (अनुशासनहीन); (२) अभक्त; (३) अशुश्रूषु (सुनने की इच्छाहीन); (४) द्वेषी। इनको यह उपदेश न दें।",
  "18.78": "जहाँ योगेश्वर कृष्ण हैं, जहाँ धनुर्धर पार्थ हैं — वहाँ श्री, विजय, विभूति और ध्रुव नीति है — यही मेरा मत है।\n\nगीता का अन्तिम श्लोक। 'योगेश्वरः कृष्णः' — योगशक्तियों के स्वामी। 'पार्थः धनुर्धरः' — धनुर्धारी पार्थ = नर-नारायण। 'श्री-विजय-भूति-ध्रुवा-नीतिः' — लक्ष्मी, विजय, ऐश्वर्य, स्थिरनीति। जहाँ भगवान् हैं और भक्त है — वहाँ सब है।\n\nमध्वाचार्य — 'नर-नारायण' — जहाँ नारायण हैं और उनका भक्त नर है — वहाँ सर्वसम्पत्।\n\nइति अष्टादशोऽध्यायः — मोक्षसंन्यासयोगः।\nइति श्रीमद्भगवद्गीतासूपनिषत्सु ब्रह्मविद्यायां योगशास्त्रे श्रीकृष्णार्जुनसंवादे मोक्षसंन्यासयोगो नामाष्टादशोऽध्यायः।",
  "18.73": "अर्जुन उवाच —\nनष्ट मोहः, स्मृति लब्धा — आपकी कृपा से, हे अच्युत। स्थित हूँ, संशयरहित। आपके वचनानुसार करूँगा।\n\n'नष्टः मोहः' — मोह नष्ट। 'स्मृतिः लब्धा' — स्मृति (यथार्थज्ञान) पुनः मिली। 'त्वत्प्रसादात्' — आपकी कृपा से। 'गतसन्देहः' — संशयमुक्त। 'करिष्ये वचनम् तव' — आपके वचन के अनुसार करूँगा।\n\nयह गीता की परिणति। अर्जुन का परिवर्तन — शोकग्रस्त से ज्ञानयुक्त। 'अच्युत' — कभी न चूकने वाले — भगवान् ने अपना वचन निभाया।",
  "16.3": "भगवान् उवाच —\nअभयं सत्त्वसंशुद्धिः ज्ञानयोगव्यवस्थितिः ।\nदानं दमश्च यज्ञश्च स्वाध्यायस्तप आर्जवम् ॥\nअहिंसा सत्यमक्रोधस्त्यागः शान्तिरपैशुनम् ।\nदया भूतेष्वलोलुप्त्वं मार्दवं ह्रीरचापलम् ॥\nतेजः क्षमा धृतिः शौचमद्रोहो नातिमानिता ।\nभवन्ति सम्पदं दैवीमभिजातस्य भारत ॥\n\nहे भारत, दैवी सम्पत् से उत्पन्न जन में ये गुण होते हैं — अभय, अन्तःकरणशुद्धि, ज्ञानयोगनिष्ठा, दान, दम, यज्ञ, स्वाध्याय, तप, आर्जव, अहिंसा, सत्य, अक्रोध, त्याग, शान्ति, अनिन्दा, दया, अलोलुपता, मार्दव, लज्जा, अचपलता, तेज, क्षमा, धृति, शौच, अद्रोह और अनतिमानिता — ये 26 दैवी गुण।\n\nकृष्ण यहाँ दैवी-आसुरी सम्पत् का वर्णन करते हैं। दैवी सम्पत् = मोक्षदायी गुण।"
};

if (typeof module !== 'undefined') {
  module.exports = { BANNANJE_VERSE_MEANINGS_HI };
}
